/*
 * Localized agent-guide copy for the landing-page agent detail pages.
 *
 * en + zh live directly in info-page-i18n.ts. Every other landing locale
 * gets its agent pages here: buildLocalizedAgentGuides() spreads the English
 * guide first (so non-rendered compact fields stay type-complete), then
 * overrides the rendered fields + the long-form `rich` payload with the
 * translation. Wired into compactInfoPageCopy() so a compact locale renders
 * fully localized agent pages instead of falling back to English.
 *
 * Machine-translated from the English source; native review welcome.
 */
import type { InfoPageCopy } from './info-page-i18n';
import type { LandingLocaleCode } from './i18n';

type Guides = NonNullable<InfoPageCopy['agentGuides']>;

export function buildLocalizedAgentGuides(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'zh-tw': {
      'claude-code': {
        ...en['claude-code']!,
        title: "用 Claude Code 做設計 — Open Design",
        description: "設計師如何用 Claude Code 做 UI 與網頁設計，以及 Open Design 如何把它變成真正的設計 agent — 本機優先、BYOK，並配上嚴選的 skill 與設計系統資源庫。",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "用 Claude Code 做設計。",
        lead: "Claude Code 是 Anthropic 的終端機 coding agent。人們已經拿它來打造 UI、設計系統與著陸頁。Open Design 把它接進真正的設計工作流程 — 帶上你的 Anthropic key 或 Claude 訂閱，所有檔案都留在本機。",
        rich: {"heroCtaLead": "Open Design 把 Claude Code 變成一個本機優先、開源的設計 agent — 你的 Anthropic key 或 Claude 訂閱、你的檔案，外加環繞其上的嚴選 skill 與設計系統資源庫。", "heroCtaActions": [{"label": "在 Open Design 裡使用 Claude Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code 被廣泛視為前端品味最好的 coding agent — 它對介面的推理格外精準，會指明確切的 hex 值、間距與字級層級，並能在龐大的程式碼庫中重構 UI 而不迷失脈絡。但開箱即用時，除非你交給它一套設計系統、skills 與真實參考，它仍會傾向產出千篇一律的外觀。這是一份實用、端到端的指南，教你如何用 Claude Code 處理 UI、前端與設計系統工作，並把它接進 Open Design 的結構化工作流程。", "內容涵蓋 Claude Code 究竟是什麼、它為何擅長前端、如何從零開始設定、CLAUDE.md 與 Skills 工作流程、官方的 Figma 雙向往返、它與 Codex 和 Cursor 的比較、讓 AI 產出顯得平庸的常見陷阱，以及 Open Design 如何以一個開放、本機優先的設計層補上這道落差。"], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code 設計回饋迴圈：終端機 agent 做出具體的設計決策、瀏覽器渲染 UI、工作區，並有一條回饋箭頭繞回", "caption": "核心迴圈：Claude Code 在終端機中推理出具體的 UI 決策，在真實瀏覽器中渲染並驗證，再對齊你的參考逐步收斂。"}, "tocLabel": "本頁內容", "toc": [{"id": "what-is-claude-code", "label": "Claude Code 究竟是什麼"}, {"id": "why-design", "label": "Claude Code 為何擅長設計"}, {"id": "setup", "label": "從零開始為設計設定 Claude Code"}, {"id": "skills-workflow", "label": "CLAUDE.md 與 Skills 工作流程"}, {"id": "figma", "label": "Claude Code + Figma 雙向往返"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "陷阱與「AI 流水線感」的外觀"}, {"id": "open-design", "label": "在 Open Design 裡用 Claude Code 做設計"}, {"id": "faq", "label": "常見問題"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code 究竟是什麼", "blocks": [{"kind": "p", "text": "Claude Code 是 Anthropic 的 agentic coding 工具。它會讀取你的程式碼庫、編輯檔案、執行指令，並與你的開發工具整合 — 從自然語言任務出發來規劃、撰寫與驗證工作，而不只是自動補完幾行程式碼。"}, {"kind": "p", "text": "它橫跨多種介面，全部共用同一個引擎：終端機 CLI、給 VS Code、Cursor 與 JetBrains 用的 IDE 擴充套件、帶有視覺化差異審查的桌面應用程式，以及用於長時間任務的網頁版。你的 CLAUDE.md 檔案、設定與 MCP 伺服器在這些介面之間都通用。"}, {"kind": "steps", "items": [{"label": "指令檔", "body": "Claude Code 會在每次工作階段開始時讀取專案根目錄下的 CLAUDE.md 檔案 — 這是把設計慣例、tokens 與審查檢查清單寫進去的最自然位置。"}, {"label": "Skills", "body": "Agent Skills 把可重複使用的指令、腳本與資源打包起來，由 Claude 按需載入，其中包含 Anthropic 官方用於培養品味的 Frontend Design skill。"}, {"label": "規劃與子 agent", "body": "它能在動手前先規劃，並派生子 agent 平行處理任務的不同部分，讓大規模的 UI 重構保持一致。"}]}, {"kind": "ul", "items": ["供應商：Anthropic", "憑證：Anthropic API key（BYOK，透過 Console）或 Claude 訂閱（Pro / Max）", "介面：終端機 CLI、VS Code / Cursor / JetBrains 擴充套件、桌面應用程式、網頁版"]}]}, {"id": "why-design", "heading": "Claude Code 為何擅長設計", "blocks": [{"kind": "p", "text": "在眾多 coding agent 之中，Claude Code 在前端工作上以有品味著稱。這背後有幾個原因。"}, {"kind": "steps", "items": [{"label": "具體而非含糊的決策", "body": "Claude Code 傾向做出明確的選擇 — 確切的 hex 值、間距級距、字級階梯與元件層級 — 而不是含糊帶過，這正是真正的介面與佔位草稿之間的分野。"}, {"label": "理解程式碼庫的推理", "body": "憑藉龐大的工作脈絡，它能一次跨多個檔案重構 UI，重用你既有的元件與 tokens，而不是重新發明一次性的樣式。"}, {"label": "官方的前端 skill", "body": "Anthropic 提供一個 Frontend Design skill，會讓 Claude 先寫出設計方向，並刻意避開常見的系統字型與千篇一律的紫色漸層。"}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "圖示呈現設計系統、skill 與參考圖三者匯聚成優秀的設計產出", "caption": "品味來自你提供的三項輸入：一套設計系統、一個 skill，以及真實的參考圖。"}, {"kind": "p", "text": "這個道理跟 Anthropic 談論自家模型時所說的一樣：Claude 預設並沒有品味 — 放任不管，它就會收斂到網頁設計的統計中心（Inter、紫色漸層、柔和陰影）。只有當你給它約束時，它才會產出好設計。Open Design 把這些輸入剛好打包好了，這正是兩者契合的原因（下文詳述）。"}]}, {"id": "setup", "heading": "從零開始為設計工作設定 Claude Code", "blocks": [{"kind": "p", "text": "以下是從一台乾淨的機器，到一個能打造並驗證 UI 的 Claude Code 的完整路徑。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "五步設定流程：安裝、驗證、設定 CLAUDE.md、加上 skill、驗證", "caption": "設定順序：安裝 → 驗證 → 設定 CLAUDE.md → 加上 Frontend Design skill → 啟用瀏覽器驗證。"}, {"kind": "steps", "items": [{"label": "把設計規則寫進去", "body": "把你的 tokens、基礎元件與慣例放進 CLAUDE.md，並讓 Claude 指向它們，這樣產出才會符合品牌，而不是退回千篇一律的外觀。"}, {"label": "加上瀏覽器驗證", "body": "接上 Playwright 或 Chrome MCP，讓 Claude 在真實瀏覽器中渲染，並跨各個斷點檢查產出，而不只是確認建置通過。"}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md 與 Skills 工作流程", "blocks": [{"kind": "p", "text": "用 Claude Code 槓桿最高的設計迴圈，是餵給它真實參考加上你的設計脈絡，然後反覆迭代直到 UI 對齊 — 而 CLAUDE.md 與 Skills 會替你扛住這些約束，讓你不必每次下提示都重新解釋一遍。"}, {"kind": "ol", "items": ["從你手上最清楚的視覺參考開始 — 並涵蓋多種狀態（桌面與行動裝置、hover、空狀態、載入中），而不是只有一張主視覺。", "提示要具體；含糊的提示就算搭配強力的 agent 也會產出千篇一律的 UI。", "把你的設計系統與慣例放進 CLAUDE.md，並告訴 Claude tokens 與標準基礎元件放在哪裡。", "加上 Frontend Design skill，讓 Claude 在寫程式碼前先確立明確的美學方向。", "接上瀏覽器驗證，讓 Claude 渲染、依斷點調整尺寸，並回頭與參考比對 — 而不只是確認它能建置通過。"]}, {"kind": "p", "text": "把一張參考圖放進工作階段，並以具體約束來下提示："}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "同時跑一個 dev server，讓提示保持精簡聚焦，並提交好的迭代 / 還原壞的迭代（還原時也告訴 Claude），讓每一輪都建立在乾淨的基礎上。較大規模的重構就用 plan 模式，這樣你可以在任何檔案被改動前先審查方案。"}]}, {"id": "figma", "heading": "Claude Code + Figma：設計 ↔ 程式碼雙向往返", "blocks": [{"kind": "p", "text": "2026 年 2 月，Anthropic 與 Figma 透過 Figma MCP 伺服器推出了一流的雙向整合。它在兩個方向上都能運作。"}, {"kind": "steps", "items": [{"label": "設計 → 程式碼", "body": "在 Figma 中選取一個 frame，或把連結貼進 Claude Code，拉取設計脈絡，再請它用你既有的元件庫實作該設計。Code Connect 讓產出對齊你真正的元件。"}, {"label": "程式碼 → 設計", "body": "在瀏覽器中打造並預覽一個功能，然後說「Send this to Figma」，把正在執行的 UI 擷取成可編輯的 Figma 圖層 — 整個畫面或選定的元素皆可。"}]}, {"kind": "p", "text": "用 claude plugin install figma@claude-plugins-official 安裝一次即可（Dev Mode MCP 需要付費的 Figma 方案）。同一套 Figma MCP 對 Claude Code、Codex、Cursor 與 VS Code 都可用 — 正是 Open Design 為之打造、用來協調的那種可攜、多 agent 能力。"}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor 做設計", "blocks": [{"kind": "p", "text": "設計工作沒有唯一的贏家 — 每個 agent 各有所長，老練的團隊會把它們疊用。一個公允的總結："}, {"kind": "table", "columns": ["Agent", "設計強項", "最適合"], "rows": [["Claude Code", "具體的設計決策（hex、間距、字型）與理解程式碼庫的 UX 推理", "前端推理與大脈絡重構"], ["Codex", "出色的視覺打磨與圖像理解；沙箱化的非同步建置", "委派的非同步建置與可攜的 AGENTS.md 規則"], ["Cursor", "邊建邊看的視覺迴圈，附即時預覽與行內編輯", "在 IDE 內緊密的邊迭代邊觀察 UI 工作"]]}, {"kind": "p", "text": "社群一再得出的結論是：品味來自人類 — 三者在缺乏 skills、參考與約束時，都會退回千篇一律的美學。那才是真正要解決的問題 — 而它是設計工具形狀的，不是模型形狀的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避免「AI 流水線感」的外觀", "blocks": [{"kind": "p", "text": "即便 Claude Code 以有品味著稱，對 AI 生成設計最常見的抱怨仍是它看起來很平庸 — Inter 字型、白底紫色漸層、柔和陰影、過大的圓角，一種「一看就知道是 AI 做的」的美學。Anthropic 自己把這歸因於分布上的收斂：安全的選擇在網頁訓練資料中佔了主導。其他被回報的問題還包括行動版排版破版，以及指令滲漏進 UI 文案。"}, {"kind": "steps", "items": [{"label": "安裝 Frontend Design skill", "body": "它會迫使 Claude 確立明確的方向，並刻意避開被 AI 過度使用的字型與漸層。"}, {"label": "啟用瀏覽器驗證", "body": "讓 Claude 跨斷點渲染並自我檢查，這樣排版才不會在行動版上悄悄破版。"}, {"label": "提供 tokens 與參考", "body": "真實的 design tokens 與參考截圖，是對產出品質最大的單一槓桿。"}, {"label": "把規則寫進 CLAUDE.md", "body": "把「不要主視覺卡片、最多兩種字體、品牌優先的層級」這類風格規則，放在 agent 每次執行都會讀到的地方。"}]}, {"kind": "p", "text": "請注意，每一項緩解措施都是在給 agent 一套嚴選的設計脈絡。逐專案、用手維護這套脈絡的苦工，正是 Open Design 替你省下的。"}]}, {"id": "open-design", "heading": "在 Open Design 裡用 Claude Code 做設計", "blocks": [{"kind": "p", "text": "Open Design 正是上述工作流程一再呼喚的那個開源設計層。它把 Claude Code 視為一級的轉接器，並用嚴選的 skill 與設計系統資源庫、結構化的渲染流程，以及一個本機桌面 UI 把它包起來 — 於是讓 Claude Code 出色的那套設計脈絡，從第一次執行就在場，而不必每次都用手拼湊。"}, {"kind": "ol", "items": ["安裝 Open Design，並選擇 Claude Code 作為你的 agent。", "用你的 Anthropic API key（BYOK）或 Claude 訂閱進行驗證 — 憑證留在你的機器上，絕不經由我們代理。", "挑一套設計系統與一個 skill，然後以一致的品味生成簡報、原型與著陸頁。", "每一份產物與 DESIGN.md 檔案都存在你自己的 repo 裡，而不是託管的雲端。"]}, {"kind": "p", "text": "同一個 Claude Code agent、同一把 key — 再加上環繞其上一套真正可攜、開源的設計工作流程。它本機優先且採用 Apache-2.0，因此你的工作與憑證都不會離開你的機器。"}]}], "faqTitle": "常見問題", "faq": [{"name": "Claude Code 適合做設計工作嗎？", "text": "適合 — 它被廣泛視為前端品味最好的 coding agent，會就 hex 值、間距與字級做出具體、理解程式碼庫的決策。當脈絡裡有 Frontend Design skill、一套設計系統與真實參考圖時，它能產出可上線品質的響應式 UI，並能在瀏覽器中驗證。缺乏這套脈絡時，它就會傾向退回千篇一律的外觀，而那正是 Open Design 補上的落差。"}, {"name": "要用 Claude Code 做設計，我需要 Claude 訂閱嗎？", "text": "你可以用 Anthropic API key（BYOK，透過 Console）或 Claude 訂閱（Pro / Max）。無論哪種，Open Design 都不會代理你的憑證 — 它們由你機器上的 agent 直接使用。"}, {"name": "前端設計該選 Claude Code 還是 Codex？", "text": "兩者都很強。Claude Code 以具體、理解程式碼庫的設計決策與前端推理著稱；Codex 視覺打磨出色，且擅長委派、沙箱化的建置。許多團隊兩者並用 — Open Design 讓你在不更動設計工作流程的情況下切換 agent。"}, {"name": "我要怎麼把 Claude Code 連到 Figma？", "text": "用 claude plugin install figma@claude-plugins-official 安裝官方 Figma plugin。接著你就能用設計脈絡把 Figma frame 實作成程式碼，並用「Send this to Figma」把正在執行的 UI 推回成可編輯的 Figma frame。Dev Mode MCP 需要付費的 Figma 方案。"}, {"name": "Skills 與 CLAUDE.md 是什麼？", "text": "CLAUDE.md 是放在專案根目錄的 markdown 檔，Claude Code 會在每次工作階段開始時讀取 — 是把設計慣例寫進去的地方。Skills 把可重複的指令與資源打包，由 Claude 按需載入，其中包含 Anthropic 官方的 Frontend Design skill。Open Design 提供一套嚴選的兩者資源庫，讓你省下逐專案的設定。"}, {"name": "我要怎麼避免那種千篇一律的「AI 流水線感」美學？", "text": "安裝 Frontend Design skill、提供真實的 design tokens 與參考截圖、把品牌規則寫進 CLAUDE.md，並啟用瀏覽器驗證。Open Design 把這些做成一套嚴選的資源庫，讓你省下逐專案的設定。"}, {"name": "Open Design 跟 Anthropic 有關係嗎？", "text": "沒有。Claude Code 是 Anthropic 的產品；Open Design 是一個獨立的開源專案，以一級轉接器的形式支援它。Claude 與 Claude Code 是 Anthropic 的商標。"}, {"name": "我的檔案與憑證安全嗎？", "text": "安全 — Open Design 本機優先且採用 Apache-2.0。你的檔案、產物與 DESIGN.md 都留在你自己的 repo 裡，你的 Anthropic 憑證由你機器上的 agent 直接使用，絕不會經由 Open Design 伺服器轉送。"}], "ctaTitle": "用開放的方式，與 Claude Code 一起做設計。", "ctaBody": "帶上你自己的 Anthropic key 或 Claude 訂閱，所有檔案都留在本機，並為你早已在用的 agent 配上一套嚴選的設計資源庫。", "ctaActions": [{"label": "在 Open Design 裡使用 Claude Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支援的 agent"},
      },
      'codex': {
        ...en['codex']!,
        title: "用 Codex 做設計 — Open Design",
        description: "人們如何用 OpenAI Codex 做 UI 與網頁設計 — Product Design plugin、Figma 整合、前端 skills — 以及 Open Design 如何把 Codex 變成本機優先、開源的設計 agent。",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "用 Codex 做設計。",
        lead: "Codex 是 OpenAI 的 coding agent。憑藉 Product Design plugin 與 Figma 整合，它已成為一個正經的設計工具。Open Design 把 Codex 接進一套開源的設計工作流程 — 你的 OpenAI key 或 ChatGPT 訂閱、你的檔案，本機優先。",
        rich: {"heroCtaLead": "Open Design 把 Codex 變成一個本機優先、開源的設計 agent — 你的 OpenAI key、你的檔案，外加環繞其上的嚴選 skill 與設計系統資源庫。", "heroCtaActions": [{"label": "在 Open Design 裡使用 Codex", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex 一開始是個程式碼產生器，但到了 2026 年，只要你給它對的參考、skills 與驗證迴圈，它就成了一個能設計真實介面的可靠工具。這是一份實用、端到端的指南，教你如何用 Codex 處理 UI、前端與設計系統工作，並把它接進 Open Design 的結構化設計工作流程。", "內容涵蓋 Codex 如今是什麼、它為何突然擅長前端、如何從零開始設定、截圖轉 UI 的迴圈、官方的 Figma 雙向往返、它與 Cursor 和 Claude Code 的比較、讓 AI 產出顯得平庸的常見陷阱，以及 Open Design 如何以一個開放、本機優先的設計層補上這道落差。"], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex 設計回饋迴圈：終端機 agent、渲染 UI 的瀏覽器、工作區，並有一條回饋箭頭繞回", "caption": "核心迴圈：Codex 在終端機中打造 UI，在真實瀏覽器中渲染並驗證，再對齊你的參考逐步迭代。"}, "tocLabel": "本頁內容", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex 究竟是什麼"}, {"id": "why-design", "label": "Codex 為何現在擅長設計"}, {"id": "setup", "label": "從零開始為設計設定 Codex"}, {"id": "screenshot-workflow", "label": "截圖轉 UI 的工作流程"}, {"id": "figma", "label": "Codex + Figma 雙向往返"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "陷阱與「AI 流水線感」的外觀"}, {"id": "open-design", "label": "在 Open Design 裡用 Codex 做設計"}, {"id": "faq", "label": "常見問題"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex 究竟是什麼（以及它不是什麼）", "blocks": [{"kind": "p", "text": "首先,要釐清一個幾乎絆倒所有搜尋「Codex」的人的混淆。最初的 OpenAI Codex 是 2021 年的程式碼補完模型,曾驅動早期的 GitHub Copilot,並於 2023 年棄用。本頁談的不是那個。如今的 Codex 是 OpenAI 的 agentic coding 工具 — 它會從自然語言任務出發來規劃、撰寫、執行與驗證程式碼。"}, {"kind": "p", "text": "現代 Codex 橫跨四種介面：終端機 CLI（以 Rust 重寫,採 Apache-2.0 授權）、給 VS Code、Cursor 與 Windsurf 用的 IDE 擴充套件、用於委派非同步任務的雲端／網頁版,以及一個內建瀏覽器與 Computer Use 的桌面應用程式。"}, {"kind": "steps", "items": [{"label": "預設模型", "body": "截至 2026 年中,推薦的模型是 gpt-5.5,而 gpt-5.4 則是 OpenAI 明確為前端與 computer use 訓練的模型。"}, {"label": "指令檔", "body": "Codex 會讀取專案中的 AGENTS.md 檔案(一個跨工具的標準)來取得專案規則 — 這是把設計慣例寫進去的最自然位置。"}, {"label": "沙箱", "body": "它在核心層級的沙箱中執行(預設為 workspace-write),因此正在編輯你 UI 的 agent 無法跑到專案之外。"}]}, {"kind": "ul", "items": ["供應商：OpenAI", "憑證：OpenAI API key（BYOK）或 ChatGPT 訂閱（Free / Go / Plus / Pro / Business / Enterprise）", "CLI 授權：Apache-2.0，開源"]}]}, {"id": "why-design", "heading": "Codex 為何現在擅長設計", "blocks": [{"kind": "p", "text": "2026 年初有三件事匯聚在一起,讓 Codex 從一個一般的程式碼產生器,變成一個真正的設計工具。"}, {"kind": "steps", "items": [{"label": "一個為前端訓練的模型", "body": "OpenAI 推出了 GPT-5.4 — 它第一個為前端與 computer use 訓練的主線模型,在整個設計工作流程中圖像理解大幅提升,自我驗證也更強。它甚至能在確定最終素材前,先生成情緒板與多個視覺選項。"}, {"label": "一個官方的前端 skill", "body": "openai/skills 目錄提供一個嚴選的 frontend-skill,強制落實真正的品味:無卡片的版面、滿版主視覺、品牌優先的層級、節制的動效、最多兩種字體與一種強調色 — 並讓 Codex 在動工前先寫出視覺論點。"}, {"label": "瀏覽器驗證", "body": "搭配 Playwright skill,Codex 會開啟真實瀏覽器、依斷點調整尺寸,並把產出回頭與參考比對,而不只是檢查建置通過。"}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "圖示呈現設計系統、skill 與參考圖三者匯聚成優秀的設計產出", "caption": "品味來自你提供的三項輸入：一套設計系統、一個 skill，以及真實的參考圖。"}, {"kind": "p", "text": "這三件事背後的道理：Codex 預設並沒有品味。只有當你給它約束時 — 一套設計系統、一個美學 skill 與具體的參考 — 它才會產出好設計。Open Design 把這些輸入剛好打包好了,這正是兩者契合的原因(下文詳述)。"}]}, {"id": "setup", "heading": "從零開始為設計工作設定 Codex", "blocks": [{"kind": "p", "text": "以下是從一台乾淨的機器,到一個能打造並驗證 UI 的 Codex 的完整路徑。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "五步設定流程：安裝、驗證、設定、安裝 skill、驗證", "caption": "設定順序：安裝 → 驗證 → 設定 AGENTS.md → 安裝前端 skill → 啟用瀏覽器驗證。"}, {"kind": "steps", "items": [{"label": "把設計規則寫進去", "body": "把你的 tokens、基礎元件與慣例放進 AGENTS.md 或 DESIGN.md,並讓 Codex 指向它們,這樣產出才會符合品牌,而不是退回千篇一律的外觀。"}, {"label": "選對的推理層級", "body": "OpenAI 指出,中低推理層級在前端上的成果往往比最高設定還要好。"}]}]}, {"id": "screenshot-workflow", "heading": "截圖轉 UI 的工作流程", "blocks": [{"kind": "p", "text": "用 Codex 槓桿最高的設計迴圈,是把一張參考圖變成可運作的響應式 UI,並反覆迭代直到對齊。OpenAI 自己的指引可以濃縮成五個步驟。"}, {"kind": "ol", "items": ["從你手上最清楚的視覺參考開始 — 並涵蓋多種狀態（桌面與行動裝置、hover、空狀態、載入中），而不是只有一張主視覺。", "提示要具體；含糊的提示會產出千篇一律的 UI。", "備好一套設計系統，並告訴 Codex tokens 與標準基礎元件放在哪裡。", "啟用 Playwright 互動 skill，讓 Codex 在真實瀏覽器中渲染並依斷點調整尺寸。", "透過讓 Codex 把它的實作回頭與截圖比對來迭代 — 而不只是確認它能建置通過。"]}, {"kind": "p", "text": "把截圖拖進終端機,或用 image 旗標來餵圖,然後以具體約束來下提示:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "在第二個終端機跑一個 dev server,讓提示保持精簡聚焦,並提交好的迭代 / 還原壞的迭代(還原時也告訴 Codex),讓每一輪都建立在乾淨的基礎上。"}]}, {"id": "figma", "heading": "Codex + Figma：設計 ↔ 程式碼雙向往返", "blocks": [{"kind": "p", "text": "2026 年 2 月,OpenAI 與 Figma 宣布官方合作,把先前的 Figma MCP beta 升級為一流的雙向整合。它在兩個方向上都能運作。"}, {"kind": "steps", "items": [{"label": "設計 → 程式碼", "body": "在 Figma 中複製一個 frame 的「link to selection」,用 get_design_context 把它貼進 Codex,再請它用你既有的元件庫實作該設計。"}, {"label": "程式碼 → 設計", "body": "generate_figma_design 工具(「Code to Canvas」)會把一個正在執行的 UI 轉回成可編輯的 Figma frame — 整個畫面、選定的元素,或整個檔案皆可。"}]}, {"kind": "p", "text": "Figma MCP 以遠端伺服器形式運作,且不受速率限制。加一次,它就對 Codex、Claude Code、Cursor、VS Code 等都可用 — 正是 Open Design 為之打造、用來協調的那種可攜、多 agent 能力。"}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code 做設計", "blocks": [{"kind": "p", "text": "設計工作沒有唯一的贏家 — 每個 agent 各有所長,老練的團隊會把它們疊用。一個公允的總結:"}, {"kind": "table", "columns": ["Agent", "設計強項", "最適合"], "rows": [["Codex", "有了 GPT-5.4 + frontend-skill 後出色的視覺打磨；圖像理解", "委派的非同步建置、沙箱化執行、可攜的 AGENTS.md 規則"], ["Cursor", "邊建邊看的視覺迴圈，附即時預覽與行內編輯", "在 IDE 內緊密的邊迭代邊觀察 UI 工作"], ["Claude Code", "具體的設計決策（hex、間距、字型）與理解程式碼庫的 UX", "前端推理與大脈絡重構"]]}, {"kind": "p", "text": "社群一再得出的結論是:品味來自人類 — 三者在缺乏 skills、參考與約束時,都會退回千篇一律的美學。那才是真正要解決的問題 — 而它是設計工具形狀的,不是模型形狀的。"}]}, {"id": "pitfalls", "heading": "陷阱,以及如何避免「AI 流水線感」的外觀", "blocks": [{"kind": "p", "text": "對 Codex 生成設計最常見的抱怨是它看起來很平庸 — 柔和漸層、漂浮面板、過大的圓角、戲劇化的陰影,一種「一看就知道是 AI 做的」的 Inter 加紫色調性。其他被回報的問題還包括行動版排版破版、指令滲漏進 UI 文案,以及很快就撞到使用上限。"}, {"kind": "steps", "items": [{"label": "安裝一個前端 skill", "body": "一個嚴選的美學 skill 會迫使 Codex 確立明確的方向,而非預設的外觀。"}, {"label": "啟用 Playwright 驗證", "body": "讓 Codex 跨斷點渲染並自我檢查,這樣排版才不會在行動版上悄悄破版。"}, {"label": "提供 tokens 與參考", "body": "真實的 design tokens 與參考截圖,是對產出品質最大的單一槓桿。"}, {"label": "把規則寫進 AGENTS.md", "body": "把「不要主視覺卡片、最多兩種字體、品牌優先的層級」這類風格規則,放在 agent 每次執行都會讀到的地方。"}]}, {"kind": "p", "text": "請注意,每一項緩解措施都是在給 agent 一套嚴選的設計脈絡。逐專案、用手維護這套脈絡的苦工,正是 Open Design 替你省下的。"}]}, {"id": "open-design", "heading": "在 Open Design 裡用 Codex 做設計", "blocks": [{"kind": "p", "text": "Open Design 正是上述工作流程一再呼喚的那個開源設計層。它把 Codex 視為一級的轉接器,並用嚴選的 skill 與設計系統資源庫、結構化的渲染流程,以及一個本機桌面 UI 把它包起來 — 於是讓 Codex 出色的那套設計脈絡,從第一次執行就在場,而不必每次都用手拼湊。"}, {"kind": "ol", "items": ["安裝 Open Design，並選擇 Codex 作為你的 agent。", "用你的 OpenAI API key（BYOK）或 ChatGPT 訂閱進行驗證 — 憑證留在你的機器上，絕不經由我們代理。", "挑一套設計系統與一個 skill，然後以一致的品味生成簡報、原型與著陸頁。", "每一份產物與 DESIGN.md 檔案都存在你自己的 repo 裡，而不是託管的雲端。"]}, {"kind": "p", "text": "同一個 Codex agent、同一把 key — 再加上環繞其上一套真正可攜、開源的設計工作流程。它本機優先且採用 Apache-2.0,因此你的工作與憑證都不會離開你的機器。"}]}], "faqTitle": "常見問題", "faq": [{"name": "OpenAI Codex 真的能做設計工作嗎？", "text": "能 — 當脈絡裡有前端 skill、一套設計系統與真實參考圖時,Codex(尤其在 GPT-5.4 上)能產出可上線品質的響應式 UI,並能在瀏覽器中驗證。缺乏這套脈絡時,它就會傾向退回千篇一律的外觀,而那正是 Open Design 補上的落差。"}, {"name": "這是 OpenAI Codex 的 Product Design plugin 嗎？", "text": "不是。Open Design 是一個獨立的開源專案,把 Codex 整合為一個 agent。它以一套本機優先、開放的 skill 與設計系統資源庫,補足 OpenAI 自家的工具。"}, {"name": "要用 Codex 做設計,我需要 ChatGPT 訂閱嗎？", "text": "你可以用 OpenAI API key（BYOK）或你的 ChatGPT 訂閱。以 ChatGPT 登入通常會給更寬鬆的上限;無論哪種,Open Design 都不會代理你的憑證。"}, {"name": "前端設計該選 Codex 還是 Claude Code？", "text": "兩者都很強。Claude Code 以具體、理解程式碼庫的設計決策著稱;Codex 在 GPT-5.4 之後視覺打磨出色,且擅長委派、沙箱化的建置。許多團隊兩者並用 — Open Design 讓你在不更動設計工作流程的情況下切換 agent。"}, {"name": "我要怎麼把 Codex 連到 Figma？", "text": "加上官方的 Figma MCP 伺服器（codex mcp add figma --url https://mcp.figma.com/mcp）。接著你就能用 get_design_context 把 Figma frame 實作成程式碼,並用 generate_figma_design 把正在執行的 UI 推回成可編輯的 Figma frame。"}, {"name": "我要怎麼避免那種千篇一律的「AI 流水線感」美學？", "text": "安裝一個前端 skill、提供真實的 design tokens 與參考截圖、把品牌規則寫進 AGENTS.md,並啟用 Playwright 驗證。Open Design 把這些做成一套嚴選的資源庫,讓你省下逐專案的設定。"}, {"name": "Open Design 跟 OpenAI 有關係嗎？", "text": "沒有。Codex 是 OpenAI 的產品;Open Design 是一個獨立的開源專案,以一級轉接器的形式支援它。OpenAI 與 Codex 是 OpenAI 的商標。"}, {"name": "我的檔案與憑證安全嗎？", "text": "安全 — Open Design 本機優先。你的檔案、產物與 DESIGN.md 都留在你自己的 repo 裡,你的 OpenAI 憑證由你機器上的 agent 直接使用,絕不會經由 Open Design 伺服器轉送。"}], "ctaTitle": "用開放的方式，與 Codex 一起做設計。", "ctaBody": "帶上你自己的 OpenAI key，所有檔案都留在本機，並為你早已在用的 agent 配上一套嚴選的設計資源庫。", "ctaActions": [{"label": "在 Open Design 裡使用 Codex", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支援的 agent"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "設計師如何用 Cursor 做設計 — Open Design",
        description: "設計師如何用 Cursor 做 UI 與網頁設計 — Design Mode、Figma 轉程式碼、Figma MCP — 以及 Open Design 如何把 Cursor 變成本機優先、開源的設計 agent。",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "設計師如何用 Cursor 做設計。",
        lead: "Cursor 是那款 AI 程式碼編輯器,如今多了一個視覺化的 Design Mode。設計師用它以指點與描繪的方式編輯 UI,並把 Figma 轉成程式碼。Open Design 把 Cursor Agent 接進一套開源的設計工作流程,讓你的檔案留在本機。",
        rich: {"heroCtaLead": "Open Design 把 Cursor 變成一個本機優先、開源的設計 agent — 你的 Cursor 帳號或模型 keys、你的檔案,外加環繞其上的嚴選 skill 與設計系統資源庫。", "heroCtaActions": [{"label": "在 Open Design 裡使用 Cursor", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor 是那款 AI 優先的程式碼編輯器,它讓「邊建邊看它渲染」成為交付 UI 的預設方式。憑藉 Agent 模式、行內編輯、編輯器內預覽,以及透過 MCP 接上的 Figma,只要你給它對的參考、規則與一條驗證迴圈,它就成了一個貨真價實的設計工具。這是一份實用、端到端的指南,教你如何用 Cursor 處理 UI、前端與設計系統工作,並把它接進 Open Design 的結構化設計工作流程。", "內容涵蓋 Cursor 究竟是什麼、它緊密的邊迭代邊觀察迴圈為何適合設計、如何從零開始設定、截圖與預覽轉 UI 的迴圈、透過 MCP 的 Figma 雙向往返、它與 Codex 和 Claude Code 的比較、讓 AI 產出顯得平庸的常見陷阱,以及 Open Design 如何以一個開放、本機優先的設計層補上這道落差。"], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor 設計匯聚:左側是編輯器,中間是一個嚴選的 skill 與設計系統樞紐、中心放著 Cursor 標誌,右側是渲染好的 UI", "caption": "核心理念:Cursor 在編輯器中編輯並渲染 UI,而一個嚴選的設計樞紐則餵給它系統、skills 與參考,讓產出看起來是刻意為之。"}, "tocLabel": "本頁內容", "toc": [{"id": "what-is-cursor", "label": "Cursor 究竟是什麼"}, {"id": "why-design", "label": "Cursor 為何擅長設計"}, {"id": "setup", "label": "從零開始為設計設定 Cursor"}, {"id": "preview-workflow", "label": "預覽轉 UI 的工作流程"}, {"id": "figma", "label": "透過 MCP 的 Cursor + Figma"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "陷阱與「AI 流水線感」的外觀"}, {"id": "open-design", "label": "在 Open Design 裡用 Cursor 做設計"}, {"id": "faq", "label": "常見問題"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor 究竟是什麼", "blocks": [{"kind": "p", "text": "Cursor 是 Anysphere 打造的一款 AI 優先的程式碼編輯器。它是 VS Code 的一個分支,因此保留了你熟悉的編輯器、擴充套件與快捷鍵,但圍繞一個 AI agent 重建了工作流程 — 這個 agent 能讀取你的整個專案、編輯多個檔案、執行指令,並在迴圈中與你一起迭代。"}, {"kind": "p", "text": "對設計工作而言,重要的介面有:Agent 模式(你描述一個結果,Cursor 跨檔案規劃並編輯)、用於快速微調的行內編輯與 Tab 補完、一個編輯器內預覽／瀏覽器(讓你不離開視窗就能看見正在執行的 UI),以及讓它拉進外部脈絡(例如一個即時的 Figma 檔案)的 MCP 支援。"}, {"kind": "steps", "items": [{"label": "專案規則", "body": "Cursor 會讀取專案指令檔 — `.cursor/rules` 下受版本控管的 `.mdc` 規則,以及一個純文字的 `AGENTS.md` — 讓你能把設計慣例寫在 agent 每次執行都會讀到的地方。"}, {"label": "模型", "body": "Cursor 在模型上很有彈性:它透過你的訂閱內建前沿模型,也支援帶上你自己的模型 keys,因此你能在同一套編輯器工作流程背後挑選引擎。"}, {"label": "MCP", "body": "它使用 Model Context Protocol,因此外部伺服器 — 最相關的就是 Figma MCP 伺服器 — 就成了 agent 一級的脈絡。"}]}, {"kind": "ul", "items": ["供應商：Anysphere", "憑證：Cursor 帳號 / 訂閱（Hobby / Pro / Business）或你自己的模型 keys（BYOK）", "形態：帶有編輯器內 agent 與預覽的 AI 優先程式碼編輯器（VS Code 分支）"]}]}, {"id": "why-design", "heading": "Cursor 為何擅長設計", "blocks": [{"kind": "p", "text": "Cursor 的設計優勢不是某一個功能 — 而是那條邊建邊看迴圈的緊密度。有三件事讓它感覺像一個設計工具,而非一般的程式碼產生器。"}, {"kind": "steps", "items": [{"label": "一條緊密的邊迭代邊觀察迴圈", "body": "你下提示,Cursor 跨檔案編輯,編輯器內預覽隨即渲染結果 — 於是你能在數秒內調整間距、層級與動效,而不必在另一個終端機與瀏覽器之間來回往返。"}, {"label": "直接視覺編輯", "body": "除了對話,Cursor 還讓你在預覽中選取元素並微調樣式,於是小幅的視覺修正感覺像設計編輯,而非考古式翻找程式碼。"}, {"label": "專案規則與 MCP 脈絡", "body": "有了 `.cursor/rules`(或 `AGENTS.md`)與 Figma MCP 伺服器,agent 是依著你的 tokens、元件與真實設計規格在做事,而非靠猜。"}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "圖示呈現設計系統、skill 與參考圖三者匯聚成優秀的設計產出", "caption": "品味來自你提供的三項輸入：一套設計系統、一個 skill，以及真實的參考圖。"}, {"kind": "p", "text": "這個道理跟每個 agent 教會我們的一樣:Cursor 預設並沒有品味。只有當你給它約束時 — 一套設計系統、一個美學 skill 與具體的參考 — 它才會產出好設計。Open Design 把這些輸入剛好打包好了,這正是兩者契合的原因(下文詳述)。"}]}, {"id": "setup", "heading": "從零開始為設計工作設定 Cursor", "blocks": [{"kind": "p", "text": "以下是從一台乾淨的機器,到一個能依你的設計系統打造、預覽並驗證 UI 的 Cursor 的完整路徑。"}, {"kind": "ol", "items": ["從 cursor.com 安裝 Cursor，並用你的 Cursor 帳號登入，或在 Settings 中設定你自己的模型 keys（BYOK）。", "開啟你的專案，並在對話 / Agent 面板中挑一個模型。", "加上專案規則：建立 `.cursor/rules/*.mdc` 來寫結構化、以 glob 限定範圍的慣例，或建立一個純文字的 `AGENTS.md` 來寫簡單、易讀的指令。", "接上 Figma MCP 伺服器（選用），讓 agent 能讀取即時的設計脈絡。", "跑你的 dev server，並在迭代時用編輯器內預覽來查看與驗證 UI。"]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "五步設定流程：安裝、驗證、設定規則、加上 skill、驗證", "caption": "設定順序：安裝 → 驗證 → 設定專案規則 → 加上一個 skill → 啟用預覽驗證。"}, {"kind": "p", "text": "一個最精簡的專案規則檔,就能讓 agent 依品牌設計,而非退回千篇一律的外觀。把它放在 Cursor 每次執行都會讀到的地方:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "把設計規則寫進去", "body": "把你的 tokens、基礎元件與慣例放進 `.cursor/rules` 或 `AGENTS.md`,並讓 Cursor 指向它們,這樣產出才會符合品牌,而不是退回千篇一律的外觀。"}, {"label": "讓提示保持精簡", "body": "Cursor 緊密的迴圈會回報聚焦的請求 — 一次迭代一個元件或一種狀態,並在每一輪之間觀察預覽。"}]}]}, {"id": "preview-workflow", "heading": "預覽轉 UI 的工作流程", "blocks": [{"kind": "p", "text": "用 Cursor 槓桿最高的設計迴圈,是把一張參考變成可運作的響應式 UI,並在編輯器中反覆迭代直到對齊 — 全程盯著即時預覽,而不是靠猜。"}, {"kind": "ol", "items": ["從你手上最清楚的視覺參考開始 — 並涵蓋多種狀態（桌面與行動裝置、hover、空狀態、載入中），而不是只有一張主視覺。", "提示要具體；含糊的提示會產出千篇一律的 UI。", "備好一套設計系統，並告訴 Cursor tokens 與標準基礎元件放在哪裡。", "讓編輯器內預覽保持開啟、dev server 保持執行，這樣每次編輯都會立即在你在意的斷點上渲染。", "透過把渲染好的 UI 回頭與參考比對來迭代 — 並用預覽中的直接元素選取來做小幅的視覺修正。"]}, {"kind": "p", "text": "把一張圖附在對話裡來餵參考,然後以具體約束來下提示:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "提交好的迭代並還原壞的迭代(還原時也告訴 Cursor),讓每一輪都建立在乾淨的基礎上 — 這正是讓任何 agent 迴圈不致跑偏的同一套紀律。"}]}, {"id": "figma", "heading": "Cursor + Figma：透過 MCP 的設計 ↔ 程式碼", "blocks": [{"kind": "p", "text": "Cursor 透過官方的 Figma MCP 伺服器連到 Figma,讓 agent 對一個即時的 Figma 檔案有結構化的存取,而不是一張扁平的截圖。這就把交接中的猜測拿掉了。"}, {"kind": "steps", "items": [{"label": "設計 → 程式碼", "body": "在 Figma 中複製一個 frame 的連結,把它貼進 Cursor,再請它實作該設計。MCP 伺服器會暴露真實的設計脈絡 — 元件、變數、版面資料、tokens — 讓生成的程式碼符合來源,而非近似而已。"}, {"label": "保持對齊", "body": "只要在 Figma 中一致地使用 design tokens、樣式與元件(並在可用之處用 Code Connect),Cursor 的產出就會保持對映到你真正的設計系統,而非重新發明基礎元件。"}]}, {"kind": "p", "text": "把遠端的 Figma MCP 伺服器設定一次,它就對 Cursor 成為一級的脈絡。由於 MCP 是開放標準,同一台伺服器在 Cursor、Claude Code、Codex 與 VS Code 之間都可重用 — 正是 Open Design 為之打造、用來協調的那種可攜、多 agent 能力。"}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code 做設計", "blocks": [{"kind": "p", "text": "設計工作沒有唯一的贏家 — 每個 agent 各有所長,老練的團隊會把它們疊用。一個公允的總結:"}, {"kind": "table", "columns": ["Agent", "設計強項", "最適合"], "rows": [["Cursor", "邊建邊看的視覺迴圈，附即時的編輯器內預覽與直接元素編輯", "在 IDE 內緊密的邊迭代邊觀察 UI 工作"], ["Codex", "搭配前端 skill 的出色視覺打磨；圖像理解與沙箱化執行", "委派的非同步建置與可攜的 AGENTS.md 規則"], ["Claude Code", "具體的設計決策（hex、間距、字型）與理解程式碼庫的 UX", "前端推理與大脈絡重構"]]}, {"kind": "p", "text": "社群一再得出的結論是:品味來自人類 — 三者在缺乏 skills、參考與約束時,都會退回千篇一律的美學。那才是真正要解決的問題 — 而它是設計工具形狀的,不是模型形狀的。"}]}, {"id": "pitfalls", "heading": "陷阱,以及如何避免「AI 流水線感」的外觀", "blocks": [{"kind": "p", "text": "對 Cursor 生成設計最常見的抱怨是它看起來很平庸 — 柔和漸層、漂浮面板、過大的圓角、戲劇化的陰影,一種「一看就知道是 AI 做的」的 Inter 加紫色調性。其他被回報的問題還包括在行動版上破版的排版,以及指令滲漏進 UI 文案。"}, {"kind": "steps", "items": [{"label": "加上一個設計 skill", "body": "一個嚴選的美學 skill 會迫使 Cursor 確立明確的方向,而非預設的外觀。"}, {"label": "用預覽來驗證", "body": "在編輯器內預覽中跨斷點渲染並自我檢查,這樣排版才不會在行動版上悄悄破版。"}, {"label": "提供 tokens 與參考", "body": "真實的 design tokens 與參考截圖,是對產出品質最大的單一槓桿。"}, {"label": "把規則寫進 `.cursor/rules`", "body": "把「不要主視覺卡片、最多兩種字體、品牌優先的層級」這類風格規則,放在 agent 每次執行都會讀到的地方。"}]}, {"kind": "p", "text": "請注意,每一項緩解措施都是在給 agent 一套嚴選的設計脈絡。逐專案、用手維護這套脈絡的苦工,正是 Open Design 替你省下的。"}]}, {"id": "open-design", "heading": "在 Open Design 裡用 Cursor 做設計", "blocks": [{"kind": "p", "text": "Open Design 正是上述工作流程一再呼喚的那個開源設計層。它把 Cursor 視為一級的轉接器,並用嚴選的 skill 與設計系統資源庫、結構化的渲染流程,以及一個本機桌面 UI 把它包起來 — 於是讓 Cursor 出色的那套設計脈絡,從第一次執行就在場,而不必每次都用手拼湊。"}, {"kind": "ol", "items": ["安裝 Open Design，並選擇 Cursor 作為你的 agent。", "用你的 Cursor 帳號或你自己的模型 keys（BYOK）進行驗證 — 憑證留在你的機器上，絕不經由我們代理。", "挑一套設計系統與一個 skill，然後以一致的品味生成簡報、原型與著陸頁。", "每一份產物與 DESIGN.md 檔案都存在你自己的 repo 裡，而不是託管的雲端。"]}, {"kind": "p", "text": "同一個 Cursor agent、同一把 key — 再加上環繞其上一套真正可攜、開源的設計工作流程。它本機優先且採用 Apache-2.0,因此你的工作與憑證都不會離開你的機器。"}]}], "faqTitle": "常見問題", "faq": [{"name": "Cursor 真的能做設計工作嗎？", "text": "能 — 當脈絡裡有一個設計 skill、一套設計系統與真實參考圖時,Cursor 能產出可上線品質的響應式 UI,而它的編輯器內預覽讓你以視覺方式驗證並精修。缺乏這套脈絡時,它就會傾向退回千篇一律的外觀,而那正是 Open Design 補上的落差。"}, {"name": "這是 Cursor 的官方產品嗎？", "text": "不是。Open Design 是一個獨立的開源專案,把 Cursor 整合為一個 agent。它以一套本機優先、開放的 skill 與設計系統資源庫,補足 Cursor。"}, {"name": "要用 Cursor 做設計,我需要 Cursor 訂閱嗎？", "text": "你可以用 Cursor 帳號 / 訂閱,或帶上你自己的模型 keys（BYOK）。無論哪種,Open Design 都不會代理你的憑證 — 它們由你的 agent 直接使用。"}, {"name": "前端設計該選 Cursor 還是 Claude Code？", "text": "兩者都很強。Claude Code 以具體、理解程式碼庫的設計決策著稱;Cursor 的優勢在於它那條緊密的邊建邊看迴圈,附有編輯器內的即時預覽。許多團隊兩者並用 — Open Design 讓你在不更動設計工作流程的情況下切換 agent。"}, {"name": "我要怎麼把 Cursor 連到 Figma？", "text": "在 Cursor 中加上官方的 Figma MCP 伺服器,然後把一個 Figma frame 連結貼進對話,並請 Cursor 實作它。該伺服器會暴露真實的元件、變數與版面資料,讓生成的程式碼符合來源設計。"}, {"name": "我要怎麼避免那種千篇一律的「AI 流水線感」美學？", "text": "加上一個設計 skill、提供真實的 design tokens 與參考截圖、把品牌規則寫進 `.cursor/rules` 或 `AGENTS.md`,並在預覽中跨斷點驗證。Open Design 把這些做成一套嚴選的資源庫,讓你省下逐專案的設定。"}, {"name": "Open Design 跟 Cursor 或 Anysphere 有關係嗎？", "text": "沒有。Cursor 是 Anysphere 的產品;Open Design 是一個獨立的開源專案,以一級轉接器的形式支援它。Cursor 與 Anysphere 是 Anysphere, Inc. 的商標。"}, {"name": "我的檔案與憑證安全嗎？", "text": "安全 — Open Design 本機優先。你的檔案、產物與 DESIGN.md 都留在你自己的 repo 裡,你的 Cursor 或模型憑證由你的 agent 直接使用,絕不會經由 Open Design 伺服器轉送。"}], "ctaTitle": "用開放的方式，與 Cursor 一起做設計。", "ctaBody": "帶上你自己的 Cursor 帳號或模型 keys，所有檔案都留在本機，並為你早已在用的 agent 配上一套嚴選的設計資源庫。", "ctaActions": [{"label": "在 Open Design 裡使用 Cursor", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支援的 agent"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "用 OpenCode 做設計 — Open Design",
        description: "人們如何用 OpenCode 做 UI 與網頁設計 — design.md 檔案、UI/UX skills、Figma MCP — 以及 Open Design 如何把 OpenCode 變成本機優先、開源的設計 agent。",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "用 OpenCode 做設計。",
        lead: "OpenCode 是那個開源的終端機 AI coding agent。設計師在它上面綁上設計 skills 與 DESIGN.md 檔案來生成真實的 UI。Open Design 讓這成為一套結構化、開源的工作流程 — 帶上你的供應商 keys,一切都留在本機。",
        rich: {"heroCtaLead": "Open Design 把 OpenCode 變成一個本機優先、開源的設計 agent — 你用自己的供應商 key 選用任何模型、你的檔案,外加環繞其上的嚴選 skill 與設計系統資源庫。", "heroCtaActions": [{"label": "在 Open Design 裡使用 OpenCode", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode 是一個開源、終端機優先的 AI coding agent,並刻意做到模型無關:你帶上自己的供應商 key,在同一套工作流程背後跑你想跑的任何模型。這份開放性讓它天然適合作為設計工作的基底 — 但跟每個 agent 一樣,只有當你給它對的參考、skills 與一條驗證迴圈時,它才會產出好 UI。這是一份實用、端到端的指南,教你如何用 OpenCode 處理 UI、前端與設計系統工作,並把它接進 Open Design 的結構化設計工作流程。", "內容涵蓋 OpenCode 究竟是什麼、一個模型無關的開放 agent 為何很適合設計、如何從零開始設定、截圖轉 UI 的迴圈、AGENTS.md 與 MCP 如何擴展它、它與 Codex、Claude Code 和 Cursor 的比較、讓 AI 產出顯得平庸的常見陷阱,以及 Open Design 如何以一個開放、本機優先的設計層補上這道落差 — 這是天然的搭配,因為兩個專案都是開源且在你自己的機器上執行。"], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode 設計回饋迴圈:一個終端機 TUI agent、渲染 UI 的瀏覽器、工作區,並有一條回饋箭頭繞回", "caption": "核心迴圈:OpenCode 在終端機中打造 UI,在真實瀏覽器中渲染並驗證,再對齊你的參考逐步迭代 — 用你選的任何模型。"}, "tocLabel": "本頁內容", "toc": [{"id": "what-is-opencode", "label": "OpenCode 究竟是什麼"}, {"id": "why-design", "label": "為何一個開放、任意模型的 agent 適合設計"}, {"id": "setup", "label": "從零開始為設計設定 OpenCode"}, {"id": "screenshot-workflow", "label": "截圖轉 UI 的工作流程"}, {"id": "extend", "label": "AGENTS.md、MCP 與可分享的工作階段"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "陷阱與「AI 流水線感」的外觀"}, {"id": "open-design", "label": "在 Open Design 裡用 OpenCode 做設計"}, {"id": "faq", "label": "常見問題"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode 究竟是什麼", "blocks": [{"kind": "p", "text": "OpenCode 是一個為終端機打造的開源 AI coding agent,由 SST(Anomaly Innovations)背後的團隊維護。它會讀取你的儲存庫、執行指令、編輯檔案,並與一個大型語言模型對話 — 但跟綁定特定供應商的 agent 不同,它不自帶模型。你把它指向你想要的任何供應商與模型,並帶上你自己的 key。"}, {"kind": "p", "text": "它以終端機 UI(TUI)形式執行,在同一個引擎之上還有桌面應用程式與 IDE 擴充套件。底層它採用 client/server 架構,因此真正做事的 agent 與你操作它的介面是解耦的。兩個內建 agent — build 與 plan — 用 Tab 鍵切換。"}, {"kind": "steps", "items": [{"label": "模型無關", "body": "模型與供應商來自 models.dev 這個開放目錄。你在 opencode.json 中用一個 provider/model-id 字串設定它們,並能停用你不想載入的供應商 — 於是同一套設計工作流程可在 Anthropic、OpenAI、Google、OpenRouter、本機模型等等之上執行。"}, {"label": "指令檔", "body": "OpenCode 會讀取專案中的 AGENTS.md 檔案(那個跨工具標準,也與 CLAUDE.md 相容)來取得專案規則 — 這是把設計慣例寫進去的最自然位置。執行 /init 來產生一個。"}, {"label": "可擴展", "body": "它支援 LSP 整合、MCP 伺服器、佈景主題、快捷鍵與自訂指令,還有可分享的工作階段連結以利協作。"}]}, {"kind": "ul", "items": ["維護者：SST / Anomaly Innovations（開源專案）", "憑證：你自己的模型供應商 API key(s) — BYOK，不被供應商綁定", "授權：MIT，開源"]}]}, {"id": "why-design", "heading": "為何一個開放、任意模型的 agent 適合設計工作", "blocks": [{"kind": "p", "text": "OpenCode 不像供應商綁定的 agent 那樣有一個單一的「設計模型」 — 而這正是重點。因為它模型無關且開放,你可以在當下前端最強的那個模型上跑同一套設計工作流程,之後再換掉,或退而求其次用一個本機模型,這一切都不必更動你的設定。"}, {"kind": "p", "text": "但光靠選模型買不到品味。跟每個 coding agent 一樣,除非你給它約束,OpenCode 就會產出千篇一律的 UI。好的設計產出來自你提供的三項輸入。"}, {"kind": "steps", "items": [{"label": "一套設計系統", "body": "真實的 tokens、基礎元件與慣例,讓 agent 去重用,這樣產出才會符合品牌,而不是退回千篇一律的外觀。"}, {"label": "一個美學 skill", "body": "一個嚴選的 skill,落實真正的品味 — 節制的動效、品牌優先的層級、最多兩種字體與一種強調色 — 並讓 agent 在動工前先確立一個方向。"}, {"label": "具體的參考", "body": "實際的參考圖與多種狀態(桌面與行動裝置、hover、空狀態、載入中),而不是單單一張主視覺。"}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "圖示呈現設計系統、skill 與參考圖三者匯聚成優秀的設計產出", "caption": "品味來自你提供的三項輸入:一套設計系統、一個 skill,以及真實的參考圖 — 與你跑哪個模型無關。"}, {"kind": "p", "text": "這個道理是:OpenCode 給你模型自由,但品味仍來自一套嚴選的設計脈絡。Open Design 把這些輸入剛好打包好了,這正是兩者契合的原因 — 兩者都是開源且本機優先(下文詳述)。"}]}, {"id": "setup", "heading": "從零開始為設計工作設定 OpenCode", "blocks": [{"kind": "p", "text": "以下是從一台乾淨的機器,到一個能打造並驗證 UI 的 OpenCode 的完整路徑。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "五步設定流程：安裝、用你的供應商 key 驗證、設定 AGENTS.md、加上一個 skill、驗證", "caption": "設定順序：安裝 → 驗證（你的供應商 key）→ 設定 AGENTS.md → 加上一個 skill → 在真實瀏覽器中驗證。"}, {"kind": "steps", "items": [{"label": "把設計規則寫進去", "body": "把你的 tokens、基礎元件與慣例放進 AGENTS.md(或從中引用的一個 DESIGN.md),這樣產出才會符合品牌,而不是退回千篇一律的外觀。opencode.json 中的 instructions 選項可透過 glob 指向額外的規則檔。"}, {"label": "選一個有實力的模型", "body": "由於 OpenCode 模型無關,就為設計這一輪挑當下前端最強的那個 provider/model — 並讓你工作流程的其餘部分維持不變。"}]}]}, {"id": "screenshot-workflow", "heading": "截圖轉 UI 的工作流程", "blocks": [{"kind": "p", "text": "用任何 agent 槓桿最高的設計迴圈,都是把一張參考圖變成可運作的響應式 UI,並反覆迭代直到對齊。同一套五步形狀也適用於 OpenCode。"}, {"kind": "ol", "items": ["從你手上最清楚的視覺參考開始 — 並涵蓋多種狀態（桌面與行動裝置、hover、空狀態、載入中），而不是只有一張主視覺。", "提示要具體；含糊的提示會產出千篇一律的 UI。", "備好一套設計系統，並告訴 OpenCode tokens 與標準基礎元件放在哪裡（在 AGENTS.md 中）。", "跑一個 dev server，並讓 agent 在真實瀏覽器中渲染，依斷點調整尺寸來檢查結果。", "透過讓 OpenCode 把它的實作回頭與截圖比對來迭代 — 而不只是確認它能建置通過。"]}, {"kind": "p", "text": "在 TUI 中用 @ 來引用檔案,以模糊搜尋你的工作目錄;以開頭的 ! 行內執行 shell 指令;並用 / 指令來驅動動作。然後以具體約束來下提示:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "讓提示保持精簡聚焦,提交好的迭代並還原壞的迭代(還原時也告訴 OpenCode),讓每一輪都建立在乾淨的基礎上。"}]}, {"id": "extend", "heading": "AGENTS.md、MCP 與可分享的工作階段", "blocks": [{"kind": "p", "text": "有三個擴充點讓 OpenCode 在持續的設計工作上很實用,而這三者都能乾淨地對映到一套開放的設計工作流程。"}, {"kind": "steps", "items": [{"label": "AGENTS.md 規則", "body": "專案規則住在 repo 根目錄的一個 AGENTS.md 裡(或全域規則放在 ~/.config/opencode/AGENTS.md)。它是你設計慣例的長久落腳處,每次執行都會被讀取,並與其他 agent 使用的 CLAUDE.md 檔案相容。"}, {"label": "MCP 伺服器", "body": "OpenCode 同時支援本機(command)與遠端(URL)MCP 伺服器,設定在 mcp 鍵下 — 這是把設計脈絡與外部工具帶進來、且能跨 agent 通用(不只 OpenCode)的可攜方式。"}, {"label": "可分享的工作階段", "body": "/share 指令會為一段對話建立一個公開連結以利協作或審查,而 /unshare 則撤銷它 — 對於為一輪設計取得回饋很有用。"}]}, {"kind": "p", "text": "這些都是可攜、多 agent 的能力 — 正是 Open Design 為之打造、用來協調的那種東西,而非逐專案重新打造。"}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor 做設計", "blocks": [{"kind": "p", "text": "設計工作沒有唯一的贏家 — 每個 agent 各有所長,老練的團隊會把它們疊用。一個公允的總結:"}, {"kind": "table", "columns": ["Agent", "設計強項", "最適合"], "rows": [["OpenCode", "開源且模型無關；在一套終端機工作流程背後跑任何供應商", "BYOK 自由、模型切換、完全開放且本機優先的設定"], ["Codex", "搭配前端 skill 的出色視覺打磨；圖像理解", "委派的非同步、沙箱化建置、可攜的 AGENTS.md 規則"], ["Claude Code", "具體的設計決策（hex、間距、字型）與理解程式碼庫的 UX", "前端推理與大脈絡重構"], ["Cursor", "邊建邊看的視覺迴圈，附即時預覽與行內編輯", "在 IDE 內緊密的邊迭代邊觀察 UI 工作"]]}, {"kind": "p", "text": "社群一再得出的結論是:品味來自人類 — 它們全都在缺乏 skills、參考與約束時,退回千篇一律的美學。那才是真正要解決的問題 — 而它是設計工具形狀的,不是模型形狀的,這也正是為何像 OpenCode 這樣的開放 agent 與一個開放的設計層如此契合。"}]}, {"id": "pitfalls", "heading": "陷阱,以及如何避免「AI 流水線感」的外觀", "blocks": [{"kind": "p", "text": "對 AI 生成設計最常見的抱怨是它看起來很平庸 — 柔和漸層、漂浮面板、過大的圓角、戲劇化的陰影,一種「一看就知道是 AI 做的」的 Inter 加紫色調性。其他被回報的問題還包括行動版排版破版,以及指令滲漏進 UI 文案。這些都不是 OpenCode 獨有的;它們是任何 agent 在缺乏一套嚴選設計脈絡下執行時都會發生的。"}, {"kind": "steps", "items": [{"label": "加上一個美學 skill", "body": "一個嚴選的設計 skill 會迫使 agent 確立明確的方向,而非預設的外觀。"}, {"label": "在真實瀏覽器中驗證", "body": "跨斷點渲染並自我檢查,這樣排版才不會在行動版上悄悄破版。"}, {"label": "提供 tokens 與參考", "body": "真實的 design tokens 與參考截圖,是對產出品質最大的單一槓桿。"}, {"label": "把規則寫進 AGENTS.md", "body": "把「不要主視覺卡片、最多兩種字體、品牌優先的層級」這類風格規則,放在 agent 每次執行都會讀到的地方。"}]}, {"kind": "p", "text": "請注意,每一項緩解措施都是在給 agent 一套嚴選的設計脈絡 — 無論你跑哪個模型。逐專案、用手維護這套脈絡的苦工,正是 Open Design 替你省下的。"}]}, {"id": "open-design", "heading": "在 Open Design 裡用 OpenCode 做設計", "blocks": [{"kind": "p", "text": "Open Design 正是上述工作流程一再呼喚的那個開源設計層。它把 OpenCode 視為一級的轉接器,並用嚴選的 skill 與設計系統資源庫、結構化的渲染流程,以及一個本機桌面 UI 把它包起來 — 於是讓任何 agent 出色的那套設計脈絡,從第一次執行就在場,而不必每次都用手拼湊。兩個專案都是開源且本機優先,這讓這個搭配渾然天成。"}, {"kind": "ol", "items": ["安裝 Open Design，並選擇 OpenCode 作為你的 agent。", "用你自己的模型供應商 API key（BYOK）進行驗證 — 憑證留在你的機器上，絕不經由我們代理。", "挑任何供應商與模型，再加上一套設計系統與一個 skill，然後以一致的品味生成簡報、原型與著陸頁。", "每一份產物與 DESIGN.md 檔案都存在你自己的 repo 裡，而不是託管的雲端。"]}, {"kind": "p", "text": "同一個 OpenCode agent、同樣的模型自由 — 再加上環繞其上一套真正可攜、開源的設計工作流程。它本機優先且採用 Apache-2.0,因此你的工作與憑證都不會離開你的機器。"}]}], "faqTitle": "常見問題", "faq": [{"name": "OpenCode 真的能做設計工作嗎？", "text": "能 — 當脈絡裡有一個美學 skill、一套設計系統與真實參考圖時,OpenCode 能產出可上線品質的響應式 UI,並能在瀏覽器中驗證。因為它模型無關,你可以跑當下前端最強的那個模型。缺乏這套嚴選脈絡時,它就會傾向退回千篇一律的外觀,而那正是 Open Design 補上的落差。"}, {"name": "用 OpenCode 做設計時,我該用哪個模型？", "text": "你喜歡哪個都行 — OpenCode 透過 models.dev 做到供應商無關,因此你可以在同一套工作流程背後跑 Anthropic、OpenAI、Google、OpenRouter 或本機模型,並隨時切換。設計產出的品質,取決於你的 skill、設計系統與參考的程度,遠勝於單靠模型。"}, {"name": "Open Design 是 OpenCode(SST)團隊做的嗎？", "text": "不是。Open Design 是一個獨立的開源專案,把 OpenCode 整合為一個 agent。它以一套本機優先、開放的 skill 與設計系統資源庫,補足 OpenCode。"}, {"name": "要用 OpenCode 做設計,我需要特別的訂閱嗎？", "text": "不需要 — OpenCode 是 BYOK。你帶上自己的模型供應商 API key,而 Open Design 絕不會代理你的憑證。沒有供應商綁定。"}, {"name": "前端設計該選 OpenCode、Codex 還是 Claude Code？", "text": "都很強,而許多團隊會把它們疊用。OpenCode 的優勢是完全開源且模型無關;Codex 擅長委派、沙箱化的建置;Claude Code 以具體、理解程式碼庫的設計決策著稱。Open Design 讓你在不更動設計工作流程的情況下切換 agent。"}, {"name": "我要怎麼為設計脈絡擴展 OpenCode？", "text": "把規則寫進 AGENTS.md、在 mcp 鍵下加上 MCP 伺服器以取得可攜的工具與設計脈絡,並用可分享的工作階段來做審查。Open Design 提供一套嚴選的 skill 與設計系統資源庫,讓你省下逐專案的設定。"}, {"name": "Open Design 跟 OpenCode 或 SST 有關係嗎？", "text": "沒有。OpenCode 是一個由 SST(Anomaly Innovations)維護的開源專案;Open Design 是一個獨立的開源專案,以一級轉接器的形式支援它。"}, {"name": "我的檔案與憑證安全嗎？", "text": "安全 — Open Design 本機優先。你的檔案、產物與 DESIGN.md 都留在你自己的 repo 裡,你的模型供應商憑證由你的 agent 直接使用,絕不會經由 Open Design 伺服器轉送。"}], "ctaTitle": "用開放的方式，與 OpenCode 一起做設計。", "ctaBody": "帶上你自己的模型供應商 key，所有檔案都留在本機，並為你早已在用的開放 agent 配上一套嚴選的設計資源庫。", "ctaActions": [{"label": "在 Open Design 裡使用 OpenCode", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上加星", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下載桌面應用程式", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支援的 agent"},
      },
    },
    'ja': {
      'claude-code': {
        ...en['claude-code']!,
        title: "デザインのための Claude Code — Open Design",
        description: "デザイナーが UI と Web デザインに Claude Code をどう使うか、そして Open Design がそれを本物のデザインエージェントへと変える方法 — ローカルファースト、BYOK、厳選された skill とデザインシステムのライブラリ付き。",
        breadcrumb: "Claude Code",
        label: "エージェント · Claude Code",
        heading: "デザインのための Claude Code。",
        lead: "Claude Code は Anthropic のターミナル型コーディングエージェントです。すでに多くの人が UI、デザインシステム、ランディングページの構築に使っています。Open Design はそれを本物のデザインワークフローへと接続します — あなたの Anthropic キーや Claude サブスクリプションを使い、すべてのファイルをローカルに保ちます。",
        rich: {"heroCtaLead": "Open Design は Claude Code をローカルファーストでオープンソースのデザインエージェントへと変えます — あなたの Anthropic キーや Claude サブスクリプション、あなたのファイル、そしてそれを取り巻く厳選された skill とデザインシステムのライブラリ。", "heroCtaActions": [{"label": "Open Design 内で Claude Code を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code は、フロントエンドのセンスが最も優れたコーディングエージェントとして広く評価されています — インターフェースについて並外れた具体性で推論し、正確な hex 値、余白、タイプスケールを指定し、大規模なコードベース全体にわたって筋を見失うことなく UI をリファクタリングします。しかし、デフォルトのままでは、デザインシステム、skills、本物のリファレンスを渡さない限り、ありきたりな見た目へと流れてしまいがちです。本稿は、UI・フロントエンド・デザインシステムの作業に Claude Code を使い、それを Open Design で構造化されたワークフローへ組み込むための、実践的でエンドツーエンドのガイドです。", "Claude Code が実際に何であるか、なぜフロントエンドに強いのか、ゼロからのセットアップ方法、CLAUDE.md と Skills のワークフロー、公式の Figma 往復連携、Codex や Cursor との比較、AI の出力をありきたりに見せてしまう落とし穴、そして Open Design がオープンでローカルファーストなデザインレイヤーとしてそのギャップをどう埋めるかを扱います。"], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code のデザインフィードバックループ: 具体的なデザイン判断を下すターミナルエージェント、UI を描画するブラウザ、ワークスペース、そして戻ってくるフィードバックの矢印", "caption": "中核となるループ: Claude Code がターミナルで具体的な UI 判断を推論し、実際のブラウザで描画・検証し、あなたのリファレンスへと収束させていきます。"}, "tocLabel": "このページの内容", "toc": [{"id": "what-is-claude-code", "label": "Claude Code とは実際に何か"}, {"id": "why-design", "label": "なぜ Claude Code はデザインが得意なのか"}, {"id": "setup", "label": "デザイン向けに Claude Code をセットアップする（ゼロから）"}, {"id": "skills-workflow", "label": "CLAUDE.md と Skills のワークフロー"}, {"id": "figma", "label": "Claude Code + Figma の往復連携"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "落とし穴と「AI スロップ」っぽい見た目"}, {"id": "open-design", "label": "Open Design で Claude Code を使ってデザインする"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code とは実際に何か", "blocks": [{"kind": "p", "text": "Claude Code は Anthropic のエージェント型コーディングツールです。コードベースを読み、ファイルを編集し、コマンドを実行し、開発ツールと連携します — 単に行を補完するのではなく、自然言語のタスクから計画・記述・検証を行います。"}, {"kind": "p", "text": "同じエンジンを共有する複数の面で提供されます: ターミナル CLI、VS Code・Cursor・JetBrains 向けの IDE 拡張機能、ビジュアルな差分レビューを備えたデスクトップアプリ、そして長時間実行タスク向けの Web 体験。あなたの CLAUDE.md ファイル、設定、MCP サーバーはそのすべてに引き継がれます。"}, {"kind": "steps", "items": [{"label": "指示ファイル", "body": "Claude Code はセッション開始時にプロジェクトルートの CLAUDE.md ファイルを読み込みます — デザインの規約、tokens、レビューのチェックリストを記述する自然な場所です。"}, {"label": "Skills", "body": "Agent Skills は、繰り返し使う指示・スクリプト・リソースをパッケージ化し、Claude がオンデマンドで読み込みます。Anthropic 公式の Frontend Design skill によるセンスの付与も含まれます。"}, {"label": "計画とサブエージェント", "body": "実行前に計画を立て、タスクの異なる部分を並行して進めるサブエージェントを生成できます。これにより大規模な UI リファクタリングの一貫性が保たれます。"}]}, {"kind": "ul", "items": ["ベンダー: Anthropic", "認証情報: Anthropic API キー（BYOK、Console 経由）または Claude サブスクリプション（Pro / Max）", "提供面: ターミナル CLI、VS Code / Cursor / JetBrains 拡張機能、デスクトップアプリ、Web"]}]}, {"id": "why-design", "heading": "なぜ Claude Code はデザインが得意なのか", "blocks": [{"kind": "p", "text": "コーディングエージェントの中でも、Claude Code はフロントエンド作業のセンスに定評があります。それにはいくつかの理由があります。"}, {"kind": "steps", "items": [{"label": "曖昧でなく具体的な判断", "body": "Claude Code は、曖昧にごまかすのではなく具体的な選択 — 正確な hex 値、余白スケール、タイプランプ、コンポーネント階層 — にコミットする傾向があります。これこそが本物のインターフェースとプレースホルダーを分けるものです。"}, {"label": "コードベースを踏まえた推論", "body": "大きな作業コンテキストを活かして多数のファイルにまたがる UI を一度にリファクタリングし、その場限りのスタイルを発明するのではなく、既存のコンポーネントや tokens を再利用します。"}, {"label": "公式のフロントエンド skill", "body": "Anthropic は Frontend Design skill を提供しており、Claude にまずデザインの方向性を書かせ、ありきたりなシステムフォントや予測可能な紫のグラデーションから意図的に距離を取らせます。"}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "デザインシステム、skill、リファレンス画像が良いデザイン出力へと収束する様子を示す図", "caption": "センスはあなたが与える 3 つの入力から生まれます: デザインシステム、skill、本物のリファレンス画像。"}, {"kind": "p", "text": "教訓は Anthropic が自社モデルについて語るのと同じです: Claude はデフォルトではセンスを持っていません — 放っておけば Web デザインの統計的な中心（Inter、紫のグラデーション、柔らかい影）へと収束します。制約を与えたときに良いデザインを生み出します。Open Design はまさにそれらの入力をパッケージ化しており、だからこそ両者は噛み合うのです（詳細は後述）。"}]}, {"id": "setup", "heading": "デザイン作業のために Claude Code をゼロからセットアップする", "blocks": [{"kind": "p", "text": "まっさらなマシンから、UI を構築・検証できる Claude Code までの全行程はこちらです。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "5 ステップのセットアップフロー: インストール、認証、CLAUDE.md 設定、skill 追加、検証", "caption": "セットアップの手順: インストール → 認証 → CLAUDE.md を設定 → Frontend Design skill を追加 → ブラウザ検証を有効化。"}, {"kind": "steps", "items": [{"label": "デザインルールを記述する", "body": "tokens、プリミティブ、規約を CLAUDE.md に書き、Claude にそれを参照させましょう。そうすれば出力がありきたりな見た目に落ち着かず、ブランドに沿ったものになります。"}, {"label": "ブラウザ検証を追加する", "body": "Playwright や Chrome MCP を接続し、Claude が実際のブラウザで描画して、ビルドが通ることだけを確認するのではなく、ブレークポイントをまたいで出力を検証するようにします。"}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md と Skills のワークフロー", "blocks": [{"kind": "p", "text": "Claude Code で最も効果の高いデザインのループは、本物のリファレンスとあなたのデザインコンテキストを与え、UI が一致するまで反復することです — CLAUDE.md と Skills が制約を運んでくれるので、プロンプトごとに説明し直す必要がありません。"}, {"kind": "ol", "items": ["手元にある最も明確なビジュアルリファレンスから始めましょう — そして 1 枚のヒーローショットだけでなく、複数の状態（デスクトップとモバイル、ホバー、空、ローディング）を含めます。", "プロンプトでは具体的に。曖昧なプロンプトは、強力なエージェントを使ってもありきたりな UI を生みます。", "デザインシステムと規約を CLAUDE.md に保ち、tokens と正規のプリミティブがどこにあるかを Claude に伝えます。", "Frontend Design skill を追加し、コードを書く前に Claude が本物の美的方向性にコミットするようにします。", "ブラウザ検証を接続し、Claude が描画し、ブレークポイントへリサイズし、リファレンスと照合し直す — 単にビルドが通ることを確認するだけにしないようにします。"]}, {"kind": "p", "text": "リファレンス画像をセッションに投入し、具体的な制約を添えてプロンプトを出します:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "並行して dev サーバーを動かし、プロンプトを小さく焦点を絞って保ち、良い反復はコミットし、悪い反復は元に戻す（戻したことを Claude に伝える）ことで、各パスがクリーンなベースの上に積み上がるようにします。大きなリファクタリングではプランモードを使い、ファイルが変更される前にアプローチをレビューできるようにします。"}]}, {"id": "figma", "heading": "Claude Code + Figma: デザイン ↔ コードの往復", "blocks": [{"kind": "p", "text": "2026 年 2 月、Anthropic と Figma は Figma MCP サーバーを介した第一級の双方向連携を提供しました。これは両方向で機能します。"}, {"kind": "steps", "items": [{"label": "デザイン → コード", "body": "Figma でフレームを選択するか、リンクを Claude Code に貼り付けてデザインコンテキストを取り込み、既存のコンポーネントライブラリを使って実装するよう依頼します。Code Connect が出力を実際のコンポーネントと整合させます。"}, {"label": "コード → デザイン", "body": "機能をブラウザで構築・プレビューし、「これを Figma に送って」と言えば、動作中の UI を編集可能な Figma レイヤーとして取り込みます — 画面全体でも、選択した要素だけでも可能です。"}]}, {"kind": "p", "text": "claude plugin install figma@claude-plugins-official で一度インストールすれば使えます（Dev Mode MCP には有料の Figma プランが必要です）。同じ Figma MCP は Claude Code、Codex、Cursor、VS Code で利用でき — まさに Open Design が編成するために作られた、ポータブルでマルチエージェントな機能です。"}]}, {"id": "vs", "heading": "デザインにおける Claude Code vs Codex vs Cursor", "blocks": [{"kind": "p", "text": "デザイン作業に唯一の勝者は存在しません — 各エージェントには異なる強みがあり、経験豊富なチームはそれらを重ねて使います。公平にまとめると:"}, {"kind": "table", "columns": ["エージェント", "デザインの強み", "適した用途"], "rows": [["Claude Code", "具体的なデザイン判断（hex、余白、タイプ）とコードベースを踏まえた UX 推論", "フロントエンドの推論と大規模コンテキストのリファクタリング"], ["Codex", "高いビジュアルの仕上がりと画像理解力、サンドボックス化された非同期ビルド", "委任された非同期ビルドとポータブルな AGENTS.md ルール"], ["Cursor", "ライブプレビューとインライン編集を備えた、作って見るビジュアルループ", "IDE 内での緊密な反復・観察型の UI 作業"]]}, {"kind": "p", "text": "コミュニティで繰り返される結論は、センスは人間から生まれるということです: 3 つとも、skills・リファレンス・制約がなければありきたりな美意識へと落ち着きます。それこそが解くべき本当の問題であり — それはモデルの形ではなく、デザインツールの形をしています。"}]}, {"id": "pitfalls", "heading": "落とし穴、そして「AI スロップ」っぽい見た目を避ける方法", "blocks": [{"kind": "p", "text": "Claude Code のセンスへの定評をもってしても、AI 生成デザインへの最もよくある不満は、ありきたりに見えるというものです — Inter フォント、白地に紫のグラデーション、柔らかい影、過大な角丸、「いかにも AI が作りました」と叫ぶような美意識。Anthropic 自身もこれを分布的収束のせいだとしています: 無難な選択が Web の学習データを支配しているのです。ほかにも、モバイルレイアウトの崩れや、指示が UI のコピーに漏れ出す問題が報告されています。"}, {"kind": "steps", "items": [{"label": "Frontend Design skill をインストールする", "body": "Claude に本物の方向性へコミットさせ、AI が使いすぎているフォントやグラデーションを明示的に避けさせます。"}, {"label": "ブラウザ検証を有効化する", "body": "Claude にブレークポイントをまたいで描画と自己チェックをさせ、レイアウトがモバイルで黙って崩れないようにします。"}, {"label": "tokens とリファレンスを供給する", "body": "本物のデザイン tokens とリファレンスのスクリーンショットは、出力品質に対する最大の単一のレバーです。"}, {"label": "ルールを CLAUDE.md に記述する", "body": "「ヒーローカードなし、書体は最大 2 つ、ブランド優先の階層」といったスタイルルールを、エージェントが毎回読む場所に置きます。"}]}, {"kind": "p", "text": "どの対策も、エージェントに厳選されたデザインコンテキストを与えることが要だと気づくでしょう。そのコンテキストをプロジェクトごとに手作業で維持する手間こそ、Open Design が取り除くものです。"}]}, {"id": "open-design", "heading": "Open Design の中で Claude Code を使ってデザインする", "blocks": [{"kind": "p", "text": "Open Design は、上記のワークフローが繰り返し求めてくるオープンソースのデザインレイヤーです。Claude Code を第一級のアダプターとして扱い、厳選された skill とデザインシステムのライブラリ、構造化されたレンダーパイプライン、ローカルなデスクトップ UI でそれを包みます — そのため、Claude Code を優れたものにするデザインコンテキストが、毎回手作業で組み立てるのではなく、最初の実行から揃っています。"}, {"kind": "ol", "items": ["Open Design をインストールし、エージェントとして Claude Code を選びます。", "Anthropic API キー（BYOK）または Claude サブスクリプションで認証します — 認証情報はあなたのマシンに留まり、私たちを経由してプロキシされることは決してありません。", "デザインシステムと skill を選び、一貫したセンスでデッキ、プロトタイプ、ランディングページを生成します。", "あらゆる成果物と DESIGN.md ファイルは、ホスト型クラウドではなくあなた自身のリポジトリに置かれます。"]}, {"kind": "p", "text": "同じ Claude Code エージェント、同じキー — それに加えて、それを取り巻く本物でポータブルなオープンソースのデザインワークフロー。ローカルファーストで Apache-2.0 なので、あなたの作業も認証情報も、マシンの外へ出ることはありません。"}]}], "faqTitle": "よくある質問", "faq": [{"name": "Claude Code はデザイン作業に向いていますか？", "text": "はい — フロントエンドのセンスが最も優れたコーディングエージェントとして広く評価されており、hex 値、余白、タイプスケールについて具体的でコードベースを踏まえた判断を下します。Frontend Design skill、デザインシステム、本物のリファレンス画像をコンテキストに与えれば、本番品質でレスポンシブな UI を生み出し、ブラウザで検証できます。そのコンテキストがなければありきたりな見た目に落ち着きがちで、それこそ Open Design が埋めるギャップです。"}, {"name": "Claude Code でデザインするには Claude サブスクリプションが必要ですか？", "text": "Anthropic API キー（BYOK、Console 経由）か Claude サブスクリプション（Pro / Max）のどちらでも使えます。いずれの場合も Open Design があなたの認証情報をプロキシすることはありません — それらはあなたのマシン上のエージェントが直接使います。"}, {"name": "フロントエンドデザインには Claude Code と Codex のどちらがよいですか？", "text": "どちらも強力です。Claude Code は具体的でコードベースを踏まえたデザイン判断とフロントエンドの推論で知られ、Codex は高いビジュアルの仕上がりを持ち、委任されたサンドボックス化ビルドに優れます。多くのチームが両方を使います — Open Design ならデザインワークフローを変えずにエージェントを切り替えられます。"}, {"name": "Claude Code を Figma に接続するには？", "text": "claude plugin install figma@claude-plugins-official で公式の Figma プラグインをインストールします。その後、デザインコンテキストを使って Figma フレームをコードで実装でき、「これを Figma に送って」で動作中の UI を編集可能な Figma フレームへ戻せます。Dev Mode MCP には有料の Figma プランが必要です。"}, {"name": "Skills と CLAUDE.md とは何ですか？", "text": "CLAUDE.md はプロジェクトルートにある markdown ファイルで、Claude Code がセッション開始時に読み込みます — デザインの規約を記述する場所です。Skills は繰り返し使う指示とリソースをパッケージ化し、Claude がオンデマンドで読み込みます。Anthropic 公式の Frontend Design skill も含まれます。Open Design は両方の厳選されたライブラリを提供するので、プロジェクトごとのセットアップを省けます。"}, {"name": "ありきたりな「AI スロップ」の美意識を避けるには？", "text": "Frontend Design skill をインストールし、本物のデザイン tokens とリファレンスのスクリーンショットを供給し、ブランドルールを CLAUDE.md に記述し、ブラウザ検証を有効にします。Open Design はこれらを厳選されたライブラリとして提供するので、プロジェクトごとのセットアップを省けます。"}, {"name": "Open Design は Anthropic と提携していますか？", "text": "いいえ。Claude Code は Anthropic の製品であり、Open Design はそれを第一級のアダプターとしてサポートする、独立したオープンソースプロジェクトです。Claude と Claude Code は Anthropic の商標です。"}, {"name": "私のファイルと認証情報は安全ですか？", "text": "はい — Open Design はローカルファーストで Apache-2.0 です。あなたのファイル、成果物、DESIGN.md はあなた自身のリポジトリに留まり、Anthropic の認証情報はあなたのエージェントが直接使い、Open Design のサーバーを経由してルーティングされることは決してありません。"}], "ctaTitle": "Claude Code で、オープンな方法でデザインしよう。", "ctaBody": "あなた自身の Anthropic キーや Claude サブスクリプションを持ち込み、すべてのファイルをローカルに保ち、すでに使っているエージェントを取り巻く厳選されたデザインライブラリを手に入れましょう。", "ctaActions": [{"label": "Open Design 内で Claude Code を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "対応エージェントをすべて見る"},
      },
      'codex': {
        ...en['codex']!,
        title: "デザインのための Codex — Open Design",
        description: "人々が UI と Web デザインに OpenAI Codex をどう使うか — Product Design プラグイン、Figma 連携、フロントエンドの skills — そして Open Design が Codex をローカルファーストでオープンソースのデザインエージェントへと変える方法。",
        breadcrumb: "Codex",
        label: "エージェント · Codex",
        heading: "デザインのための Codex。",
        lead: "Codex は OpenAI のコーディングエージェントです。Product Design プラグインと Figma 連携によって、本格的なデザインツールになりました。Open Design は Codex をオープンソースのデザインワークフローへと接続します — あなたの OpenAI キーや ChatGPT サブスクリプション、あなたのファイル、ローカルファースト。",
        rich: {"heroCtaLead": "Open Design は Codex をローカルファーストでオープンソースのデザインエージェントへと変えます — あなたの OpenAI キー、あなたのファイル、そしてそれを取り巻く厳選された skill とデザインシステムのライブラリ。", "heroCtaActions": [{"label": "Open Design 内で Codex を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex はコードジェネレーターとして始まりましたが、2026 年には本物のインターフェースをデザインする信頼できるツールになりました — 適切なリファレンス、skills、検証ループを与えればの話です。本稿は、UI・フロントエンド・デザインシステムの作業に Codex を使い、それを Open Design で構造化されたデザインワークフローへ組み込むための、実践的でエンドツーエンドのガイドです。", "今日の Codex が何であるか、なぜ急にフロントエンドが得意になったのか、ゼロからのセットアップ方法、スクリーンショットから UI へのループ、公式の Figma 往復連携、Cursor や Claude Code との比較、AI の出力をありきたりに見せてしまう落とし穴、そして Open Design がオープンでローカルファーストなデザインレイヤーとしてそのギャップをどう埋めるかを扱います。"], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex のデザインフィードバックループ: ターミナルエージェント、UI を描画するブラウザ、ワークスペース、そして戻ってくるフィードバックの矢印", "caption": "中核となるループ: Codex がターミナルで UI を構築し、実際のブラウザで描画・検証し、あなたのリファレンスへ向けて反復します。"}, "tocLabel": "このページの内容", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex とは実際に何か"}, {"id": "why-design", "label": "なぜ Codex は今やデザインが得意なのか"}, {"id": "setup", "label": "デザイン向けに Codex をセットアップする（ゼロから）"}, {"id": "screenshot-workflow", "label": "スクリーンショットから UI へのワークフロー"}, {"id": "figma", "label": "Codex + Figma の往復連携"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "落とし穴と「AI スロップ」っぽい見た目"}, {"id": "open-design", "label": "Open Design で Codex を使ってデザインする"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex とは実際に何か（そして何でないか）", "blocks": [{"kind": "p", "text": "まず、「Codex」を検索するほぼ全員がつまずく区別から。元々の OpenAI Codex は、初期の GitHub Copilot を支えた 2021 年のコード補完モデルで、2023 年に提供終了しました。本ページが扱うのはそれではありません。今日の Codex は OpenAI のエージェント型コーディングツールであり — 自然言語のタスクから計画・記述・実行・検証を行います。"}, {"kind": "p", "text": "現代の Codex は 4 つの面で提供されます: ターミナル CLI（Rust で書き直され、Apache-2.0 ライセンス）、VS Code・Cursor・Windsurf 向けの IDE 拡張機能、委任された非同期タスク向けのクラウド/Web 体験、そしてアプリ内ブラウザと Computer Use を備えたデスクトップアプリ。"}, {"kind": "steps", "items": [{"label": "デフォルトモデル", "body": "2026 年半ば時点で推奨モデルは gpt-5.5 で、gpt-5.4 は OpenAI がフロントエンドと computer use のために明示的に訓練したモデルです。"}, {"label": "指示ファイル", "body": "Codex はプロジェクト内の AGENTS.md ファイル（ツール横断の標準）をプロジェクトルールとして読み込みます — デザインの規約を記述する自然な場所です。"}, {"label": "サンドボックス", "body": "カーネルレベルのサンドボックス（デフォルトは workspace-write）で動作するため、UI を編集するエージェントがプロジェクトの外をさまようことはありません。"}]}, {"kind": "ul", "items": ["ベンダー: OpenAI", "認証情報: OpenAI API キー（BYOK）または ChatGPT サブスクリプション（Free / Go / Plus / Pro / Business / Enterprise）", "CLI のライセンス: Apache-2.0、オープンソース"]}]}, {"id": "why-design", "heading": "なぜ Codex は今やデザインが得意なのか", "blocks": [{"kind": "p", "text": "2026 年初頭、3 つの要素が重なり、Codex はありきたりなコードジェネレーターではなく本物のデザインツールになりました。"}, {"kind": "steps", "items": [{"label": "フロントエンド向けに訓練されたモデル", "body": "OpenAI は GPT-5.4 を投入しました。これはフロントエンドと computer use のために訓練された初の主力モデルで、デザインワークフロー全体で画像理解が大幅に向上し、自己検証も強化されています。最終アセットを確定する前に、ムードボードやビジュアルの選択肢を生成することさえできます。"}, {"label": "公式のフロントエンド skill", "body": "openai/skills カタログには、本物のセンスを徹底するフロントエンド skill が用意されています: カードレスなレイアウト、フルブリードのヒーロー、ブランド優先の階層、抑制されたモーション、最大 2 つの書体と 1 つのアクセントカラー — そして構築前に Codex にビジュアルのテーゼを書かせます。"}, {"label": "ブラウザ検証", "body": "Playwright skill を使えば、Codex は実際のブラウザを開き、ブレークポイントへリサイズし、ビルドが通ることだけを確認するのではなく、出力をリファレンスと照合し直します。"}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "デザインシステム、skill、リファレンス画像が良いデザイン出力へと収束する様子を示す図", "caption": "センスはあなたが与える 3 つの入力から生まれます: デザインシステム、skill、本物のリファレンス画像。"}, {"kind": "p", "text": "3 つすべての背後にある教訓: Codex はデフォルトではセンスを持っていません。制約 — デザインシステム、美的な skill、具体的なリファレンス — を与えたときに良いデザインを生み出します。Open Design はまさにそれらの入力をパッケージ化しており、だからこそ両者は噛み合うのです（詳細は後述）。"}]}, {"id": "setup", "heading": "デザイン作業のために Codex をゼロからセットアップする", "blocks": [{"kind": "p", "text": "まっさらなマシンから、UI を構築・検証できる Codex までの全行程はこちらです。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "5 ステップのセットアップフロー: インストール、認証、設定、skill インストール、検証", "caption": "セットアップの手順: インストール → 認証 → AGENTS.md を設定 → フロントエンド skill をインストール → ブラウザ検証を有効化。"}, {"kind": "steps", "items": [{"label": "デザインルールを記述する", "body": "tokens、プリミティブ、規約を AGENTS.md または DESIGN.md に書き、Codex にそれを参照させましょう。そうすれば出力がありきたりな見た目に落ち着かず、ブランドに沿ったものになります。"}, {"label": "適切な reasoning レベルを選ぶ", "body": "OpenAI は、最高設定よりも低〜中程度の reasoning レベルのほうがフロントエンドの結果が優れることが多いと指摘しています。"}]}]}, {"id": "screenshot-workflow", "heading": "スクリーンショットから UI へのワークフロー", "blocks": [{"kind": "p", "text": "Codex で最も効果の高いデザインのループは、リファレンス画像を動作するレスポンシブな UI に変え、一致するまで反復することです。OpenAI 自身のガイダンスは 5 つのステップに集約されます。"}, {"kind": "ol", "items": ["手元にある最も明確なビジュアルリファレンスから始めましょう — そして 1 枚のヒーローショットだけでなく、複数の状態（デスクトップとモバイル、ホバー、空、ローディング）を含めます。", "プロンプトでは具体的に。曖昧なプロンプトはありきたりな UI を生みます。", "デザインシステムを用意し、tokens と正規のプリミティブがどこにあるかを Codex に伝えます。", "Playwright のインタラクティブ skill を有効にし、Codex が実際のブラウザで描画し、ブレークポイントへリサイズするようにします。", "Codex に実装をスクリーンショットと照合し直させて反復します — 単にビルドが通ることを確認するだけにしないようにします。"]}, {"kind": "p", "text": "スクリーンショットをターミナルにドラッグするか image フラグで画像を渡し、具体的な制約を添えてプロンプトを出します:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "2 つ目のターミナルで dev サーバーを動かし、プロンプトを小さく焦点を絞って保ち、良い反復はコミットし、悪い反復は元に戻す（戻したことを Codex に伝える）ことで、各パスがクリーンなベースの上に積み上がるようにします。"}]}, {"id": "figma", "heading": "Codex + Figma: デザイン ↔ コードの往復", "blocks": [{"kind": "p", "text": "2026 年 2 月、OpenAI と Figma は公式パートナーシップを発表し、以前の Figma MCP ベータを第一級の双方向連携へと進化させました。これは両方向で機能します。"}, {"kind": "steps", "items": [{"label": "デザイン → コード", "body": "Figma でフレームの「link to selection」をコピーし、それを get_design_context とともに Codex に貼り付け、既存のコンポーネントライブラリを使って実装するよう依頼します。"}, {"label": "コード → デザイン", "body": "generate_figma_design ツール（「Code to Canvas」）は、ライブで動作中の UI を編集可能な Figma フレームへ戻します — 画面全体、選択した要素、ファイル全体のいずれでも可能です。"}]}, {"kind": "p", "text": "Figma MCP はリモートサーバーとして動作し、レート制限の対象外です。一度追加すれば、Codex、Claude Code、Cursor、VS Code などで利用できます — まさに Open Design が編成するために作られた、ポータブルでマルチエージェントな機能です。"}]}, {"id": "vs", "heading": "デザインにおける Codex vs Cursor vs Claude Code", "blocks": [{"kind": "p", "text": "デザイン作業に唯一の勝者は存在しません — 各エージェントには異なる強みがあり、経験豊富なチームはそれらを重ねて使います。公平にまとめると:"}, {"kind": "table", "columns": ["エージェント", "デザインの強み", "適した用途"], "rows": [["Codex", "GPT-5.4 + フロントエンド skill による高いビジュアルの仕上がり、画像理解", "委任された非同期ビルド、サンドボックス実行、ポータブルな AGENTS.md ルール"], ["Cursor", "ライブプレビューとインライン編集を備えた、作って見るビジュアルループ", "IDE 内での緊密な反復・観察型の UI 作業"], ["Claude Code", "具体的なデザイン判断（hex、余白、タイプ）とコードベースを踏まえた UX", "フロントエンドの推論と大規模コンテキストのリファクタリング"]]}, {"kind": "p", "text": "コミュニティで繰り返される結論は、センスは人間から生まれるということです: 3 つとも、skills・リファレンス・制約がなければありきたりな美意識へと落ち着きます。それこそが解くべき本当の問題であり — それはモデルの形ではなく、デザインツールの形をしています。"}]}, {"id": "pitfalls", "heading": "落とし穴、そして「AI スロップ」っぽい見た目を避ける方法", "blocks": [{"kind": "p", "text": "Codex 生成デザインへの最もよくある不満は、ありきたりに見えるというものです — 柔らかいグラデーション、浮いたパネル、過大な角丸、ドラマチックな影、「いかにも AI が作りました」と叫ぶような Inter と紫の雰囲気。ほかにも、モバイルレイアウトの崩れ、指示が UI のコピーに漏れ出すこと、利用上限にすぐ達することが報告されています。"}, {"kind": "steps", "items": [{"label": "フロントエンド skill をインストールする", "body": "厳選された美的な skill は、Codex にデフォルトの見た目ではなく本物の方向性へコミットさせます。"}, {"label": "Playwright 検証を有効化する", "body": "Codex にブレークポイントをまたいで描画と自己チェックをさせ、レイアウトがモバイルで黙って崩れないようにします。"}, {"label": "tokens とリファレンスを供給する", "body": "本物のデザイン tokens とリファレンスのスクリーンショットは、出力品質に対する最大の単一のレバーです。"}, {"label": "ルールを AGENTS.md に記述する", "body": "「ヒーローカードなし、書体は最大 2 つ、ブランド優先の階層」といったスタイルルールを、エージェントが毎回読む場所に置きます。"}]}, {"kind": "p", "text": "どの対策も、エージェントに厳選されたデザインコンテキストを与えることが要だと気づくでしょう。そのコンテキストをプロジェクトごとに手作業で維持する手間こそ、Open Design が取り除くものです。"}]}, {"id": "open-design", "heading": "Open Design の中で Codex を使ってデザインする", "blocks": [{"kind": "p", "text": "Open Design は、上記のワークフローが繰り返し求めてくるオープンソースのデザインレイヤーです。Codex を第一級のアダプターとして扱い、厳選された skill とデザインシステムのライブラリ、構造化されたレンダーパイプライン、ローカルなデスクトップ UI でそれを包みます — そのため、Codex を優れたものにするデザインコンテキストが、毎回手作業で組み立てるのではなく、最初の実行から揃っています。"}, {"kind": "ol", "items": ["Open Design をインストールし、エージェントとして Codex を選びます。", "OpenAI API キー（BYOK）または ChatGPT サブスクリプションで認証します — 認証情報はあなたのマシンに留まり、私たちを経由してプロキシされることは決してありません。", "デザインシステムと skill を選び、一貫したセンスでデッキ、プロトタイプ、ランディングページを生成します。", "あらゆる成果物と DESIGN.md ファイルは、ホスト型クラウドではなくあなた自身のリポジトリに置かれます。"]}, {"kind": "p", "text": "同じ Codex エージェント、同じキー — それに加えて、それを取り巻く本物でポータブルなオープンソースのデザインワークフロー。ローカルファーストで Apache-2.0 なので、あなたの作業も認証情報も、マシンの外へ出ることはありません。"}]}], "faqTitle": "よくある質問", "faq": [{"name": "OpenAI Codex は本当にデザイン作業ができますか？", "text": "はい — フロントエンド skill、デザインシステム、本物のリファレンス画像をコンテキストに与えれば、Codex（特に GPT-5.4）は本番品質でレスポンシブな UI を生み出し、ブラウザで検証できます。そのコンテキストがなければありきたりな見た目に落ち着きがちで、それこそ Open Design が埋めるギャップです。"}, {"name": "これは OpenAI Codex の Product Design プラグインですか？", "text": "いいえ。Open Design は Codex をエージェントとして統合する、独立したオープンソースプロジェクトです。OpenAI 自身のツールを、ローカルファーストでオープンな skill とデザインシステムのライブラリで補完します。"}, {"name": "Codex でデザインするには ChatGPT サブスクリプションが必要ですか？", "text": "OpenAI API キー（BYOK）か ChatGPT サブスクリプションのどちらでも使えます。ChatGPT でのサインインのほうが一般的に上限が寛大ですが、いずれの場合も Open Design があなたの認証情報をプロキシすることはありません。"}, {"name": "フロントエンドデザインには Codex と Claude Code のどちらがよいですか？", "text": "どちらも強力です。Claude Code は具体的でコードベースを踏まえたデザイン判断で知られ、Codex は GPT-5.4 以降の高いビジュアルの仕上がりを持ち、委任されたサンドボックス化ビルドに優れます。多くのチームが両方を使います — Open Design ならデザインワークフローを変えずにエージェントを切り替えられます。"}, {"name": "Codex を Figma に接続するには？", "text": "公式の Figma MCP サーバーを追加します（codex mcp add figma --url https://mcp.figma.com/mcp）。その後、get_design_context で Figma フレームをコードで実装でき、generate_figma_design で動作中の UI を編集可能な Figma フレームへ戻せます。"}, {"name": "ありきたりな「AI スロップ」の美意識を避けるには？", "text": "フロントエンド skill をインストールし、本物のデザイン tokens とリファレンスのスクリーンショットを供給し、ブランドルールを AGENTS.md に記述し、Playwright 検証を有効にします。Open Design はこれらを厳選されたライブラリとして提供するので、プロジェクトごとのセットアップを省けます。"}, {"name": "Open Design は OpenAI と提携していますか？", "text": "いいえ。Codex は OpenAI の製品であり、Open Design はそれを第一級のアダプターとしてサポートする、独立したオープンソースプロジェクトです。OpenAI と Codex は OpenAI の商標です。"}, {"name": "私のファイルと認証情報は安全ですか？", "text": "はい — Open Design はローカルファーストです。あなたのファイル、成果物、DESIGN.md はあなた自身のリポジトリに留まり、OpenAI の認証情報はあなたのエージェントが直接使い、Open Design のサーバーを経由してルーティングされることは決してありません。"}], "ctaTitle": "Codex で、オープンな方法でデザインしよう。", "ctaBody": "あなた自身の OpenAI キーを持ち込み、すべてのファイルをローカルに保ち、すでに使っているエージェントを取り巻く厳選されたデザインライブラリを手に入れましょう。", "ctaActions": [{"label": "Open Design 内で Codex を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "対応エージェントをすべて見る"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "デザイナーのための Cursor — Open Design",
        description: "デザイナーが UI と Web デザインに Cursor をどう使うか — Design Mode、Figma からコードへ、Figma MCP — そして Open Design が Cursor をローカルファーストでオープンソースのデザインエージェントへと変える方法。",
        breadcrumb: "Cursor",
        label: "エージェント · Cursor",
        heading: "デザイナーのための Cursor。",
        lead: "Cursor は AI コードエディタで、いまやビジュアルな Design Mode を備えています。デザイナーはこれを使い、ポイントして描くことで UI を編集し、Figma をコードに変換します。Open Design は Cursor Agent をオープンソースのデザインワークフローへと接続し、あなたのファイルをローカルに保ちます。",
        rich: {"heroCtaLead": "Open Design は Cursor をローカルファーストでオープンソースのデザインエージェントへと変えます — あなたの Cursor アカウントやモデルキー、あなたのファイル、そしてそれを取り巻く厳選された skill とデザインシステムのライブラリ。", "heroCtaActions": [{"label": "Open Design 内で Cursor を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor は AI ファーストのコードエディタで、「作って描画されるのを見る」を UI を出荷するデフォルトの方法にしました。Agent モード、インライン編集、エディタ内プレビュー、MCP 経由の Figma により、本物のデザインツールになりました — 適切なリファレンス、ルール、検証ループを与えればの話です。本稿は、UI・フロントエンド・デザインシステムの作業に Cursor を使い、それを Open Design で構造化されたデザインワークフローへ組み込むための、実践的でエンドツーエンドのガイドです。", "Cursor が実際に何であるか、なぜその緊密な反復・観察ループがデザインに向いているのか、ゼロからのセットアップ方法、スクリーンショットとプレビューから UI へのループ、MCP 経由の Figma 往復連携、Codex や Claude Code との比較、AI の出力をありきたりに見せてしまう落とし穴、そして Open Design がオープンでローカルファーストなデザインレイヤーとしてそのギャップをどう埋めるかを扱います。"], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor のデザイン収束: 左にエディタ、中央に Cursor マークを中心とした厳選された skill とデザインシステムのハブ、右に描画された UI", "caption": "中核となる発想: Cursor がエディタ内で UI を編集・描画する一方、厳選されたデザインハブが、出力を意図的に見せるシステム・skills・リファレンスを供給します。"}, "tocLabel": "このページの内容", "toc": [{"id": "what-is-cursor", "label": "Cursor とは実際に何か"}, {"id": "why-design", "label": "なぜ Cursor はデザインが得意なのか"}, {"id": "setup", "label": "デザイン向けに Cursor をセットアップする（ゼロから）"}, {"id": "preview-workflow", "label": "プレビューから UI へのワークフロー"}, {"id": "figma", "label": "MCP 経由の Cursor + Figma"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "落とし穴と「AI スロップ」っぽい見た目"}, {"id": "open-design", "label": "Open Design で Cursor を使ってデザインする"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor とは実際に何か", "blocks": [{"kind": "p", "text": "Cursor は Anysphere が開発した AI ファーストのコードエディタです。VS Code のフォークなので、見慣れたエディタ、拡張機能、キーバインドはそのままに、プロジェクト全体を読み、複数のファイルを編集し、コマンドを実行し、あなたをループに入れて反復できる AI エージェントを中心にワークフローを作り直しています。"}, {"kind": "p", "text": "デザイン作業にとって重要な面は、Agent モード（成果を記述すると Cursor がファイルをまたいで計画・編集します）、素早い微調整のためのインライン編集と Tab 補完、ウィンドウを離れずに動作中の UI を見られるエディタ内プレビュー/ブラウザ、そしてライブの Figma ファイルのような外部コンテキストを取り込める MCP サポートです。"}, {"kind": "steps", "items": [{"label": "プロジェクトルール", "body": "Cursor はプロジェクトの指示ファイルを読み込みます — `.cursor/rules` 配下のバージョン管理された `.mdc` ルールと、プレーンな `AGENTS.md` — そのため、エージェントが毎回読む場所にデザインの規約を記述できます。"}, {"label": "モデル", "body": "Cursor はモデルに柔軟です: サブスクリプション経由でフロンティアモデルを提供し、独自のモデルキーの持ち込みもサポートするので、同じエディタワークフローの背後にあるエンジンを選べます。"}, {"label": "MCP", "body": "Model Context Protocol を話すので、外部サーバー — 最も関連性が高いのは Figma MCP サーバー — がエージェントの第一級のコンテキストになります。"}]}, {"kind": "ul", "items": ["ベンダー: Anysphere", "認証情報: Cursor アカウント / サブスクリプション（Hobby / Pro / Business）または独自のモデルキー（BYOK）", "形態: エディタ内エージェントとプレビューを備えた AI ファーストのコードエディタ（VS Code フォーク）"]}]}, {"id": "why-design", "heading": "なぜ Cursor はデザインが得意なのか", "blocks": [{"kind": "p", "text": "Cursor のデザイン上の強みは単一の機能ではありません — 作って見るループの緊密さです。3 つの要素が、ありきたりなコードジェネレーターではなくデザインツールのように感じさせます。"}, {"kind": "steps", "items": [{"label": "緊密な反復・観察ループ", "body": "プロンプトを出すと Cursor がファイルをまたいで編集し、エディタ内プレビューが結果を即座に描画します — そのため、別のターミナルとブラウザを往復するのではなく、数秒で余白、階層、モーションを調整できます。"}, {"label": "直接的なビジュアル編集", "body": "チャットを超えて、Cursor はプレビュー内で要素を選択してスタイルを微調整させてくれるので、小さなビジュアル修正がコードの発掘ではなくデザイン編集のように感じられます。"}, {"label": "プロジェクトルールと MCP コンテキスト", "body": "`.cursor/rules`（または `AGENTS.md`）と Figma MCP サーバーを使えば、エージェントは推測ではなく、あなたの tokens、コンポーネント、実際のデザイン仕様に対して作業します。"}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "デザインシステム、skill、リファレンス画像が良いデザイン出力へと収束する様子を示す図", "caption": "センスはあなたが与える 3 つの入力から生まれます: デザインシステム、skill、本物のリファレンス画像。"}, {"kind": "p", "text": "教訓はどのエージェントが教えるのと同じです: Cursor はデフォルトではセンスを持っていません。制約 — デザインシステム、美的な skill、具体的なリファレンス — を与えたときに良いデザインを生み出します。Open Design はまさにそれらの入力をパッケージ化しており、だからこそ両者は噛み合うのです（詳細は後述）。"}]}, {"id": "setup", "heading": "デザイン作業のために Cursor をゼロからセットアップする", "blocks": [{"kind": "p", "text": "まっさらなマシンから、デザインシステムに対して UI を構築・プレビュー・検証できる Cursor までの全行程はこちらです。"}, {"kind": "ol", "items": ["cursor.com から Cursor をインストールし、Cursor アカウントでサインインするか、設定で独自のモデルキー（BYOK）を構成します。", "プロジェクトを開き、チャット / Agent パネルでモデルを選びます。", "プロジェクトルールを追加します: 構造化されたグロブスコープの規約には `.cursor/rules/*.mdc` を、シンプルで読みやすい指示にはプレーンな `AGENTS.md` を作成します。", "Figma MCP サーバーを接続して（任意）、エージェントがライブのデザインコンテキストを読めるようにします。", "dev サーバーを動かし、エディタ内プレビューを使って反復しながら UI を見て検証します。"]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "5 ステップのセットアップフロー: インストール、認証、ルール設定、skill 追加、検証", "caption": "セットアップの手順: インストール → 認証 → プロジェクトルールを設定 → skill を追加 → プレビュー検証を有効化。"}, {"kind": "p", "text": "最小限のプロジェクトルールファイルがあれば、エージェントはありきたりな見た目に落ち着くのではなくブランドに沿ってデザインします。Cursor が毎回読む場所に置きましょう:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "デザインルールを記述する", "body": "tokens、プリミティブ、規約を `.cursor/rules` または `AGENTS.md` に書き、Cursor にそれを参照させましょう。そうすれば出力がありきたりな見た目に落ち着かず、ブランドに沿ったものになります。"}, {"label": "プロンプトを小さく保つ", "body": "Cursor の緊密なループは焦点を絞った依頼に報いてくれます — 一度に 1 つのコンポーネントや状態を反復し、パスの合間にプレビューを見ましょう。"}]}]}, {"id": "preview-workflow", "heading": "プレビューから UI へのワークフロー", "blocks": [{"kind": "p", "text": "Cursor で最も効果の高いデザインのループは、リファレンスを動作するレスポンシブな UI に変え、一致するまでエディタ内で反復することです — 推測する代わりに、ずっとライブプレビューを見ながら進めます。"}, {"kind": "ol", "items": ["手元にある最も明確なビジュアルリファレンスから始めましょう — そして 1 枚のヒーローショットだけでなく、複数の状態（デスクトップとモバイル、ホバー、空、ローディング）を含めます。", "プロンプトでは具体的に。曖昧なプロンプトはありきたりな UI を生みます。", "デザインシステムを用意し、tokens と正規のプリミティブがどこにあるかを Cursor に伝えます。", "エディタ内プレビューを開いたまま dev サーバーを動かし続け、各編集が、気にするブレークポイントで即座に描画されるようにします。", "描画された UI をリファレンスと照合し直して反復し — 小さなビジュアル修正にはプレビュー内の直接要素選択を使います。"]}, {"kind": "p", "text": "チャットに画像を添付してリファレンスを与え、具体的な制約を添えてプロンプトを出します:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "良い反復はコミットし、悪い反復は元に戻す（戻したことを Cursor に伝える）ことで、各パスがクリーンなベースの上に積み上がるようにします — どのエージェントループも逸脱させないための同じ規律です。"}]}, {"id": "figma", "heading": "Cursor + Figma: MCP 経由のデザイン ↔ コード", "blocks": [{"kind": "p", "text": "Cursor は公式の Figma MCP サーバーを通じて Figma に接続し、平坦なスクリーンショットではなくライブの Figma ファイルへの構造化されたアクセスをエージェントに与えます。これがハンドオフから当て推量を取り除きます。"}, {"kind": "steps", "items": [{"label": "デザイン → コード", "body": "Figma でフレームのリンクをコピーし、それを Cursor に貼り付けて実装を依頼します。MCP サーバーは実際のデザインコンテキスト — コンポーネント、変数、レイアウトデータ、tokens — を公開するので、生成されるコードは近似ではなくソースと一致します。"}, {"label": "整合を保つ", "body": "Figma 内でデザイン tokens、スタイル、コンポーネントを一貫して使い（可能なら Code Connect も使い）、Cursor の出力はプリミティブを再発明するのではなく、あなたの実際のデザインシステムへとマッピングされ続けます。"}]}, {"kind": "p", "text": "リモートの Figma MCP サーバーを一度セットアップすれば、Cursor に第一級のコンテキストとして利用できます。MCP はオープンな標準なので、同じサーバーは Cursor、Claude Code、Codex、VS Code をまたいで再利用できます — まさに Open Design が編成するために作られた、ポータブルでマルチエージェントな機能です。"}]}, {"id": "vs", "heading": "デザインにおける Cursor vs Codex vs Claude Code", "blocks": [{"kind": "p", "text": "デザイン作業に唯一の勝者は存在しません — 各エージェントには異なる強みがあり、経験豊富なチームはそれらを重ねて使います。公平にまとめると:"}, {"kind": "table", "columns": ["エージェント", "デザインの強み", "適した用途"], "rows": [["Cursor", "エディタ内ライブプレビューと直接的な要素編集を備えた、作って見るビジュアルループ", "IDE 内での緊密な反復・観察型の UI 作業"], ["Codex", "フロントエンド skill による高いビジュアルの仕上がり、画像理解とサンドボックス実行", "委任された非同期ビルドとポータブルな AGENTS.md ルール"], ["Claude Code", "具体的なデザイン判断（hex、余白、タイプ）とコードベースを踏まえた UX", "フロントエンドの推論と大規模コンテキストのリファクタリング"]]}, {"kind": "p", "text": "コミュニティで繰り返される結論は、センスは人間から生まれるということです: 3 つとも、skills・リファレンス・制約がなければありきたりな美意識へと落ち着きます。それこそが解くべき本当の問題であり — それはモデルの形ではなく、デザインツールの形をしています。"}]}, {"id": "pitfalls", "heading": "落とし穴、そして「AI スロップ」っぽい見た目を避ける方法", "blocks": [{"kind": "p", "text": "Cursor 生成デザインへの最もよくある不満は、ありきたりに見えるというものです — 柔らかいグラデーション、浮いたパネル、過大な角丸、ドラマチックな影、「いかにも AI が作りました」と叫ぶような Inter と紫の雰囲気。ほかにも、モバイルで崩れるレイアウトや、指示が UI のコピーに漏れ出す問題が報告されています。"}, {"kind": "steps", "items": [{"label": "デザイン skill を追加する", "body": "厳選された美的な skill は、Cursor にデフォルトの見た目ではなく本物の方向性へコミットさせます。"}, {"label": "プレビューを使って検証する", "body": "エディタ内プレビューでブレークポイントをまたいで描画と自己チェックをし、レイアウトがモバイルで黙って崩れないようにします。"}, {"label": "tokens とリファレンスを供給する", "body": "本物のデザイン tokens とリファレンスのスクリーンショットは、出力品質に対する最大の単一のレバーです。"}, {"label": "ルールを `.cursor/rules` に記述する", "body": "「ヒーローカードなし、書体は最大 2 つ、ブランド優先の階層」といったスタイルルールを、エージェントが毎回読む場所に置きます。"}]}, {"kind": "p", "text": "どの対策も、エージェントに厳選されたデザインコンテキストを与えることが要だと気づくでしょう。そのコンテキストをプロジェクトごとに手作業で維持する手間こそ、Open Design が取り除くものです。"}]}, {"id": "open-design", "heading": "Open Design の中で Cursor を使ってデザインする", "blocks": [{"kind": "p", "text": "Open Design は、上記のワークフローが繰り返し求めてくるオープンソースのデザインレイヤーです。Cursor を第一級のアダプターとして扱い、厳選された skill とデザインシステムのライブラリ、構造化されたレンダーパイプライン、ローカルなデスクトップ UI でそれを包みます — そのため、Cursor を優れたものにするデザインコンテキストが、毎回手作業で組み立てるのではなく、最初の実行から揃っています。"}, {"kind": "ol", "items": ["Open Design をインストールし、エージェントとして Cursor を選びます。", "Cursor アカウントまたは独自のモデルキー（BYOK）で認証します — 認証情報はあなたのマシンに留まり、私たちを経由してプロキシされることは決してありません。", "デザインシステムと skill を選び、一貫したセンスでデッキ、プロトタイプ、ランディングページを生成します。", "あらゆる成果物と DESIGN.md ファイルは、ホスト型クラウドではなくあなた自身のリポジトリに置かれます。"]}, {"kind": "p", "text": "同じ Cursor エージェント、同じキー — それに加えて、それを取り巻く本物でポータブルなオープンソースのデザインワークフロー。ローカルファーストで Apache-2.0 なので、あなたの作業も認証情報も、マシンの外へ出ることはありません。"}]}], "faqTitle": "よくある質問", "faq": [{"name": "Cursor は本当にデザイン作業ができますか？", "text": "はい — デザイン skill、デザインシステム、本物のリファレンス画像をコンテキストに与えれば、Cursor は本番品質でレスポンシブな UI を生み出し、エディタ内プレビューでビジュアルに検証・洗練できます。そのコンテキストがなければありきたりな見た目に落ち着きがちで、それこそ Open Design が埋めるギャップです。"}, {"name": "これは公式の Cursor 製品ですか？", "text": "いいえ。Open Design は Cursor をエージェントとして統合する、独立したオープンソースプロジェクトです。Cursor を、ローカルファーストでオープンな skill とデザインシステムのライブラリで補完します。"}, {"name": "Cursor でデザインするには Cursor サブスクリプションが必要ですか？", "text": "Cursor アカウント / サブスクリプションを使うか、独自のモデルキー（BYOK）を持ち込めます。いずれの場合も Open Design があなたの認証情報をプロキシすることはありません — それらはあなたのエージェントが直接使います。"}, {"name": "フロントエンドデザインには Cursor と Claude Code のどちらがよいですか？", "text": "どちらも強力です。Claude Code は具体的でコードベースを踏まえたデザイン判断で知られ、Cursor の強みはエディタ内のライブプレビューを備えた緊密な作って見るループです。多くのチームが両方を使います — Open Design ならデザインワークフローを変えずにエージェントを切り替えられます。"}, {"name": "Cursor を Figma に接続するには？", "text": "Cursor に公式の Figma MCP サーバーを追加し、Figma フレームのリンクをチャットに貼り付けて、Cursor に実装を依頼します。サーバーは実際のコンポーネント、変数、レイアウトデータを公開するので、生成されるコードはソースのデザインと一致します。"}, {"name": "ありきたりな「AI スロップ」の美意識を避けるには？", "text": "デザイン skill を追加し、本物のデザイン tokens とリファレンスのスクリーンショットを供給し、ブランドルールを `.cursor/rules` または `AGENTS.md` に記述し、プレビューでブレークポイントをまたいで検証します。Open Design はこれらを厳選されたライブラリとして提供するので、プロジェクトごとのセットアップを省けます。"}, {"name": "Open Design は Cursor または Anysphere と提携していますか？", "text": "いいえ。Cursor は Anysphere の製品であり、Open Design はそれを第一級のアダプターとしてサポートする、独立したオープンソースプロジェクトです。Cursor と Anysphere は Anysphere, Inc. の商標です。"}, {"name": "私のファイルと認証情報は安全ですか？", "text": "はい — Open Design はローカルファーストです。あなたのファイル、成果物、DESIGN.md はあなた自身のリポジトリに留まり、Cursor またはモデルの認証情報はあなたのエージェントが直接使い、Open Design のサーバーを経由してルーティングされることは決してありません。"}], "ctaTitle": "Cursor で、オープンな方法でデザインしよう。", "ctaBody": "あなた自身の Cursor アカウントやモデルキーを持ち込み、すべてのファイルをローカルに保ち、すでに使っているエージェントを取り巻く厳選されたデザインライブラリを手に入れましょう。", "ctaActions": [{"label": "Open Design 内で Cursor を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "対応エージェントをすべて見る"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "デザインのための OpenCode — Open Design",
        description: "人々が UI と Web デザインに OpenCode をどう使うか — design.md ファイル、UI/UX の skills、Figma MCP — そして Open Design が OpenCode をローカルファーストでオープンソースのデザインエージェントへと変える方法。",
        breadcrumb: "OpenCode",
        label: "エージェント · OpenCode",
        heading: "デザインのための OpenCode。",
        lead: "OpenCode はオープンソースのターミナル型 AI コーディングエージェントです。デザイナーはデザインの skills と DESIGN.md ファイルを組み合わせて本物の UI を生成します。Open Design はそれを構造化されたオープンソースのワークフローにします — あなたのプロバイダーキーを持ち込み、すべてをローカルに保ちます。",
        rich: {"heroCtaLead": "Open Design は OpenCode をローカルファーストでオープンソースのデザインエージェントへと変えます — あなた自身のプロバイダーキーで選んだ任意のモデル、あなたのファイル、そしてそれを取り巻く厳選された skill とデザインシステムのライブラリ。", "heroCtaActions": [{"label": "Open Design 内で OpenCode を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode はオープンソースでターミナルファーストの AI コーディングエージェントであり、意図的にモデル非依存です: あなた自身のプロバイダーキーを持ち込み、同じワークフローの背後で好きなモデルを動かせます。その開放性が、デザイン作業にとって自然な土台になります — しかしどのエージェントとも同じで、適切なリファレンス、skills、検証ループを与えたときにのみ良い UI を生み出します。本稿は、UI・フロントエンド・デザインシステムの作業に OpenCode を使い、それを Open Design で構造化されたデザインワークフローへ組み込むための、実践的でエンドツーエンドのガイドです。", "OpenCode が実際に何であるか、なぜモデル非依存のオープンなエージェントがデザインに向いているのか、ゼロからのセットアップ方法、スクリーンショットから UI へのループ、AGENTS.md と MCP がどう拡張するか、Codex・Claude Code・Cursor との比較、AI の出力をありきたりに見せてしまう落とし穴、そして Open Design がオープンでローカルファーストなデザインレイヤーとしてそのギャップをどう埋めるか — 両プロジェクトともオープンソースであなた自身のマシン上で動くので、自然な組み合わせです — を扱います。"], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode のデザインフィードバックループ: ターミナル TUI エージェント、UI を描画するブラウザ、ワークスペース、そして戻ってくるフィードバックの矢印", "caption": "中核となるループ: OpenCode がターミナルで UI を構築し、実際のブラウザで描画・検証し、あなたのリファレンスへ向けて反復します — 選んだどのモデルでも。"}, "tocLabel": "このページの内容", "toc": [{"id": "what-is-opencode", "label": "OpenCode とは実際に何か"}, {"id": "why-design", "label": "なぜオープンで任意モデルのエージェントがデザインに合うのか"}, {"id": "setup", "label": "デザイン向けに OpenCode をセットアップする（ゼロから）"}, {"id": "screenshot-workflow", "label": "スクリーンショットから UI へのワークフロー"}, {"id": "extend", "label": "AGENTS.md、MCP、共有可能なセッション"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "落とし穴と「AI スロップ」っぽい見た目"}, {"id": "open-design", "label": "Open Design で OpenCode を使ってデザインする"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode とは実際に何か", "blocks": [{"kind": "p", "text": "OpenCode は、SST（Anomaly Innovations）のチームが保守する、ターミナル向けに作られたオープンソースの AI コーディングエージェントです。リポジトリを読み、コマンドを実行し、ファイルを編集し、大規模言語モデルと対話します — しかしベンダーに縛られたエージェントと違い、自前のモデルは出荷しません。好きなプロバイダーとモデルを指定し、あなた自身のキーを持ち込みます。"}, {"kind": "p", "text": "ターミナル UI（TUI）として動作し、同じエンジンの上にデスクトップアプリと IDE 拡張機能が乗っています。内部ではクライアント/サーバーアーキテクチャを使っているため、作業を行うエージェントは、あなたがそれを操作する面から切り離されています。組み込みの 2 つのエージェント — build と plan — は Tab キーで切り替わります。"}, {"kind": "steps", "items": [{"label": "モデル非依存", "body": "モデルとプロバイダーはオープンなカタログ models.dev から来ます。opencode.json で provider/model-id の文字列により構成し、読み込みたくないプロバイダーは無効化できます — そのため同じデザインワークフローが Anthropic、OpenAI、Google、OpenRouter、ローカルモデルなどで動きます。"}, {"label": "指示ファイル", "body": "OpenCode はプロジェクト内の AGENTS.md ファイル（ツール横断の標準で、CLAUDE.md とも互換）をプロジェクトルールとして読み込みます — デザインの規約を記述する自然な場所です。/init を実行すると 1 つ生成されます。"}, {"label": "拡張可能", "body": "LSP 連携、MCP サーバー、テーマ、キーバインド、カスタムコマンドに加え、コラボレーションのための共有可能なセッションリンクもサポートします。"}]}, {"kind": "ul", "items": ["メンテナー: SST / Anomaly Innovations（オープンソースプロジェクト）", "認証情報: あなた自身のモデルプロバイダー API キー — BYOK、ベンダーロックインなし", "ライセンス: MIT、オープンソース"]}]}, {"id": "why-design", "heading": "なぜオープンで任意モデルのエージェントがデザイン作業に合うのか", "blocks": [{"kind": "p", "text": "OpenCode は、ベンダーエージェントのような単一の「デザインモデル」を持っていません — そしてそれが要点です。モデル非依存でオープンなので、いま最もフロントエンドに優れたモデルで同じデザインワークフローを動かし、あとで入れ替え、あるいはローカルモデルへフォールバックすることが、セットアップを一切変えずにできます。"}, {"kind": "p", "text": "しかしモデルの選択だけではセンスは手に入りません。どのコーディングエージェントとも同じで、制約を与えない限り OpenCode はありきたりな UI を生み出します。良いデザイン出力は、あなたが与える 3 つの入力から生まれます。"}, {"kind": "steps", "items": [{"label": "デザインシステム", "body": "エージェントが再利用する本物の tokens、プリミティブ、規約。これにより出力がありきたりな見た目に落ち着かず、ブランドに沿ったものになります。"}, {"label": "美的な skill", "body": "本物のセンスを徹底する厳選された skill — 抑制されたモーション、ブランド優先の階層、最大 2 つの書体と 1 つのアクセントカラー — そして構築前にエージェントに方向性をコミットさせます。"}, {"label": "具体的なリファレンス", "body": "実際のリファレンス画像と複数の状態（デスクトップとモバイル、ホバー、空、ローディング）であり、1 枚のヒーローショットではありません。"}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "デザインシステム、skill、リファレンス画像が良いデザイン出力へと収束する様子を示す図", "caption": "センスはあなたが与える 3 つの入力から生まれます: デザインシステム、skill、本物のリファレンス画像 — どのモデルを動かすかに関係なく。"}, {"kind": "p", "text": "教訓: OpenCode はモデルの自由を与えてくれますが、センスは依然として厳選されたデザインコンテキストから生まれます。Open Design はまさにそれらの入力をパッケージ化しており、だからこそ両者は噛み合うのです — どちらもオープンソースでローカルファーストです（詳細は後述）。"}]}, {"id": "setup", "heading": "デザイン作業のために OpenCode をゼロからセットアップする", "blocks": [{"kind": "p", "text": "まっさらなマシンから、UI を構築・検証できる OpenCode までの全行程はこちらです。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "5 ステップのセットアップフロー: インストール、プロバイダーキーで認証、AGENTS.md 設定、skill 追加、検証", "caption": "セットアップの手順: インストール → 認証（あなたのプロバイダーキー）→ AGENTS.md を設定 → skill を追加 → 実際のブラウザで検証。"}, {"kind": "steps", "items": [{"label": "デザインルールを記述する", "body": "tokens、プリミティブ、規約を AGENTS.md（またはそこから参照される DESIGN.md）に書き、出力がありきたりな見た目に落ち着かず、ブランドに沿ったものになるようにします。opencode.json の instructions オプションは、グロブによって追加のルールファイルを指せます。"}, {"label": "有能なモデルを選ぶ", "body": "OpenCode はモデル非依存なので、デザインパスにはいま最もフロントエンドに強い provider/model を選び — ワークフローの残りはそのままに保ちます。"}]}]}, {"id": "screenshot-workflow", "heading": "スクリーンショットから UI へのワークフロー", "blocks": [{"kind": "p", "text": "どのエージェントでも最も効果の高いデザインのループは、リファレンス画像を動作するレスポンシブな UI に変え、一致するまで反復することです。OpenCode でも同じ 5 ステップの形が当てはまります。"}, {"kind": "ol", "items": ["手元にある最も明確なビジュアルリファレンスから始めましょう — そして 1 枚のヒーローショットだけでなく、複数の状態（デスクトップとモバイル、ホバー、空、ローディング）を含めます。", "プロンプトでは具体的に。曖昧なプロンプトはありきたりな UI を生みます。", "デザインシステムを用意し、tokens と正規のプリミティブがどこにあるか（AGENTS.md 内）を OpenCode に伝えます。", "dev サーバーを動かし、エージェントに実際のブラウザで描画させ、結果を確認するためにブレークポイントへリサイズさせます。", "OpenCode に実装をスクリーンショットと照合し直させて反復します — 単にビルドが通ることを確認するだけにしないようにします。"]}, {"kind": "p", "text": "TUI で @ を使ってファイルを参照すると作業ディレクトリのあいまい検索ができ、先頭に ! を付けてシェルコマンドをインラインで実行し、/ コマンドでアクションを駆動します。そのうえで具体的な制約を添えてプロンプトを出します:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "プロンプトを小さく焦点を絞って保ち、良い反復はコミットし、悪い反復は元に戻す（戻したことを OpenCode に伝える）ことで、各パスがクリーンなベースの上に積み上がるようにします。"}]}, {"id": "extend", "heading": "AGENTS.md、MCP、共有可能なセッション", "blocks": [{"kind": "p", "text": "3 つの拡張ポイントが OpenCode を継続的なデザイン作業に実用的なものにし、その 3 つともオープンなデザインワークフローへきれいに対応します。"}, {"kind": "steps", "items": [{"label": "AGENTS.md ルール", "body": "プロジェクトルールはリポジトリルートの AGENTS.md（またはグローバルルールとして ~/.config/opencode/AGENTS.md）に置きます。それはデザインの規約の恒久的な置き場であり、毎回の実行で読み込まれ、他のエージェントが使う CLAUDE.md ファイルとも互換です。"}, {"label": "MCP サーバー", "body": "OpenCode はローカル（コマンド）とリモート（URL）の両方の MCP サーバーをサポートし、mcp キーの下で構成します — OpenCode だけでなくエージェント横断で機能する、デザインコンテキストや外部ツールを取り込むためのポータブルな方法です。"}, {"label": "共有可能なセッション", "body": "/share コマンドはコラボレーションやレビューのために会話への公開リンクを作り、/unshare がそれを取り消します — デザインパスへのフィードバックを得るのに便利です。"}]}, {"kind": "p", "text": "これらはポータブルでマルチエージェントな機能です — まさに Open Design が、プロジェクトごとに再作成するのではなく、編成するために作られたものです。"}]}, {"id": "vs", "heading": "デザインにおける OpenCode vs Codex vs Claude Code vs Cursor", "blocks": [{"kind": "p", "text": "デザイン作業に唯一の勝者は存在しません — 各エージェントには異なる強みがあり、経験豊富なチームはそれらを重ねて使います。公平にまとめると:"}, {"kind": "table", "columns": ["エージェント", "デザインの強み", "適した用途"], "rows": [["OpenCode", "オープンソースでモデル非依存。1 つのターミナルワークフローの背後で任意のプロバイダーを動かせる", "BYOK の自由、モデル切り替え、完全にオープンでローカルファーストな構成"], ["Codex", "フロントエンド skill による高いビジュアルの仕上がり、画像理解", "委任された非同期、サンドボックス化ビルド、ポータブルな AGENTS.md ルール"], ["Claude Code", "具体的なデザイン判断（hex、余白、タイプ）とコードベースを踏まえた UX", "フロントエンドの推論と大規模コンテキストのリファクタリング"], ["Cursor", "ライブプレビューとインライン編集を備えた、作って見るビジュアルループ", "IDE 内での緊密な反復・観察型の UI 作業"]]}, {"kind": "p", "text": "コミュニティで繰り返される結論は、センスは人間から生まれるということです: どれもが、skills・リファレンス・制約がなければありきたりな美意識へと落ち着きます。それこそが解くべき本当の問題であり — それはモデルの形ではなくデザインツールの形をしています。だからこそ OpenCode のようなオープンなエージェントは、オープンなデザインレイヤーと非常に相性が良いのです。"}]}, {"id": "pitfalls", "heading": "落とし穴、そして「AI スロップ」っぽい見た目を避ける方法", "blocks": [{"kind": "p", "text": "AI 生成デザインへの最もよくある不満は、ありきたりに見えるというものです — 柔らかいグラデーション、浮いたパネル、過大な角丸、ドラマチックな影、「いかにも AI が作りました」と叫ぶような Inter と紫の雰囲気。ほかにも、モバイルレイアウトの崩れや、指示が UI のコピーに漏れ出す問題が報告されています。これらはどれも OpenCode に固有のものではありません。どのエージェントでも、厳選されたデザインコンテキストなしに動かしたときに起こることです。"}, {"kind": "steps", "items": [{"label": "美的な skill を追加する", "body": "厳選されたデザイン skill は、エージェントにデフォルトの見た目ではなく本物の方向性へコミットさせます。"}, {"label": "実際のブラウザで検証する", "body": "ブレークポイントをまたいで描画と自己チェックをし、レイアウトがモバイルで黙って崩れないようにします。"}, {"label": "tokens とリファレンスを供給する", "body": "本物のデザイン tokens とリファレンスのスクリーンショットは、出力品質に対する最大の単一のレバーです。"}, {"label": "ルールを AGENTS.md に記述する", "body": "「ヒーローカードなし、書体は最大 2 つ、ブランド優先の階層」といったスタイルルールを、エージェントが毎回読む場所に置きます。"}]}, {"kind": "p", "text": "どの対策も、どのモデルを動かすかに関係なく、エージェントに厳選されたデザインコンテキストを与えることが要だと気づくでしょう。そのコンテキストをプロジェクトごとに手作業で維持する手間こそ、Open Design が取り除くものです。"}]}, {"id": "open-design", "heading": "Open Design の中で OpenCode を使ってデザインする", "blocks": [{"kind": "p", "text": "Open Design は、上記のワークフローが繰り返し求めてくるオープンソースのデザインレイヤーです。OpenCode を第一級のアダプターとして扱い、厳選された skill とデザインシステムのライブラリ、構造化されたレンダーパイプライン、ローカルなデスクトップ UI でそれを包みます — そのため、どのエージェントも優れたものにするデザインコンテキストが、毎回手作業で組み立てるのではなく、最初の実行から揃っています。両プロジェクトともオープンソースでローカルファーストなので、組み合わせは自然にフィットします。"}, {"kind": "ol", "items": ["Open Design をインストールし、エージェントとして OpenCode を選びます。", "あなた自身のモデルプロバイダー API キー（BYOK）で認証します — 認証情報はあなたのマシンに留まり、私たちを経由してプロキシされることは決してありません。", "任意のプロバイダーとモデルを選び、さらにデザインシステムと skill を選んで、一貫したセンスでデッキ、プロトタイプ、ランディングページを生成します。", "あらゆる成果物と DESIGN.md ファイルは、ホスト型クラウドではなくあなた自身のリポジトリに置かれます。"]}, {"kind": "p", "text": "同じ OpenCode エージェント、同じモデルの自由 — それに加えて、それを取り巻く本物でポータブルなオープンソースのデザインワークフロー。ローカルファーストで Apache-2.0 なので、あなたの作業も認証情報も、マシンの外へ出ることはありません。"}]}], "faqTitle": "よくある質問", "faq": [{"name": "OpenCode は本当にデザイン作業ができますか？", "text": "はい — 美的な skill、デザインシステム、本物のリファレンス画像をコンテキストに与えれば、OpenCode は本番品質でレスポンシブな UI を生み出し、ブラウザで検証できます。モデル非依存なので、いま最もフロントエンドに優れたモデルを動かせます。その厳選されたコンテキストがなければありきたりな見た目に落ち着きがちで、それこそ Open Design が埋めるギャップです。"}, {"name": "OpenCode でデザインするにはどのモデルを使うべきですか？", "text": "好きなものを — OpenCode は models.dev 経由でプロバイダー非依存なので、Anthropic、OpenAI、Google、OpenRouter、ローカルモデルを同じワークフローの背後で動かし、いつでも切り替えられます。デザイン出力の品質は、モデル単独よりも、あなたの skill、デザインシステム、リファレンスにはるかに左右されます。"}, {"name": "Open Design は OpenCode（SST）チームが作っていますか？", "text": "いいえ。Open Design は OpenCode をエージェントとして統合する、独立したオープンソースプロジェクトです。OpenCode を、ローカルファーストでオープンな skill とデザインシステムのライブラリで補完します。"}, {"name": "OpenCode でデザインするには特別なサブスクリプションが必要ですか？", "text": "いいえ — OpenCode は BYOK です。あなた自身のモデルプロバイダー API キーを持ち込み、Open Design があなたの認証情報をプロキシすることはありません。ベンダーロックインはありません。"}, {"name": "フロントエンドデザインには OpenCode、Codex、Claude Code のどれがよいですか？", "text": "どれも強力で、多くのチームがそれらを重ねて使います。OpenCode の強みは完全にオープンソースでモデル非依存であること、Codex は委任されたサンドボックス化ビルドに優れ、Claude Code は具体的でコードベースを踏まえたデザイン判断で知られます。Open Design ならデザインワークフローを変えずにエージェントを切り替えられます。"}, {"name": "デザインコンテキストのために OpenCode をどう拡張しますか？", "text": "ルールを AGENTS.md に記述し、ポータブルなツールやデザインコンテキストのために mcp キーの下に MCP サーバーを追加し、レビューには共有可能なセッションを使います。Open Design は厳選された skill とデザインシステムのライブラリを提供するので、プロジェクトごとのセットアップを省けます。"}, {"name": "Open Design は OpenCode または SST と提携していますか？", "text": "いいえ。OpenCode は SST（Anomaly Innovations）が保守するオープンソースプロジェクトであり、Open Design はそれを第一級のアダプターとしてサポートする、独立したオープンソースプロジェクトです。"}, {"name": "私のファイルと認証情報は安全ですか？", "text": "はい — Open Design はローカルファーストです。あなたのファイル、成果物、DESIGN.md はあなた自身のリポジトリに留まり、モデルプロバイダーの認証情報はあなたのエージェントが直接使い、Open Design のサーバーを経由してルーティングされることは決してありません。"}], "ctaTitle": "OpenCode で、オープンな方法でデザインしよう。", "ctaBody": "あなた自身のモデルプロバイダーキーを持ち込み、すべてのファイルをローカルに保ち、すでに使っているオープンなエージェントを取り巻く厳選されたデザインライブラリを手に入れましょう。", "ctaActions": [{"label": "Open Design 内で OpenCode を使う", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub でスターを付ける", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "デスクトップアプリをダウンロード", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "対応エージェントをすべて見る"},
      },
    },
    'ko': {
      'claude-code': {
        ...en['claude-code']!,
        title: "디자인을 위한 Claude Code — Open Design",
        description: "디자이너가 UI와 웹 디자인에 Claude Code를 활용하는 방법, 그리고 Open Design이 이를 실제 디자인 에이전트로 바꾸는 방식 — 로컬 우선, BYOK, 엄선된 skill 및 디자인 시스템 라이브러리와 함께.",
        breadcrumb: "Claude Code",
        label: "에이전트 · Claude Code",
        heading: "디자인을 위한 Claude Code.",
        lead: "Claude Code는 Anthropic의 터미널 코딩 에이전트입니다. 사람들은 이미 이를 활용해 UI, 디자인 시스템, 랜딩 페이지를 만들고 있습니다. Open Design은 이를 실제 디자인 워크플로에 연결합니다 — 자신의 Anthropic 키 또는 Claude 구독을 가져오고, 모든 파일을 로컬에 유지하세요.",
        rich: {"heroCtaLead": "Open Design은 Claude Code를 로컬 우선의 오픈소스 디자인 에이전트로 바꿉니다 — 자신의 Anthropic 키 또는 Claude 구독, 자신의 파일, 그리고 그 주위를 감싸는 엄선된 skill 및 디자인 시스템 라이브러리.", "heroCtaActions": [{"label": "Open Design 안에서 Claude Code 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code는 프런트엔드 감각이 가장 뛰어난 코딩 에이전트로 널리 인정받습니다 — 인터페이스를 유난히 구체적으로 추론하며 정확한 hex 값, 간격, 타입 스케일을 명시하고, 큰 코드베이스 전반에 걸쳐 맥락을 잃지 않으면서 UI를 리팩터링합니다. 하지만 기본 상태에서는 디자인 시스템, skill, 실제 레퍼런스를 건네지 않으면 여전히 평범한 모습으로 흘러갑니다. 이 글은 UI, 프런트엔드, 디자인 시스템 작업에 Claude Code를 활용하고, 이를 Open Design과 함께 구조화된 워크플로에 연결하는 실용적이고 처음부터 끝까지 이어지는 가이드입니다.", "Claude Code가 실제로 무엇인지, 왜 프런트엔드에 강한지, 처음부터 설정하는 방법, CLAUDE.md와 Skills 워크플로, 공식 Figma 왕복 연동, Codex 및 Cursor와의 비교, AI 결과물을 평범해 보이게 만드는 함정, 그리고 Open Design이 개방적이고 로컬 우선인 디자인 레이어로서 이 격차를 메우는 방식을 다룹니다."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code 디자인 피드백 루프: 구체적인 디자인 결정을 내리는 터미널 에이전트, UI를 렌더링하는 브라우저, 그리고 작업 공간, 다시 돌아오는 피드백 화살표와 함께", "caption": "핵심 루프: Claude Code는 터미널에서 구체적인 UI 결정을 추론하고, 실제 브라우저에서 렌더링하고 검증하며, 레퍼런스에 수렴합니다."}, "tocLabel": "이 페이지에서", "toc": [{"id": "what-is-claude-code", "label": "Claude Code는 실제로 무엇인가"}, {"id": "why-design", "label": "Claude Code가 디자인에 강한 이유"}, {"id": "setup", "label": "디자인을 위한 Claude Code 설정하기 (처음부터)"}, {"id": "skills-workflow", "label": "CLAUDE.md와 Skills 워크플로"}, {"id": "figma", "label": "Claude Code + Figma 왕복 연동"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "함정과 “AI 티” 나는 결과물"}, {"id": "open-design", "label": "Open Design에서 Claude Code로 디자인하기"}, {"id": "faq", "label": "자주 묻는 질문"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code는 실제로 무엇인가", "blocks": [{"kind": "p", "text": "Claude Code는 Anthropic의 에이전트형 코딩 도구입니다. 코드베이스를 읽고, 파일을 편집하고, 명령을 실행하며, 개발 도구와 통합됩니다 — 단순히 줄을 자동 완성하는 것이 아니라 자연어 작업으로부터 작업을 계획하고, 작성하고, 검증합니다."}, {"kind": "p", "text": "동일한 엔진을 공유하는 여러 표면으로 제공됩니다: 터미널 CLI, VS Code·Cursor·JetBrains용 IDE 확장, 시각적 diff 리뷰를 갖춘 데스크톱 앱, 그리고 장시간 작업을 위한 웹 환경. CLAUDE.md 파일, 설정, MCP 서버는 이 모든 표면에 걸쳐 이어집니다."}, {"kind": "steps", "items": [{"label": "지시 파일", "body": "Claude Code는 모든 세션 시작 시 프로젝트 루트의 CLAUDE.md 파일을 읽습니다 — 디자인 컨벤션, tokens, 리뷰 체크리스트를 담기에 가장 자연스러운 곳입니다."}, {"label": "Skills", "body": "Agent Skills는 반복 가능한 지시, 스크립트, 리소스를 패키징하여 Claude가 필요할 때 불러옵니다. Anthropic의 공식 Frontend Design skill을 포함해 감각을 더합니다."}, {"label": "계획과 서브에이전트", "body": "행동에 앞서 계획을 세우고, 작업의 여러 부분을 병렬로 처리하는 서브에이전트를 띄울 수 있어 대규모 UI 리팩터링도 일관되게 유지합니다."}]}, {"kind": "ul", "items": ["공급사: Anthropic", "자격 증명: Anthropic API 키(BYOK, Console 경유) 또는 Claude 구독(Pro / Max)", "표면: 터미널 CLI, VS Code / Cursor / JetBrains 확장, 데스크톱 앱, 웹"]}]}, {"id": "why-design", "heading": "Claude Code가 디자인에 강한 이유", "blocks": [{"kind": "p", "text": "코딩 에이전트들 가운데 Claude Code는 프런트엔드 작업에서 감각이 좋다는 평판을 가지고 있습니다. 그 이유는 몇 가지로 설명됩니다."}, {"kind": "steps", "items": [{"label": "모호하지 않은, 구체적인 결정", "body": "Claude Code는 두루뭉술하게 넘기지 않고 구체적인 선택 — 정확한 hex 값, 간격 스케일, 타입 램프, 컴포넌트 위계 — 에 명확히 전념하는 경향이 있습니다. 이것이 실제 인터페이스와 자리채움을 가르는 차이입니다."}, {"label": "코드베이스를 이해하는 추론", "body": "큰 작업 컨텍스트를 바탕으로 여러 파일에 걸친 UI를 한 번에 리팩터링하며, 일회성 스타일을 새로 만들기보다 기존 컴포넌트와 tokens를 재사용합니다."}, {"label": "공식 프런트엔드 skill", "body": "Anthropic은 Claude가 먼저 디자인 방향을 쓰게 하고, 평범한 시스템 폰트와 뻔한 보라색 그라데이션을 의도적으로 피하도록 만드는 Frontend Design skill을 제공합니다."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "디자인 시스템, skill, 레퍼런스 이미지가 좋은 디자인 결과물로 수렴하는 것을 보여주는 다이어그램", "caption": "감각은 여러분이 제공하는 세 가지 입력에서 나옵니다: 디자인 시스템, skill, 그리고 실제 레퍼런스 이미지."}, {"kind": "p", "text": "교훈은 Anthropic이 자사 모델에 대해 말하는 것과 같습니다: Claude는 기본적으로 감각을 가지고 있지 않습니다 — 내버려 두면 웹 디자인의 통계적 중심(Inter, 보라색 그라데이션, 부드러운 그림자)으로 수렴합니다. 제약을 주면 좋은 디자인을 만들어 냅니다. Open Design은 바로 그 입력들을 패키징하며, 그래서 둘이 잘 맞물립니다(아래에서 자세히)."}]}, {"id": "setup", "heading": "디자인 작업을 위한 Claude Code 설정하기, 처음부터", "blocks": [{"kind": "p", "text": "깨끗한 머신에서 UI를 만들고 검증할 수 있는 Claude Code까지 가는 전체 경로는 다음과 같습니다."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "다섯 단계 설정 흐름: 설치, 인증, CLAUDE.md 구성, skill 추가, 검증", "caption": "설정 순서: 설치 → 인증 → CLAUDE.md 구성 → Frontend Design skill 추가 → 브라우저 검증 활성화."}, {"kind": "steps", "items": [{"label": "디자인 규칙을 담기", "body": "tokens, 기본 요소, 컨벤션을 CLAUDE.md에 담고 Claude가 그것을 보도록 가리키세요. 그러면 결과물이 평범한 모습으로 기본 회귀하지 않고 브랜드에 맞춰집니다."}, {"label": "브라우저 검증 추가하기", "body": "Playwright 또는 Chrome MCP를 연결해 Claude가 실제 브라우저에서 렌더링하고, 빌드 통과만 확인하는 대신 여러 브레이크포인트에 걸쳐 결과물을 점검하도록 하세요."}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md와 Skills 워크플로", "blocks": [{"kind": "p", "text": "Claude Code로 얻는 가장 효과적인 디자인 루프는 실제 레퍼런스와 디자인 컨텍스트를 함께 제공하고 UI가 맞아떨어질 때까지 반복하는 것입니다 — CLAUDE.md와 Skills가 제약을 담아 두기에 매번 다시 설명할 필요가 없습니다."}, {"kind": "ol", "items": ["가지고 있는 가장 명확한 시각 레퍼런스에서 시작하세요 — 그리고 히어로 한 컷이 아니라 여러 상태(데스크톱과 모바일, hover, 빈 상태, 로딩)를 포함하세요.", "프롬프트에서 구체적으로 쓰세요. 강력한 에이전트라도 모호한 프롬프트는 평범한 UI를 낳습니다.", "디자인 시스템과 컨벤션을 CLAUDE.md에 두고, tokens와 정식 기본 요소가 어디에 있는지 Claude에게 알려 주세요.", "Claude가 코드를 작성하기 전에 실제 미학적 방향에 전념하도록 Frontend Design skill을 추가하세요.", "Claude가 단지 빌드가 되는지만 확인하는 게 아니라, 렌더링하고 브레이크포인트로 크기를 바꿔 레퍼런스와 다시 비교하도록 브라우저 검증을 연결하세요."]}, {"kind": "p", "text": "세션에 레퍼런스 이미지를 넣고 구체적인 제약과 함께 프롬프트하세요:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "옆에서 dev 서버를 띄우고, 프롬프트는 작고 집중되게 유지하며, 좋은 반복은 커밋하고 나쁜 반복은 되돌리세요(되돌릴 때 Claude에게 알려 주세요). 그래야 각 패스가 깨끗한 기반 위에서 쌓입니다. 더 큰 리팩터링에는 plan 모드를 사용해 파일이 변경되기 전에 접근 방식을 검토하세요."}]}, {"id": "figma", "heading": "Claude Code + Figma: 디자인 ↔ 코드 왕복 연동", "blocks": [{"kind": "p", "text": "2026년 2월, Anthropic과 Figma는 Figma MCP 서버를 통해 일급의 양방향 통합을 선보였습니다. 양쪽 방향 모두에서 작동합니다."}, {"kind": "steps", "items": [{"label": "디자인 → 코드", "body": "Figma에서 프레임을 선택하거나 링크를 Claude Code에 붙여넣고, 디자인 컨텍스트를 가져온 다음, 기존 컴포넌트 라이브러리를 사용해 디자인을 구현하도록 요청하세요. Code Connect는 결과물을 실제 컴포넌트에 맞춰 유지합니다."}, {"label": "코드 → 디자인", "body": "브라우저에서 기능을 만들고 미리 본 뒤 “Send this to Figma”라고 말하면 실행 중인 UI를 편집 가능한 Figma 레이어로 — 화면 전체 또는 선택한 요소로 — 캡처합니다."}]}, {"kind": "p", "text": "claude plugin install figma@claude-plugins-official로 한 번만 설치하면 됩니다(Dev Mode MCP는 유료 Figma 플랜이 필요합니다). 동일한 Figma MCP는 Claude Code, Codex, Cursor, VS Code에서 사용할 수 있습니다 — 바로 Open Design이 오케스트레이션하도록 설계된 이식 가능한 멀티 에이전트 역량의 전형입니다."}]}, {"id": "vs", "heading": "디자인을 위한 Claude Code vs Codex vs Cursor", "blocks": [{"kind": "p", "text": "디자인 작업에 단 하나의 승자는 없습니다 — 에이전트마다 강점이 다르고, 숙련된 팀은 이들을 함께 쌓아 씁니다. 공정한 요약은 다음과 같습니다:"}, {"kind": "table", "columns": ["에이전트", "디자인 강점", "가장 적합한 경우"], "rows": [["Claude Code", "구체적인 디자인 결정(hex, 간격, 타입)과 코드베이스를 이해하는 UX 추론", "프런트엔드 추론과 대형 컨텍스트 리팩터링"], ["Codex", "강한 비주얼 완성도와 이미지 이해; 샌드박스 비동기 빌드", "위임된 비동기 빌드와 이식 가능한 AGENTS.md 규칙"], ["Cursor", "라이브 미리보기와 인라인 편집을 갖춘 시각적 만들고-보기 루프", "IDE 안에서의 긴밀한 반복하며-지켜보는 UI 작업"]]}, {"kind": "p", "text": "커뮤니티에서 반복되는 결론은 감각이 사람에게서 나온다는 것입니다: 셋 모두 skill, 레퍼런스, 제약이 없으면 평범한 미학으로 기본 회귀합니다. 그것이 풀어야 할 진짜 문제이며 — 모델 모양이 아니라 디자인 도구 모양의 문제입니다."}]}, {"id": "pitfalls", "heading": "함정, 그리고 “AI 티” 나는 결과물을 피하는 법", "blocks": [{"kind": "p", "text": "Claude Code가 감각으로 평판이 좋더라도, AI가 생성한 디자인에 대한 가장 흔한 불만은 평범해 보인다는 것입니다 — Inter 폰트, 흰 배경 위 보라색 그라데이션, 부드러운 그림자, 과도하게 둥근 모서리, “AI가 만들었다고 외치는” 듯한 미학. Anthropic 스스로도 이를 분포적 수렴 탓으로 봅니다: 안전한 선택이 웹 학습 데이터를 지배하기 때문입니다. 그 밖에 보고된 문제로는 깨진 모바일 레이아웃과 지시문이 UI 카피에 새어 나오는 것이 있습니다."}, {"kind": "steps", "items": [{"label": "Frontend Design skill 설치하기", "body": "Claude가 실제 방향에 전념하도록 강제하고, AI가 과용하는 폰트와 그라데이션을 명시적으로 피합니다."}, {"label": "브라우저 검증 활성화하기", "body": "Claude가 브레이크포인트 전반에서 렌더링하고 스스로 점검하게 하여 레이아웃이 모바일에서 조용히 깨지지 않도록 하세요."}, {"label": "tokens와 레퍼런스 제공하기", "body": "실제 디자인 tokens와 레퍼런스 스크린샷은 결과물 품질을 좌우하는 가장 큰 단일 지렛대입니다."}, {"label": "CLAUDE.md에 규칙 담기", "body": "“히어로 카드 금지, 서체 최대 두 종, 브랜드 우선 위계” 같은 스타일 규칙을 에이전트가 매번 읽는 곳에 두세요."}]}, {"kind": "p", "text": "모든 완화책이 에이전트에게 엄선된 디자인 컨텍스트를 주는 것임에 주목하세요. 그 컨텍스트를 프로젝트마다 손으로 유지하는 수고가 바로 Open Design이 없애는 것입니다."}]}, {"id": "open-design", "heading": "Open Design 안에서 Claude Code로 디자인하기", "blocks": [{"kind": "p", "text": "Open Design은 위 워크플로가 계속 요구하던 그 오픈소스 디자인 레이어입니다. Claude Code를 일급 어댑터로 취급하고 엄선된 skill 및 디자인 시스템 라이브러리, 구조화된 렌더 파이프라인, 로컬 데스크톱 UI로 감싸 줍니다 — 그래서 Claude Code를 좋게 만드는 디자인 컨텍스트가 매번 손으로 조립하는 대신 첫 실행부터 갖춰져 있습니다."}, {"kind": "ol", "items": ["Open Design을 설치하고 에이전트로 Claude Code를 선택하세요.", "Anthropic API 키(BYOK) 또는 Claude 구독으로 인증하세요 — 자격 증명은 여러분의 머신에 머물며 결코 저희를 거쳐 프록시되지 않습니다.", "디자인 시스템과 skill을 고른 다음, 일관된 감각으로 덱, 프로토타입, 랜딩 페이지를 생성하세요.", "모든 산출물과 DESIGN.md 파일은 호스팅 클라우드가 아니라 여러분 자신의 레포에 존재합니다."]}, {"kind": "p", "text": "같은 Claude Code 에이전트, 같은 키 — 그 위에 실제로 이식 가능한 오픈소스 디자인 워크플로가 더해집니다. 로컬 우선이며 Apache-2.0이라, 여러분의 작업이나 자격 증명 중 어떤 것도 머신을 떠나지 않습니다."}]}], "faqTitle": "자주 묻는 질문", "faq": [{"name": "Claude Code는 디자인 작업에 좋은가요?", "text": "네 — 프런트엔드 감각이 가장 뛰어난 코딩 에이전트로 널리 인정받으며, hex 값, 간격, 타입 스케일에 대해 구체적이고 코드베이스를 이해하는 결정을 내립니다. Frontend Design skill, 디자인 시스템, 그리고 실제 레퍼런스 이미지가 컨텍스트에 있으면 양산 품질의 반응형 UI를 만들고 브라우저에서 검증할 수 있습니다. 그런 컨텍스트가 없으면 평범한 모습으로 기본 회귀하는 경향이 있는데, 그것이 바로 Open Design이 메우는 격차입니다."}, {"name": "Claude Code로 디자인하려면 Claude 구독이 필요한가요?", "text": "Anthropic API 키(BYOK, Console 경유) 또는 Claude 구독(Pro / Max) 중 어느 쪽이든 사용할 수 있습니다. 어느 경우든 Open Design은 결코 여러분의 자격 증명을 프록시하지 않습니다 — 자격 증명은 여러분의 머신에서 에이전트가 직접 사용합니다."}, {"name": "프런트엔드 디자인에는 Claude Code인가요, Codex인가요?", "text": "둘 다 강력합니다. Claude Code는 구체적이고 코드베이스를 이해하는 디자인 결정과 프런트엔드 추론으로 알려져 있고, Codex는 강한 비주얼 완성도와 위임된 샌드박스 빌드에 능합니다. 많은 팀이 둘 다 씁니다 — Open Design을 쓰면 디자인 워크플로를 바꾸지 않고 에이전트를 전환할 수 있습니다."}, {"name": "Claude Code를 Figma에 어떻게 연결하나요?", "text": "claude plugin install figma@claude-plugins-official로 공식 Figma 플러그인을 설치하세요. 그러면 디자인 컨텍스트를 사용해 Figma 프레임을 코드로 구현할 수 있고, “Send this to Figma”로 실행 중인 UI를 편집 가능한 Figma 프레임으로 되돌릴 수 있습니다. Dev Mode MCP는 유료 Figma 플랜이 필요합니다."}, {"name": "Skills와 CLAUDE.md란 무엇인가요?", "text": "CLAUDE.md는 프로젝트 루트에 있는 마크다운 파일로, Claude Code가 모든 세션 시작 시 읽습니다 — 디자인 컨벤션을 담는 곳입니다. Skills는 Claude가 필요할 때 불러오는 반복 가능한 지시와 리소스를 패키징하며, Anthropic의 공식 Frontend Design skill을 포함합니다. Open Design은 두 가지를 엄선한 라이브러리로 제공하여 프로젝트마다 하는 설정을 건너뛰게 해 줍니다."}, {"name": "평범한 “AI 티” 미학을 어떻게 피하나요?", "text": "Frontend Design skill을 설치하고, 실제 디자인 tokens와 레퍼런스 스크린샷을 제공하며, 브랜드 규칙을 CLAUDE.md에 담고, 브라우저 검증을 활성화하세요. Open Design은 이것들을 엄선한 라이브러리로 제공하여 프로젝트마다 하는 설정을 건너뛰게 해 줍니다."}, {"name": "Open Design은 Anthropic과 제휴되어 있나요?", "text": "아니요. Claude Code는 Anthropic의 제품이며, Open Design은 이를 일급 어댑터로 지원하는 독립적인 오픈소스 프로젝트입니다. Claude와 Claude Code는 Anthropic의 상표입니다."}, {"name": "제 파일과 자격 증명은 안전한가요?", "text": "네 — Open Design은 로컬 우선이며 Apache-2.0입니다. 여러분의 파일, 산출물, DESIGN.md는 여러분 자신의 레포에 머물고, Anthropic 자격 증명은 에이전트가 직접 사용하며 결코 Open Design 서버를 거치지 않습니다."}], "ctaTitle": "Claude Code로, 개방적인 방식으로 디자인하세요.", "ctaBody": "자신의 Anthropic 키 또는 Claude 구독을 가져오고, 모든 파일을 로컬에 유지하며, 이미 쓰고 있는 에이전트 주위에 엄선된 디자인 라이브러리를 더하세요.", "ctaActions": [{"label": "Open Design 안에서 Claude Code 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "지원되는 모든 에이전트 보기"},
      },
      'codex': {
        ...en['codex']!,
        title: "디자인을 위한 Codex — Open Design",
        description: "사람들이 UI와 웹 디자인에 OpenAI Codex를 활용하는 방법 — Product Design 플러그인, Figma 통합, 프런트엔드 skill — 그리고 Open Design이 Codex를 로컬 우선의 오픈소스 디자인 에이전트로 바꾸는 방식.",
        breadcrumb: "Codex",
        label: "에이전트 · Codex",
        heading: "디자인을 위한 Codex.",
        lead: "Codex는 OpenAI의 코딩 에이전트입니다. Product Design 플러그인과 Figma 통합과 함께 진지한 디자인 도구가 되었습니다. Open Design은 Codex를 오픈소스 디자인 워크플로에 연결합니다 — 자신의 OpenAI 키 또는 ChatGPT 구독, 자신의 파일, 로컬 우선.",
        rich: {"heroCtaLead": "Open Design은 Codex를 로컬 우선의 오픈소스 디자인 에이전트로 바꿉니다 — 자신의 OpenAI 키, 자신의 파일, 그리고 그 주위를 감싸는 엄선된 skill 및 디자인 시스템 라이브러리.", "heroCtaActions": [{"label": "Open Design 안에서 Codex 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex는 코드 생성기로 시작했지만, 2026년에 — 올바른 레퍼런스, skill, 검증 루프를 주기만 하면 — 실제 인터페이스를 디자인하는 신뢰할 만한 도구가 되었습니다. 이 글은 UI, 프런트엔드, 디자인 시스템 작업에 Codex를 활용하고, 이를 Open Design과 함께 구조화된 디자인 워크플로에 연결하는 실용적이고 처음부터 끝까지 이어지는 가이드입니다.", "오늘날 Codex가 무엇인지, 왜 갑자기 프런트엔드에 강한지, 처음부터 설정하는 방법, 스크린샷-투-UI 루프, 공식 Figma 왕복 연동, Cursor 및 Claude Code와의 비교, AI 결과물을 평범해 보이게 만드는 함정, 그리고 Open Design이 개방적이고 로컬 우선인 디자인 레이어로서 이 격차를 메우는 방식을 다룹니다."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex 디자인 피드백 루프: 터미널 에이전트, UI를 렌더링하는 브라우저, 그리고 작업 공간, 다시 돌아오는 피드백 화살표와 함께", "caption": "핵심 루프: Codex는 터미널에서 UI를 만들고, 실제 브라우저에서 렌더링하고 검증하며, 레퍼런스에 맞춰 반복합니다."}, "tocLabel": "이 페이지에서", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex는 실제로 무엇인가"}, {"id": "why-design", "label": "이제 Codex가 디자인에 강한 이유"}, {"id": "setup", "label": "디자인을 위한 Codex 설정하기 (처음부터)"}, {"id": "screenshot-workflow", "label": "스크린샷-투-UI 워크플로"}, {"id": "figma", "label": "Codex + Figma 왕복 연동"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "함정과 “AI 티” 나는 결과물"}, {"id": "open-design", "label": "Open Design에서 Codex로 디자인하기"}, {"id": "faq", "label": "자주 묻는 질문"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex는 실제로 무엇인가 (그리고 무엇이 아닌가)", "blocks": [{"kind": "p", "text": "먼저, “Codex”를 검색하는 거의 모든 사람을 헷갈리게 하는 구분부터. 원래의 OpenAI Codex는 초기 GitHub Copilot을 구동하던 2021년의 코드 자동 완성 모델이었고 2023년에 폐기되었습니다. 이 페이지가 다루는 것은 그것이 아닙니다. 오늘날의 Codex는 OpenAI의 에이전트형 코딩 도구로 — 자연어 작업으로부터 코드를 계획하고, 작성하고, 실행하고, 검증합니다."}, {"kind": "p", "text": "현대의 Codex는 네 가지 표면으로 제공됩니다: 터미널 CLI(Rust로 다시 작성, Apache-2.0 라이선스), VS Code·Cursor·Windsurf용 IDE 확장, 위임된 비동기 작업을 위한 클라우드/웹 환경, 그리고 인앱 브라우저와 Computer Use를 갖춘 데스크톱 앱."}, {"kind": "steps", "items": [{"label": "기본 모델", "body": "2026년 중반 기준 권장 모델은 gpt-5.5이며, gpt-5.4는 OpenAI가 프런트엔드와 컴퓨터 사용을 위해 명시적으로 학습시킨 모델입니다."}, {"label": "지시 파일", "body": "Codex는 프로젝트 규칙을 위해 프로젝트의 AGENTS.md 파일(도구 간 표준)을 읽습니다 — 디자인 컨벤션을 담기에 자연스러운 곳입니다."}, {"label": "샌드박스", "body": "커널 수준 샌드박스(기본은 workspace-write)에서 실행되므로, UI를 편집하는 에이전트가 프로젝트 밖으로 벗어날 수 없습니다."}]}, {"kind": "ul", "items": ["공급사: OpenAI", "자격 증명: OpenAI API 키(BYOK) 또는 ChatGPT 구독(Free / Go / Plus / Pro / Business / Enterprise)", "CLI 라이선스: Apache-2.0, 오픈소스"]}]}, {"id": "why-design", "heading": "이제 Codex가 디자인에 강한 이유", "blocks": [{"kind": "p", "text": "2026년 초에 세 가지가 맞물리며 Codex를 평범한 코드 생성기가 아닌 진짜 디자인 도구로 만들었습니다."}, {"kind": "steps", "items": [{"label": "프런트엔드로 학습된 모델", "body": "OpenAI는 프런트엔드와 컴퓨터 사용을 위해 학습된 첫 번째 메인라인 모델 GPT-5.4를 선보였습니다. 디자인 워크플로 전반에서 이미지 이해가 훨씬 좋아졌고 자기 검증도 더 강해졌습니다. 최종 에셋을 확정하기 전에 무드보드와 시각적 선택지를 생성할 수도 있습니다."}, {"label": "공식 프런트엔드 skill", "body": "openai/skills 카탈로그는 실제 감각을 강제하는 엄선된 frontend-skill을 제공합니다: 카드 없는 레이아웃, 풀블리드 히어로, 브랜드 우선 위계, 절제된 모션, 서체 최대 두 종과 액센트 색 하나 — 그리고 Codex가 만들기 전에 비주얼 논지를 쓰게 합니다."}, {"label": "브라우저 검증", "body": "Playwright skill과 함께 Codex는 실제 브라우저를 열어 브레이크포인트로 크기를 바꾸고, 단지 빌드가 통과하는지만 확인하는 대신 결과물을 레퍼런스와 다시 비교합니다."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "디자인 시스템, skill, 레퍼런스 이미지가 좋은 디자인 결과물로 수렴하는 것을 보여주는 다이어그램", "caption": "감각은 여러분이 제공하는 세 가지 입력에서 나옵니다: 디자인 시스템, skill, 그리고 실제 레퍼런스 이미지."}, {"kind": "p", "text": "세 가지 모두의 바탕에 깔린 교훈: Codex는 기본적으로 감각을 가지고 있지 않습니다. 제약 — 디자인 시스템, 미학 skill, 구체적 레퍼런스 — 을 주면 좋은 디자인을 만들어 냅니다. Open Design은 바로 그 입력들을 패키징하며, 그래서 둘이 잘 맞물립니다(아래에서 자세히)."}]}, {"id": "setup", "heading": "디자인 작업을 위한 Codex 설정하기, 처음부터", "blocks": [{"kind": "p", "text": "깨끗한 머신에서 UI를 만들고 검증할 수 있는 Codex까지 가는 전체 경로는 다음과 같습니다."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "다섯 단계 설정 흐름: 설치, 인증, 구성, skill 설치, 검증", "caption": "설정 순서: 설치 → 인증 → AGENTS.md 구성 → 프런트엔드 skill 설치 → 브라우저 검증 활성화."}, {"kind": "steps", "items": [{"label": "디자인 규칙을 담기", "body": "tokens, 기본 요소, 컨벤션을 AGENTS.md 또는 DESIGN.md에 담고 Codex가 그것을 보도록 가리키세요. 그러면 결과물이 평범한 모습으로 기본 회귀하지 않고 브랜드에 맞춰집니다."}, {"label": "올바른 추론 수준 고르기", "body": "OpenAI는 낮음~중간 추론 수준이 종종 최고 설정보다 더 강한 프런트엔드 결과를 낸다고 밝힙니다."}]}]}, {"id": "screenshot-workflow", "heading": "스크린샷-투-UI 워크플로", "blocks": [{"kind": "p", "text": "Codex로 얻는 가장 효과적인 디자인 루프는 레퍼런스 이미지를 동작하는 반응형 UI로 바꾸고 맞아떨어질 때까지 반복하는 것입니다. OpenAI 자체의 안내는 다섯 단계로 압축됩니다."}, {"kind": "ol", "items": ["가지고 있는 가장 명확한 시각 레퍼런스에서 시작하세요 — 그리고 히어로 한 컷이 아니라 여러 상태(데스크톱과 모바일, hover, 빈 상태, 로딩)를 포함하세요.", "프롬프트에서 구체적으로 쓰세요. 모호한 프롬프트는 평범한 UI를 낳습니다.", "디자인 시스템을 준비하고, tokens와 정식 기본 요소가 어디에 있는지 Codex에게 알려 주세요.", "Codex가 실제 브라우저에서 렌더링하고 브레이크포인트로 크기를 바꾸도록 Playwright 대화형 skill을 활성화하세요.", "Codex가 자신의 구현을 스크린샷과 다시 비교하게 하여 반복하세요 — 단지 빌드가 되는지만 확인하지 마세요."]}, {"kind": "p", "text": "스크린샷을 터미널로 끌어다 놓거나 image 플래그로 이미지를 넣은 다음, 구체적인 제약과 함께 프롬프트하세요:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "두 번째 터미널에서 dev 서버를 띄우고, 프롬프트는 작고 집중되게 유지하며, 좋은 반복은 커밋하고 나쁜 반복은 되돌리세요(되돌릴 때 Codex에게 알려 주세요). 그래야 각 패스가 깨끗한 기반 위에서 쌓입니다."}]}, {"id": "figma", "heading": "Codex + Figma: 디자인 ↔ 코드 왕복 연동", "blocks": [{"kind": "p", "text": "2026년 2월, OpenAI와 Figma는 공식 파트너십을 발표하며 앞선 Figma MCP 베타를 일급의 양방향 통합으로 끌어올렸습니다. 양쪽 방향 모두에서 작동합니다."}, {"kind": "steps", "items": [{"label": "디자인 → 코드", "body": "Figma에서 프레임의 “link to selection”을 복사해 get_design_context와 함께 Codex에 붙여넣고, 기존 컴포넌트 라이브러리를 사용해 디자인을 구현하도록 요청하세요."}, {"label": "코드 → 디자인", "body": "generate_figma_design 도구(“Code to Canvas”)는 실행 중인 라이브 UI를 편집 가능한 Figma 프레임으로 — 화면 전체, 선택한 요소, 또는 파일 전체로 — 되돌립니다."}]}, {"kind": "p", "text": "Figma MCP는 원격 서버로 실행되며 요청 한도에서 면제됩니다. 한 번 추가하면 Codex, Claude Code, Cursor, VS Code 등에서 사용할 수 있습니다 — 바로 Open Design이 오케스트레이션하도록 설계된 이식 가능한 멀티 에이전트 역량의 전형입니다."}]}, {"id": "vs", "heading": "디자인을 위한 Codex vs Cursor vs Claude Code", "blocks": [{"kind": "p", "text": "디자인 작업에 단 하나의 승자는 없습니다 — 에이전트마다 강점이 다르고, 숙련된 팀은 이들을 함께 쌓아 씁니다. 공정한 요약은 다음과 같습니다:"}, {"kind": "table", "columns": ["에이전트", "디자인 강점", "가장 적합한 경우"], "rows": [["Codex", "GPT-5.4 + frontend-skill 이후의 강한 비주얼 완성도; 이미지 이해", "위임된 비동기 빌드, 샌드박스 실행, 이식 가능한 AGENTS.md 규칙"], ["Cursor", "라이브 미리보기와 인라인 편집을 갖춘 시각적 만들고-보기 루프", "IDE 안에서의 긴밀한 반복하며-지켜보는 UI 작업"], ["Claude Code", "구체적인 디자인 결정(hex, 간격, 타입)과 코드베이스를 이해하는 UX", "프런트엔드 추론과 대형 컨텍스트 리팩터링"]]}, {"kind": "p", "text": "커뮤니티에서 반복되는 결론은 감각이 사람에게서 나온다는 것입니다: 셋 모두 skill, 레퍼런스, 제약이 없으면 평범한 미학으로 기본 회귀합니다. 그것이 풀어야 할 진짜 문제이며 — 모델 모양이 아니라 디자인 도구 모양의 문제입니다."}]}, {"id": "pitfalls", "heading": "함정, 그리고 “AI 티” 나는 결과물을 피하는 법", "blocks": [{"kind": "p", "text": "Codex가 생성한 디자인에 대한 가장 흔한 불만은 평범해 보인다는 것입니다 — 부드러운 그라데이션, 떠 있는 패널, 과도하게 둥근 모서리, 극적인 그림자, “AI가 만들었다고 외치는” Inter-와-보라색 분위기. 그 밖에 보고된 문제로는 깨진 모바일 레이아웃, 지시문이 UI 카피에 새어 나오는 것, 사용 한도에 빠르게 도달하는 것이 있습니다."}, {"kind": "steps", "items": [{"label": "프런트엔드 skill 설치하기", "body": "엄선된 미학 skill은 Codex가 기본 모습 대신 실제 방향에 전념하도록 강제합니다."}, {"label": "Playwright 검증 활성화하기", "body": "Codex가 브레이크포인트 전반에서 렌더링하고 스스로 점검하게 하여 레이아웃이 모바일에서 조용히 깨지지 않도록 하세요."}, {"label": "tokens와 레퍼런스 제공하기", "body": "실제 디자인 tokens와 레퍼런스 스크린샷은 결과물 품질을 좌우하는 가장 큰 단일 지렛대입니다."}, {"label": "AGENTS.md에 규칙 담기", "body": "“히어로 카드 금지, 서체 최대 두 종, 브랜드 우선 위계” 같은 스타일 규칙을 에이전트가 매번 읽는 곳에 두세요."}]}, {"kind": "p", "text": "모든 완화책이 에이전트에게 엄선된 디자인 컨텍스트를 주는 것임에 주목하세요. 그 컨텍스트를 프로젝트마다 손으로 유지하는 수고가 바로 Open Design이 없애는 것입니다."}]}, {"id": "open-design", "heading": "Open Design 안에서 Codex로 디자인하기", "blocks": [{"kind": "p", "text": "Open Design은 위 워크플로가 계속 요구하던 그 오픈소스 디자인 레이어입니다. Codex를 일급 어댑터로 취급하고 엄선된 skill 및 디자인 시스템 라이브러리, 구조화된 렌더 파이프라인, 로컬 데스크톱 UI로 감싸 줍니다 — 그래서 Codex를 좋게 만드는 디자인 컨텍스트가 매번 손으로 조립하는 대신 첫 실행부터 갖춰져 있습니다."}, {"kind": "ol", "items": ["Open Design을 설치하고 에이전트로 Codex를 선택하세요.", "OpenAI API 키(BYOK) 또는 ChatGPT 구독으로 인증하세요 — 자격 증명은 여러분의 머신에 머물며 결코 저희를 거쳐 프록시되지 않습니다.", "디자인 시스템과 skill을 고른 다음, 일관된 감각으로 덱, 프로토타입, 랜딩 페이지를 생성하세요.", "모든 산출물과 DESIGN.md 파일은 호스팅 클라우드가 아니라 여러분 자신의 레포에 존재합니다."]}, {"kind": "p", "text": "같은 Codex 에이전트, 같은 키 — 그 위에 실제로 이식 가능한 오픈소스 디자인 워크플로가 더해집니다. 로컬 우선이며 Apache-2.0이라, 여러분의 작업이나 자격 증명 중 어떤 것도 머신을 떠나지 않습니다."}]}], "faqTitle": "자주 묻는 질문", "faq": [{"name": "OpenAI Codex가 정말 디자인 작업을 할 수 있나요?", "text": "네 — 프런트엔드 skill, 디자인 시스템, 그리고 실제 레퍼런스 이미지가 컨텍스트에 있으면 Codex는(특히 GPT-5.4에서) 양산 품질의 반응형 UI를 만들고 브라우저에서 검증할 수 있습니다. 그런 컨텍스트가 없으면 평범한 모습으로 기본 회귀하는 경향이 있는데, 그것이 바로 Open Design이 메우는 격차입니다."}, {"name": "이것이 OpenAI Codex Product Design 플러그인인가요?", "text": "아니요. Open Design은 Codex를 에이전트로 통합하는 독립적인 오픈소스 프로젝트입니다. 로컬 우선의 개방적인 skill 및 디자인 시스템 라이브러리로 OpenAI 자체 도구를 보완합니다."}, {"name": "Codex로 디자인하려면 ChatGPT 구독이 필요한가요?", "text": "OpenAI API 키(BYOK) 또는 ChatGPT 구독 중 어느 쪽이든 사용할 수 있습니다. ChatGPT 로그인은 대체로 더 넉넉한 한도를 주며, Open Design은 어느 경우든 결코 여러분의 자격 증명을 프록시하지 않습니다."}, {"name": "프런트엔드 디자인에는 Codex인가요, Claude Code인가요?", "text": "둘 다 강력합니다. Claude Code는 구체적이고 코드베이스를 이해하는 디자인 결정으로 알려져 있고, Codex는 GPT-5.4 이후 강한 비주얼 완성도를 갖추었으며 위임된 샌드박스 빌드에 능합니다. 많은 팀이 둘 다 씁니다 — Open Design을 쓰면 디자인 워크플로를 바꾸지 않고 에이전트를 전환할 수 있습니다."}, {"name": "Codex를 Figma에 어떻게 연결하나요?", "text": "공식 Figma MCP 서버를 추가하세요(codex mcp add figma --url https://mcp.figma.com/mcp). 그러면 get_design_context로 Figma 프레임을 코드로 구현하고, generate_figma_design으로 실행 중인 UI를 편집 가능한 Figma 프레임으로 되돌릴 수 있습니다."}, {"name": "평범한 “AI 티” 미학을 어떻게 피하나요?", "text": "프런트엔드 skill을 설치하고, 실제 디자인 tokens와 레퍼런스 스크린샷을 제공하며, 브랜드 규칙을 AGENTS.md에 담고, Playwright 검증을 활성화하세요. Open Design은 이것들을 엄선한 라이브러리로 제공하여 프로젝트마다 하는 설정을 건너뛰게 해 줍니다."}, {"name": "Open Design은 OpenAI와 제휴되어 있나요?", "text": "아니요. Codex는 OpenAI의 제품이며, Open Design은 이를 일급 어댑터로 지원하는 독립적인 오픈소스 프로젝트입니다. OpenAI와 Codex는 OpenAI의 상표입니다."}, {"name": "제 파일과 자격 증명은 안전한가요?", "text": "네 — Open Design은 로컬 우선입니다. 여러분의 파일, 산출물, DESIGN.md는 여러분 자신의 레포에 머물고, OpenAI 자격 증명은 에이전트가 직접 사용하며 결코 Open Design 서버를 거치지 않습니다."}], "ctaTitle": "Codex로, 개방적인 방식으로 디자인하세요.", "ctaBody": "자신의 OpenAI 키를 가져오고, 모든 파일을 로컬에 유지하며, 이미 쓰고 있는 에이전트 주위에 엄선된 디자인 라이브러리를 더하세요.", "ctaActions": [{"label": "Open Design 안에서 Codex 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "지원되는 모든 에이전트 보기"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "디자이너를 위한 Cursor — Open Design",
        description: "디자이너가 UI와 웹 디자인에 Cursor를 활용하는 방법 — Design Mode, Figma-투-코드, Figma MCP — 그리고 Open Design이 Cursor를 로컬 우선의 오픈소스 디자인 에이전트로 바꾸는 방식.",
        breadcrumb: "Cursor",
        label: "에이전트 · Cursor",
        heading: "디자이너를 위한 Cursor.",
        lead: "Cursor는 AI 코드 에디터이며, 이제 시각적 Design Mode를 갖추었습니다. 디자이너는 이를 활용해 포인팅과 드로잉으로 UI를 편집하고 Figma를 코드로 바꿉니다. Open Design은 Cursor Agent를 파일을 로컬에 유지하는 오픈소스 디자인 워크플로에 연결합니다.",
        rich: {"heroCtaLead": "Open Design은 Cursor를 로컬 우선의 오픈소스 디자인 에이전트로 바꿉니다 — 자신의 Cursor 계정 또는 모델 키, 자신의 파일, 그리고 그 주위를 감싸는 엄선된 skill 및 디자인 시스템 라이브러리.", "heroCtaActions": [{"label": "Open Design 안에서 Cursor 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor는 “만들고 렌더링되는 것을 지켜본다”를 UI 출시의 기본 방식으로 만든 AI 우선 코드 에디터입니다. Agent 모드, 인라인 편집, 에디터 내 미리보기, 그리고 MCP를 통한 Figma와 함께 — 올바른 레퍼런스, 규칙, 검증 루프를 주기만 하면 — 진정한 디자인 도구가 되었습니다. 이 글은 UI, 프런트엔드, 디자인 시스템 작업에 Cursor를 활용하고, 이를 Open Design과 함께 구조화된 디자인 워크플로에 연결하는 실용적이고 처음부터 끝까지 이어지는 가이드입니다.", "Cursor가 실제로 무엇인지, 왜 긴밀한 반복하며-지켜보는 루프가 디자인에 좋은지, 처음부터 설정하는 방법, 스크린샷-과-미리보기-투-UI 루프, MCP를 통한 Figma 왕복 연동, Codex 및 Claude Code와의 비교, AI 결과물을 평범해 보이게 만드는 함정, 그리고 Open Design이 개방적이고 로컬 우선인 디자인 레이어로서 이 격차를 메우는 방식을 다룹니다."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor 디자인 수렴: 왼쪽에 에디터, 가운데에 Cursor 마크를 중심에 둔 엄선된 skill 및 디자인 시스템 허브, 오른쪽에 렌더링된 UI", "caption": "핵심 아이디어: Cursor는 에디터에서 UI를 편집하고 렌더링하며, 엄선된 디자인 허브가 결과물을 의도적으로 보이게 만드는 시스템, skill, 레퍼런스를 공급합니다."}, "tocLabel": "이 페이지에서", "toc": [{"id": "what-is-cursor", "label": "Cursor는 실제로 무엇인가"}, {"id": "why-design", "label": "Cursor가 디자인에 강한 이유"}, {"id": "setup", "label": "디자인을 위한 Cursor 설정하기 (처음부터)"}, {"id": "preview-workflow", "label": "미리보기-투-UI 워크플로"}, {"id": "figma", "label": "MCP를 통한 Cursor + Figma"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "함정과 “AI 티” 나는 결과물"}, {"id": "open-design", "label": "Open Design에서 Cursor로 디자인하기"}, {"id": "faq", "label": "자주 묻는 질문"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor는 실제로 무엇인가", "blocks": [{"kind": "p", "text": "Cursor는 Anysphere가 만든 AI 우선 코드 에디터입니다. VS Code의 포크라서 익숙한 에디터, 확장, 키바인딩을 유지하지만, 프로젝트 전체를 읽고 여러 파일을 편집하며 명령을 실행하고 여러분과 함께 루프를 돌며 반복할 수 있는 AI 에이전트를 중심으로 워크플로를 다시 짰습니다."}, {"kind": "p", "text": "디자인 작업에서 중요한 표면은 Agent 모드(원하는 결과를 설명하면 Cursor가 파일 전반에 걸쳐 계획하고 편집), 빠른 조정을 위한 인라인 편집과 Tab 자동 완성, 창을 떠나지 않고 실행 중인 UI를 볼 수 있는 에디터 내 미리보기/브라우저, 그리고 라이브 Figma 파일 같은 외부 컨텍스트를 끌어오게 해 주는 MCP 지원입니다."}, {"kind": "steps", "items": [{"label": "프로젝트 규칙", "body": "Cursor는 프로젝트 지시 파일 — `.cursor/rules` 아래 버전 관리되는 `.mdc` 규칙, 그리고 평문 `AGENTS.md` — 을 읽으므로, 에이전트가 매번 읽는 곳에 디자인 컨벤션을 담을 수 있습니다."}, {"label": "모델", "body": "Cursor는 모델에 유연합니다: 구독을 통해 프런티어 모델을 제공하고, 자신의 모델 키를 가져오는 것도 지원하므로 같은 에디터 워크플로 뒤의 엔진을 직접 고를 수 있습니다."}, {"label": "MCP", "body": "Model Context Protocol을 구사하므로 외부 서버 — 가장 관련성 높은 Figma MCP 서버 — 가 에이전트의 일급 컨텍스트가 됩니다."}]}, {"kind": "ul", "items": ["공급사: Anysphere", "자격 증명: Cursor 계정 / 구독(Hobby / Pro / Business) 또는 자신의 모델 키(BYOK)", "형태: 에디터 내 에이전트와 미리보기를 갖춘 AI 우선 코드 에디터(VS Code 포크)"]}]}, {"id": "why-design", "heading": "Cursor가 디자인에 강한 이유", "blocks": [{"kind": "p", "text": "Cursor의 디자인 강점은 단일 기능이 아닙니다 — 만들고-보기 루프의 긴밀함입니다. 세 가지가 이를 평범한 코드 생성기가 아닌 디자인 도구처럼 느껴지게 합니다."}, {"kind": "steps", "items": [{"label": "긴밀한 반복하며-지켜보는 루프", "body": "프롬프트하면 Cursor가 파일 전반을 편집하고, 에디터 내 미리보기가 결과를 즉시 렌더링합니다 — 그래서 별도의 터미널과 브라우저를 오가는 대신 몇 초 만에 간격, 위계, 모션을 조정합니다."}, {"label": "직접 시각 편집", "body": "채팅을 넘어, Cursor는 미리보기에서 요소를 선택해 스타일을 미세 조정하게 해 주므로, 작은 시각적 수정이 코드 고고학이 아니라 디자인 편집처럼 느껴집니다."}, {"label": "프로젝트 규칙과 MCP 컨텍스트", "body": "`.cursor/rules`(또는 `AGENTS.md`)와 Figma MCP 서버와 함께, 에이전트는 추측하는 대신 여러분의 tokens, 컴포넌트, 실제 디자인 명세에 맞춰 작업합니다."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "디자인 시스템, skill, 레퍼런스 이미지가 좋은 디자인 결과물로 수렴하는 것을 보여주는 다이어그램", "caption": "감각은 여러분이 제공하는 세 가지 입력에서 나옵니다: 디자인 시스템, skill, 그리고 실제 레퍼런스 이미지."}, {"kind": "p", "text": "교훈은 모든 에이전트가 가르치는 것과 같습니다: Cursor는 기본적으로 감각을 가지고 있지 않습니다. 제약 — 디자인 시스템, 미학 skill, 구체적 레퍼런스 — 을 주면 좋은 디자인을 만들어 냅니다. Open Design은 바로 그 입력들을 패키징하며, 그래서 둘이 잘 맞물립니다(아래에서 자세히)."}]}, {"id": "setup", "heading": "디자인 작업을 위한 Cursor 설정하기, 처음부터", "blocks": [{"kind": "p", "text": "깨끗한 머신에서 디자인 시스템에 맞춰 UI를 만들고, 미리 보고, 검증할 수 있는 Cursor까지 가는 전체 경로는 다음과 같습니다."}, {"kind": "ol", "items": ["cursor.com에서 Cursor를 설치하고 Cursor 계정으로 로그인하거나, Settings에서 자신의 모델 키(BYOK)를 구성하세요.", "프로젝트를 열고 채팅 / Agent 패널에서 모델을 고르세요.", "프로젝트 규칙을 추가하세요: 구조화되고 glob 범위가 지정된 컨벤션을 위해 `.cursor/rules/*.mdc`를, 또는 간단하고 읽기 쉬운 지시를 위해 평문 `AGENTS.md`를 만드세요.", "에이전트가 라이브 디자인 컨텍스트를 읽을 수 있도록 Figma MCP 서버를 연결하세요(선택).", "dev 서버를 실행하고 에디터 내 미리보기를 사용해 반복하면서 UI를 보고 검증하세요."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "다섯 단계 설정 흐름: 설치, 인증, 규칙 구성, skill 추가, 검증", "caption": "설정 순서: 설치 → 인증 → 프로젝트 규칙 구성 → skill 추가 → 미리보기 검증 활성화."}, {"kind": "p", "text": "최소한의 프로젝트 규칙 파일은 에이전트가 평범한 모습으로 기본 회귀하는 대신 브랜드에 맞춰 디자인하게 만듭니다. Cursor가 매번 읽는 곳에 두세요:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "디자인 규칙을 담기", "body": "tokens, 기본 요소, 컨벤션을 `.cursor/rules` 또는 `AGENTS.md`에 담고 Cursor가 그것을 보도록 가리키세요. 그러면 결과물이 평범한 모습으로 기본 회귀하지 않고 브랜드에 맞춰집니다."}, {"label": "프롬프트를 작게 유지하기", "body": "Cursor의 긴밀한 루프는 집중된 요청에 보답합니다 — 한 번에 컴포넌트나 상태 하나씩 반복하고 패스 사이마다 미리보기를 지켜보세요."}]}]}, {"id": "preview-workflow", "heading": "미리보기-투-UI 워크플로", "blocks": [{"kind": "p", "text": "Cursor로 얻는 가장 효과적인 디자인 루프는 레퍼런스를 동작하는 반응형 UI로 바꾸고 에디터에서 맞아떨어질 때까지 반복하는 것입니다 — 추측하는 대신 내내 라이브 미리보기를 지켜보면서."}, {"kind": "ol", "items": ["가지고 있는 가장 명확한 시각 레퍼런스에서 시작하세요 — 그리고 히어로 한 컷이 아니라 여러 상태(데스크톱과 모바일, hover, 빈 상태, 로딩)를 포함하세요.", "프롬프트에서 구체적으로 쓰세요. 모호한 프롬프트는 평범한 UI를 낳습니다.", "디자인 시스템을 준비하고, tokens와 정식 기본 요소가 어디에 있는지 Cursor에게 알려 주세요.", "에디터 내 미리보기를 열어 두고 dev 서버를 실행해 각 편집이 여러분이 신경 쓰는 브레이크포인트에서 즉시 렌더링되도록 하세요.", "렌더링된 UI를 레퍼런스와 다시 비교하며 반복하세요 — 그리고 작은 시각적 수정에는 미리보기에서의 직접 요소 선택을 사용하세요."]}, {"kind": "p", "text": "채팅에 이미지를 첨부해 레퍼런스를 넣은 다음, 구체적인 제약과 함께 프롬프트하세요:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "좋은 반복은 커밋하고 나쁜 반복은 되돌리세요(되돌릴 때 Cursor에게 알려 주세요). 그래야 각 패스가 깨끗한 기반 위에서 쌓입니다 — 어떤 에이전트 루프든 흐트러지지 않게 하는 바로 그 규율입니다."}]}, {"id": "figma", "heading": "Cursor + Figma: MCP를 통한 디자인 ↔ 코드", "blocks": [{"kind": "p", "text": "Cursor는 공식 Figma MCP 서버를 통해 Figma에 연결되며, 이는 에이전트에게 납작한 스크린샷이 아니라 라이브 Figma 파일에 대한 구조화된 접근을 줍니다. 그래서 핸드오프에서 추측이 사라집니다."}, {"kind": "steps", "items": [{"label": "디자인 → 코드", "body": "Figma에서 프레임의 링크를 복사해 Cursor에 붙여넣고, 디자인을 구현하도록 요청하세요. MCP 서버는 실제 디자인 컨텍스트 — 컴포넌트, 변수, 레이아웃 데이터, tokens — 를 노출하므로, 생성된 코드가 원본을 근사하는 대신 일치시킵니다."}, {"label": "정렬 유지하기", "body": "Figma에서 디자인 tokens, 스타일, 컴포넌트를 일관되게 사용하면(가능한 경우 Code Connect와 함께), Cursor의 결과물은 기본 요소를 새로 만들지 않고 여러분의 실제 디자인 시스템에 매핑된 상태로 유지됩니다."}]}, {"kind": "p", "text": "원격 Figma MCP 서버를 한 번 설정하면 Cursor에서 일급 컨텍스트로 사용할 수 있습니다. MCP가 개방형 표준이라, 같은 서버를 Cursor, Claude Code, Codex, VS Code에서 재사용할 수 있습니다 — 바로 Open Design이 오케스트레이션하도록 설계된 이식 가능한 멀티 에이전트 역량의 전형입니다."}]}, {"id": "vs", "heading": "디자인을 위한 Cursor vs Codex vs Claude Code", "blocks": [{"kind": "p", "text": "디자인 작업에 단 하나의 승자는 없습니다 — 에이전트마다 강점이 다르고, 숙련된 팀은 이들을 함께 쌓아 씁니다. 공정한 요약은 다음과 같습니다:"}, {"kind": "table", "columns": ["에이전트", "디자인 강점", "가장 적합한 경우"], "rows": [["Cursor", "라이브 에디터 내 미리보기와 직접 요소 편집을 갖춘 시각적 만들고-보기 루프", "IDE 안에서의 긴밀한 반복하며-지켜보는 UI 작업"], ["Codex", "프런트엔드 skill과 함께하는 강한 비주얼 완성도; 이미지 이해와 샌드박스 실행", "위임된 비동기 빌드와 이식 가능한 AGENTS.md 규칙"], ["Claude Code", "구체적인 디자인 결정(hex, 간격, 타입)과 코드베이스를 이해하는 UX", "프런트엔드 추론과 대형 컨텍스트 리팩터링"]]}, {"kind": "p", "text": "커뮤니티에서 반복되는 결론은 감각이 사람에게서 나온다는 것입니다: 셋 모두 skill, 레퍼런스, 제약이 없으면 평범한 미학으로 기본 회귀합니다. 그것이 풀어야 할 진짜 문제이며 — 모델 모양이 아니라 디자인 도구 모양의 문제입니다."}]}, {"id": "pitfalls", "heading": "함정, 그리고 “AI 티” 나는 결과물을 피하는 법", "blocks": [{"kind": "p", "text": "Cursor가 생성한 디자인에 대한 가장 흔한 불만은 평범해 보인다는 것입니다 — 부드러운 그라데이션, 떠 있는 패널, 과도하게 둥근 모서리, 극적인 그림자, “AI가 만들었다고 외치는” Inter-와-보라색 분위기. 그 밖에 보고된 문제로는 모바일에서 깨지는 레이아웃과 지시문이 UI 카피에 새어 나오는 것이 있습니다."}, {"kind": "steps", "items": [{"label": "디자인 skill 추가하기", "body": "엄선된 미학 skill은 Cursor가 기본 모습 대신 실제 방향에 전념하도록 강제합니다."}, {"label": "미리보기로 검증하기", "body": "에디터 내 미리보기에서 브레이크포인트 전반에 걸쳐 렌더링하고 스스로 점검하여 레이아웃이 모바일에서 조용히 깨지지 않도록 하세요."}, {"label": "tokens와 레퍼런스 제공하기", "body": "실제 디자인 tokens와 레퍼런스 스크린샷은 결과물 품질을 좌우하는 가장 큰 단일 지렛대입니다."}, {"label": "`.cursor/rules`에 규칙 담기", "body": "“히어로 카드 금지, 서체 최대 두 종, 브랜드 우선 위계” 같은 스타일 규칙을 에이전트가 매번 읽는 곳에 두세요."}]}, {"kind": "p", "text": "모든 완화책이 에이전트에게 엄선된 디자인 컨텍스트를 주는 것임에 주목하세요. 그 컨텍스트를 프로젝트마다 손으로 유지하는 수고가 바로 Open Design이 없애는 것입니다."}]}, {"id": "open-design", "heading": "Open Design 안에서 Cursor로 디자인하기", "blocks": [{"kind": "p", "text": "Open Design은 위 워크플로가 계속 요구하던 그 오픈소스 디자인 레이어입니다. Cursor를 일급 어댑터로 취급하고 엄선된 skill 및 디자인 시스템 라이브러리, 구조화된 렌더 파이프라인, 로컬 데스크톱 UI로 감싸 줍니다 — 그래서 Cursor를 좋게 만드는 디자인 컨텍스트가 매번 손으로 조립하는 대신 첫 실행부터 갖춰져 있습니다."}, {"kind": "ol", "items": ["Open Design을 설치하고 에이전트로 Cursor를 선택하세요.", "Cursor 계정 또는 자신의 모델 키(BYOK)로 인증하세요 — 자격 증명은 여러분의 머신에 머물며 결코 저희를 거쳐 프록시되지 않습니다.", "디자인 시스템과 skill을 고른 다음, 일관된 감각으로 덱, 프로토타입, 랜딩 페이지를 생성하세요.", "모든 산출물과 DESIGN.md 파일은 호스팅 클라우드가 아니라 여러분 자신의 레포에 존재합니다."]}, {"kind": "p", "text": "같은 Cursor 에이전트, 같은 키 — 그 위에 실제로 이식 가능한 오픈소스 디자인 워크플로가 더해집니다. 로컬 우선이며 Apache-2.0이라, 여러분의 작업이나 자격 증명 중 어떤 것도 머신을 떠나지 않습니다."}]}], "faqTitle": "자주 묻는 질문", "faq": [{"name": "Cursor가 정말 디자인 작업을 할 수 있나요?", "text": "네 — 디자인 skill, 디자인 시스템, 그리고 실제 레퍼런스 이미지가 컨텍스트에 있으면 Cursor는 양산 품질의 반응형 UI를 만들고, 에디터 내 미리보기로 시각적으로 검증하고 다듬게 해 줍니다. 그런 컨텍스트가 없으면 평범한 모습으로 기본 회귀하는 경향이 있는데, 그것이 바로 Open Design이 메우는 격차입니다."}, {"name": "이것이 공식 Cursor 제품인가요?", "text": "아니요. Open Design은 Cursor를 에이전트로 통합하는 독립적인 오픈소스 프로젝트입니다. 로컬 우선의 개방적인 skill 및 디자인 시스템 라이브러리로 Cursor를 보완합니다."}, {"name": "Cursor로 디자인하려면 Cursor 구독이 필요한가요?", "text": "Cursor 계정 / 구독을 사용하거나 자신의 모델 키(BYOK)를 가져올 수 있습니다. Open Design은 어느 경우든 결코 여러분의 자격 증명을 프록시하지 않습니다 — 자격 증명은 에이전트가 직접 사용합니다."}, {"name": "프런트엔드 디자인에는 Cursor인가요, Claude Code인가요?", "text": "둘 다 강력합니다. Claude Code는 구체적이고 코드베이스를 이해하는 디자인 결정으로 알려져 있고, Cursor의 강점은 에디터 안의 라이브 미리보기를 갖춘 긴밀한 만들고-보기 루프입니다. 많은 팀이 둘 다 씁니다 — Open Design을 쓰면 디자인 워크플로를 바꾸지 않고 에이전트를 전환할 수 있습니다."}, {"name": "Cursor를 Figma에 어떻게 연결하나요?", "text": "Cursor에 공식 Figma MCP 서버를 추가한 다음, Figma 프레임 링크를 채팅에 붙여넣고 Cursor에게 구현하도록 요청하세요. 서버는 실제 컴포넌트, 변수, 레이아웃 데이터를 노출하므로 생성된 코드가 원본 디자인과 일치합니다."}, {"name": "평범한 “AI 티” 미학을 어떻게 피하나요?", "text": "디자인 skill을 추가하고, 실제 디자인 tokens와 레퍼런스 스크린샷을 제공하며, 브랜드 규칙을 `.cursor/rules` 또는 `AGENTS.md`에 담고, 미리보기에서 브레이크포인트 전반을 검증하세요. Open Design은 이것들을 엄선한 라이브러리로 제공하여 프로젝트마다 하는 설정을 건너뛰게 해 줍니다."}, {"name": "Open Design은 Cursor 또는 Anysphere와 제휴되어 있나요?", "text": "아니요. Cursor는 Anysphere의 제품이며, Open Design은 이를 일급 어댑터로 지원하는 독립적인 오픈소스 프로젝트입니다. Cursor와 Anysphere는 Anysphere, Inc.의 상표입니다."}, {"name": "제 파일과 자격 증명은 안전한가요?", "text": "네 — Open Design은 로컬 우선입니다. 여러분의 파일, 산출물, DESIGN.md는 여러분 자신의 레포에 머물고, Cursor 또는 모델 자격 증명은 에이전트가 직접 사용하며 결코 Open Design 서버를 거치지 않습니다."}], "ctaTitle": "Cursor로, 개방적인 방식으로 디자인하세요.", "ctaBody": "자신의 Cursor 계정 또는 모델 키를 가져오고, 모든 파일을 로컬에 유지하며, 이미 쓰고 있는 에이전트 주위에 엄선된 디자인 라이브러리를 더하세요.", "ctaActions": [{"label": "Open Design 안에서 Cursor 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "지원되는 모든 에이전트 보기"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "디자인을 위한 OpenCode — Open Design",
        description: "사람들이 UI와 웹 디자인에 OpenCode를 활용하는 방법 — design.md 파일, UI/UX skill, Figma MCP — 그리고 Open Design이 OpenCode를 로컬 우선의 오픈소스 디자인 에이전트로 바꾸는 방식.",
        breadcrumb: "OpenCode",
        label: "에이전트 · OpenCode",
        heading: "디자인을 위한 OpenCode.",
        lead: "OpenCode는 오픈소스 터미널 AI 코딩 에이전트입니다. 디자이너는 여기에 디자인 skill과 DESIGN.md 파일을 붙여 실제 UI를 생성합니다. Open Design은 이를 구조화된 오픈소스 워크플로로 만듭니다 — 자신의 공급자 키를 가져오고, 모든 것을 로컬에 유지하세요.",
        rich: {"heroCtaLead": "Open Design은 OpenCode를 로컬 우선의 오픈소스 디자인 에이전트로 바꿉니다 — 자신의 공급자 키로 고른 어떤 모델이든, 자신의 파일, 그리고 그 주위를 감싸는 엄선된 skill 및 디자인 시스템 라이브러리.", "heroCtaActions": [{"label": "Open Design 안에서 OpenCode 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode는 의도적으로 모델에 구애받지 않는 오픈소스의 터미널 우선 AI 코딩 에이전트입니다: 자신의 공급자 키를 가져와 같은 워크플로 뒤에서 원하는 어떤 모델이든 실행합니다. 그 개방성은 디자인 작업에 자연스러운 기반이 됩니다 — 하지만 모든 에이전트가 그렇듯, 올바른 레퍼런스, skill, 검증 루프를 주어야만 좋은 UI를 만들어 냅니다. 이 글은 UI, 프런트엔드, 디자인 시스템 작업에 OpenCode를 활용하고, 이를 Open Design과 함께 구조화된 디자인 워크플로에 연결하는 실용적이고 처음부터 끝까지 이어지는 가이드입니다.", "OpenCode가 실제로 무엇인지, 왜 모델에 구애받지 않는 개방형 에이전트가 디자인에 잘 맞는지, 처음부터 설정하는 방법, 스크린샷-투-UI 루프, AGENTS.md와 MCP가 이를 어떻게 확장하는지, Codex·Claude Code·Cursor와의 비교, AI 결과물을 평범해 보이게 만드는 함정, 그리고 Open Design이 개방적이고 로컬 우선인 디자인 레이어로서 이 격차를 메우는 방식을 다룹니다 — 두 프로젝트 모두 오픈소스이고 여러분 자신의 머신에서 실행되므로 자연스러운 짝입니다."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode 디자인 피드백 루프: 터미널 TUI 에이전트, UI를 렌더링하는 브라우저, 그리고 작업 공간, 다시 돌아오는 피드백 화살표와 함께", "caption": "핵심 루프: OpenCode는 터미널에서 UI를 만들고, 실제 브라우저에서 렌더링하고 검증하며, 레퍼런스에 맞춰 반복합니다 — 여러분이 고른 어떤 모델로든."}, "tocLabel": "이 페이지에서", "toc": [{"id": "what-is-opencode", "label": "OpenCode는 실제로 무엇인가"}, {"id": "why-design", "label": "개방형의 모든-모델 에이전트가 디자인에 맞는 이유"}, {"id": "setup", "label": "디자인을 위한 OpenCode 설정하기 (처음부터)"}, {"id": "screenshot-workflow", "label": "스크린샷-투-UI 워크플로"}, {"id": "extend", "label": "AGENTS.md, MCP, 그리고 공유 가능한 세션"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "함정과 “AI 티” 나는 결과물"}, {"id": "open-design", "label": "Open Design에서 OpenCode로 디자인하기"}, {"id": "faq", "label": "자주 묻는 질문"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode는 실제로 무엇인가", "blocks": [{"kind": "p", "text": "OpenCode는 터미널을 위해 만들어진 오픈소스 AI 코딩 에이전트로, SST(Anomaly Innovations)를 만든 팀이 유지보수합니다. 저장소를 읽고, 명령을 실행하고, 파일을 편집하며, 대규모 언어 모델과 대화합니다 — 하지만 공급사에 묶인 에이전트와 달리, 자체 모델을 함께 제공하지 않습니다. 원하는 어떤 공급자와 모델이든 가리키고 자신의 키를 가져옵니다."}, {"kind": "p", "text": "터미널 UI(TUI)로 실행되며, 같은 엔진 위에 데스크톱 앱과 IDE 확장이 얹힙니다. 내부적으로 클라이언트/서버 아키텍처를 사용하므로, 실제로 작업을 하는 에이전트가 여러분이 구동하는 표면과 분리되어 있습니다. 두 가지 내장 에이전트 — build와 plan — 는 Tab 키로 전환됩니다."}, {"kind": "steps", "items": [{"label": "모델에 구애받지 않음", "body": "모델과 공급자는 개방형 카탈로그인 models.dev에서 가져옵니다. opencode.json에서 provider/model-id 문자열로 구성하고, 로드하고 싶지 않은 공급자를 비활성화할 수 있습니다 — 그래서 같은 디자인 워크플로가 Anthropic, OpenAI, Google, OpenRouter, 로컬 모델 등에서 실행됩니다."}, {"label": "지시 파일", "body": "OpenCode는 프로젝트 규칙을 위해 프로젝트의 AGENTS.md 파일(도구 간 표준이며 CLAUDE.md와도 호환)을 읽습니다 — 디자인 컨벤션을 담기에 자연스러운 곳입니다. /init를 실행해 하나 생성하세요."}, {"label": "확장 가능", "body": "LSP 통합, MCP 서버, 테마, 키바인드, 커스텀 명령을 지원하며, 협업을 위한 공유 가능한 세션 링크도 제공합니다."}]}, {"kind": "ul", "items": ["유지보수: SST / Anomaly Innovations (오픈소스 프로젝트)", "자격 증명: 자신의 모델 공급자 API 키 — BYOK, 공급사 종속 없음", "라이선스: MIT, 오픈소스"]}]}, {"id": "why-design", "heading": "개방형의 모든-모델 에이전트가 디자인 작업에 맞는 이유", "blocks": [{"kind": "p", "text": "OpenCode는 공급사 에이전트처럼 단일한 “디자인 모델”을 가지고 있지 않습니다 — 그리고 그것이 핵심입니다. 모델에 구애받지 않고 개방적이기 때문에, 현재 프런트엔드에 가장 강한 모델로 같은 디자인 워크플로를 실행하고, 나중에 바꾸고, 로컬 모델로 되돌릴 수 있습니다. 모두 설정을 바꾸지 않고서."}, {"kind": "p", "text": "하지만 모델 선택만으로는 감각을 살 수 없습니다. 모든 코딩 에이전트가 그렇듯, OpenCode도 제약을 주지 않으면 평범한 UI를 만듭니다. 좋은 디자인 결과물은 여러분이 제공하는 세 가지 입력에서 나옵니다."}, {"kind": "steps", "items": [{"label": "디자인 시스템", "body": "에이전트가 재사용하는 실제 tokens, 기본 요소, 컨벤션 — 그래서 결과물이 평범한 모습으로 기본 회귀하지 않고 브랜드에 맞춰집니다."}, {"label": "미학 skill", "body": "실제 감각을 강제하는 엄선된 skill — 절제된 모션, 브랜드 우선 위계, 서체 최대 두 종과 액센트 색 하나 — 그리고 에이전트가 만들기 전에 방향에 전념하게 합니다."}, {"label": "구체적 레퍼런스", "body": "실제 레퍼런스 이미지와 여러 상태(데스크톱과 모바일, hover, 빈 상태, 로딩), 히어로 한 컷이 아니라."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "디자인 시스템, skill, 레퍼런스 이미지가 좋은 디자인 결과물로 수렴하는 것을 보여주는 다이어그램", "caption": "감각은 여러분이 제공하는 세 가지 입력에서 나옵니다: 디자인 시스템, skill, 그리고 실제 레퍼런스 이미지 — 어떤 모델을 실행하든 무관하게."}, {"kind": "p", "text": "교훈: OpenCode는 모델 자유를 주지만, 감각은 여전히 엄선된 디자인 컨텍스트에서 나옵니다. Open Design은 바로 그 입력들을 패키징하며, 그래서 둘이 잘 맞물립니다 — 둘 다 오픈소스이고 로컬 우선입니다(아래에서 자세히)."}]}, {"id": "setup", "heading": "디자인 작업을 위한 OpenCode 설정하기, 처음부터", "blocks": [{"kind": "p", "text": "깨끗한 머신에서 UI를 만들고 검증할 수 있는 OpenCode까지 가는 전체 경로는 다음과 같습니다."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "다섯 단계 설정 흐름: 설치, 공급자 키로 인증, AGENTS.md 구성, skill 추가, 검증", "caption": "설정 순서: 설치 → 인증(여러분의 공급자 키) → AGENTS.md 구성 → skill 추가 → 실제 브라우저에서 검증."}, {"kind": "steps", "items": [{"label": "디자인 규칙을 담기", "body": "tokens, 기본 요소, 컨벤션을 AGENTS.md(또는 거기서 참조하는 DESIGN.md)에 담아 결과물이 평범한 모습으로 기본 회귀하지 않고 브랜드에 맞춰지도록 하세요. opencode.json의 instructions 옵션은 glob을 통해 추가 규칙 파일을 가리킬 수 있습니다."}, {"label": "유능한 모델 고르기", "body": "OpenCode는 모델에 구애받지 않으므로, 디자인 패스를 위해 현재 프런트엔드에 가장 강한 공급자/모델을 고르고 — 워크플로의 나머지는 그대로 두세요."}]}]}, {"id": "screenshot-workflow", "heading": "스크린샷-투-UI 워크플로", "blocks": [{"kind": "p", "text": "어떤 에이전트로든 얻는 가장 효과적인 디자인 루프는 레퍼런스 이미지를 동작하는 반응형 UI로 바꾸고 맞아떨어질 때까지 반복하는 것입니다. OpenCode에서도 같은 다섯 단계 형태가 적용됩니다."}, {"kind": "ol", "items": ["가지고 있는 가장 명확한 시각 레퍼런스에서 시작하세요 — 그리고 히어로 한 컷이 아니라 여러 상태(데스크톱과 모바일, hover, 빈 상태, 로딩)를 포함하세요.", "프롬프트에서 구체적으로 쓰세요. 모호한 프롬프트는 평범한 UI를 낳습니다.", "디자인 시스템을 준비하고, tokens와 정식 기본 요소가 어디에 있는지(AGENTS.md에) OpenCode에게 알려 주세요.", "dev 서버를 실행하고 에이전트가 실제 브라우저에서 렌더링하며 브레이크포인트로 크기를 바꿔 결과를 확인하게 하세요.", "OpenCode가 자신의 구현을 스크린샷과 다시 비교하게 하여 반복하세요 — 단지 빌드가 되는지만 확인하지 마세요."]}, {"kind": "p", "text": "TUI에서 @로 파일을 참조해 작업 디렉터리를 퍼지 검색하고, 앞에 !를 붙여 셸 명령을 인라인으로 실행하며, / 명령으로 동작을 구동하세요. 그런 다음 구체적인 제약과 함께 프롬프트하세요:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "프롬프트는 작고 집중되게 유지하고, 좋은 반복은 커밋하고 나쁜 반복은 되돌리세요(되돌릴 때 OpenCode에게 알려 주세요). 그래야 각 패스가 깨끗한 기반 위에서 쌓입니다."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, 그리고 공유 가능한 세션", "blocks": [{"kind": "p", "text": "세 가지 확장 지점이 OpenCode를 지속적인 디자인 작업에 실용적으로 만들며, 셋 모두 개방형 디자인 워크플로에 깔끔하게 매핑됩니다."}, {"kind": "steps", "items": [{"label": "AGENTS.md 규칙", "body": "프로젝트 규칙은 레포 루트의 AGENTS.md(또는 ~/.config/opencode/AGENTS.md의 전역 규칙)에 존재합니다. 매번 읽히는, 여러분의 디자인 컨벤션을 위한 견고한 거처이며, 다른 에이전트가 쓰는 CLAUDE.md 파일과 호환됩니다."}, {"label": "MCP 서버", "body": "OpenCode는 로컬(command)과 원격(URL) MCP 서버를 모두 지원하며 mcp 키 아래에서 구성됩니다 — OpenCode뿐 아니라 여러 에이전트에서 작동하는 디자인 컨텍스트와 외부 도구를 끌어오는 이식 가능한 방법입니다."}, {"label": "공유 가능한 세션", "body": "/share 명령은 협업이나 리뷰를 위해 대화에 대한 공개 링크를 만들고, /unshare가 이를 취소합니다 — 디자인 패스에 대한 피드백을 받기에 유용합니다."}]}, {"kind": "p", "text": "이것들은 이식 가능한 멀티 에이전트 역량입니다 — 바로 Open Design이 프로젝트마다 다시 만드는 대신 오케스트레이션하도록 설계된 종류의 것입니다."}]}, {"id": "vs", "heading": "디자인을 위한 OpenCode vs Codex vs Claude Code vs Cursor", "blocks": [{"kind": "p", "text": "디자인 작업에 단 하나의 승자는 없습니다 — 에이전트마다 강점이 다르고, 숙련된 팀은 이들을 함께 쌓아 씁니다. 공정한 요약은 다음과 같습니다:"}, {"kind": "table", "columns": ["에이전트", "디자인 강점", "가장 적합한 경우"], "rows": [["OpenCode", "오픈소스이며 모델에 구애받지 않음; 하나의 터미널 워크플로 뒤에서 어떤 공급자든 실행", "BYOK 자유, 모델 전환, 완전히 개방적이고 로컬 우선인 설정"], ["Codex", "프런트엔드 skill과 함께하는 강한 비주얼 완성도; 이미지 이해", "위임된 비동기, 샌드박스 빌드, 이식 가능한 AGENTS.md 규칙"], ["Claude Code", "구체적인 디자인 결정(hex, 간격, 타입)과 코드베이스를 이해하는 UX", "프런트엔드 추론과 대형 컨텍스트 리팩터링"], ["Cursor", "라이브 미리보기와 인라인 편집을 갖춘 시각적 만들고-보기 루프", "IDE 안에서의 긴밀한 반복하며-지켜보는 UI 작업"]]}, {"kind": "p", "text": "커뮤니티에서 반복되는 결론은 감각이 사람에게서 나온다는 것입니다: 모두 skill, 레퍼런스, 제약이 없으면 평범한 미학으로 기본 회귀합니다. 그것이 풀어야 할 진짜 문제이며 — 모델 모양이 아니라 디자인 도구 모양의 문제입니다. 바로 그래서 OpenCode 같은 개방형 에이전트가 개방형 디자인 레이어와 그토록 잘 어울립니다."}]}, {"id": "pitfalls", "heading": "함정, 그리고 “AI 티” 나는 결과물을 피하는 법", "blocks": [{"kind": "p", "text": "AI가 생성한 디자인에 대한 가장 흔한 불만은 평범해 보인다는 것입니다 — 부드러운 그라데이션, 떠 있는 패널, 과도하게 둥근 모서리, 극적인 그림자, “AI가 만들었다고 외치는” Inter-와-보라색 분위기. 그 밖에 보고된 문제로는 깨진 모바일 레이아웃과 지시문이 UI 카피에 새어 나오는 것이 있습니다. 이 중 어느 것도 OpenCode만의 문제가 아닙니다. 모두 어떤 에이전트든 엄선된 디자인 컨텍스트 없이 실행될 때 일어나는 일입니다."}, {"kind": "steps", "items": [{"label": "미학 skill 추가하기", "body": "엄선된 디자인 skill은 에이전트가 기본 모습 대신 실제 방향에 전념하도록 강제합니다."}, {"label": "실제 브라우저에서 검증하기", "body": "브레이크포인트 전반에 걸쳐 렌더링하고 스스로 점검하여 레이아웃이 모바일에서 조용히 깨지지 않도록 하세요."}, {"label": "tokens와 레퍼런스 제공하기", "body": "실제 디자인 tokens와 레퍼런스 스크린샷은 결과물 품질을 좌우하는 가장 큰 단일 지렛대입니다."}, {"label": "AGENTS.md에 규칙 담기", "body": "“히어로 카드 금지, 서체 최대 두 종, 브랜드 우선 위계” 같은 스타일 규칙을 에이전트가 매번 읽는 곳에 두세요."}]}, {"kind": "p", "text": "모든 완화책이 — 어떤 모델을 실행하든 무관하게 — 에이전트에게 엄선된 디자인 컨텍스트를 주는 것임에 주목하세요. 그 컨텍스트를 프로젝트마다 손으로 유지하는 수고가 바로 Open Design이 없애는 것입니다."}]}, {"id": "open-design", "heading": "Open Design 안에서 OpenCode로 디자인하기", "blocks": [{"kind": "p", "text": "Open Design은 위 워크플로가 계속 요구하던 그 오픈소스 디자인 레이어입니다. OpenCode를 일급 어댑터로 취급하고 엄선된 skill 및 디자인 시스템 라이브러리, 구조화된 렌더 파이프라인, 로컬 데스크톱 UI로 감싸 줍니다 — 그래서 어떤 에이전트든 좋게 만드는 디자인 컨텍스트가 매번 손으로 조립하는 대신 첫 실행부터 갖춰져 있습니다. 두 프로젝트 모두 오픈소스이고 로컬 우선이라, 이 짝은 자연스럽게 잘 맞습니다."}, {"kind": "ol", "items": ["Open Design을 설치하고 에이전트로 OpenCode를 선택하세요.", "자신의 모델 공급자 API 키(BYOK)로 인증하세요 — 자격 증명은 여러분의 머신에 머물며 결코 저희를 거쳐 프록시되지 않습니다.", "어떤 공급자와 모델이든 고르고, 디자인 시스템과 skill을 더한 다음, 일관된 감각으로 덱, 프로토타입, 랜딩 페이지를 생성하세요.", "모든 산출물과 DESIGN.md 파일은 호스팅 클라우드가 아니라 여러분 자신의 레포에 존재합니다."]}, {"kind": "p", "text": "같은 OpenCode 에이전트, 같은 모델 자유 — 그 위에 실제로 이식 가능한 오픈소스 디자인 워크플로가 더해집니다. 로컬 우선이며 Apache-2.0이라, 여러분의 작업이나 자격 증명 중 어떤 것도 머신을 떠나지 않습니다."}]}], "faqTitle": "자주 묻는 질문", "faq": [{"name": "OpenCode가 정말 디자인 작업을 할 수 있나요?", "text": "네 — 미학 skill, 디자인 시스템, 그리고 실제 레퍼런스 이미지가 컨텍스트에 있으면 OpenCode는 양산 품질의 반응형 UI를 만들고 브라우저에서 검증할 수 있습니다. 모델에 구애받지 않으므로, 현재 프런트엔드에 가장 좋은 모델을 실행할 수 있습니다. 그런 엄선된 컨텍스트가 없으면 평범한 모습으로 기본 회귀하는 경향이 있는데, 그것이 바로 Open Design이 메우는 격차입니다."}, {"name": "디자인에는 OpenCode와 어떤 모델을 써야 하나요?", "text": "원하는 어떤 것이든 — OpenCode는 models.dev를 통해 공급자에 구애받지 않으므로, 같은 워크플로 뒤에서 Anthropic, OpenAI, Google, OpenRouter, 또는 로컬 모델을 실행하고 언제든 전환할 수 있습니다. 디자인 결과물의 품질은 모델 자체보다 여러분의 skill, 디자인 시스템, 레퍼런스에 훨씬 더 좌우됩니다."}, {"name": "Open Design은 OpenCode(SST) 팀이 만들었나요?", "text": "아니요. Open Design은 OpenCode를 에이전트로 통합하는 독립적인 오픈소스 프로젝트입니다. 로컬 우선의 개방적인 skill 및 디자인 시스템 라이브러리로 OpenCode를 보완합니다."}, {"name": "OpenCode로 디자인하려면 특별한 구독이 필요한가요?", "text": "아니요 — OpenCode는 BYOK입니다. 자신의 모델 공급자 API 키를 가져오고, Open Design은 결코 여러분의 자격 증명을 프록시하지 않습니다. 공급사 종속이 없습니다."}, {"name": "프런트엔드 디자인에는 OpenCode인가요, Codex인가요, Claude Code인가요?", "text": "모두 강력하며, 많은 팀이 이들을 함께 쌓아 씁니다. OpenCode의 강점은 완전히 오픈소스이고 모델에 구애받지 않는다는 점이며, Codex는 위임된 샌드박스 빌드에 뛰어나고, Claude Code는 구체적이고 코드베이스를 이해하는 디자인 결정으로 알려져 있습니다. Open Design을 쓰면 디자인 워크플로를 바꾸지 않고 에이전트를 전환할 수 있습니다."}, {"name": "디자인 컨텍스트를 위해 OpenCode를 어떻게 확장하나요?", "text": "규칙을 AGENTS.md에 담고, 이식 가능한 도구와 디자인 컨텍스트를 위해 mcp 키 아래에 MCP 서버를 추가하며, 리뷰를 위해 공유 가능한 세션을 사용하세요. Open Design은 엄선된 skill 및 디자인 시스템 라이브러리를 제공하여 프로젝트마다 하는 설정을 건너뛰게 해 줍니다."}, {"name": "Open Design은 OpenCode 또는 SST와 제휴되어 있나요?", "text": "아니요. OpenCode는 SST(Anomaly Innovations)가 유지보수하는 오픈소스 프로젝트이며, Open Design은 이를 일급 어댑터로 지원하는 독립적인 오픈소스 프로젝트입니다."}, {"name": "제 파일과 자격 증명은 안전한가요?", "text": "네 — Open Design은 로컬 우선입니다. 여러분의 파일, 산출물, DESIGN.md는 여러분 자신의 레포에 머물고, 모델 공급자 자격 증명은 에이전트가 직접 사용하며 결코 Open Design 서버를 거치지 않습니다."}], "ctaTitle": "OpenCode로, 개방적인 방식으로 디자인하세요.", "ctaBody": "자신의 모델 공급자 키를 가져오고, 모든 파일을 로컬에 유지하며, 이미 쓰고 있는 개방형 에이전트 주위에 엄선된 디자인 라이브러리를 더하세요.", "ctaActions": [{"label": "Open Design 안에서 OpenCode 사용하기", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub에서 Star 누르기", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "데스크톱 앱 다운로드", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "지원되는 모든 에이전트 보기"},
      },
    },
    'de': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code für Design — Open Design",
        description: "Wie Designer Claude Code für UI- und Webdesign nutzen und wie Open Design daraus einen echten Design-Agenten macht — local-first, BYOK, mit einer kuratierten skill- und Designsystem-Bibliothek.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code für Design.",
        lead: "Claude Code ist der Terminal-Coding-Agent von Anthropic. Menschen nutzen ihn bereits, um UIs, Designsysteme und Landingpages zu bauen. Open Design bindet ihn in einen echten Design-Workflow ein — bring deinen Anthropic-Key oder dein Claude-Abo mit und behalte jede Datei lokal.",
        rich: {"heroCtaLead": "Open Design macht Claude Code zu einem local-first, quelloffenen Design-Agenten — dein Anthropic-Key oder Claude-Abo, deine Dateien, dazu eine kuratierte skill- und Designsystem-Bibliothek drumherum.", "heroCtaActions": [{"label": "Claude Code in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code gilt weithin als der Coding-Agent mit dem besten Frontend-Geschmack — er argumentiert über Interfaces mit ungewöhnlicher Präzision, nennt exakte hex-Werte, Abstände und Schriftskalen und refaktoriert UI über eine große Codebasis hinweg, ohne den roten Faden zu verlieren. Doch ohne weitere Vorgaben tendiert er trotzdem zu einem generischen Look, solange du ihm kein Designsystem, keine skills und keine echten Referenzen an die Hand gibst. Dies ist ein praktischer End-to-End-Leitfaden, wie du Claude Code für UI-, Frontend- und Designsystem-Arbeit einsetzt und ihn mit Open Design in einen strukturierten Workflow einbindest.", "Er behandelt, was Claude Code wirklich ist, warum er im Frontend stark ist, wie du ihn von null aufsetzt, den CLAUDE.md- und Skills-Workflow, den offiziellen Figma-Roundtrip, wie er im Vergleich zu Codex und Cursor abschneidet, die Fallstricke, die KI-Output generisch wirken lassen, und wie Open Design die Lücke als offene, local-first Design-Schicht schließt."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude-Code-Design-Feedbackschleife: Terminal-Agent, der spezifische Designentscheidungen trifft, ein Browser, der die UI rendert, und ein Workspace, mit einem zurückführenden Feedback-Pfeil", "caption": "Die Kernschleife: Claude Code durchdenkt spezifische UI-Entscheidungen im Terminal, rendert und verifiziert sie in einem echten Browser und nähert sich deinen Referenzen an."}, "tocLabel": "Auf dieser Seite", "toc": [{"id": "what-is-claude-code", "label": "Was Claude Code wirklich ist"}, {"id": "why-design", "label": "Warum Claude Code gut im Design ist"}, {"id": "setup", "label": "Claude Code für Design einrichten (von null)"}, {"id": "skills-workflow", "label": "Der CLAUDE.md- und Skills-Workflow"}, {"id": "figma", "label": "Claude Code + Figma-Roundtrip"}, {"id": "vs", "label": "Claude Code vs. Codex vs. Cursor"}, {"id": "pitfalls", "label": "Fallstricke und der „AI-Slop“-Look"}, {"id": "open-design", "label": "Mit Claude Code in Open Design gestalten"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Was Claude Code wirklich ist", "blocks": [{"kind": "p", "text": "Claude Code ist das agentische Coding-Tool von Anthropic. Es liest deine Codebasis, bearbeitet Dateien, führt Befehle aus und integriert sich in deine Dev-Tools — es plant, schreibt und verifiziert Arbeit aus Aufgaben in natürlicher Sprache, statt nur Zeilen zu vervollständigen."}, {"kind": "p", "text": "Es ist über mehrere Oberflächen verfügbar, die alle dieselbe Engine teilen: eine Terminal-CLI, IDE-Erweiterungen für VS Code, Cursor und JetBrains, eine Desktop-App mit visueller Diff-Prüfung und eine Web-Oberfläche für lang laufende Aufgaben. Deine CLAUDE.md-Dateien, Einstellungen und MCP-Server gelten über alle hinweg."}, {"kind": "steps", "items": [{"label": "Anweisungsdatei", "body": "Claude Code liest zu Beginn jeder Session eine CLAUDE.md-Datei im Projektstamm — der natürliche Ort, um deine Design-Konventionen, tokens und Review-Checklisten zu hinterlegen."}, {"label": "Skills", "body": "Agent Skills bündeln wiederverwendbare Anweisungen, Skripte und Ressourcen, die Claude bei Bedarf lädt — darunter Anthropics offizielle Frontend-Design-skill für Geschmack."}, {"label": "Plan und Subagenten", "body": "Es kann vor dem Handeln planen und Subagenten starten, die parallel an verschiedenen Teilen einer Aufgabe arbeiten, was umfangreiche UI-Refactorings kohärent hält."}]}, {"kind": "ul", "items": ["Anbieter: Anthropic", "Zugangsdaten: Anthropic-API-Key (BYOK, über die Console) oder ein Claude-Abo (Pro / Max)", "Oberflächen: Terminal-CLI, VS Code / Cursor / JetBrains-Erweiterungen, Desktop-App, Web"]}]}, {"id": "why-design", "heading": "Warum Claude Code gut im Design ist", "blocks": [{"kind": "p", "text": "Unter den Coding-Agenten hat Claude Code den Ruf, Geschmack für Frontend-Arbeit zu haben. Dafür gibt es einige Gründe."}, {"kind": "steps", "items": [{"label": "Konkrete statt vage Entscheidungen", "body": "Claude Code legt sich tendenziell auf konkrete Entscheidungen fest — exakte hex-Werte, Abstandsskalen, Schriftverläufe und Komponentenhierarchie — statt sich vage durchzulavieren, und genau das unterscheidet ein echtes Interface von einem Platzhalter."}, {"label": "Codebasis-bewusstes Denken", "body": "Mit großem Arbeitskontext refaktoriert es UI über viele Dateien gleichzeitig und nutzt deine bestehenden Komponenten und tokens wieder, statt Einzelstile neu zu erfinden."}, {"label": "Eine offizielle Frontend-skill", "body": "Anthropic liefert eine Frontend-Design-skill aus, die Claude zuerst eine Designrichtung formulieren lässt und bewusst von generischen System-Schriften und vorhersehbaren lila Verläufen wegsteuert."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagramm, das zeigt, wie Designsystem, skill und Referenzbild zu gutem Design-Output zusammenlaufen", "caption": "Geschmack entsteht aus drei Eingaben, die du lieferst: einem Designsystem, einer skill und echten Referenzbildern."}, {"kind": "p", "text": "Die Lektion ist dieselbe, die Anthropic über seine eigenen Modelle formuliert: Claude hat standardmäßig keinen Geschmack — sich selbst überlassen konvergiert es zum statistischen Mittelpunkt des Webdesigns (Inter, lila Verläufe, weiche Schatten). Es liefert gutes Design, wenn du ihm Vorgaben machst. Open Design bündelt genau diese Eingaben — deshalb passen die beiden zusammen (mehr dazu weiter unten)."}]}, {"id": "setup", "heading": "Claude Code für Designarbeit einrichten, von null", "blocks": [{"kind": "p", "text": "Hier ist der komplette Weg von einer frischen Maschine zu einem Claude Code, das UI bauen und verifizieren kann."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Fünfstufiger Einrichtungsablauf: installieren, authentifizieren, CLAUDE.md konfigurieren, skill hinzufügen, verifizieren", "caption": "Die Einrichtungssequenz: installieren → authentifizieren → CLAUDE.md konfigurieren → die Frontend-Design-skill hinzufügen → Browser-Verifizierung aktivieren."}, {"kind": "steps", "items": [{"label": "Hinterlege deine Designregeln", "body": "Schreibe deine tokens, Primitive und Konventionen in CLAUDE.md und verweise Claude darauf, damit der Output zu einer Marke passt, statt zu einem generischen Look zurückzufallen."}, {"label": "Browser-Verifizierung hinzufügen", "body": "Binde einen Playwright- oder Chrome-MCP ein, damit Claude in einem echten Browser rendert und seinen Output über Breakpoints hinweg prüft, statt nur zu bestätigen, dass der Build durchläuft."}]}]}, {"id": "skills-workflow", "heading": "Der CLAUDE.md- und Skills-Workflow", "blocks": [{"kind": "p", "text": "Die wirkungsvollste Design-Schleife mit Claude Code besteht darin, ihm echte Referenzen plus deinen Design-Kontext zu geben und dann zu iterieren, bis die UI passt — wobei CLAUDE.md und Skills die Vorgaben tragen, sodass du sie nicht bei jedem Prompt neu erklären musst."}, {"kind": "ol", "items": ["Beginne mit den klarsten visuellen Referenzen, die du hast — und nimm mehrere Zustände auf (Desktop und Mobile, Hover, leer, ladend), nicht nur einen Hero-Shot.", "Sei im Prompt konkret; vage Prompts erzeugen generische UI, selbst mit einem starken Agenten.", "Halte dein Designsystem und deine Konventionen in CLAUDE.md fest und sag Claude, wo die tokens und kanonischen Primitive liegen.", "Füge die Frontend-Design-skill hinzu, damit Claude sich auf eine echte ästhetische Richtung festlegt, bevor er Code schreibt.", "Binde Browser-Verifizierung ein, damit Claude rendert, auf Breakpoints umstellt und mit den Referenzen abgleicht — nicht bloß bestätigt, dass es baut."]}, {"kind": "p", "text": "Wirf ein Referenzbild in die Session und prompte mit konkreten Vorgaben:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Lass parallel einen Dev-Server laufen, halte Prompts klein und fokussiert und committe gute Iterationen / verwirf schlechte (und teile Claude mit, wenn du zurücksetzt), damit jeder Durchlauf auf einer sauberen Basis aufbaut. Nutze den Plan-Modus für größere Refactorings, damit du den Ansatz prüfen kannst, bevor Dateien geändert werden."}]}, {"id": "figma", "heading": "Claude Code + Figma: Design-↔-Code-Roundtrip", "blocks": [{"kind": "p", "text": "Im Februar 2026 brachten Anthropic und Figma eine erstklassige, bidirektionale Integration über den Figma-MCP-Server. Sie funktioniert in beide Richtungen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Wähle einen Frame in Figma aus oder füge einen Link in Claude Code ein, ziehe den Design-Kontext heran und bitte es, das Design mit deiner bestehenden Komponentenbibliothek umzusetzen. Code Connect hält den Output an deinen echten Komponenten ausgerichtet."}, {"label": "Code → Design", "body": "Baue ein Feature und sieh es im Browser an, sag dann „Send this to Figma“, um die laufende UI als bearbeitbare Figma-Ebenen festzuhalten — den ganzen Screen oder ein ausgewähltes Element."}]}, {"kind": "p", "text": "Installiere es einmalig mit claude plugin install figma@claude-plugins-official (Dev Mode MCP erfordert einen kostenpflichtigen Figma-Plan). Derselbe Figma-MCP steht Claude Code, Codex, Cursor und VS Code zur Verfügung — genau die Art portabler, agentenübergreifender Fähigkeit, die Open Design orchestrieren soll."}]}, {"id": "vs", "heading": "Claude Code vs. Codex vs. Cursor für Design", "blocks": [{"kind": "p", "text": "Es gibt keinen einzelnen Gewinner für Designarbeit — jeder Agent hat eine andere Stärke, und erfahrene Teams kombinieren sie. Eine faire Zusammenfassung:"}, {"kind": "table", "columns": ["Agent", "Design-Stärke", "Am besten für"], "rows": [["Claude Code", "Konkrete Designentscheidungen (hex, Abstände, Typografie) und codebasis-bewusstes UX-Denken", "Frontend-Argumentation und Refactorings mit großem Kontext"], ["Codex", "Starker visueller Feinschliff und Bildverständnis; sandboxed asynchrone Builds", "Delegierte asynchrone Builds und portable AGENTS.md-Regeln"], ["Cursor", "Visuelle Build-and-See-Schleife mit Live-Vorschau und Inline-Edits", "Enge iterieren-und-beobachten-UI-Arbeit innerhalb einer IDE"]]}, {"kind": "p", "text": "Das wiederkehrende Urteil der Community lautet, dass Geschmack von Menschen kommt: Alle drei tendieren ohne skills, Referenzen und Vorgaben zu einer generischen Ästhetik. Das ist das eigentliche Problem, das es zu lösen gilt — und es hat die Form eines Design-Tools, nicht die eines Modells."}]}, {"id": "pitfalls", "heading": "Fallstricke und wie du den „AI-Slop“-Look vermeidest", "blocks": [{"kind": "p", "text": "Selbst trotz Claude Codes Ruf für Geschmack lautet die häufigste Klage über KI-generiertes Design, dass es generisch aussieht — Inter-Schriften, lila Verläufe auf Weiß, weiche Schatten, übergroße runde Ecken, eine Ästhetik, die „schreit, dass eine KI das gemacht hat“. Anthropic selbst führt das auf distributionelle Konvergenz zurück: Sichere Entscheidungen dominieren die Web-Trainingsdaten. Weitere gemeldete Probleme sind kaputte Mobile-Layouts und Anweisungen, die in die UI-Texte durchsickern."}, {"kind": "steps", "items": [{"label": "Installiere die Frontend-Design-skill", "body": "Sie zwingt Claude, sich auf eine echte Richtung festzulegen, und vermeidet ausdrücklich von KI überstrapazierte Schriften und Verläufe."}, {"label": "Aktiviere Browser-Verifizierung", "body": "Lass Claude über Breakpoints hinweg rendern und sich selbst prüfen, damit Layouts nicht stillschweigend auf Mobilgeräten brechen."}, {"label": "Liefere tokens und Referenzen", "body": "Echte Design-tokens und Referenz-Screenshots sind der größte Einzelhebel für die Output-Qualität."}, {"label": "Hinterlege Regeln in CLAUDE.md", "body": "Schreibe Regeln im Stil „keine Hero-Cards, höchstens zwei Schriftarten, markenorientierte Hierarchie“ dorthin, wo der Agent sie bei jedem Durchlauf liest."}]}, {"kind": "p", "text": "Beachte: Jede dieser Maßnahmen dreht sich darum, dem Agenten einen kuratierten Design-Kontext zu geben. Diesen Kontext von Hand und pro Projekt zu pflegen, ist genau die Mühsal, die Open Design beseitigt."}]}, {"id": "open-design", "heading": "Mit Claude Code in Open Design gestalten", "blocks": [{"kind": "p", "text": "Open Design ist die quelloffene Design-Schicht, nach der der obige Workflow immer wieder verlangt. Es behandelt Claude Code als First-Party-Adapter und umgibt ihn mit einer kuratierten skill- und Designsystem-Bibliothek, einer strukturierten Render-Pipeline und einer lokalen Desktop-UI — sodass der Design-Kontext, der Claude Code gut macht, vom ersten Durchlauf an da ist, statt jedes Mal von Hand zusammengebaut zu werden."}, {"kind": "ol", "items": ["Installiere Open Design und wähle Claude Code als deinen Agenten.", "Authentifiziere dich mit deinem Anthropic-API-Key (BYOK) oder Claude-Abo — die Zugangsdaten bleiben auf deiner Maschine und werden niemals über uns geleitet.", "Wähle ein Designsystem und eine skill und erzeuge dann Decks, Prototypen und Landingpages mit konsistentem Geschmack.", "Jedes Artefakt und jede DESIGN.md-Datei liegt in deinem eigenen Repo, nicht in einer gehosteten Cloud."]}, {"kind": "p", "text": "Derselbe Claude-Code-Agent, derselbe Key — plus ein echter, portabler, quelloffener Design-Workflow drumherum. Es ist local-first und Apache-2.0, sodass nichts an deiner Arbeit oder deinen Zugangsdaten deine Maschine verlässt."}]}], "faqTitle": "Häufig gestellte Fragen", "faq": [{"name": "Eignet sich Claude Code für Designarbeit?", "text": "Ja — er gilt weithin als der Coding-Agent mit dem besten Frontend-Geschmack und trifft konkrete, codebasis-bewusste Entscheidungen über hex-Werte, Abstände und Schriftskalen. Mit der Frontend-Design-skill, einem Designsystem und echten Referenzbildern im Kontext liefert er produktionsreife, responsive UI und kann sie in einem Browser verifizieren. Ohne diesen Kontext fällt er tendenziell auf einen generischen Look zurück — und genau diese Lücke schließt Open Design."}, {"name": "Brauche ich ein Claude-Abo, um mit Claude Code zu gestalten?", "text": "Du kannst entweder einen Anthropic-API-Key (BYOK, über die Console) oder ein Claude-Abo (Pro / Max) verwenden. So oder so leitet Open Design deine Zugangsdaten niemals weiter — sie werden direkt von deinem Agenten auf deiner Maschine genutzt."}, {"name": "Claude Code oder Codex für Frontend-Design?", "text": "Beide sind stark. Claude Code ist bekannt für konkrete, codebasis-bewusste Designentscheidungen und Frontend-Argumentation; Codex hat starken visuellen Feinschliff und glänzt bei delegierten, sandboxed Builds. Viele Teams nutzen beide — Open Design lässt dich die Agenten wechseln, ohne deinen Design-Workflow zu ändern."}, {"name": "Wie verbinde ich Claude Code mit Figma?", "text": "Installiere das offizielle Figma-Plugin mit claude plugin install figma@claude-plugins-official. Du kannst dann Figma-Frames mithilfe des Design-Kontexts in Code umsetzen und eine laufende UI mit „Send this to Figma“ zurück in bearbeitbare Figma-Frames schieben. Dev Mode MCP erfordert einen kostenpflichtigen Figma-Plan."}, {"name": "Was sind Skills und CLAUDE.md?", "text": "CLAUDE.md ist eine Markdown-Datei im Projektstamm, die Claude Code zu Beginn jeder Session liest — der Ort, um deine Design-Konventionen zu hinterlegen. Skills bündeln wiederverwendbare Anweisungen und Ressourcen, die Claude bei Bedarf lädt, darunter Anthropics offizielle Frontend-Design-skill. Open Design liefert eine kuratierte Bibliothek von beidem, sodass du das Setup pro Projekt überspringst."}, {"name": "Wie vermeide ich die generische „AI-Slop“-Ästhetik?", "text": "Installiere die Frontend-Design-skill, liefere echte Design-tokens und Referenz-Screenshots, hinterlege Markenregeln in CLAUDE.md und aktiviere Browser-Verifizierung. Open Design liefert diese als kuratierte Bibliothek aus, sodass du das Setup pro Projekt überspringst."}, {"name": "Ist Open Design mit Anthropic verbunden?", "text": "Nein. Claude Code ist ein Produkt von Anthropic; Open Design ist ein unabhängiges quelloffenes Projekt, das ihn als First-Party-Adapter unterstützt. Claude und Claude Code sind Marken von Anthropic."}, {"name": "Sind meine Dateien und Zugangsdaten sicher?", "text": "Ja — Open Design ist local-first und Apache-2.0. Deine Dateien, Artefakte und DESIGN.md bleiben in deinem eigenen Repo, und deine Anthropic-Zugangsdaten werden direkt von deinem Agenten genutzt, niemals über Open-Design-Server geleitet."}], "ctaTitle": "Gestalte mit Claude Code, auf die offene Art.", "ctaBody": "Bring deinen eigenen Anthropic-Key oder dein Claude-Abo mit, behalte jede Datei lokal und erhalte eine kuratierte Design-Bibliothek rund um den Agenten, den du ohnehin schon nutzt.", "ctaActions": [{"label": "Claude Code in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Alle unterstützten Agenten ansehen"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex für Design — Open Design",
        description: "Wie Menschen OpenAI Codex für UI- und Webdesign nutzen — das Product-Design-Plugin, die Figma-Integration, Frontend-skills — und wie Open Design Codex zu einem local-first, quelloffenen Design-Agenten macht.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex für Design.",
        lead: "Codex ist der Coding-Agent von OpenAI. Mit seinem Product-Design-Plugin und der Figma-Integration ist es zu einem ernstzunehmenden Design-Tool geworden. Open Design bindet Codex in einen quelloffenen Design-Workflow ein — dein OpenAI-Key oder ChatGPT-Abo, deine Dateien, local-first.",
        rich: {"heroCtaLead": "Open Design macht Codex zu einem local-first, quelloffenen Design-Agenten — dein OpenAI-Key, deine Dateien, dazu eine kuratierte skill- und Designsystem-Bibliothek drumherum.", "heroCtaActions": [{"label": "Codex in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex begann als Code-Generator, wurde 2026 aber zu einem glaubwürdigen Werkzeug, um echte Interfaces zu gestalten — sobald du ihm die richtigen Referenzen, skills und eine Verifizierungsschleife gibst. Dies ist ein praktischer End-to-End-Leitfaden, wie du Codex für UI-, Frontend- und Designsystem-Arbeit einsetzt und ihn mit Open Design in einen strukturierten Design-Workflow einbindest.", "Er behandelt, was Codex heute ist, warum es plötzlich gut im Frontend ist, wie du es von null aufsetzt, die Screenshot-zu-UI-Schleife, den offiziellen Figma-Roundtrip, wie es im Vergleich zu Cursor und Claude Code abschneidet, die Fallstricke, die KI-Output generisch wirken lassen, und wie Open Design die Lücke als offene, local-first Design-Schicht schließt."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex-Design-Feedbackschleife: Terminal-Agent, Browser, der die UI rendert, und ein Workspace, mit einem zurückführenden Feedback-Pfeil", "caption": "Die Kernschleife: Codex baut UI im Terminal, rendert und verifiziert sie in einem echten Browser und iteriert gegen deine Referenzen."}, "tocLabel": "Auf dieser Seite", "toc": [{"id": "what-is-codex", "label": "Was OpenAI Codex wirklich ist"}, {"id": "why-design", "label": "Warum Codex jetzt gut im Design ist"}, {"id": "setup", "label": "Codex für Design einrichten (von null)"}, {"id": "screenshot-workflow", "label": "Der Screenshot-zu-UI-Workflow"}, {"id": "figma", "label": "Codex + Figma-Roundtrip"}, {"id": "vs", "label": "Codex vs. Cursor vs. Claude Code"}, {"id": "pitfalls", "label": "Fallstricke und der „AI-Slop“-Look"}, {"id": "open-design", "label": "Mit Codex in Open Design gestalten"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Was OpenAI Codex wirklich ist (und was nicht)", "blocks": [{"kind": "p", "text": "Zuerst eine Begriffsklärung, über die fast jeder stolpert, der nach „Codex“ sucht. Das ursprüngliche OpenAI Codex war ein Code-Vervollständigungsmodell von 2021, das den frühen GitHub Copilot antrieb und 2023 eingestellt wurde. Darum geht es auf dieser Seite nicht. Das heutige Codex ist OpenAIs agentisches Coding-Tool — es plant, schreibt, führt aus und verifiziert Code aus Aufgaben in natürlicher Sprache."}, {"kind": "p", "text": "Das moderne Codex ist über vier Oberflächen verfügbar: eine Terminal-CLI (in Rust neu geschrieben, Apache-2.0-lizenziert), eine IDE-Erweiterung für VS Code, Cursor und Windsurf, eine Cloud-/Web-Oberfläche für delegierte asynchrone Aufgaben und eine Desktop-App mit eingebautem Browser und Computer Use."}, {"kind": "steps", "items": [{"label": "Standardmodell", "body": "Stand Mitte 2026 ist das empfohlene Modell gpt-5.5, wobei gpt-5.4 das Modell ist, das OpenAI ausdrücklich für Frontend und Computer Use trainiert hat."}, {"label": "Anweisungsdatei", "body": "Codex liest eine AGENTS.md-Datei in deinem Projekt (ein toolübergreifender Standard) für Projektregeln — der natürliche Ort, um deine Design-Konventionen zu hinterlegen."}, {"label": "Sandbox", "body": "Es läuft in einer Sandbox auf Kernel-Ebene (standardmäßig workspace-write), sodass ein Agent, der deine UI bearbeitet, nicht aus dem Projekt ausbrechen kann."}]}, {"kind": "ul", "items": ["Anbieter: OpenAI", "Zugangsdaten: OpenAI-API-Key (BYOK) oder ChatGPT-Abo (Free / Go / Plus / Pro / Business / Enterprise)", "Lizenz der CLI: Apache-2.0, quelloffen"]}]}, {"id": "why-design", "heading": "Warum Codex jetzt gut im Design ist", "blocks": [{"kind": "p", "text": "Anfang 2026 kamen drei Dinge zusammen, die Codex von einem generischen Code-Generator zu einem echten Design-Tool machten."}, {"kind": "steps", "items": [{"label": "Ein frontend-trainiertes Modell", "body": "OpenAI brachte GPT-5.4, sein erstes Mainline-Modell, das für Frontend und Computer Use trainiert wurde, mit deutlich besserem Bildverständnis über den gesamten Design-Workflow und stärkerer Selbstverifizierung. Es kann sogar Mood-Boards und visuelle Optionen erzeugen, bevor es sich auf finale Assets festlegt."}, {"label": "Eine offizielle Frontend-skill", "body": "Der openai/skills-Katalog liefert eine kuratierte frontend-skill aus, die echten Geschmack erzwingt: kartenlose Layouts, randvolle Heroes, markenorientierte Hierarchie, zurückhaltende Bewegung, höchstens zwei Schriftarten und eine Akzentfarbe — und Codex eine visuelle These schreiben lässt, bevor es baut."}, {"label": "Browser-Verifizierung", "body": "Mit der Playwright-skill öffnet Codex einen echten Browser, stellt auf Breakpoints um und gleicht seinen Output mit der Referenz ab, statt nur zu prüfen, ob der Build durchläuft."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagramm, das zeigt, wie Designsystem, skill und Referenzbild zu gutem Design-Output zusammenlaufen", "caption": "Geschmack entsteht aus drei Eingaben, die du lieferst: einem Designsystem, einer skill und echten Referenzbildern."}, {"kind": "p", "text": "Die Lektion hinter allen dreien: Codex hat standardmäßig keinen Geschmack. Es liefert gutes Design, wenn du ihm Vorgaben machst — ein Designsystem, eine ästhetische skill und konkrete Referenzen. Open Design bündelt genau diese Eingaben — deshalb passen die beiden zusammen (mehr dazu weiter unten)."}]}, {"id": "setup", "heading": "Codex für Designarbeit einrichten, von null", "blocks": [{"kind": "p", "text": "Hier ist der komplette Weg von einer frischen Maschine zu einem Codex, das UI bauen und verifizieren kann."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Fünfstufiger Einrichtungsablauf: installieren, authentifizieren, konfigurieren, skill installieren, verifizieren", "caption": "Die Einrichtungssequenz: installieren → authentifizieren → AGENTS.md konfigurieren → die frontend-skill installieren → Browser-Verifizierung aktivieren."}, {"kind": "steps", "items": [{"label": "Hinterlege deine Designregeln", "body": "Schreibe deine tokens, Primitive und Konventionen in AGENTS.md oder eine DESIGN.md und verweise Codex darauf, damit der Output zu einer Marke passt, statt zu einem generischen Look zurückzufallen."}, {"label": "Wähle die richtige Reasoning-Stufe", "body": "OpenAI weist darauf hin, dass niedrige bis mittlere Reasoning-Stufen oft stärkere Frontend-Ergebnisse liefern als die höchste Einstellung."}]}]}, {"id": "screenshot-workflow", "heading": "Der Screenshot-zu-UI-Workflow", "blocks": [{"kind": "p", "text": "Die wirkungsvollste Design-Schleife mit Codex besteht darin, ein Referenzbild in funktionierende, responsive UI zu verwandeln und zu iterieren, bis es passt. OpenAIs eigene Anleitung lässt sich auf fünf Schritte verdichten."}, {"kind": "ol", "items": ["Beginne mit den klarsten visuellen Referenzen, die du hast — und nimm mehrere Zustände auf (Desktop und Mobile, Hover, leer, ladend), nicht nur einen Hero-Shot.", "Sei im Prompt konkret; vage Prompts erzeugen generische UI.", "Bereite ein Designsystem vor und sag Codex, wo die tokens und kanonischen Primitive liegen.", "Aktiviere die interaktive Playwright-skill, damit Codex in einem echten Browser rendert und auf Breakpoints umstellt.", "Iteriere, indem du Codex seine Umsetzung mit den Screenshots abgleichen lässt — nicht bloß bestätigen, dass es baut."]}, {"kind": "p", "text": "Füttere Bilder, indem du einen Screenshot ins Terminal ziehst oder das Image-Flag nutzt, und prompte dann mit konkreten Vorgaben:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Lass einen Dev-Server in einem zweiten Terminal laufen, halte Prompts klein und fokussiert und committe gute Iterationen / verwirf schlechte (und teile Codex mit, wenn du zurücksetzt), damit jeder Durchlauf auf einer sauberen Basis aufbaut."}]}, {"id": "figma", "heading": "Codex + Figma: Design-↔-Code-Roundtrip", "blocks": [{"kind": "p", "text": "Im Februar 2026 kündigten OpenAI und Figma eine offizielle Partnerschaft an und machten aus der früheren Figma-MCP-Beta eine erstklassige, bidirektionale Integration. Sie funktioniert in beide Richtungen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopiere in Figma den „link to selection“ eines Frames, füge ihn mit get_design_context in Codex ein und bitte es, das Design mit deiner bestehenden Komponentenbibliothek umzusetzen."}, {"label": "Code → Design", "body": "Das Werkzeug generate_figma_design („Code to Canvas“) verwandelt eine laufende UI zurück in bearbeitbare Figma-Frames — den ganzen Screen, ein ausgewähltes Element oder eine ganze Datei."}]}, {"kind": "p", "text": "Der Figma-MCP läuft als Remote-Server und ist von Rate-Limits ausgenommen. Füge ihn einmal hinzu und er steht Codex, Claude Code, Cursor, VS Code und mehr zur Verfügung — genau die Art portabler, agentenübergreifender Fähigkeit, die Open Design orchestrieren soll."}]}, {"id": "vs", "heading": "Codex vs. Cursor vs. Claude Code für Design", "blocks": [{"kind": "p", "text": "Es gibt keinen einzelnen Gewinner für Designarbeit — jeder Agent hat eine andere Stärke, und erfahrene Teams kombinieren sie. Eine faire Zusammenfassung:"}, {"kind": "table", "columns": ["Agent", "Design-Stärke", "Am besten für"], "rows": [["Codex", "Starker visueller Feinschliff nach GPT-5.4 + frontend-skill; Bildverständnis", "Delegierte asynchrone Builds, sandboxed Läufe, portable AGENTS.md-Regeln"], ["Cursor", "Visuelle Build-and-See-Schleife mit Live-Vorschau und Inline-Edits", "Enge iterieren-und-beobachten-UI-Arbeit innerhalb einer IDE"], ["Claude Code", "Konkrete Designentscheidungen (hex, Abstände, Typografie) und codebasis-bewusstes UX", "Frontend-Argumentation und Refactorings mit großem Kontext"]]}, {"kind": "p", "text": "Das wiederkehrende Urteil der Community lautet, dass Geschmack von Menschen kommt: Alle drei tendieren ohne skills, Referenzen und Vorgaben zu einer generischen Ästhetik. Das ist das eigentliche Problem, das es zu lösen gilt — und es hat die Form eines Design-Tools, nicht die eines Modells."}]}, {"id": "pitfalls", "heading": "Fallstricke und wie du den „AI-Slop“-Look vermeidest", "blocks": [{"kind": "p", "text": "Die häufigste Klage über Codex-generiertes Design lautet, dass es generisch aussieht — weiche Verläufe, schwebende Panels, übergroße runde Ecken, dramatische Schatten, eine Inter-und-Lila-Stimmung, die „schreit, dass eine KI das gemacht hat“. Weitere gemeldete Probleme sind kaputte Mobile-Layouts, Anweisungen, die in die UI-Texte durchsickern, und schnell erreichte Nutzungslimits."}, {"kind": "steps", "items": [{"label": "Installiere eine Frontend-skill", "body": "Eine kuratierte ästhetische skill zwingt Codex, sich auf eine echte Richtung festzulegen, statt auf den Standard-Look."}, {"label": "Aktiviere Playwright-Verifizierung", "body": "Lass Codex über Breakpoints hinweg rendern und sich selbst prüfen, damit Layouts nicht stillschweigend auf Mobilgeräten brechen."}, {"label": "Liefere tokens und Referenzen", "body": "Echte Design-tokens und Referenz-Screenshots sind der größte Einzelhebel für die Output-Qualität."}, {"label": "Hinterlege Regeln in AGENTS.md", "body": "Schreibe Regeln im Stil „keine Hero-Cards, höchstens zwei Schriftarten, markenorientierte Hierarchie“ dorthin, wo der Agent sie bei jedem Durchlauf liest."}]}, {"kind": "p", "text": "Beachte: Jede dieser Maßnahmen dreht sich darum, dem Agenten einen kuratierten Design-Kontext zu geben. Diesen Kontext von Hand und pro Projekt zu pflegen, ist genau die Mühsal, die Open Design beseitigt."}]}, {"id": "open-design", "heading": "Mit Codex in Open Design gestalten", "blocks": [{"kind": "p", "text": "Open Design ist die quelloffene Design-Schicht, nach der der obige Workflow immer wieder verlangt. Es behandelt Codex als First-Party-Adapter und umgibt es mit einer kuratierten skill- und Designsystem-Bibliothek, einer strukturierten Render-Pipeline und einer lokalen Desktop-UI — sodass der Design-Kontext, der Codex gut macht, vom ersten Durchlauf an da ist, statt jedes Mal von Hand zusammengebaut zu werden."}, {"kind": "ol", "items": ["Installiere Open Design und wähle Codex als deinen Agenten.", "Authentifiziere dich mit deinem OpenAI-API-Key (BYOK) oder ChatGPT-Abo — die Zugangsdaten bleiben auf deiner Maschine und werden niemals über uns geleitet.", "Wähle ein Designsystem und eine skill und erzeuge dann Decks, Prototypen und Landingpages mit konsistentem Geschmack.", "Jedes Artefakt und jede DESIGN.md-Datei liegt in deinem eigenen Repo, nicht in einer gehosteten Cloud."]}, {"kind": "p", "text": "Derselbe Codex-Agent, derselbe Key — plus ein echter, portabler, quelloffener Design-Workflow drumherum. Es ist local-first und Apache-2.0, sodass nichts an deiner Arbeit oder deinen Zugangsdaten deine Maschine verlässt."}]}], "faqTitle": "Häufig gestellte Fragen", "faq": [{"name": "Kann OpenAI Codex wirklich Designarbeit leisten?", "text": "Ja — mit einer Frontend-skill, einem Designsystem und echten Referenzbildern im Kontext liefert Codex (besonders auf GPT-5.4) produktionsreife, responsive UI und kann sie in einem Browser verifizieren. Ohne diesen Kontext fällt es tendenziell auf einen generischen Look zurück — und genau diese Lücke schließt Open Design."}, {"name": "Ist das das OpenAI-Codex-Product-Design-Plugin?", "text": "Nein. Open Design ist ein unabhängiges quelloffenes Projekt, das Codex als Agenten integriert. Es ergänzt OpenAIs eigenes Tooling um eine local-first, offene skill- und Designsystem-Bibliothek."}, {"name": "Brauche ich ein ChatGPT-Abo, um mit Codex zu gestalten?", "text": "Du kannst entweder einen OpenAI-API-Key (BYOK) oder dein ChatGPT-Abo verwenden. Die Anmeldung über ChatGPT gewährt in der Regel großzügigere Limits; Open Design leitet deine Zugangsdaten in keinem Fall weiter."}, {"name": "Codex oder Claude Code für Frontend-Design?", "text": "Beide sind stark. Claude Code ist bekannt für konkrete, codebasis-bewusste Designentscheidungen; Codex hat nach GPT-5.4 starken visuellen Feinschliff und glänzt bei delegierten, sandboxed Builds. Viele Teams nutzen beide — Open Design lässt dich die Agenten wechseln, ohne deinen Design-Workflow zu ändern."}, {"name": "Wie verbinde ich Codex mit Figma?", "text": "Füge den offiziellen Figma-MCP-Server hinzu (codex mcp add figma --url https://mcp.figma.com/mcp). Du kannst dann Figma-Frames mit get_design_context in Code umsetzen und eine laufende UI mit generate_figma_design zurück in bearbeitbare Figma-Frames schieben."}, {"name": "Wie vermeide ich die generische „AI-Slop“-Ästhetik?", "text": "Installiere eine Frontend-skill, liefere echte Design-tokens und Referenz-Screenshots, hinterlege Markenregeln in AGENTS.md und aktiviere Playwright-Verifizierung. Open Design liefert diese als kuratierte Bibliothek aus, sodass du das Setup pro Projekt überspringst."}, {"name": "Ist Open Design mit OpenAI verbunden?", "text": "Nein. Codex ist ein Produkt von OpenAI; Open Design ist ein unabhängiges quelloffenes Projekt, das es als First-Party-Adapter unterstützt. OpenAI und Codex sind Marken von OpenAI."}, {"name": "Sind meine Dateien und Zugangsdaten sicher?", "text": "Ja — Open Design ist local-first. Deine Dateien, Artefakte und DESIGN.md bleiben in deinem eigenen Repo, und deine OpenAI-Zugangsdaten werden direkt von deinem Agenten genutzt, niemals über Open-Design-Server geleitet."}], "ctaTitle": "Gestalte mit Codex, auf die offene Art.", "ctaBody": "Bring deinen eigenen OpenAI-Key mit, behalte jede Datei lokal und erhalte eine kuratierte Design-Bibliothek rund um den Agenten, den du ohnehin schon nutzt.", "ctaActions": [{"label": "Codex in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Alle unterstützten Agenten ansehen"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor für Designer — Open Design",
        description: "Wie Designer Cursor für UI- und Webdesign nutzen — Design Mode, Figma-zu-Code, der Figma-MCP — und wie Open Design Cursor zu einem local-first, quelloffenen Design-Agenten macht.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor für Designer.",
        lead: "Cursor ist der KI-Code-Editor, jetzt mit einem visuellen Design Mode. Designer nutzen ihn, um UI durch Zeigen und Zeichnen zu bearbeiten und Figma in Code zu verwandeln. Open Design bindet den Cursor Agent in einen quelloffenen Design-Workflow ein, der deine Dateien lokal hält.",
        rich: {"heroCtaLead": "Open Design macht Cursor zu einem local-first, quelloffenen Design-Agenten — dein Cursor-Account oder deine Modell-Keys, deine Dateien, dazu eine kuratierte skill- und Designsystem-Bibliothek drumherum.", "heroCtaActions": [{"label": "Cursor in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor ist der KI-First-Code-Editor, der „bauen und beim Rendern zusehen“ zur Standardmethode gemacht hat, UI auszuliefern. Mit dem Agent-Modus, Inline-Edits, einer In-Editor-Vorschau und Figma über MCP ist er zu einem echten Design-Tool geworden — sobald du ihm die richtigen Referenzen, Regeln und eine Verifizierungsschleife gibst. Dies ist ein praktischer End-to-End-Leitfaden, wie du Cursor für UI-, Frontend- und Designsystem-Arbeit einsetzt und ihn mit Open Design in einen strukturierten Design-Workflow einbindest.", "Er behandelt, was Cursor wirklich ist, warum seine enge iterieren-und-beobachten-Schleife gut für Design ist, wie du ihn von null aufsetzt, die Screenshot-und-Vorschau-zu-UI-Schleife, den Figma-Roundtrip über MCP, wie er im Vergleich zu Codex und Claude Code abschneidet, die Fallstricke, die KI-Output generisch wirken lassen, und wie Open Design die Lücke als offene, local-first Design-Schicht schließt."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor-Design-Konvergenz: Editor links, ein kuratierter skill- und Designsystem-Hub in der Mitte mit dem Cursor-Zeichen im Zentrum und eine gerenderte UI rechts", "caption": "Die Kernidee: Cursor bearbeitet und rendert UI im Editor, während ein kuratierter Design-Hub ihn mit dem System, den skills und den Referenzen versorgt, die den Output absichtlich wirken lassen."}, "tocLabel": "Auf dieser Seite", "toc": [{"id": "what-is-cursor", "label": "Was Cursor wirklich ist"}, {"id": "why-design", "label": "Warum Cursor gut im Design ist"}, {"id": "setup", "label": "Cursor für Design einrichten (von null)"}, {"id": "preview-workflow", "label": "Der Vorschau-zu-UI-Workflow"}, {"id": "figma", "label": "Cursor + Figma über MCP"}, {"id": "vs", "label": "Cursor vs. Codex vs. Claude Code"}, {"id": "pitfalls", "label": "Fallstricke und der „AI-Slop“-Look"}, {"id": "open-design", "label": "Mit Cursor in Open Design gestalten"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Was Cursor wirklich ist", "blocks": [{"kind": "p", "text": "Cursor ist ein KI-First-Code-Editor von Anysphere. Es ist ein Fork von VS Code, behält also den vertrauten Editor, die Erweiterungen und Tastenkürzel, baut den Workflow aber rund um einen KI-Agenten neu auf, der dein gesamtes Projekt lesen, mehrere Dateien bearbeiten, Befehle ausführen und mit dir in der Schleife iterieren kann."}, {"kind": "p", "text": "Für Designarbeit sind die wichtigen Oberflächen der Agent-Modus (du beschreibst ein Ergebnis und Cursor plant und bearbeitet dateiübergreifend), Inline-Edits und Tab-Vervollständigungen für schnelle Anpassungen, eine In-Editor-Vorschau / ein Browser, sodass du die laufende UI siehst, ohne das Fenster zu verlassen, und MCP-Unterstützung, mit der er externen Kontext wie eine Live-Figma-Datei einbinden kann."}, {"kind": "steps", "items": [{"label": "Projektregeln", "body": "Cursor liest Projekt-Anweisungsdateien — versionierte `.mdc`-Regeln unter `.cursor/rules` und eine schlichte `AGENTS.md` — sodass du deine Design-Konventionen dort hinterlegen kannst, wo der Agent sie bei jedem Durchlauf liest."}, {"label": "Modelle", "body": "Cursor ist modell-flexibel: Es kommt mit Frontier-Modellen über dein Abo und unterstützt zudem das Mitbringen eigener Modell-Keys, sodass du die Engine hinter demselben Editor-Workflow wählst."}, {"label": "MCP", "body": "Es spricht das Model Context Protocol, sodass externe Server — am relevantesten der Figma-MCP-Server — zu erstklassigem Kontext für den Agenten werden."}]}, {"kind": "ul", "items": ["Anbieter: Anysphere", "Zugangsdaten: Cursor-Account / -Abo (Hobby / Pro / Business) oder deine eigenen Modell-Keys (BYOK)", "Form: KI-First-Code-Editor (VS-Code-Fork) mit einem In-Editor-Agenten und Vorschau"]}]}, {"id": "why-design", "heading": "Warum Cursor gut im Design ist", "blocks": [{"kind": "p", "text": "Cursors Design-Vorteil ist kein einzelnes Feature — es ist die Enge der Build-and-See-Schleife. Drei Dinge lassen ihn eher wie ein Design-Tool als wie einen generischen Code-Generator wirken."}, {"kind": "steps", "items": [{"label": "Eine enge iterieren-und-beobachten-Schleife", "body": "Du promptest, Cursor bearbeitet dateiübergreifend und die In-Editor-Vorschau rendert das Ergebnis sofort — sodass du Abstände, Hierarchie und Bewegung in Sekunden anpasst, statt über ein separates Terminal und einen Browser hin- und herzuwechseln."}, {"label": "Direktes visuelles Bearbeiten", "body": "Über den Chat hinaus lässt dich Cursor Elemente in der Vorschau auswählen und Stile anstupsen, sodass kleine visuelle Korrekturen sich wie Design-Edits anfühlen statt wie Code-Archäologie."}, {"label": "Projektregeln und MCP-Kontext", "body": "Mit `.cursor/rules` (oder `AGENTS.md`) und dem Figma-MCP-Server arbeitet der Agent gegen deine tokens, Komponenten und echten Design-Spezifikationen, statt zu raten."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagramm, das zeigt, wie Designsystem, skill und Referenzbild zu gutem Design-Output zusammenlaufen", "caption": "Geschmack entsteht aus drei Eingaben, die du lieferst: einem Designsystem, einer skill und echten Referenzbildern."}, {"kind": "p", "text": "Die Lektion ist dieselbe, die jeder Agent lehrt: Cursor hat standardmäßig keinen Geschmack. Es liefert gutes Design, wenn du ihm Vorgaben machst — ein Designsystem, eine ästhetische skill und konkrete Referenzen. Open Design bündelt genau diese Eingaben — deshalb passen die beiden zusammen (mehr dazu weiter unten)."}]}, {"id": "setup", "heading": "Cursor für Designarbeit einrichten, von null", "blocks": [{"kind": "p", "text": "Hier ist der komplette Weg von einer frischen Maschine zu einem Cursor, der UI gegen dein Designsystem bauen, in der Vorschau ansehen und verifizieren kann."}, {"kind": "ol", "items": ["Installiere Cursor von cursor.com und melde dich mit deinem Cursor-Account an oder konfiguriere deine eigenen Modell-Keys (BYOK) in den Einstellungen.", "Öffne dein Projekt und wähle ein Modell im Chat- / Agent-Panel.", "Füge Projektregeln hinzu: Erstelle `.cursor/rules/*.mdc` für strukturierte, glob-bezogene Konventionen oder eine schlichte `AGENTS.md` für einfache, lesbare Anweisungen.", "Verbinde den Figma-MCP-Server (optional), damit der Agent Live-Design-Kontext lesen kann.", "Starte deinen Dev-Server und nutze die In-Editor-Vorschau, um die UI zu sehen und zu verifizieren, während du iterierst."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Fünfstufiger Einrichtungsablauf: installieren, authentifizieren, Regeln konfigurieren, skill hinzufügen, verifizieren", "caption": "Die Einrichtungssequenz: installieren → authentifizieren → Projektregeln konfigurieren → eine skill hinzufügen → Vorschau-Verifizierung aktivieren."}, {"kind": "p", "text": "Eine minimale Projektregel-Datei sorgt dafür, dass der Agent für eine Marke gestaltet, statt auf einen generischen Look zurückzufallen. Lege sie dorthin, wo Cursor sie bei jedem Durchlauf liest:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Hinterlege deine Designregeln", "body": "Schreibe deine tokens, Primitive und Konventionen in `.cursor/rules` oder `AGENTS.md` und verweise Cursor darauf, damit der Output zu einer Marke passt, statt zu einem generischen Look zurückzufallen."}, {"label": "Halte Prompts klein", "body": "Cursors enge Schleife belohnt fokussierte Anfragen — iteriere eine Komponente oder einen Zustand nach dem anderen und beobachte die Vorschau zwischen den Durchläufen."}]}]}, {"id": "preview-workflow", "heading": "Der Vorschau-zu-UI-Workflow", "blocks": [{"kind": "p", "text": "Die wirkungsvollste Design-Schleife mit Cursor besteht darin, eine Referenz in funktionierende, responsive UI zu verwandeln und im Editor zu iterieren, bis sie passt — und dabei die ganze Zeit die Live-Vorschau zu beobachten, statt zu raten."}, {"kind": "ol", "items": ["Beginne mit den klarsten visuellen Referenzen, die du hast — und nimm mehrere Zustände auf (Desktop und Mobile, Hover, leer, ladend), nicht nur einen Hero-Shot.", "Sei im Prompt konkret; vage Prompts erzeugen generische UI.", "Bereite ein Designsystem vor und sag Cursor, wo die tokens und kanonischen Primitive liegen.", "Halte die In-Editor-Vorschau offen und deinen Dev-Server am Laufen, damit jede Bearbeitung sofort an den Breakpoints rendert, die dir wichtig sind.", "Iteriere, indem du die gerenderte UI mit den Referenzen abgleichst — und nutze direkte Elementauswahl in der Vorschau für kleine visuelle Korrekturen."]}, {"kind": "p", "text": "Füttere Referenzen, indem du ein Bild an den Chat anhängst, und prompte dann mit konkreten Vorgaben:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Committe gute Iterationen und verwirf schlechte (und teile Cursor mit, wenn du zurücksetzt), damit jeder Durchlauf auf einer sauberen Basis aufbaut — dieselbe Disziplin, die jede Agenten-Schleife vor dem Abdriften bewahrt."}]}, {"id": "figma", "heading": "Cursor + Figma: Design ↔ Code über MCP", "blocks": [{"kind": "p", "text": "Cursor verbindet sich über den offiziellen Figma-MCP-Server mit Figma, der dem Agenten strukturierten Zugriff auf eine Live-Figma-Datei gibt statt auf einen flachen Screenshot. Das nimmt das Rätselraten aus der Übergabe."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopiere in Figma den Link eines Frames, füge ihn in Cursor ein und bitte es, das Design umzusetzen. Der MCP-Server legt echten Design-Kontext offen — Komponenten, Variablen, Layout-Daten, tokens —, sodass der erzeugte Code zur Quelle passt, statt sie nur anzunähern."}, {"label": "Konsistent bleiben", "body": "Wenn Design-tokens, Stile und Komponenten in Figma konsistent verwendet werden (und Code Connect, wo verfügbar), bleibt Cursors Output auf dein echtes Designsystem abgebildet, statt Primitive neu zu erfinden."}]}, {"kind": "p", "text": "Richte den Remote-Figma-MCP-Server einmal ein und er steht Cursor als erstklassiger Kontext zur Verfügung. Weil MCP ein offener Standard ist, ist derselbe Server über Cursor, Claude Code, Codex und VS Code hinweg wiederverwendbar — genau die Art portabler, agentenübergreifender Fähigkeit, die Open Design orchestrieren soll."}]}, {"id": "vs", "heading": "Cursor vs. Codex vs. Claude Code für Design", "blocks": [{"kind": "p", "text": "Es gibt keinen einzelnen Gewinner für Designarbeit — jeder Agent hat eine andere Stärke, und erfahrene Teams kombinieren sie. Eine faire Zusammenfassung:"}, {"kind": "table", "columns": ["Agent", "Design-Stärke", "Am besten für"], "rows": [["Cursor", "Visuelle Build-and-See-Schleife mit Live-In-Editor-Vorschau und direktem Bearbeiten von Elementen", "Enge iterieren-und-beobachten-UI-Arbeit innerhalb einer IDE"], ["Codex", "Starker visueller Feinschliff mit einer frontend-skill; Bildverständnis und sandboxed Läufe", "Delegierte asynchrone Builds und portable AGENTS.md-Regeln"], ["Claude Code", "Konkrete Designentscheidungen (hex, Abstände, Typografie) und codebasis-bewusstes UX", "Frontend-Argumentation und Refactorings mit großem Kontext"]]}, {"kind": "p", "text": "Das wiederkehrende Urteil der Community lautet, dass Geschmack von Menschen kommt: Alle drei tendieren ohne skills, Referenzen und Vorgaben zu einer generischen Ästhetik. Das ist das eigentliche Problem, das es zu lösen gilt — und es hat die Form eines Design-Tools, nicht die eines Modells."}]}, {"id": "pitfalls", "heading": "Fallstricke und wie du den „AI-Slop“-Look vermeidest", "blocks": [{"kind": "p", "text": "Die häufigste Klage über Cursor-generiertes Design lautet, dass es generisch aussieht — weiche Verläufe, schwebende Panels, übergroße runde Ecken, dramatische Schatten, eine Inter-und-Lila-Stimmung, die „schreit, dass eine KI das gemacht hat“. Weitere gemeldete Probleme sind Layouts, die auf Mobilgeräten brechen, und Anweisungen, die in die UI-Texte durchsickern."}, {"kind": "steps", "items": [{"label": "Füge eine Design-skill hinzu", "body": "Eine kuratierte ästhetische skill zwingt Cursor, sich auf eine echte Richtung festzulegen, statt auf den Standard-Look."}, {"label": "Nutze die Vorschau zum Verifizieren", "body": "Rendere und prüfe in der In-Editor-Vorschau über Breakpoints hinweg, damit Layouts nicht stillschweigend auf Mobilgeräten brechen."}, {"label": "Liefere tokens und Referenzen", "body": "Echte Design-tokens und Referenz-Screenshots sind der größte Einzelhebel für die Output-Qualität."}, {"label": "Hinterlege Regeln in `.cursor/rules`", "body": "Schreibe Regeln im Stil „keine Hero-Cards, höchstens zwei Schriftarten, markenorientierte Hierarchie“ dorthin, wo der Agent sie bei jedem Durchlauf liest."}]}, {"kind": "p", "text": "Beachte: Jede dieser Maßnahmen dreht sich darum, dem Agenten einen kuratierten Design-Kontext zu geben. Diesen Kontext von Hand und pro Projekt zu pflegen, ist genau die Mühsal, die Open Design beseitigt."}]}, {"id": "open-design", "heading": "Mit Cursor in Open Design gestalten", "blocks": [{"kind": "p", "text": "Open Design ist die quelloffene Design-Schicht, nach der der obige Workflow immer wieder verlangt. Es behandelt Cursor als First-Party-Adapter und umgibt ihn mit einer kuratierten skill- und Designsystem-Bibliothek, einer strukturierten Render-Pipeline und einer lokalen Desktop-UI — sodass der Design-Kontext, der Cursor gut macht, vom ersten Durchlauf an da ist, statt jedes Mal von Hand zusammengebaut zu werden."}, {"kind": "ol", "items": ["Installiere Open Design und wähle Cursor als deinen Agenten.", "Authentifiziere dich mit deinem Cursor-Account oder deinen eigenen Modell-Keys (BYOK) — die Zugangsdaten bleiben auf deiner Maschine und werden niemals über uns geleitet.", "Wähle ein Designsystem und eine skill und erzeuge dann Decks, Prototypen und Landingpages mit konsistentem Geschmack.", "Jedes Artefakt und jede DESIGN.md-Datei liegt in deinem eigenen Repo, nicht in einer gehosteten Cloud."]}, {"kind": "p", "text": "Derselbe Cursor-Agent, derselbe Key — plus ein echter, portabler, quelloffener Design-Workflow drumherum. Es ist local-first und Apache-2.0, sodass nichts an deiner Arbeit oder deinen Zugangsdaten deine Maschine verlässt."}]}], "faqTitle": "Häufig gestellte Fragen", "faq": [{"name": "Kann Cursor wirklich Designarbeit leisten?", "text": "Ja — mit einer Design-skill, einem Designsystem und echten Referenzbildern im Kontext liefert Cursor produktionsreife, responsive UI, und seine In-Editor-Vorschau lässt dich sie visuell verifizieren und verfeinern. Ohne diesen Kontext fällt es tendenziell auf einen generischen Look zurück — und genau diese Lücke schließt Open Design."}, {"name": "Ist das ein offizielles Cursor-Produkt?", "text": "Nein. Open Design ist ein unabhängiges quelloffenes Projekt, das Cursor als Agenten integriert. Es ergänzt Cursor um eine local-first, offene skill- und Designsystem-Bibliothek."}, {"name": "Brauche ich ein Cursor-Abo, um mit Cursor zu gestalten?", "text": "Du kannst einen Cursor-Account / ein -Abo nutzen oder deine eigenen Modell-Keys (BYOK) mitbringen. Open Design leitet deine Zugangsdaten in keinem Fall weiter — sie werden direkt von deinem Agenten genutzt."}, {"name": "Cursor oder Claude Code für Frontend-Design?", "text": "Beide sind stark. Claude Code ist bekannt für konkrete, codebasis-bewusste Designentscheidungen; Cursors Vorteil ist seine enge Build-and-See-Schleife mit einer Live-Vorschau im Editor. Viele Teams nutzen beide — Open Design lässt dich die Agenten wechseln, ohne deinen Design-Workflow zu ändern."}, {"name": "Wie verbinde ich Cursor mit Figma?", "text": "Füge den offiziellen Figma-MCP-Server in Cursor hinzu, füge dann einen Figma-Frame-Link in den Chat ein und bitte Cursor, ihn umzusetzen. Der Server legt echte Komponenten, Variablen und Layout-Daten offen, sodass der erzeugte Code zum Quelldesign passt."}, {"name": "Wie vermeide ich die generische „AI-Slop“-Ästhetik?", "text": "Füge eine Design-skill hinzu, liefere echte Design-tokens und Referenz-Screenshots, hinterlege Markenregeln in `.cursor/rules` oder `AGENTS.md` und verifiziere in der Vorschau über Breakpoints hinweg. Open Design liefert diese als kuratierte Bibliothek aus, sodass du das Setup pro Projekt überspringst."}, {"name": "Ist Open Design mit Cursor oder Anysphere verbunden?", "text": "Nein. Cursor ist ein Produkt von Anysphere; Open Design ist ein unabhängiges quelloffenes Projekt, das es als First-Party-Adapter unterstützt. Cursor und Anysphere sind Marken von Anysphere, Inc."}, {"name": "Sind meine Dateien und Zugangsdaten sicher?", "text": "Ja — Open Design ist local-first. Deine Dateien, Artefakte und DESIGN.md bleiben in deinem eigenen Repo, und deine Cursor- oder Modell-Zugangsdaten werden direkt von deinem Agenten genutzt, niemals über Open-Design-Server geleitet."}], "ctaTitle": "Gestalte mit Cursor, auf die offene Art.", "ctaBody": "Bring deinen eigenen Cursor-Account oder deine Modell-Keys mit, behalte jede Datei lokal und erhalte eine kuratierte Design-Bibliothek rund um den Agenten, den du ohnehin schon nutzt.", "ctaActions": [{"label": "Cursor in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Alle unterstützten Agenten ansehen"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode für Design — Open Design",
        description: "Wie Menschen OpenCode für UI- und Webdesign nutzen — design.md-Dateien, UI/UX-skills, Figma-MCP — und wie Open Design OpenCode zu einem local-first, quelloffenen Design-Agenten macht.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode für Design.",
        lead: "OpenCode ist der quelloffene KI-Coding-Agent für das Terminal. Designer schrauben Design-skills und DESIGN.md-Dateien daran, um echte UI zu erzeugen. Open Design macht daraus einen strukturierten, quelloffenen Workflow — bring deine Provider-Keys mit und behalte alles lokal.",
        rich: {"heroCtaLead": "Open Design macht OpenCode zu einem local-first, quelloffenen Design-Agenten — jedes Modell, das du wählst, mit deinem eigenen Provider-Key, deine Dateien, dazu eine kuratierte skill- und Designsystem-Bibliothek drumherum.", "heroCtaActions": [{"label": "OpenCode in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode ist ein quelloffener, terminal-first KI-Coding-Agent, der bewusst modell-agnostisch ist: Du bringst deinen eigenen Provider-Key mit und lässt hinter demselben Workflow jedes beliebige Modell laufen. Diese Offenheit macht ihn zu einer natürlichen Basis für Designarbeit — doch wie jeder Agent liefert er nur dann gute UI, wenn du ihm die richtigen Referenzen, skills und eine Verifizierungsschleife gibst. Dies ist ein praktischer End-to-End-Leitfaden, wie du OpenCode für UI-, Frontend- und Designsystem-Arbeit einsetzt und ihn mit Open Design in einen strukturierten Design-Workflow einbindest.", "Er behandelt, was OpenCode wirklich ist, warum ein modell-agnostischer offener Agent gut zu Design passt, wie du ihn von null aufsetzt, die Screenshot-zu-UI-Schleife, wie AGENTS.md und MCP ihn erweitern, wie er im Vergleich zu Codex, Claude Code und Cursor abschneidet, die Fallstricke, die KI-Output generisch wirken lassen, und wie Open Design die Lücke als offene, local-first Design-Schicht schließt — eine natürliche Paarung, da beide Projekte quelloffen sind und auf deiner eigenen Maschine laufen."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode-Design-Feedbackschleife: ein Terminal-TUI-Agent, ein Browser, der die UI rendert, und ein Workspace, mit einem zurückführenden Feedback-Pfeil", "caption": "Die Kernschleife: OpenCode baut UI im Terminal, rendert und verifiziert sie in einem echten Browser und iteriert gegen deine Referenzen — auf welchem Modell auch immer du wählst."}, "tocLabel": "Auf dieser Seite", "toc": [{"id": "what-is-opencode", "label": "Was OpenCode wirklich ist"}, {"id": "why-design", "label": "Warum ein offener Any-Model-Agent zu Design passt"}, {"id": "setup", "label": "OpenCode für Design einrichten (von null)"}, {"id": "screenshot-workflow", "label": "Der Screenshot-zu-UI-Workflow"}, {"id": "extend", "label": "AGENTS.md, MCP und teilbare Sessions"}, {"id": "vs", "label": "OpenCode vs. Codex vs. Claude Code vs. Cursor"}, {"id": "pitfalls", "label": "Fallstricke und der „AI-Slop“-Look"}, {"id": "open-design", "label": "Mit OpenCode in Open Design gestalten"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Was OpenCode wirklich ist", "blocks": [{"kind": "p", "text": "OpenCode ist ein quelloffener KI-Coding-Agent für das Terminal, gepflegt vom Team hinter SST (Anomaly Innovations). Es liest dein Repository, führt Befehle aus, bearbeitet Dateien und spricht mit einem großen Sprachmodell — doch anders als anbietergebundene Agenten liefert es kein eigenes Modell mit. Du richtest es auf den Provider und das Modell aus, das du willst, und bringst deinen eigenen Key mit."}, {"kind": "p", "text": "Es läuft als Terminal-UI (TUI), mit einer Desktop-App und IDE-Erweiterungen auf derselben Engine. Unter der Haube nutzt es eine Client-/Server-Architektur, sodass der Agent, der die Arbeit erledigt, von der Oberfläche entkoppelt ist, über die du ihn steuerst. Zwei eingebaute Agenten — build und plan — wechselst du mit der Tab-Taste."}, {"kind": "steps", "items": [{"label": "Modell-agnostisch", "body": "Modelle und Provider kommen aus models.dev, einem offenen Katalog. Du konfigurierst sie in opencode.json mit einem provider/model-id-String und kannst Provider deaktivieren, die du nicht geladen haben willst — sodass derselbe Design-Workflow auf Anthropic, OpenAI, Google, OpenRouter, lokalen Modellen und mehr läuft."}, {"label": "Anweisungsdatei", "body": "OpenCode liest eine AGENTS.md-Datei in deinem Projekt (den toolübergreifenden Standard, auch kompatibel mit CLAUDE.md) für Projektregeln — der natürliche Ort, um deine Design-Konventionen zu hinterlegen. Führe /init aus, um eine zu erzeugen."}, {"label": "Erweiterbar", "body": "Es unterstützt LSP-Integration, MCP-Server, Themes, Tastenkürzel und eigene Befehle sowie teilbare Session-Links zur Zusammenarbeit."}]}, {"kind": "ul", "items": ["Betreuer: SST / Anomaly Innovations (quelloffenes Projekt)", "Zugangsdaten: deine eigenen API-Keys der Modell-Provider — BYOK, kein Vendor-Lock-in", "Lizenz: MIT, quelloffen"]}]}, {"id": "why-design", "heading": "Warum ein offener Any-Model-Agent zu Designarbeit passt", "blocks": [{"kind": "p", "text": "OpenCode hat kein einzelnes „Design-Modell“ wie ein Anbieter-Agent — und das ist der Punkt. Weil es modell-agnostisch und offen ist, kannst du denselben Design-Workflow auf dem Modell laufen lassen, das gerade am besten im Frontend ist, es später tauschen oder auf ein lokales Modell zurückgreifen, alles ohne dein Setup zu ändern."}, {"kind": "p", "text": "Aber die Modellwahl allein erkauft keinen Geschmack. Wie jeder Coding-Agent erzeugt OpenCode generische UI, solange du ihm keine Vorgaben machst. Guter Design-Output entsteht aus drei Eingaben, die du lieferst."}, {"kind": "steps", "items": [{"label": "Ein Designsystem", "body": "Echte tokens, Primitive und Konventionen, die der Agent wiederverwendet, sodass der Output zu einer Marke passt, statt zu einem generischen Look zurückzufallen."}, {"label": "Eine ästhetische skill", "body": "Eine kuratierte skill, die echten Geschmack erzwingt — zurückhaltende Bewegung, markenorientierte Hierarchie, höchstens zwei Schriftarten und eine Akzentfarbe — und den Agenten dazu bringt, sich auf eine Richtung festzulegen, bevor er baut."}, {"label": "Konkrete Referenzen", "body": "Echte Referenzbilder und mehrere Zustände (Desktop und Mobile, Hover, leer, ladend), nicht ein einzelner Hero-Shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagramm, das zeigt, wie Designsystem, skill und Referenzbild zu gutem Design-Output zusammenlaufen", "caption": "Geschmack entsteht aus drei Eingaben, die du lieferst: einem Designsystem, einer skill und echten Referenzbildern — unabhängig davon, welches Modell du laufen lässt."}, {"kind": "p", "text": "Die Lektion: OpenCode gibt dir Modell-Freiheit, aber Geschmack entsteht weiterhin aus einem kuratierten Design-Kontext. Open Design bündelt genau diese Eingaben — deshalb passen die beiden zusammen: Beide sind quelloffen und local-first (mehr dazu weiter unten)."}]}, {"id": "setup", "heading": "OpenCode für Designarbeit einrichten, von null", "blocks": [{"kind": "p", "text": "Hier ist der komplette Weg von einer frischen Maschine zu einem OpenCode, das UI bauen und verifizieren kann."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Fünfstufiger Einrichtungsablauf: installieren, mit deinem Provider-Key authentifizieren, AGENTS.md konfigurieren, eine skill hinzufügen, verifizieren", "caption": "Die Einrichtungssequenz: installieren → authentifizieren (dein Provider-Key) → AGENTS.md konfigurieren → eine skill hinzufügen → in einem echten Browser verifizieren."}, {"kind": "steps", "items": [{"label": "Hinterlege deine Designregeln", "body": "Schreibe deine tokens, Primitive und Konventionen in AGENTS.md (oder eine daraus referenzierte DESIGN.md), damit der Output zu einer Marke passt, statt zu einem generischen Look zurückzufallen. Die instructions-Option in opencode.json kann über globs auf zusätzliche Regeldateien verweisen."}, {"label": "Wähle ein leistungsfähiges Modell", "body": "Weil OpenCode modell-agnostisch ist, wähle für den Design-Durchlauf den Provider / das Modell, das gerade am stärksten im Frontend ist — und lass den Rest deines Workflows unverändert."}]}]}, {"id": "screenshot-workflow", "heading": "Der Screenshot-zu-UI-Workflow", "blocks": [{"kind": "p", "text": "Die wirkungsvollste Design-Schleife mit jedem Agenten besteht darin, ein Referenzbild in funktionierende, responsive UI zu verwandeln und zu iterieren, bis es passt. Dieselbe fünfstufige Form gilt in OpenCode."}, {"kind": "ol", "items": ["Beginne mit den klarsten visuellen Referenzen, die du hast — und nimm mehrere Zustände auf (Desktop und Mobile, Hover, leer, ladend), nicht nur einen Hero-Shot.", "Sei im Prompt konkret; vage Prompts erzeugen generische UI.", "Bereite ein Designsystem vor und sag OpenCode, wo die tokens und kanonischen Primitive liegen (in AGENTS.md).", "Lass einen Dev-Server laufen und lass den Agenten in einem echten Browser rendern, wobei er auf Breakpoints umstellt, um das Ergebnis zu prüfen.", "Iteriere, indem du OpenCode seine Umsetzung mit den Screenshots abgleichen lässt — nicht bloß bestätigen, dass es baut."]}, {"kind": "p", "text": "Referenziere Dateien mit @ in der TUI für eine Fuzzy-Suche deines Arbeitsverzeichnisses, führe Shell-Befehle inline mit vorangestelltem ! aus und steuere Aktionen mit /-Befehlen. Prompte dann mit konkreten Vorgaben:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Halte Prompts klein und fokussiert, committe gute Iterationen und verwirf schlechte (und teile OpenCode mit, wenn du zurücksetzt), damit jeder Durchlauf auf einer sauberen Basis aufbaut."}]}, {"id": "extend", "heading": "AGENTS.md, MCP und teilbare Sessions", "blocks": [{"kind": "p", "text": "Drei Erweiterungspunkte machen OpenCode für nachhaltige Designarbeit praktisch, und alle drei bilden sauber einen offenen Design-Workflow ab."}, {"kind": "steps", "items": [{"label": "AGENTS.md-Regeln", "body": "Projektregeln liegen in einer AGENTS.md im Repo-Stamm (oder als globale Regeln in ~/.config/opencode/AGENTS.md). Es ist die dauerhafte Heimat für deine Design-Konventionen, wird bei jedem Durchlauf gelesen und ist mit den CLAUDE.md-Dateien kompatibel, die andere Agenten verwenden."}, {"label": "MCP-Server", "body": "OpenCode unterstützt sowohl lokale (command) als auch entfernte (URL) MCP-Server, konfiguriert unter dem mcp-Schlüssel — der portable Weg, Design-Kontext und externe Tools einzubinden, die über Agenten hinweg funktionieren, nicht nur in OpenCode."}, {"label": "Teilbare Sessions", "body": "Der /share-Befehl erstellt einen öffentlichen Link zu einer Konversation für Zusammenarbeit oder Review, und /unshare widerruft ihn — nützlich, um Feedback zu einem Design-Durchlauf einzuholen."}]}, {"kind": "p", "text": "Das sind portable, agentenübergreifende Fähigkeiten — genau die Art Sache, die Open Design orchestrieren soll, statt sie pro Projekt neu zu erstellen."}]}, {"id": "vs", "heading": "OpenCode vs. Codex vs. Claude Code vs. Cursor für Design", "blocks": [{"kind": "p", "text": "Es gibt keinen einzelnen Gewinner für Designarbeit — jeder Agent hat eine andere Stärke, und erfahrene Teams kombinieren sie. Eine faire Zusammenfassung:"}, {"kind": "table", "columns": ["Agent", "Design-Stärke", "Am besten für"], "rows": [["OpenCode", "Quelloffen und modell-agnostisch; jeden Provider hinter einem Terminal-Workflow laufen lassen", "BYOK-Freiheit, Modellwechsel, vollständig offene und local-first Setups"], ["Codex", "Starker visueller Feinschliff mit einer frontend-skill; Bildverständnis", "Delegiert asynchron, sandboxed Builds, portable AGENTS.md-Regeln"], ["Claude Code", "Konkrete Designentscheidungen (hex, Abstände, Typografie) und codebasis-bewusstes UX", "Frontend-Argumentation und Refactorings mit großem Kontext"], ["Cursor", "Visuelle Build-and-See-Schleife mit Live-Vorschau und Inline-Edits", "Enge iterieren-und-beobachten-UI-Arbeit innerhalb einer IDE"]]}, {"kind": "p", "text": "Das wiederkehrende Urteil der Community lautet, dass Geschmack von Menschen kommt: Alle tendieren ohne skills, Referenzen und Vorgaben zu einer generischen Ästhetik. Das ist das eigentliche Problem, das es zu lösen gilt — und es hat die Form eines Design-Tools, nicht die eines Modells, was genau der Grund ist, warum ein offener Agent wie OpenCode so gut zu einer offenen Design-Schicht passt."}]}, {"id": "pitfalls", "heading": "Fallstricke und wie du den „AI-Slop“-Look vermeidest", "blocks": [{"kind": "p", "text": "Die häufigste Klage über KI-generiertes Design lautet, dass es generisch aussieht — weiche Verläufe, schwebende Panels, übergroße runde Ecken, dramatische Schatten, eine Inter-und-Lila-Stimmung, die „schreit, dass eine KI das gemacht hat“. Weitere gemeldete Probleme sind kaputte Mobile-Layouts und Anweisungen, die in die UI-Texte durchsickern. Keines davon ist OpenCode-spezifisch; sie sind das, was passiert, wenn irgendein Agent ohne kuratierten Design-Kontext läuft."}, {"kind": "steps", "items": [{"label": "Füge eine ästhetische skill hinzu", "body": "Eine kuratierte Design-skill zwingt den Agenten, sich auf eine echte Richtung festzulegen, statt auf den Standard-Look."}, {"label": "Verifiziere in einem echten Browser", "body": "Rendere und prüfe über Breakpoints hinweg, damit Layouts nicht stillschweigend auf Mobilgeräten brechen."}, {"label": "Liefere tokens und Referenzen", "body": "Echte Design-tokens und Referenz-Screenshots sind der größte Einzelhebel für die Output-Qualität."}, {"label": "Hinterlege Regeln in AGENTS.md", "body": "Schreibe Regeln im Stil „keine Hero-Cards, höchstens zwei Schriftarten, markenorientierte Hierarchie“ dorthin, wo der Agent sie bei jedem Durchlauf liest."}]}, {"kind": "p", "text": "Beachte: Jede dieser Maßnahmen dreht sich darum, dem Agenten einen kuratierten Design-Kontext zu geben — unabhängig davon, welches Modell du laufen lässt. Diesen Kontext von Hand und pro Projekt zu pflegen, ist genau die Mühsal, die Open Design beseitigt."}]}, {"id": "open-design", "heading": "Mit OpenCode in Open Design gestalten", "blocks": [{"kind": "p", "text": "Open Design ist die quelloffene Design-Schicht, nach der der obige Workflow immer wieder verlangt. Es behandelt OpenCode als First-Party-Adapter und umgibt es mit einer kuratierten skill- und Designsystem-Bibliothek, einer strukturierten Render-Pipeline und einer lokalen Desktop-UI — sodass der Design-Kontext, der jeden Agenten gut macht, vom ersten Durchlauf an da ist, statt jedes Mal von Hand zusammengebaut zu werden. Beide Projekte sind quelloffen und local-first, was die Paarung zu einer natürlichen Wahl macht."}, {"kind": "ol", "items": ["Installiere Open Design und wähle OpenCode als deinen Agenten.", "Authentifiziere dich mit deinem eigenen API-Key des Modell-Providers (BYOK) — die Zugangsdaten bleiben auf deiner Maschine und werden niemals über uns geleitet.", "Wähle einen beliebigen Provider und ein Modell, dazu ein Designsystem und eine skill, und erzeuge dann Decks, Prototypen und Landingpages mit konsistentem Geschmack.", "Jedes Artefakt und jede DESIGN.md-Datei liegt in deinem eigenen Repo, nicht in einer gehosteten Cloud."]}, {"kind": "p", "text": "Derselbe OpenCode-Agent, dieselbe Modell-Freiheit — plus ein echter, portabler, quelloffener Design-Workflow drumherum. Es ist local-first und Apache-2.0, sodass nichts an deiner Arbeit oder deinen Zugangsdaten deine Maschine verlässt."}]}], "faqTitle": "Häufig gestellte Fragen", "faq": [{"name": "Kann OpenCode wirklich Designarbeit leisten?", "text": "Ja — mit einer ästhetischen skill, einem Designsystem und echten Referenzbildern im Kontext liefert OpenCode produktionsreife, responsive UI und kann sie in einem Browser verifizieren. Weil es modell-agnostisch ist, lässt du das Modell laufen, das gerade am besten im Frontend ist. Ohne diesen kuratierten Kontext fällt es tendenziell auf einen generischen Look zurück — und genau diese Lücke schließt Open Design."}, {"name": "Welches Modell sollte ich mit OpenCode für Design verwenden?", "text": "Welches du magst — OpenCode ist über models.dev provider-agnostisch, sodass du Anthropic, OpenAI, Google, OpenRouter oder lokale Modelle hinter demselben Workflow laufen lassen und jederzeit wechseln kannst. Die Qualität des Design-Outputs hängt weit mehr von deiner skill, deinem Designsystem und deinen Referenzen ab als vom Modell allein."}, {"name": "Ist Open Design vom OpenCode- (SST-)Team gemacht?", "text": "Nein. Open Design ist ein unabhängiges quelloffenes Projekt, das OpenCode als Agenten integriert. Es ergänzt OpenCode um eine local-first, offene skill- und Designsystem-Bibliothek."}, {"name": "Brauche ich ein spezielles Abo, um mit OpenCode zu gestalten?", "text": "Nein — OpenCode ist BYOK. Du bringst deinen eigenen API-Key des Modell-Providers mit, und Open Design leitet deine Zugangsdaten niemals weiter. Es gibt kein Vendor-Lock-in."}, {"name": "OpenCode oder Codex oder Claude Code für Frontend-Design?", "text": "Alle sind stark, und viele Teams kombinieren sie. OpenCodes Vorteil ist, vollständig quelloffen und modell-agnostisch zu sein; Codex glänzt bei delegierten, sandboxed Builds; Claude Code ist bekannt für konkrete, codebasis-bewusste Designentscheidungen. Open Design lässt dich die Agenten wechseln, ohne deinen Design-Workflow zu ändern."}, {"name": "Wie erweitere ich OpenCode um Design-Kontext?", "text": "Hinterlege Regeln in AGENTS.md, füge MCP-Server unter dem mcp-Schlüssel für portable Tools und Design-Kontext hinzu und nutze teilbare Sessions für Reviews. Open Design liefert eine kuratierte skill- und Designsystem-Bibliothek aus, sodass du das Setup pro Projekt überspringst."}, {"name": "Ist Open Design mit OpenCode oder SST verbunden?", "text": "Nein. OpenCode ist ein quelloffenes Projekt, das von SST (Anomaly Innovations) gepflegt wird; Open Design ist ein unabhängiges quelloffenes Projekt, das es als First-Party-Adapter unterstützt."}, {"name": "Sind meine Dateien und Zugangsdaten sicher?", "text": "Ja — Open Design ist local-first. Deine Dateien, Artefakte und DESIGN.md bleiben in deinem eigenen Repo, und deine Zugangsdaten des Modell-Providers werden direkt von deinem Agenten genutzt, niemals über Open-Design-Server geleitet."}], "ctaTitle": "Gestalte mit OpenCode, auf die offene Art.", "ctaBody": "Bring deinen eigenen Modell-Provider-Key mit, behalte jede Datei lokal und erhalte eine kuratierte Design-Bibliothek rund um den offenen Agenten, den du ohnehin schon nutzt.", "ctaActions": [{"label": "OpenCode in Open Design verwenden", "href": "/quickstart/", "variant": "primary"}, {"label": "Auf GitHub mit Stern markieren", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Desktop-App herunterladen", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Alle unterstützten Agenten ansehen"},
      },
    },
    'fr': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code pour le design — Open Design",
        description: "Comment les designers utilisent Claude Code pour le design d’interfaces et de sites web, et comment Open Design en fait un véritable agent de design — local-first, BYOK, avec une bibliothèque organisée de skills et de design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code pour le design.",
        lead: "Claude Code est l’agent de code en terminal d’Anthropic. On l’utilise déjà pour construire des interfaces, des design systems et des landing pages. Open Design le branche sur un véritable workflow de design — apportez votre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local.",
        rich: {"heroCtaLead": "Open Design transforme Claude Code en un agent de design open source et local-first — votre clé Anthropic ou votre abonnement Claude, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code est largement considéré comme l’agent de code au meilleur goût en frontend — il raisonne sur les interfaces avec une précision inhabituelle, nommant des valeurs hex exactes, des espacements et des échelles typographiques, et il refactorise l’UI à travers une grande base de code sans perdre le fil. Mais tel quel, il dérive encore vers un rendu générique tant que vous ne lui fournissez pas un design system, des skills et de vraies références. Voici un guide pratique et complet pour utiliser Claude Code dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow structuré avec Open Design.", "Il couvre ce qu’est réellement Claude Code, pourquoi il excelle en frontend, comment le configurer à partir de zéro, le workflow CLAUDE.md et Skills, l’aller-retour officiel avec Figma, sa comparaison avec Codex et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Boucle de rétroaction de design avec Claude Code : un agent en terminal prenant des décisions de design précises, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Claude Code raisonne sur des décisions d’UI précises dans le terminal, les affiche et les vérifie dans un vrai navigateur, et converge vers vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-claude-code", "label": "Ce qu’est réellement Claude Code"}, {"id": "why-design", "label": "Pourquoi Claude Code est bon en design"}, {"id": "setup", "label": "Configurer Claude Code pour le design (à partir de zéro)"}, {"id": "skills-workflow", "label": "Le workflow CLAUDE.md et Skills"}, {"id": "figma", "label": "Aller-retour Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Claude Code dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Ce qu’est réellement Claude Code", "blocks": [{"kind": "p", "text": "Claude Code est l’outil de code agentique d’Anthropic. Il lit votre base de code, modifie des fichiers, exécute des commandes et s’intègre à vos outils de développement — il planifie, écrit et vérifie le travail à partir de tâches en langage naturel, plutôt que de se contenter de compléter des lignes."}, {"kind": "p", "text": "Il se décline sur plusieurs surfaces qui partagent toutes le même moteur : une CLI en terminal, des extensions IDE pour VS Code, Cursor et JetBrains, une application desktop avec revue visuelle des diffs, et une expérience web pour les tâches de longue durée. Vos fichiers CLAUDE.md, vos réglages et vos serveurs MCP s’appliquent à toutes."}, {"kind": "steps", "items": [{"label": "Fichier d’instructions", "body": "Claude Code lit un fichier CLAUDE.md à la racine de votre projet au début de chaque session — l’endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue."}, {"label": "Skills", "body": "Les Agent Skills regroupent des instructions, scripts et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic pour le goût."}, {"label": "Plan et sous-agents", "body": "Il peut planifier avant d’agir et lancer des sous-agents qui travaillent en parallèle sur différentes parties d’une tâche, ce qui maintient la cohérence des grands refactors d’UI."}]}, {"kind": "ul", "items": ["Éditeur : Anthropic", "Identifiant : clé API Anthropic (BYOK, via la Console) ou abonnement Claude (Pro / Max)", "Surfaces : CLI en terminal, extensions VS Code / Cursor / JetBrains, application desktop, web"]}]}, {"id": "why-design", "heading": "Pourquoi Claude Code est bon en design", "blocks": [{"kind": "p", "text": "Parmi les agents de code, Claude Code a une réputation de goût pour le travail en frontend. Quelques raisons l’expliquent."}, {"kind": "steps", "items": [{"label": "Des décisions précises, pas vagues", "body": "Claude Code a tendance à s’engager sur des choix concrets — valeurs hex exactes, échelles d’espacement, rampes typographiques et hiérarchie des composants — au lieu de rester évasif, ce qui distingue une vraie interface d’une maquette de remplissage."}, {"label": "Un raisonnement conscient de la base de code", "body": "Avec un large contexte de travail, il refactorise l’UI à travers de nombreux fichiers à la fois, en réutilisant vos composants et tokens existants au lieu de réinventer des styles isolés."}, {"label": "Une skill frontend officielle", "body": "Anthropic fournit une skill Frontend Design qui amène Claude à définir d’abord une direction de design et l’éloigne délibérément des polices système génériques et des dégradés violets prévisibles."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle qu’Anthropic formule à propos de ses propres modèles : Claude n’a pas de goût par défaut — laissé à lui-même, il converge vers le centre statistique du web design (Inter, dégradés violets, ombres douces). Il produit de bons designs quand vous lui donnez des contraintes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Claude Code pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Claude Code capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer CLAUDE.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer CLAUDE.md → ajouter la skill Frontend Design → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans CLAUDE.md et orientez Claude vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Ajoutez la vérification en navigateur", "body": "Branchez un MCP Playwright ou Chrome pour que Claude rende dans un vrai navigateur et contrôle ses sorties sur les différents breakpoints, au lieu de simplement confirmer que le build passe."}]}]}, {"id": "skills-workflow", "heading": "Le workflow CLAUDE.md et Skills", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Claude Code consiste à lui donner de vraies références ainsi que votre contexte de design, puis à itérer jusqu’à ce que l’UI corresponde — avec CLAUDE.md et les Skills qui portent les contraintes pour ne pas avoir à les réexpliquer à chaque prompt."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique, même avec un agent puissant.", "Gardez votre design system et vos conventions dans CLAUDE.md, et indiquez à Claude où se trouvent les tokens et les primitives canoniques.", "Ajoutez la skill Frontend Design pour que Claude s’engage sur une véritable direction esthétique avant d’écrire du code.", "Branchez la vérification en navigateur pour que Claude rende, redimensionne aux breakpoints et compare aux références — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Déposez une image de référence dans la session et formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev en parallèle, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Claude quand vous revenez en arrière) pour que chaque passe parte d’une base propre. Utilisez le mode plan pour les refactors plus importants afin de pouvoir relire l’approche avant toute modification de fichier."}]}, {"id": "figma", "heading": "Claude Code + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, Anthropic et Figma ont livré une intégration bidirectionnelle de premier ordre via le serveur Figma MCP. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Sélectionnez une frame dans Figma ou collez un lien dans Claude Code, récupérez le contexte de design et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante. Code Connect garde les sorties alignées sur vos vrais composants."}, {"label": "Code → Design", "body": "Construisez et prévisualisez une fonctionnalité dans le navigateur, puis dites « Send this to Figma » pour capturer l’UI en cours d’exécution sous forme de calques Figma éditables — écran entier ou élément sélectionné."}]}, {"kind": "p", "text": "Installez-le une fois avec claude plugin install figma@claude-plugins-official (le MCP Dev Mode requiert un plan Figma payant). Le même Figma MCP est disponible pour Claude Code, Codex, Cursor et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Claude Code", "Décisions de design précises (hex, espacement, typographie) et raisonnement UX conscient de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Codex", "Forte finition visuelle et compréhension d’images ; builds async en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "Malgré la réputation de goût de Claude Code, la critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — polices Inter, dégradés violets sur blanc, ombres douces, coins arrondis surdimensionnés, une esthétique qui « crie qu’une IA a fait ça ». Anthropic elle-même attribue cela à une convergence distributionnelle : les choix sûrs dominent les données d’entraînement du web. Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Installez la skill Frontend Design", "body": "Elle force Claude à s’engager sur une vraie direction et évite explicitement les polices et dégradés surexploités par l’IA."}, {"label": "Activez la vérification en navigateur", "body": "Faites en sorte que Claude rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans CLAUDE.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Claude Code dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Claude Code comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Claude Code bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Claude Code comme agent.", "Authentifiez-vous avec votre clé API Anthropic (BYOK) ou votre abonnement Claude — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Claude Code, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Claude Code est-il bon pour le travail de design ?", "text": "Oui — il est largement considéré comme l’agent de code au meilleur goût en frontend, prenant des décisions précises et conscientes de la base de code sur les valeurs hex, l’espacement et les échelles typographiques. Avec la skill Frontend Design, un design system et de vraies images de référence dans le contexte, il produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Ai-je besoin d’un abonnement Claude pour concevoir avec Claude Code ?", "text": "Vous pouvez utiliser soit une clé API Anthropic (BYOK, via la Console), soit un abonnement Claude (Pro / Max). Dans les deux cas, Open Design ne fait jamais transiter vos identifiants — ils sont utilisés directement par votre agent sur votre machine."}, {"name": "Claude Code ou Codex pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code et pour son raisonnement frontend ; Codex offre une forte finition visuelle et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Claude Code à Figma ?", "text": "Installez le plugin Figma officiel avec claude plugin install figma@claude-plugins-official. Vous pouvez ensuite implémenter des frames Figma en code à partir du contexte de design, et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec « Send this to Figma ». Le MCP Dev Mode requiert un plan Figma payant."}, {"name": "Que sont les Skills et CLAUDE.md ?", "text": "CLAUDE.md est un fichier markdown à la racine de votre projet que Claude Code lit au début de chaque session — l’endroit où encoder vos conventions de design. Les Skills regroupent des instructions et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic. Open Design fournit une bibliothèque organisée des deux pour vous éviter la configuration projet par projet."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez la skill Frontend Design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans CLAUDE.md et activez la vérification en navigateur. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Anthropic ?", "text": "Non. Claude Code est un produit d’Anthropic ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Claude et Claude Code sont des marques d’Anthropic."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Anthropic sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Claude Code, à la manière ouverte.", "ctaBody": "Apportez votre propre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex pour le design — Open Design",
        description: "Comment on utilise OpenAI Codex pour le design d’interfaces et de sites web — le plugin Product Design, l’intégration Figma, les skills frontend — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex pour le design.",
        lead: "Codex est l’agent de code d’OpenAI. Avec son plugin Product Design et son intégration Figma, il est devenu un véritable outil de design. Open Design branche Codex sur un workflow de design open source — votre clé OpenAI ou votre abonnement ChatGPT, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Codex en un agent de design open source et local-first — votre clé OpenAI, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex a démarré comme générateur de code, mais en 2026 il est devenu un outil crédible pour concevoir de vraies interfaces — à condition de lui donner les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser Codex dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est Codex aujourd’hui, pourquoi il est soudain bon en frontend, comment le configurer à partir de zéro, la boucle capture-vers-UI, l’aller-retour officiel avec Figma, sa comparaison avec Cursor et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Boucle de rétroaction de design avec Codex : un agent en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Codex construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-codex", "label": "Ce qu’est réellement OpenAI Codex"}, {"id": "why-design", "label": "Pourquoi Codex est bon en design désormais"}, {"id": "setup", "label": "Configurer Codex pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "figma", "label": "Aller-retour Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Codex dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Ce qu’est réellement OpenAI Codex (et ce qu’il n’est pas)", "blocks": [{"kind": "p", "text": "D’abord, une mise au point qui désarçonne presque tous ceux qui cherchent « Codex ». Le Codex d’OpenAI d’origine était un modèle de complétion de code de 2021 qui propulsait les premiers GitHub Copilot et a été déprécié en 2023. Ce n’est pas le sujet de cette page. Le Codex d’aujourd’hui est l’outil de code agentique d’OpenAI — il planifie, écrit, exécute et vérifie du code à partir de tâches en langage naturel."}, {"kind": "p", "text": "Le Codex moderne se décline sur quatre surfaces : une CLI en terminal (réécrite en Rust, sous licence Apache-2.0), une extension IDE pour VS Code, Cursor et Windsurf, une expérience cloud/web pour les tâches async déléguées, et une application desktop avec un navigateur intégré et Computer Use."}, {"kind": "steps", "items": [{"label": "Modèle par défaut", "body": "À la mi-2026, le modèle recommandé est gpt-5.5, gpt-5.4 étant le modèle qu’OpenAI a explicitement entraîné pour le frontend et l’usage de l’ordinateur."}, {"label": "Fichier d’instructions", "body": "Codex lit un fichier AGENTS.md dans votre projet (un standard inter-outils) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design."}, {"label": "Sandbox", "body": "Il s’exécute dans un sandbox au niveau noyau (workspace-write par défaut), de sorte qu’un agent qui modifie votre UI ne peut pas sortir du projet."}]}, {"kind": "ul", "items": ["Éditeur : OpenAI", "Identifiant : clé API OpenAI (BYOK) ou abonnement ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licence de la CLI : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi Codex est bon en design désormais", "blocks": [{"kind": "p", "text": "Trois choses ont convergé début 2026 pour faire de Codex un véritable outil de design plutôt qu’un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Un modèle entraîné pour le frontend", "body": "OpenAI a livré GPT-5.4, son premier modèle mainline entraîné pour le frontend et l’usage de l’ordinateur, avec une bien meilleure compréhension d’images tout au long du workflow de design et une auto-vérification renforcée. Il peut même générer des mood boards et des options visuelles avant de s’engager sur les assets finaux."}, {"label": "Une skill frontend officielle", "body": "Le catalogue openai/skills fournit une frontend-skill organisée qui impose un vrai goût : des mises en page sans cartes, des héros pleine largeur, une hiérarchie qui met la marque d’abord, un mouvement sobre, deux familles typographiques et une couleur d’accent au maximum — et amène Codex à écrire une thèse visuelle avant de construire."}, {"label": "La vérification en navigateur", "body": "Avec la skill Playwright, Codex ouvre un vrai navigateur, redimensionne aux breakpoints et compare ses sorties à la référence au lieu de simplement vérifier que le build passe."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon derrière ces trois points : Codex n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Codex pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Codex capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer, installer la skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer AGENTS.md → installer la skill frontend → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md ou un DESIGN.md et orientez Codex vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Choisissez le bon niveau de raisonnement", "body": "OpenAI note que les niveaux de raisonnement faibles à moyens produisent souvent de meilleurs résultats frontend que le réglage le plus élevé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Codex consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. Les recommandations d’OpenAI elles-mêmes se résument à cinq étapes."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Codex où se trouvent les tokens et les primitives canoniques.", "Activez la skill interactive Playwright pour que Codex rende dans un vrai navigateur et redimensionne aux breakpoints.", "Itérez en faisant comparer à Codex son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Fournissez les images en glissant une capture dans le terminal ou via le flag image, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev dans un second terminal, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Codex quand vous revenez en arrière) pour que chaque passe parte d’une base propre."}]}, {"id": "figma", "heading": "Codex + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, OpenAI et Figma ont annoncé un partenariat officiel, transformant la précédente bêta du Figma MCP en une intégration bidirectionnelle de premier ordre. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le « link to selection » d’une frame dans Figma, collez-le dans Codex avec get_design_context, et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante."}, {"label": "Code → Design", "body": "L’outil generate_figma_design (« Code to Canvas ») retransforme une UI en cours d’exécution en frames Figma éditables — écran entier, élément sélectionné ou fichier complet."}]}, {"kind": "p", "text": "Le Figma MCP s’exécute comme un serveur distant et est exempté des limites de débit. Ajoutez-le une fois et il est disponible pour Codex, Claude Code, Cursor, VS Code et plus encore — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Codex", "Forte finition visuelle après GPT-5.4 + frontend-skill ; compréhension d’images", "Les builds async délégués, les exécutions en sandbox, les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Codex est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées, des instructions qui fuient dans les textes de l’UI et des limites d’usage atteintes rapidement."}, {"kind": "steps", "items": [{"label": "Installez une skill frontend", "body": "Une skill esthétique organisée force Codex à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Activez la vérification Playwright", "body": "Faites en sorte que Codex rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Codex dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Codex comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Codex bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Codex comme agent.", "Authentifiez-vous avec votre clé API OpenAI (BYOK) ou votre abonnement ChatGPT — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Codex, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenAI Codex peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill frontend, un design system et de vraies images de référence dans le contexte, Codex (surtout sur GPT-5.4) produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "S’agit-il du plugin Product Design d’OpenAI Codex ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Codex comme agent. Il complète l’outillage propre d’OpenAI avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement ChatGPT pour concevoir avec Codex ?", "text": "Vous pouvez utiliser soit une clé API OpenAI (BYOK), soit votre abonnement ChatGPT. La connexion ChatGPT offre généralement des limites plus généreuses ; Open Design ne fait jamais transiter vos identifiants, dans les deux cas."}, {"name": "Codex ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; Codex offre une forte finition visuelle après GPT-5.4 et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Codex à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel (codex mcp add figma --url https://mcp.figma.com/mcp). Vous pouvez ensuite implémenter des frames Figma en code avec get_design_context et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec generate_figma_design."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez une skill frontend, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans AGENTS.md et activez la vérification Playwright. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenAI ?", "text": "Non. Codex est un produit d’OpenAI ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. OpenAI et Codex sont des marques d’OpenAI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants OpenAI sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Codex, à la manière ouverte.", "ctaBody": "Apportez votre propre clé OpenAI, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor pour les designers — Open Design",
        description: "Comment les designers utilisent Cursor pour le design d’interfaces et de sites web — le Design Mode, Figma-vers-code, le Figma MCP — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor pour les designers.",
        lead: "Cursor est l’éditeur de code IA, désormais doté d’un Design Mode visuel. Les designers l’utilisent pour modifier l’UI en pointant et en dessinant, et pour transformer Figma en code. Open Design branche Cursor Agent sur un workflow de design open source qui garde vos fichiers en local.",
        rich: {"heroCtaLead": "Open Design transforme Cursor en un agent de design open source et local-first — votre compte Cursor ou vos clés de modèle, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor est l’éditeur de code IA-first qui a fait de « construire et regarder le rendu » la façon par défaut de livrer de l’UI. Avec le mode Agent, les éditions inline, un aperçu intégré à l’éditeur et Figma via MCP, il est devenu un véritable outil de design — à condition de lui donner les bonnes références, les bonnes règles et une boucle de vérification. Voici un guide pratique et complet pour utiliser Cursor dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement Cursor, pourquoi sa boucle serrée d’itération est bonne pour le design, comment le configurer à partir de zéro, la boucle capture-et-aperçu-vers-UI, l’aller-retour Figma via MCP, sa comparaison avec Codex et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergence de design avec Cursor : l’éditeur à gauche, un hub organisé de skills et de design systems au centre avec la marque Cursor au milieu, et une UI rendue à droite", "caption": "L’idée centrale : Cursor modifie et affiche l’UI dans l’éditeur, tandis qu’un hub de design organisé lui fournit le système, les skills et les références qui font paraître les sorties intentionnelles."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-cursor", "label": "Ce qu’est réellement Cursor"}, {"id": "why-design", "label": "Pourquoi Cursor est bon en design"}, {"id": "setup", "label": "Configurer Cursor pour le design (à partir de zéro)"}, {"id": "preview-workflow", "label": "Le workflow aperçu-vers-UI"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Cursor dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Ce qu’est réellement Cursor", "blocks": [{"kind": "p", "text": "Cursor est un éditeur de code IA-first conçu par Anysphere. C’est un fork de VS Code, il conserve donc l’éditeur, les extensions et les raccourcis clavier familiers, mais reconstruit le workflow autour d’un agent IA capable de lire tout votre projet, de modifier plusieurs fichiers, d’exécuter des commandes et d’itérer avec vous dans la boucle."}, {"kind": "p", "text": "Pour le travail de design, les surfaces importantes sont le mode Agent (vous décrivez un résultat et Cursor planifie et modifie à travers les fichiers), les éditions inline et les complétions Tab pour des ajustements rapides, un aperçu / navigateur intégré à l’éditeur pour voir l’UI en cours d’exécution sans quitter la fenêtre, et le support MCP qui lui permet d’intégrer du contexte externe comme un fichier Figma en direct."}, {"kind": "steps", "items": [{"label": "Règles de projet", "body": "Cursor lit des fichiers d’instructions de projet — des règles `.mdc` versionnées sous `.cursor/rules`, et un simple `AGENTS.md` — pour que vous puissiez encoder vos conventions de design là où l’agent les lit à chaque exécution."}, {"label": "Modèles", "body": "Cursor est flexible côté modèles : il est livré avec des modèles de pointe via votre abonnement et prend aussi en charge l’apport de vos propres clés de modèle, vous choisissez donc le moteur derrière le même workflow d’éditeur."}, {"label": "MCP", "body": "Il parle le Model Context Protocol, de sorte que des serveurs externes — le plus pertinent étant le serveur Figma MCP — deviennent un contexte de premier ordre pour l’agent."}]}, {"kind": "ul", "items": ["Éditeur : Anysphere", "Identifiant : compte / abonnement Cursor (Hobby / Pro / Business) ou vos propres clés de modèle (BYOK)", "Forme : éditeur de code IA-first (fork de VS Code) avec un agent et un aperçu intégrés à l’éditeur"]}]}, {"id": "why-design", "heading": "Pourquoi Cursor est bon en design", "blocks": [{"kind": "p", "text": "L’avantage de Cursor en design n’est pas une fonctionnalité unique — c’est la rapidité de la boucle construire-et-voir. Trois choses le font ressembler à un outil de design plutôt qu’à un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Une boucle d’itération serrée", "body": "Vous donnez un prompt, Cursor modifie à travers les fichiers, et l’aperçu intégré à l’éditeur affiche le résultat immédiatement — vous ajustez ainsi l’espacement, la hiérarchie et le mouvement en quelques secondes au lieu de faire des allers-retours entre un terminal et un navigateur séparés."}, {"label": "L’édition visuelle directe", "body": "Au-delà du chat, Cursor vous laisse sélectionner des éléments dans l’aperçu et ajuster les styles, de sorte que les petites corrections visuelles ressemblent à des éditions de design plutôt qu’à de l’archéologie de code."}, {"label": "Règles de projet et contexte MCP", "body": "Avec `.cursor/rules` (ou `AGENTS.md`) et le serveur Figma MCP, l’agent travaille par rapport à vos tokens, composants et vraies specs de design au lieu de deviner."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Cursor n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Cursor pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Cursor capable de construire, prévisualiser et vérifier l’UI par rapport à votre design system."}, {"kind": "ol", "items": ["Installez Cursor depuis cursor.com et connectez-vous avec votre compte Cursor, ou configurez vos propres clés de modèle (BYOK) dans les Réglages.", "Ouvrez votre projet et choisissez un modèle dans le panneau chat / Agent.", "Ajoutez des règles de projet : créez `.cursor/rules/*.mdc` pour des conventions structurées et délimitées par glob, ou un simple `AGENTS.md` pour des instructions simples et lisibles.", "Connectez le serveur Figma MCP (optionnel) pour que l’agent puisse lire le contexte de design en direct.", "Faites tourner votre serveur de dev et utilisez l’aperçu intégré à l’éditeur pour voir et vérifier l’UI au fil de vos itérations."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer les règles, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer les règles de projet → ajouter une skill → activer la vérification par aperçu."}, {"kind": "p", "text": "Un fichier de règles de projet minimal amène l’agent à concevoir pour une marque au lieu de retomber sur un rendu générique. Placez-le là où Cursor le lit à chaque exécution :"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans `.cursor/rules` ou `AGENTS.md` et orientez Cursor vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Gardez des prompts courts", "body": "La boucle serrée de Cursor récompense les demandes ciblées — itérez un composant ou un état à la fois et observez l’aperçu entre chaque passe."}]}]}, {"id": "preview-workflow", "heading": "Le workflow aperçu-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Cursor consiste à transformer une référence en une UI fonctionnelle et responsive, puis à itérer dans l’éditeur jusqu’à ce qu’elle corresponde — en observant l’aperçu en direct tout du long au lieu de deviner."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Cursor où se trouvent les tokens et les primitives canoniques.", "Gardez l’aperçu intégré à l’éditeur ouvert et votre serveur de dev en route pour que chaque édition s’affiche immédiatement aux breakpoints qui vous importent.", "Itérez en comparant l’UI rendue avec les références — et utilisez la sélection directe d’éléments dans l’aperçu pour les petites corrections visuelles."]}, {"kind": "p", "text": "Fournissez les références en attachant une image au chat, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Committez les bonnes itérations et annulez les mauvaises (en prévenant Cursor quand vous revenez en arrière) pour que chaque passe parte d’une base propre — la même discipline qui empêche toute boucle d’agent de dériver."}]}, {"id": "figma", "heading": "Cursor + Figma : design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor se connecte à Figma via le serveur Figma MCP officiel, qui donne à l’agent un accès structuré à un fichier Figma en direct au lieu d’une capture à plat. Cela retire le tâtonnement du handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le lien d’une frame dans Figma, collez-le dans Cursor et demandez-lui d’implémenter la maquette. Le serveur MCP expose un vrai contexte de design — composants, variables, données de mise en page, tokens — pour que le code généré corresponde à la source au lieu de l’approximer."}, {"label": "Restez aligné", "body": "Avec des design tokens, des styles et des composants utilisés de manière cohérente dans Figma (et Code Connect là où c’est disponible), les sorties de Cursor restent mappées sur votre vrai design system plutôt que de réinventer des primitives."}]}, {"kind": "p", "text": "Configurez le serveur Figma MCP distant une fois et il est disponible pour Cursor en tant que contexte de premier ordre. Comme MCP est un standard ouvert, le même serveur est réutilisable à travers Cursor, Claude Code, Codex et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct dans l’éditeur et édition directe des éléments", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images et exécutions en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Cursor est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page qui cassent sur mobile et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill de design", "body": "Une skill esthétique organisée force Cursor à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Utilisez l’aperçu pour vérifier", "body": "Rendez et auto-contrôlez sur les différents breakpoints dans l’aperçu intégré à l’éditeur pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans `.cursor/rules`", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Cursor dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Cursor comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Cursor bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Cursor comme agent.", "Authentifiez-vous avec votre compte Cursor ou vos propres clés de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Cursor, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Cursor peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill de design, un design system et de vraies images de référence dans le contexte, Cursor produit une UI responsive de qualité production, et son aperçu intégré à l’éditeur vous laisse la vérifier et l’affiner visuellement. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Est-ce un produit officiel de Cursor ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Cursor comme agent. Il complète Cursor avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement Cursor pour concevoir avec Cursor ?", "text": "Vous pouvez utiliser un compte / abonnement Cursor ou apporter vos propres clés de modèle (BYOK). Open Design ne fait jamais transiter vos identifiants, dans les deux cas — ils sont utilisés directement par votre agent."}, {"name": "Cursor ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; l’avantage de Cursor est sa boucle serrée construire-et-voir avec un aperçu en direct au sein de l’éditeur. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Cursor à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel dans Cursor, puis collez un lien de frame Figma dans le chat et demandez à Cursor de l’implémenter. Le serveur expose de vrais composants, variables et données de mise en page pour que le code généré corresponde à la maquette source."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Ajoutez une skill de design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans `.cursor/rules` ou `AGENTS.md`, et vérifiez sur les différents breakpoints dans l’aperçu. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Cursor ou Anysphere ?", "text": "Non. Cursor est un produit d’Anysphere ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Cursor et Anysphere sont des marques d’Anysphere, Inc."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Cursor ou de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Cursor, à la manière ouverte.", "ctaBody": "Apportez votre propre compte Cursor ou vos clés de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode pour le design — Open Design",
        description: "Comment on utilise OpenCode pour le design d’interfaces et de sites web — les fichiers design.md, les skills UI/UX, le Figma MCP — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode pour le design.",
        lead: "OpenCode est l’agent de code IA en terminal, open source. Les designers lui ajoutent des skills de design et des fichiers DESIGN.md pour générer de vraies UI. Open Design en fait un workflow structuré et open source — apportez vos clés de fournisseur, gardez tout en local.",
        rich: {"heroCtaLead": "Open Design transforme OpenCode en un agent de design open source et local-first — n’importe quel modèle de votre choix avec votre propre clé de fournisseur, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode est un agent de code IA open source, pensé d’abord pour le terminal et délibérément agnostique au modèle : vous apportez votre propre clé de fournisseur et exécutez le modèle de votre choix derrière le même workflow. Cette ouverture en fait une base naturelle pour le travail de design — mais, comme tout agent, il ne produit de bonnes UI que si vous lui donnez les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser OpenCode dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement OpenCode, pourquoi un agent ouvert et agnostique au modèle convient au design, comment le configurer à partir de zéro, la boucle capture-vers-UI, comment AGENTS.md et MCP l’étendent, sa comparaison avec Codex, Claude Code et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first — un appariement naturel, puisque les deux projets sont open source et s’exécutent sur votre propre machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Boucle de rétroaction de design avec OpenCode : un agent TUI en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : OpenCode construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références — sur le modèle de votre choix."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-opencode", "label": "Ce qu’est réellement OpenCode"}, {"id": "why-design", "label": "Pourquoi un agent ouvert et tout-modèle convient au design"}, {"id": "setup", "label": "Configurer OpenCode pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "extend", "label": "AGENTS.md, MCP et sessions partageables"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec OpenCode dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Ce qu’est réellement OpenCode", "blocks": [{"kind": "p", "text": "OpenCode est un agent de code IA open source conçu pour le terminal, maintenu par l’équipe derrière SST (Anomaly Innovations). Il lit votre dépôt, exécute des commandes, modifie des fichiers et dialogue avec un grand modèle de langage — mais, contrairement aux agents liés à un éditeur, il ne fournit pas son propre modèle. Vous le pointez vers le fournisseur et le modèle de votre choix et apportez votre propre clé."}, {"kind": "p", "text": "Il s’exécute comme une UI en terminal (TUI), avec une application desktop et des extensions IDE par-dessus le même moteur. Sous le capot, il utilise une architecture client/serveur, de sorte que l’agent qui fait le travail est découplé de la surface depuis laquelle vous le pilotez. Deux agents intégrés — build et plan — se basculent avec la touche Tab."}, {"kind": "steps", "items": [{"label": "Agnostique au modèle", "body": "Les modèles et fournisseurs proviennent de models.dev, un catalogue ouvert. Vous les configurez dans opencode.json avec une chaîne provider/model-id et pouvez désactiver les fournisseurs que vous ne voulez pas charger — le même workflow de design s’exécute ainsi sur Anthropic, OpenAI, Google, OpenRouter, des modèles locaux et plus encore."}, {"label": "Fichier d’instructions", "body": "OpenCode lit un fichier AGENTS.md dans votre projet (le standard inter-outils, également compatible avec CLAUDE.md) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design. Exécutez /init pour en générer un."}, {"label": "Extensible", "body": "Il prend en charge l’intégration LSP, les serveurs MCP, les thèmes, les raccourcis clavier et les commandes personnalisées, ainsi que des liens de session partageables pour la collaboration."}]}, {"kind": "ul", "items": ["Mainteneur : SST / Anomaly Innovations (projet open source)", "Identifiant : votre/vos propre(s) clé(s) API de fournisseur de modèle — BYOK, sans verrouillage par l’éditeur", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent ouvert et tout-modèle convient au travail de design", "blocks": [{"kind": "p", "text": "OpenCode n’a pas un unique « modèle de design » comme en a un agent d’éditeur — et c’est tout l’intérêt. Parce qu’il est agnostique au modèle et ouvert, vous pouvez exécuter le même workflow de design sur le modèle actuellement le meilleur en frontend, en changer plus tard, ou vous rabattre sur un modèle local, le tout sans modifier votre configuration."}, {"kind": "p", "text": "Mais le choix du modèle seul n’achète pas le goût. Comme tout agent de code, OpenCode produit une UI générique tant que vous ne lui donnez pas de contraintes. Une bonne sortie de design provient de trois entrées que vous fournissez."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "De vrais tokens, primitives et conventions que l’agent réutilise, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Une skill esthétique", "body": "Une skill organisée qui impose un vrai goût — mouvement sobre, hiérarchie qui met la marque d’abord, deux familles typographiques et une couleur d’accent au maximum — et amène l’agent à s’engager sur une direction avant de construire."}, {"label": "Des références concrètes", "body": "De vraies images de référence et plusieurs états (desktop et mobile, survol, vide, chargement), pas un unique visuel héros."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence — indépendamment du modèle que vous exécutez."}, {"kind": "p", "text": "La leçon : OpenCode vous donne la liberté du modèle, mais le goût vient toujours d’un contexte de design organisé. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent — tous deux sont open source et local-first (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer OpenCode pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un OpenCode capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier avec votre clé de fournisseur, configurer AGENTS.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier (votre clé de fournisseur) → configurer AGENTS.md → ajouter une skill → vérifier dans un vrai navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md (ou un DESIGN.md référencé depuis lui) pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique. L’option instructions dans opencode.json peut pointer vers des fichiers de règles supplémentaires via des globs."}, {"label": "Choisissez un modèle capable", "body": "Parce qu’OpenCode est agnostique au modèle, choisissez le fournisseur/modèle actuellement le plus fort en frontend pour la passe de design — et gardez le reste de votre workflow inchangé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec n’importe quel agent consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. La même structure en cinq étapes s’applique dans OpenCode."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à OpenCode où se trouvent les tokens et les primitives canoniques (dans AGENTS.md).", "Faites tourner un serveur de dev et faites rendre l’agent dans un vrai navigateur, en redimensionnant aux breakpoints pour contrôler le résultat.", "Itérez en faisant comparer à OpenCode son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Référencez des fichiers avec @ dans le TUI pour une recherche floue de votre répertoire de travail, exécutez des commandes shell en ligne avec un ! en tête, et déclenchez des actions avec les commandes /. Puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, committez les bonnes itérations et annulez les mauvaises (en prévenant OpenCode quand vous revenez en arrière), pour que chaque passe parte d’une base propre."}]}, {"id": "extend", "heading": "AGENTS.md, MCP et sessions partageables", "blocks": [{"kind": "p", "text": "Trois points d’extension rendent OpenCode pratique pour un travail de design durable, et tous trois se projettent proprement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Règles AGENTS.md", "body": "Les règles de projet vivent dans un AGENTS.md à la racine du dépôt (ou des règles globales dans ~/.config/opencode/AGENTS.md). C’est le foyer durable de vos conventions de design, lu à chaque exécution, et il est compatible avec les fichiers CLAUDE.md qu’utilisent d’autres agents."}, {"label": "Serveurs MCP", "body": "OpenCode prend en charge à la fois les serveurs MCP locaux (command) et distants (URL), configurés sous la clé mcp — la façon portable d’apporter du contexte de design et des outils externes qui fonctionnent à travers les agents, pas seulement OpenCode."}, {"label": "Sessions partageables", "body": "La commande /share crée un lien public vers une conversation pour la collaboration ou la revue, et /unshare le révoque — utile pour obtenir des retours sur une passe de design."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agent — exactement le genre de chose qu’Open Design est conçu pour orchestrer, plutôt que de recréer projet par projet."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["OpenCode", "Open source et agnostique au modèle ; exécutez n’importe quel fournisseur derrière un seul workflow en terminal", "La liberté BYOK, le changement de modèle, les configurations entièrement ouvertes et local-first"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images", "L’async délégué, les builds en sandbox, les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle, ce qui est précisément pourquoi un agent ouvert comme OpenCode s’accorde si bien avec une couche de design ouverte."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI. Aucun de ces problèmes n’est propre à OpenCode ; c’est ce qui arrive quand un agent, quel qu’il soit, s’exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill esthétique", "body": "Une skill de design organisée force l’agent à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Rendez et auto-contrôlez sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé — quel que soit le modèle que vous exécutez. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec OpenCode dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite OpenCode comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend tout agent bon soit présent dès la première exécution, et non assemblé à la main à chaque fois. Les deux projets sont open source et local-first, ce qui rend l’appariement naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez OpenCode comme agent.", "Authentifiez-vous avec votre propre clé API de fournisseur de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez n’importe quel fournisseur et modèle, plus un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent OpenCode, la même liberté de modèle — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenCode peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill esthétique, un design system et de vraies images de référence dans le contexte, OpenCode produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Parce qu’il est agnostique au modèle, vous exécutez celui qui est actuellement le meilleur en frontend. Sans ce contexte organisé, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Quel modèle utiliser avec OpenCode pour le design ?", "text": "Celui que vous voulez — OpenCode est agnostique au fournisseur via models.dev, vous pouvez donc exécuter Anthropic, OpenAI, Google, OpenRouter ou des modèles locaux derrière le même workflow et en changer à tout moment. La qualité de la sortie de design dépend bien plus de votre skill, de votre design system et de vos références que du modèle seul."}, {"name": "Open Design est-il fait par l’équipe OpenCode (SST) ?", "text": "Non. Open Design est un projet open source indépendant qui intègre OpenCode comme agent. Il complète OpenCode avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement spécial pour concevoir avec OpenCode ?", "text": "Non — OpenCode est BYOK. Vous apportez votre propre clé API de fournisseur de modèle, et Open Design ne fait jamais transiter vos identifiants. Il n’y a pas de verrouillage par l’éditeur."}, {"name": "OpenCode, Codex ou Claude Code pour le design frontend ?", "text": "Tous sont solides, et beaucoup d’équipes les combinent. L’avantage d’OpenCode est d’être entièrement open source et agnostique au modèle ; Codex excelle dans les builds délégués en sandbox ; Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code. Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment étendre OpenCode pour le contexte de design ?", "text": "Encodez les règles dans AGENTS.md, ajoutez des serveurs MCP sous la clé mcp pour des outils portables et du contexte de design, et utilisez les sessions partageables pour la revue. Open Design fournit une bibliothèque organisée de skills et de design systems pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenCode ou SST ?", "text": "Non. OpenCode est un projet open source maintenu par SST (Anomaly Innovations) ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec OpenCode, à la manière ouverte.", "ctaBody": "Apportez votre propre clé de fournisseur de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent ouvert que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
    },
    'ru': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code для дизайна — Open Design",
        description: "Как дизайнеры используют Claude Code для UI и веб-дизайна и как Open Design превращает его в полноценного дизайн-агента — local-first, BYOK, с курируемой библиотекой skill и дизайн-систем.",
        breadcrumb: "Claude Code",
        label: "Агент · Claude Code",
        heading: "Claude Code для дизайна.",
        lead: "Claude Code — это терминальный кодинг-агент от Anthropic. Им уже создают интерфейсы, дизайн-системы и лендинги. Open Design встраивает его в настоящий дизайн-процесс — используйте свой ключ Anthropic или подписку Claude и держите каждый файл локально.",
        rich: {"heroCtaLead": "Open Design превращает Claude Code в local-first, open-source дизайн-агента — ваш ключ Anthropic или подписка Claude, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code широко считается кодинг-агентом с лучшим вкусом во фронтенде — он рассуждает об интерфейсах с необычной точностью, называя конкретные значения hex, отступы и типографические шкалы, и рефакторит UI по большой кодовой базе, не теряя нить. Но «из коробки» он всё равно тяготеет к шаблонному виду, пока вы не дадите ему дизайн-систему, skills и реальные референсы. Это практичное, сквозное руководство по использованию Claude Code для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный процесс с Open Design.", "Оно охватывает то, чем на самом деле является Claude Code, почему он силён во фронтенде, как настроить его с нуля, рабочий процесс с CLAUDE.md и Skills, официальный round-trip с Figma, как он сравнивается с Codex и Cursor, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Цикл обратной связи дизайна Claude Code: терминальный агент принимает конкретные дизайн-решения, браузер отрисовывает UI, рабочее пространство и стрелка обратной связи, замыкающая цикл", "caption": "Ключевой цикл: Claude Code обдумывает конкретные UI-решения в терминале, отрисовывает и проверяет их в настоящем браузере и сходится к вашим референсам."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-claude-code", "label": "Чем на самом деле является Claude Code"}, {"id": "why-design", "label": "Почему Claude Code хорош в дизайне"}, {"id": "setup", "label": "Настройка Claude Code для дизайна (с нуля)"}, {"id": "skills-workflow", "label": "Рабочий процесс с CLAUDE.md и Skills"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code против Codex против Cursor"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Claude Code в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Чем на самом деле является Claude Code", "blocks": [{"kind": "p", "text": "Claude Code — это агентный инструмент для кодинга от Anthropic. Он читает вашу кодовую базу, редактирует файлы, выполняет команды и интегрируется с вашими инструментами разработки — планируя, создавая и проверяя работу по задачам на естественном языке, а не просто дополняя строки."}, {"kind": "p", "text": "Он поставляется в нескольких форматах, которые используют один и тот же движок: терминальный CLI, расширения IDE для VS Code, Cursor и JetBrains, десктопное приложение с визуальным просмотром диффов и веб-версия для долгих задач. Ваши файлы CLAUDE.md, настройки и серверы MCP переносятся между всеми ними."}, {"kind": "steps", "items": [{"label": "Файл инструкций", "body": "Claude Code читает файл CLAUDE.md в корне проекта в начале каждой сессии — естественное место, где можно зафиксировать ваши дизайн-конвенции, tokens и чек-листы ревью."}, {"label": "Skills", "body": "Agent Skills упаковывают повторяемые инструкции, скрипты и ресурсы, которые Claude подгружает по требованию, включая официальный Frontend Design skill от Anthropic для вкуса."}, {"label": "Планирование и субагенты", "body": "Он может планировать перед действием и порождать субагентов, которые работают над разными частями задачи параллельно, что сохраняет целостность крупных UI-рефакторингов."}]}, {"kind": "ul", "items": ["Поставщик: Anthropic", "Учётные данные: API-ключ Anthropic (BYOK, через Console) или подписка Claude (Pro / Max)", "Форматы: терминальный CLI, расширения VS Code / Cursor / JetBrains, десктопное приложение, веб"]}]}, {"id": "why-design", "heading": "Почему Claude Code хорош в дизайне", "blocks": [{"kind": "p", "text": "Среди кодинг-агентов Claude Code заслужил репутацию обладателя вкуса в работе над фронтендом. Это объясняется несколькими причинами."}, {"kind": "steps", "items": [{"label": "Конкретные, а не расплывчатые решения", "body": "Claude Code склонен принимать конкретные решения — точные значения hex, шкалы отступов, типографические шкалы и иерархию компонентов — вместо общих фраз, и именно это отличает настоящий интерфейс от заглушки."}, {"label": "Рассуждение с учётом кодовой базы", "body": "Имея большой рабочий контекст, он рефакторит UI сразу по множеству файлов, переиспользуя ваши существующие компоненты и tokens, а не изобретая разовые стили."}, {"label": "Официальный frontend skill", "body": "Anthropic поставляет Frontend Design skill, который заставляет Claude сначала задавать дизайн-направление и осознанно уходит от шаблонных системных шрифтов и предсказуемых фиолетовых градиентов."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок тот же, что Anthropic делает о своих моделях: у Claude по умолчанию нет вкуса — предоставленный сам себе, он сходится к статистическому центру веб-дизайна (Inter, фиолетовые градиенты, мягкие тени). Он создаёт хороший дизайн, когда вы даёте ему ограничения. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Claude Code для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Claude Code, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка CLAUDE.md, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка CLAUDE.md → добавление Frontend Design skill → включение проверки в браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в CLAUDE.md и направьте Claude к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Добавьте проверку в браузере", "body": "Подключите Playwright или Chrome MCP, чтобы Claude отрисовывал результат в настоящем браузере и проверял его на разных брейкпоинтах, а не просто подтверждал успешную сборку."}]}]}, {"id": "skills-workflow", "heading": "Рабочий процесс с CLAUDE.md и Skills", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Claude Code — это давать ему реальные референсы вместе с вашим дизайн-контекстом, а затем итерировать, пока UI не совпадёт, при этом CLAUDE.md и Skills удерживают ограничения, чтобы не объяснять их заново в каждом промпте."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI даже с сильным агентом.", "Держите дизайн-систему и конвенции в CLAUDE.md и подсказывайте Claude, где лежат tokens и канонические примитивы.", "Добавьте Frontend Design skill, чтобы Claude задал реальное эстетическое направление до написания кода.", "Подключите проверку в браузере, чтобы Claude отрисовывал, менял размер до брейкпоинтов и сравнивал с референсами, а не просто подтверждал сборку."]}, {"kind": "p", "text": "Добавьте референсное изображение в сессию и задайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Запускайте рядом dev-сервер, держите промпты короткими и сфокусированными и коммитьте удачные итерации / откатывайте неудачные (сообщая Claude об откате), чтобы каждый проход строился на чистой основе. Используйте режим планирования для крупных рефакторингов, чтобы пересмотреть подход до любых изменений в файлах."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip дизайн ↔ код", "blocks": [{"kind": "p", "text": "В феврале 2026 года Anthropic и Figma выпустили первоклассную двунаправленную интеграцию через сервер Figma MCP. Она работает в обе стороны."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Выберите фрейм в Figma или вставьте ссылку в Claude Code, подтяните дизайн-контекст и попросите реализовать дизайн с использованием вашей существующей библиотеки компонентов. Code Connect удерживает вывод в соответствии с вашими реальными компонентами."}, {"label": "Код → Дизайн", "body": "Соберите и предпросмотрите фичу в браузере, затем скажите «Send this to Figma», чтобы зафиксировать работающий UI как редактируемые слои Figma — весь экран или выбранный элемент."}]}, {"kind": "p", "text": "Установите её один раз командой claude plugin install figma@claude-plugins-official (Dev Mode MCP требует платного плана Figma). Тот же Figma MCP доступен Claude Code, Codex, Cursor и VS Code — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Claude Code против Codex против Cursor для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX-рассуждение с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"], ["Codex", "Сильная визуальная отточенность и понимание изображений; асинхронные сборки в песочнице", "Делегированные асинхронные сборки и переносимые правила AGENTS.md"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Даже при репутации Claude Code как обладателя вкуса самая частая жалоба на дизайн, сгенерированный ИИ, в том, что он выглядит шаблонно — шрифты Inter, фиолетовые градиенты на белом, мягкие тени, чрезмерно скруглённые углы, эстетика, которая «кричит, что это сделал ИИ». Сама Anthropic объясняет это сходимостью распределения: безопасные решения доминируют в обучающих данных веба. Среди других сообщаемых проблем — сломанные мобильные раскладки и инструкции, протекающие в текст UI."}, {"kind": "steps", "items": [{"label": "Установите Frontend Design skill", "body": "Он заставляет Claude задать реальное направление и явно избегает шрифтов и градиентов, чрезмерно используемых ИИ."}, {"label": "Включите проверку в браузере", "body": "Заставьте Claude отрисовывать и самопроверять результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в CLAUDE.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Claude Code внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Claude Code как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Claude Code хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Claude Code как своего агента.", "Аутентифицируйтесь с помощью API-ключа Anthropic (BYOK) или подписки Claude — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Claude Code, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Хорош ли Claude Code для дизайн-работы?", "text": "Да — он широко считается кодинг-агентом с лучшим вкусом во фронтенде, принимая конкретные, учитывающие кодовую базу решения о значениях hex, отступах и типографических шкалах. С Frontend Design skill, дизайн-системой и реальными референсными изображениями в контексте он создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Нужна ли подписка Claude, чтобы заниматься дизайном с Claude Code?", "text": "Вы можете использовать либо API-ключ Anthropic (BYOK, через Console), либо подписку Claude (Pro / Max). В любом случае Open Design никогда не проксирует ваши учётные данные — они используются напрямую вашим агентом на вашей машине."}, {"name": "Claude Code или Codex для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями и фронтенд-рассуждениями; Codex обладает сильной визуальной отточенностью и блистает в делегированных сборках в песочнице. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Claude Code к Figma?", "text": "Установите официальный плагин Figma командой claude plugin install figma@claude-plugins-official. После этого вы можете реализовывать фреймы Figma в коде, используя дизайн-контекст, и отправлять работающий UI обратно в редактируемые фреймы Figma через «Send this to Figma». Dev Mode MCP требует платного плана Figma."}, {"name": "Что такое Skills и CLAUDE.md?", "text": "CLAUDE.md — это markdown-файл в корне проекта, который Claude Code читает в начале каждой сессии — место для фиксации ваших дизайн-конвенций. Skills упаковывают повторяемые инструкции и ресурсы, которые Claude подгружает по требованию, включая официальный Frontend Design skill от Anthropic. Open Design поставляет курируемую библиотеку и того, и другого, так что вы пропускаете настройку под каждый проект."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Установите Frontend Design skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в CLAUDE.md и включите проверку в браузере. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с Anthropic?", "text": "Нет. Claude Code — продукт Anthropic; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. Claude и Claude Code являются товарными знаками Anthropic."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first и под Apache-2.0. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные Anthropic используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Claude Code, по-открытому.", "ctaBody": "Используйте свой ключ Anthropic или подписку Claude, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex для дизайна — Open Design",
        description: "Как люди используют OpenAI Codex для UI и веб-дизайна — плагин Product Design, интеграция с Figma, фронтенд-skills — и как Open Design превращает Codex в local-first, open-source дизайн-агента.",
        breadcrumb: "Codex",
        label: "Агент · Codex",
        heading: "Codex для дизайна.",
        lead: "Codex — это кодинг-агент от OpenAI. С плагином Product Design и интеграцией Figma он стал серьёзным дизайн-инструментом. Open Design встраивает Codex в open-source дизайн-процесс — ваш ключ OpenAI или подписка ChatGPT, ваши файлы, local-first.",
        rich: {"heroCtaLead": "Open Design превращает Codex в local-first, open-source дизайн-агента — ваш ключ OpenAI, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex начинался как генератор кода, но в 2026 году стал достойным инструментом для проектирования настоящих интерфейсов — стоит дать ему правильные референсы, skills и цикл проверки. Это практичное, сквозное руководство по использованию Codex для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем Codex является сегодня, почему он внезапно хорош во фронтенде, как настроить его с нуля, цикл «скриншот в UI», официальный round-trip с Figma, как он сравнивается с Cursor и Claude Code, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Цикл обратной связи дизайна Codex: терминальный агент, браузер отрисовывает UI и рабочее пространство со стрелкой обратной связи, замыкающей цикл", "caption": "Ключевой цикл: Codex собирает UI в терминале, отрисовывает и проверяет его в настоящем браузере и итерирует по вашим референсам."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-codex", "label": "Чем на самом деле является OpenAI Codex"}, {"id": "why-design", "label": "Почему Codex теперь хорош в дизайне"}, {"id": "setup", "label": "Настройка Codex для дизайна (с нуля)"}, {"id": "screenshot-workflow", "label": "Рабочий процесс «скриншот в UI»"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex против Cursor против Claude Code"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Codex в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Чем на самом деле является OpenAI Codex (и чем он не является)", "blocks": [{"kind": "p", "text": "Сначала уточнение, которое сбивает с толку почти всех, кто ищет «Codex». Изначальный OpenAI Codex был моделью автодополнения кода 2021 года, питавшей ранний GitHub Copilot и устаревшей в 2023 году. Эта страница не о нём. Сегодняшний Codex — это агентный инструмент для кодинга от OpenAI: он планирует, пишет, запускает и проверяет код по задачам на естественном языке."}, {"kind": "p", "text": "Современный Codex поставляется в четырёх форматах: терминальный CLI (переписанный на Rust, под лицензией Apache-2.0), расширение IDE для VS Code, Cursor и Windsurf, облачно-веб-версия для делегированных асинхронных задач и десптопное приложение со встроенным браузером и Computer Use."}, {"kind": "steps", "items": [{"label": "Модель по умолчанию", "body": "По состоянию на середину 2026 года рекомендуемая модель — gpt-5.5, при этом gpt-5.4 — это модель, которую OpenAI явно обучала для фронтенда и computer use."}, {"label": "Файл инструкций", "body": "Codex читает файл AGENTS.md в вашем проекте (кросс-инструментальный стандарт) для правил проекта — естественное место, где можно зафиксировать ваши дизайн-конвенции."}, {"label": "Песочница", "body": "Он работает в песочнице на уровне ядра (по умолчанию workspace-write), так что агент, редактирующий ваш UI, не может выйти за пределы проекта."}]}, {"kind": "ul", "items": ["Поставщик: OpenAI", "Учётные данные: API-ключ OpenAI (BYOK) или подписка ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Лицензия CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Почему Codex теперь хорош в дизайне", "blocks": [{"kind": "p", "text": "В начале 2026 года сошлись три вещи, превратившие Codex в настоящий дизайн-инструмент, а не в общий генератор кода."}, {"kind": "steps", "items": [{"label": "Модель, обученная для фронтенда", "body": "OpenAI выпустила GPT-5.4 — свою первую основную модель, обученную для фронтенда и computer use, с гораздо лучшим пониманием изображений во всём дизайн-процессе и более сильной самопроверкой. Она даже умеет генерировать mood-board'ы и визуальные варианты до фиксации финальных ассетов."}, {"label": "Официальный frontend skill", "body": "Каталог openai/skills поставляет курируемый frontend-skill, который навязывает реальный вкус: раскладки без карточек, full-bleed герои, иерархия от бренда, сдержанная анимация, не более двух шрифтов и одного акцентного цвета — и заставляет Codex сформулировать визуальный тезис до сборки."}, {"label": "Проверка в браузере", "body": "С Playwright skill Codex открывает настоящий браузер, меняет размер до брейкпоинтов и сравнивает свой вывод с референсом, а не просто проверяет, что сборка прошла."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок, стоящий за всеми тремя: у Codex по умолчанию нет вкуса. Он создаёт хороший дизайн, когда вы даёте ему ограничения — дизайн-систему, эстетический skill и конкретные референсы. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Codex для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Codex, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка, установка skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка AGENTS.md → установка frontend skill → включение проверки в браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в AGENTS.md или DESIGN.md и направьте Codex к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Выберите правильный уровень рассуждения", "body": "OpenAI отмечает, что низкий-средний уровни рассуждения часто дают более сильные фронтенд-результаты, чем максимальная настройка."}]}]}, {"id": "screenshot-workflow", "heading": "Рабочий процесс «скриншот в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Codex — это превращение референсного изображения в работающий, адаптивный UI и итерация до совпадения. Собственное руководство OpenAI сводится к пяти шагам."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите Codex, где лежат tokens и канонические примитивы.", "Включите интерактивный Playwright skill, чтобы Codex отрисовывал результат в настоящем браузере и менял размер до брейкпоинтов.", "Итерируйте, заставляя Codex сравнивать свою реализацию со скриншотами, а не просто подтверждать сборку."]}, {"kind": "p", "text": "Передавайте изображения, перетаскивая скриншот в терминал или с помощью флага изображения, затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер во втором терминале, держите промпты короткими и сфокусированными и коммитьте удачные итерации / откатывайте неудачные (сообщая Codex об откате), чтобы каждый проход строился на чистой основе."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip дизайн ↔ код", "blocks": [{"kind": "p", "text": "В феврале 2026 года OpenAI и Figma объявили об официальном партнёрстве, превратив более раннюю бету Figma MCP в первоклассную двунаправленную интеграцию. Она работает в обе стороны."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопируйте «link to selection» фрейма в Figma, вставьте его в Codex вместе с get_design_context и попросите реализовать дизайн с использованием вашей существующей библиотеки компонентов."}, {"label": "Код → Дизайн", "body": "Инструмент generate_figma_design («Code to Canvas») превращает живой, работающий UI обратно в редактируемые фреймы Figma — весь экран, выбранный элемент или целый файл."}]}, {"kind": "p", "text": "Figma MCP работает как удалённый сервер и не подпадает под лимиты запросов. Добавьте его один раз — и он доступен Codex, Claude Code, Cursor, VS Code и другим — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Codex против Cursor против Claude Code для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Codex", "Сильная визуальная отточенность после GPT-5.4 + frontend-skill; понимание изображений", "Делегированные асинхронные сборки, запуски в песочнице, переносимые правила AGENTS.md"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный Codex, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — сломанные мобильные раскладки, инструкции, протекающие в текст UI, и быстрое достижение лимитов использования."}, {"kind": "steps", "items": [{"label": "Установите frontend skill", "body": "Курируемый эстетический skill заставляет Codex задать реальное направление вместо вида по умолчанию."}, {"label": "Включите проверку Playwright", "body": "Заставьте Codex отрисовывать и самопроверять результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в AGENTS.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Codex внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Codex как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Codex хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Codex как своего агента.", "Аутентифицируйтесь с помощью API-ключа OpenAI (BYOK) или подписки ChatGPT — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Codex, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли OpenAI Codex способен на дизайн-работу?", "text": "Да — с frontend skill, дизайн-системой и реальными референсными изображениями в контексте Codex (особенно на GPT-5.4) создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Это плагин OpenAI Codex Product Design?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует Codex как агента. Он дополняет собственный инструментарий OpenAI local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли подписка ChatGPT, чтобы заниматься дизайном с Codex?", "text": "Вы можете использовать либо API-ключ OpenAI (BYOK), либо вашу подписку ChatGPT. Вход через ChatGPT обычно даёт более щедрые лимиты; в любом случае Open Design никогда не проксирует ваши учётные данные."}, {"name": "Codex или Claude Code для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями; Codex обладает сильной визуальной отточенностью после GPT-5.4 и блистает в делегированных сборках в песочнице. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Codex к Figma?", "text": "Добавьте официальный сервер Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). После этого вы можете реализовывать фреймы Figma в коде с помощью get_design_context и отправлять работающий UI обратно в редактируемые фреймы Figma через generate_figma_design."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Установите frontend skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в AGENTS.md и включите проверку Playwright. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с OpenAI?", "text": "Нет. Codex — продукт OpenAI; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. OpenAI и Codex являются товарными знаками OpenAI."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные OpenAI используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Codex, по-открытому.", "ctaBody": "Используйте свой ключ OpenAI, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor для дизайнеров — Open Design",
        description: "Как дизайнеры используют Cursor для UI и веб-дизайна — Design Mode, Figma-в-код, Figma MCP — и как Open Design превращает Cursor в local-first, open-source дизайн-агента.",
        breadcrumb: "Cursor",
        label: "Агент · Cursor",
        heading: "Cursor для дизайнеров.",
        lead: "Cursor — это редактор кода с ИИ, теперь с визуальным Design Mode. Дизайнеры используют его, чтобы редактировать UI наведением и рисованием и превращать Figma в код. Open Design встраивает Cursor Agent в open-source дизайн-процесс, который держит ваши файлы локально.",
        rich: {"heroCtaLead": "Open Design превращает Cursor в local-first, open-source дизайн-агента — ваш аккаунт Cursor или ключи моделей, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor — это AI-first редактор кода, сделавший «собери и смотри, как отрисовывается» способом по умолчанию для выпуска UI. С режимом Agent, инлайн-правками, предпросмотром в редакторе и Figma поверх MCP он стал настоящим дизайн-инструментом — стоит дать ему правильные референсы, правила и цикл проверки. Это практичное, сквозное руководство по использованию Cursor для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем на самом деле является Cursor, почему его тесный цикл «итерируй и наблюдай» хорош для дизайна, как настроить его с нуля, цикл «скриншот-и-предпросмотр в UI», round-trip с Figma поверх MCP, как он сравнивается с Codex и Claude Code, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Сходимость дизайна Cursor: редактор слева, курируемый хаб skill и дизайн-систем по центру со знаком Cursor в середине и отрисованный UI справа", "caption": "Ключевая идея: Cursor редактирует и отрисовывает UI в редакторе, а курируемый дизайн-хаб подаёт ему систему, skills и референсы, благодаря которым вывод выглядит осознанным."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-cursor", "label": "Чем на самом деле является Cursor"}, {"id": "why-design", "label": "Почему Cursor хорош в дизайне"}, {"id": "setup", "label": "Настройка Cursor для дизайна (с нуля)"}, {"id": "preview-workflow", "label": "Рабочий процесс «предпросмотр в UI»"}, {"id": "figma", "label": "Cursor + Figma поверх MCP"}, {"id": "vs", "label": "Cursor против Codex против Claude Code"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Cursor в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Чем на самом деле является Cursor", "blocks": [{"kind": "p", "text": "Cursor — это AI-first редактор кода, созданный Anysphere. Это форк VS Code, поэтому он сохраняет привычный редактор, расширения и горячие клавиши, но перестраивает рабочий процесс вокруг ИИ-агента, который умеет читать весь ваш проект, редактировать множество файлов, выполнять команды и итерировать вместе с вами в цикле."}, {"kind": "p", "text": "Для дизайн-работы важны режим Agent (вы описываете результат, а Cursor планирует и редактирует по файлам), инлайн-правки и дополнения Tab для быстрых правок, предпросмотр / браузер прямо в редакторе, чтобы видеть работающий UI, не покидая окно, и поддержка MCP, позволяющая подтягивать внешний контекст, например живой файл Figma."}, {"kind": "steps", "items": [{"label": "Правила проекта", "body": "Cursor читает файлы инструкций проекта — версионируемые правила `.mdc` в `.cursor/rules` и обычный `AGENTS.md` — так что вы можете зафиксировать дизайн-конвенции там, где агент читает их при каждом запуске."}, {"label": "Модели", "body": "Cursor гибок по моделям: он поставляется с передовыми моделями через вашу подписку, а также поддерживает использование собственных ключей моделей, так что вы выбираете движок за тем же рабочим процессом редактора."}, {"label": "MCP", "body": "Он говорит на Model Context Protocol, так что внешние серверы — в первую очередь сервер Figma MCP — становятся первоклассным контекстом для агента."}]}, {"kind": "ul", "items": ["Поставщик: Anysphere", "Учётные данные: аккаунт / подписка Cursor (Hobby / Pro / Business) или ваши собственные ключи моделей (BYOK)", "Форма: AI-first редактор кода (форк VS Code) со встроенным агентом и предпросмотром"]}]}, {"id": "why-design", "heading": "Почему Cursor хорош в дизайне", "blocks": [{"kind": "p", "text": "Преимущество Cursor в дизайне — не отдельная фича, а теснота цикла «собери и посмотри». Три вещи делают его похожим на дизайн-инструмент, а не на общий генератор кода."}, {"kind": "steps", "items": [{"label": "Тесный цикл «итерируй и наблюдай»", "body": "Вы задаёте промпт, Cursor редактирует по файлам, а предпросмотр в редакторе отрисовывает результат немедленно — так вы правите отступы, иерархию и анимацию за секунды, вместо того чтобы ходить туда-сюда через отдельный терминал и браузер."}, {"label": "Прямое визуальное редактирование", "body": "Помимо чата, Cursor позволяет выбирать элементы в предпросмотре и подкручивать стили, так что мелкие визуальные правки ощущаются как дизайн-правки, а не как археология кода."}, {"label": "Правила проекта и контекст MCP", "body": "С `.cursor/rules` (или `AGENTS.md`) и сервером Figma MCP агент работает с вашими tokens, компонентами и реальными дизайн-спецификациями, а не угадывает."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок тот же, что преподаёт каждый агент: у Cursor по умолчанию нет вкуса. Он создаёт хороший дизайн, когда вы даёте ему ограничения — дизайн-систему, эстетический skill и конкретные референсы. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Cursor для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Cursor, способного собирать, предпросматривать и проверять UI на соответствие вашей дизайн-системе."}, {"kind": "ol", "items": ["Установите Cursor с cursor.com и войдите со своим аккаунтом Cursor либо настройте собственные ключи моделей (BYOK) в Settings.", "Откройте свой проект и выберите модель на панели чата / Agent.", "Добавьте правила проекта: создайте `.cursor/rules/*.mdc` для структурированных конвенций с областью по glob либо обычный `AGENTS.md` для простых, читаемых инструкций.", "Подключите сервер Figma MCP (опционально), чтобы агент мог читать живой дизайн-контекст.", "Запустите dev-сервер и используйте предпросмотр в редакторе, чтобы видеть и проверять UI по мере итерации."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка правил, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка правил проекта → добавление skill → включение проверки в предпросмотре."}, {"kind": "p", "text": "Минимальный файл правил проекта заставляет агента проектировать под бренд, а не сваливаться в шаблонный вид. Поместите его туда, где Cursor читает его при каждом запуске:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в `.cursor/rules` или `AGENTS.md` и направьте Cursor к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Держите промпты короткими", "body": "Тесный цикл Cursor вознаграждает сфокусированные запросы — итерируйте по одному компоненту или состоянию за раз и смотрите на предпросмотр между проходами."}]}]}, {"id": "preview-workflow", "heading": "Рабочий процесс «предпросмотр в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Cursor — это превращение референса в работающий, адаптивный UI и итерация в редакторе до совпадения, наблюдая живой предпросмотр всё время, а не угадывая."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите Cursor, где лежат tokens и канонические примитивы.", "Держите предпросмотр в редакторе открытым, а dev-сервер запущенным, чтобы каждая правка отрисовывалась немедленно на нужных вам брейкпоинтах.", "Итерируйте, сравнивая отрисованный UI с референсами, — и используйте прямой выбор элементов в предпросмотре для мелких визуальных правок."]}, {"kind": "p", "text": "Передавайте референсы, прикрепляя изображение к чату, затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Коммитьте удачные итерации и откатывайте неудачные (сообщая Cursor об откате), чтобы каждый проход строился на чистой основе — та же дисциплина, что удерживает любой агентный цикл от дрейфа."}]}, {"id": "figma", "heading": "Cursor + Figma: дизайн ↔ код поверх MCP", "blocks": [{"kind": "p", "text": "Cursor подключается к Figma через официальный сервер Figma MCP, дающий агенту структурированный доступ к живому файлу Figma вместо плоского скриншота. Это убирает угадывание из handoff."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопируйте ссылку фрейма в Figma, вставьте её в Cursor и попросите реализовать дизайн. Сервер MCP раскрывает реальный дизайн-контекст — компоненты, переменные, данные раскладки, tokens — так что сгенерированный код соответствует источнику, а не приближается к нему."}, {"label": "Оставайтесь согласованными", "body": "При согласованном использовании дизайн-tokens, стилей и компонентов в Figma (и Code Connect, где доступен) вывод Cursor остаётся сопоставленным с вашей реальной дизайн-системой, а не переизобретает примитивы."}]}, {"kind": "p", "text": "Настройте удалённый сервер Figma MCP один раз — и он доступен Cursor как первоклассный контекст. Поскольку MCP — открытый стандарт, тот же сервер переиспользуется в Cursor, Claude Code, Codex и VS Code — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Cursor против Codex против Claude Code для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром в редакторе и прямым редактированием элементов", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"], ["Codex", "Сильная визуальная отточенность с frontend skill; понимание изображений и запуски в песочнице", "Делегированные асинхронные сборки и переносимые правила AGENTS.md"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный Cursor, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — раскладки, ломающиеся на мобильном, и инструкции, протекающие в текст UI."}, {"kind": "steps", "items": [{"label": "Добавьте дизайн-skill", "body": "Курируемый эстетический skill заставляет Cursor задать реальное направление вместо вида по умолчанию."}, {"label": "Используйте предпросмотр для проверки", "body": "Отрисовывайте и самопроверяйте результат на разных брейкпоинтах в предпросмотре редактора, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в `.cursor/rules`", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Cursor внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Cursor как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Cursor хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Cursor как своего агента.", "Аутентифицируйтесь с помощью аккаунта Cursor или собственных ключей моделей (BYOK) — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Cursor, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли Cursor способен на дизайн-работу?", "text": "Да — с дизайн-skill, дизайн-системой и реальными референсными изображениями в контексте Cursor создаёт продакшен-качественный, адаптивный UI, а его предпросмотр в редакторе позволяет проверять и дорабатывать его визуально. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Это официальный продукт Cursor?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует Cursor как агента. Он дополняет Cursor local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли подписка Cursor, чтобы заниматься дизайном с Cursor?", "text": "Вы можете использовать аккаунт / подписку Cursor либо собственные ключи моделей (BYOK). В любом случае Open Design никогда не проксирует ваши учётные данные — они используются напрямую вашим агентом."}, {"name": "Cursor или Claude Code для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями; преимущество Cursor — его тесный цикл «собери и посмотри» с живым предпросмотром внутри редактора. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Cursor к Figma?", "text": "Добавьте официальный сервер Figma MCP в Cursor, затем вставьте ссылку на фрейм Figma в чат и попросите Cursor реализовать его. Сервер раскрывает реальные компоненты, переменные и данные раскладки, так что сгенерированный код соответствует исходному дизайну."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Добавьте дизайн-skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в `.cursor/rules` или `AGENTS.md` и проверяйте на разных брейкпоинтах в предпросмотре. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с Cursor или Anysphere?", "text": "Нет. Cursor — продукт Anysphere; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. Cursor и Anysphere являются товарными знаками Anysphere, Inc."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные Cursor или моделей используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Cursor, по-открытому.", "ctaBody": "Используйте свой аккаунт Cursor или ключи моделей, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode для дизайна — Open Design",
        description: "Как люди используют OpenCode для UI и веб-дизайна — файлы design.md, UI/UX skills, Figma MCP — и как Open Design превращает OpenCode в local-first, open-source дизайн-агента.",
        breadcrumb: "OpenCode",
        label: "Агент · OpenCode",
        heading: "OpenCode для дизайна.",
        lead: "OpenCode — это open-source терминальный ИИ-агент для кодинга. Дизайнеры навешивают на него дизайн-skills и файлы DESIGN.md, чтобы генерировать настоящий UI. Open Design делает это структурированным, open-source процессом — используйте свои ключи провайдеров и держите всё локально.",
        rich: {"heroCtaLead": "Open Design превращает OpenCode в local-first, open-source дизайн-агента — любая модель на ваш выбор с вашим собственным ключом провайдера, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode — это open-source, терминальный ИИ-агент для кодинга, намеренно независимый от моделей: вы используете собственный ключ провайдера и запускаете любую модель за тем же рабочим процессом. Эта открытость делает его естественной базой для дизайн-работы — но, как и любой агент, он создаёт хороший UI лишь тогда, когда вы даёте ему правильные референсы, skills и цикл проверки. Это практичное, сквозное руководство по использованию OpenCode для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем на самом деле является OpenCode, почему независимый от моделей открытый агент хорошо подходит для дизайна, как настроить его с нуля, цикл «скриншот в UI», как AGENTS.md и MCP расширяют его, как он сравнивается с Codex, Claude Code и Cursor, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой — естественное сочетание, ведь оба проекта open-source и работают на вашей собственной машине."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Цикл обратной связи дизайна OpenCode: терминальный TUI-агент, браузер отрисовывает UI и рабочее пространство со стрелкой обратной связи, замыкающей цикл", "caption": "Ключевой цикл: OpenCode собирает UI в терминале, отрисовывает и проверяет его в настоящем браузере и итерирует по вашим референсам — на любой модели по вашему выбору."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-opencode", "label": "Чем на самом деле является OpenCode"}, {"id": "why-design", "label": "Почему открытый агент с любой моделью подходит для дизайна"}, {"id": "setup", "label": "Настройка OpenCode для дизайна (с нуля)"}, {"id": "screenshot-workflow", "label": "Рабочий процесс «скриншот в UI»"}, {"id": "extend", "label": "AGENTS.md, MCP и общие сессии"}, {"id": "vs", "label": "OpenCode против Codex против Claude Code против Cursor"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с OpenCode в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Чем на самом деле является OpenCode", "blocks": [{"kind": "p", "text": "OpenCode — это open-source ИИ-агент для кодинга, созданный для терминала и поддерживаемый командой, стоящей за SST (Anomaly Innovations). Он читает ваш репозиторий, выполняет команды, редактирует файлы и общается с большой языковой моделью — но, в отличие от агентов, привязанных к поставщику, он не поставляет собственную модель. Вы направляете его на любого провайдера и любую модель и используете собственный ключ."}, {"kind": "p", "text": "Он работает как терминальный UI (TUI), с десктопным приложением и расширениями IDE поверх того же движка. Под капотом он использует клиент-серверную архитектуру, так что агент, который делает работу, отделён от поверхности, с которой вы им управляете. Два встроенных агента — build и plan — переключаются клавишей Tab."}, {"kind": "steps", "items": [{"label": "Независимость от моделей", "body": "Модели и провайдеры берутся из models.dev — открытого каталога. Вы настраиваете их в opencode.json строкой provider/model-id и можете отключить нежелательных провайдеров — так что тот же дизайн-процесс работает на Anthropic, OpenAI, Google, OpenRouter, локальных моделях и не только."}, {"label": "Файл инструкций", "body": "OpenCode читает файл AGENTS.md в вашем проекте (кросс-инструментальный стандарт, также совместимый с CLAUDE.md) для правил проекта — естественное место, где можно зафиксировать ваши дизайн-конвенции. Запустите /init, чтобы сгенерировать его."}, {"label": "Расширяемость", "body": "Он поддерживает интеграцию LSP, серверы MCP, темы, горячие клавиши и пользовательские команды, плюс ссылки на общие сессии для совместной работы."}]}, {"kind": "ul", "items": ["Сопровождающий: SST / Anomaly Innovations (open-source проект)", "Учётные данные: ваши собственные API-ключи провайдеров моделей — BYOK, без привязки к поставщику", "Лицензия: MIT, open source"]}]}, {"id": "why-design", "heading": "Почему открытый агент с любой моделью подходит для дизайн-работы", "blocks": [{"kind": "p", "text": "У OpenCode нет единой «дизайн-модели», как у агента, привязанного к поставщику, — и в этом весь смысл. Поскольку он независим от моделей и открыт, вы можете запускать тот же дизайн-процесс на той модели, что сейчас лучшая во фронтенде, позже сменить её или откатиться к локальной модели — и всё это без изменения настройки."}, {"kind": "p", "text": "Но один лишь выбор модели не покупает вкус. Как и любой кодинг-агент, OpenCode создаёт шаблонный UI, пока вы не дадите ему ограничения. Хороший дизайн-результат рождается из трёх вводных, которые вы предоставляете."}, {"kind": "steps", "items": [{"label": "Дизайн-система", "body": "Реальные tokens, примитивы и конвенции, которые агент переиспользует, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Эстетический skill", "body": "Курируемый skill, навязывающий реальный вкус — сдержанная анимация, иерархия от бренда, не более двух шрифтов и одного акцентного цвета — и заставляющий агента задать направление до сборки."}, {"label": "Конкретные референсы", "body": "Реальные референсные изображения и несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не один hero-кадр."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений — независимо от того, какую модель вы запускаете."}, {"kind": "p", "text": "Урок: OpenCode даёт вам свободу выбора модели, но вкус по-прежнему рождается из курируемого дизайн-контекста. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются — оба open-source и local-first (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка OpenCode для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до OpenCode, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация с ключом провайдера, настройка AGENTS.md, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация (ваш ключ провайдера) → настройка AGENTS.md → добавление skill → проверка в настоящем браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в AGENTS.md (или DESIGN.md, на который он ссылается), чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид. Опция instructions в opencode.json может указывать на дополнительные файлы правил через globs."}, {"label": "Выберите способную модель", "body": "Поскольку OpenCode независим от моделей, выберите для дизайн-прохода тот provider/model, что сейчас сильнее всего во фронтенде, — и оставьте остальной процесс без изменений."}]}]}, {"id": "screenshot-workflow", "heading": "Рабочий процесс «скриншот в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с любым агентом — это превращение референсного изображения в работающий, адаптивный UI и итерация до совпадения. Та же пятишаговая форма применима в OpenCode."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите OpenCode, где лежат tokens и канонические примитивы (в AGENTS.md).", "Запустите dev-сервер и заставьте агента отрисовывать результат в настоящем браузере, меняя размер до брейкпоинтов, чтобы проверить результат.", "Итерируйте, заставляя OpenCode сравнивать свою реализацию со скриншотами, а не просто подтверждать сборку."]}, {"kind": "p", "text": "Ссылайтесь на файлы через @ в TUI для нечёткого поиска по рабочей директории, выполняйте shell-команды инлайн с ведущим !, и управляйте действиями через команды /. Затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Держите промпты короткими и сфокусированными, коммитьте удачные итерации и откатывайте неудачные (сообщая OpenCode об откате), чтобы каждый проход строился на чистой основе."}]}, {"id": "extend", "heading": "AGENTS.md, MCP и общие сессии", "blocks": [{"kind": "p", "text": "Три точки расширения делают OpenCode практичным для длительной дизайн-работы, и все три аккуратно ложатся на открытый дизайн-процесс."}, {"kind": "steps", "items": [{"label": "Правила AGENTS.md", "body": "Правила проекта живут в AGENTS.md в корне репозитория (или глобальные правила в ~/.config/opencode/AGENTS.md). Это устойчивый дом для ваших дизайн-конвенций, читаемый при каждом запуске, и он совместим с файлами CLAUDE.md, которые используют другие агенты."}, {"label": "Серверы MCP", "body": "OpenCode поддерживает как локальные (command), так и удалённые (URL) серверы MCP, настраиваемые под ключом mcp — переносимый способ подтянуть дизайн-контекст и внешние инструменты, работающие в разных агентах, а не только в OpenCode."}, {"label": "Общие сессии", "body": "Команда /share создаёт публичную ссылку на диалог для совместной работы или ревью, а /unshare отзывает её — полезно для получения обратной связи по дизайн-проходу."}]}, {"kind": "p", "text": "Это переносимые, мультиагентные возможности — именно то, что Open Design создан оркестрировать, а не пересоздавать в каждом проекте."}]}, {"id": "vs", "heading": "OpenCode против Codex против Claude Code против Cursor для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["OpenCode", "Open-source и независимость от моделей; запуск любого провайдера за одним терминальным процессом", "Свобода BYOK, переключение моделей, полностью открытые и local-first сетапы"], ["Codex", "Сильная визуальная отточенность с frontend skill; понимание изображений", "Делегированные асинхронные сборки в песочнице, переносимые правила AGENTS.md"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все они по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели, и именно поэтому открытый агент вроде OpenCode так хорошо сочетается с открытым дизайн-слоем."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный ИИ, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — сломанные мобильные раскладки и инструкции, протекающие в текст UI. Ничто из этого не уникально для OpenCode; это то, что происходит, когда любой агент работает без курируемого дизайн-контекста."}, {"kind": "steps", "items": [{"label": "Добавьте эстетический skill", "body": "Курируемый дизайн-skill заставляет агента задать реальное направление вместо вида по умолчанию."}, {"label": "Проверяйте в настоящем браузере", "body": "Отрисовывайте и самопроверяйте результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в AGENTS.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст — независимо от того, какую модель вы запускаете. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с OpenCode внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает OpenCode как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий любого агента хорошим, есть с первого запуска, а не собирается вручную каждый раз. Оба проекта open-source и local-first, что делает их сочетание естественным."}, {"kind": "ol", "items": ["Установите Open Design и выберите OpenCode как своего агента.", "Аутентифицируйтесь с помощью собственного API-ключа провайдера моделей (BYOK) — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите любого провайдера и модель, плюс дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент OpenCode, та же свобода выбора модели — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли OpenCode способен на дизайн-работу?", "text": "Да — с эстетическим skill, дизайн-системой и реальными референсными изображениями в контексте OpenCode создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Поскольку он независим от моделей, вы запускаете ту модель, что сейчас лучшая во фронтенде. Без такого курируемого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Какую модель использовать с OpenCode для дизайна?", "text": "Любую на ваш вкус — OpenCode независим от провайдера через models.dev, так что вы можете запускать Anthropic, OpenAI, Google, OpenRouter или локальные модели за тем же рабочим процессом и переключаться в любой момент. Качество дизайн-вывода зависит куда больше от вашего skill, дизайн-системы и референсов, чем от одной только модели."}, {"name": "Сделан ли Open Design командой OpenCode (SST)?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует OpenCode как агента. Он дополняет OpenCode local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли специальная подписка, чтобы заниматься дизайном с OpenCode?", "text": "Нет — OpenCode работает по BYOK. Вы используете собственный API-ключ провайдера моделей, и Open Design никогда не проксирует ваши учётные данные. Привязки к поставщику нет."}, {"name": "OpenCode, Codex или Claude Code для фронтенд-дизайна?", "text": "Все сильны, и многие команды комбинируют их. Преимущество OpenCode — полная открытость и независимость от моделей; Codex блистает в делегированных сборках в песочнице; Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями. Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как расширить OpenCode для дизайн-контекста?", "text": "Зафиксируйте правила в AGENTS.md, добавьте серверы MCP под ключом mcp для переносимых инструментов и дизайн-контекста и используйте общие сессии для ревью. Open Design поставляет курируемую библиотеку skill и дизайн-систем, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с OpenCode или SST?", "text": "Нет. OpenCode — open-source проект, поддерживаемый SST (Anomaly Innovations); Open Design — независимый open-source проект, который поддерживает его как нативный адаптер."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные провайдера моделей используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с OpenCode, по-открытому.", "ctaBody": "Используйте свой ключ провайдера моделей, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг открытого агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
    },
    'es': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code para diseño — Open Design",
        description: "Cómo los diseñadores usan Claude Code para diseño de UI y web, y cómo Open Design lo convierte en un verdadero agente de diseño — local-first, BYOK, con una biblioteca curada de skills y sistemas de diseño.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code para diseño.",
        lead: "Claude Code es el agente de codificación de terminal de Anthropic. La gente ya lo usa para construir interfaces, sistemas de diseño y landing pages. Open Design lo conecta a un flujo de trabajo de diseño real — usa tu clave de Anthropic o tu suscripción a Claude y mantén cada archivo en local.",
        rich: {"heroCtaLead": "Open Design convierte Claude Code en un agente de diseño open-source y local-first — tu clave de Anthropic o tu suscripción a Claude, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code es ampliamente considerado el agente de codificación con mejor gusto para el frontend — razona sobre las interfaces con una especificidad inusual, nombrando valores hex exactos, espaciados y escalas tipográficas, y refactoriza la UI a lo largo de una base de código grande sin perder el hilo. Pero, listo para usar, sigue derivando hacia un aspecto genérico a menos que le entregues un sistema de diseño, skills y referencias reales. Esta es una guía práctica y de extremo a extremo para usar Claude Code en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo estructurado con Open Design.", "Cubre qué es realmente Claude Code, por qué es fuerte en frontend, cómo configurarlo desde cero, el flujo de trabajo de CLAUDE.md y Skills, el round-trip oficial con Figma, cómo se compara con Codex y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Claude Code: un agente de terminal tomando decisiones de diseño específicas, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Claude Code razona decisiones de UI específicas en la terminal, las renderiza y verifica en un navegador real, y converge contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-claude-code", "label": "Qué es realmente Claude Code"}, {"id": "why-design", "label": "Por qué Claude Code es bueno en diseño"}, {"id": "setup", "label": "Configura Claude Code para diseño (desde cero)"}, {"id": "skills-workflow", "label": "El flujo de trabajo de CLAUDE.md y Skills"}, {"id": "figma", "label": "Round-trip de Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Claude Code en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-claude-code", "heading": "Qué es realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code es la herramienta de codificación agéntica de Anthropic. Lee tu base de código, edita archivos, ejecuta comandos y se integra con tus herramientas de desarrollo — planifica, escribe y verifica el trabajo a partir de tareas en lenguaje natural, en lugar de limitarse a autocompletar líneas."}, {"kind": "p", "text": "Se distribuye en varias superficies que comparten el mismo motor: una CLI de terminal, extensiones de IDE para VS Code, Cursor y JetBrains, una aplicación de escritorio con revisión visual de diferencias, y una experiencia web para tareas de larga duración. Tus archivos CLAUDE.md, ajustes y servidores MCP se trasladan a todas ellas."}, {"kind": "steps", "items": [{"label": "Archivo de instrucciones", "body": "Claude Code lee un archivo CLAUDE.md en la raíz de tu proyecto al inicio de cada sesión — el lugar natural para codificar tus convenciones de diseño, tokens y listas de verificación de revisión."}, {"label": "Skills", "body": "Las Agent Skills empaquetan instrucciones, scripts y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic para el gusto."}, {"label": "Planificación y subagentes", "body": "Puede planificar antes de actuar y generar subagentes que trabajan en distintas partes de una tarea en paralelo, lo que mantiene coherentes las refactorizaciones grandes de UI."}]}, {"kind": "ul", "items": ["Proveedor: Anthropic", "Credencial: clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max)", "Superficies: CLI de terminal, extensiones de VS Code / Cursor / JetBrains, aplicación de escritorio, web"]}]}, {"id": "why-design", "heading": "Por qué Claude Code es bueno en diseño", "blocks": [{"kind": "p", "text": "Entre los agentes de codificación, Claude Code tiene reputación de buen gusto en el trabajo de frontend. Hay varias razones que lo explican."}, {"kind": "steps", "items": [{"label": "Decisiones específicas, no vagas", "body": "Claude Code tiende a comprometerse con opciones concretas — valores hex exactos, escalas de espaciado, rampas tipográficas y jerarquía de componentes — en lugar de andar con rodeos, que es lo que separa una interfaz real de un marcador de posición."}, {"label": "Razonamiento consciente de la base de código", "body": "Con un contexto de trabajo amplio, refactoriza la UI a través de muchos archivos a la vez, reutilizando tus componentes y tokens existentes en lugar de reinventar estilos puntuales."}, {"label": "Una skill de frontend oficial", "body": "Anthropic ofrece una skill de Frontend Design que hace que Claude escriba primero una dirección de diseño y se aleje deliberadamente de las fuentes de sistema genéricas y los predecibles degradados morados."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que Anthropic plantea sobre sus propios modelos: Claude no tiene gusto por defecto — librado a su suerte, converge hacia el centro estadístico del diseño web (Inter, degradados morados, sombras suaves). Produce buen diseño cuando le das restricciones. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Claude Code para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Claude Code capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar CLAUDE.md, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar CLAUDE.md → añadir la skill de Frontend Design → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en CLAUDE.md y dirige a Claude hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o Chrome para que Claude renderice en un navegador real y compruebe su resultado en distintos breakpoints, en lugar de solo confirmar que la compilación pasa."}]}]}, {"id": "skills-workflow", "heading": "El flujo de trabajo de CLAUDE.md y Skills", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Claude Code es alimentarlo con referencias reales más tu contexto de diseño, y luego iterar hasta que la UI coincida — con CLAUDE.md y Skills llevando las restricciones, para que no las vuelvas a explicar en cada prompt."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica incluso con un agente potente.", "Mantén tu sistema de diseño y tus convenciones en CLAUDE.md, e indícale a Claude dónde viven los tokens y las primitivas canónicas.", "Añade la skill de Frontend Design para que Claude se comprometa con una dirección estética real antes de escribir código.", "Conecta la verificación en el navegador para que Claude renderice, redimensione a los breakpoints y compare con las referencias — no solo confirme que compila."]}, {"kind": "p", "text": "Arrastra una imagen de referencia a la sesión y formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en paralelo, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Claude cuándo reviertes) para que cada pasada parta de una base limpia. Usa el modo de planificación para refactorizaciones más grandes, de modo que puedas revisar el enfoque antes de que se modifique cualquier archivo."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, Anthropic y Figma lanzaron una integración bidireccional de primera clase a través del servidor MCP de Figma. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Selecciona un frame en Figma o pega un enlace en Claude Code, extrae el contexto de diseño y pídele que implemente el diseño usando tu biblioteca de componentes existente. Code Connect mantiene el resultado alineado con tus componentes reales."}, {"label": "Código → Diseño", "body": "Construye y previsualiza una funcionalidad en el navegador, y luego di “Send this to Figma” para capturar la UI en ejecución como capas editables de Figma — pantalla completa o un elemento seleccionado."}]}, {"kind": "p", "text": "Instálalo una vez con claude plugin install figma@claude-plugins-official (el MCP de Dev Mode requiere un plan de pago de Figma). El mismo MCP de Figma está disponible para Claude Code, Codex, Cursor y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y razonamiento de UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Codex", "Fuerte pulido visual y comprensión de imágenes; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "Incluso con la reputación de buen gusto de Claude Code, la queja más común sobre el diseño generado por IA es que parece genérico — fuentes Inter, degradados morados sobre blanco, sombras suaves, esquinas redondeadas excesivas, una estética que “grita que esto lo hizo una IA”. La propia Anthropic lo atribuye a la convergencia distribucional: las opciones seguras dominan los datos de entrenamiento web. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Instala la skill de Frontend Design", "body": "Obliga a Claude a comprometerse con una dirección real y evita explícitamente las fuentes y degradados sobreutilizados por la IA."}, {"label": "Habilita la verificación en el navegador", "body": "Haz que Claude renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en CLAUDE.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Claude Code dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Claude Code como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Claude Code esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Claude Code como tu agente.", "Autentícate con tu clave de API de Anthropic (BYOK) o tu suscripción a Claude — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Claude Code, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Es Claude Code bueno para el trabajo de diseño?", "text": "Sí — es ampliamente considerado el agente de codificación con mejor gusto para el frontend, tomando decisiones específicas y conscientes de la base de código sobre valores hex, espaciado y escalas tipográficas. Con la skill de Frontend Design, un sistema de diseño e imágenes de referencia reales en contexto, produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Necesito una suscripción a Claude para diseñar con Claude Code?", "text": "Puedes usar una clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max). En cualquier caso, Open Design nunca actúa como proxy de tus credenciales — las usa directamente tu agente en tu máquina."}, {"name": "¿Claude Code o Codex para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código y por su razonamiento de frontend; Codex tiene un fuerte pulido visual y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Claude Code con Figma?", "text": "Instala el plugin oficial de Figma con claude plugin install figma@claude-plugins-official. Después podrás implementar frames de Figma en código usando el contexto de diseño, y enviar una UI en ejecución de vuelta a frames editables de Figma con “Send this to Figma”. El MCP de Dev Mode requiere un plan de pago de Figma."}, {"name": "¿Qué son las Skills y CLAUDE.md?", "text": "CLAUDE.md es un archivo markdown en la raíz de tu proyecto que Claude Code lee al inicio de cada sesión — el lugar para codificar tus convenciones de diseño. Las Skills empaquetan instrucciones y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic. Open Design incluye una biblioteca curada de ambos para que te saltes la configuración por proyecto."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala la skill de Frontend Design, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en CLAUDE.md y habilita la verificación en el navegador. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Anthropic?", "text": "No. Claude Code es un producto de Anthropic; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Claude y Claude Code son marcas comerciales de Anthropic."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Anthropic las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Claude Code, a la manera abierta.", "ctaBody": "Usa tu propia clave de Anthropic o tu suscripción a Claude, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex para diseño — Open Design",
        description: "Cómo la gente usa OpenAI Codex para diseño de UI y web — el plugin de Product Design, la integración con Figma, las skills de frontend — y cómo Open Design convierte a Codex en un agente de diseño open-source y local-first.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex para diseño.",
        lead: "Codex es el agente de codificación de OpenAI. Con su plugin de Product Design y su integración con Figma se ha convertido en una herramienta de diseño seria. Open Design conecta a Codex con un flujo de trabajo de diseño open-source — tu clave de OpenAI o tu suscripción a ChatGPT, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Codex en un agente de diseño open-source y local-first — tu clave de OpenAI, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex empezó como un generador de código, pero en 2026 se convirtió en una herramienta creíble para diseñar interfaces reales — una vez que le das las referencias, skills y el bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Codex en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es Codex hoy, por qué de repente es bueno en frontend, cómo configurarlo desde cero, el bucle de captura a UI, el round-trip oficial con Figma, cómo se compara con Cursor y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Bucle de retroalimentación de diseño de Codex: un agente de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Codex construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-codex", "label": "Qué es realmente OpenAI Codex"}, {"id": "why-design", "label": "Por qué Codex es bueno en diseño ahora"}, {"id": "setup", "label": "Configura Codex para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "figma", "label": "Round-trip de Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Codex en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-codex", "heading": "Qué es realmente OpenAI Codex (y qué no es)", "blocks": [{"kind": "p", "text": "Primero, una aclaración que confunde a casi todos los que buscan “Codex”. El Codex original de OpenAI era un modelo de autocompletado de código de 2021 que impulsaba los primeros GitHub Copilot y fue descontinuado en 2023. No es de eso de lo que trata esta página. El Codex de hoy es la herramienta de codificación agéntica de OpenAI — planifica, escribe, ejecuta y verifica código a partir de tareas en lenguaje natural."}, {"kind": "p", "text": "El Codex moderno se distribuye en cuatro superficies: una CLI de terminal (reescrita en Rust, con licencia Apache-2.0), una extensión de IDE para VS Code, Cursor y Windsurf, una experiencia cloud/web para tareas asíncronas delegadas, y una aplicación de escritorio con un navegador integrado y Computer Use."}, {"kind": "steps", "items": [{"label": "Modelo por defecto", "body": "A mediados de 2026, el modelo recomendado es gpt-5.5, siendo gpt-5.4 el modelo que OpenAI entrenó explícitamente para frontend y computer use."}, {"label": "Archivo de instrucciones", "body": "Codex lee un archivo AGENTS.md en tu proyecto (un estándar entre herramientas) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño."}, {"label": "Sandbox", "body": "Se ejecuta en un sandbox a nivel de kernel (workspace-write por defecto), de modo que un agente que edita tu UI no puede salirse del proyecto."}]}, {"kind": "ul", "items": ["Proveedor: OpenAI", "Credencial: clave de API de OpenAI (BYOK) o suscripción a ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencia de la CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Por qué Codex es bueno en diseño ahora", "blocks": [{"kind": "p", "text": "Tres cosas convergieron a principios de 2026 para convertir a Codex en una verdadera herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un modelo entrenado para frontend", "body": "OpenAI lanzó GPT-5.4, su primer modelo principal entrenado para frontend y computer use, con una comprensión de imágenes mucho mejor en todo el flujo de diseño y una autoverificación más sólida. Incluso puede generar mood boards y opciones visuales antes de comprometerse con los assets finales."}, {"label": "Una skill de frontend oficial", "body": "El catálogo openai/skills incluye una skill de frontend curada que impone gusto real: diseños sin tarjetas, heroes a sangre completa, jerarquía centrada en la marca, movimiento contenido, como máximo dos tipografías y un color de acento — y hace que Codex escriba una tesis visual antes de construir."}, {"label": "Verificación en el navegador", "body": "Con la skill de Playwright, Codex abre un navegador real, redimensiona a los breakpoints y compara su resultado con la referencia en lugar de solo comprobar que la compilación pasa."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección detrás de las tres: Codex no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Codex para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Codex capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar, instalar skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar AGENTS.md → instalar la skill de frontend → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md o en un DESIGN.md y dirige a Codex hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Elige el nivel de razonamiento adecuado", "body": "OpenAI señala que los niveles de razonamiento de bajo a medio suelen producir mejores resultados de frontend que el ajuste más alto."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Codex es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La propia guía de OpenAI se reduce a cinco pasos."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Codex dónde viven los tokens y las primitivas canónicas.", "Habilita la skill interactiva de Playwright para que Codex renderice en un navegador real y redimensione a los breakpoints.", "Itera haciendo que Codex compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Alimenta las imágenes arrastrando una captura a la terminal o con el flag de imagen, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en una segunda terminal, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Codex cuándo reviertes) para que cada pasada parta de una base limpia."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, OpenAI y Figma anunciaron una asociación oficial, convirtiendo la beta anterior del MCP de Figma en una integración bidireccional de primera clase. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el “link to selection” de un frame en Figma, pégalo en Codex con get_design_context y pídele que implemente el diseño usando tu biblioteca de componentes existente."}, {"label": "Código → Diseño", "body": "La herramienta generate_figma_design (“Code to Canvas”) convierte una UI en vivo y en ejecución de vuelta en frames editables de Figma — pantalla completa, un elemento seleccionado o un archivo entero."}]}, {"kind": "p", "text": "El MCP de Figma se ejecuta como un servidor remoto y está exento de límites de tasa. Añádelo una vez y estará disponible para Codex, Claude Code, Cursor, VS Code y más — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Codex", "Fuerte pulido visual tras GPT-5.4 + skill de frontend; comprensión de imágenes", "Compilaciones asíncronas delegadas, ejecuciones en sandbox, reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Codex es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos, instrucciones que se filtran en el texto de la UI y alcanzar rápidamente los límites de uso."}, {"kind": "steps", "items": [{"label": "Instala una skill de frontend", "body": "Una skill estética curada obliga a Codex a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Habilita la verificación con Playwright", "body": "Haz que Codex renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Codex dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Codex como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Codex esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Codex como tu agente.", "Autentícate con tu clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Codex, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenAI Codex realmente hacer trabajo de diseño?", "text": "Sí — con una skill de frontend, un sistema de diseño e imágenes de referencia reales en contexto, Codex (especialmente con GPT-5.4) produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este el plugin de Product Design de OpenAI Codex?", "text": "No. Open Design es un proyecto open-source independiente que integra a Codex como agente. Complementa las propias herramientas de OpenAI con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a ChatGPT para diseñar con Codex?", "text": "Puedes usar una clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT. El inicio de sesión con ChatGPT suele dar límites más generosos; en cualquier caso, Open Design nunca actúa como proxy de tus credenciales."}, {"name": "¿Codex o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; Codex tiene un fuerte pulido visual tras GPT-5.4 y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Codex con Figma?", "text": "Añade el servidor MCP oficial de Figma (codex mcp add figma --url https://mcp.figma.com/mcp). Después podrás implementar frames de Figma en código con get_design_context y enviar una UI en ejecución de vuelta a frames editables de Figma con generate_figma_design."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala una skill de frontend, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en AGENTS.md y habilita la verificación con Playwright. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenAI?", "text": "No. Codex es un producto de OpenAI; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. OpenAI y Codex son marcas comerciales de OpenAI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de OpenAI las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Codex, a la manera abierta.", "ctaBody": "Usa tu propia clave de OpenAI, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor para diseñadores — Open Design",
        description: "Cómo los diseñadores usan Cursor para diseño de UI y web — Design Mode, Figma a código, el MCP de Figma — y cómo Open Design convierte a Cursor en un agente de diseño open-source y local-first.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor para diseñadores.",
        lead: "Cursor es el editor de código con IA, ahora con un Design Mode visual. Los diseñadores lo usan para editar la UI señalando y dibujando, y para convertir Figma en código. Open Design conecta a Cursor Agent con un flujo de trabajo de diseño open-source que mantiene tus archivos en local.",
        rich: {"heroCtaLead": "Open Design convierte a Cursor en un agente de diseño open-source y local-first — tu cuenta de Cursor o tus claves de modelo, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor es el editor de código con IA primero que convirtió el “constrúyelo y míralo renderizar” en la forma por defecto de entregar UI. Con el modo Agent, ediciones en línea, una vista previa dentro del editor y Figma sobre MCP, se ha convertido en una verdadera herramienta de diseño — una vez que le das las referencias, reglas y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Cursor en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Cursor, por qué su ajustado bucle de iterar y observar es bueno para el diseño, cómo configurarlo desde cero, el bucle de captura y vista previa a UI, el round-trip con Figma sobre MCP, cómo se compara con Codex y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergencia de diseño de Cursor: el editor a la izquierda, un hub curado de skills y sistema de diseño en el centro con la marca de Cursor al medio, y una UI renderizada a la derecha", "caption": "La idea central: Cursor edita y renderiza la UI en el editor, mientras un hub de diseño curado le aporta el sistema, las skills y las referencias que hacen que el resultado parezca intencional."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-cursor", "label": "Qué es realmente Cursor"}, {"id": "why-design", "label": "Por qué Cursor es bueno en diseño"}, {"id": "setup", "label": "Configura Cursor para diseño (desde cero)"}, {"id": "preview-workflow", "label": "El flujo de trabajo de vista previa a UI"}, {"id": "figma", "label": "Cursor + Figma sobre MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Cursor en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-cursor", "heading": "Qué es realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor es un editor de código con IA primero construido por Anysphere. Es un fork de VS Code, por lo que conserva el editor, las extensiones y los atajos de teclado familiares, pero reconstruye el flujo de trabajo en torno a un agente de IA que puede leer todo tu proyecto, editar varios archivos, ejecutar comandos e iterar contigo en el bucle."}, {"kind": "p", "text": "Para el trabajo de diseño, las superficies importantes son el modo Agent (describes un resultado y Cursor planifica y edita a través de los archivos), las ediciones en línea y las completaciones con Tab para ajustes rápidos, una vista previa / navegador dentro del editor para que veas la UI en ejecución sin salir de la ventana, y el soporte de MCP que le permite incorporar contexto externo como un archivo de Figma en vivo."}, {"kind": "steps", "items": [{"label": "Reglas del proyecto", "body": "Cursor lee archivos de instrucciones del proyecto — reglas `.mdc` versionadas bajo `.cursor/rules`, y un `AGENTS.md` simple — para que puedas codificar tus convenciones de diseño donde el agente las lee en cada ejecución."}, {"label": "Modelos", "body": "Cursor es flexible en cuanto a modelos: viene con modelos de frontera a través de tu suscripción y también admite traer tus propias claves de modelo, así que eliges el motor detrás del mismo flujo de trabajo del editor."}, {"label": "MCP", "body": "Habla el Model Context Protocol, así que los servidores externos — el más relevante, el servidor MCP de Figma — se convierten en contexto de primera clase para el agente."}]}, {"kind": "ul", "items": ["Proveedor: Anysphere", "Credencial: cuenta / suscripción de Cursor (Hobby / Pro / Business) o tus propias claves de modelo (BYOK)", "Forma: editor de código con IA primero (fork de VS Code) con un agente y una vista previa dentro del editor"]}]}, {"id": "why-design", "heading": "Por qué Cursor es bueno en diseño", "blocks": [{"kind": "p", "text": "La ventaja de diseño de Cursor no es una sola característica — es lo ajustado del bucle de construir y ver. Tres cosas hacen que se sienta como una herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un bucle ajustado de iterar y observar", "body": "Tú formulas el prompt, Cursor edita a través de los archivos, y la vista previa dentro del editor renderiza el resultado de inmediato — así ajustas espaciado, jerarquía y movimiento en segundos en lugar de ir y volver entre una terminal y un navegador separados."}, {"label": "Edición visual directa", "body": "Más allá del chat, Cursor te permite seleccionar elementos en la vista previa y retocar estilos, así que las pequeñas correcciones visuales se sienten como ediciones de diseño en lugar de arqueología de código."}, {"label": "Reglas del proyecto y contexto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) y el servidor MCP de Figma, el agente trabaja contra tus tokens, componentes y especificaciones de diseño reales en lugar de adivinar."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Cursor no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Cursor para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Cursor capaz de construir, previsualizar y verificar UI contra tu sistema de diseño."}, {"kind": "ol", "items": ["Instala Cursor desde cursor.com e inicia sesión con tu cuenta de Cursor, o configura tus propias claves de modelo (BYOK) en Settings.", "Abre tu proyecto y elige un modelo en el panel de chat / Agent.", "Añade reglas del proyecto: crea `.cursor/rules/*.mdc` para convenciones estructuradas y delimitadas por globs, o un `AGENTS.md` simple para instrucciones sencillas y legibles.", "Conecta el servidor MCP de Figma (opcional) para que el agente pueda leer el contexto de diseño en vivo.", "Ejecuta tu servidor de desarrollo y usa la vista previa dentro del editor para ver y verificar la UI a medida que iteras."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar reglas, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar las reglas del proyecto → añadir una skill → habilitar la verificación con vista previa."}, {"kind": "p", "text": "Un archivo mínimo de reglas del proyecto hace que el agente diseñe para una marca en lugar de recaer en un aspecto genérico. Ponlo donde Cursor lo lea en cada ejecución:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en `.cursor/rules` o `AGENTS.md` y dirige a Cursor hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Mantén los prompts pequeños", "body": "El bucle ajustado de Cursor recompensa las peticiones enfocadas — itera un componente o estado a la vez y observa la vista previa entre pasadas."}]}]}, {"id": "preview-workflow", "heading": "El flujo de trabajo de vista previa a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Cursor es convertir una referencia en una UI funcional y responsive e iterar en el editor hasta que coincida — observando la vista previa en vivo todo el tiempo en lugar de adivinar."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Cursor dónde viven los tokens y las primitivas canónicas.", "Mantén abierta la vista previa dentro del editor y tu servidor de desarrollo en marcha para que cada edición renderice de inmediato en los breakpoints que te importan.", "Itera comparando la UI renderizada con las referencias — y usa la selección directa de elementos en la vista previa para pequeñas correcciones visuales."]}, {"kind": "p", "text": "Alimenta las referencias adjuntando una imagen al chat, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Confirma las buenas iteraciones y revierte las malas (diciéndole a Cursor cuándo reviertes) para que cada pasada parta de una base limpia — la misma disciplina que evita que cualquier bucle de agente derive."}]}, {"id": "figma", "heading": "Cursor + Figma: diseño ↔ código sobre MCP", "blocks": [{"kind": "p", "text": "Cursor se conecta a Figma a través del servidor MCP oficial de Figma, que da al agente acceso estructurado a un archivo de Figma en vivo en lugar de una captura plana. Eso elimina las conjeturas del handoff."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el enlace de un frame en Figma, pégalo en Cursor y pídele que implemente el diseño. El servidor MCP expone contexto de diseño real — componentes, variables, datos de layout, tokens — para que el código generado coincida con la fuente en lugar de aproximarla."}, {"label": "Mantente alineado", "body": "Con los tokens de diseño, estilos y componentes usados de forma consistente en Figma (y Code Connect donde esté disponible), el resultado de Cursor permanece mapeado a tu sistema de diseño real en lugar de reinventar primitivas."}]}, {"kind": "p", "text": "Configura una vez el servidor MCP remoto de Figma y estará disponible para Cursor como contexto de primera clase. Como MCP es un estándar abierto, el mismo servidor es reutilizable en Cursor, Claude Code, Codex y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Cursor", "Bucle visual de construir y ver con vista previa en vivo dentro del editor y edición directa de elementos", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes y ejecuciones en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Cursor es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños que se rompen en móvil e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Añade una skill de diseño", "body": "Una skill estética curada obliga a Cursor a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Usa la vista previa para verificar", "body": "Renderiza y autoverifica en distintos breakpoints en la vista previa dentro del editor para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en `.cursor/rules`", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Cursor dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Cursor como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Cursor esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Cursor como tu agente.", "Autentícate con tu cuenta de Cursor o tus propias claves de modelo (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Cursor, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Cursor realmente hacer trabajo de diseño?", "text": "Sí — con una skill de diseño, un sistema de diseño e imágenes de referencia reales en contexto, Cursor produce UI responsive de calidad de producción, y su vista previa dentro del editor te permite verificarla y refinarla visualmente. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este un producto oficial de Cursor?", "text": "No. Open Design es un proyecto open-source independiente que integra a Cursor como agente. Complementa a Cursor con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a Cursor para diseñar con Cursor?", "text": "Puedes usar una cuenta / suscripción de Cursor o traer tus propias claves de modelo (BYOK). Open Design nunca actúa como proxy de tus credenciales en ningún caso — las usa directamente tu agente."}, {"name": "¿Cursor o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Cursor es su ajustado bucle de construir y ver con una vista previa en vivo dentro del editor. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Cursor con Figma?", "text": "Añade el servidor MCP oficial de Figma en Cursor, luego pega un enlace de un frame de Figma en el chat y pídele a Cursor que lo implemente. El servidor expone componentes, variables y datos de layout reales para que el código generado coincida con el diseño fuente."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Añade una skill de diseño, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en `.cursor/rules` o `AGENTS.md`, y verifica en distintos breakpoints en la vista previa. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Cursor o Anysphere?", "text": "No. Cursor es un producto de Anysphere; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Cursor y Anysphere son marcas comerciales de Anysphere, Inc."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Cursor o de modelo las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Cursor, a la manera abierta.", "ctaBody": "Usa tu propia cuenta de Cursor o claves de modelo, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode para diseño — Open Design",
        description: "Cómo la gente usa OpenCode para diseño de UI y web — archivos design.md, skills de UI/UX, MCP de Figma — y cómo Open Design convierte a OpenCode en un agente de diseño open-source y local-first.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode para diseño.",
        lead: "OpenCode es el agente de codificación con IA de terminal y open-source. Los diseñadores le acoplan skills de diseño y archivos DESIGN.md para generar UI real. Open Design lo convierte en un flujo de trabajo estructurado y open-source — usa tus claves de proveedor y mantén todo en local.",
        rich: {"heroCtaLead": "Open Design convierte a OpenCode en un agente de diseño open-source y local-first — cualquier modelo que elijas con tu propia clave de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode es un agente de codificación con IA, open-source y orientado a la terminal, que es deliberadamente agnóstico respecto al modelo: traes tu propia clave de proveedor y ejecutas el modelo que quieras detrás del mismo flujo de trabajo. Esa apertura lo convierte en una base natural para el trabajo de diseño — pero, como todo agente, solo produce buena UI cuando le das las referencias, skills y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar OpenCode en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente OpenCode, por qué un agente abierto y agnóstico respecto al modelo encaja bien con el diseño, cómo configurarlo desde cero, el bucle de captura a UI, cómo AGENTS.md y MCP lo extienden, cómo se compara con Codex, Claude Code y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first — un emparejamiento natural, ya que ambos proyectos son open-source y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de OpenCode: un agente TUI de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: OpenCode construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias — con el modelo que elijas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-opencode", "label": "Qué es realmente OpenCode"}, {"id": "why-design", "label": "Por qué un agente abierto y de cualquier modelo encaja con el diseño"}, {"id": "setup", "label": "Configura OpenCode para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "extend", "label": "AGENTS.md, MCP y sesiones compartibles"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con OpenCode en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-opencode", "heading": "Qué es realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode es un agente de codificación con IA open-source construido para la terminal, mantenido por el equipo detrás de SST (Anomaly Innovations). Lee tu repositorio, ejecuta comandos, edita archivos y se comunica con un modelo de lenguaje grande — pero, a diferencia de los agentes atados a un proveedor, no incluye su propio modelo. Lo apuntas a cualquier proveedor y modelo que quieras y traes tu propia clave."}, {"kind": "p", "text": "Se ejecuta como una UI de terminal (TUI), con una aplicación de escritorio y extensiones de IDE sobre el mismo motor. Por debajo usa una arquitectura cliente/servidor, así que el agente que hace el trabajo está desacoplado de la superficie desde la que lo controlas. Dos agentes integrados — build y plan — se alternan con la tecla Tab."}, {"kind": "steps", "items": [{"label": "Agnóstico respecto al modelo", "body": "Los modelos y proveedores provienen de models.dev, un catálogo abierto. Los configuras en opencode.json con una cadena provider/model-id y puedes deshabilitar los proveedores que no quieras cargar — así el mismo flujo de trabajo de diseño se ejecuta sobre Anthropic, OpenAI, Google, OpenRouter, modelos locales y más."}, {"label": "Archivo de instrucciones", "body": "OpenCode lee un archivo AGENTS.md en tu proyecto (el estándar entre herramientas, también compatible con CLAUDE.md) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño. Ejecuta /init para generar uno."}, {"label": "Extensible", "body": "Admite integración con LSP, servidores MCP, temas, atajos de teclado y comandos personalizados, además de enlaces de sesión compartibles para la colaboración."}]}, {"kind": "ul", "items": ["Mantenedor: SST / Anomaly Innovations (proyecto open-source)", "Credencial: tu(s) propia(s) clave(s) de API de proveedor de modelos — BYOK, sin atadura a un proveedor", "Licencia: MIT, open source"]}]}, {"id": "why-design", "heading": "Por qué un agente abierto y de cualquier modelo encaja con el trabajo de diseño", "blocks": [{"kind": "p", "text": "OpenCode no tiene un único “modelo de diseño” como sí lo tiene un agente de proveedor — y ese es el punto. Como es agnóstico respecto al modelo y abierto, puedes ejecutar el mismo flujo de trabajo de diseño sobre el modelo que actualmente sea mejor en frontend, cambiarlo después o recurrir a un modelo local, todo sin cambiar tu configuración."}, {"kind": "p", "text": "Pero la elección del modelo por sí sola no compra gusto. Como todo agente de codificación, OpenCode produce UI genérica a menos que le des restricciones. El buen resultado de diseño proviene de tres insumos que tú aportas."}, {"kind": "steps", "items": [{"label": "Un sistema de diseño", "body": "Tokens, primitivas y convenciones reales que el agente reutiliza, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Una skill estética", "body": "Una skill curada que impone gusto real — movimiento contenido, jerarquía centrada en la marca, como máximo dos tipografías y un color de acento — y hace que el agente se comprometa con una dirección antes de construir."}, {"label": "Referencias concretas", "body": "Imágenes de referencia reales y varios estados (escritorio y móvil, hover, vacío, cargando), no una única toma principal."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales — con independencia del modelo que ejecutes."}, {"kind": "p", "text": "La lección: OpenCode te da libertad de modelo, pero el gusto sigue proviniendo de un contexto de diseño curado. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan — los dos son open-source y local-first (más abajo)."}]}, {"id": "setup", "heading": "Configura OpenCode para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un OpenCode capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar con tu clave de proveedor, configurar AGENTS.md, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar (tu clave de proveedor) → configurar AGENTS.md → añadir una skill → verificar en un navegador real."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md (o en un DESIGN.md referenciado desde él) para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico. La opción instructions de opencode.json puede apuntar a archivos de reglas adicionales mediante globs."}, {"label": "Elige un modelo capaz", "body": "Como OpenCode es agnóstico respecto al modelo, elige el proveedor/modelo que actualmente sea más fuerte en frontend para la pasada de diseño — y mantén el resto de tu flujo de trabajo sin cambios."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con cualquier agente es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La misma forma de cinco pasos aplica en OpenCode."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a OpenCode dónde viven los tokens y las primitivas canónicas (en AGENTS.md).", "Ejecuta un servidor de desarrollo y haz que el agente renderice en un navegador real, redimensionando a los breakpoints para comprobar el resultado.", "Itera haciendo que OpenCode compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Referencia archivos con @ en la TUI para una búsqueda difusa de tu directorio de trabajo, ejecuta comandos de shell en línea con un ! inicial, y dirige las acciones con comandos /. Luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (diciéndole a OpenCode cuándo reviertes), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "AGENTS.md, MCP y sesiones compartibles", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen a OpenCode práctico para el trabajo de diseño sostenido, y los tres se mapean limpiamente sobre un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Reglas de AGENTS.md", "body": "Las reglas del proyecto viven en un AGENTS.md en la raíz del repositorio (o reglas globales en ~/.config/opencode/AGENTS.md). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución, y es compatible con los archivos CLAUDE.md que usan otros agentes."}, {"label": "Servidores MCP", "body": "OpenCode admite servidores MCP tanto locales (command) como remotos (URL), configurados bajo la clave mcp — la forma portátil de incorporar contexto de diseño y herramientas externas que funcionan en todos los agentes, no solo en OpenCode."}, {"label": "Sesiones compartibles", "body": "El comando /share crea un enlace público a una conversación para colaboración o revisión, y /unshare lo revoca — útil para obtener feedback sobre una pasada de diseño."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente — exactamente el tipo de cosa que Open Design está hecho para orquestar, en lugar de recrear en cada proyecto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["OpenCode", "Open-source y agnóstico respecto al modelo; ejecuta cualquier proveedor detrás de un único flujo de trabajo de terminal", "Libertad BYOK, cambio de modelo, configuraciones totalmente abiertas y local-first"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes", "Async delegado, compilaciones en sandbox, reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: todos recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo, que es precisamente por lo que un agente abierto como OpenCode encaja tan bien con una capa de diseño abierta."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI. Ninguno de estos es exclusivo de OpenCode; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado — sin importar qué modelo ejecutes. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con OpenCode dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a OpenCode como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a cualquier agente esté ahí desde la primera ejecución, no se ensamble a mano cada vez. Ambos proyectos son open-source y local-first, lo que hace que el emparejamiento sea un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona OpenCode como tu agente.", "Autentícate con tu propia clave de API de proveedor de modelos (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige cualquier proveedor y modelo, además de un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente OpenCode, la misma libertad de modelo — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenCode realmente hacer trabajo de diseño?", "text": "Sí — con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, OpenCode produce UI responsive de calidad de producción y puede verificarla en un navegador. Como es agnóstico respecto al modelo, ejecutas el modelo que actualmente sea mejor en frontend. Sin ese contexto curado tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Qué modelo debería usar con OpenCode para diseño?", "text": "El que prefieras — OpenCode es agnóstico respecto al proveedor a través de models.dev, así que puedes ejecutar Anthropic, OpenAI, Google, OpenRouter o modelos locales detrás del mismo flujo de trabajo y cambiar en cualquier momento. La calidad del resultado de diseño depende mucho más de tu skill, tu sistema de diseño y tus referencias que del modelo por sí solo."}, {"name": "¿Open Design está hecho por el equipo de OpenCode (SST)?", "text": "No. Open Design es un proyecto open-source independiente que integra a OpenCode como agente. Complementa a OpenCode con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción especial para diseñar con OpenCode?", "text": "No — OpenCode es BYOK. Traes tu propia clave de API de proveedor de modelos, y Open Design nunca actúa como proxy de tus credenciales. No hay atadura a un proveedor."}, {"name": "¿OpenCode, Codex o Claude Code para diseño de frontend?", "text": "Todos son fuertes, y muchos equipos los combinan. La ventaja de OpenCode es ser totalmente open-source y agnóstico respecto al modelo; Codex destaca en compilaciones delegadas en sandbox; Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código. Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo extiendo OpenCode para el contexto de diseño?", "text": "Codifica reglas en AGENTS.md, añade servidores MCP bajo la clave mcp para herramientas portátiles y contexto de diseño, y usa sesiones compartibles para la revisión. Open Design incluye una biblioteca curada de skills y sistemas de diseño para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenCode o SST?", "text": "No. OpenCode es un proyecto open-source mantenido por SST (Anomaly Innovations); Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor de modelos las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con OpenCode, a la manera abierta.", "ctaBody": "Usa tu propia clave de proveedor de modelos, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente abierto que ya usas.", "ctaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
    },
    'pt-br': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code para design — Open Design",
        description: "Como designers usam o Claude Code para design de UI e web, e como o Open Design o transforma em um verdadeiro agente de design — local-first, BYOK, com uma biblioteca curada de skills e design systems.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code para design.",
        lead: "O Claude Code é o agente de programação no terminal da Anthropic. As pessoas já o usam para criar UIs, design systems e landing pages. O Open Design o conecta a um fluxo de design real — traga sua chave da Anthropic ou sua assinatura do Claude e mantenha cada arquivo local.",
        rich: {"heroCtaLead": "O Open Design transforma o Claude Code em um agente de design local-first e open-source — sua chave da Anthropic ou assinatura do Claude, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Claude Code dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O Claude Code é amplamente considerado o agente de programação com o melhor bom gosto em frontend — ele raciocina sobre interfaces com uma especificidade incomum, nomeando valores hex exatos, espaçamentos e escalas tipográficas, e refatora UI em uma base de código grande sem perder o fio da meada. Mas, de saída, ele ainda tende a derivar para uma aparência genérica, a menos que você lhe forneça um design system, skills e referências reais. Este é um guia prático e completo para usar o Claude Code em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo estruturado com o Open Design.", "Ele cobre o que o Claude Code realmente é, por que ele é forte em frontend, como configurá-lo do zero, o fluxo de CLAUDE.md e Skills, a integração oficial de ida e volta com o Figma, como ele se compara ao Codex e ao Cursor, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Loop de feedback de design do Claude Code: o agente no terminal tomando decisões de design específicas, um navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o Claude Code raciocina sobre decisões de UI específicas no terminal, renderiza e as verifica em um navegador real e converge em direção às suas referências."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-claude-code", "label": "O que o Claude Code realmente é"}, {"id": "why-design", "label": "Por que o Claude Code é bom em design"}, {"id": "setup", "label": "Configure o Claude Code para design (do zero)"}, {"id": "skills-workflow", "label": "O fluxo de CLAUDE.md e Skills"}, {"id": "figma", "label": "Integração de ida e volta Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Claude Code no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-claude-code", "heading": "O que o Claude Code realmente é", "blocks": [{"kind": "p", "text": "O Claude Code é a ferramenta de programação agêntica da Anthropic. Ele lê sua base de código, edita arquivos, executa comandos e se integra às suas ferramentas de desenvolvimento — planejando, escrevendo e verificando o trabalho a partir de tarefas em linguagem natural, em vez de apenas autocompletar linhas."}, {"kind": "p", "text": "Ele está disponível em várias superfícies que compartilham o mesmo motor: uma CLI de terminal, extensões para IDE no VS Code, Cursor e JetBrains, um aplicativo desktop com revisão visual de diff e uma experiência web para tarefas de longa duração. Seus arquivos CLAUDE.md, configurações e servidores MCP acompanham todas elas."}, {"kind": "steps", "items": [{"label": "Arquivo de instruções", "body": "O Claude Code lê um arquivo CLAUDE.md na raiz do seu projeto no início de cada sessão — o lugar natural para codificar suas convenções de design, tokens e checklists de revisão."}, {"label": "Skills", "body": "As Agent Skills empacotam instruções, scripts e recursos reutilizáveis que o Claude carrega sob demanda, incluindo a skill oficial de Frontend Design da Anthropic, voltada ao bom gosto."}, {"label": "Plano e subagentes", "body": "Ele pode planejar antes de agir e criar subagentes que trabalham em diferentes partes de uma tarefa em paralelo, o que mantém grandes refatorações de UI coerentes."}]}, {"kind": "ul", "items": ["Fornecedor: Anthropic", "Credencial: chave de API da Anthropic (BYOK, via Console) ou assinatura do Claude (Pro / Max)", "Superfícies: CLI de terminal, extensões para VS Code / Cursor / JetBrains, aplicativo desktop, web"]}]}, {"id": "why-design", "heading": "Por que o Claude Code é bom em design", "blocks": [{"kind": "p", "text": "Entre os agentes de programação, o Claude Code tem reputação de bom gosto em trabalho de frontend. Algumas coisas explicam isso."}, {"kind": "steps", "items": [{"label": "Decisões específicas, não vagas", "body": "O Claude Code tende a se comprometer com escolhas concretas — valores hex exatos, escalas de espaçamento, rampas tipográficas e hierarquia de componentes — em vez de generalizar, e é isso que separa uma interface de verdade de um placeholder."}, {"label": "Raciocínio ciente da base de código", "body": "Com um amplo contexto de trabalho, ele refatora a UI em muitos arquivos de uma vez, reutilizando seus componentes e tokens existentes em vez de reinventar estilos avulsos."}, {"label": "Uma skill oficial de frontend", "body": "A Anthropic disponibiliza uma skill de Frontend Design que faz o Claude escrever primeiro uma direção de design e o afasta deliberadamente de fontes de sistema genéricas e dos previsíveis gradientes roxos."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição é a mesma que a Anthropic faz sobre seus próprios modelos: o Claude não tem bom gosto por padrão — deixado por conta própria, ele converge para o centro estatístico do web design (Inter, gradientes roxos, sombras suaves). Ele produz bom design quando você lhe dá restrições. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Claude Code para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Claude Code capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar o CLAUDE.md, adicionar a skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar o CLAUDE.md → adicionar a skill de Frontend Design → habilitar a verificação no navegador."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no CLAUDE.md e aponte o Claude para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Adicione verificação no navegador", "body": "Conecte um MCP do Playwright ou do Chrome para que o Claude renderize em um navegador real e verifique sua saída em diferentes breakpoints, em vez de apenas confirmar que o build passou."}]}]}, {"id": "skills-workflow", "heading": "O fluxo de CLAUDE.md e Skills", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Claude Code é alimentá-lo com referências reais mais o seu contexto de design e então iterar até que a UI corresponda — com o CLAUDE.md e as Skills carregando as restrições, para que você não precise reexplicá-las a cada prompt."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica mesmo com um agente forte.", "Mantenha seu design system e suas convenções no CLAUDE.md e diga ao Claude onde ficam os tokens e os primitivos canônicos.", "Adicione a skill de Frontend Design para que o Claude se comprometa com uma direção estética real antes de escrever o código.", "Conecte a verificação no navegador para que o Claude renderize, redimensione para os breakpoints e compare de volta com as referências — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Solte uma imagem de referência na sessão e escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Mantenha um servidor de desenvolvimento rodando ao lado, mantenha os prompts pequenos e focados, e faça commit das boas iterações / reverta as ruins (avisando o Claude quando reverter), para que cada passada parta de uma base limpa. Use o modo de plano para refatorações maiores, de modo a poder revisar a abordagem antes de qualquer alteração nos arquivos."}]}, {"id": "figma", "heading": "Claude Code + Figma: ida e volta entre design ↔ código", "blocks": [{"kind": "p", "text": "Em fevereiro de 2026, a Anthropic e a Figma lançaram uma integração bidirecional de primeira classe via servidor MCP do Figma. Ela funciona nas duas direções."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Selecione um frame no Figma ou cole um link no Claude Code, traga o contexto de design e peça que ele implemente o design usando sua biblioteca de componentes existente. O Code Connect mantém a saída alinhada com seus componentes reais."}, {"label": "Código → Design", "body": "Crie e visualize um recurso no navegador e então diga “Send this to Figma” para capturar a UI em execução como camadas editáveis do Figma — a tela inteira ou um elemento selecionado."}]}, {"kind": "p", "text": "Instale uma vez com claude plugin install figma@claude-plugins-official (o MCP do Dev Mode exige um plano pago do Figma). O mesmo MCP do Figma está disponível para Claude Code, Codex, Cursor e VS Code — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e raciocínio de UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"], ["Codex", "Forte refinamento visual e compreensão de imagens; builds assíncronos em sandbox", "Builds assíncronos delegados e regras portáteis em AGENTS.md"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "Mesmo com a reputação de bom gosto do Claude Code, a reclamação mais comum sobre design gerado por IA é que ele parece genérico — fontes Inter, gradientes roxos sobre branco, sombras suaves, cantos arredondados exagerados, uma estética que “grita que uma IA fez isso”. A própria Anthropic atribui isso à convergência distribucional: escolhas seguras dominam os dados de treinamento da web. Outros problemas relatados incluem layouts mobile quebrados e instruções vazando para o texto da UI."}, {"kind": "steps", "items": [{"label": "Instale a skill de Frontend Design", "body": "Ela força o Claude a se comprometer com uma direção real e evita explicitamente fontes e gradientes usados em excesso por IA."}, {"label": "Habilite a verificação no navegador", "body": "Faça o Claude renderizar e verificar a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no CLAUDE.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Claude Code dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Claude Code como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Claude Code bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Claude Code como seu agente.", "Autentique-se com sua chave de API da Anthropic (BYOK) ou sua assinatura do Claude — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Claude Code, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O Claude Code é bom para trabalho de design?", "text": "Sim — ele é amplamente considerado o agente de programação com o melhor bom gosto em frontend, tomando decisões específicas e cientes da base de código sobre valores hex, espaçamento e escalas tipográficas. Com a skill de Frontend Design, um design system e imagens de referência reais no contexto, ele produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Preciso de uma assinatura do Claude para projetar com o Claude Code?", "text": "Você pode usar uma chave de API da Anthropic (BYOK, via Console) ou uma assinatura do Claude (Pro / Max). De qualquer forma, o Open Design nunca usa um proxy para suas credenciais — elas são usadas diretamente pelo seu agente na sua máquina."}, {"name": "Claude Code ou Codex para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código e por raciocínio de frontend; o Codex tem forte refinamento visual e se destaca em builds delegados e em sandbox. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Claude Code ao Figma?", "text": "Instale o plugin oficial do Figma com claude plugin install figma@claude-plugins-official. Você pode então implementar frames do Figma em código usando o contexto de design e enviar uma UI em execução de volta para frames editáveis do Figma com “Send this to Figma”. O MCP do Dev Mode exige um plano pago do Figma."}, {"name": "O que são Skills e CLAUDE.md?", "text": "O CLAUDE.md é um arquivo markdown na raiz do seu projeto que o Claude Code lê no início de cada sessão — o lugar para codificar suas convenções de design. As Skills empacotam instruções e recursos reutilizáveis que o Claude carrega sob demanda, incluindo a skill oficial de Frontend Design da Anthropic. O Open Design oferece uma biblioteca curada de ambos para que você pule a configuração projeto a projeto."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Instale a skill de Frontend Design, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca no CLAUDE.md e habilite a verificação no navegador. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado à Anthropic?", "text": "Não. O Claude Code é um produto da Anthropic; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. Claude e Claude Code são marcas registradas da Anthropic."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first e Apache-2.0. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais da Anthropic são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Claude Code, do jeito aberto.", "ctaBody": "Traga sua própria chave da Anthropic ou assinatura do Claude, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Claude Code dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex para design — Open Design",
        description: "Como as pessoas usam o OpenAI Codex para design de UI e web — o plugin Product Design, a integração com o Figma, skills de frontend — e como o Open Design transforma o Codex em um agente de design local-first e open-source.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex para design.",
        lead: "O Codex é o agente de programação da OpenAI. Com seu plugin Product Design e sua integração com o Figma, ele se tornou uma ferramenta de design séria. O Open Design conecta o Codex a um fluxo de design open-source — sua chave da OpenAI ou assinatura do ChatGPT, seus arquivos, local-first.",
        rich: {"heroCtaLead": "O Open Design transforma o Codex em um agente de design local-first e open-source — sua chave da OpenAI, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Codex dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O OpenAI Codex começou como um gerador de código, mas em 2026 se tornou uma ferramenta confiável para projetar interfaces de verdade — desde que você lhe dê as referências, skills e o loop de verificação certos. Este é um guia prático e completo para usar o Codex em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o Codex é hoje, por que ele de repente ficou bom em frontend, como configurá-lo do zero, o loop de screenshot para UI, a integração oficial de ida e volta com o Figma, como ele se compara ao Cursor e ao Claude Code, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Loop de feedback de design do Codex: o agente no terminal, o navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o Codex cria a UI no terminal, renderiza e a verifica em um navegador real e itera em direção às suas referências."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-codex", "label": "O que o OpenAI Codex realmente é"}, {"id": "why-design", "label": "Por que o Codex é bom em design agora"}, {"id": "setup", "label": "Configure o Codex para design (do zero)"}, {"id": "screenshot-workflow", "label": "O fluxo de screenshot para UI"}, {"id": "figma", "label": "Integração de ida e volta Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Codex no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-codex", "heading": "O que o OpenAI Codex realmente é (e o que não é)", "blocks": [{"kind": "p", "text": "Primeiro, uma desambiguação que confunde quase todo mundo que busca por “Codex”. O OpenAI Codex original era um modelo de autocompletar código de 2021 que alimentava as primeiras versões do GitHub Copilot e foi descontinuado em 2023. Não é disso que esta página trata. O Codex de hoje é a ferramenta de programação agêntica da OpenAI — ele planeja, escreve, executa e verifica código a partir de tarefas em linguagem natural."}, {"kind": "p", "text": "O Codex moderno está disponível em quatro superfícies: uma CLI de terminal (reescrita em Rust, licenciada sob Apache-2.0), uma extensão para IDE no VS Code, Cursor e Windsurf, uma experiência em nuvem/web para tarefas assíncronas delegadas e um aplicativo desktop com um navegador embutido e Computer Use."}, {"kind": "steps", "items": [{"label": "Modelo padrão", "body": "Em meados de 2026, o modelo recomendado é o gpt-5.5, sendo o gpt-5.4 o modelo que a OpenAI treinou explicitamente para frontend e computer use."}, {"label": "Arquivo de instruções", "body": "O Codex lê um arquivo AGENTS.md no seu projeto (um padrão entre ferramentas) para as regras do projeto — o lugar natural para codificar suas convenções de design."}, {"label": "Sandbox", "body": "Ele roda em um sandbox a nível de kernel (workspace-write por padrão), então um agente editando sua UI não consegue sair dos limites do projeto."}]}, {"kind": "ul", "items": ["Fornecedor: OpenAI", "Credencial: chave de API da OpenAI (BYOK) ou assinatura do ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licença da CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Por que o Codex é bom em design agora", "blocks": [{"kind": "p", "text": "Três coisas convergiram no início de 2026 para tornar o Codex uma ferramenta de design de verdade, em vez de um gerador de código genérico."}, {"kind": "steps", "items": [{"label": "Um modelo treinado para frontend", "body": "A OpenAI lançou o GPT-5.4, seu primeiro modelo de linha principal treinado para frontend e computer use, com compreensão de imagens muito melhor ao longo do fluxo de design e autoverificação mais forte. Ele consegue até gerar mood boards e opções visuais antes de se comprometer com os assets finais."}, {"label": "Uma skill oficial de frontend", "body": "O catálogo openai/skills traz uma frontend-skill curada que impõe bom gosto de verdade: layouts sem cards, heros full-bleed, hierarquia que prioriza a marca, movimento contido, no máximo dois tipos de fonte e uma cor de destaque — e faz o Codex escrever uma tese visual antes de construir."}, {"label": "Verificação no navegador", "body": "Com a skill do Playwright, o Codex abre um navegador real, redimensiona para os breakpoints e compara sua saída de volta com a referência, em vez de apenas verificar que o build passou."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição por trás das três: o Codex não tem bom gosto por padrão. Ele produz bom design quando você lhe dá restrições — um design system, uma skill estética e referências concretas. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Codex para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Codex capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar, instalar a skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar o AGENTS.md → instalar a skill de frontend → habilitar a verificação no navegador."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no AGENTS.md ou em um DESIGN.md e aponte o Codex para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Escolha o nível de raciocínio certo", "body": "A OpenAI observa que níveis de raciocínio de baixo a médio costumam produzir resultados de frontend mais fortes do que o nível mais alto."}]}]}, {"id": "screenshot-workflow", "heading": "O fluxo de screenshot para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Codex é transformar uma imagem de referência em uma UI funcional e responsiva e iterar até que ela corresponda. A própria orientação da OpenAI se resume a cinco passos."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao Codex onde ficam os tokens e os primitivos canônicos.", "Habilite a skill interativa do Playwright para que o Codex renderize em um navegador real e redimensione para os breakpoints.", "Itere fazendo o Codex comparar sua implementação de volta com as capturas de tela — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Alimente as imagens arrastando uma captura de tela para o terminal ou usando a flag de imagem, e então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Rode um servidor de desenvolvimento em um segundo terminal, mantenha os prompts pequenos e focados, e faça commit das boas iterações / reverta as ruins (avisando o Codex quando reverter), para que cada passada parta de uma base limpa."}]}, {"id": "figma", "heading": "Codex + Figma: ida e volta entre design ↔ código", "blocks": [{"kind": "p", "text": "Em fevereiro de 2026, a OpenAI e a Figma anunciaram uma parceria oficial, transformando o beta anterior do MCP do Figma em uma integração bidirecional de primeira classe. Ela funciona nas duas direções."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Copie o “link to selection” de um frame no Figma, cole-o no Codex com get_design_context e peça que ele implemente o design usando sua biblioteca de componentes existente."}, {"label": "Código → Design", "body": "A ferramenta generate_figma_design (“Code to Canvas”) transforma uma UI viva e em execução de volta em frames editáveis do Figma — a tela inteira, um elemento selecionado ou um arquivo completo."}]}, {"kind": "p", "text": "O MCP do Figma roda como um servidor remoto e está isento de limites de taxa. Adicione-o uma vez e ele fica disponível para Codex, Claude Code, Cursor, VS Code e mais — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Codex", "Forte refinamento visual após o GPT-5.4 + frontend-skill; compreensão de imagens", "Builds assíncronos delegados, execuções em sandbox, regras portáteis em AGENTS.md"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado pelo Codex é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts mobile quebrados, instruções vazando para o texto da UI e atingir os limites de uso rapidamente."}, {"kind": "steps", "items": [{"label": "Instale uma skill de frontend", "body": "Uma skill estética curada força o Codex a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Habilite a verificação com Playwright", "body": "Faça o Codex renderizar e verificar a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no AGENTS.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Codex dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Codex como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Codex bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Codex como seu agente.", "Autentique-se com sua chave de API da OpenAI (BYOK) ou sua assinatura do ChatGPT — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Codex, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O OpenAI Codex realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill de frontend, um design system e imagens de referência reais no contexto, o Codex (especialmente no GPT-5.4) produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Isto é o plugin Product Design do OpenAI Codex?", "text": "Não. O Open Design é um projeto open-source independente que integra o Codex como um agente. Ele complementa as próprias ferramentas da OpenAI com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura do ChatGPT para projetar com o Codex?", "text": "Você pode usar uma chave de API da OpenAI (BYOK) ou sua assinatura do ChatGPT. O login com o ChatGPT geralmente oferece limites mais generosos; de qualquer forma, o Open Design nunca usa um proxy para suas credenciais."}, {"name": "Codex ou Claude Code para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código; o Codex tem forte refinamento visual após o GPT-5.4 e se destaca em builds delegados e em sandbox. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Codex ao Figma?", "text": "Adicione o servidor MCP oficial do Figma (codex mcp add figma --url https://mcp.figma.com/mcp). Você pode então implementar frames do Figma em código com get_design_context e enviar uma UI em execução de volta para frames editáveis do Figma com generate_figma_design."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Instale uma skill de frontend, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca no AGENTS.md e habilite a verificação com Playwright. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado à OpenAI?", "text": "Não. O Codex é um produto da OpenAI; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. OpenAI e Codex são marcas registradas da OpenAI."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais da OpenAI são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Codex, do jeito aberto.", "ctaBody": "Traga sua própria chave da OpenAI, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Codex dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor para designers — Open Design",
        description: "Como designers usam o Cursor para design de UI e web — Design Mode, Figma-para-código, o MCP do Figma — e como o Open Design transforma o Cursor em um agente de design local-first e open-source.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor para designers.",
        lead: "O Cursor é o editor de código com IA, agora com um Design Mode visual. Designers o usam para editar a UI apontando e desenhando, e para transformar o Figma em código. O Open Design conecta o Cursor Agent a um fluxo de design open-source que mantém seus arquivos locais.",
        rich: {"heroCtaLead": "O Open Design transforma o Cursor em um agente de design local-first e open-source — sua conta do Cursor ou chaves de modelo, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Cursor dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O Cursor é o editor de código IA-first que tornou “criar e ver renderizar” a forma padrão de entregar UI. Com o modo Agent, edições inline, um preview dentro do editor e o Figma via MCP, ele se tornou uma ferramenta de design genuína — desde que você lhe dê as referências, regras e um loop de verificação certos. Este é um guia prático e completo para usar o Cursor em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o Cursor realmente é, por que seu loop apertado de iterar e observar é bom para design, como configurá-lo do zero, o loop de screenshot e preview até a UI, a integração de ida e volta com o Figma via MCP, como ele se compara ao Codex e ao Claude Code, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergência de design do Cursor: o editor à esquerda, um hub curado de skills e design systems no meio com a marca do Cursor ao centro, e uma UI renderizada à direita", "caption": "A ideia central: o Cursor edita e renderiza a UI no editor, enquanto um hub de design curado o alimenta com o system, as skills e as referências que fazem a saída parecer intencional."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-cursor", "label": "O que o Cursor realmente é"}, {"id": "why-design", "label": "Por que o Cursor é bom em design"}, {"id": "setup", "label": "Configure o Cursor para design (do zero)"}, {"id": "preview-workflow", "label": "O fluxo de preview para UI"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Cursor no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-cursor", "heading": "O que o Cursor realmente é", "blocks": [{"kind": "p", "text": "O Cursor é um editor de código IA-first criado pela Anysphere. É um fork do VS Code, então mantém o editor, as extensões e os atalhos de teclado familiares, mas reconstrói o fluxo de trabalho em torno de um agente de IA que pode ler seu projeto inteiro, editar múltiplos arquivos, executar comandos e iterar com você no loop."}, {"kind": "p", "text": "Para trabalho de design, as superfícies importantes são o modo Agent (você descreve um resultado e o Cursor planeja e edita entre arquivos), edições inline e completions com Tab para ajustes rápidos, um preview / navegador dentro do editor para que você veja a UI em execução sem sair da janela, e o suporte a MCP que permite trazer contexto externo como um arquivo Figma ao vivo."}, {"kind": "steps", "items": [{"label": "Regras de projeto", "body": "O Cursor lê arquivos de instruções do projeto — regras `.mdc` versionadas em `.cursor/rules` e um `AGENTS.md` simples — para que você codifique suas convenções de design onde o agente as lê a cada execução."}, {"label": "Modelos", "body": "O Cursor é flexível quanto a modelos: ele vem com modelos de fronteira pela sua assinatura e também suporta trazer suas próprias chaves de modelo, então você escolhe o motor por trás do mesmo fluxo de trabalho do editor."}, {"label": "MCP", "body": "Ele fala o Model Context Protocol, então servidores externos — o mais relevante sendo o servidor MCP do Figma — se tornam contexto de primeira classe para o agente."}]}, {"kind": "ul", "items": ["Fornecedor: Anysphere", "Credencial: conta / assinatura do Cursor (Hobby / Pro / Business) ou suas próprias chaves de modelo (BYOK)", "Forma: editor de código IA-first (fork do VS Code) com um agente e preview dentro do editor"]}]}, {"id": "why-design", "heading": "Por que o Cursor é bom em design", "blocks": [{"kind": "p", "text": "A vantagem do Cursor em design não é um único recurso — é a precisão do loop de criar e ver. Três coisas o fazem parecer uma ferramenta de design em vez de um gerador de código genérico."}, {"kind": "steps", "items": [{"label": "Um loop apertado de iterar e observar", "body": "Você escreve o prompt, o Cursor edita entre arquivos e o preview dentro do editor renderiza o resultado imediatamente — então você ajusta espaçamento, hierarquia e movimento em segundos, em vez de ir e voltar entre um terminal e um navegador separados."}, {"label": "Edição visual direta", "body": "Além do chat, o Cursor permite selecionar elementos no preview e ajustar estilos, de modo que pequenas correções visuais parecem edições de design em vez de arqueologia de código."}, {"label": "Regras de projeto e contexto de MCP", "body": "Com `.cursor/rules` (ou `AGENTS.md`) e o servidor MCP do Figma, o agente trabalha a partir dos seus tokens, componentes e specs de design reais, em vez de adivinhar."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição é a mesma que todo agente ensina: o Cursor não tem bom gosto por padrão. Ele produz bom design quando você lhe dá restrições — um design system, uma skill estética e referências concretas. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Cursor para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Cursor capaz de criar, visualizar e verificar UI em relação ao seu design system."}, {"kind": "ol", "items": ["Instale o Cursor a partir de cursor.com e faça login com sua conta do Cursor, ou configure suas próprias chaves de modelo (BYOK) em Settings.", "Abra seu projeto e escolha um modelo no painel de chat / Agent.", "Adicione regras de projeto: crie `.cursor/rules/*.mdc` para convenções estruturadas e com escopo por glob, ou um `AGENTS.md` simples para instruções legíveis e diretas.", "Conecte o servidor MCP do Figma (opcional) para que o agente possa ler o contexto de design ao vivo.", "Rode seu servidor de desenvolvimento e use o preview dentro do editor para ver e verificar a UI enquanto você itera."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar regras, adicionar skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar as regras de projeto → adicionar uma skill → habilitar a verificação no preview."}, {"kind": "p", "text": "Um arquivo mínimo de regras de projeto faz o agente projetar para uma marca em vez de cair em uma aparência genérica. Coloque-o onde o Cursor o lê a cada execução:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções em `.cursor/rules` ou `AGENTS.md` e aponte o Cursor para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Mantenha os prompts pequenos", "body": "O loop apertado do Cursor recompensa pedidos focados — itere um componente ou estado de cada vez e observe o preview entre as passadas."}]}]}, {"id": "preview-workflow", "heading": "O fluxo de preview para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Cursor é transformar uma referência em uma UI funcional e responsiva e iterar no editor até que ela corresponda — observando o preview ao vivo o tempo todo, em vez de adivinhar."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao Cursor onde ficam os tokens e os primitivos canônicos.", "Mantenha o preview dentro do editor aberto e seu servidor de desenvolvimento rodando para que cada edição renderize imediatamente nos breakpoints que importam para você.", "Itere comparando a UI renderizada de volta com as referências — e use a seleção direta de elementos no preview para pequenas correções visuais."]}, {"kind": "p", "text": "Alimente as referências anexando uma imagem ao chat e então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Faça commit das boas iterações e reverta as ruins (avisando o Cursor quando reverter), para que cada passada parta de uma base limpa — a mesma disciplina que impede qualquer loop de agente de derivar."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ código via MCP", "blocks": [{"kind": "p", "text": "O Cursor se conecta ao Figma por meio do servidor MCP oficial do Figma, que dá ao agente acesso estruturado a um arquivo Figma ao vivo em vez de uma captura de tela plana. Isso elimina a adivinhação do handoff."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Copie o link de um frame no Figma, cole-o no Cursor e peça que ele implemente o design. O servidor MCP expõe o contexto de design real — componentes, variáveis, dados de layout, tokens — para que o código gerado corresponda à fonte em vez de aproximá-la."}, {"label": "Mantenha o alinhamento", "body": "Com tokens de design, estilos e componentes usados de forma consistente no Figma (e o Code Connect quando disponível), a saída do Cursor permanece mapeada ao seu design system real, em vez de reinventar primitivos."}]}, {"kind": "p", "text": "Configure o servidor MCP remoto do Figma uma vez e ele fica disponível para o Cursor como contexto de primeira classe. Como o MCP é um padrão aberto, o mesmo servidor é reutilizável entre Cursor, Claude Code, Codex e VS Code — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Cursor", "Loop visual de criar e ver com preview ao vivo dentro do editor e edição direta de elementos", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"], ["Codex", "Forte refinamento visual com uma skill de frontend; compreensão de imagens e execuções em sandbox", "Builds assíncronos delegados e regras portáteis em AGENTS.md"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado pelo Cursor é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts que quebram no mobile e instruções vazando para o texto da UI."}, {"kind": "steps", "items": [{"label": "Adicione uma skill de design", "body": "Uma skill estética curada força o Cursor a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Use o preview para verificar", "body": "Renderize e verifique a si mesmo nos diferentes breakpoints no preview dentro do editor para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras em `.cursor/rules`", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Cursor dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Cursor como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Cursor bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Cursor como seu agente.", "Autentique-se com sua conta do Cursor ou suas próprias chaves de modelo (BYOK) — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Cursor, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O Cursor realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill de design, um design system e imagens de referência reais no contexto, o Cursor produz UI responsiva e de qualidade de produção, e seu preview dentro do editor permite verificá-la e refiná-la visualmente. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Isto é um produto oficial do Cursor?", "text": "Não. O Open Design é um projeto open-source independente que integra o Cursor como um agente. Ele complementa o Cursor com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura do Cursor para projetar com o Cursor?", "text": "Você pode usar uma conta / assinatura do Cursor ou trazer suas próprias chaves de modelo (BYOK). De qualquer forma, o Open Design nunca usa um proxy para suas credenciais — elas são usadas diretamente pelo seu agente."}, {"name": "Cursor ou Claude Code para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código; a vantagem do Cursor é seu loop apertado de criar e ver com um preview ao vivo dentro do editor. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Cursor ao Figma?", "text": "Adicione o servidor MCP oficial do Figma no Cursor, então cole um link de frame do Figma no chat e peça ao Cursor que o implemente. O servidor expõe componentes, variáveis e dados de layout reais para que o código gerado corresponda ao design de origem."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Adicione uma skill de design, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca em `.cursor/rules` ou `AGENTS.md` e verifique nos diferentes breakpoints no preview. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado ao Cursor ou à Anysphere?", "text": "Não. O Cursor é um produto da Anysphere; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. Cursor e Anysphere são marcas registradas da Anysphere, Inc."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais do Cursor ou de modelo são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Cursor, do jeito aberto.", "ctaBody": "Traga sua própria conta do Cursor ou chaves de modelo, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Cursor dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode para design — Open Design",
        description: "Como as pessoas usam o OpenCode para design de UI e web — arquivos design.md, skills de UI/UX, MCP do Figma — e como o Open Design transforma o OpenCode em um agente de design local-first e open-source.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode para design.",
        lead: "O OpenCode é o agente de programação com IA no terminal, open-source. Designers acoplam a ele skills de design e arquivos DESIGN.md para gerar UI de verdade. O Open Design transforma isso em um fluxo estruturado e open-source — traga suas chaves de provedor e mantenha tudo local.",
        rich: {"heroCtaLead": "O Open Design transforma o OpenCode em um agente de design local-first e open-source — qualquer modelo que você escolher com sua própria chave de provedor, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o OpenCode dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O OpenCode é um agente de programação com IA, open-source e que prioriza o terminal, deliberadamente agnóstico quanto a modelos: você traz sua própria chave de provedor e roda qualquer modelo que quiser por trás do mesmo fluxo. Essa abertura o torna uma base natural para trabalho de design — mas, como todo agente, ele só produz boa UI quando você lhe dá as referências, skills e um loop de verificação certos. Este é um guia prático e completo para usar o OpenCode em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o OpenCode realmente é, por que um agente aberto e agnóstico quanto a modelos se encaixa bem em design, como configurá-lo do zero, o loop de screenshot para UI, como o AGENTS.md e o MCP o estendem, como ele se compara ao Codex, ao Claude Code e ao Cursor, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first — uma combinação natural, já que ambos os projetos são open-source e rodam na sua própria máquina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Loop de feedback de design do OpenCode: um agente TUI no terminal, um navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o OpenCode cria a UI no terminal, renderiza e a verifica em um navegador real e itera em direção às suas referências — em qualquer modelo que você escolher."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-opencode", "label": "O que o OpenCode realmente é"}, {"id": "why-design", "label": "Por que um agente aberto e de qualquer modelo se encaixa em design"}, {"id": "setup", "label": "Configure o OpenCode para design (do zero)"}, {"id": "screenshot-workflow", "label": "O fluxo de screenshot para UI"}, {"id": "extend", "label": "AGENTS.md, MCP e sessões compartilháveis"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o OpenCode no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-opencode", "heading": "O que o OpenCode realmente é", "blocks": [{"kind": "p", "text": "O OpenCode é um agente de programação com IA open-source feito para o terminal, mantido pelo time por trás do SST (Anomaly Innovations). Ele lê seu repositório, executa comandos, edita arquivos e conversa com um grande modelo de linguagem — mas, diferente dos agentes presos a um fornecedor, ele não traz seu próprio modelo. Você o aponta para qualquer provedor e modelo que quiser e traz sua própria chave."}, {"kind": "p", "text": "Ele roda como uma UI de terminal (TUI), com um aplicativo desktop e extensões para IDE em cima do mesmo motor. Por baixo, ele usa uma arquitetura cliente/servidor, então o agente que faz o trabalho é desacoplado da superfície a partir da qual você o controla. Dois agentes embutidos — build e plan — alternam com a tecla Tab."}, {"kind": "steps", "items": [{"label": "Agnóstico quanto a modelos", "body": "Os modelos e provedores vêm do models.dev, um catálogo aberto. Você os configura no opencode.json com uma string provider/model-id e pode desabilitar provedores que não quer carregar — então o mesmo fluxo de design roda em Anthropic, OpenAI, Google, OpenRouter, modelos locais e mais."}, {"label": "Arquivo de instruções", "body": "O OpenCode lê um arquivo AGENTS.md no seu projeto (o padrão entre ferramentas, também compatível com CLAUDE.md) para as regras do projeto — o lugar natural para codificar suas convenções de design. Execute /init para gerar um."}, {"label": "Extensível", "body": "Ele suporta integração com LSP, servidores MCP, temas, atalhos de teclado e comandos personalizados, além de links de sessão compartilháveis para colaboração."}]}, {"kind": "ul", "items": ["Mantenedor: SST / Anomaly Innovations (projeto open-source)", "Credencial: sua(s) própria(s) chave(s) de API de provedor de modelo — BYOK, sem lock-in de fornecedor", "Licença: MIT, open source"]}]}, {"id": "why-design", "heading": "Por que um agente aberto e de qualquer modelo se encaixa em trabalho de design", "blocks": [{"kind": "p", "text": "O OpenCode não tem um único “modelo de design” como tem um agente de fornecedor — e é esse o ponto. Como ele é agnóstico quanto a modelos e aberto, você pode rodar o mesmo fluxo de design em qualquer modelo que esteja atualmente melhor em frontend, trocá-lo depois ou recorrer a um modelo local, tudo sem mudar sua configuração."}, {"kind": "p", "text": "Mas a escolha do modelo sozinha não compra bom gosto. Como todo agente de programação, o OpenCode produz UI genérica a menos que você lhe dê restrições. Boa saída de design vem de três insumos que você fornece."}, {"kind": "steps", "items": [{"label": "Um design system", "body": "Tokens, primitivos e convenções reais que o agente reutiliza, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Uma skill estética", "body": "Uma skill curada que impõe bom gosto de verdade — movimento contido, hierarquia que prioriza a marca, no máximo dois tipos de fonte e uma cor de destaque — e faz o agente se comprometer com uma direção antes de construir."}, {"label": "Referências concretas", "body": "Imagens de referência reais e múltiplos estados (desktop e mobile, hover, vazio, carregando), não uma única imagem de destaque."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais — independentemente do modelo que você roda."}, {"kind": "p", "text": "A lição: o OpenCode lhe dá liberdade de modelo, mas o bom gosto ainda vem de um contexto de design curado. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam — ambos são open-source e local-first (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o OpenCode para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um OpenCode capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar com sua chave de provedor, configurar o AGENTS.md, adicionar uma skill, verificar", "caption": "A sequência de configuração: instalar → autenticar (sua chave de provedor) → configurar o AGENTS.md → adicionar uma skill → verificar em um navegador real."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no AGENTS.md (ou em um DESIGN.md referenciado a partir dele) para que a saída combine com uma marca em vez de cair em uma aparência genérica. A opção instructions no opencode.json pode apontar para arquivos de regras adicionais via globs."}, {"label": "Escolha um modelo capaz", "body": "Como o OpenCode é agnóstico quanto a modelos, escolha o provedor/modelo que estiver atualmente mais forte em frontend para a passada de design — e mantenha o resto do seu fluxo inalterado."}]}]}, {"id": "screenshot-workflow", "heading": "O fluxo de screenshot para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com qualquer agente é transformar uma imagem de referência em uma UI funcional e responsiva e iterar até que ela corresponda. A mesma forma de cinco passos se aplica no OpenCode."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao OpenCode onde ficam os tokens e os primitivos canônicos (no AGENTS.md).", "Rode um servidor de desenvolvimento e faça o agente renderizar em um navegador real, redimensionando para os breakpoints para checar o resultado.", "Itere fazendo o OpenCode comparar sua implementação de volta com as capturas de tela — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Referencie arquivos com @ na TUI para uma busca aproximada no seu diretório de trabalho, execute comandos de shell inline com um ! inicial e dispare ações com comandos /. Então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantenha os prompts pequenos e focados, faça commit das boas iterações e reverta as ruins (avisando o OpenCode quando reverter), para que cada passada parta de uma base limpa."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e sessões compartilháveis", "blocks": [{"kind": "p", "text": "Três pontos de extensão tornam o OpenCode prático para trabalho de design sustentado, e todos os três mapeiam de forma limpa para um fluxo de design aberto."}, {"kind": "steps", "items": [{"label": "Regras do AGENTS.md", "body": "As regras de projeto vivem em um AGENTS.md na raiz do repositório (ou regras globais em ~/.config/opencode/AGENTS.md). É a casa durável das suas convenções de design, lida a cada execução, e é compatível com os arquivos CLAUDE.md que outros agentes usam."}, {"label": "Servidores MCP", "body": "O OpenCode suporta servidores MCP locais (comando) e remotos (URL), configurados sob a chave mcp — a forma portátil de trazer contexto de design e ferramentas externas que funcionam entre agentes, não só no OpenCode."}, {"label": "Sessões compartilháveis", "body": "O comando /share cria um link público para uma conversa para colaboração ou revisão, e o /unshare o revoga — útil para obter feedback sobre uma passada de design."}]}, {"kind": "p", "text": "Essas são capacidades portáteis e multiagente — exatamente o tipo de coisa que o Open Design foi feito para orquestrar, em vez de recriar projeto a projeto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["OpenCode", "Open-source e agnóstico quanto a modelos; rode qualquer provedor por trás de um único fluxo no terminal", "Liberdade BYOK, troca de modelos, configurações totalmente abertas e local-first"], ["Codex", "Forte refinamento visual com uma skill de frontend; compreensão de imagens", "Builds delegados, assíncronos e em sandbox, regras portáteis em AGENTS.md"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos eles caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo, que é precisamente por que um agente aberto como o OpenCode combina tão bem com uma camada de design aberta."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado por IA é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts mobile quebrados e instruções vazando para o texto da UI. Nenhum deles é exclusivo do OpenCode; é o que acontece quando qualquer agente roda sem um contexto de design curado."}, {"kind": "steps", "items": [{"label": "Adicione uma skill estética", "body": "Uma skill de design curada força o agente a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Verifique em um navegador real", "body": "Renderize e verifique a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no AGENTS.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado — independentemente do modelo que você roda. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o OpenCode dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o OpenCode como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna qualquer agente bom esteja presente desde a primeira execução, e não montado à mão a cada vez. Ambos os projetos são open-source e local-first, o que torna a combinação um encaixe natural."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o OpenCode como seu agente.", "Autentique-se com sua própria chave de API de provedor de modelo (BYOK) — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha qualquer provedor e modelo, mais um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente OpenCode, a mesma liberdade de modelo — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O OpenCode realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill estética, um design system e imagens de referência reais no contexto, o OpenCode produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Como ele é agnóstico quanto a modelos, você roda qualquer modelo que esteja atualmente melhor em frontend. Sem esse contexto curado, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Qual modelo devo usar com o OpenCode para design?", "text": "O que você preferir — o OpenCode é agnóstico quanto a provedores via models.dev, então você pode rodar Anthropic, OpenAI, Google, OpenRouter ou modelos locais por trás do mesmo fluxo e trocar a qualquer momento. A qualidade da saída de design depende muito mais da sua skill, do seu design system e das suas referências do que do modelo sozinho."}, {"name": "O Open Design é feito pelo time do OpenCode (SST)?", "text": "Não. O Open Design é um projeto open-source independente que integra o OpenCode como um agente. Ele complementa o OpenCode com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura especial para projetar com o OpenCode?", "text": "Não — o OpenCode é BYOK. Você traz sua própria chave de API de provedor de modelo, e o Open Design nunca usa um proxy para suas credenciais. Não há lock-in de fornecedor."}, {"name": "OpenCode, Codex ou Claude Code para design de frontend?", "text": "Todos são fortes, e muitos times os combinam. A vantagem do OpenCode é ser totalmente open-source e agnóstico quanto a modelos; o Codex se destaca em builds delegados e em sandbox; o Claude Code é conhecido por decisões de design específicas e cientes da base de código. O Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como estendo o OpenCode para contexto de design?", "text": "Codifique regras no AGENTS.md, adicione servidores MCP sob a chave mcp para ferramentas portáteis e contexto de design, e use sessões compartilháveis para revisão. O Open Design oferece uma biblioteca curada de skills e design systems para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado ao OpenCode ou ao SST?", "text": "Não. O OpenCode é um projeto open-source mantido pelo SST (Anomaly Innovations); o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais de provedor de modelo são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o OpenCode, do jeito aberto.", "ctaBody": "Traga sua própria chave de provedor de modelo, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente aberto que você já usa.", "ctaActions": [{"label": "Use o OpenCode dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
    },
    'it': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code per il design — Open Design",
        description: "Come i designer usano Claude Code per il design di UI e web, e come Open Design lo trasforma in un vero agente di design — local-first, BYOK, con una libreria curata di skill e design system.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code per il design.",
        lead: "Claude Code è l'agente di coding da terminale di Anthropic. Le persone lo usano già per costruire UI, design system e landing page. Open Design lo collega a un vero flusso di lavoro di design — porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Claude Code in un agente di design open-source e local-first — la tua chiave Anthropic o il tuo abbonamento Claude, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code è ampiamente considerato l'agente di coding con il miglior gusto per il frontend — ragiona sulle interfacce con una specificità insolita, indicando valori hex esatti, spaziature e scale tipografiche, e rifattorizza la UI in un'intera grande codebase senza perdere il filo. Ma, di base, tende comunque a derivare verso un look generico a meno che non gli si forniscano un design system, delle skill e dei riferimenti reali. Questa è una guida pratica ed end-to-end all'uso di Claude Code per UI, frontend e design system, e a come integrarlo in un flusso di lavoro strutturato con Open Design.", "Copre cos'è realmente Claude Code, perché è forte nel frontend, come configurarlo da zero, il flusso di lavoro con CLAUDE.md e le Skill, il round-trip ufficiale con Figma, come si confronta con Codex e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Il ciclo di feedback del design con Claude Code: l'agente da terminale che prende decisioni di design specifiche, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Claude Code ragiona su decisioni di UI specifiche nel terminale, le renderizza e le verifica in un browser reale e converge rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-claude-code", "label": "Cos'è realmente Claude Code"}, {"id": "why-design", "label": "Perché Claude Code è bravo nel design"}, {"id": "setup", "label": "Configurare Claude Code per il design (da zero)"}, {"id": "skills-workflow", "label": "Il flusso di lavoro con CLAUDE.md e le Skill"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Cos'è realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code è lo strumento di coding agentico di Anthropic. Legge la tua codebase, modifica file, esegue comandi e si integra con i tuoi strumenti di sviluppo — pianificando, scrivendo e verificando il lavoro a partire da compiti in linguaggio naturale, anziché limitarsi a completare righe in autocompletamento."}, {"kind": "p", "text": "È disponibile su diverse superfici che condividono tutte lo stesso motore: una CLI da terminale, estensioni IDE per VS Code, Cursor e JetBrains, un'app desktop con revisione visiva delle diff e un'esperienza web per i task a lunga esecuzione. I tuoi file CLAUDE.md, le impostazioni e i server MCP ti seguono su tutte."}, {"kind": "steps", "items": [{"label": "File di istruzioni", "body": "Claude Code legge un file CLAUDE.md nella root del progetto all'inizio di ogni sessione — il posto naturale dove codificare le tue convenzioni di design, i tokens e le checklist di revisione."}, {"label": "Skill", "body": "Le Agent Skill impacchettano istruzioni, script e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic per il gusto estetico."}, {"label": "Pianificazione e subagenti", "body": "Può pianificare prima di agire e generare subagenti che lavorano in parallelo su parti diverse di un task, il che mantiene coerenti i grandi refactoring di UI."}]}, {"kind": "ul", "items": ["Fornitore: Anthropic", "Credenziale: chiave API Anthropic (BYOK, tramite la Console) o un abbonamento Claude (Pro / Max)", "Superfici: CLI da terminale, estensioni VS Code / Cursor / JetBrains, app desktop, web"]}]}, {"id": "why-design", "heading": "Perché Claude Code è bravo nel design", "blocks": [{"kind": "p", "text": "Tra gli agenti di coding, Claude Code ha la reputazione di avere gusto nel lavoro frontend. Alcune cose lo spiegano."}, {"kind": "steps", "items": [{"label": "Decisioni specifiche, non vaghe", "body": "Claude Code tende a impegnarsi su scelte concrete — valori hex esatti, scale di spaziatura, ramp tipografici e gerarchia dei componenti — invece di tergiversare, ed è proprio questo che distingue una vera interfaccia da un segnaposto."}, {"label": "Ragionamento consapevole della codebase", "body": "Con un ampio contesto di lavoro rifattorizza la UI su molti file contemporaneamente, riutilizzando i tuoi componenti e tokens esistenti invece di reinventare stili improvvisati."}, {"label": "Una skill frontend ufficiale", "body": "Anthropic include una skill Frontend Design che fa scrivere a Claude prima una direzione di design e lo allontana deliberatamente da font di sistema generici e prevedibili gradienti viola."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che Anthropic ripete sui propri modelli: Claude non ha gusto di default — lasciato a sé converge verso il centro statistico del web design (Inter, gradienti viola, ombre soft). Produce buon design quando gli dai dei vincoli. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Claude Code per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Claude Code in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura CLAUDE.md, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura CLAUDE.md → aggiungi la skill Frontend Design → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in CLAUDE.md e indirizza Claude verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o Chrome così Claude renderizza in un browser reale e controlla il proprio output sui vari breakpoint, invece di confermare solo che la build passa."}]}]}, {"id": "skills-workflow", "heading": "Il flusso di lavoro con CLAUDE.md e le Skill", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Claude Code consiste nel fornirgli riferimenti reali più il tuo contesto di design, e poi iterare finché la UI non corrisponde — con CLAUDE.md e le Skill a portare i vincoli, così da non doverli rispiegare a ogni prompt."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche anche con un agente forte.", "Tieni il tuo design system e le tue convenzioni in CLAUDE.md, e indica a Claude dove si trovano i tokens e le primitive canoniche.", "Aggiungi la skill Frontend Design così Claude si impegna su una vera direzione estetica prima di scrivere codice.", "Collega la verifica nel browser così Claude renderizza, ridimensiona ai breakpoint e confronta con i riferimenti — non si limita a confermare che la build funziona."]}, {"kind": "p", "text": "Inserisci un'immagine di riferimento nella sessione e formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Tieni in esecuzione un dev server a fianco, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Claude quando fai revert) così ogni passaggio si costruisce su una base pulita. Usa la modalità plan per i refactoring più grandi così da poter rivedere l'approccio prima di qualsiasi modifica ai file."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 Anthropic e Figma hanno rilasciato un'integrazione bidirezionale di prima classe tramite il server Figma MCP. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Seleziona un frame in Figma o incolla un link in Claude Code, recupera il contesto di design e chiedigli di implementarlo usando la tua libreria di componenti esistente. Code Connect mantiene l'output allineato ai tuoi componenti reali."}, {"label": "Codice → Design", "body": "Costruisci e visualizza in anteprima una funzionalità nel browser, poi di' \"Send this to Figma\" per catturare la UI in esecuzione come layer Figma modificabili — l'intera schermata o un elemento selezionato."}]}, {"kind": "p", "text": "Installalo una volta con claude plugin install figma@claude-plugins-official (la modalità Dev Mode MCP richiede un piano Figma a pagamento). Lo stesso Figma MCP è disponibile per Claude Code, Codex, Cursor e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e ragionamento UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Codex", "Forte rifinitura visiva e comprensione delle immagini; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "Anche con la reputazione di gusto di Claude Code, la lamentela più comune sul design generato dall'IA è che appare generico — font Inter, gradienti viola su bianco, ombre soft, angoli arrotondati esagerati, un'estetica che \"urla che l'ha fatto un'IA\". Anthropic stessa lo attribuisce alla convergenza distributiva: le scelte sicure dominano i dati di addestramento del web. Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Installa la skill Frontend Design", "body": "Costringe Claude a impegnarsi su una vera direzione ed evita esplicitamente font e gradienti abusati dall'IA."}, {"label": "Abilita la verifica nel browser", "body": "Fai renderizzare Claude e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in CLAUDE.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Claude Code dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Claude Code come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Claude Code è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Claude Code come tuo agente.", "Autenticati con la tua chiave API Anthropic (BYOK) o il tuo abbonamento Claude — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Claude Code, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Claude Code è adatto al lavoro di design?", "text": "Sì — è ampiamente considerato l'agente di coding con il miglior gusto per il frontend, capace di decisioni specifiche e consapevoli della codebase su valori hex, spaziatura e scale tipografiche. Con la skill Frontend Design, un design system e immagini di riferimento reali nel contesto produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Mi serve un abbonamento Claude per progettare con Claude Code?", "text": "Puoi usare sia una chiave API Anthropic (BYOK, tramite la Console) sia un abbonamento Claude (Pro / Max). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente sulla tua macchina."}, {"name": "Claude Code o Codex per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase e per il ragionamento frontend; Codex ha una forte rifinitura visiva ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Claude Code a Figma?", "text": "Installa il plugin Figma ufficiale con claude plugin install figma@claude-plugins-official. Potrai poi implementare i frame di Figma in codice usando il contesto di design, e riportare una UI in esecuzione verso frame Figma modificabili con \"Send this to Figma\". La modalità Dev Mode MCP richiede un piano Figma a pagamento."}, {"name": "Cosa sono le Skill e CLAUDE.md?", "text": "CLAUDE.md è un file markdown nella root del tuo progetto che Claude Code legge all'inizio di ogni sessione — il posto dove codificare le tue convenzioni di design. Le Skill impacchettano istruzioni e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic. Open Design include una libreria curata di entrambe, così salti la configurazione progetto per progetto."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa la skill Frontend Design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in CLAUDE.md e abilita la verifica nel browser. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato ad Anthropic?", "text": "No. Claude Code è un prodotto di Anthropic; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Claude e Claude Code sono marchi di Anthropic."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Anthropic vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Claude Code, in modo aperto.", "ctaBody": "Porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex per il design — Open Design",
        description: "Come le persone usano OpenAI Codex per il design di UI e web — il plugin Product Design, l'integrazione con Figma, le skill frontend — e come Open Design trasforma Codex in un agente di design open-source e local-first.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex per il design.",
        lead: "Codex è l'agente di coding di OpenAI. Con il suo plugin Product Design e l'integrazione con Figma è diventato un serio strumento di design. Open Design collega Codex a un flusso di lavoro di design open-source — la tua chiave OpenAI o il tuo abbonamento ChatGPT, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Codex in un agente di design open-source e local-first — la tua chiave OpenAI, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex è nato come generatore di codice, ma nel 2026 è diventato uno strumento credibile per progettare interfacce reali — una volta che gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Codex per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è Codex oggi, perché è improvvisamente bravo nel frontend, come configurarlo da zero, il ciclo screenshot-to-UI, il round-trip ufficiale con Figma, come si confronta con Cursor e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Il ciclo di feedback del design con Codex: l'agente da terminale, il browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Codex costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-codex", "label": "Cos'è realmente OpenAI Codex"}, {"id": "why-design", "label": "Perché ora Codex è bravo nel design"}, {"id": "setup", "label": "Configurare Codex per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Cos'è realmente OpenAI Codex (e cosa non è)", "blocks": [{"kind": "p", "text": "Prima, una disambiguazione che inganna quasi tutti quelli che cercano \"Codex\". L'originale OpenAI Codex era un modello di completamento del codice del 2021 che alimentava i primi GitHub Copilot ed è stato deprecato nel 2023. Non è di questo che parla questa pagina. Il Codex di oggi è lo strumento di coding agentico di OpenAI — pianifica, scrive, esegue e verifica codice a partire da compiti in linguaggio naturale."}, {"kind": "p", "text": "Il Codex moderno è disponibile su quattro superfici: una CLI da terminale (riscritta in Rust, con licenza Apache-2.0), un'estensione IDE per VS Code, Cursor e Windsurf, un'esperienza cloud/web per task asincroni delegati e un'app desktop con un browser integrato e Computer Use."}, {"kind": "steps", "items": [{"label": "Modello predefinito", "body": "A metà 2026 il modello raccomandato è gpt-5.5, con gpt-5.4 come modello che OpenAI ha addestrato esplicitamente per il frontend e il computer use."}, {"label": "File di istruzioni", "body": "Codex legge un file AGENTS.md nel tuo progetto (uno standard cross-tool) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design."}, {"label": "Sandbox", "body": "Gira in una sandbox a livello kernel (workspace-write di default), così un agente che modifica la tua UI non può vagare al di fuori del progetto."}]}, {"kind": "ul", "items": ["Fornitore: OpenAI", "Credenziale: chiave API OpenAI (BYOK) o abbonamento ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licenza della CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché ora Codex è bravo nel design", "blocks": [{"kind": "p", "text": "Tre cose sono convergute all'inizio del 2026 per rendere Codex un vero strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Un modello addestrato per il frontend", "body": "OpenAI ha rilasciato GPT-5.4, il suo primo modello mainline addestrato per il frontend e il computer use, con una comprensione delle immagini molto migliore lungo tutto il flusso di design e un'auto-verifica più solida. Può persino generare mood board e opzioni visive prima di impegnarsi sugli asset finali."}, {"label": "Una skill frontend ufficiale", "body": "Il catalogo openai/skills include una skill frontend curata che impone vero gusto: layout senza card, hero a tutto schermo, gerarchia brand-first, movimento contenuto, al massimo due caratteri e un colore d'accento — e fa scrivere a Codex una tesi visiva prima di costruire."}, {"label": "Verifica nel browser", "body": "Con la skill Playwright Codex apre un browser reale, ridimensiona ai breakpoint e confronta il proprio output con il riferimento invece di limitarsi a controllare che la build passi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione dietro tutte e tre: Codex non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Codex per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Codex in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura, installa la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura AGENTS.md → installa la skill frontend → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md o in un DESIGN.md e indirizza Codex verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Scegli il giusto livello di ragionamento", "body": "OpenAI osserva che livelli di ragionamento da basso a medio spesso producono risultati frontend migliori rispetto all'impostazione più alta."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Codex consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. Le linee guida di OpenAI si distillano in cinque passi."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Codex dove si trovano i tokens e le primitive canoniche.", "Abilita la skill interattiva Playwright così Codex renderizza in un browser reale e ridimensiona ai breakpoint.", "Itera facendo confrontare a Codex la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Fornisci le immagini trascinando uno screenshot nel terminale o con il flag image, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Esegui un dev server in un secondo terminale, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Codex quando fai revert) così ogni passaggio si costruisce su una base pulita."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 OpenAI e Figma hanno annunciato una partnership ufficiale, trasformando la precedente beta del Figma MCP in un'integrazione bidirezionale di prima classe. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il \"link to selection\" di un frame in Figma, incollalo in Codex con get_design_context e chiedigli di implementare il design usando la tua libreria di componenti esistente."}, {"label": "Codice → Design", "body": "Lo strumento generate_figma_design (\"Code to Canvas\") trasforma una UI live, in esecuzione, in frame Figma modificabili — l'intera schermata, un elemento selezionato o un intero file."}]}, {"kind": "p", "text": "Il Figma MCP gira come server remoto ed è esente dai rate limit. Aggiungilo una volta ed è disponibile per Codex, Claude Code, Cursor, VS Code e altri — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Codex", "Forte rifinitura visiva dopo GPT-5.4 + skill frontend; comprensione delle immagini", "Build asincrone delegate, esecuzioni in sandbox, regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Codex è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti, istruzioni che trapelano nel testo della UI e il raggiungimento rapido dei limiti d'uso."}, {"kind": "steps", "items": [{"label": "Installa una skill frontend", "body": "Una skill estetica curata costringe Codex a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Abilita la verifica con Playwright", "body": "Fai renderizzare Codex e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Codex dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Codex come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Codex è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Codex come tuo agente.", "Autenticati con la tua chiave API OpenAI (BYOK) o il tuo abbonamento ChatGPT — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Codex, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenAI Codex può davvero fare lavoro di design?", "text": "Sì — con una skill frontend, un design system e immagini di riferimento reali nel contesto, Codex (specialmente su GPT-5.4) produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è il plugin Product Design di OpenAI Codex?", "text": "No. Open Design è un progetto open-source indipendente che integra Codex come agente. Completa gli strumenti di OpenAI con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento ChatGPT per progettare con Codex?", "text": "Puoi usare sia una chiave API OpenAI (BYOK) sia il tuo abbonamento ChatGPT. L'accesso con ChatGPT in genere offre limiti più generosi; in ogni caso Open Design non instrada mai le tue credenziali."}, {"name": "Codex o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; Codex ha una forte rifinitura visiva dopo GPT-5.4 ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Codex a Figma?", "text": "Aggiungi il server Figma MCP ufficiale (codex mcp add figma --url https://mcp.figma.com/mcp). Potrai poi implementare i frame di Figma in codice con get_design_context e riportare una UI in esecuzione verso frame Figma modificabili con generate_figma_design."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa una skill frontend, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in AGENTS.md e abilita la verifica con Playwright. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenAI?", "text": "No. Codex è un prodotto di OpenAI; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. OpenAI e Codex sono marchi di OpenAI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali OpenAI vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Codex, in modo aperto.", "ctaBody": "Porta la tua chiave OpenAI, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor per i designer — Open Design",
        description: "Come i designer usano Cursor per il design di UI e web — Design Mode, da Figma a codice, il Figma MCP — e come Open Design trasforma Cursor in un agente di design open-source e local-first.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor per i designer.",
        lead: "Cursor è l'editor di codice IA, ora con una Design Mode visiva. I designer lo usano per modificare la UI puntando e disegnando, e per trasformare Figma in codice. Open Design collega Cursor Agent a un flusso di lavoro di design open-source che mantiene i tuoi file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Cursor in un agente di design open-source e local-first — il tuo account Cursor o le tue chiavi di modello, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor è l'editor di codice AI-first che ha reso \"costruiscilo e guardalo renderizzare\" il modo predefinito di rilasciare UI. Con la modalità Agent, le modifiche inline, un'anteprima nell'editor e Figma tramite MCP, è diventato un vero strumento di design — una volta che gli fornisci i riferimenti giusti, le regole e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Cursor per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Cursor, perché il suo stretto ciclo itera-e-osserva è adatto al design, come configurarlo da zero, il ciclo screenshot-e-anteprima-to-UI, il round-trip con Figma tramite MCP, come si confronta con Codex e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "La convergenza del design con Cursor: l'editor a sinistra, un hub curato di skill e design system al centro con il marchio Cursor al centro, e una UI renderizzata a destra", "caption": "L'idea centrale: Cursor modifica e renderizza la UI nell'editor, mentre un hub di design curato gli fornisce il sistema, le skill e i riferimenti che fanno apparire intenzionale l'output."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-cursor", "label": "Cos'è realmente Cursor"}, {"id": "why-design", "label": "Perché Cursor è bravo nel design"}, {"id": "setup", "label": "Configurare Cursor per il design (da zero)"}, {"id": "preview-workflow", "label": "Il flusso di lavoro anteprima-to-UI"}, {"id": "figma", "label": "Cursor + Figma tramite MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Cos'è realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor è un editor di codice AI-first costruito da Anysphere. È un fork di VS Code, quindi conserva l'editor, le estensioni e le scorciatoie da tastiera familiari, ma ricostruisce il flusso di lavoro attorno a un agente IA capace di leggere l'intero progetto, modificare più file, eseguire comandi e iterare con te nel ciclo."}, {"kind": "p", "text": "Per il lavoro di design le superfici importanti sono la modalità Agent (descrivi un risultato e Cursor pianifica e modifica attraverso i file), le modifiche inline e i completamenti Tab per aggiustamenti rapidi, un'anteprima / browser nell'editor così puoi vedere la UI in esecuzione senza lasciare la finestra, e il supporto MCP che gli permette di attingere a contesto esterno come un file Figma live."}, {"kind": "steps", "items": [{"label": "Regole di progetto", "body": "Cursor legge file di istruzioni di progetto — regole `.mdc` versionate sotto `.cursor/rules`, e un semplice `AGENTS.md` — così puoi codificare le tue convenzioni di design dove l'agente le legge a ogni esecuzione."}, {"label": "Modelli", "body": "Cursor è flessibile sui modelli: include modelli di frontiera tramite il tuo abbonamento e supporta anche l'uso delle tue chiavi di modello, così scegli il motore dietro lo stesso flusso di lavoro dell'editor."}, {"label": "MCP", "body": "Parla il Model Context Protocol, così i server esterni — il più rilevante è il server Figma MCP — diventano contesto di prima classe per l'agente."}]}, {"kind": "ul", "items": ["Fornitore: Anysphere", "Credenziale: account / abbonamento Cursor (Hobby / Pro / Business) o le tue chiavi di modello (BYOK)", "Forma: editor di codice AI-first (fork di VS Code) con agente e anteprima nell'editor"]}]}, {"id": "why-design", "heading": "Perché Cursor è bravo nel design", "blocks": [{"kind": "p", "text": "Il vantaggio di Cursor nel design non è una singola funzionalità — è la strettezza del ciclo costruisci-e-osserva. Tre cose lo fanno sembrare uno strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Uno stretto ciclo itera-e-osserva", "body": "Tu dai il prompt, Cursor modifica attraverso i file e l'anteprima nell'editor renderizza il risultato immediatamente — così aggiusti spaziatura, gerarchia e movimento in secondi invece di fare avanti e indietro tra un terminale e un browser separati."}, {"label": "Editing visivo diretto", "body": "Oltre alla chat, Cursor ti permette di selezionare elementi nell'anteprima e ritoccare gli stili, così le piccole correzioni visive sembrano modifiche di design piuttosto che archeologia del codice."}, {"label": "Regole di progetto e contesto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) e il server Figma MCP, l'agente lavora rispetto ai tuoi tokens, componenti e specifiche di design reali invece di tirare a indovinare."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Cursor non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Cursor per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Cursor in grado di costruire, visualizzare in anteprima e verificare la UI rispetto al tuo design system."}, {"kind": "ol", "items": ["Installa Cursor da cursor.com e accedi con il tuo account Cursor, oppure configura le tue chiavi di modello (BYOK) nelle Impostazioni.", "Apri il tuo progetto e scegli un modello nel pannello chat / Agent.", "Aggiungi regole di progetto: crea `.cursor/rules/*.mdc` per convenzioni strutturate e con ambito glob, oppure un semplice `AGENTS.md` per istruzioni semplici e leggibili.", "Connetti il server Figma MCP (opzionale) così l'agente può leggere il contesto di design live.", "Esegui il tuo dev server e usa l'anteprima nell'editor per vedere e verificare la UI mentre iteri."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura le regole, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura le regole di progetto → aggiungi una skill → abilita la verifica in anteprima."}, {"kind": "p", "text": "Un file di regole di progetto minimale fa progettare l'agente verso un brand invece di ripiegare su un look generico. Mettilo dove Cursor lo legge a ogni esecuzione:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in `.cursor/rules` o `AGENTS.md` e indirizza Cursor verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Mantieni i prompt piccoli", "body": "Lo stretto ciclo di Cursor premia le richieste mirate — itera un componente o uno stato alla volta e osserva l'anteprima tra un passaggio e l'altro."}]}]}, {"id": "preview-workflow", "heading": "Il flusso di lavoro anteprima-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Cursor consiste nel trasformare un riferimento in una UI funzionante e responsive e iterare nell'editor finché non corrisponde — guardando l'anteprima live per tutto il tempo invece di tirare a indovinare."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Cursor dove si trovano i tokens e le primitive canoniche.", "Tieni aperta l'anteprima nell'editor e in esecuzione il tuo dev server così ogni modifica renderizza immediatamente ai breakpoint che ti interessano.", "Itera confrontando la UI renderizzata con i riferimenti — e usa la selezione diretta degli elementi nell'anteprima per piccole correzioni visive."]}, {"kind": "p", "text": "Fornisci i riferimenti allegando un'immagine alla chat, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Fai commit delle buone iterazioni e revert di quelle cattive (avvisando Cursor quando fai revert) così ogni passaggio si costruisce su una base pulita — la stessa disciplina che impedisce a qualsiasi ciclo di agente di andare alla deriva."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ codice tramite MCP", "blocks": [{"kind": "p", "text": "Cursor si connette a Figma attraverso il server Figma MCP ufficiale, che dà all'agente accesso strutturato a un file Figma live invece di uno screenshot piatto. Questo elimina le congetture dall'handoff."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il link di un frame in Figma, incollalo in Cursor e chiedigli di implementare il design. Il server MCP espone contesto di design reale — componenti, variabili, dati di layout, tokens — così il codice generato corrisponde alla sorgente invece di approssimarla."}, {"label": "Resta allineato", "body": "Con tokens di design, stili e componenti usati in modo coerente in Figma (e Code Connect dove disponibile), l'output di Cursor resta mappato sul tuo design system reale anziché reinventare le primitive."}]}, {"kind": "p", "text": "Configura il server Figma MCP remoto una volta ed è disponibile per Cursor come contesto di prima classe. Poiché MCP è uno standard aperto, lo stesso server è riutilizzabile su Cursor, Claude Code, Codex e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live nell'editor e editing diretto degli elementi", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini ed esecuzioni in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Cursor è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout che si rompono su mobile e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill di design", "body": "Una skill estetica curata costringe Cursor a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Usa l'anteprima per verificare", "body": "Renderizza e auto-controlla sui vari breakpoint nell'anteprima nell'editor così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in `.cursor/rules`", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Cursor dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Cursor come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Cursor è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Cursor come tuo agente.", "Autenticati con il tuo account Cursor o le tue chiavi di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Cursor, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Cursor può davvero fare lavoro di design?", "text": "Sì — con una skill di design, un design system e immagini di riferimento reali nel contesto, Cursor produce UI responsive di qualità da produzione, e la sua anteprima nell'editor ti permette di verificarla e rifinirla visivamente. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è un prodotto Cursor ufficiale?", "text": "No. Open Design è un progetto open-source indipendente che integra Cursor come agente. Completa Cursor con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento Cursor per progettare con Cursor?", "text": "Puoi usare un account / abbonamento Cursor oppure portare le tue chiavi di modello (BYOK). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente."}, {"name": "Cursor o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; il vantaggio di Cursor è il suo stretto ciclo costruisci-e-osserva con un'anteprima live dentro l'editor. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Cursor a Figma?", "text": "Aggiungi il server Figma MCP ufficiale in Cursor, poi incolla il link di un frame Figma nella chat e chiedi a Cursor di implementarlo. Il server espone componenti, variabili e dati di layout reali così il codice generato corrisponde al design sorgente."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Aggiungi una skill di design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in `.cursor/rules` o `AGENTS.md`, e verifica sui vari breakpoint nell'anteprima. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a Cursor o Anysphere?", "text": "No. Cursor è un prodotto di Anysphere; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Cursor e Anysphere sono marchi di Anysphere, Inc."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Cursor o di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Cursor, in modo aperto.", "ctaBody": "Porta il tuo account Cursor o le tue chiavi di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode per il design — Open Design",
        description: "Come le persone usano OpenCode per il design di UI e web — file design.md, skill UI/UX, Figma MCP — e come Open Design trasforma OpenCode in un agente di design open-source e local-first.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode per il design.",
        lead: "OpenCode è l'agente di coding IA da terminale open-source. I designer vi aggiungono skill di design e file DESIGN.md per generare UI reali. Open Design ne fa un flusso di lavoro strutturato e open-source — porta le chiavi dei tuoi provider, mantieni tutto in locale.",
        rich: {"heroCtaLead": "Open Design trasforma OpenCode in un agente di design open-source e local-first — qualsiasi modello tu scelga con la tua chiave di provider, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode è un agente di coding IA open-source e terminal-first deliberatamente agnostico rispetto al modello: porti la tua chiave di provider ed esegui qualunque modello vuoi dietro lo stesso flusso di lavoro. Questa apertura ne fa una base naturale per il lavoro di design — ma, come ogni agente, produce buona UI solo quando gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di OpenCode per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente OpenCode, perché un agente aperto e agnostico rispetto al modello è adatto al design, come configurarlo da zero, il ciclo screenshot-to-UI, come AGENTS.md e MCP lo estendono, come si confronta con Codex, Claude Code e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, dato che entrambi i progetti sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Il ciclo di feedback del design con OpenCode: un agente TUI da terminale, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: OpenCode costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti — su qualsiasi modello tu scelga."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-opencode", "label": "Cos'è realmente OpenCode"}, {"id": "why-design", "label": "Perché un agente aperto e con qualsiasi modello è adatto al design"}, {"id": "setup", "label": "Configurare OpenCode per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP e sessioni condivisibili"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Cos'è realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode è un agente di coding IA open-source costruito per il terminale, mantenuto dal team dietro SST (Anomaly Innovations). Legge la tua repository, esegue comandi, modifica file e parla con un modello linguistico di grandi dimensioni — ma, a differenza degli agenti legati a un fornitore, non include un proprio modello. Lo punti verso qualunque provider e modello vuoi e porti la tua chiave."}, {"kind": "p", "text": "Gira come UI da terminale (TUI), con un'app desktop ed estensioni IDE sopra lo stesso motore. Sotto il cofano usa un'architettura client/server, così l'agente che fa il lavoro è disaccoppiato dalla superficie da cui lo guidi. Due agenti integrati — build e plan — si alternano con il tasto Tab."}, {"kind": "steps", "items": [{"label": "Agnostico rispetto al modello", "body": "Modelli e provider provengono da models.dev, un catalogo aperto. Li configuri in opencode.json con una stringa provider/model-id e puoi disabilitare i provider che non vuoi caricare — così lo stesso flusso di lavoro di design gira su Anthropic, OpenAI, Google, OpenRouter, modelli locali e altro."}, {"label": "File di istruzioni", "body": "OpenCode legge un file AGENTS.md nel tuo progetto (lo standard cross-tool, compatibile anche con CLAUDE.md) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design. Esegui /init per generarne uno."}, {"label": "Estendibile", "body": "Supporta l'integrazione LSP, i server MCP, i temi, le scorciatoie da tastiera e i comandi personalizzati, oltre a link di sessione condivisibili per la collaborazione."}]}, {"kind": "ul", "items": ["Manutentore: SST / Anomaly Innovations (progetto open-source)", "Credenziale: la/le tua/e chiave/i API di provider di modello — BYOK, senza vincoli di fornitore", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente aperto e con qualsiasi modello è adatto al lavoro di design", "blocks": [{"kind": "p", "text": "OpenCode non ha un singolo \"modello di design\" come ce l'ha un agente di fornitore — ed è proprio il punto. Poiché è agnostico rispetto al modello e aperto, puoi eseguire lo stesso flusso di lavoro di design su qualsiasi modello sia attualmente il migliore nel frontend, cambiarlo in seguito o ripiegare su un modello locale, tutto senza modificare la tua configurazione."}, {"kind": "p", "text": "Ma la scelta del modello da sola non compra il gusto. Come ogni agente di coding, OpenCode produce UI generiche a meno che non gli dia dei vincoli. Un buon output di design nasce da tre input che fornisci tu."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "Tokens, primitive e convenzioni reali che l'agente riutilizza, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Una skill estetica", "body": "Una skill curata che impone vero gusto — movimento contenuto, gerarchia brand-first, al massimo due caratteri e un colore d'accento — e fa impegnare l'agente su una direzione prima di costruire."}, {"label": "Riferimenti concreti", "body": "Immagini di riferimento reali e più stati (desktop e mobile, hover, vuoto, caricamento), non una singola immagine hero."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali — indipendentemente da quale modello esegui."}, {"kind": "p", "text": "La lezione: OpenCode ti dà libertà di modello, ma il gusto continua a nascere da un contesto di design curato. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene — entrambi sono open-source e local-first (più sotto)."}]}, {"id": "setup", "heading": "Configurare OpenCode per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un OpenCode in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica con la tua chiave di provider, configura AGENTS.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica (la tua chiave di provider) → configura AGENTS.md → aggiungi una skill → verifica in un browser reale."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md (o in un DESIGN.md richiamato da esso) così l'output rispetta un brand invece di ripiegare su un look generico. L'opzione instructions in opencode.json può puntare a file di regole aggiuntivi tramite glob."}, {"label": "Scegli un modello capace", "body": "Poiché OpenCode è agnostico rispetto al modello, scegli quale provider/modello sia attualmente il più forte nel frontend per il passaggio di design — e mantieni invariato il resto del tuo flusso di lavoro."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con qualsiasi agente consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. La stessa struttura in cinque passi vale in OpenCode."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a OpenCode dove si trovano i tokens e le primitive canoniche (in AGENTS.md).", "Esegui un dev server e fai renderizzare l'agente in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a OpenCode la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Richiama i file con @ nella TUI per una ricerca fuzzy della tua directory di lavoro, esegui comandi shell inline con un ! iniziale e guida le azioni con i comandi /. Poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e revert di quelle cattive (avvisando OpenCode quando fai revert), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e sessioni condivisibili", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono OpenCode pratico per il lavoro di design prolungato, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Regole AGENTS.md", "body": "Le regole di progetto vivono in un AGENTS.md nella root della repo (o regole globali in ~/.config/opencode/AGENTS.md). È la casa duratura per le tue convenzioni di design, letta a ogni esecuzione, ed è compatibile con i file CLAUDE.md usati da altri agenti."}, {"label": "Server MCP", "body": "OpenCode supporta server MCP sia locali (command) sia remoti (URL), configurati sotto la chiave mcp — il modo portabile per portare contesto di design e strumenti esterni che funzionano su più agenti, non solo OpenCode."}, {"label": "Sessioni condivisibili", "body": "Il comando /share crea un link pubblico a una conversazione per collaborazione o revisione, e /unshare lo revoca — utile per ottenere feedback su un passaggio di design."}]}, {"kind": "p", "text": "Queste sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearla progetto per progetto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["OpenCode", "Open-source e agnostico rispetto al modello; esegui qualsiasi provider dietro un unico flusso di lavoro da terminale", "Libertà BYOK, cambio di modello, configurazioni completamente aperte e local-first"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini", "Asincrono delegato, build in sandbox, regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello, ed è precisamente per questo che un agente aperto come OpenCode si abbina così bene a un layer di design aperto."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI. Nessuno di questi è esclusivo di OpenCode; sono ciò che accade quando qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato — indipendentemente da quale modello esegui. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con OpenCode dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta OpenCode come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo qualsiasi agente è presente fin dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi i progetti sono open-source e local-first, il che rende l'abbinamento un'unione naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona OpenCode come tuo agente.", "Autenticati con la tua chiave API di provider di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli qualsiasi provider e modello, più un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente OpenCode, stessa libertà di modello — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenCode può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, OpenCode produce UI responsive di qualità da produzione e può verificarla in un browser. Poiché è agnostico rispetto al modello, esegui qualsiasi modello sia attualmente il migliore nel frontend. Senza quel contesto curato tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Quale modello dovrei usare con OpenCode per il design?", "text": "Quello che preferisci — OpenCode è agnostico rispetto al provider tramite models.dev, così puoi eseguire Anthropic, OpenAI, Google, OpenRouter o modelli locali dietro lo stesso flusso di lavoro e cambiarli in qualsiasi momento. La qualità dell'output di design dipende molto più dalla tua skill, dal tuo design system e dai tuoi riferimenti che dal modello da solo."}, {"name": "Open Design è realizzato dal team di OpenCode (SST)?", "text": "No. Open Design è un progetto open-source indipendente che integra OpenCode come agente. Completa OpenCode con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento speciale per progettare con OpenCode?", "text": "No — OpenCode è BYOK. Porti la tua chiave API di provider di modello, e Open Design non instrada mai le tue credenziali. Non c'è alcun vincolo di fornitore."}, {"name": "OpenCode o Codex o Claude Code per il design frontend?", "text": "Sono tutti forti, e molti team li combinano. Il vantaggio di OpenCode è essere completamente open-source e agnostico rispetto al modello; Codex eccelle nelle build delegate e in sandbox; Claude Code è noto per decisioni di design specifiche e consapevoli della codebase. Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come estendo OpenCode per il contesto di design?", "text": "Codifica le regole in AGENTS.md, aggiungi server MCP sotto la chiave mcp per strumenti e contesto di design portabili, e usa le sessioni condivisibili per la revisione. Open Design include una libreria curata di skill e design system, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenCode o SST?", "text": "No. OpenCode è un progetto open-source mantenuto da SST (Anomaly Innovations); Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali di provider di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con OpenCode, in modo aperto.", "ctaBody": "Porta la tua chiave di provider di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente aperto che già usi.", "ctaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
    },
    'vi': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code cho thiết kế — Open Design",
        description: "Cách các nhà thiết kế dùng Claude Code cho thiết kế UI và web, và cách Open Design biến nó thành một agent thiết kế thực thụ — local-first, BYOK, kèm thư viện skill và design-system được tuyển chọn.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code cho thiết kế.",
        lead: "Claude Code là agent lập trình chạy trên terminal của Anthropic. Người ta đã dùng nó để dựng UI, design system và landing page. Open Design cắm nó vào một quy trình thiết kế thực thụ — mang theo khóa Anthropic hoặc gói đăng ký Claude của bạn, giữ mọi tệp tin ở máy bạn.",
        rich: {"heroCtaLead": "Open Design biến Claude Code thành một agent thiết kế local-first, mã nguồn mở — khóa Anthropic hoặc gói đăng ký Claude của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Claude Code trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code được nhiều người xem là agent lập trình có gu thẩm mỹ frontend tốt nhất — nó lập luận về giao diện với độ cụ thể khác thường, gọi đúng giá trị hex, khoảng cách và type scale, đồng thời tái cấu trúc UI xuyên suốt một codebase lớn mà không lạc mạch. Nhưng ngay khi mới dùng, nó vẫn có xu hướng trôi về một diện mạo chung chung trừ khi bạn trao cho nó một design system, các skill và những tham chiếu thực. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Claude Code cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình có cấu trúc với Open Design.", "Bài viết bao quát Claude Code thực chất là gì, vì sao nó mạnh ở frontend, cách thiết lập nó từ con số không, quy trình CLAUDE.md và Skills, vòng đi-về Figma chính thức, so sánh với Codex và Cursor, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Vòng phản hồi thiết kế của Claude Code: agent terminal đưa ra các quyết định thiết kế cụ thể, trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: Claude Code lập luận ra các quyết định UI cụ thể trong terminal, render và kiểm chứng chúng trong một trình duyệt thực, rồi hội tụ theo các tham chiếu của bạn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-claude-code", "label": "Claude Code thực chất là gì"}, {"id": "why-design", "label": "Vì sao Claude Code giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Claude Code cho thiết kế (từ con số không)"}, {"id": "skills-workflow", "label": "Quy trình CLAUDE.md và Skills"}, {"id": "figma", "label": "Vòng đi-về Claude Code + Figma"}, {"id": "vs", "label": "Claude Code so với Codex so với Cursor"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Claude Code trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code thực chất là gì", "blocks": [{"kind": "p", "text": "Claude Code là công cụ lập trình theo dạng agent của Anthropic. Nó đọc codebase của bạn, chỉnh sửa tệp tin, chạy lệnh và tích hợp với các công cụ phát triển của bạn — lập kế hoạch, viết và kiểm chứng công việc từ các tác vụ bằng ngôn ngữ tự nhiên, thay vì chỉ tự động hoàn thành từng dòng."}, {"kind": "p", "text": "Nó hiện diện trên nhiều bề mặt cùng chung một engine: một CLI trên terminal, các tiện ích mở rộng IDE cho VS Code, Cursor và JetBrains, một ứng dụng desktop có tính năng xem diff trực quan, và một trải nghiệm web cho các tác vụ chạy dài. Các tệp CLAUDE.md, thiết lập và máy chủ MCP của bạn theo cùng bạn trên tất cả chúng."}, {"kind": "steps", "items": [{"label": "Tệp chỉ dẫn", "body": "Claude Code đọc tệp CLAUDE.md ở thư mục gốc dự án vào đầu mỗi phiên — nơi tự nhiên để mã hóa các quy ước thiết kế, tokens và danh mục kiểm tra review của bạn."}, {"label": "Skills", "body": "Agent Skills đóng gói các chỉ dẫn, script và tài nguyên lặp lại được mà Claude nạp theo nhu cầu, bao gồm skill Frontend Design chính thức của Anthropic dành cho gu thẩm mỹ."}, {"label": "Kế hoạch và subagent", "body": "Nó có thể lập kế hoạch trước khi hành động và sinh ra các subagent làm việc song song trên những phần khác nhau của một tác vụ, giúp giữ cho các đợt tái cấu trúc UI lớn được nhất quán."}]}, {"kind": "ul", "items": ["Nhà cung cấp: Anthropic", "Thông tin xác thực: Khóa API Anthropic (BYOK, qua Console) hoặc gói đăng ký Claude (Pro / Max)", "Bề mặt: CLI terminal, tiện ích VS Code / Cursor / JetBrains, ứng dụng desktop, web"]}]}, {"id": "why-design", "heading": "Vì sao Claude Code giỏi thiết kế", "blocks": [{"kind": "p", "text": "Trong số các agent lập trình, Claude Code nổi tiếng về gu thẩm mỹ trong công việc frontend. Có vài điều giải thích cho điều đó."}, {"kind": "steps", "items": [{"label": "Quyết định cụ thể, không mơ hồ", "body": "Claude Code có xu hướng cam kết với những lựa chọn cụ thể — giá trị hex chính xác, các thang khoảng cách, type ramp và phân cấp component — thay vì nói chung chung, và đó chính là điều phân biệt một giao diện thực với một bản giữ chỗ."}, {"label": "Lập luận hiểu codebase", "body": "Với ngữ cảnh làm việc lớn, nó tái cấu trúc UI trên nhiều tệp cùng lúc, tái dùng các component và tokens sẵn có của bạn thay vì sáng chế lại các style dùng một lần."}, {"label": "Một skill frontend chính thức", "body": "Anthropic cung cấp skill Frontend Design khiến Claude viết ra một định hướng thiết kế trước, và chủ động tránh xa các font hệ thống chung chung cùng những gradient tím dễ đoán."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học cũng chính là điều Anthropic nói về các mô hình của họ: Claude không có gu thẩm mỹ mặc định — để mặc kệ, nó hội tụ về trung tâm thống kê của thiết kế web (Inter, gradient tím, đổ bóng mềm). Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Claude Code cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Claude Code có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình CLAUDE.md, thêm skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình CLAUDE.md → thêm skill Frontend Design → bật kiểm chứng trên trình duyệt."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào CLAUDE.md rồi trỏ Claude tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Thêm kiểm chứng trên trình duyệt", "body": "Nối một MCP Playwright hoặc Chrome để Claude render trong trình duyệt thực và kiểm tra đầu ra trên các breakpoint thay vì chỉ xác nhận build thành công."}]}]}, {"id": "skills-workflow", "heading": "Quy trình CLAUDE.md và Skills", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Claude Code là cấp cho nó các tham chiếu thực cộng với ngữ cảnh thiết kế của bạn, rồi lặp đi lặp lại cho đến khi UI khớp — với CLAUDE.md và Skills mang theo các ràng buộc để bạn không phải giải thích lại chúng ở mỗi prompt."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung ngay cả với một agent mạnh.", "Giữ design system và các quy ước của bạn trong CLAUDE.md, và cho Claude biết tokens cùng các primitive chuẩn nằm ở đâu.", "Thêm skill Frontend Design để Claude cam kết với một định hướng thẩm mỹ thực sự trước khi viết code.", "Nối kiểm chứng trên trình duyệt để Claude render, đổi kích thước theo breakpoint và đối chiếu lại với các tham chiếu — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Thả một ảnh tham chiếu vào phiên và prompt bằng các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Chạy một dev server song song, giữ prompt nhỏ và tập trung, commit các vòng lặp tốt / hoàn tác các vòng tệ (báo cho Claude biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch. Dùng chế độ plan cho các đợt tái cấu trúc lớn hơn để bạn xem xét cách tiếp cận trước khi bất kỳ tệp nào thay đổi."}]}, {"id": "figma", "heading": "Claude Code + Figma: vòng đi-về thiết kế ↔ code", "blocks": [{"kind": "p", "text": "Vào tháng 2 năm 2026, Anthropic và Figma ra mắt một tích hợp hai chiều hạng nhất qua máy chủ Figma MCP. Nó hoạt động theo cả hai chiều."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Chọn một frame trong Figma hoặc dán một liên kết vào Claude Code, kéo ngữ cảnh thiết kế về, và yêu cầu nó hiện thực thiết kế bằng thư viện component sẵn có của bạn. Code Connect giữ cho đầu ra ăn khớp với các component thực của bạn."}, {"label": "Code → Thiết kế", "body": "Dựng và xem trước một tính năng trong trình duyệt, rồi nói “Send this to Figma” để chụp lại UI đang chạy thành các layer Figma chỉnh sửa được — toàn bộ màn hình hoặc một phần tử được chọn."}]}, {"kind": "p", "text": "Cài đặt một lần với claude plugin install figma@claude-plugins-official (Dev Mode MCP yêu cầu gói Figma trả phí). Cùng một Figma MCP có sẵn cho Claude Code, Codex, Cursor và VS Code — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Claude Code so với Codex so với Cursor cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và lập luận UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"], ["Codex", "Độ tinh chỉnh thị giác mạnh và khả năng hiểu hình ảnh; build bất đồng bộ trong sandbox", "Build bất đồng bộ được ủy thác và quy tắc AGENTS.md di động"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Ngay cả với danh tiếng về gu thẩm mỹ của Claude Code, phàn nàn phổ biến nhất về thiết kế do AI tạo ra là nó trông chung chung — font Inter, gradient tím trên nền trắng, đổ bóng mềm, bo góc quá khổ, một thẩm mỹ “gào lên rằng AI làm cái này.” Chính Anthropic quy điều này cho sự hội tụ phân phối: các lựa chọn an toàn áp đảo dữ liệu huấn luyện web. Những vấn đề khác được báo cáo gồm bố cục mobile vỡ và phần chỉ dẫn rò rỉ vào nội dung UI."}, {"kind": "steps", "items": [{"label": "Cài skill Frontend Design", "body": "Nó buộc Claude cam kết với một định hướng thực và chủ động tránh các font cùng gradient bị AI lạm dụng."}, {"label": "Bật kiểm chứng trên trình duyệt", "body": "Bắt Claude render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong CLAUDE.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Claude Code bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Claude Code như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Claude Code trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Claude Code làm agent của bạn.", "Xác thực bằng khóa API Anthropic (BYOK) hoặc gói đăng ký Claude của bạn — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Claude Code, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "Claude Code có tốt cho công việc thiết kế không?", "text": "Có — nó được nhiều người xem là agent lập trình có gu thẩm mỹ frontend tốt nhất, đưa ra các quyết định cụ thể và hiểu codebase về giá trị hex, khoảng cách và type scale. Với skill Frontend Design, một design system và những ảnh tham chiếu thực trong ngữ cảnh, nó tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Tôi có cần gói đăng ký Claude để thiết kế với Claude Code không?", "text": "Bạn có thể dùng hoặc khóa API Anthropic (BYOK, qua Console) hoặc gói đăng ký Claude (Pro / Max). Dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn — chúng được agent của bạn dùng trực tiếp trên máy bạn."}, {"name": "Claude Code hay Codex cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase và lập luận frontend; Codex có độ tinh chỉnh thị giác mạnh và xuất sắc ở các bản build được ủy thác, chạy trong sandbox. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Claude Code với Figma?", "text": "Cài plugin Figma chính thức bằng claude plugin install figma@claude-plugins-official. Sau đó bạn có thể hiện thực các frame Figma thành code bằng ngữ cảnh thiết kế, và đẩy một UI đang chạy ngược lại thành các frame Figma chỉnh sửa được với “Send this to Figma.” Dev Mode MCP yêu cầu một gói Figma trả phí."}, {"name": "Skills và CLAUDE.md là gì?", "text": "CLAUDE.md là một tệp markdown ở thư mục gốc dự án mà Claude Code đọc vào đầu mỗi phiên — nơi để mã hóa các quy ước thiết kế của bạn. Skills đóng gói các chỉ dẫn và tài nguyên lặp lại được mà Claude nạp theo nhu cầu, bao gồm skill Frontend Design chính thức của Anthropic. Open Design cung cấp một thư viện tuyển chọn cả hai để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Cài skill Frontend Design, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong CLAUDE.md, và bật kiểm chứng trên trình duyệt. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với Anthropic không?", "text": "Không. Claude Code là sản phẩm của Anthropic; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. Claude và Claude Code là thương hiệu của Anthropic."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first và Apache-2.0. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực Anthropic của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Claude Code, theo cách mở.", "ctaBody": "Mang theo khóa Anthropic hoặc gói đăng ký Claude của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Claude Code trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex cho thiết kế — Open Design",
        description: "Cách người ta dùng OpenAI Codex cho thiết kế UI và web — plugin Product Design, tích hợp Figma, các skill frontend — và cách Open Design biến Codex thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex cho thiết kế.",
        lead: "Codex là agent lập trình của OpenAI. Với plugin Product Design và tích hợp Figma, nó đã trở thành một công cụ thiết kế nghiêm túc. Open Design nối Codex vào một quy trình thiết kế mã nguồn mở — khóa OpenAI hoặc gói đăng ký ChatGPT của bạn, tệp tin của bạn, local-first.",
        rich: {"heroCtaLead": "Open Design biến Codex thành một agent thiết kế local-first, mã nguồn mở — khóa OpenAI của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Codex trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex khởi đầu là một bộ sinh code, nhưng trong năm 2026 nó đã trở thành một công cụ đáng tin cậy để thiết kế các giao diện thực — một khi bạn trao cho nó đúng tham chiếu, skill và vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Codex cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát Codex hôm nay là gì, vì sao nó đột nhiên giỏi frontend, cách thiết lập nó từ con số không, vòng ảnh-chụp-thành-UI, vòng đi-về Figma chính thức, so sánh với Cursor và Claude Code, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Vòng phản hồi thiết kế của Codex: agent terminal, trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: Codex dựng UI trong terminal, render và kiểm chứng nó trong một trình duyệt thực, rồi lặp lại theo các tham chiếu của bạn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex thực chất là gì"}, {"id": "why-design", "label": "Vì sao Codex giờ đây giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Codex cho thiết kế (từ con số không)"}, {"id": "screenshot-workflow", "label": "Quy trình ảnh-chụp-thành-UI"}, {"id": "figma", "label": "Vòng đi-về Codex + Figma"}, {"id": "vs", "label": "Codex so với Cursor so với Claude Code"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Codex trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex thực chất là gì (và không phải là gì)", "blocks": [{"kind": "p", "text": "Trước hết, một sự phân biệt làm vấp ngã gần như tất cả những ai tìm kiếm “Codex.” OpenAI Codex nguyên gốc là một mô hình hoàn thành code năm 2021 từng vận hành GitHub Copilot thời đầu và bị ngừng hỗ trợ năm 2023. Đó không phải điều trang này nói tới. Codex ngày nay là công cụ lập trình theo dạng agent của OpenAI — nó lập kế hoạch, viết, chạy và kiểm chứng code từ các tác vụ bằng ngôn ngữ tự nhiên."}, {"kind": "p", "text": "Codex hiện đại hiện diện trên bốn bề mặt: một CLI terminal (được viết lại bằng Rust, cấp phép Apache-2.0), một tiện ích IDE cho VS Code, Cursor và Windsurf, một trải nghiệm cloud/web cho các tác vụ bất đồng bộ được ủy thác, và một ứng dụng desktop có trình duyệt trong ứng dụng và Computer Use."}, {"kind": "steps", "items": [{"label": "Mô hình mặc định", "body": "Tính đến giữa năm 2026, mô hình được khuyến nghị là gpt-5.5, với gpt-5.4 là mô hình mà OpenAI huấn luyện rõ ràng cho frontend và computer use."}, {"label": "Tệp chỉ dẫn", "body": "Codex đọc một tệp AGENTS.md trong dự án của bạn (một chuẩn liên-công-cụ) để lấy các quy tắc dự án — nơi tự nhiên để mã hóa các quy ước thiết kế của bạn."}, {"label": "Sandbox", "body": "Nó chạy trong một sandbox ở cấp kernel (mặc định workspace-write), nên một agent đang chỉnh sửa UI của bạn không thể lang thang ra ngoài dự án."}]}, {"kind": "ul", "items": ["Nhà cung cấp: OpenAI", "Thông tin xác thực: Khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Giấy phép của CLI: Apache-2.0, mã nguồn mở"]}]}, {"id": "why-design", "heading": "Vì sao Codex giờ đây giỏi thiết kế", "blocks": [{"kind": "p", "text": "Ba điều hội tụ vào đầu năm 2026 khiến Codex trở thành một công cụ thiết kế thực thụ thay vì một bộ sinh code chung chung."}, {"kind": "steps", "items": [{"label": "Một mô hình được huấn luyện cho frontend", "body": "OpenAI ra mắt GPT-5.4, mô hình dòng chính đầu tiên của họ được huấn luyện cho frontend và computer use, với khả năng hiểu hình ảnh tốt hơn nhiều xuyên suốt quy trình thiết kế và tự-kiểm-chứng mạnh hơn. Nó thậm chí có thể tạo mood board và các phương án thị giác trước khi cam kết với tài sản cuối cùng."}, {"label": "Một skill frontend chính thức", "body": "Danh mục openai/skills cung cấp một frontend-skill được tuyển chọn nhằm thực thi gu thẩm mỹ thực: bố cục không thẻ, hero tràn viền, phân cấp ưu tiên thương hiệu, chuyển động tiết chế, tối đa hai kiểu chữ và một màu nhấn — và khiến Codex viết ra một luận đề thị giác trước khi dựng."}, {"label": "Kiểm chứng trên trình duyệt", "body": "Với skill Playwright, Codex mở một trình duyệt thực, đổi kích thước theo breakpoint, và đối chiếu đầu ra của mình với tham chiếu thay vì chỉ kiểm tra rằng build thành công."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học đằng sau cả ba: Codex không có gu thẩm mỹ mặc định. Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc — một design system, một skill thẩm mỹ và những tham chiếu cụ thể. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Codex cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Codex có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình, cài skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình AGENTS.md → cài skill frontend → bật kiểm chứng trên trình duyệt."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào AGENTS.md hoặc một DESIGN.md rồi trỏ Codex tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Chọn đúng mức reasoning", "body": "OpenAI lưu ý rằng các mức reasoning thấp-đến-trung bình thường tạo ra kết quả frontend mạnh hơn so với mức cao nhất."}]}]}, {"id": "screenshot-workflow", "heading": "Quy trình ảnh-chụp-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Codex là biến một ảnh tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại cho đến khi nó khớp. Chính hướng dẫn của OpenAI cô đọng thành năm bước."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho Codex biết tokens cùng các primitive chuẩn nằm ở đâu.", "Bật skill tương tác Playwright để Codex render trong một trình duyệt thực và đổi kích thước theo breakpoint.", "Lặp lại bằng cách cho Codex đối chiếu phần hiện thực của nó với các ảnh chụp — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Cấp ảnh bằng cách kéo một ảnh chụp vào terminal hoặc bằng cờ image, rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Chạy một dev server ở terminal thứ hai, giữ prompt nhỏ và tập trung, commit các vòng lặp tốt / hoàn tác các vòng tệ (báo cho Codex biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch."}]}, {"id": "figma", "heading": "Codex + Figma: vòng đi-về thiết kế ↔ code", "blocks": [{"kind": "p", "text": "Vào tháng 2 năm 2026, OpenAI và Figma công bố một quan hệ đối tác chính thức, biến bản beta Figma MCP trước đó thành một tích hợp hai chiều hạng nhất. Nó hoạt động theo cả hai chiều."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Sao chép “link to selection” của một frame trong Figma, dán nó vào Codex với get_design_context, và yêu cầu nó hiện thực thiết kế bằng thư viện component sẵn có của bạn."}, {"label": "Code → Thiết kế", "body": "Công cụ generate_figma_design (“Code to Canvas”) biến một UI sống động, đang chạy ngược lại thành các frame Figma chỉnh sửa được — toàn bộ màn hình, một phần tử được chọn, hoặc cả một tệp."}]}, {"kind": "p", "text": "Figma MCP chạy như một máy chủ từ xa và được miễn khỏi giới hạn tần suất. Thêm nó một lần và nó có sẵn cho Codex, Claude Code, Cursor, VS Code và nhiều hơn nữa — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Codex so với Cursor so với Claude Code cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Codex", "Độ tinh chỉnh thị giác mạnh sau GPT-5.4 + frontend-skill; khả năng hiểu hình ảnh", "Build bất đồng bộ được ủy thác, chạy trong sandbox, quy tắc AGENTS.md di động"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do Codex tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục mobile vỡ, phần chỉ dẫn rò rỉ vào nội dung UI, và chạm giới hạn sử dụng nhanh chóng."}, {"kind": "steps", "items": [{"label": "Cài một skill frontend", "body": "Một skill thẩm mỹ được tuyển chọn buộc Codex cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Bật kiểm chứng Playwright", "body": "Bắt Codex render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong AGENTS.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Codex bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Codex như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Codex trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Codex làm agent của bạn.", "Xác thực bằng khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT của bạn — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Codex, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "OpenAI Codex có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill frontend, một design system và những ảnh tham chiếu thực trong ngữ cảnh, Codex (đặc biệt trên GPT-5.4) tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Đây có phải plugin Product Design của OpenAI Codex không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp Codex như một agent. Nó bổ sung cho bộ công cụ riêng của OpenAI bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần gói đăng ký ChatGPT để thiết kế với Codex không?", "text": "Bạn có thể dùng hoặc khóa API OpenAI (BYOK) hoặc gói đăng ký ChatGPT của bạn. Đăng nhập ChatGPT thường cho giới hạn hào phóng hơn; dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn."}, {"name": "Codex hay Claude Code cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase; Codex có độ tinh chỉnh thị giác mạnh sau GPT-5.4 và xuất sắc ở các bản build được ủy thác, chạy trong sandbox. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Codex với Figma?", "text": "Thêm máy chủ Figma MCP chính thức (codex mcp add figma --url https://mcp.figma.com/mcp). Sau đó bạn có thể hiện thực các frame Figma thành code với get_design_context và đẩy một UI đang chạy ngược lại thành các frame Figma chỉnh sửa được với generate_figma_design."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Cài một skill frontend, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong AGENTS.md, và bật kiểm chứng Playwright. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với OpenAI không?", "text": "Không. Codex là sản phẩm của OpenAI; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. OpenAI và Codex là thương hiệu của OpenAI."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực OpenAI của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Codex, theo cách mở.", "ctaBody": "Mang theo khóa OpenAI của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Codex trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor cho nhà thiết kế — Open Design",
        description: "Cách các nhà thiết kế dùng Cursor cho thiết kế UI và web — Design Mode, Figma-to-code, Figma MCP — và cách Open Design biến Cursor thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor cho nhà thiết kế.",
        lead: "Cursor là trình soạn code AI, giờ đây có Design Mode trực quan. Các nhà thiết kế dùng nó để chỉnh sửa UI bằng cách trỏ và vẽ, và để biến Figma thành code. Open Design cắm Cursor Agent vào một quy trình thiết kế mã nguồn mở giữ tệp tin của bạn ở máy.",
        rich: {"heroCtaLead": "Open Design biến Cursor thành một agent thiết kế local-first, mã nguồn mở — tài khoản Cursor hoặc khóa mô hình của bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng Cursor trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor là trình soạn code lấy AI làm trọng tâm, đã biến “dựng nó và xem nó render” thành cách mặc định để ship UI. Với chế độ Agent, chỉnh sửa inline, xem trước trong trình soạn và Figma qua MCP, nó đã trở thành một công cụ thiết kế đích thực — một khi bạn trao cho nó đúng tham chiếu, quy tắc và một vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng Cursor cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát Cursor thực chất là gì, vì sao vòng lặp-và-quan-sát chặt chẽ của nó tốt cho thiết kế, cách thiết lập nó từ con số không, vòng ảnh-chụp-và-xem-trước-thành-UI, vòng đi-về Figma qua MCP, so sánh với Codex và Claude Code, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Sự hội tụ thiết kế của Cursor: trình soạn ở bên trái, một hub skill và design-system được tuyển chọn ở giữa với biểu tượng Cursor ở trung tâm, và một UI đã render ở bên phải", "caption": "Ý tưởng cốt lõi: Cursor chỉnh sửa và render UI trong trình soạn, trong khi một hub thiết kế được tuyển chọn cấp cho nó hệ thống, skill và tham chiếu khiến đầu ra trông có chủ đích."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-cursor", "label": "Cursor thực chất là gì"}, {"id": "why-design", "label": "Vì sao Cursor giỏi thiết kế"}, {"id": "setup", "label": "Thiết lập Cursor cho thiết kế (từ con số không)"}, {"id": "preview-workflow", "label": "Quy trình xem-trước-thành-UI"}, {"id": "figma", "label": "Cursor + Figma qua MCP"}, {"id": "vs", "label": "Cursor so với Codex so với Claude Code"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với Cursor trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor thực chất là gì", "blocks": [{"kind": "p", "text": "Cursor là một trình soạn code lấy AI làm trọng tâm do Anysphere xây dựng. Nó là một bản fork của VS Code, nên giữ lại trình soạn, các tiện ích mở rộng và phím tắt quen thuộc, nhưng dựng lại quy trình quanh một agent AI có thể đọc toàn bộ dự án, chỉnh sửa nhiều tệp, chạy lệnh và lặp đi lặp lại cùng bạn trong vòng lặp."}, {"kind": "p", "text": "Với công việc thiết kế, các bề mặt quan trọng là chế độ Agent (bạn mô tả một kết quả và Cursor lập kế hoạch cùng chỉnh sửa xuyên các tệp), chỉnh sửa inline và hoàn thành bằng Tab cho các tinh chỉnh nhanh, một xem trước / trình duyệt trong trình soạn để bạn thấy UI đang chạy mà không rời cửa sổ, và hỗ trợ MCP cho phép nó kéo về ngữ cảnh bên ngoài như một tệp Figma sống động."}, {"kind": "steps", "items": [{"label": "Quy tắc dự án", "body": "Cursor đọc các tệp chỉ dẫn dự án — các quy tắc `.mdc` được phiên bản hóa dưới `.cursor/rules`, và một `AGENTS.md` đơn giản — nên bạn có thể mã hóa các quy ước thiết kế ở nơi agent đọc mỗi lần chạy."}, {"label": "Mô hình", "body": "Cursor linh hoạt về mô hình: nó đi kèm các mô hình tiên phong qua gói đăng ký của bạn và cũng hỗ trợ mang theo khóa mô hình của riêng bạn, nên bạn chọn engine đứng sau cùng một quy trình trình soạn."}, {"label": "MCP", "body": "Nó nói được Model Context Protocol, nên các máy chủ bên ngoài — liên quan nhất là máy chủ Figma MCP — trở thành ngữ cảnh hạng nhất cho agent."}]}, {"kind": "ul", "items": ["Nhà cung cấp: Anysphere", "Thông tin xác thực: Tài khoản / gói đăng ký Cursor (Hobby / Pro / Business) hoặc khóa mô hình của riêng bạn (BYOK)", "Hình thức: Trình soạn code lấy AI làm trọng tâm (bản fork VS Code) với một agent và xem trước trong trình soạn"]}]}, {"id": "why-design", "heading": "Vì sao Cursor giỏi thiết kế", "blocks": [{"kind": "p", "text": "Lợi thế thiết kế của Cursor không phải một tính năng đơn lẻ — đó là độ chặt chẽ của vòng dựng-và-thấy. Ba điều khiến nó cảm giác như một công cụ thiết kế thay vì một bộ sinh code chung chung."}, {"kind": "steps", "items": [{"label": "Một vòng lặp-và-quan-sát chặt chẽ", "body": "Bạn prompt, Cursor chỉnh sửa xuyên các tệp, và xem trước trong trình soạn render kết quả ngay lập tức — nên bạn điều chỉnh khoảng cách, phân cấp và chuyển động trong vài giây thay vì đi-về qua một terminal và trình duyệt riêng."}, {"label": "Chỉnh sửa thị giác trực tiếp", "body": "Ngoài chat, Cursor cho phép bạn chọn phần tử trong xem trước và nhích các style, nên những chỉnh sửa thị giác nhỏ giống như sửa thiết kế hơn là khảo cổ code."}, {"label": "Quy tắc dự án và ngữ cảnh MCP", "body": "Với `.cursor/rules` (hoặc `AGENTS.md`) và máy chủ Figma MCP, agent làm việc dựa trên tokens, component và đặc tả thiết kế thực của bạn thay vì đoán mò."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực."}, {"kind": "p", "text": "Bài học cũng chính là điều mọi agent đều dạy: Cursor không có gu thẩm mỹ mặc định. Nó tạo ra thiết kế tốt khi bạn trao cho nó các ràng buộc — một design system, một skill thẩm mỹ và những tham chiếu cụ thể. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập Cursor cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một Cursor có thể dựng, xem trước và kiểm chứng UI theo design system của bạn."}, {"kind": "ol", "items": ["Cài Cursor từ cursor.com và đăng nhập bằng tài khoản Cursor của bạn, hoặc cấu hình khóa mô hình của riêng bạn (BYOK) trong Settings.", "Mở dự án của bạn và chọn một mô hình trong panel chat / Agent.", "Thêm quy tắc dự án: tạo `.cursor/rules/*.mdc` cho các quy ước có cấu trúc, được giới hạn theo glob, hoặc một `AGENTS.md` đơn giản cho các chỉ dẫn dễ đọc.", "Kết nối máy chủ Figma MCP (tùy chọn) để agent có thể đọc ngữ cảnh thiết kế sống động.", "Chạy dev server của bạn và dùng xem trước trong trình soạn để thấy và kiểm chứng UI khi bạn lặp đi lặp lại."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực, cấu hình quy tắc, thêm skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực → cấu hình quy tắc dự án → thêm một skill → bật kiểm chứng bằng xem trước."}, {"kind": "p", "text": "Một tệp quy tắc dự án tối giản khiến agent thiết kế theo một thương hiệu thay vì mặc định về một diện mạo chung chung. Đặt nó ở nơi Cursor đọc mỗi lần chạy:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào `.cursor/rules` hoặc `AGENTS.md` rồi trỏ Cursor tới đó, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Giữ prompt nhỏ", "body": "Vòng lặp chặt chẽ của Cursor thưởng cho những yêu cầu tập trung — lặp từng component hoặc trạng thái một và quan sát xem trước giữa các lượt."}]}]}, {"id": "preview-workflow", "heading": "Quy trình xem-trước-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với Cursor là biến một tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại trong trình soạn cho đến khi nó khớp — quan sát xem trước trực tiếp suốt quá trình thay vì đoán mò."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho Cursor biết tokens cùng các primitive chuẩn nằm ở đâu.", "Giữ xem trước trong trình soạn luôn mở và dev server của bạn luôn chạy để mỗi chỉnh sửa render ngay lập tức ở các breakpoint bạn quan tâm.", "Lặp lại bằng cách đối chiếu UI đã render với các tham chiếu — và dùng chọn phần tử trực tiếp trong xem trước cho các chỉnh sửa thị giác nhỏ."]}, {"kind": "p", "text": "Cấp tham chiếu bằng cách đính một ảnh vào chat, rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit các vòng lặp tốt và hoàn tác các vòng tệ (báo cho Cursor biết khi bạn hoàn tác) để mỗi lượt dựng trên một nền sạch — chính kỷ luật giữ cho bất kỳ vòng lặp agent nào khỏi trôi dạt."}]}, {"id": "figma", "heading": "Cursor + Figma: thiết kế ↔ code qua MCP", "blocks": [{"kind": "p", "text": "Cursor kết nối với Figma qua máy chủ Figma MCP chính thức, thứ cấp cho agent quyền truy cập có cấu trúc vào một tệp Figma sống động thay vì một ảnh chụp phẳng. Điều đó loại bỏ sự đoán mò khỏi quá trình bàn giao."}, {"kind": "steps", "items": [{"label": "Thiết kế → Code", "body": "Sao chép liên kết của một frame trong Figma, dán nó vào Cursor, và yêu cầu nó hiện thực thiết kế. Máy chủ MCP phơi bày ngữ cảnh thiết kế thực — component, biến, dữ liệu bố cục, tokens — nên code sinh ra khớp với nguồn thay vì xấp xỉ nó."}, {"label": "Giữ sự ăn khớp", "body": "Với design tokens, style và component được dùng nhất quán trong Figma (và Code Connect ở nơi có sẵn), đầu ra của Cursor vẫn ánh xạ tới design system thực của bạn thay vì sáng chế lại các primitive."}]}, {"kind": "p", "text": "Thiết lập máy chủ Figma MCP từ xa một lần và nó có sẵn cho Cursor như ngữ cảnh hạng nhất. Vì MCP là một chuẩn mở, cùng một máy chủ có thể tái dùng trên Cursor, Claude Code, Codex và VS Code — đúng kiểu năng lực di động, đa-agent mà Open Design được tạo ra để điều phối."}]}, {"id": "vs", "heading": "Cursor so với Codex so với Claude Code cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp trong trình soạn và chỉnh sửa phần tử trực tiếp", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"], ["Codex", "Độ tinh chỉnh thị giác mạnh với một skill frontend; khả năng hiểu hình ảnh và chạy trong sandbox", "Build bất đồng bộ được ủy thác và quy tắc AGENTS.md di động"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: cả ba đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do Cursor tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục vỡ trên mobile và phần chỉ dẫn rò rỉ vào nội dung UI."}, {"kind": "steps", "items": [{"label": "Thêm một skill thiết kế", "body": "Một skill thẩm mỹ được tuyển chọn buộc Cursor cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Dùng xem trước để kiểm chứng", "body": "Render và tự kiểm tra trên các breakpoint trong xem trước trong trình soạn để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong `.cursor/rules`", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với Cursor bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi Cursor như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp Cursor trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn Cursor làm agent của bạn.", "Xác thực bằng tài khoản Cursor hoặc khóa mô hình của riêng bạn (BYOK) — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent Cursor, cùng một khóa — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "Cursor có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill thiết kế, một design system và những ảnh tham chiếu thực trong ngữ cảnh, Cursor tạo ra UI responsive chất lượng sản xuất, và xem trước trong trình soạn của nó cho phép bạn kiểm chứng và tinh chỉnh nó một cách trực quan. Thiếu ngữ cảnh đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Đây có phải sản phẩm Cursor chính thức không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp Cursor như một agent. Nó bổ sung cho Cursor bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần gói đăng ký Cursor để thiết kế với Cursor không?", "text": "Bạn có thể dùng một tài khoản / gói đăng ký Cursor hoặc mang theo khóa mô hình của riêng bạn (BYOK). Dù theo cách nào, Open Design cũng không bao giờ trung chuyển thông tin xác thực của bạn — chúng được agent của bạn dùng trực tiếp."}, {"name": "Cursor hay Claude Code cho thiết kế frontend?", "text": "Cả hai đều mạnh. Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase; lợi thế của Cursor là vòng dựng-và-thấy chặt chẽ với một xem trước trực tiếp bên trong trình soạn. Nhiều đội dùng cả hai — Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao kết nối Cursor với Figma?", "text": "Thêm máy chủ Figma MCP chính thức trong Cursor, rồi dán một liên kết frame Figma vào chat và yêu cầu Cursor hiện thực nó. Máy chủ phơi bày các component, biến và dữ liệu bố cục thực nên code sinh ra khớp với thiết kế nguồn."}, {"name": "Làm sao tránh thẩm mỹ “AI slop” chung chung?", "text": "Thêm một skill thiết kế, cung cấp tokens thiết kế thực và ảnh chụp tham chiếu, mã hóa quy tắc thương hiệu trong `.cursor/rules` hoặc `AGENTS.md`, và kiểm chứng trên các breakpoint trong xem trước. Open Design cung cấp những thứ này dưới dạng một thư viện tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với Cursor hay Anysphere không?", "text": "Không. Cursor là sản phẩm của Anysphere; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất. Cursor và Anysphere là thương hiệu của Anysphere, Inc."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực Cursor hoặc mô hình của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với Cursor, theo cách mở.", "ctaBody": "Mang theo tài khoản Cursor hoặc khóa mô hình của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent bạn đã dùng.", "ctaActions": [{"label": "Dùng Cursor trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode cho thiết kế — Open Design",
        description: "Cách người ta dùng OpenCode cho thiết kế UI và web — tệp design.md, các skill UI/UX, Figma MCP — và cách Open Design biến OpenCode thành một agent thiết kế local-first, mã nguồn mở.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode cho thiết kế.",
        lead: "OpenCode là agent lập trình AI chạy trên terminal mã nguồn mở. Các nhà thiết kế gắn các skill thiết kế và tệp DESIGN.md lên nó để tạo ra UI thực. Open Design biến điều đó thành một quy trình có cấu trúc, mã nguồn mở — mang theo khóa nhà cung cấp của bạn, giữ mọi thứ ở máy.",
        rich: {"heroCtaLead": "Open Design biến OpenCode thành một agent thiết kế local-first, mã nguồn mở — bất kỳ mô hình nào bạn chọn với khóa nhà cung cấp của riêng bạn, tệp tin của bạn, kèm thư viện skill và design-system được tuyển chọn bao quanh nó.", "heroCtaActions": [{"label": "Dùng OpenCode trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode là một agent lập trình AI mã nguồn mở, lấy terminal làm trọng tâm, được thiết kế có chủ đích để không phụ thuộc mô hình: bạn mang theo khóa nhà cung cấp của riêng mình và chạy bất kỳ mô hình nào bạn muốn đứng sau cùng một quy trình. Sự cởi mở đó khiến nó là một nền tảng tự nhiên cho công việc thiết kế — nhưng như mọi agent, nó chỉ tạo ra UI tốt khi bạn trao cho nó đúng tham chiếu, skill và một vòng kiểm chứng. Đây là hướng dẫn thực hành, đầu-cuối về cách dùng OpenCode cho công việc UI, frontend và design-system, cũng như cách nối nó vào một quy trình thiết kế có cấu trúc với Open Design.", "Bài viết bao quát OpenCode thực chất là gì, vì sao một agent mở không phụ thuộc mô hình phù hợp với thiết kế, cách thiết lập nó từ con số không, vòng ảnh-chụp-thành-UI, cách AGENTS.md và MCP mở rộng nó, so sánh với Codex, Claude Code và Cursor, những cạm bẫy khiến đầu ra AI trông chung chung, và cách Open Design lấp khoảng cách đó như một lớp thiết kế mở, local-first — một sự ghép đôi tự nhiên, vì cả hai dự án đều mã nguồn mở và chạy trên máy của riêng bạn."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Vòng phản hồi thiết kế của OpenCode: một agent TUI terminal, một trình duyệt render UI, và một không gian làm việc, với mũi tên phản hồi quay vòng trở lại", "caption": "Vòng lặp cốt lõi: OpenCode dựng UI trong terminal, render và kiểm chứng nó trong một trình duyệt thực, rồi lặp lại theo các tham chiếu của bạn — trên bất kỳ mô hình nào bạn chọn."}, "tocLabel": "Trên trang này", "toc": [{"id": "what-is-opencode", "label": "OpenCode thực chất là gì"}, {"id": "why-design", "label": "Vì sao một agent mở, bất-kỳ-mô-hình hợp với thiết kế"}, {"id": "setup", "label": "Thiết lập OpenCode cho thiết kế (từ con số không)"}, {"id": "screenshot-workflow", "label": "Quy trình ảnh-chụp-thành-UI"}, {"id": "extend", "label": "AGENTS.md, MCP và các phiên chia sẻ được"}, {"id": "vs", "label": "OpenCode so với Codex so với Claude Code so với Cursor"}, {"id": "pitfalls", "label": "Cạm bẫy và diện mạo “AI slop”"}, {"id": "open-design", "label": "Thiết kế với OpenCode trong Open Design"}, {"id": "faq", "label": "Câu hỏi thường gặp"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode thực chất là gì", "blocks": [{"kind": "p", "text": "OpenCode là một agent lập trình AI mã nguồn mở được xây dựng cho terminal, do đội ngũ đứng sau SST (Anomaly Innovations) duy trì. Nó đọc kho mã của bạn, chạy lệnh, chỉnh sửa tệp và trò chuyện với một mô hình ngôn ngữ lớn — nhưng khác với các agent buộc chặt vào nhà cung cấp, nó không đi kèm mô hình riêng. Bạn trỏ nó tới bất kỳ nhà cung cấp và mô hình nào bạn muốn và mang theo khóa của riêng mình."}, {"kind": "p", "text": "Nó chạy như một giao diện terminal (TUI), với một ứng dụng desktop và các tiện ích IDE đặt trên cùng một engine. Bên dưới, nó dùng kiến trúc client/server, nên agent thực hiện công việc được tách rời khỏi bề mặt mà bạn điều khiển nó. Hai agent dựng sẵn — build và plan — chuyển đổi bằng phím Tab."}, {"kind": "steps", "items": [{"label": "Không phụ thuộc mô hình", "body": "Mô hình và nhà cung cấp đến từ models.dev, một danh mục mở. Bạn cấu hình chúng trong opencode.json bằng một chuỗi provider/model-id và có thể tắt các nhà cung cấp bạn không muốn nạp — nên cùng một quy trình thiết kế chạy trên Anthropic, OpenAI, Google, OpenRouter, các mô hình cục bộ và nhiều hơn nữa."}, {"label": "Tệp chỉ dẫn", "body": "OpenCode đọc một tệp AGENTS.md trong dự án của bạn (chuẩn liên-công-cụ, cũng tương thích với CLAUDE.md) để lấy các quy tắc dự án — nơi tự nhiên để mã hóa các quy ước thiết kế của bạn. Chạy /init để tạo một tệp."}, {"label": "Mở rộng được", "body": "Nó hỗ trợ tích hợp LSP, máy chủ MCP, theme, phím tắt và lệnh tùy chỉnh, cùng các liên kết phiên chia sẻ được cho việc cộng tác."}]}, {"kind": "ul", "items": ["Người duy trì: SST / Anomaly Innovations (dự án mã nguồn mở)", "Thông tin xác thực: (các) khóa API nhà cung cấp mô hình của riêng bạn — BYOK, không khóa chặt vào nhà cung cấp", "Giấy phép: MIT, mã nguồn mở"]}]}, {"id": "why-design", "heading": "Vì sao một agent mở, bất-kỳ-mô-hình hợp với công việc thiết kế", "blocks": [{"kind": "p", "text": "OpenCode không có một “mô hình thiết kế” đơn lẻ như cách một agent gắn nhà cung cấp có — và đó chính là điểm mấu chốt. Vì nó không phụ thuộc mô hình và mở, bạn có thể chạy cùng một quy trình thiết kế trên mô hình nào đang giỏi frontend nhất hiện tại, đổi nó về sau, hoặc lùi về một mô hình cục bộ, tất cả mà không thay đổi thiết lập của bạn."}, {"kind": "p", "text": "Nhưng riêng việc chọn mô hình không mua được gu thẩm mỹ. Như mọi agent lập trình, OpenCode tạo ra UI chung chung trừ khi bạn trao cho nó các ràng buộc. Đầu ra thiết kế tốt đến từ ba đầu vào mà bạn cung cấp."}, {"kind": "steps", "items": [{"label": "Một design system", "body": "Tokens, primitive và quy ước thực mà agent tái dùng, để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung."}, {"label": "Một skill thẩm mỹ", "body": "Một skill được tuyển chọn thực thi gu thẩm mỹ thực — chuyển động tiết chế, phân cấp ưu tiên thương hiệu, tối đa hai kiểu chữ và một màu nhấn — và khiến agent cam kết với một định hướng trước khi dựng."}, {"label": "Tham chiếu cụ thể", "body": "Những ảnh tham chiếu thực và nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Sơ đồ thể hiện design system, skill và ảnh tham chiếu hội tụ thành đầu ra thiết kế tốt", "caption": "Gu thẩm mỹ đến từ ba đầu vào mà bạn cung cấp: một design system, một skill và những ảnh tham chiếu thực — bất kể bạn chạy mô hình nào."}, {"kind": "p", "text": "Bài học: OpenCode cho bạn tự do về mô hình, nhưng gu thẩm mỹ vẫn đến từ một ngữ cảnh thiết kế được tuyển chọn. Open Design đóng gói đúng những đầu vào ấy, và đó là lý do hai thứ ăn khớp với nhau — cả hai đều mã nguồn mở và local-first (chi tiết bên dưới)."}]}, {"id": "setup", "heading": "Thiết lập OpenCode cho công việc thiết kế, từ con số không", "blocks": [{"kind": "p", "text": "Đây là toàn bộ lộ trình từ một máy sạch đến một OpenCode có thể dựng và kiểm chứng UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Quy trình thiết lập năm bước: cài đặt, xác thực bằng khóa nhà cung cấp của bạn, cấu hình AGENTS.md, thêm một skill, kiểm chứng", "caption": "Trình tự thiết lập: cài đặt → xác thực (khóa nhà cung cấp của bạn) → cấu hình AGENTS.md → thêm một skill → kiểm chứng trong một trình duyệt thực."}, {"kind": "steps", "items": [{"label": "Mã hóa các quy tắc thiết kế của bạn", "body": "Đặt tokens, primitive và quy ước của bạn vào AGENTS.md (hoặc một DESIGN.md được tham chiếu từ đó) để đầu ra khớp với một thương hiệu thay vì mặc định về một diện mạo chung chung. Tùy chọn instructions trong opencode.json có thể trỏ tới các tệp quy tắc bổ sung qua glob."}, {"label": "Chọn một mô hình có năng lực", "body": "Vì OpenCode không phụ thuộc mô hình, hãy chọn provider/model nào đang mạnh nhất ở frontend hiện tại cho lượt thiết kế — và giữ phần còn lại của quy trình không đổi."}]}]}, {"id": "screenshot-workflow", "heading": "Quy trình ảnh-chụp-thành-UI", "blocks": [{"kind": "p", "text": "Vòng thiết kế đòn bẩy cao nhất với bất kỳ agent nào là biến một ảnh tham chiếu thành UI hoạt động được, responsive và lặp đi lặp lại cho đến khi nó khớp. Cùng dạng năm bước ấy áp dụng trong OpenCode."}, {"kind": "ol", "items": ["Bắt đầu từ những tham chiếu hình ảnh rõ ràng nhất bạn có — và đưa vào nhiều trạng thái (desktop và mobile, hover, rỗng, đang tải), không chỉ một ảnh hero.", "Hãy cụ thể trong prompt; prompt mơ hồ tạo ra UI chung chung.", "Chuẩn bị một design system và cho OpenCode biết tokens cùng các primitive chuẩn nằm ở đâu (trong AGENTS.md).", "Chạy một dev server và để agent render trong một trình duyệt thực, đổi kích thước theo breakpoint để kiểm tra kết quả.", "Lặp lại bằng cách cho OpenCode đối chiếu phần hiện thực của nó với các ảnh chụp — không chỉ xác nhận nó build được."]}, {"kind": "p", "text": "Tham chiếu tệp bằng @ trong TUI để tìm kiếm mờ trong thư mục làm việc của bạn, chạy lệnh shell trực tiếp với một dấu ! ở đầu, và điều khiển hành động bằng các lệnh /. Rồi prompt với các ràng buộc cụ thể:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Giữ prompt nhỏ và tập trung, commit các vòng lặp tốt và hoàn tác các vòng tệ (báo cho OpenCode biết khi bạn hoàn tác), để mỗi lượt dựng trên một nền sạch."}]}, {"id": "extend", "heading": "AGENTS.md, MCP và các phiên chia sẻ được", "blocks": [{"kind": "p", "text": "Ba điểm mở rộng khiến OpenCode thực dụng cho công việc thiết kế bền bỉ, và cả ba đều ánh xạ gọn gàng lên một quy trình thiết kế mở."}, {"kind": "steps", "items": [{"label": "Quy tắc AGENTS.md", "body": "Các quy tắc dự án nằm trong một AGENTS.md ở thư mục gốc repo (hoặc các quy tắc toàn cục trong ~/.config/opencode/AGENTS.md). Đó là nơi trú ngụ bền lâu cho các quy ước thiết kế của bạn, được đọc ở mỗi lần chạy, và nó tương thích với các tệp CLAUDE.md mà các agent khác dùng."}, {"label": "Máy chủ MCP", "body": "OpenCode hỗ trợ cả máy chủ MCP cục bộ (command) lẫn từ xa (URL), được cấu hình dưới khóa mcp — cách di động để mang vào ngữ cảnh thiết kế và các công cụ bên ngoài hoạt động xuyên các agent, không chỉ OpenCode."}, {"label": "Các phiên chia sẻ được", "body": "Lệnh /share tạo một liên kết công khai tới một cuộc hội thoại để cộng tác hoặc review, và /unshare thu hồi nó — hữu ích để lấy phản hồi về một lượt thiết kế."}]}, {"kind": "p", "text": "Đây là những năng lực di động, đa-agent — đúng kiểu thứ mà Open Design được tạo ra để điều phối, thay vì tạo lại theo từng dự án."}]}, {"id": "vs", "heading": "OpenCode so với Codex so với Claude Code so với Cursor cho thiết kế", "blocks": [{"kind": "p", "text": "Không có người thắng cuộc duy nhất cho công việc thiết kế — mỗi agent có một thế mạnh khác nhau, và các đội ngũ giàu kinh nghiệm xếp chồng chúng. Một bản tóm tắt công bằng:"}, {"kind": "table", "columns": ["Agent", "Thế mạnh thiết kế", "Phù hợp nhất cho"], "rows": [["OpenCode", "Mã nguồn mở và không phụ thuộc mô hình; chạy bất kỳ nhà cung cấp nào đứng sau một quy trình terminal", "Tự do BYOK, đổi mô hình, các thiết lập hoàn toàn mở và local-first"], ["Codex", "Độ tinh chỉnh thị giác mạnh với một skill frontend; khả năng hiểu hình ảnh", "Bất đồng bộ được ủy thác, build trong sandbox, quy tắc AGENTS.md di động"], ["Claude Code", "Quyết định thiết kế cụ thể (hex, khoảng cách, kiểu chữ) và UX hiểu codebase", "Lập luận frontend và tái cấu trúc ngữ cảnh lớn"], ["Cursor", "Vòng dựng-và-thấy trực quan với xem trước trực tiếp và chỉnh sửa inline", "Công việc UI lặp-và-quan-sát chặt chẽ bên trong một IDE"]]}, {"kind": "p", "text": "Kết luận lặp đi lặp lại của cộng đồng là gu thẩm mỹ đến từ con người: tất cả chúng đều mặc định về một thẩm mỹ chung chung nếu thiếu skill, tham chiếu và ràng buộc. Đó mới là vấn đề thực cần giải — và nó mang hình hài công cụ thiết kế, chứ không phải hình hài mô hình, đó chính là lý do một agent mở như OpenCode ghép đôi rất hợp với một lớp thiết kế mở."}]}, {"id": "pitfalls", "heading": "Cạm bẫy, và cách tránh diện mạo “AI slop”", "blocks": [{"kind": "p", "text": "Phàn nàn phổ biến nhất về thiết kế do AI tạo ra là nó trông chung chung — gradient mềm, panel lơ lửng, bo góc quá khổ, đổ bóng kịch tính, một cảm giác Inter-và-tím “gào lên rằng AI làm cái này.” Những vấn đề khác được báo cáo gồm bố cục mobile vỡ và phần chỉ dẫn rò rỉ vào nội dung UI. Không điều nào trong số này là riêng có ở OpenCode; chúng là điều xảy ra khi bất kỳ agent nào chạy mà không có một ngữ cảnh thiết kế được tuyển chọn."}, {"kind": "steps", "items": [{"label": "Thêm một skill thẩm mỹ", "body": "Một skill thiết kế được tuyển chọn buộc agent cam kết với một định hướng thực thay vì diện mạo mặc định."}, {"label": "Kiểm chứng trong một trình duyệt thực", "body": "Render và tự kiểm tra trên các breakpoint để bố cục không âm thầm vỡ trên mobile."}, {"label": "Cung cấp tokens và tham chiếu", "body": "Tokens thiết kế thực và ảnh chụp tham chiếu là đòn bẩy lớn nhất duy nhất lên chất lượng đầu ra."}, {"label": "Mã hóa quy tắc trong AGENTS.md", "body": "Đặt những quy tắc kiểu “không thẻ hero, tối đa hai kiểu chữ, phân cấp ưu tiên thương hiệu” ở nơi agent đọc mỗi lần chạy."}]}, {"kind": "p", "text": "Hãy để ý rằng mọi biện pháp giảm thiểu đều xoay quanh việc trao cho agent một ngữ cảnh thiết kế được tuyển chọn — bất kể bạn chạy mô hình nào. Duy trì ngữ cảnh đó bằng tay, theo từng dự án, chính là sự cực nhọc mà Open Design loại bỏ."}]}, {"id": "open-design", "heading": "Thiết kế với OpenCode bên trong Open Design", "blocks": [{"kind": "p", "text": "Open Design là lớp thiết kế mã nguồn mở mà quy trình ở trên cứ liên tục đòi hỏi. Nó coi OpenCode như một adapter hạng nhất và bao bọc nó trong một thư viện skill và design-system được tuyển chọn, một render pipeline có cấu trúc và một giao diện desktop cục bộ — để ngữ cảnh thiết kế giúp bất kỳ agent nào trở nên giỏi đã có sẵn ngay từ lần chạy đầu tiên, chứ không phải ghép lại bằng tay mỗi lần. Cả hai dự án đều mã nguồn mở và local-first, điều khiến sự ghép đôi này là một sự phù hợp tự nhiên."}, {"kind": "ol", "items": ["Cài đặt Open Design và chọn OpenCode làm agent của bạn.", "Xác thực bằng khóa API nhà cung cấp mô hình của riêng bạn (BYOK) — thông tin xác thực ở lại trên máy bạn và không bao giờ được trung chuyển qua chúng tôi.", "Chọn bất kỳ nhà cung cấp và mô hình nào, cùng một design system và một skill, rồi tạo ra deck, prototype và landing page với gu thẩm mỹ nhất quán.", "Mọi sản phẩm và tệp DESIGN.md đều nằm trong repo của riêng bạn, không phải một đám mây được lưu trữ ở nơi khác."]}, {"kind": "p", "text": "Cùng một agent OpenCode, cùng một sự tự do về mô hình — cộng thêm một quy trình thiết kế thực, di động, mã nguồn mở bao quanh nó. Nó local-first và Apache-2.0, nên không gì về công việc hay thông tin xác thực của bạn rời khỏi máy bạn."}]}], "faqTitle": "Câu hỏi thường gặp", "faq": [{"name": "OpenCode có thực sự làm được công việc thiết kế không?", "text": "Có — với một skill thẩm mỹ, một design system và những ảnh tham chiếu thực trong ngữ cảnh, OpenCode tạo ra UI responsive chất lượng sản xuất và có thể kiểm chứng trong trình duyệt. Vì nó không phụ thuộc mô hình, bạn chạy mô hình nào đang giỏi frontend nhất hiện tại. Thiếu ngữ cảnh được tuyển chọn đó, nó có xu hướng mặc định về một diện mạo chung chung, và đó chính là khoảng cách mà Open Design lấp đầy."}, {"name": "Tôi nên dùng mô hình nào với OpenCode cho thiết kế?", "text": "Mô hình nào bạn thích — OpenCode không phụ thuộc nhà cung cấp qua models.dev, nên bạn có thể chạy Anthropic, OpenAI, Google, OpenRouter, hoặc các mô hình cục bộ đứng sau cùng một quy trình và đổi bất cứ lúc nào. Chất lượng đầu ra thiết kế phụ thuộc vào skill, design system và tham chiếu của bạn nhiều hơn nhiều so với riêng mô hình."}, {"name": "Open Design có do đội ngũ OpenCode (SST) làm không?", "text": "Không. Open Design là một dự án mã nguồn mở độc lập tích hợp OpenCode như một agent. Nó bổ sung cho OpenCode bằng một thư viện skill và design-system mở, local-first."}, {"name": "Tôi có cần một gói đăng ký đặc biệt để thiết kế với OpenCode không?", "text": "Không — OpenCode là BYOK. Bạn mang theo khóa API nhà cung cấp mô hình của riêng mình, và Open Design không bao giờ trung chuyển thông tin xác thực của bạn. Không có khóa chặt vào nhà cung cấp."}, {"name": "OpenCode hay Codex hay Claude Code cho thiết kế frontend?", "text": "Tất cả đều mạnh, và nhiều đội xếp chồng chúng. Lợi thế của OpenCode là hoàn toàn mã nguồn mở và không phụ thuộc mô hình; Codex xuất sắc ở các bản build được ủy thác, chạy trong sandbox; Claude Code nổi tiếng với các quyết định thiết kế cụ thể, hiểu codebase. Open Design cho phép bạn đổi agent mà không thay đổi quy trình thiết kế của mình."}, {"name": "Làm sao mở rộng OpenCode cho ngữ cảnh thiết kế?", "text": "Mã hóa quy tắc trong AGENTS.md, thêm các máy chủ MCP dưới khóa mcp cho các công cụ di động và ngữ cảnh thiết kế, và dùng các phiên chia sẻ được để review. Open Design cung cấp một thư viện skill và design-system được tuyển chọn để bạn bỏ qua phần thiết lập theo từng dự án."}, {"name": "Open Design có liên kết với OpenCode hay SST không?", "text": "Không. OpenCode là một dự án mã nguồn mở được SST (Anomaly Innovations) duy trì; Open Design là một dự án mã nguồn mở độc lập hỗ trợ nó như một adapter hạng nhất."}, {"name": "Tệp tin và thông tin xác thực của tôi có an toàn không?", "text": "Có — Open Design là local-first. Tệp tin, sản phẩm và DESIGN.md của bạn ở lại trong repo của riêng bạn, còn thông tin xác thực nhà cung cấp mô hình của bạn được agent của bạn dùng trực tiếp, không bao giờ định tuyến qua máy chủ Open Design."}], "ctaTitle": "Thiết kế với OpenCode, theo cách mở.", "ctaBody": "Mang theo khóa nhà cung cấp mô hình của riêng bạn, giữ mọi tệp tin ở máy, và có một thư viện thiết kế được tuyển chọn bao quanh agent mở bạn đã dùng.", "ctaActions": [{"label": "Dùng OpenCode trong Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gắn sao trên GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Tải ứng dụng desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Xem tất cả agent được hỗ trợ"},
      },
    },
    'pl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code dla projektowania — Open Design",
        description: "Jak projektanci wykorzystują Claude Code do projektowania UI i stron internetowych oraz jak Open Design zamienia go w prawdziwego agenta projektowego — local-first, BYOK, z wyselekcjonowaną biblioteką skills i systemów projektowych.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code dla projektowania.",
        lead: "Claude Code to terminalowy agent kodujący od Anthropic. Ludzie już używają go do budowania interfejsów, systemów projektowych i stron docelowych. Open Design wpina go w prawdziwy proces projektowy — przynieś swój klucz Anthropic lub subskrypcję Claude i zachowaj każdy plik lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Claude Code w local-first, open-source'owego agenta projektowego — twój klucz Anthropic lub subskrypcja Claude, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu — rozumuje o interfejsach z niezwykłą precyzją, podając dokładne wartości hex, odstępy i skale typograficzne, oraz refaktoryzuje UI w dużej bazie kodu, nie gubiąc wątku. Ale prosto z pudełka i tak skłania się ku generycznemu wyglądowi, dopóki nie podasz mu systemu projektowego, skills i prawdziwych referencji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Claude Code do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces z Open Design.", "Obejmuje on to, czym właściwie jest Claude Code, dlaczego jest mocny we frontendzie, jak skonfigurować go od zera, proces pracy z CLAUDE.md i Skills, oficjalny obieg dwukierunkowy z Figmą, jak wypada na tle Codeksa i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Claude Code: terminalowy agent podejmujący konkretne decyzje projektowe, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Claude Code wyrozumowuje konkretne decyzje dotyczące UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz zbiega się ku twoim referencjom."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-claude-code", "label": "Czym właściwie jest Claude Code"}, {"id": "why-design", "label": "Dlaczego Claude Code jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Claude Code do projektowania (od zera)"}, {"id": "skills-workflow", "label": "Proces pracy z CLAUDE.md i Skills"}, {"id": "figma", "label": "Claude Code + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Claude Code kontra Codex kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Claude Code w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Czym właściwie jest Claude Code", "blocks": [{"kind": "p", "text": "Claude Code to agentowe narzędzie do kodowania od Anthropic. Czyta twoją bazę kodu, edytuje pliki, uruchamia polecenia i integruje się z twoimi narzędziami deweloperskimi — planuje, pisze i weryfikuje pracę na podstawie zadań w języku naturalnym, zamiast tylko uzupełniać linijki."}, {"kind": "p", "text": "Dostarczany jest na kilku powierzchniach, które dzielą ten sam silnik: terminalowy CLI, rozszerzenia IDE dla VS Code, Cursora i JetBrains, aplikacja desktopowa z wizualnym przeglądem diffów oraz wersja webowa do długotrwałych zadań. Twoje pliki CLAUDE.md, ustawienia i serwery MCP przenoszą się między nimi wszystkimi."}, {"kind": "steps", "items": [{"label": "Plik instrukcji", "body": "Claude Code czyta plik CLAUDE.md w korzeniu projektu na początku każdej sesji — to naturalne miejsce, by zakodować swoje konwencje projektowe, tokens i listy kontrolne przeglądu."}, {"label": "Skills", "body": "Agent Skills pakują powtarzalne instrukcje, skrypty i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic dla wyczucia smaku."}, {"label": "Plan i podagenci", "body": "Może planować przed działaniem i powoływać podagentów pracujących równolegle nad różnymi częściami zadania, co utrzymuje spójność dużych refaktoryzacji UI."}]}, {"kind": "ul", "items": ["Dostawca: Anthropic", "Poświadczenie: klucz API Anthropic (BYOK, przez Console) lub subskrypcja Claude (Pro / Max)", "Powierzchnie: terminalowy CLI, rozszerzenia VS Code / Cursor / JetBrains, aplikacja desktopowa, web"]}]}, {"id": "why-design", "heading": "Dlaczego Claude Code jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Wśród agentów kodujących Claude Code ma reputację narzędzia o wyczuciu smaku w pracy frontendowej. Wyjaśnia to kilka rzeczy."}, {"kind": "steps", "items": [{"label": "Konkretne, a nie mgliste decyzje", "body": "Claude Code zwykle zobowiązuje się do konkretnych wyborów — dokładnych wartości hex, skal odstępów, ramp typograficznych i hierarchii komponentów — zamiast machać ręką, a właśnie to odróżnia prawdziwy interfejs od atrapy."}, {"label": "Rozumowanie świadome bazy kodu", "body": "Dysponując dużym kontekstem roboczym, refaktoryzuje UI w wielu plikach naraz, ponownie wykorzystując twoje istniejące komponenty i tokens zamiast wymyślać jednorazowe style."}, {"label": "Oficjalny skill frontendowy", "body": "Anthropic dostarcza skill Frontend Design, który sprawia, że Claude najpierw spisuje kierunek projektowy i celowo odchodzi od generycznych czcionek systemowych i przewidywalnych fioletowych gradientów."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, który Anthropic formułuje o własnych modelach: Claude domyślnie nie ma wyczucia smaku — pozostawiony sam sobie zbiega ku statystycznemu środkowi projektowania webowego (Inter, fioletowe gradienty, miękkie cienie). Tworzy dobry projekt, gdy podasz mu ograniczenia. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Claude Code do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Claude Code, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja CLAUDE.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja CLAUDE.md → dodanie skilla Frontend Design → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w CLAUDE.md i nakieruj na nie Claude'a, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Podłącz MCP Playwright lub Chrome, aby Claude renderował w prawdziwej przeglądarce i sprawdzał swój wynik na różnych breakpointach, zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "skills-workflow", "heading": "Proces pracy z CLAUDE.md i Skills", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Claude Code jest podawanie mu prawdziwych referencji wraz z twoim kontekstem projektowym, a następnie iterowanie, aż UI się zgodzi — przy czym CLAUDE.md i Skills niosą ograniczenia, więc nie musisz tłumaczyć ich od nowa przy każdym poleceniu."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI nawet przy silnym agencie.", "Trzymaj swój system projektowy i konwencje w CLAUDE.md i powiedz Claude'owi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Dodaj skill Frontend Design, aby Claude zobowiązał się do prawdziwego kierunku estetycznego, zanim napisze kod.", "Podłącz weryfikację w przeglądarce, aby Claude renderował, zmieniał rozmiar do breakpointów i porównywał z referencjami — a nie tylko potwierdzał, że się buduje."]}, {"kind": "p", "text": "Wrzuć obraz referencyjny do sesji i daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Uruchom obok serwer deweloperski, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Claude'owi, kiedy cofasz), aby każde przejście budowało na czystej bazie. Używaj trybu planu do większych refaktoryzacji, abyś mógł przejrzeć podejście przed jakąkolwiek zmianą plików."}]}, {"id": "figma", "heading": "Claude Code + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 Anthropic i Figma dostarczyły pierwszorzędną, dwukierunkową integrację za pośrednictwem serwera Figma MCP. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Zaznacz ramkę w Figmie lub wklej link do Claude Code, pobierz kontekst projektowy i poproś go o implementację projektu z użyciem twojej istniejącej biblioteki komponentów. Code Connect utrzymuje wynik zgodny z twoimi rzeczywistymi komponentami."}, {"label": "Kod → Projekt", "body": "Zbuduj i podejrzyj funkcję w przeglądarce, a następnie powiedz „Send this to Figma”, aby uchwycić działające UI jako edytowalne warstwy Figmy — cały ekran lub wybrany element."}]}, {"kind": "p", "text": "Zainstaluj go raz poleceniem claude plugin install figma@claude-plugins-official (Dev Mode MCP wymaga płatnego planu Figma). Ten sam Figma MCP jest dostępny dla Claude Code, Codeksa, Cursora i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Claude Code kontra Codex kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i rozumowanie UX świadome bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Codex", "Mocne dopracowanie wizualne i rozumienie obrazów; asynchroniczne buildy w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Nawet przy reputacji Claude Code za wyczucie smaku najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — czcionki Inter, fioletowe gradienty na bieli, miękkie cienie, przeskalowane zaokrąglone rogi, estetyka, która „krzyczy, że zrobiło to AI”. Sam Anthropic przypisuje to zbieżności rozkładowej: bezpieczne wybory dominują w danych treningowych z sieci. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill Frontend Design", "body": "Zmusza Claude'a do zobowiązania się do prawdziwego kierunku i wyraźnie unika czcionek oraz gradientów nadużywanych przez AI."}, {"label": "Włącz weryfikację w przeglądarce", "body": "Spraw, aby Claude renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w CLAUDE.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Claude Code wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Claude Code jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Claude Code dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Claude Code jako swojego agenta.", "Uwierzytelnij się swoim kluczem API Anthropic (BYOK) lub subskrypcją Claude — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Claude Code, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Claude Code nadaje się do pracy projektowej?", "text": "Tak — jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu, podejmującego konkretne, świadome bazy kodu decyzje dotyczące wartości hex, odstępów i skal typograficznych. Mając w kontekście skill Frontend Design, system projektowy i prawdziwe obrazy referencyjne, tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy potrzebuję subskrypcji Claude, aby projektować z Claude Code?", "text": "Możesz użyć albo klucza API Anthropic (BYOK, przez Console), albo subskrypcji Claude (Pro / Max). Tak czy inaczej Open Design nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta na twojej maszynie."}, {"name": "Claude Code czy Codex do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych i rozumowania frontendowego; Codex ma mocne dopracowanie wizualne i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Claude Code z Figmą?", "text": "Zainstaluj oficjalny plugin Figma poleceniem claude plugin install figma@claude-plugins-official. Następnie możesz implementować ramki Figmy w kodzie z użyciem kontekstu projektowego oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą „Send this to Figma”. Dev Mode MCP wymaga płatnego planu Figma."}, {"name": "Czym są Skills i CLAUDE.md?", "text": "CLAUDE.md to plik markdown w korzeniu projektu, który Claude Code czyta na początku każdej sesji — miejsce na zakodowanie twoich konwencji projektowych. Skills pakują powtarzalne instrukcje i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic. Open Design dostarcza wyselekcjonowaną bibliotekę obu, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill Frontend Design, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w CLAUDE.md oraz włącz weryfikację w przeglądarce. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Anthropic?", "text": "Nie. Claude Code jest produktem Anthropic; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Claude i Claude Code są znakami towarowymi Anthropic."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Anthropic są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Claude Code, w otwarty sposób.", "ctaBody": "Przynieś własny klucz Anthropic lub subskrypcję Claude, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenAI Codex do projektowania UI i stron internetowych — plugin Product Design, integracja z Figmą, skills frontendowe — i jak Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex dla projektowania.",
        lead: "Codex to agent kodujący od OpenAI. Dzięki swojemu pluginowi Product Design i integracji z Figmą stał się poważnym narzędziem projektowym. Open Design wpina Codeksa w open-source'owy proces projektowy — twój klucz OpenAI lub subskrypcja ChatGPT, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego — twój klucz OpenAI, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex zaczynał jako generator kodu, ale w 2026 stał się wiarygodnym narzędziem do projektowania prawdziwych interfejsów — gdy tylko podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Codeksa do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym Codex jest dzisiaj, dlaczego nagle jest dobry we frontendzie, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, oficjalny dwukierunkowy obieg z Figmą, jak wypada na tle Cursora i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Codeksem: terminalowy agent, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Codex buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-codex", "label": "Czym właściwie jest OpenAI Codex"}, {"id": "why-design", "label": "Dlaczego Codex jest teraz dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Codeksa do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "figma", "label": "Codex + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Codex kontra Cursor kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Codeksem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Czym właściwie jest OpenAI Codex (a czym nie jest)", "blocks": [{"kind": "p", "text": "Najpierw rozróżnienie, które myli niemal każdego, kto szuka „Codeksa”. Pierwotny OpenAI Codex był modelem uzupełniania kodu z 2021 roku, który napędzał wczesny GitHub Copilot i został wycofany w 2023. Nie o tym jest ta strona. Dzisiejszy Codex to agentowe narzędzie do kodowania od OpenAI — planuje, pisze, uruchamia i weryfikuje kod na podstawie zadań w języku naturalnym."}, {"kind": "p", "text": "Nowoczesny Codex dostarczany jest na czterech powierzchniach: terminalowy CLI (przepisany w Rust, na licencji Apache-2.0), rozszerzenie IDE dla VS Code, Cursora i Windsurfa, doświadczenie chmurowe/webowe do delegowanych zadań asynchronicznych oraz aplikacja desktopowa z wbudowaną przeglądarką i Computer Use."}, {"kind": "steps", "items": [{"label": "Domyślny model", "body": "Od połowy 2026 zalecanym modelem jest gpt-5.5, przy czym gpt-5.4 to model, który OpenAI wprost wytrenowało pod frontend i computer use."}, {"label": "Plik instrukcji", "body": "Codex czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe."}, {"label": "Sandbox", "body": "Działa w sandboksie na poziomie jądra (domyślnie workspace-write), więc agent edytujący twoje UI nie może wyjść poza projekt."}]}, {"kind": "ul", "items": ["Dostawca: OpenAI", "Poświadczenie: klucz API OpenAI (BYOK) lub subskrypcja ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencja CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego Codex jest teraz dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Na początku 2026 zbiegły się trzy rzeczy, które uczyniły z Codeksa prawdziwe narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Model wytrenowany pod frontend", "body": "OpenAI dostarczyło GPT-5.4, swój pierwszy główny model wytrenowany pod frontend i computer use, ze znacznie lepszym rozumieniem obrazów w całym procesie projektowym i silniejszą samoweryfikacją. Potrafi nawet generować mood boardy i opcje wizualne, zanim zobowiąże się do finalnych zasobów."}, {"label": "Oficjalny skill frontendowy", "body": "Katalog openai/skills dostarcza wyselekcjonowany skill frontendowy, który egzekwuje prawdziwe wyczucie smaku: układy bez kart, hero na całą szerokość, hierarchia stawiająca markę na pierwszym miejscu, powściągliwy ruch, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że Codex spisuje tezę wizualną przed budowaniem."}, {"label": "Weryfikacja w przeglądarce", "body": "Dzięki skillowi Playwright Codex otwiera prawdziwą przeglądarkę, zmienia rozmiar do breakpointów i porównuje swój wynik z referencją, zamiast tylko sprawdzać, że build przechodzi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek za całą trójką: Codex domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Codeksa do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Codeksa, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja, instalacja skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja AGENTS.md → instalacja skilla frontendowego → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md lub DESIGN.md i nakieruj na nie Codeksa, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Wybierz właściwy poziom rozumowania", "body": "OpenAI zauważa, że niskie-do-średnich poziomy rozumowania często dają silniejsze rezultaty frontendowe niż ustawienie najwyższe."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Codeksem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Własne wskazówki OpenAI sprowadzają się do pięciu kroków."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Codeksowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Włącz interaktywny skill Playwright, aby Codex renderował w prawdziwej przeglądarce i zmieniał rozmiar do breakpointów.", "Iteruj, każąc Codeksowi porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Podaj obrazy, przeciągając zrzut ekranu do terminala lub używając flagi obrazu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Uruchom serwer deweloperski w drugim terminalu, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Codeksowi, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "figma", "heading": "Codex + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 OpenAI i Figma ogłosiły oficjalne partnerstwo, zamieniając wcześniejszą betę Figma MCP w pierwszorzędną, dwukierunkową integrację. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj „link to selection” ramki w Figmie, wklej go do Codeksa z get_design_context i poproś o implementację projektu z użyciem twojej istniejącej biblioteki komponentów."}, {"label": "Kod → Projekt", "body": "Narzędzie generate_figma_design („Code to Canvas”) zamienia działające, uruchomione UI z powrotem w edytowalne ramki Figmy — cały ekran, wybrany element lub cały plik."}]}, {"kind": "p", "text": "Figma MCP działa jako serwer zdalny i jest zwolniony z limitów przepustowości. Dodaj go raz, a jest dostępny dla Codeksa, Claude Code, Cursora, VS Code i innych — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Codex kontra Cursor kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Codex", "Mocne dopracowanie wizualne po GPT-5.4 + skill frontendowy; rozumienie obrazów", "Delegowane asynchroniczne buildy, uruchomienia w sandboksie, przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Codeksa jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne, przeciekanie instrukcji do treści UI oraz szybkie osiąganie limitów użycia."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill frontendowy", "body": "Wyselekcjonowany skill estetyczny zmusza Codeksa do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Włącz weryfikację Playwright", "body": "Spraw, aby Codex renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Codeksem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Codeksa jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Codeksa dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Codeksa jako swojego agenta.", "Uwierzytelnij się swoim kluczem API OpenAI (BYOK) lub subskrypcją ChatGPT — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Codex, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenAI Codex naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill frontendowy, system projektowy i prawdziwe obrazy referencyjne, Codex (zwłaszcza na GPT-5.4) tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to plugin Product Design od OpenAI Codex?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Codeksa jako agenta. Uzupełnia własne narzędzia OpenAI o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji ChatGPT, aby projektować z Codeksem?", "text": "Możesz użyć albo klucza API OpenAI (BYOK), albo swojej subskrypcji ChatGPT. Logowanie do ChatGPT zazwyczaj daje hojniejsze limity; Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń."}, {"name": "Codex czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; Codex ma mocne dopracowanie wizualne po GPT-5.4 i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Codeksa z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Następnie możesz implementować ramki Figmy w kodzie za pomocą get_design_context oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą generate_figma_design."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill frontendowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w AGENTS.md oraz włącz weryfikację Playwright. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenAI?", "text": "Nie. Codex jest produktem OpenAI; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. OpenAI i Codex są znakami towarowymi OpenAI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia OpenAI są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Codeksem, w otwarty sposób.", "ctaBody": "Przynieś własny klucz OpenAI, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor dla projektantów — Open Design",
        description: "Jak projektanci wykorzystują Cursora do projektowania UI i stron internetowych — Design Mode, Figma-do-kodu, Figma MCP — i jak Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor dla projektantów.",
        lead: "Cursor to edytor kodu oparty na AI, teraz z wizualnym Design Mode. Projektanci używają go do edycji UI poprzez wskazywanie i rysowanie oraz do zamiany Figmy w kod. Open Design wpina Cursor Agent w open-source'owy proces projektowy, który zachowuje twoje pliki lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego — twoje konto Cursor lub klucze modeli, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor to edytor kodu AI-first, który uczynił z „zbuduj i obserwuj, jak się renderuje” domyślny sposób dostarczania UI. Dzięki trybowi Agent, edycjom inline, podglądowi w edytorze i Figmie przez MCP stał się prawdziwym narzędziem projektowym — gdy tylko podasz mu właściwe referencje, reguły i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Cursora do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest Cursor, dlaczego jego ciasna pętla iteruj-i-obserwuj jest dobra do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-i-podgląd-do-UI, dwukierunkowy obieg z Figmą przez MCP, jak wypada na tle Codeksa i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Zbieżność projektowa Cursora: edytor po lewej, wyselekcjonowane centrum skills i systemu projektowego pośrodku ze znakiem Cursora w środku oraz wyrenderowane UI po prawej", "caption": "Główna idea: Cursor edytuje i renderuje UI w edytorze, podczas gdy wyselekcjonowane centrum projektowe zasila go systemem, skills i referencjami, które sprawiają, że wynik wygląda celowo."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-cursor", "label": "Czym właściwie jest Cursor"}, {"id": "why-design", "label": "Dlaczego Cursor jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Cursora do projektowania (od zera)"}, {"id": "preview-workflow", "label": "Proces podgląd-do-UI"}, {"id": "figma", "label": "Cursor + Figma przez MCP"}, {"id": "vs", "label": "Cursor kontra Codex kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Cursorem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Czym właściwie jest Cursor", "blocks": [{"kind": "p", "text": "Cursor to edytor kodu AI-first zbudowany przez Anysphere. To fork VS Code, więc zachowuje znajomy edytor, rozszerzenia i skróty klawiszowe, ale przebudowuje proces wokół agenta AI, który potrafi czytać cały twój projekt, edytować wiele plików, uruchamiać polecenia i iterować z tobą w pętli."}, {"kind": "p", "text": "Do pracy projektowej ważnymi powierzchniami są tryb Agent (opisujesz wynik, a Cursor planuje i edytuje w wielu plikach), edycje inline i uzupełnienia Tab do szybkich poprawek, podgląd / przeglądarka w edytorze, dzięki czemu widzisz działające UI bez opuszczania okna, oraz wsparcie MCP, które pozwala mu wciągać zewnętrzny kontekst, jak żywy plik Figmy."}, {"kind": "steps", "items": [{"label": "Reguły projektu", "body": "Cursor czyta pliki instrukcji projektu — wersjonowane reguły `.mdc` w `.cursor/rules` oraz zwykły `AGENTS.md` — więc możesz zakodować swoje konwencje projektowe tam, gdzie agent czyta je przy każdym uruchomieniu."}, {"label": "Modele", "body": "Cursor jest elastyczny pod względem modeli: dostarczany jest z czołowymi modelami przez twoją subskrypcję, a także obsługuje wnoszenie własnych kluczy modeli, więc wybierasz silnik stojący za tym samym procesem w edytorze."}, {"label": "MCP", "body": "Mówi w Model Context Protocol, więc zewnętrzne serwery — najistotniejszy serwer Figma MCP — stają się pierwszorzędnym kontekstem dla agenta."}]}, {"kind": "ul", "items": ["Dostawca: Anysphere", "Poświadczenie: konto / subskrypcja Cursor (Hobby / Pro / Business) lub własne klucze modeli (BYOK)", "Forma: edytor kodu AI-first (fork VS Code) z agentem i podglądem w edytorze"]}]}, {"id": "why-design", "heading": "Dlaczego Cursor jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Przewaga projektowa Cursora to nie pojedyncza funkcja — to ciasność pętli buduj-i-zobacz. Trzy rzeczy sprawiają, że odczuwa się go jak narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Ciasna pętla iteruj-i-obserwuj", "body": "Dajesz polecenie, Cursor edytuje w wielu plikach, a podgląd w edytorze natychmiast renderuje wynik — więc dostrajasz odstępy, hierarchię i ruch w sekundy, zamiast krążyć przez osobny terminal i przeglądarkę."}, {"label": "Bezpośrednia edycja wizualna", "body": "Poza czatem Cursor pozwala zaznaczać elementy w podglądzie i korygować style, więc drobne poprawki wizualne odczuwa się jak edycje projektowe, a nie archeologię kodu."}, {"label": "Reguły projektu i kontekst MCP", "body": "Dzięki `.cursor/rules` (lub `AGENTS.md`) i serwerowi Figma MCP agent pracuje względem twoich tokens, komponentów i prawdziwych specyfikacji projektowych zamiast zgadywać."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, którego uczy każdy agent: Cursor domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Cursora do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Cursora, który potrafi budować, podglądać i weryfikować UI względem twojego systemu projektowego."}, {"kind": "ol", "items": ["Zainstaluj Cursora z cursor.com i zaloguj się swoim kontem Cursor lub skonfiguruj własne klucze modeli (BYOK) w Ustawieniach.", "Otwórz swój projekt i wybierz model w panelu czatu / Agent.", "Dodaj reguły projektu: utwórz `.cursor/rules/*.mdc` dla ustrukturyzowanych, ograniczonych globami konwencji lub zwykły `AGENTS.md` dla prostych, czytelnych instrukcji.", "Połącz serwer Figma MCP (opcjonalnie), aby agent mógł czytać żywy kontekst projektowy.", "Uruchom serwer deweloperski i używaj podglądu w edytorze, aby widzieć i weryfikować UI w trakcie iterowania."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja reguł, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja reguł projektu → dodanie skilla → włączenie weryfikacji w podglądzie."}, {"kind": "p", "text": "Minimalny plik reguł projektu sprawia, że agent projektuje pod markę zamiast domyślać się generycznego wyglądu. Umieść go tam, gdzie Cursor czyta go przy każdym uruchomieniu:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w `.cursor/rules` lub `AGENTS.md` i nakieruj na nie Cursora, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Trzymaj polecenia krótkie", "body": "Ciasna pętla Cursora nagradza skupione prośby — iteruj po jednym komponencie lub stanie naraz i obserwuj podgląd między przejściami."}]}]}, {"id": "preview-workflow", "heading": "Proces podgląd-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Cursorem jest zamiana referencji w działające, responsywne UI i iterowanie w edytorze, aż się zgodzi — obserwując podgląd na żywo przez cały czas zamiast zgadywać."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Cursorowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Trzymaj podgląd w edytorze otwarty, a serwer deweloperski uruchomiony, aby każda edycja renderowała się natychmiast na breakpointach, na których ci zależy.", "Iteruj, porównując wyrenderowane UI z powrotem z referencjami — i używaj bezpośredniego zaznaczania elementów w podglądzie do drobnych poprawek wizualnych."]}, {"kind": "p", "text": "Podaj referencje, dołączając obraz do czatu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commituj dobre iteracje i cofaj złe (mówiąc Cursorowi, kiedy cofasz), aby każde przejście budowało na czystej bazie — ta sama dyscyplina, która chroni każdą pętlę agenta przed dryfowaniem."}]}, {"id": "figma", "heading": "Cursor + Figma: projekt ↔ kod przez MCP", "blocks": [{"kind": "p", "text": "Cursor łączy się z Figmą przez oficjalny serwer Figma MCP, który daje agentowi ustrukturyzowany dostęp do żywego pliku Figmy zamiast płaskiego zrzutu ekranu. To usuwa zgadywanie z przekazania."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj link ramki w Figmie, wklej go do Cursora i poproś o implementację projektu. Serwer MCP udostępnia prawdziwy kontekst projektowy — komponenty, zmienne, dane układu, tokens — więc wygenerowany kod pasuje do źródła zamiast je przybliżać."}, {"label": "Zachowaj zgodność", "body": "Przy spójnie używanych w Figmie design tokens, stylach i komponentach (oraz Code Connect tam, gdzie jest dostępny) wynik Cursora pozostaje zmapowany na twój prawdziwy system projektowy zamiast wymyślać prymitywy na nowo."}]}, {"kind": "p", "text": "Skonfiguruj zdalny serwer Figma MCP raz, a jest dostępny dla Cursora jako pierwszorzędny kontekst. Ponieważ MCP jest otwartym standardem, ten sam serwer można ponownie wykorzystać w Cursorze, Claude Code, Codeksie i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Cursor kontra Codex kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo w edytorze i bezpośrednią edycją elementów", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów i uruchomienia w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Cursora jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to układy psujące się na mobile oraz przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Dodaj skill projektowy", "body": "Wyselekcjonowany skill estetyczny zmusza Cursora do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Użyj podglądu do weryfikacji", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach w podglądzie w edytorze, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w `.cursor/rules`", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Cursorem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Cursora jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Cursora dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Cursora jako swojego agenta.", "Uwierzytelnij się swoim kontem Cursor lub własnymi kluczami modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Cursor, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Cursor naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill projektowy, system projektowy i prawdziwe obrazy referencyjne, Cursor tworzy responsywne UI o jakości produkcyjnej, a jego podgląd w edytorze pozwala je wizualnie zweryfikować i dopracować. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to oficjalny produkt Cursora?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Cursora jako agenta. Uzupełnia Cursora o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji Cursor, aby projektować z Cursorem?", "text": "Możesz użyć konta / subskrypcji Cursor albo wnieść własne klucze modeli (BYOK). Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta."}, {"name": "Cursor czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; przewagą Cursora jest jego ciasna pętla buduj-i-zobacz z podglądem na żywo wewnątrz edytora. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Cursora z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP w Cursorze, a następnie wklej link ramki Figmy do czatu i poproś Cursora o jej implementację. Serwer udostępnia prawdziwe komponenty, zmienne i dane układu, więc wygenerowany kod pasuje do źródłowego projektu."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Dodaj skill projektowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w `.cursor/rules` lub `AGENTS.md` oraz weryfikuj na różnych breakpointach w podglądzie. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Cursorem lub Anysphere?", "text": "Nie. Cursor jest produktem Anysphere; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Cursor i Anysphere są znakami towarowymi Anysphere, Inc."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Cursora lub modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Cursorem, w otwarty sposób.", "ctaBody": "Przynieś własne konto Cursor lub klucze modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenCode do projektowania UI i stron internetowych — pliki design.md, skills UI/UX, Figma MCP — i jak Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode dla projektowania.",
        lead: "OpenCode to open-source'owy, terminalowy agent kodujący AI. Projektanci dokręcają do niego skills projektowe i pliki DESIGN.md, aby generować prawdziwe UI. Open Design czyni z tego ustrukturyzowany, open-source'owy proces — przynieś swoje klucze dostawców i zachowaj wszystko lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego — dowolny model, który wybierzesz, z własnym kluczem dostawcy, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode to open-source'owy, terminalowy w pierwszej kolejności agent kodujący AI, który jest celowo niezależny od modelu: przynosisz własny klucz dostawcy i uruchamiasz dowolny model za tym samym procesem. Ta otwartość czyni go naturalną bazą do pracy projektowej — ale jak każdy agent, tworzy dobre UI tylko wtedy, gdy podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu OpenCode do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest OpenCode, dlaczego niezależny od modelu otwarty agent jest dobrym wyborem do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, jak AGENTS.md i MCP go rozszerzają, jak wypada na tle Codeksa, Claude Code i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, skoro oba projekty są open-source i działają na twojej własnej maszynie."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z OpenCode: terminalowy agent TUI, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: OpenCode buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji — na dowolnym modelu, który wybierzesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-opencode", "label": "Czym właściwie jest OpenCode"}, {"id": "why-design", "label": "Dlaczego otwarty, dowolnomodelowy agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj OpenCode do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "extend", "label": "AGENTS.md, MCP i udostępnialne sesje"}, {"id": "vs", "label": "OpenCode kontra Codex kontra Claude Code kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z OpenCode w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Czym właściwie jest OpenCode", "blocks": [{"kind": "p", "text": "OpenCode to open-source'owy agent kodujący AI zbudowany pod terminal, utrzymywany przez zespół stojący za SST (Anomaly Innovations). Czyta twoje repozytorium, uruchamia polecenia, edytuje pliki i rozmawia z dużym modelem językowym — ale w przeciwieństwie do agentów związanych z dostawcą nie dostarcza własnego modelu. Kierujesz go na dowolnego dostawcę i model, jaki chcesz, i przynosisz własny klucz."}, {"kind": "p", "text": "Działa jako terminalowy interfejs (TUI), z aplikacją desktopową i rozszerzeniami IDE nadbudowanymi na tym samym silniku. Pod maską używa architektury klient/serwer, więc agent wykonujący pracę jest odsprzężony od powierzchni, z której nim sterujesz. Dwaj wbudowani agenci — build i plan — przełączają się klawiszem Tab."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu", "body": "Modele i dostawcy pochodzą z models.dev, otwartego katalogu. Konfigurujesz je w opencode.json łańcuchem provider/model-id i możesz wyłączać dostawców, których nie chcesz ładować — więc ten sam proces projektowy działa na Anthropic, OpenAI, Google, OpenRouter, modelach lokalnych i innych."}, {"label": "Plik instrukcji", "body": "OpenCode czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy, zgodny także z CLAUDE.md) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe. Uruchom /init, aby wygenerować jeden."}, {"label": "Rozszerzalny", "body": "Obsługuje integrację LSP, serwery MCP, motywy, skróty klawiszowe i niestandardowe polecenia, a także udostępnialne linki do sesji dla współpracy."}]}, {"kind": "ul", "items": ["Opiekun: SST / Anomaly Innovations (projekt open-source)", "Poświadczenie: twój własny klucz/klucze API dostawcy modeli — BYOK, bez uwiązania do dostawcy", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego otwarty, dowolnomodelowy agent pasuje do pracy projektowej", "blocks": [{"kind": "p", "text": "OpenCode nie ma jednego „modelu projektowego” tak jak agent związany z dostawcą — i o to właśnie chodzi. Ponieważ jest niezależny od modelu i otwarty, możesz uruchamiać ten sam proces projektowy na modelu, który aktualnie jest najlepszy we frontendzie, później go wymienić lub cofnąć się do modelu lokalnego, a wszystko to bez zmiany konfiguracji."}, {"kind": "p", "text": "Ale sam wybór modelu nie kupuje wyczucia smaku. Jak każdy agent kodujący, OpenCode tworzy generyczne UI, dopóki nie podasz mu ograniczeń. Dobry wynik projektowy bierze się z trzech wkładów, które dostarczasz."}, {"kind": "steps", "items": [{"label": "System projektowy", "body": "Prawdziwe tokens, prymitywy i konwencje, które agent ponownie wykorzystuje, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Skill estetyczny", "body": "Wyselekcjonowany skill, który egzekwuje prawdziwe wyczucie smaku — powściągliwy ruch, hierarchia stawiająca markę na pierwszym miejscu, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że agent zobowiązuje się do kierunku przed budowaniem."}, {"label": "Konkretne referencje", "body": "Faktyczne obrazy referencyjne i wiele stanów (desktop i mobile, hover, pusty, ładowanie), a nie pojedynczy kadr bohaterski."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych — niezależnie od tego, który model uruchamiasz."}, {"kind": "p", "text": "Wniosek: OpenCode daje ci swobodę modelu, ale wyczucie smaku wciąż bierze się z wyselekcjonowanego kontekstu projektowego. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują — oba są open-source i local-first (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj OpenCode do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do OpenCode, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie kluczem dostawcy, konfiguracja AGENTS.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie (twój klucz dostawcy) → konfiguracja AGENTS.md → dodanie skilla → weryfikacja w prawdziwej przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md (lub DESIGN.md przywoływanym z niego), aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu. Opcja instructions w opencode.json może wskazywać na dodatkowe pliki reguł przez globy."}, {"label": "Wybierz zdolny model", "body": "Ponieważ OpenCode jest niezależny od modelu, wybierz dostawcę/model aktualnie najsilniejszy we frontendzie na przejście projektowe — i zostaw resztę swojego procesu bez zmian."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z dowolnym agentem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Ten sam pięciokrokowy kształt obowiązuje w OpenCode."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz OpenCode, gdzie znajdują się tokens i kanoniczne prymitywy (w AGENTS.md).", "Uruchom serwer deweloperski i każ agentowi renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, każąc OpenCode porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Odwołuj się do plików za pomocą @ w TUI, aby uzyskać rozmyte wyszukiwanie w twoim katalogu roboczym, uruchamiaj polecenia powłoki inline z wiodącym !, a akcjami steruj poleceniami /. Następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Trzymaj polecenia krótkie i skupione, commituj dobre iteracje i cofaj złe (mówiąc OpenCode, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "AGENTS.md, MCP i udostępnialne sesje", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią OpenCode praktycznym do długotrwałej pracy projektowej, a wszystkie trzy czysto odwzorowują się na otwarty proces projektowy."}, {"kind": "steps", "items": [{"label": "Reguły AGENTS.md", "body": "Reguły projektu żyją w AGENTS.md w korzeniu repozytorium (lub reguły globalne w ~/.config/opencode/AGENTS.md). To trwały dom dla twoich konwencji projektowych, czytany przy każdym uruchomieniu, i jest zgodny z plikami CLAUDE.md, których używają inne agenty."}, {"label": "Serwery MCP", "body": "OpenCode obsługuje zarówno lokalne (command), jak i zdalne (URL) serwery MCP, konfigurowane pod kluczem mcp — przenośny sposób wnoszenia kontekstu projektowego i zewnętrznych narzędzi, które działają w wielu agentach, nie tylko w OpenCode."}, {"label": "Udostępnialne sesje", "body": "Polecenie /share tworzy publiczny link do rozmowy dla współpracy lub przeglądu, a /unshare go odwołuje — przydatne do uzyskania informacji zwrotnej na temat przejścia projektowego."}]}, {"kind": "p", "text": "To są przenośne, wieloagentowe możliwości — dokładnie to, do orkiestracji czego zbudowany jest Open Design, zamiast odtwarzać je dla każdego projektu z osobna."}]}, {"id": "vs", "heading": "OpenCode kontra Codex kontra Claude Code kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["OpenCode", "Open-source i niezależny od modelu; uruchom dowolnego dostawcę za jednym terminalowym procesem", "Swoboda BYOK, przełączanie modeli, w pełni otwarte i local-first konfiguracje"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów", "Delegowane asynchroniczne, buildy w sandboksie, przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: wszystkie z nich domyślnie zbiegają ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu, co jest dokładnie powodem, dla którego otwarty agent jak OpenCode tak dobrze łączy się z otwartą warstwą projektową."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI. Żaden z nich nie jest charakterystyczny wyłącznie dla OpenCode; to się dzieje, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego — niezależnie od tego, który model uruchamiasz. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z OpenCode wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje OpenCode jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni dowolnego agenta dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym dopasowaniem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz OpenCode jako swojego agenta.", "Uwierzytelnij się własnym kluczem API dostawcy modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz dowolnego dostawcę i model, a także system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent OpenCode, ta sama swoboda modelu — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenCode naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, OpenCode tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Ponieważ jest niezależny od modelu, uruchamiasz model aktualnie najlepszy we frontendzie. Bez tego wyselekcjonowanego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Którego modelu powinienem użyć z OpenCode do projektowania?", "text": "Dowolnego, jaki lubisz — OpenCode jest niezależny od dostawcy przez models.dev, więc możesz uruchamiać Anthropic, OpenAI, Google, OpenRouter lub modele lokalne za tym samym procesem i przełączać się w dowolnym momencie. Jakość wyniku projektowego zależy znacznie bardziej od twojego skilla, systemu projektowego i referencji niż od samego modelu."}, {"name": "Czy Open Design jest tworzony przez zespół OpenCode (SST)?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje OpenCode jako agenta. Uzupełnia OpenCode o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję specjalnej subskrypcji, aby projektować z OpenCode?", "text": "Nie — OpenCode jest BYOK. Przynosisz własny klucz API dostawcy modeli, a Open Design nigdy nie przekierowuje twoich poświadczeń. Nie ma uwiązania do dostawcy."}, {"name": "OpenCode, Codex czy Claude Code do projektowania frontendu?", "text": "Wszystkie są mocne, a wiele zespołów zestawia je ze sobą. Przewagą OpenCode jest bycie w pełni open-source i niezależnym od modelu; Codex wyróżnia się w delegowanych buildach w sandboksie; Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych. Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak rozszerzyć OpenCode o kontekst projektowy?", "text": "Zakoduj reguły w AGENTS.md, dodaj serwery MCP pod kluczem mcp dla przenośnych narzędzi i kontekstu projektowego oraz używaj udostępnialnych sesji do przeglądu. Open Design dostarcza wyselekcjonowaną bibliotekę skills i systemów projektowych, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenCode lub SST?", "text": "Nie. OpenCode to projekt open-source utrzymywany przez SST (Anomaly Innovations); Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia dostawcy modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z OpenCode, w otwarty sposób.", "ctaBody": "Przynieś własny klucz dostawcy modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół otwartego agenta, którego już używasz.", "ctaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
    },
    'id': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code untuk desain — Open Design",
        description: "Bagaimana desainer menggunakan Claude Code untuk desain UI dan web, dan bagaimana Open Design mengubahnya menjadi agen desain sungguhan — local-first, BYOK, dengan pustaka skill dan design system yang terkurasi.",
        breadcrumb: "Claude Code",
        label: "Agen · Claude Code",
        heading: "Claude Code untuk desain.",
        lead: "Claude Code adalah agen coding terminal dari Anthropic. Orang sudah menggunakannya untuk membangun UI, design system, dan landing page. Open Design menghubungkannya ke alur kerja desain sungguhan — bawa kunci Anthropic atau langganan Claude Anda, simpan setiap file secara lokal.",
        rich: {"heroCtaLead": "Open Design mengubah Claude Code menjadi agen desain open-source yang local-first — kunci Anthropic atau langganan Claude Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Claude Code di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code secara luas dianggap sebagai agen coding dengan selera frontend terbaik — ia bernalar tentang antarmuka dengan kekhususan yang tidak biasa, menyebutkan nilai hex, spacing, dan type scale yang persis, serta merefaktor UI di seluruh codebase besar tanpa kehilangan alur pikir. Namun secara default, ia masih cenderung mengarah ke tampilan generik kecuali Anda memberikannya design system, skill, dan referensi nyata. Ini adalah panduan praktis end-to-end untuk menggunakan Claude Code dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke dalam alur kerja terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya Claude Code itu, mengapa ia kuat di frontend, cara menyiapkannya dari nol, alur kerja CLAUDE.md dan Skills, round-trip Figma resmi, perbandingannya dengan Codex dan Cursor, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Loop umpan balik desain Claude Code: agen terminal yang membuat keputusan desain spesifik, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: Claude Code menalar keputusan UI yang spesifik di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengonvergensikannya terhadap referensi Anda."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-claude-code", "label": "Apa sebenarnya Claude Code itu"}, {"id": "why-design", "label": "Mengapa Claude Code bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Claude Code untuk desain (dari nol)"}, {"id": "skills-workflow", "label": "Alur kerja CLAUDE.md dan Skills"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Claude Code di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Apa sebenarnya Claude Code itu", "blocks": [{"kind": "p", "text": "Claude Code adalah alat coding agentic dari Anthropic. Ia membaca codebase Anda, menyunting file, menjalankan perintah, dan terintegrasi dengan alat pengembangan Anda — merencanakan, menulis, dan memverifikasi pekerjaan dari tugas berbahasa alami, bukan sekadar melengkapi baris secara otomatis."}, {"kind": "p", "text": "Ia hadir di beberapa permukaan yang semuanya berbagi mesin yang sama: CLI terminal, ekstensi IDE untuk VS Code, Cursor, dan JetBrains, aplikasi desktop dengan tinjauan diff visual, serta pengalaman web untuk tugas yang berjalan lama. File CLAUDE.md, pengaturan, dan server MCP Anda terbawa di semuanya."}, {"kind": "steps", "items": [{"label": "File instruksi", "body": "Claude Code membaca file CLAUDE.md di root proyek Anda pada awal setiap sesi — tempat alami untuk menuliskan konvensi desain, tokens, dan checklist tinjauan Anda."}, {"label": "Skills", "body": "Agent Skills mengemas instruksi, skrip, dan sumber daya yang dapat diulang yang dimuat Claude sesuai kebutuhan, termasuk skill Frontend Design resmi dari Anthropic untuk selera."}, {"label": "Plan dan subagent", "body": "Ia dapat merencanakan sebelum bertindak dan memunculkan subagent yang mengerjakan bagian-bagian berbeda dari suatu tugas secara paralel, yang menjaga refaktor UI besar tetap koheren."}]}, {"kind": "ul", "items": ["Vendor: Anthropic", "Kredensial: kunci API Anthropic (BYOK, melalui Console) atau langganan Claude (Pro / Max)", "Permukaan: CLI terminal, ekstensi VS Code / Cursor / JetBrains, aplikasi desktop, web"]}]}, {"id": "why-design", "heading": "Mengapa Claude Code bagus untuk desain", "blocks": [{"kind": "p", "text": "Di antara agen coding, Claude Code punya reputasi soal selera dalam pekerjaan frontend. Beberapa hal menjelaskannya."}, {"kind": "steps", "items": [{"label": "Keputusan spesifik, bukan samar", "body": "Claude Code cenderung berkomitmen pada pilihan konkret — nilai hex yang persis, spacing scale, type ramp, dan hierarki komponen — alih-alih mengambang, dan itulah yang membedakan antarmuka sungguhan dari placeholder."}, {"label": "Penalaran yang sadar codebase", "body": "Dengan konteks kerja yang besar, ia merefaktor UI di banyak file sekaligus, menggunakan kembali komponen dan tokens Anda yang ada, alih-alih menciptakan ulang gaya sekali pakai."}, {"label": "Skill frontend resmi", "body": "Anthropic menyediakan skill Frontend Design yang membuat Claude menulis arah desain lebih dulu dan secara sengaja menjauh dari font sistem generik dan gradien ungu yang bisa ditebak."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajarannya sama dengan yang Anthropic katakan tentang modelnya sendiri: Claude tidak punya selera secara default — dibiarkan sendiri, ia mengonvergensi ke pusat statistik desain web (Inter, gradien ungu, soft shadow). Ia menghasilkan desain yang baik ketika Anda memberinya batasan. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Claude Code untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Claude Code yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi CLAUDE.md, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi CLAUDE.md → tambahkan skill Frontend Design → aktifkan verifikasi browser."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di CLAUDE.md dan arahkan Claude ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Tambahkan verifikasi browser", "body": "Hubungkan Playwright atau Chrome MCP agar Claude merender di browser sungguhan dan memeriksa output-nya di berbagai breakpoint, bukan hanya memastikan build lolos."}]}]}, {"id": "skills-workflow", "heading": "Alur kerja CLAUDE.md dan Skills", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Claude Code adalah memberinya referensi nyata plus konteks desain Anda, lalu mengiterasi hingga UI cocok — dengan CLAUDE.md dan Skills membawa batasannya sehingga Anda tidak perlu menjelaskannya ulang di setiap prompt."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik bahkan dengan agen yang kuat.", "Simpan design system dan konvensi Anda di CLAUDE.md, dan beri tahu Claude di mana tokens dan primitif kanonis berada.", "Tambahkan skill Frontend Design agar Claude berkomitmen pada arah estetik nyata sebelum menulis kode.", "Hubungkan verifikasi browser agar Claude merender, mengubah ukuran ke breakpoint, dan membandingkannya kembali ke referensi — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Jatuhkan gambar referensi ke dalam sesi dan beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Jalankan dev server di sampingnya, jaga prompt tetap kecil dan terfokus, lalu commit iterasi yang baik / revert yang buruk (beri tahu Claude saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih. Gunakan plan mode untuk refaktor yang lebih besar agar Anda bisa meninjau pendekatannya sebelum ada perubahan file."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip desain ↔ kode", "blocks": [{"kind": "p", "text": "Pada Februari 2026 Anthropic dan Figma merilis integrasi dwiarah kelas satu melalui server Figma MCP. Ia bekerja di kedua arah."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Pilih sebuah frame di Figma atau tempelkan tautan ke Claude Code, tarik konteks desainnya, dan minta ia mengimplementasikan desain menggunakan pustaka komponen Anda yang ada. Code Connect menjaga output tetap selaras dengan komponen nyata Anda."}, {"label": "Kode → Desain", "body": "Bangun dan pratinjau sebuah fitur di browser, lalu katakan “Send this to Figma” untuk menangkap UI yang berjalan sebagai layer Figma yang dapat disunting — seluruh layar atau elemen terpilih."}]}, {"kind": "p", "text": "Install sekali dengan claude plugin install figma@claude-plugins-official (Dev Mode MCP memerlukan paket Figma berbayar). Figma MCP yang sama tersedia untuk Claude Code, Codex, Cursor, dan VS Code — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan penalaran UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"], ["Codex", "Poles visual yang kuat dan pemahaman gambar; build asinkron tersandbox", "Build asinkron yang didelegasikan dan aturan AGENTS.md yang portabel"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Bahkan dengan reputasi selera Claude Code, keluhan paling umum tentang desain hasil AI adalah tampilannya yang generik — font Inter, gradien ungu di atas putih, soft shadow, sudut membulat berukuran berlebihan, estetika yang “berteriak ini buatan AI.” Anthropic sendiri mengaitkannya dengan konvergensi distribusional: pilihan aman mendominasi data pelatihan web. Masalah lain yang dilaporkan termasuk layout mobile yang rusak dan instruksi yang bocor ke teks UI."}, {"kind": "steps", "items": [{"label": "Install skill Frontend Design", "body": "Ia memaksa Claude berkomitmen pada arah nyata dan secara eksplisit menghindari font dan gradien yang terlalu sering dipakai oleh AI."}, {"label": "Aktifkan verifikasi browser", "body": "Buat Claude merender dan memeriksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di CLAUDE.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Claude Code di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Claude Code sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Claude Code bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Claude Code sebagai agen Anda.", "Autentikasi dengan kunci API Anthropic (BYOK) atau langganan Claude Anda — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Claude Code yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah Claude Code bagus untuk pekerjaan desain?", "text": "Ya — ia secara luas dianggap sebagai agen coding dengan selera frontend terbaik, membuat keputusan spesifik dan sadar codebase tentang nilai hex, spacing, dan type scale. Dengan skill Frontend Design, design system, dan gambar referensi nyata dalam konteks, ia menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah saya butuh langganan Claude untuk mendesain dengan Claude Code?", "text": "Anda dapat menggunakan kunci API Anthropic (BYOK, melalui Console) atau langganan Claude (Pro / Max). Bagaimanapun, Open Design tidak pernah memproksi kredensial Anda — kredensial digunakan langsung oleh agen Anda di mesin Anda."}, {"name": "Claude Code atau Codex untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase serta penalaran frontend; Codex punya poles visual yang kuat dan unggul dalam build yang didelegasikan dan tersandbox. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Claude Code ke Figma?", "text": "Install plugin Figma resmi dengan claude plugin install figma@claude-plugins-official. Anda kemudian dapat mengimplementasikan frame Figma dalam kode menggunakan konteks desain, dan mendorong UI yang berjalan kembali ke frame Figma yang dapat disunting dengan “Send this to Figma.” Dev Mode MCP memerlukan paket Figma berbayar."}, {"name": "Apa itu Skills dan CLAUDE.md?", "text": "CLAUDE.md adalah file markdown di root proyek Anda yang dibaca Claude Code pada awal setiap sesi — tempat untuk menuliskan konvensi desain Anda. Skills mengemas instruksi dan sumber daya yang dapat diulang yang dimuat Claude sesuai kebutuhan, termasuk skill Frontend Design resmi dari Anthropic. Open Design menyediakan pustaka keduanya yang terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Install skill Frontend Design, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di CLAUDE.md, dan aktifkan verifikasi browser. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan Anthropic?", "text": "Tidak. Claude Code adalah produk Anthropic; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. Claude dan Claude Code adalah merek dagang Anthropic."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first dan Apache-2.0. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial Anthropic Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Claude Code, dengan cara terbuka.", "ctaBody": "Bawa kunci Anthropic atau langganan Claude Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Claude Code di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex untuk desain — Open Design",
        description: "Bagaimana orang menggunakan OpenAI Codex untuk desain UI dan web — plugin Product Design, integrasi Figma, skill frontend — dan bagaimana Open Design mengubah Codex menjadi agen desain open-source yang local-first.",
        breadcrumb: "Codex",
        label: "Agen · Codex",
        heading: "Codex untuk desain.",
        lead: "Codex adalah agen coding dari OpenAI. Dengan plugin Product Design dan integrasi Figma-nya, ia telah menjadi alat desain yang serius. Open Design merangkai Codex ke alur kerja desain open-source — kunci OpenAI atau langganan ChatGPT Anda, file Anda, local-first.",
        rich: {"heroCtaLead": "Open Design mengubah Codex menjadi agen desain open-source yang local-first — kunci OpenAI Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Codex di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex bermula sebagai generator kode, tetapi pada 2026 ia menjadi alat yang kredibel untuk mendesain antarmuka sungguhan — begitu Anda memberinya referensi, skill, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan Codex dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa itu Codex sekarang, mengapa ia tiba-tiba bagus di frontend, cara menyiapkannya dari nol, loop screenshot-to-UI, round-trip Figma resmi, perbandingannya dengan Cursor dan Claude Code, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Loop umpan balik desain Codex: agen terminal, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: Codex membangun UI di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengiterasinya terhadap referensi Anda."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-codex", "label": "Apa sebenarnya OpenAI Codex itu"}, {"id": "why-design", "label": "Mengapa Codex sekarang bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Codex untuk desain (dari nol)"}, {"id": "screenshot-workflow", "label": "Alur kerja screenshot-to-UI"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Codex di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Apa sebenarnya OpenAI Codex itu (dan apa yang bukan)", "blocks": [{"kind": "p", "text": "Pertama, sebuah penjelasan yang membingungkan hampir semua orang yang mencari “Codex.” OpenAI Codex yang asli adalah model penyelesaian kode tahun 2021 yang menggerakkan GitHub Copilot awal dan dihentikan pada 2023. Itu bukan yang dibahas halaman ini. Codex masa kini adalah alat coding agentic dari OpenAI — ia merencanakan, menulis, menjalankan, dan memverifikasi kode dari tugas berbahasa alami."}, {"kind": "p", "text": "Codex modern hadir di empat permukaan: CLI terminal (ditulis ulang dalam Rust, berlisensi Apache-2.0), ekstensi IDE untuk VS Code, Cursor, dan Windsurf, pengalaman cloud/web untuk tugas asinkron yang didelegasikan, dan aplikasi desktop dengan browser internal dan Computer Use."}, {"kind": "steps", "items": [{"label": "Model default", "body": "Per pertengahan 2026, model yang direkomendasikan adalah gpt-5.5, dengan gpt-5.4 sebagai model yang secara eksplisit dilatih OpenAI untuk frontend dan computer use."}, {"label": "File instruksi", "body": "Codex membaca file AGENTS.md di proyek Anda (standar lintas alat) untuk aturan proyek — tempat alami untuk menuliskan konvensi desain Anda."}, {"label": "Sandbox", "body": "Ia berjalan dalam sandbox tingkat kernel (workspace-write secara default), sehingga agen yang menyunting UI Anda tidak dapat berkelana ke luar proyek."}]}, {"kind": "ul", "items": ["Vendor: OpenAI", "Kredensial: kunci API OpenAI (BYOK) atau langganan ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Lisensi CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Mengapa Codex sekarang bagus untuk desain", "blocks": [{"kind": "p", "text": "Tiga hal berkonvergensi pada awal 2026 untuk menjadikan Codex alat desain sungguhan, bukan sekadar generator kode generik."}, {"kind": "steps", "items": [{"label": "Model yang dilatih untuk frontend", "body": "OpenAI merilis GPT-5.4, model mainline pertamanya yang dilatih untuk frontend dan computer use, dengan pemahaman gambar yang jauh lebih baik di seluruh alur kerja desain dan verifikasi diri yang lebih kuat. Ia bahkan dapat menghasilkan mood board dan opsi visual sebelum berkomitmen pada aset final."}, {"label": "Skill frontend resmi", "body": "Katalog openai/skills menyediakan frontend-skill terkurasi yang menegakkan selera nyata: layout tanpa card, hero full-bleed, hierarki brand-first, gerak yang terkendali, paling banyak dua typeface dan satu accent color — dan membuat Codex menulis tesis visual sebelum membangun."}, {"label": "Verifikasi browser", "body": "Dengan skill Playwright, Codex membuka browser sungguhan, mengubah ukuran ke breakpoint, dan membandingkan output-nya kembali ke referensi alih-alih hanya memeriksa bahwa build lolos."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajaran di balik ketiganya: Codex tidak punya selera secara default. Ia menghasilkan desain yang baik ketika Anda memberinya batasan — design system, skill estetik, dan referensi konkret. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Codex untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Codex yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi, install skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi AGENTS.md → install skill frontend → aktifkan verifikasi browser."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di AGENTS.md atau DESIGN.md dan arahkan Codex ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Pilih tingkat reasoning yang tepat", "body": "OpenAI mencatat bahwa tingkat reasoning rendah hingga sedang sering menghasilkan hasil frontend yang lebih kuat daripada pengaturan tertinggi."}]}]}, {"id": "screenshot-workflow", "heading": "Alur kerja screenshot-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Codex adalah mengubah gambar referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya hingga cocok. Panduan OpenAI sendiri menyaringnya menjadi lima langkah."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu Codex di mana tokens dan primitif kanonis berada.", "Aktifkan skill interaktif Playwright agar Codex merender di browser sungguhan dan mengubah ukuran ke breakpoint.", "Iterasi dengan meminta Codex membandingkan implementasinya kembali ke screenshot — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Beri gambar dengan menyeret screenshot ke dalam terminal atau dengan flag image, lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Jalankan dev server di terminal kedua, jaga prompt tetap kecil dan terfokus, lalu commit iterasi yang baik / revert yang buruk (beri tahu Codex saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip desain ↔ kode", "blocks": [{"kind": "p", "text": "Pada Februari 2026 OpenAI dan Figma mengumumkan kemitraan resmi, mengubah beta Figma MCP sebelumnya menjadi integrasi dwiarah kelas satu. Ia bekerja di kedua arah."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Salin “link to selection” sebuah frame di Figma, tempelkan ke Codex dengan get_design_context, dan minta ia mengimplementasikan desain menggunakan pustaka komponen Anda yang ada."}, {"label": "Kode → Desain", "body": "Alat generate_figma_design (“Code to Canvas”) mengubah UI yang hidup dan berjalan kembali menjadi frame Figma yang dapat disunting — seluruh layar, elemen terpilih, atau seluruh file."}]}, {"kind": "p", "text": "Figma MCP berjalan sebagai server remote dan dikecualikan dari rate limit. Tambahkan sekali dan ia tersedia untuk Codex, Claude Code, Cursor, VS Code, dan lainnya — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Codex", "Poles visual yang kuat setelah GPT-5.4 + frontend-skill; pemahaman gambar", "Build asinkron yang didelegasikan, jalankan tersandbox, aturan AGENTS.md yang portabel"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil Codex adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout mobile yang rusak, instruksi yang bocor ke teks UI, dan cepat mencapai batas penggunaan."}, {"kind": "steps", "items": [{"label": "Install sebuah skill frontend", "body": "Skill estetik terkurasi memaksa Codex berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Aktifkan verifikasi Playwright", "body": "Buat Codex merender dan memeriksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di AGENTS.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Codex di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Codex sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Codex bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Codex sebagai agen Anda.", "Autentikasi dengan kunci API OpenAI (BYOK) atau langganan ChatGPT Anda — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Codex yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah OpenAI Codex benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill frontend, design system, dan gambar referensi nyata dalam konteks, Codex (terutama pada GPT-5.4) menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah ini plugin Product Design OpenAI Codex?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan Codex sebagai agen. Ia melengkapi tooling OpenAI sendiri dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan ChatGPT untuk mendesain dengan Codex?", "text": "Anda dapat menggunakan kunci API OpenAI (BYOK) atau langganan ChatGPT Anda. Masuk dengan ChatGPT umumnya memberi batas yang lebih murah hati; Open Design tidak pernah memproksi kredensial Anda dengan cara apa pun."}, {"name": "Codex atau Claude Code untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase; Codex punya poles visual yang kuat setelah GPT-5.4 dan unggul dalam build yang didelegasikan dan tersandbox. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Codex ke Figma?", "text": "Tambahkan server Figma MCP resmi (codex mcp add figma --url https://mcp.figma.com/mcp). Anda kemudian dapat mengimplementasikan frame Figma dalam kode dengan get_design_context dan mendorong UI yang berjalan kembali ke frame Figma yang dapat disunting dengan generate_figma_design."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Install skill frontend, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di AGENTS.md, dan aktifkan verifikasi Playwright. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan OpenAI?", "text": "Tidak. Codex adalah produk OpenAI; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. OpenAI dan Codex adalah merek dagang OpenAI."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial OpenAI Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Codex, dengan cara terbuka.", "ctaBody": "Bawa kunci OpenAI Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Codex di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor untuk desainer — Open Design",
        description: "Bagaimana desainer menggunakan Cursor untuk desain UI dan web — Design Mode, Figma-to-code, Figma MCP — dan bagaimana Open Design mengubah Cursor menjadi agen desain open-source yang local-first.",
        breadcrumb: "Cursor",
        label: "Agen · Cursor",
        heading: "Cursor untuk desainer.",
        lead: "Cursor adalah editor kode AI, kini dengan Design Mode visual. Desainer menggunakannya untuk menyunting UI dengan menunjuk dan menggambar, serta untuk mengubah Figma menjadi kode. Open Design menghubungkan Cursor Agent ke alur kerja desain open-source yang menjaga file Anda tetap lokal.",
        rich: {"heroCtaLead": "Open Design mengubah Cursor menjadi agen desain open-source yang local-first — akun Cursor atau kunci model Anda, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan Cursor di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor adalah editor kode AI-first yang menjadikan “bangun lalu lihat ia merender” sebagai cara default untuk mengirimkan UI. Dengan mode Agent, suntingan inline, pratinjau di dalam editor, dan Figma lewat MCP, ia telah menjadi alat desain yang sungguhan — begitu Anda memberinya referensi, aturan, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan Cursor dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya Cursor itu, mengapa loop iterate-and-watch-nya yang rapat bagus untuk desain, cara menyiapkannya dari nol, loop screenshot-dan-pratinjau-to-UI, round-trip Figma lewat MCP, perbandingannya dengan Codex dan Claude Code, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Konvergensi desain Cursor: editor di kiri, hub skill dan design system terkurasi di tengah dengan mark Cursor di pusat, dan UI yang dirender di kanan", "caption": "Ide intinya: Cursor menyunting dan merender UI di dalam editor, sementara hub desain terkurasi memberinya system, skill, dan referensi yang membuat output terlihat disengaja."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-cursor", "label": "Apa sebenarnya Cursor itu"}, {"id": "why-design", "label": "Mengapa Cursor bagus untuk desain"}, {"id": "setup", "label": "Menyiapkan Cursor untuk desain (dari nol)"}, {"id": "preview-workflow", "label": "Alur kerja preview-to-UI"}, {"id": "figma", "label": "Cursor + Figma lewat MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan Cursor di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Apa sebenarnya Cursor itu", "blocks": [{"kind": "p", "text": "Cursor adalah editor kode AI-first yang dibangun oleh Anysphere. Ia adalah fork dari VS Code, sehingga tetap mempertahankan editor, ekstensi, dan keybinding yang familier, tetapi membangun ulang alur kerja di seputar agen AI yang dapat membaca seluruh proyek Anda, menyunting banyak file, menjalankan perintah, dan mengiterasi bersama Anda dalam loop."}, {"kind": "p", "text": "Untuk pekerjaan desain, permukaan yang penting adalah mode Agent (Anda mendeskripsikan hasil dan Cursor merencanakan serta menyunting di banyak file), suntingan inline dan penyelesaian Tab untuk perubahan cepat, pratinjau / browser di dalam editor agar Anda bisa melihat UI yang berjalan tanpa meninggalkan jendela, serta dukungan MCP yang membuatnya dapat menarik konteks eksternal seperti file Figma yang hidup."}, {"kind": "steps", "items": [{"label": "Aturan proyek", "body": "Cursor membaca file instruksi proyek — aturan `.mdc` yang berversi di bawah `.cursor/rules`, dan `AGENTS.md` biasa — sehingga Anda dapat menuliskan konvensi desain di tempat yang dibaca agen pada setiap putaran."}, {"label": "Model", "body": "Cursor fleksibel soal model: ia hadir dengan model-model terdepan melalui langganan Anda dan juga mendukung membawa kunci model Anda sendiri, sehingga Anda memilih mesin di balik alur kerja editor yang sama."}, {"label": "MCP", "body": "Ia berbicara Model Context Protocol, sehingga server eksternal — yang paling relevan server Figma MCP — menjadi konteks kelas satu bagi agen."}]}, {"kind": "ul", "items": ["Vendor: Anysphere", "Kredensial: akun / langganan Cursor (Hobby / Pro / Business) atau kunci model Anda sendiri (BYOK)", "Bentuk: editor kode AI-first (fork VS Code) dengan agen dan pratinjau di dalam editor"]}]}, {"id": "why-design", "heading": "Mengapa Cursor bagus untuk desain", "blocks": [{"kind": "p", "text": "Keunggulan desain Cursor bukan satu fitur tunggal — melainkan kerapatan loop build-and-see. Tiga hal membuatnya terasa seperti alat desain alih-alih generator kode generik."}, {"kind": "steps", "items": [{"label": "Loop iterate-and-watch yang rapat", "body": "Anda memberi prompt, Cursor menyunting di banyak file, dan pratinjau di dalam editor merender hasilnya seketika — sehingga Anda menyesuaikan spacing, hierarki, dan gerak dalam hitungan detik alih-alih bolak-balik melalui terminal dan browser terpisah."}, {"label": "Penyuntingan visual langsung", "body": "Selain chat, Cursor memungkinkan Anda memilih elemen di pratinjau dan menyetel gaya, sehingga koreksi visual kecil terasa seperti suntingan desain alih-alih arkeologi kode."}, {"label": "Aturan proyek dan konteks MCP", "body": "Dengan `.cursor/rules` (atau `AGENTS.md`) dan server Figma MCP, agen bekerja terhadap tokens, komponen, dan spesifikasi desain nyata Anda alih-alih menebak."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata."}, {"kind": "p", "text": "Pelajarannya sama dengan yang diajarkan setiap agen: Cursor tidak punya selera secara default. Ia menghasilkan desain yang baik ketika Anda memberinya batasan — design system, skill estetik, dan referensi konkret. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan Cursor untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga Cursor yang dapat membangun, mempratinjau, dan memverifikasi UI terhadap design system Anda."}, {"kind": "ol", "items": ["Install Cursor dari cursor.com dan masuk dengan akun Cursor Anda, atau konfigurasikan kunci model Anda sendiri (BYOK) di Settings.", "Buka proyek Anda dan pilih model di panel chat / Agent.", "Tambahkan aturan proyek: buat `.cursor/rules/*.mdc` untuk konvensi terstruktur yang bercakupan glob, atau `AGENTS.md` biasa untuk instruksi yang sederhana dan mudah dibaca.", "Hubungkan server Figma MCP (opsional) agar agen dapat membaca konteks desain yang hidup.", "Jalankan dev server Anda dan gunakan pratinjau di dalam editor untuk melihat dan memverifikasi UI saat Anda mengiterasi."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi, konfigurasi aturan, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi → konfigurasi aturan proyek → tambahkan skill → aktifkan verifikasi pratinjau."}, {"kind": "p", "text": "File aturan-proyek minimal membuat agen mendesain ke sebuah brand alih-alih jatuh ke tampilan generik. Letakkan di tempat yang dibaca Cursor pada setiap putaran:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di `.cursor/rules` atau `AGENTS.md` dan arahkan Cursor ke sana, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Jaga prompt tetap kecil", "body": "Loop Cursor yang rapat memberi imbalan pada permintaan yang terfokus — iterasi satu komponen atau state pada satu waktu dan amati pratinjau di antara putaran."}]}]}, {"id": "preview-workflow", "heading": "Alur kerja preview-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada Cursor adalah mengubah referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya di dalam editor hingga cocok — mengamati pratinjau langsung sepanjang waktu alih-alih menebak."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu Cursor di mana tokens dan primitif kanonis berada.", "Jaga pratinjau di dalam editor tetap terbuka dan dev server Anda tetap berjalan agar setiap suntingan dirender seketika pada breakpoint yang Anda pedulikan.", "Iterasi dengan membandingkan UI yang dirender kembali ke referensi — dan gunakan pemilihan elemen langsung di pratinjau untuk koreksi visual kecil."]}, {"kind": "p", "text": "Beri referensi dengan melampirkan gambar ke chat, lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit iterasi yang baik dan revert yang buruk (beri tahu Cursor saat Anda revert) sehingga setiap putaran dibangun di atas dasar yang bersih — disiplin yang sama yang menjaga loop agen mana pun agar tidak menyimpang."}]}, {"id": "figma", "heading": "Cursor + Figma: desain ↔ kode lewat MCP", "blocks": [{"kind": "p", "text": "Cursor terhubung ke Figma melalui server Figma MCP resmi, yang memberi agen akses terstruktur ke file Figma yang hidup alih-alih screenshot datar. Itu menghilangkan tebak-tebakan dari handoff."}, {"kind": "steps", "items": [{"label": "Desain → Kode", "body": "Salin tautan sebuah frame di Figma, tempelkan ke Cursor, dan minta ia mengimplementasikan desain. Server MCP mengekspos konteks desain nyata — komponen, variabel, data layout, tokens — sehingga kode yang dihasilkan cocok dengan sumber alih-alih mendekatinya."}, {"label": "Tetap selaras", "body": "Dengan design tokens, gaya, dan komponen yang digunakan secara konsisten di Figma (dan Code Connect bila tersedia), output Cursor tetap terpetakan ke design system nyata Anda alih-alih menciptakan ulang primitif."}]}, {"kind": "p", "text": "Siapkan server Figma MCP remote sekali dan ia tersedia bagi Cursor sebagai konteks kelas satu. Karena MCP adalah standar terbuka, server yang sama dapat dipakai ulang di Cursor, Claude Code, Codex, dan VS Code — persis jenis kemampuan portabel dan multi-agen yang dibuat untuk diorkestrasikan oleh Open Design."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["Cursor", "Loop build-and-see visual dengan pratinjau langsung di dalam editor dan penyuntingan elemen langsung", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"], ["Codex", "Poles visual yang kuat dengan skill frontend; pemahaman gambar dan jalankan tersandbox", "Build asinkron yang didelegasikan dan aturan AGENTS.md yang portabel"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: ketiganya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil Cursor adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout yang rusak di mobile dan instruksi yang bocor ke teks UI."}, {"kind": "steps", "items": [{"label": "Tambahkan sebuah skill desain", "body": "Skill estetik terkurasi memaksa Cursor berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Gunakan pratinjau untuk verifikasi", "body": "Render dan periksa diri sendiri di berbagai breakpoint di pratinjau dalam editor sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di `.cursor/rules`", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan Cursor di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan Cursor sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat Cursor bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali."}, {"kind": "ol", "items": ["Install Open Design dan pilih Cursor sebagai agen Anda.", "Autentikasi dengan akun Cursor Anda atau kunci model Anda sendiri (BYOK) — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen Cursor yang sama, kunci yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah Cursor benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill desain, design system, dan gambar referensi nyata dalam konteks, Cursor menghasilkan UI berkualitas produksi dan responsif, dan pratinjau di dalam editornya memungkinkan Anda memverifikasi serta menyempurnakannya secara visual. Tanpa konteks itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Apakah ini produk Cursor resmi?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan Cursor sebagai agen. Ia melengkapi Cursor dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan Cursor untuk mendesain dengan Cursor?", "text": "Anda dapat menggunakan akun / langganan Cursor atau membawa kunci model Anda sendiri (BYOK). Open Design tidak pernah memproksi kredensial Anda dengan cara apa pun — kredensial digunakan langsung oleh agen Anda."}, {"name": "Cursor atau Claude Code untuk desain frontend?", "text": "Keduanya kuat. Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase; keunggulan Cursor adalah loop build-and-see-nya yang rapat dengan pratinjau langsung di dalam editor. Banyak tim memakai keduanya — Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara menghubungkan Cursor ke Figma?", "text": "Tambahkan server Figma MCP resmi di Cursor, lalu tempelkan tautan frame Figma ke chat dan minta Cursor mengimplementasikannya. Server mengekspos komponen, variabel, dan data layout nyata sehingga kode yang dihasilkan cocok dengan desain sumber."}, {"name": "Bagaimana cara menghindari estetika “AI slop” yang generik?", "text": "Tambahkan skill desain, sediakan design tokens nyata dan screenshot referensi, tuliskan aturan brand di `.cursor/rules` atau `AGENTS.md`, dan verifikasi di berbagai breakpoint di pratinjau. Open Design menyediakan ini sebagai pustaka terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan Cursor atau Anysphere?", "text": "Tidak. Cursor adalah produk Anysphere; Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party. Cursor dan Anysphere adalah merek dagang Anysphere, Inc."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial Cursor atau model Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan Cursor, dengan cara terbuka.", "ctaBody": "Bawa akun Cursor atau kunci model Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan Cursor di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode untuk desain — Open Design",
        description: "Bagaimana orang menggunakan OpenCode untuk desain UI dan web — file design.md, skill UI/UX, Figma MCP — dan bagaimana Open Design mengubah OpenCode menjadi agen desain open-source yang local-first.",
        breadcrumb: "OpenCode",
        label: "Agen · OpenCode",
        heading: "OpenCode untuk desain.",
        lead: "OpenCode adalah agen coding AI terminal yang open-source. Desainer memasangkan skill desain dan file DESIGN.md padanya untuk menghasilkan UI sungguhan. Open Design menjadikannya alur kerja open-source yang terstruktur — bawa kunci provider Anda, simpan semuanya secara lokal.",
        rich: {"heroCtaLead": "Open Design mengubah OpenCode menjadi agen desain open-source yang local-first — model apa pun yang Anda pilih dengan kunci provider Anda sendiri, file Anda, dengan pustaka skill dan design system terkurasi di sekelilingnya.", "heroCtaActions": [{"label": "Gunakan OpenCode di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode adalah agen coding AI yang open-source dan mengutamakan terminal, yang sengaja dibuat model-agnostic: Anda membawa kunci provider Anda sendiri dan menjalankan model apa pun yang Anda inginkan di balik alur kerja yang sama. Keterbukaan itu menjadikannya basis alami untuk pekerjaan desain — tetapi seperti setiap agen, ia hanya menghasilkan UI yang baik ketika Anda memberinya referensi, skill, dan loop verifikasi yang tepat. Ini adalah panduan praktis end-to-end untuk menggunakan OpenCode dalam pekerjaan UI, frontend, dan design system, serta untuk merangkainya ke alur kerja desain terstruktur dengan Open Design.", "Panduan ini membahas apa sebenarnya OpenCode itu, mengapa agen terbuka yang model-agnostic cocok untuk desain, cara menyiapkannya dari nol, loop screenshot-to-UI, bagaimana AGENTS.md dan MCP memperluasnya, perbandingannya dengan Codex, Claude Code, dan Cursor, jebakan yang membuat output AI terlihat generik, dan bagaimana Open Design menutup celah itu sebagai lapisan desain terbuka yang local-first — sebuah pasangan alami, karena kedua proyek bersifat open-source dan berjalan di mesin Anda sendiri."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Loop umpan balik desain OpenCode: agen TUI terminal, browser yang merender UI, dan workspace, dengan panah umpan balik yang berputar kembali", "caption": "Loop inti: OpenCode membangun UI di terminal, merender dan memverifikasinya di browser sungguhan, lalu mengiterasinya terhadap referensi Anda — pada model apa pun yang Anda pilih."}, "tocLabel": "Di halaman ini", "toc": [{"id": "what-is-opencode", "label": "Apa sebenarnya OpenCode itu"}, {"id": "why-design", "label": "Mengapa agen terbuka apa-pun-modelnya cocok untuk desain"}, {"id": "setup", "label": "Menyiapkan OpenCode untuk desain (dari nol)"}, {"id": "screenshot-workflow", "label": "Alur kerja screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP, dan sesi yang dapat dibagikan"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Jebakan dan tampilan “AI slop”"}, {"id": "open-design", "label": "Mendesain dengan OpenCode di Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Apa sebenarnya OpenCode itu", "blocks": [{"kind": "p", "text": "OpenCode adalah agen coding AI open-source yang dibangun untuk terminal, dipelihara oleh tim di balik SST (Anomaly Innovations). Ia membaca repositori Anda, menjalankan perintah, menyunting file, dan berbicara dengan model bahasa besar — tetapi tidak seperti agen yang terikat vendor, ia tidak menyertakan modelnya sendiri. Anda mengarahkannya ke provider dan model apa pun yang Anda inginkan dan membawa kunci Anda sendiri."}, {"kind": "p", "text": "Ia berjalan sebagai terminal UI (TUI), dengan aplikasi desktop dan ekstensi IDE di atas mesin yang sama. Di balik layar, ia menggunakan arsitektur client/server, sehingga agen yang melakukan pekerjaan terpisah dari permukaan tempat Anda mengendalikannya. Dua agen bawaan — build dan plan — berganti dengan tombol Tab."}, {"kind": "steps", "items": [{"label": "Model-agnostic", "body": "Model dan provider berasal dari models.dev, sebuah katalog terbuka. Anda mengonfigurasikannya di opencode.json dengan string provider/model-id dan dapat menonaktifkan provider yang tidak ingin dimuat — sehingga alur kerja desain yang sama berjalan di Anthropic, OpenAI, Google, OpenRouter, model lokal, dan lainnya."}, {"label": "File instruksi", "body": "OpenCode membaca file AGENTS.md di proyek Anda (standar lintas alat, juga kompatibel dengan CLAUDE.md) untuk aturan proyek — tempat alami untuk menuliskan konvensi desain Anda. Jalankan /init untuk menghasilkannya."}, {"label": "Dapat diperluas", "body": "Ia mendukung integrasi LSP, server MCP, tema, keybind, dan perintah kustom, ditambah tautan sesi yang dapat dibagikan untuk kolaborasi."}]}, {"kind": "ul", "items": ["Pemelihara: SST / Anomaly Innovations (proyek open-source)", "Kredensial: kunci API provider model Anda sendiri — BYOK, tanpa vendor lock-in", "Lisensi: MIT, open source"]}]}, {"id": "why-design", "heading": "Mengapa agen terbuka apa-pun-modelnya cocok untuk pekerjaan desain", "blocks": [{"kind": "p", "text": "OpenCode tidak punya satu “model desain” seperti agen vendor — dan itulah intinya. Karena ia model-agnostic dan terbuka, Anda dapat menjalankan alur kerja desain yang sama pada model mana pun yang saat ini terbaik di frontend, menukarnya nanti, atau beralih ke model lokal, semua tanpa mengubah penyiapan Anda."}, {"kind": "p", "text": "Tetapi pilihan model saja tidak membeli selera. Seperti setiap agen coding, OpenCode menghasilkan UI generik kecuali Anda memberinya batasan. Output desain yang baik datang dari tiga masukan yang Anda berikan."}, {"kind": "steps", "items": [{"label": "Sebuah design system", "body": "Tokens, primitif, dan konvensi nyata yang digunakan kembali oleh agen, sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik."}, {"label": "Sebuah skill estetik", "body": "Skill terkurasi yang menegakkan selera nyata — gerak yang terkendali, hierarki brand-first, paling banyak dua typeface dan satu accent color — dan membuat agen berkomitmen pada arah sebelum membangun."}, {"label": "Referensi konkret", "body": "Gambar referensi nyata dan banyak state (desktop dan mobile, hover, kosong, loading), bukan satu hero shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram yang menunjukkan design system, skill, dan gambar referensi mengonvergensi menjadi output desain yang baik", "caption": "Selera datang dari tiga masukan yang Anda berikan: design system, skill, dan gambar referensi nyata — terlepas dari model mana yang Anda jalankan."}, {"kind": "p", "text": "Pelajarannya: OpenCode memberi Anda kebebasan model, tetapi selera tetap datang dari konteks desain yang terkurasi. Open Design mengemas masukan-masukan itu secara persis, dan itulah mengapa keduanya cocok bersama — keduanya open-source dan local-first (lebih lanjut di bawah)."}]}, {"id": "setup", "heading": "Menyiapkan OpenCode untuk pekerjaan desain, dari nol", "blocks": [{"kind": "p", "text": "Berikut jalur lengkap dari mesin yang bersih hingga OpenCode yang dapat membangun dan memverifikasi UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Alur penyiapan lima langkah: install, autentikasi dengan kunci provider Anda, konfigurasi AGENTS.md, tambah skill, verifikasi", "caption": "Urutan penyiapan: install → autentikasi (kunci provider Anda) → konfigurasi AGENTS.md → tambahkan skill → verifikasi di browser sungguhan."}, {"kind": "steps", "items": [{"label": "Tuliskan aturan desain Anda", "body": "Letakkan tokens, primitif, dan konvensi Anda di AGENTS.md (atau DESIGN.md yang dirujuk darinya) sehingga output sesuai dengan brand alih-alih jatuh ke tampilan generik. Opsi instructions di opencode.json dapat mengarah ke file aturan tambahan via glob."}, {"label": "Pilih model yang mumpuni", "body": "Karena OpenCode model-agnostic, pilih provider/model mana pun yang saat ini paling kuat di frontend untuk putaran desain — dan biarkan sisa alur kerja Anda tetap tidak berubah."}]}]}, {"id": "screenshot-workflow", "heading": "Alur kerja screenshot-to-UI", "blocks": [{"kind": "p", "text": "Loop desain dengan daya ungkit tertinggi pada agen mana pun adalah mengubah gambar referensi menjadi UI yang berfungsi dan responsif, lalu mengiterasinya hingga cocok. Bentuk lima langkah yang sama berlaku di OpenCode."}, {"kind": "ol", "items": ["Mulai dari referensi visual paling jelas yang Anda miliki — dan sertakan banyak state (desktop dan mobile, hover, kosong, loading), bukan hanya satu hero shot.", "Bersikaplah spesifik dalam prompt; prompt yang samar menghasilkan UI generik.", "Siapkan design system dan beri tahu OpenCode di mana tokens dan primitif kanonis berada (di AGENTS.md).", "Jalankan dev server dan minta agen merender di browser sungguhan, mengubah ukuran ke breakpoint untuk memeriksa hasilnya.", "Iterasi dengan meminta OpenCode membandingkan implementasinya kembali ke screenshot — bukan sekadar memastikan ia berhasil build."]}, {"kind": "p", "text": "Rujuk file dengan @ di TUI untuk pencarian fuzzy direktori kerja Anda, jalankan perintah shell secara inline dengan awalan !, dan kendalikan tindakan dengan perintah /. Lalu beri prompt dengan batasan konkret:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Jaga prompt tetap kecil dan terfokus, commit iterasi yang baik dan revert yang buruk (beri tahu OpenCode saat Anda revert), sehingga setiap putaran dibangun di atas dasar yang bersih."}]}, {"id": "extend", "heading": "AGENTS.md, MCP, dan sesi yang dapat dibagikan", "blocks": [{"kind": "p", "text": "Tiga titik ekstensi membuat OpenCode praktis untuk pekerjaan desain yang berkelanjutan, dan ketiganya terpetakan rapi ke alur kerja desain terbuka."}, {"kind": "steps", "items": [{"label": "Aturan AGENTS.md", "body": "Aturan proyek tinggal di sebuah AGENTS.md di root repo (atau aturan global di ~/.config/opencode/AGENTS.md). Ia adalah rumah yang tahan lama bagi konvensi desain Anda, dibaca pada setiap putaran, dan kompatibel dengan file CLAUDE.md yang dipakai agen lain."}, {"label": "Server MCP", "body": "OpenCode mendukung server MCP lokal (command) maupun remote (URL), dikonfigurasikan di bawah kunci mcp — cara portabel untuk membawa konteks desain dan alat eksternal yang bekerja lintas agen, bukan hanya OpenCode."}, {"label": "Sesi yang dapat dibagikan", "body": "Perintah /share membuat tautan publik ke sebuah percakapan untuk kolaborasi atau tinjauan, dan /unshare mencabutnya — berguna untuk mendapatkan umpan balik atas sebuah putaran desain."}]}, {"kind": "p", "text": "Ini adalah kemampuan portabel dan multi-agen — persis jenis hal yang dibuat untuk diorkestrasikan oleh Open Design, alih-alih dibuat ulang per proyek."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor untuk desain", "blocks": [{"kind": "p", "text": "Tidak ada pemenang tunggal untuk pekerjaan desain — setiap agen punya kekuatan berbeda, dan tim berpengalaman menumpuknya. Ringkasan yang adil:"}, {"kind": "table", "columns": ["Agen", "Kekuatan desain", "Paling cocok untuk"], "rows": [["OpenCode", "Open-source dan model-agnostic; jalankan provider apa pun di balik satu alur kerja terminal", "Kebebasan BYOK, pergantian model, penyiapan yang sepenuhnya terbuka dan local-first"], ["Codex", "Poles visual yang kuat dengan skill frontend; pemahaman gambar", "Asinkron yang didelegasikan, build tersandbox, aturan AGENTS.md yang portabel"], ["Claude Code", "Keputusan desain spesifik (hex, spacing, type) dan UX yang sadar codebase", "Penalaran frontend dan refaktor konteks besar"], ["Cursor", "Loop build-and-see visual dengan pratinjau langsung dan suntingan inline", "Pekerjaan UI iterate-and-watch yang rapat di dalam IDE"]]}, {"kind": "p", "text": "Putusan komunitas yang berulang adalah bahwa selera datang dari manusia: semuanya jatuh ke estetika generik tanpa skill, referensi, dan batasan. Itulah masalah sebenarnya yang harus dipecahkan — dan bentuknya seperti alat desain, bukan seperti model, yang justru menjadi alasan mengapa agen terbuka seperti OpenCode berpasangan begitu baik dengan lapisan desain terbuka."}]}, {"id": "pitfalls", "heading": "Jebakan, dan cara menghindari tampilan “AI slop”", "blocks": [{"kind": "p", "text": "Keluhan paling umum tentang desain hasil AI adalah tampilannya yang generik — gradien lembut, panel mengambang, sudut membulat berukuran berlebihan, bayangan dramatis, nuansa Inter-dan-ungu yang “berteriak ini buatan AI.” Masalah lain yang dilaporkan termasuk layout mobile yang rusak dan instruksi yang bocor ke teks UI. Tak satu pun dari ini unik bagi OpenCode; semuanya terjadi ketika agen mana pun berjalan tanpa konteks desain yang terkurasi."}, {"kind": "steps", "items": [{"label": "Tambahkan sebuah skill estetik", "body": "Skill desain terkurasi memaksa agen berkomitmen pada arah nyata alih-alih tampilan default."}, {"label": "Verifikasi di browser sungguhan", "body": "Render dan periksa diri sendiri di berbagai breakpoint sehingga layout tidak diam-diam rusak di mobile."}, {"label": "Sediakan tokens dan referensi", "body": "Design tokens nyata dan screenshot referensi adalah satu daya ungkit terbesar bagi kualitas output."}, {"label": "Tuliskan aturan di AGENTS.md", "body": "Letakkan aturan bergaya “tanpa hero card, maksimal dua typeface, hierarki brand-first” di tempat yang dibaca agen pada setiap putaran."}]}, {"kind": "p", "text": "Perhatikan bahwa setiap mitigasi adalah soal memberi agen konteks desain yang terkurasi — terlepas dari model mana yang Anda jalankan. Memelihara konteks itu secara manual, per proyek, adalah kerja melelahkan yang dihapus Open Design."}]}, {"id": "open-design", "heading": "Mendesain dengan OpenCode di dalam Open Design", "blocks": [{"kind": "p", "text": "Open Design adalah lapisan desain open-source yang terus diminta oleh alur kerja di atas. Ia memperlakukan OpenCode sebagai adaptor first-party dan membungkusnya dengan pustaka skill dan design system terkurasi, pipeline render terstruktur, dan UI desktop lokal — sehingga konteks desain yang membuat agen mana pun bagus sudah ada sejak putaran pertama, bukan dirakit secara manual setiap kali. Kedua proyek bersifat open-source dan local-first, yang menjadikan pasangan ini cocok secara alami."}, {"kind": "ol", "items": ["Install Open Design dan pilih OpenCode sebagai agen Anda.", "Autentikasi dengan kunci API provider model Anda sendiri (BYOK) — kredensial tetap di mesin Anda dan tidak pernah diproksi melalui kami.", "Pilih provider dan model apa pun, plus design system dan skill, lalu hasilkan deck, prototipe, dan landing page dengan selera yang konsisten.", "Setiap artefak dan file DESIGN.md hidup di repo Anda sendiri, bukan di cloud yang dihosting."]}, {"kind": "p", "text": "Agen OpenCode yang sama, kebebasan model yang sama — ditambah alur kerja desain open-source yang nyata dan portabel di sekelilingnya. Ia local-first dan Apache-2.0, sehingga tidak ada bagian dari pekerjaan atau kredensial Anda yang meninggalkan mesin Anda."}]}], "faqTitle": "Pertanyaan yang sering diajukan", "faq": [{"name": "Apakah OpenCode benar-benar bisa melakukan pekerjaan desain?", "text": "Ya — dengan skill estetik, design system, dan gambar referensi nyata dalam konteks, OpenCode menghasilkan UI berkualitas produksi dan responsif serta dapat memverifikasinya di browser. Karena ia model-agnostic, Anda menjalankan model mana pun yang saat ini terbaik di frontend. Tanpa konteks terkurasi itu, ia cenderung jatuh ke tampilan generik, dan itulah celah yang diisi Open Design."}, {"name": "Model mana yang sebaiknya saya gunakan dengan OpenCode untuk desain?", "text": "Mana pun yang Anda suka — OpenCode bersifat provider-agnostic via models.dev, sehingga Anda dapat menjalankan Anthropic, OpenAI, Google, OpenRouter, atau model lokal di balik alur kerja yang sama dan beralih kapan saja. Kualitas output desain jauh lebih bergantung pada skill, design system, dan referensi Anda daripada pada modelnya saja."}, {"name": "Apakah Open Design dibuat oleh tim OpenCode (SST)?", "text": "Bukan. Open Design adalah proyek open-source independen yang mengintegrasikan OpenCode sebagai agen. Ia melengkapi OpenCode dengan pustaka skill dan design system yang terbuka dan local-first."}, {"name": "Apakah saya butuh langganan khusus untuk mendesain dengan OpenCode?", "text": "Tidak — OpenCode bersifat BYOK. Anda membawa kunci API provider model Anda sendiri, dan Open Design tidak pernah memproksi kredensial Anda. Tidak ada vendor lock-in."}, {"name": "OpenCode atau Codex atau Claude Code untuk desain frontend?", "text": "Semuanya kuat, dan banyak tim menumpuknya. Keunggulan OpenCode adalah sepenuhnya open-source dan model-agnostic; Codex unggul dalam build yang didelegasikan dan tersandbox; Claude Code dikenal karena keputusan desain yang spesifik dan sadar codebase. Open Design memungkinkan Anda berganti agen tanpa mengubah alur kerja desain Anda."}, {"name": "Bagaimana cara memperluas OpenCode untuk konteks desain?", "text": "Tuliskan aturan di AGENTS.md, tambahkan server MCP di bawah kunci mcp untuk alat portabel dan konteks desain, serta gunakan sesi yang dapat dibagikan untuk tinjauan. Open Design menyediakan pustaka skill dan design system terkurasi sehingga Anda melewati penyiapan per proyek."}, {"name": "Apakah Open Design berafiliasi dengan OpenCode atau SST?", "text": "Tidak. OpenCode adalah proyek open-source yang dipelihara oleh SST (Anomaly Innovations); Open Design adalah proyek open-source independen yang mendukungnya sebagai adaptor first-party."}, {"name": "Apakah file dan kredensial saya aman?", "text": "Ya — Open Design bersifat local-first. File, artefak, dan DESIGN.md Anda tetap di repo Anda sendiri, dan kredensial provider model Anda digunakan langsung oleh agen Anda, tidak pernah dirutekan melalui server Open Design."}], "ctaTitle": "Mendesain dengan OpenCode, dengan cara terbuka.", "ctaBody": "Bawa kunci provider model Anda sendiri, simpan setiap file secara lokal, dan dapatkan pustaka desain terkurasi di sekeliling agen terbuka yang sudah Anda gunakan.", "ctaActions": [{"label": "Gunakan OpenCode di dalam Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Beri bintang di GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Unduh aplikasi desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Lihat semua agen yang didukung"},
      },
    },
    'nl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code voor design — Open Design",
        description: "Hoe designers Claude Code gebruiken voor UI- en webdesign, en hoe Open Design er een echte design-agent van maakt — local-first, BYOK, met een samengestelde bibliotheek van skills en design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code voor design.",
        lead: "Claude Code is de terminal-coding-agent van Anthropic. Mensen gebruiken hem al om UI's, design systems en landingspagina's te bouwen. Open Design koppelt hem aan een echte design-workflow — neem je Anthropic-key of Claude-abonnement mee en houd elk bestand lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van Claude Code een local-first, open-source design-agent — je Anthropic-key of Claude-abonnement, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak — hij redeneert met ongewone precisie over interfaces, noemt exacte hex-waarden, spacing en typeschalen, en refactort UI in een grote codebase zonder de draad kwijt te raken. Maar standaard neigt hij toch naar een generieke look, tenzij je hem een design system, skills en echte referenties aanreikt. Dit is een praktische, end-to-end gids voor het gebruik van Claude Code voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde workflow met Open Design.", "Het behandelt wat Claude Code precies is, waarom hij sterk is in frontend, hoe je hem vanaf nul opzet, de CLAUDE.md- en Skills-workflow, de officiële Figma-round-trip, hoe hij zich verhoudt tot Codex en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Feedbacklus van Claude Code-design: terminal-agent die specifieke designbeslissingen neemt, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Claude Code redeneert specifieke UI-beslissingen uit in de terminal, rendert en verifieert ze in een echte browser, en convergeert naar je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-claude-code", "label": "Wat Claude Code precies is"}, {"id": "why-design", "label": "Waarom Claude Code goed is in design"}, {"id": "setup", "label": "Claude Code instellen voor design (vanaf nul)"}, {"id": "skills-workflow", "label": "De CLAUDE.md- en Skills-workflow"}, {"id": "figma", "label": "Claude Code + Figma-round-trip"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Wat Claude Code precies is", "blocks": [{"kind": "p", "text": "Claude Code is de agentic coding-tool van Anthropic. Hij leest je codebase, bewerkt bestanden, voert commando's uit en integreert met je dev-tools — hij plant, schrijft en verifieert werk op basis van taken in natuurlijke taal in plaats van alleen regels aan te vullen."}, {"kind": "p", "text": "Hij komt in meerdere vormen die allemaal dezelfde engine delen: een terminal-CLI, IDE-extensies voor VS Code, Cursor en JetBrains, een desktop-app met visuele diff-review, en een web-ervaring voor langlopende taken. Je CLAUDE.md-bestanden, instellingen en MCP-servers reizen overal mee."}, {"kind": "steps", "items": [{"label": "Instructiebestand", "body": "Claude Code leest aan het begin van elke sessie een CLAUDE.md-bestand in je projectroot — de natuurlijke plek om je designconventies, tokens en review-checklists vast te leggen."}, {"label": "Skills", "body": "Agent Skills bundelen herbruikbare instructies, scripts en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill voor smaak."}, {"label": "Plan en subagents", "body": "Hij kan plannen voordat hij handelt en subagents opstarten die parallel aan verschillende delen van een taak werken, wat grote UI-refactors coherent houdt."}]}, {"kind": "ul", "items": ["Leverancier: Anthropic", "Credential: Anthropic API-key (BYOK, via de Console) of een Claude-abonnement (Pro / Max)", "Vormen: terminal-CLI, VS Code- / Cursor- / JetBrains-extensies, desktop-app, web"]}]}, {"id": "why-design", "heading": "Waarom Claude Code goed is in design", "blocks": [{"kind": "p", "text": "Onder coding-agents heeft Claude Code een reputatie voor smaak in frontend-werk. Een paar dingen verklaren dat."}, {"kind": "steps", "items": [{"label": "Specifieke, niet vage, beslissingen", "body": "Claude Code neigt naar concrete keuzes — exacte hex-waarden, spacing-schalen, typeschalen en componenthiërarchie — in plaats van vaagheid, en dat is wat een echte interface onderscheidt van een placeholder."}, {"label": "Codebase-bewust redeneren", "body": "Met een grote werkcontext refactort hij UI over veel bestanden tegelijk en hergebruikt hij je bestaande componenten en tokens in plaats van eenmalige stijlen opnieuw uit te vinden."}, {"label": "Een officiële frontend-skill", "body": "Anthropic levert een Frontend Design-skill die Claude eerst een designrichting laat schrijven en bewust wegstuurt van generieke systeemlettertypen en voorspelbare paarse gradiënten."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die Anthropic over zijn eigen modellen maakt: Claude heeft standaard geen smaak — aan zichzelf overgelaten convergeert hij naar het statistische midden van webdesign (Inter, paarse gradiënten, zachte schaduwen). Hij levert goed design wanneer je hem beperkingen geeft. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Claude Code voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Claude Code die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, CLAUDE.md configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → CLAUDE.md configureren → de Frontend Design-skill toevoegen → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in CLAUDE.md en wijs Claude erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Voeg browserverificatie toe", "body": "Koppel een Playwright- of Chrome-MCP zodat Claude in een echte browser rendert en zijn output over breakpoints heen controleert, in plaats van alleen te bevestigen dat de build slaagt."}]}]}, {"id": "skills-workflow", "heading": "De CLAUDE.md- en Skills-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Claude Code is hem echte referenties plus je designcontext voeden en dan itereren tot de UI klopt — met CLAUDE.md en Skills die de beperkingen vasthouden, zodat je ze niet bij elke prompt opnieuw hoeft uit te leggen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op, zelfs met een sterke agent.", "Houd je design system en conventies in CLAUDE.md en vertel Claude waar de tokens en canonieke primitives staan.", "Voeg de Frontend Design-skill toe zodat Claude zich vastlegt op een echte esthetische richting voordat hij code schrijft.", "Koppel browserverificatie zodat Claude rendert, naar breakpoints herschaalt en terugvergelijkt met de referenties — niet alleen bevestigt dat het bouwt."]}, {"kind": "p", "text": "Sleep een referentiebeeld in de sessie en prompt met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Draai er een dev-server naast, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Claude wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis. Gebruik plan-mode voor grotere refactors zodat je de aanpak kunt beoordelen voordat er bestanden veranderen."}]}, {"id": "figma", "heading": "Claude Code + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 leverden Anthropic en Figma een eersteklas, bidirectionele integratie via de Figma MCP-server. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Selecteer een frame in Figma of plak een link in Claude Code, haal de designcontext op en vraag hem het design te implementeren met je bestaande componentbibliotheek. Code Connect houdt de output uitgelijnd met je echte componenten."}, {"label": "Code → Design", "body": "Bouw en bekijk een feature in de browser en zeg dan “Send this to Figma” om de draaiende UI vast te leggen als bewerkbare Figma-lagen — het hele scherm of een geselecteerd element."}]}, {"kind": "p", "text": "Installeer hem eenmalig met claude plugin install figma@claude-plugins-official (Dev Mode MCP vereist een betaald Figma-plan). Dezelfde Figma MCP is beschikbaar voor Claude Code, Codex, Cursor en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewust UX-redeneren", "Frontend-redeneren en refactors met grote context"], ["Codex", "Sterke visuele afwerking en beeldbegrip; gesandboxte async builds", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "Zelfs met Claude Code's reputatie voor smaak is de meest voorkomende klacht over AI-gegenereerd design dat het generiek oogt — Inter-lettertypen, paarse gradiënten op wit, zachte schaduwen, te grote afgeronde hoeken, een esthetiek die “schreeuwt dat een AI dit maakte.” Anthropic zelf schrijft dit toe aan distributionele convergentie: veilige keuzes domineren de trainingsdata van het web. Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Installeer de Frontend Design-skill", "body": "Hij dwingt Claude zich op een echte richting vast te leggen en vermijdt expliciet lettertypen en gradiënten die door AI worden overgebruikt."}, {"label": "Schakel browserverificatie in", "body": "Laat Claude renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in CLAUDE.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Claude Code binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Claude Code als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Claude Code goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Claude Code als je agent.", "Authenticeer met je Anthropic API-key (BYOK) of Claude-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Claude Code-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Is Claude Code goed voor designwerk?", "text": "Ja — hij wordt algemeen beschouwd als de coding-agent met de beste frontend-smaak, die specifieke, codebase-bewuste beslissingen neemt over hex-waarden, spacing en typeschalen. Met de Frontend Design-skill, een design system en echte referentiebeelden in context produceert hij responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Heb ik een Claude-abonnement nodig om te designen met Claude Code?", "text": "Je kunt zowel een Anthropic API-key (BYOK, via de Console) als een Claude-abonnement (Pro / Max) gebruiken. Hoe dan ook sluist Open Design je credentials nooit door — ze worden direct gebruikt door je agent op je machine."}, {"name": "Claude Code of Codex voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen en frontend-redeneren; Codex heeft sterke visuele afwerking en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Claude Code met Figma?", "text": "Installeer de officiële Figma-plugin met claude plugin install figma@claude-plugins-official. Je kunt dan Figma-frames in code implementeren met de designcontext, en een draaiende UI terugduwen naar bewerkbare Figma-frames met “Send this to Figma.” Dev Mode MCP vereist een betaald Figma-plan."}, {"name": "Wat zijn Skills en CLAUDE.md?", "text": "CLAUDE.md is een markdown-bestand in je projectroot dat Claude Code aan het begin van elke sessie leest — de plek om je designconventies vast te leggen. Skills bundelen herbruikbare instructies en resources die Claude op aanvraag laadt, waaronder Anthropics officiële Frontend Design-skill. Open Design levert een samengestelde bibliotheek van beide, zodat je de setup per project overslaat."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer de Frontend Design-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in CLAUDE.md en schakel browserverificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Anthropic?", "text": "Nee. Claude Code is een product van Anthropic; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Claude en Claude Code zijn handelsmerken van Anthropic."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first en Apache-2.0. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Anthropic-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Claude Code, op de open manier.", "ctaBody": "Neem je eigen Anthropic-key of Claude-abonnement mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Claude Code binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex voor design — Open Design",
        description: "Hoe mensen OpenAI Codex gebruiken voor UI- en webdesign — de Product Design-plugin, Figma-integratie, frontend-skills — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex voor design.",
        lead: "Codex is de coding-agent van OpenAI. Met de Product Design-plugin en Figma-integratie is het een serieuze design-tool geworden. Open Design koppelt Codex aan een open-source design-workflow — je OpenAI-key of ChatGPT-abonnement, je bestanden, local-first.",
        rich: {"heroCtaLead": "Open Design maakt van Codex een local-first, open-source design-agent — je OpenAI-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex begon als codegenerator, maar werd in 2026 een geloofwaardige tool voor het ontwerpen van echte interfaces — zodra je hem de juiste referenties, skills en verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Codex voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Codex vandaag is, waarom hij plotseling goed is in frontend, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, de officiële Figma-round-trip, hoe hij zich verhoudt tot Cursor en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Feedbacklus van Codex-design: terminal-agent, browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: Codex bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-codex", "label": "Wat OpenAI Codex precies is"}, {"id": "why-design", "label": "Waarom Codex nu goed is in design"}, {"id": "setup", "label": "Codex instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "figma", "label": "Codex + Figma-round-trip"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Wat OpenAI Codex precies is (en wat niet)", "blocks": [{"kind": "p", "text": "Eerst een verduidelijking die bijna iedereen die op “Codex” zoekt op het verkeerde been zet. De oorspronkelijke OpenAI Codex was een code-completion-model uit 2021 dat de vroege GitHub Copilot aandreef en in 2023 werd uitgefaseerd. Daar gaat deze pagina niet over. De Codex van vandaag is de agentic coding-tool van OpenAI — hij plant, schrijft, draait en verifieert code op basis van taken in natuurlijke taal."}, {"kind": "p", "text": "De moderne Codex komt in vier vormen: een terminal-CLI (herschreven in Rust, gelicentieerd onder Apache-2.0), een IDE-extensie voor VS Code, Cursor en Windsurf, een cloud-/web-ervaring voor gedelegeerde async-taken, en een desktop-app met een ingebouwde browser en Computer Use."}, {"kind": "steps", "items": [{"label": "Standaardmodel", "body": "Vanaf medio 2026 is het aanbevolen model gpt-5.5, waarbij gpt-5.4 het model is dat OpenAI expliciet trainde voor frontend en computer use."}, {"label": "Instructiebestand", "body": "Codex leest een AGENTS.md-bestand in je project (een cross-tool-standaard) voor projectregels — de natuurlijke plek om je designconventies vast te leggen."}, {"label": "Sandbox", "body": "Hij draait in een sandbox op kernelniveau (standaard workspace-write), zodat een agent die je UI bewerkt niet buiten het project kan dwalen."}]}, {"kind": "ul", "items": ["Leverancier: OpenAI", "Credential: OpenAI API-key (BYOK) of ChatGPT-abonnement (Free / Go / Plus / Pro / Business / Enterprise)", "Licentie van de CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Waarom Codex nu goed is in design", "blocks": [{"kind": "p", "text": "Begin 2026 kwamen drie dingen samen die van Codex een echte design-tool maakten in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een frontend-getraind model", "body": "OpenAI leverde GPT-5.4, het eerste mainline-model getraind voor frontend en computer use, met veel beter beeldbegrip over de hele design-workflow en sterkere zelfverificatie. Het kan zelfs mood boards en visuele opties genereren voordat het zich vastlegt op de definitieve assets."}, {"label": "Een officiële frontend-skill", "body": "De openai/skills-catalogus levert een samengestelde frontend-skill die echte smaak afdwingt: cardloze layouts, full-bleed hero's, merk-eerste hiërarchie, ingetogen beweging, hooguit twee lettertypen en één accentkleur — en laat Codex een visuele these schrijven voordat hij bouwt."}, {"label": "Browserverificatie", "body": "Met de Playwright-skill opent Codex een echte browser, herschaalt naar breakpoints en vergelijkt zijn output terug met de referentie in plaats van alleen te controleren of de build slaagt."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les achter alle drie: Codex heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Codex voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Codex die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, configureren, skill installeren, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → AGENTS.md configureren → de frontend-skill installeren → browserverificatie inschakelen."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md of een DESIGN.md en wijs Codex erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Kies het juiste reasoning-niveau", "body": "OpenAI merkt op dat laag-tot-gemiddelde reasoning-niveaus vaak sterkere frontend-resultaten opleveren dan de hoogste instelling."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Codex is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. OpenAI's eigen richtlijnen komen neer op vijf stappen."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Codex waar de tokens en canonieke primitives staan.", "Schakel de interactieve Playwright-skill in zodat Codex in een echte browser rendert en naar breakpoints herschaalt.", "Itereer door Codex zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Voer beelden in door een screenshot in de terminal te slepen of met de image-flag, en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Draai een dev-server in een tweede terminal, houd prompts klein en gericht, en commit goede iteraties / draai slechte terug (vertel Codex wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "figma", "heading": "Codex + Figma: design ↔ code-round-trip", "blocks": [{"kind": "p", "text": "In februari 2026 kondigden OpenAI en Figma een officieel partnerschap aan, waarmee de eerdere Figma MCP-bèta een eersteklas, bidirectionele integratie werd. Hij werkt in beide richtingen."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de “link to selection” van een frame in Figma, plak die in Codex met get_design_context en vraag hem het design te implementeren met je bestaande componentbibliotheek."}, {"label": "Code → Design", "body": "De generate_figma_design-tool (“Code to Canvas”) zet een live, draaiende UI terug om in bewerkbare Figma-frames — het hele scherm, een geselecteerd element of een heel bestand."}]}, {"kind": "p", "text": "De Figma MCP draait als een remote server en is vrijgesteld van rate limits. Voeg hem eenmalig toe en hij is beschikbaar voor Codex, Claude Code, Cursor, VS Code en meer — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Codex", "Sterke visuele afwerking na GPT-5.4 + frontend-skill; beeldbegrip", "Gedelegeerde async builds, gesandboxte runs, draagbare AGENTS.md-regels"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Codex gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts, instructies die in de UI-tekst lekken en het snel bereiken van gebruikslimieten."}, {"kind": "steps", "items": [{"label": "Installeer een frontend-skill", "body": "Een samengestelde esthetische skill dwingt Codex zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Schakel Playwright-verificatie in", "body": "Laat Codex renderen en zichzelf controleren over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Codex binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Codex als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Codex goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Codex als je agent.", "Authenticeer met je OpenAI API-key (BYOK) of ChatGPT-abonnement — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Codex-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenAI Codex echt designwerk doen?", "text": "Ja — met een frontend-skill, een design system en echte referentiebeelden in context produceert Codex (zeker op GPT-5.4) responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit de OpenAI Codex Product Design-plugin?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Codex integreert als agent. Het vult OpenAI's eigen tooling aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een ChatGPT-abonnement nodig om te designen met Codex?", "text": "Je kunt zowel een OpenAI API-key (BYOK) als je ChatGPT-abonnement gebruiken. Inloggen met ChatGPT geeft doorgaans ruimere limieten; Open Design sluist je credentials hoe dan ook nooit door."}, {"name": "Codex of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Codex heeft sterke visuele afwerking na GPT-5.4 en blinkt uit in gedelegeerde, gesandboxte builds. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Codex met Figma?", "text": "Voeg de officiële Figma MCP-server toe (codex mcp add figma --url https://mcp.figma.com/mcp). Je kunt dan Figma-frames in code implementeren met get_design_context en een draaiende UI terugduwen naar bewerkbare Figma-frames met generate_figma_design."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Installeer een frontend-skill, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in AGENTS.md en schakel Playwright-verificatie in. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenAI?", "text": "Nee. Codex is een product van OpenAI; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. OpenAI en Codex zijn handelsmerken van OpenAI."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je OpenAI-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Codex, op de open manier.", "ctaBody": "Neem je eigen OpenAI-key mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Codex binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor voor designers — Open Design",
        description: "Hoe designers Cursor gebruiken voor UI- en webdesign — Design Mode, Figma-naar-code, de Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor voor designers.",
        lead: "Cursor is de AI-code-editor, nu met een visuele Design Mode. Designers gebruiken hem om UI te bewerken door aan te wijzen en te tekenen, en om Figma in code om te zetten. Open Design koppelt Cursor Agent aan een open-source design-workflow die je bestanden lokaal houdt.",
        rich: {"heroCtaLead": "Open Design maakt van Cursor een local-first, open-source design-agent — je Cursor-account of model-keys, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor is de AI-first code-editor die van “bouw het en zie het renderen” de standaardmanier maakte om UI te leveren. Met Agent-mode, inline edits, een preview in de editor en Figma via MCP is het een echte design-tool geworden — zodra je hem de juiste referenties, regels en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van Cursor voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat Cursor precies is, waarom zijn strakke itereren-en-bekijken-lus goed is voor design, hoe je hem vanaf nul opzet, de screenshot-en-preview-naar-UI-lus, de Figma-round-trip via MCP, hoe hij zich verhoudt tot Codex en Claude Code, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor-design-convergentie: editor links, een samengestelde hub met skills en design systems in het midden met het Cursor-merk centraal, en een gerenderde UI rechts", "caption": "Het kernidee: Cursor bewerkt en rendert UI in de editor, terwijl een samengestelde design-hub hem het system, de skills en de referenties voedt die de output intentioneel doen ogen."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-cursor", "label": "Wat Cursor precies is"}, {"id": "why-design", "label": "Waarom Cursor goed is in design"}, {"id": "setup", "label": "Cursor instellen voor design (vanaf nul)"}, {"id": "preview-workflow", "label": "De preview-naar-UI-workflow"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Wat Cursor precies is", "blocks": [{"kind": "p", "text": "Cursor is een AI-first code-editor gebouwd door Anysphere. Het is een fork van VS Code, dus de vertrouwde editor, extensies en keybindings blijven behouden, maar de workflow is heropgebouwd rond een AI-agent die je hele project kan lezen, meerdere bestanden kan bewerken, commando's kan uitvoeren en met jou in de lus kan itereren."}, {"kind": "p", "text": "Voor designwerk zijn de belangrijke vormen Agent-mode (je beschrijft een uitkomst en Cursor plant en bewerkt over bestanden heen), inline edits en Tab-completions voor snelle aanpassingen, een preview / browser in de editor zodat je de draaiende UI ziet zonder het venster te verlaten, en MCP-ondersteuning waarmee hij externe context kan binnenhalen, zoals een live Figma-bestand."}, {"kind": "steps", "items": [{"label": "Project-regels", "body": "Cursor leest project-instructiebestanden — geversioneerde `.mdc`-regels onder `.cursor/rules`, en een gewone `AGENTS.md` — zodat je je designconventies kunt vastleggen waar de agent ze elke ronde leest."}, {"label": "Modellen", "body": "Cursor is model-flexibel: hij wordt geleverd met frontier-modellen via je abonnement en ondersteunt ook het meebrengen van je eigen model-keys, zodat je de engine achter dezelfde editor-workflow kiest."}, {"label": "MCP", "body": "Hij spreekt het Model Context Protocol, zodat externe servers — meest relevant de Figma MCP-server — eersteklas context worden voor de agent."}]}, {"kind": "ul", "items": ["Leverancier: Anysphere", "Credential: Cursor-account / -abonnement (Hobby / Pro / Business) of je eigen model-keys (BYOK)", "Vorm: AI-first code-editor (VS Code-fork) met een agent en preview in de editor"]}]}, {"id": "why-design", "heading": "Waarom Cursor goed is in design", "blocks": [{"kind": "p", "text": "Cursors design-voorsprong is geen enkele feature — het is de strakheid van de build-and-see-lus. Drie dingen laten het aanvoelen als een design-tool in plaats van een generieke codegenerator."}, {"kind": "steps", "items": [{"label": "Een strakke itereren-en-bekijken-lus", "body": "Je prompt, Cursor bewerkt over bestanden heen, en de preview in de editor rendert het resultaat meteen — zodat je spacing, hiërarchie en beweging in seconden aanpast in plaats van heen en weer te gaan tussen een aparte terminal en browser."}, {"label": "Direct visueel bewerken", "body": "Naast chat laat Cursor je elementen in de preview selecteren en stijlen bijstellen, zodat kleine visuele correcties aanvoelen als design-edits in plaats van code-archeologie."}, {"label": "Project-regels en MCP-context", "body": "Met `.cursor/rules` (of `AGENTS.md`) en de Figma MCP-server werkt de agent tegen je tokens, componenten en echte design-specs in plaats van te gokken."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden."}, {"kind": "p", "text": "De les is dezelfde die elke agent leert: Cursor heeft standaard geen smaak. Hij levert goed design wanneer je hem beperkingen geeft — een design system, een esthetische skill en concrete referenties. Open Design verpakt precies die inputs, en daarom passen de twee samen (meer hieronder)."}]}, {"id": "setup", "heading": "Cursor voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een Cursor die UI kan bouwen, previewen en verifiëren tegen je design system."}, {"kind": "ol", "items": ["Installeer Cursor vanaf cursor.com en log in met je Cursor-account, of configureer je eigen model-keys (BYOK) in Settings.", "Open je project en kies een model in het chat- / Agent-paneel.", "Voeg project-regels toe: maak `.cursor/rules/*.mdc` voor gestructureerde, glob-scoped conventies, of een gewone `AGENTS.md` voor eenvoudige, leesbare instructies.", "Verbind de Figma MCP-server (optioneel) zodat de agent live designcontext kan lezen.", "Draai je dev-server en gebruik de preview in de editor om de UI te zien en te verifiëren terwijl je itereert."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren, regels configureren, skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren → project-regels configureren → een skill toevoegen → preview-verificatie inschakelen."}, {"kind": "p", "text": "Een minimaal project-regelbestand laat de agent designen naar een merk in plaats van terug te vallen op een generieke look. Zet het waar Cursor het elke ronde leest:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in `.cursor/rules` of `AGENTS.md` en wijs Cursor erop, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Houd prompts klein", "body": "Cursors strakke lus beloont gerichte vragen — itereer één component of state tegelijk en bekijk de preview tussen de rondes."}]}]}, {"id": "preview-workflow", "heading": "De preview-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij Cursor is een referentie omzetten in werkende, responsieve UI en in de editor itereren tot het klopt — terwijl je de hele tijd naar de live preview kijkt in plaats van te gokken."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel Cursor waar de tokens en canonieke primitives staan.", "Houd de preview in de editor open en je dev-server draaiend zodat elke edit meteen rendert op de breakpoints die voor jou belangrijk zijn.", "Itereer door de gerenderde UI terug te vergelijken met de referenties — en gebruik directe elementselectie in de preview voor kleine visuele correcties."]}, {"kind": "p", "text": "Voer referenties in door een beeld aan de chat te koppelen en prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commit goede iteraties en draai slechte terug (vertel Cursor wanneer je terugdraait) zodat elke ronde voortbouwt op een schone basis — dezelfde discipline die elke agent-lus tegen afdrijven beschermt."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor verbindt met Figma via de officiële Figma MCP-server, die de agent gestructureerde toegang geeft tot een live Figma-bestand in plaats van een platte screenshot. Dat haalt het giswerk uit de handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Kopieer de link van een frame in Figma, plak die in Cursor en vraag hem het design te implementeren. De MCP-server stelt echte designcontext beschikbaar — componenten, variabelen, layout-data, tokens — zodat de gegenereerde code de bron evenaart in plaats van benadert."}, {"label": "Blijf uitgelijnd", "body": "Met design-tokens, stijlen en componenten consistent gebruikt in Figma (en Code Connect waar beschikbaar) blijft Cursors output gekoppeld aan je echte design system in plaats van primitives opnieuw uit te vinden."}]}, {"kind": "p", "text": "Stel de remote Figma MCP-server eenmalig in en hij is beschikbaar voor Cursor als eersteklas context. Omdat MCP een open standaard is, is dezelfde server herbruikbaar over Cursor, Claude Code, Codex en VS Code — precies het soort draagbare, multi-agent-capaciteit dat Open Design is gebouwd om te orkestreren."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["Cursor", "Visuele build-and-see-lus met live preview in de editor en direct elementen bewerken", "Strak itereren-en-bekijken van UI-werk binnen een IDE"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip en gesandboxte runs", "Gedelegeerde async builds en draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: alle drie vallen zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over door Cursor gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn layouts die breken op mobiel en instructies die in de UI-tekst lekken."}, {"kind": "steps", "items": [{"label": "Voeg een design-skill toe", "body": "Een samengestelde esthetische skill dwingt Cursor zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Gebruik de preview om te verifiëren", "body": "Render en controleer jezelf over breakpoints heen in de preview in de editor, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in `.cursor/rules`", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met Cursor binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt Cursor als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die Cursor goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld."}, {"kind": "ol", "items": ["Installeer Open Design en kies Cursor als je agent.", "Authenticeer met je Cursor-account of je eigen model-keys (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde Cursor-agent, dezelfde key — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan Cursor echt designwerk doen?", "text": "Ja — met een design-skill, een design system en echte referentiebeelden in context produceert Cursor responsieve UI van productiekwaliteit, en met de preview in de editor kun je die visueel verifiëren en verfijnen. Zonder die context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Is dit een officieel Cursor-product?", "text": "Nee. Open Design is een onafhankelijk open-source project dat Cursor integreert als agent. Het vult Cursor aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een Cursor-abonnement nodig om te designen met Cursor?", "text": "Je kunt een Cursor-account / -abonnement gebruiken of je eigen model-keys meebrengen (BYOK). Open Design sluist je credentials hoe dan ook nooit door — ze worden direct gebruikt door je agent."}, {"name": "Cursor of Claude Code voor frontend-design?", "text": "Beide zijn sterk. Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen; Cursors voorsprong is zijn strakke build-and-see-lus met een live preview in de editor. Veel teams gebruiken beide — met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe verbind ik Cursor met Figma?", "text": "Voeg de officiële Figma MCP-server toe in Cursor, plak dan een Figma-frame-link in de chat en vraag Cursor die te implementeren. De server stelt echte componenten, variabelen en layout-data beschikbaar zodat de gegenereerde code het brondesign evenaart."}, {"name": "Hoe vermijd ik de generieke “AI slop”-esthetiek?", "text": "Voeg een design-skill toe, lever echte design-tokens en referentie-screenshots aan, leg merkregels vast in `.cursor/rules` of `AGENTS.md`, en verifieer over breakpoints heen in de preview. Open Design levert deze als een samengestelde bibliotheek, zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan Cursor of Anysphere?", "text": "Nee. Cursor is een product van Anysphere; Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter. Cursor en Anysphere zijn handelsmerken van Anysphere, Inc."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je Cursor- of model-credentials worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met Cursor, op de open manier.", "ctaBody": "Neem je eigen Cursor-account of model-keys mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik Cursor binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode voor design — Open Design",
        description: "Hoe mensen OpenCode gebruiken voor UI- en webdesign — design.md-bestanden, UI/UX-skills, Figma MCP — en hoe Open Design er een local-first, open-source design-agent van maakt.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode voor design.",
        lead: "OpenCode is de open-source terminal-AI-coding-agent. Designers schroeven er design-skills en DESIGN.md-bestanden op om echte UI te genereren. Open Design maakt daar een gestructureerde, open-source workflow van — neem je provider-keys mee en houd alles lokaal.",
        rich: {"heroCtaLead": "Open Design maakt van OpenCode een local-first, open-source design-agent — elk model dat je kiest met je eigen provider-key, je bestanden, en een samengestelde bibliotheek van skills en design systems eromheen.", "heroCtaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode is een open-source, terminal-first AI-coding-agent die bewust modelonafhankelijk is: je neemt je eigen provider-key mee en draait welk model je maar wilt achter dezelfde workflow. Die openheid maakt hem een natuurlijke basis voor designwerk — maar zoals elke agent levert hij alleen goede UI wanneer je hem de juiste referenties, skills en een verificatielus geeft. Dit is een praktische, end-to-end gids voor het gebruik van OpenCode voor UI-, frontend- en design-system-werk, en voor het inbedden ervan in een gestructureerde design-workflow met Open Design.", "Het behandelt wat OpenCode precies is, waarom een modelonafhankelijke open agent goed past bij design, hoe je hem vanaf nul opzet, de screenshot-naar-UI-lus, hoe AGENTS.md en MCP hem uitbreiden, hoe hij zich verhoudt tot Codex, Claude Code en Cursor, de valkuilen die AI-output generiek doen ogen, en hoe Open Design de kloof dicht als een open, local-first designlaag — een natuurlijke combinatie, want beide projecten zijn open-source en draaien op je eigen machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Feedbacklus van OpenCode-design: een terminal-TUI-agent, een browser die de UI rendert, en een werkruimte, met een feedbackpijl die terugloopt", "caption": "De kernlus: OpenCode bouwt UI in de terminal, rendert en verifieert die in een echte browser, en itereert tegen je referenties — op welk model je ook kiest."}, "tocLabel": "Op deze pagina", "toc": [{"id": "what-is-opencode", "label": "Wat OpenCode precies is"}, {"id": "why-design", "label": "Waarom een open, elk-model-agent past bij design"}, {"id": "setup", "label": "OpenCode instellen voor design (vanaf nul)"}, {"id": "screenshot-workflow", "label": "De screenshot-naar-UI-workflow"}, {"id": "extend", "label": "AGENTS.md, MCP en deelbare sessies"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Valkuilen en de “AI slop”-look"}, {"id": "open-design", "label": "Designen met OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Wat OpenCode precies is", "blocks": [{"kind": "p", "text": "OpenCode is een open-source AI-coding-agent gebouwd voor de terminal, onderhouden door het team achter SST (Anomaly Innovations). Hij leest je repository, voert commando's uit, bewerkt bestanden en praat met een large language model — maar anders dan leverancier-gebonden agents levert hij geen eigen model. Je richt hem op welke provider en welk model je maar wilt en neemt je eigen key mee."}, {"kind": "p", "text": "Hij draait als een terminal-UI (TUI), met een desktop-app en IDE-extensies bovenop dezelfde engine. Onder de motorkap gebruikt hij een client/server-architectuur, zodat de agent die het werk doet losgekoppeld is van de vorm waarmee je hem aanstuurt. Twee ingebouwde agents — build en plan — wissel je met de Tab-toets."}, {"kind": "steps", "items": [{"label": "Modelonafhankelijk", "body": "Modellen en providers komen van models.dev, een open catalogus. Je configureert ze in opencode.json met een provider/model-id-string en kunt providers die je niet geladen wilt hebben uitschakelen — zodat dezelfde design-workflow draait op Anthropic, OpenAI, Google, OpenRouter, lokale modellen en meer."}, {"label": "Instructiebestand", "body": "OpenCode leest een AGENTS.md-bestand in je project (de cross-tool-standaard, ook compatibel met CLAUDE.md) voor projectregels — de natuurlijke plek om je designconventies vast te leggen. Draai /init om er een te genereren."}, {"label": "Uitbreidbaar", "body": "Hij ondersteunt LSP-integratie, MCP-servers, thema's, keybinds en custom commando's, plus deelbare sessielinks voor samenwerking."}]}, {"kind": "ul", "items": ["Maintainer: SST / Anomaly Innovations (open-source project)", "Credential: je eigen API-key(s) voor model-providers — BYOK, geen vendor lock-in", "Licentie: MIT, open source"]}]}, {"id": "why-design", "heading": "Waarom een open, elk-model-agent past bij designwerk", "blocks": [{"kind": "p", "text": "OpenCode heeft geen enkel “design-model” zoals een leverancier-agent dat heeft — en dat is precies het punt. Omdat hij modelonafhankelijk en open is, kun je dezelfde design-workflow draaien op welk model op dit moment het best is in frontend, hem later vervangen, of terugvallen op een lokaal model, allemaal zonder je setup te veranderen."}, {"kind": "p", "text": "Maar modelkeuze alleen koopt geen smaak. Zoals elke coding-agent produceert OpenCode generieke UI tenzij je hem beperkingen geeft. Goede design-output komt voort uit drie inputs die jij aanlevert."}, {"kind": "steps", "items": [{"label": "Een design system", "body": "Echte tokens, primitives en conventies die de agent hergebruikt, zodat de output bij een merk past in plaats van terug te vallen op een generieke look."}, {"label": "Een esthetische skill", "body": "Een samengestelde skill die echte smaak afdwingt — ingetogen beweging, merk-eerste hiërarchie, hooguit twee lettertypen en één accentkleur — en de agent zich op een richting laat vastleggen voordat hij bouwt."}, {"label": "Concrete referenties", "body": "Echte referentiebeelden en meerdere states (desktop en mobiel, hover, leeg, laden), niet één enkele hero-shot."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram dat laat zien hoe design system, skill en referentiebeeld samenkomen tot goede design-output", "caption": "Smaak komt voort uit drie inputs die jij aanlevert: een design system, een skill en echte referentiebeelden — onafhankelijk van welk model je draait."}, {"kind": "p", "text": "De les: OpenCode geeft je modelvrijheid, maar smaak komt nog steeds voort uit een samengestelde designcontext. Open Design verpakt precies die inputs, en daarom passen de twee samen — beide zijn open-source en local-first (meer hieronder)."}]}, {"id": "setup", "heading": "OpenCode voor designwerk opzetten, vanaf nul", "blocks": [{"kind": "p", "text": "Dit is het volledige pad van een schone machine naar een OpenCode die UI kan bouwen en verifiëren."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Setupflow in vijf stappen: installeren, authenticeren met je provider-key, AGENTS.md configureren, een skill toevoegen, verifiëren", "caption": "De setup-volgorde: installeren → authenticeren (je provider-key) → AGENTS.md configureren → een skill toevoegen → verifiëren in een echte browser."}, {"kind": "steps", "items": [{"label": "Leg je designregels vast", "body": "Zet je tokens, primitives en conventies in AGENTS.md (of een DESIGN.md die daaruit wordt aangehaald) zodat de output bij een merk past in plaats van terug te vallen op een generieke look. De instructions-optie in opencode.json kan via globs naar extra regelbestanden verwijzen."}, {"label": "Kies een capabel model", "body": "Omdat OpenCode modelonafhankelijk is, kies je welke provider/model op dit moment het sterkst is in frontend voor de design-ronde — en houd je de rest van je workflow onveranderd."}]}]}, {"id": "screenshot-workflow", "heading": "De screenshot-naar-UI-workflow", "blocks": [{"kind": "p", "text": "De design-lus met de meeste hefboomwerking bij elke agent is een referentiebeeld omzetten in werkende, responsieve UI en itereren tot het klopt. Dezelfde vijfstappenvorm geldt in OpenCode."}, {"kind": "ol", "items": ["Begin met de helderste visuele referenties die je hebt — en neem meerdere states mee (desktop en mobiel, hover, leeg, laden), niet alleen één hero-shot.", "Wees specifiek in de prompt; vage prompts leveren generieke UI op.", "Bereid een design system voor en vertel OpenCode waar de tokens en canonieke primitives staan (in AGENTS.md).", "Draai een dev-server en laat de agent in een echte browser renderen, met herschaling naar breakpoints om het resultaat te controleren.", "Itereer door OpenCode zijn implementatie terug te laten vergelijken met de screenshots — niet alleen te bevestigen dat het bouwt."]}, {"kind": "p", "text": "Verwijs naar bestanden met @ in de TUI voor een fuzzy-zoekopdracht in je werkmap, voer shell-commando's inline uit met een voorafgaande !, en stuur acties aan met /-commando's. Prompt dan met concrete beperkingen:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Houd prompts klein en gericht, commit goede iteraties en draai slechte terug (vertel OpenCode wanneer je terugdraait), zodat elke ronde voortbouwt op een schone basis."}]}, {"id": "extend", "heading": "AGENTS.md, MCP en deelbare sessies", "blocks": [{"kind": "p", "text": "Drie uitbreidingspunten maken OpenCode praktisch voor langdurig designwerk, en alle drie sluiten naadloos aan op een open design-workflow."}, {"kind": "steps", "items": [{"label": "AGENTS.md-regels", "body": "Projectregels staan in een AGENTS.md in de repo-root (of globale regels in ~/.config/opencode/AGENTS.md). Het is de duurzame thuisbasis voor je designconventies, gelezen bij elke ronde, en compatibel met de CLAUDE.md-bestanden die andere agents gebruiken."}, {"label": "MCP-servers", "body": "OpenCode ondersteunt zowel lokale (command) als remote (URL) MCP-servers, geconfigureerd onder de mcp-sleutel — de draagbare manier om designcontext en externe tools binnen te halen die over agents heen werken, niet alleen in OpenCode."}, {"label": "Deelbare sessies", "body": "Het /share-commando maakt een publieke link naar een gesprek voor samenwerking of review, en /unshare trekt die in — handig om feedback te krijgen op een design-ronde."}]}, {"kind": "p", "text": "Dit zijn draagbare, multi-agent-capaciteiten — precies het soort dingen die Open Design is gebouwd om te orkestreren, in plaats van per project opnieuw te creëren."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor voor design", "blocks": [{"kind": "p", "text": "Er is geen enkele winnaar voor designwerk — elke agent heeft een andere kracht, en ervaren teams stapelen ze. Een eerlijke samenvatting:"}, {"kind": "table", "columns": ["Agent", "Design-kracht", "Beste voor"], "rows": [["OpenCode", "Open-source en modelonafhankelijk; draai elke provider achter één terminal-workflow", "BYOK-vrijheid, modellen wisselen, volledig open en local-first setups"], ["Codex", "Sterke visuele afwerking met een frontend-skill; beeldbegrip", "Gedelegeerd async, gesandboxte builds, draagbare AGENTS.md-regels"], ["Claude Code", "Specifieke designbeslissingen (hex, spacing, type) en codebase-bewuste UX", "Frontend-redeneren en refactors met grote context"], ["Cursor", "Visuele build-and-see-lus met live preview en inline edits", "Strak itereren-en-bekijken van UI-werk binnen een IDE"]]}, {"kind": "p", "text": "Het terugkerende oordeel van de community is dat smaak van mensen komt: ze vallen allemaal zonder skills, referenties en beperkingen terug op een generieke esthetiek. Dat is het echte probleem dat opgelost moet worden — en het heeft de vorm van een design-tool, niet van een model, en precies daarom past een open agent als OpenCode zo goed bij een open designlaag."}]}, {"id": "pitfalls", "heading": "Valkuilen, en hoe je de “AI slop”-look vermijdt", "blocks": [{"kind": "p", "text": "De meest voorkomende klacht over AI-gegenereerd design is dat het generiek oogt — zachte gradiënten, zwevende panelen, te grote afgeronde hoeken, dramatische schaduwen, een Inter-en-paars-sfeer die “schreeuwt dat een AI dit maakte.” Andere gemelde problemen zijn kapotte mobiele layouts en instructies die in de UI-tekst lekken. Geen van deze is uniek voor OpenCode; ze zijn wat er gebeurt wanneer welke agent dan ook draait zonder een samengestelde designcontext."}, {"kind": "steps", "items": [{"label": "Voeg een esthetische skill toe", "body": "Een samengestelde design-skill dwingt de agent zich op een echte richting vast te leggen in plaats van de standaard look."}, {"label": "Verifieer in een echte browser", "body": "Render en controleer jezelf over breakpoints heen, zodat layouts niet stilletjes breken op mobiel."}, {"label": "Lever tokens en referenties aan", "body": "Echte design-tokens en referentie-screenshots zijn de grootste hefboom op de outputkwaliteit."}, {"label": "Leg regels vast in AGENTS.md", "body": "Zet stijlregels als “geen hero cards, maximaal twee lettertypen, merk-eerste hiërarchie” daar waar de agent ze elke ronde leest."}]}, {"kind": "p", "text": "Merk op dat elke remedie draait om het geven van een samengestelde designcontext aan de agent — ongeacht welk model je draait. Die context met de hand onderhouden, per project, is precies het sleurwerk dat Open Design wegneemt."}]}, {"id": "open-design", "heading": "Designen met OpenCode binnen Open Design", "blocks": [{"kind": "p", "text": "Open Design is de open-source designlaag waar de workflow hierboven steeds om vraagt. Het behandelt OpenCode als een first-party adapter en omhult hem met een samengestelde bibliotheek van skills en design systems, een gestructureerde render-pipeline en een lokale desktop-UI — zodat de designcontext die elke agent goed maakt er vanaf de eerste run is, niet elke keer met de hand samengesteld. Beide projecten zijn open-source en local-first, wat de combinatie een natuurlijke match maakt."}, {"kind": "ol", "items": ["Installeer Open Design en kies OpenCode als je agent.", "Authenticeer met je eigen API-key voor model-providers (BYOK) — credentials blijven op je machine en worden nooit via ons doorgesluisd.", "Kies een willekeurige provider en model, plus een design system en een skill, en genereer vervolgens decks, prototypes en landingspagina's met consistente smaak.", "Elk artefact en DESIGN.md-bestand staat in je eigen repo, niet in een gehoste cloud."]}, {"kind": "p", "text": "Dezelfde OpenCode-agent, dezelfde modelvrijheid — plus een echte, draagbare, open-source design-workflow eromheen. Het is local-first en Apache-2.0, dus niets over je werk of je credentials verlaat je machine."}]}], "faqTitle": "Veelgestelde vragen", "faq": [{"name": "Kan OpenCode echt designwerk doen?", "text": "Ja — met een esthetische skill, een design system en echte referentiebeelden in context produceert OpenCode responsieve UI van productiekwaliteit en kan hij die in een browser verifiëren. Omdat hij modelonafhankelijk is, draai je welk model op dit moment het best is in frontend. Zonder die samengestelde context neigt hij naar een generieke look, en dat is de kloof die Open Design dicht."}, {"name": "Welk model moet ik gebruiken met OpenCode voor design?", "text": "Welk je maar wilt — OpenCode is provider-onafhankelijk via models.dev, dus je kunt Anthropic, OpenAI, Google, OpenRouter of lokale modellen achter dezelfde workflow draaien en op elk moment wisselen. De kwaliteit van de design-output hangt veel meer af van je skill, design system en referenties dan van het model alleen."}, {"name": "Is Open Design gemaakt door het OpenCode-team (SST)?", "text": "Nee. Open Design is een onafhankelijk open-source project dat OpenCode integreert als agent. Het vult OpenCode aan met een local-first, open bibliotheek van skills en design systems."}, {"name": "Heb ik een speciaal abonnement nodig om te designen met OpenCode?", "text": "Nee — OpenCode is BYOK. Je neemt je eigen API-key voor model-providers mee, en Open Design sluist je credentials nooit door. Er is geen vendor lock-in."}, {"name": "OpenCode of Codex of Claude Code voor frontend-design?", "text": "Alle zijn sterk, en veel teams stapelen ze. OpenCode's voorsprong is dat hij volledig open-source en modelonafhankelijk is; Codex blinkt uit in gedelegeerde, gesandboxte builds; Claude Code staat bekend om specifieke, codebase-bewuste designbeslissingen. Met Open Design wissel je van agent zonder je design-workflow te veranderen."}, {"name": "Hoe breid ik OpenCode uit voor designcontext?", "text": "Leg regels vast in AGENTS.md, voeg MCP-servers toe onder de mcp-sleutel voor draagbare tools en designcontext, en gebruik deelbare sessies voor review. Open Design levert een samengestelde bibliotheek van skills en design systems zodat je de setup per project overslaat."}, {"name": "Is Open Design gelieerd aan OpenCode of SST?", "text": "Nee. OpenCode is een open-source project onderhouden door SST (Anomaly Innovations); Open Design is een onafhankelijk open-source project dat hem ondersteunt als first-party adapter."}, {"name": "Zijn mijn bestanden en credentials veilig?", "text": "Ja — Open Design is local-first. Je bestanden, artefacten en DESIGN.md blijven in je eigen repo, en je credentials voor model-providers worden direct gebruikt door je agent, nooit via Open Design-servers geleid."}], "ctaTitle": "Design met OpenCode, op de open manier.", "ctaBody": "Neem je eigen key voor model-providers mee, houd elk bestand lokaal, en krijg een samengestelde design-bibliotheek rondom de open agent die je al gebruikt.", "ctaActions": [{"label": "Gebruik OpenCode binnen Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Geef een ster op GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Download de desktop-app", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Bekijk alle ondersteunde agents"},
      },
    },
    'ar': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code للتصميم — Open Design",
        description: "كيف يستخدم المصممون Claude Code في تصميم الواجهات والويب، وكيف يحوّله Open Design إلى وكيل تصميم حقيقي — محلي أولًا، بمبدأ BYOK، مع مكتبة منسّقة من الـ skills وأنظمة التصميم.",
        breadcrumb: "Claude Code",
        label: "وكيل · Claude Code",
        heading: "Claude Code للتصميم.",
        lead: "‏Claude Code هو وكيل البرمجة الطرفي من Anthropic. يستخدمه الناس بالفعل لبناء الواجهات وأنظمة التصميم وصفحات الهبوط. يربطه Open Design بسير عمل تصميمي حقيقي — أحضر مفتاح Anthropic أو اشتراك Claude، واحتفظ بكل ملف محليًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Claude Code إلى وكيل تصميم محلي أولًا ومفتوح المصدر — مفتاح Anthropic أو اشتراك Claude الخاص بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Claude Code داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["يُعدّ Claude Code على نطاق واسع وكيل البرمجة صاحب الذوق الأفضل في عمل الواجهات الأمامية — فهو يحلّل الواجهات بدقة غير معتادة، ويسمّي قيم hex بالضبط والمسافات وسلالم الخطوط، ويعيد هيكلة الواجهة عبر قاعدة شيفرة كبيرة دون أن يفقد الخيط. لكنه افتراضيًا يظل ينحرف نحو مظهر عام ما لم تزوّده بنظام تصميم وskills ومراجع حقيقية. هذا دليل عملي وشامل لاستخدام Claude Code في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل منظّم عبر Open Design.", "يغطّي ما هو Claude Code فعلًا، ولماذا هو قوي في الواجهة الأمامية، وكيف تعدّه من الصفر، وسير عمل CLAUDE.md والـ Skills، والتكامل الرسمي ثنائي الاتجاه مع Figma، وكيف يقارَن بـ Codex وCursor، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "حلقة تغذية راجعة لتصميم Claude Code: وكيل طرفي يتخذ قرارات تصميم محددة، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يحلّل Claude Code قرارات الواجهة المحددة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويتقارب نحو مراجعك."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-claude-code", "label": "ما هو Claude Code فعلًا"}, {"id": "why-design", "label": "لماذا يجيد Claude Code التصميم"}, {"id": "setup", "label": "إعداد Claude Code للتصميم (من الصفر)"}, {"id": "skills-workflow", "label": "سير عمل CLAUDE.md والـ Skills"}, {"id": "figma", "label": "التكامل ثنائي الاتجاه بين Claude Code وFigma"}, {"id": "vs", "label": "‏Claude Code مقابل Codex مقابل Cursor"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Claude Code داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-claude-code", "heading": "ما هو Claude Code فعلًا", "blocks": [{"kind": "p", "text": "‏Claude Code هو أداة البرمجة الوكيلة من Anthropic. يقرأ قاعدة شيفرتك، ويحرّر الملفات، ويشغّل الأوامر، ويتكامل مع أدوات التطوير لديك — مخطِّطًا وكاتبًا ومتحققًا من العمل انطلاقًا من مهام باللغة الطبيعية بدلًا من مجرد إكمال السطور تلقائيًا."}, {"kind": "p", "text": "يأتي عبر عدة واجهات تشترك جميعها في المحرك نفسه: واجهة سطر أوامر طرفية، وإضافات لبيئات التطوير VS Code وCursor وJetBrains، وتطبيق سطح مكتب بمراجعة فروقات مرئية، وتجربة ويب للمهام الطويلة. وتنتقل ملفات CLAUDE.md وإعداداتك وخوادم MCP عبرها كلها."}, {"kind": "steps", "items": [{"label": "ملف التعليمات", "body": "يقرأ Claude Code ملف CLAUDE.md في جذر مشروعك في بداية كل جلسة — المكان الطبيعي لترميز أعراف التصميم لديك والـ tokens وقوائم المراجعة."}, {"label": "الـ Skills", "body": "تجمع Agent Skills تعليمات وسكربتات وموارد قابلة للتكرار يحمّلها Claude عند الطلب، بما في ذلك Frontend Design skill الرسمي من Anthropic للذوق."}, {"label": "التخطيط والوكلاء الفرعيون", "body": "يمكنه التخطيط قبل التنفيذ وإنشاء وكلاء فرعيين يعملون على أجزاء مختلفة من المهمة بالتوازي، ما يحافظ على تماسك إعادة هيكلة الواجهات الكبيرة."}]}, {"kind": "ul", "items": ["المزوِّد: Anthropic", "بيانات الاعتماد: مفتاح Anthropic API (مبدأ BYOK، عبر الـ Console) أو اشتراك Claude (Pro / Max)", "الواجهات: واجهة سطر أوامر طرفية، إضافات VS Code / Cursor / JetBrains، تطبيق سطح مكتب، ويب"]}]}, {"id": "why-design", "heading": "لماذا يجيد Claude Code التصميم", "blocks": [{"kind": "p", "text": "من بين وكلاء البرمجة، يتمتع Claude Code بسمعة الذوق في عمل الواجهات الأمامية. تفسّر ذلك بضعة أمور."}, {"kind": "steps", "items": [{"label": "قرارات محددة لا غامضة", "body": "يميل Claude Code إلى الالتزام بخيارات ملموسة — قيم hex بالضبط، وسلالم المسافات، وتدرّجات الخطوط، وهرمية المكوّنات — بدلًا من التهرّب، وهذا ما يميّز واجهة حقيقية عن مجرد عنصر نائب."}, {"label": "تفكير واعٍ بقاعدة الشيفرة", "body": "بفضل سياق عمل واسع، يعيد هيكلة الواجهة عبر ملفات كثيرة دفعة واحدة، معيدًا استخدام مكوّناتك وtokens الموجودة بدلًا من ابتكار أنماط لمرة واحدة."}, {"label": "skill رسمي للواجهة الأمامية", "body": "تقدّم Anthropic مهارة Frontend Design تجعل Claude يكتب اتجاهًا تصميميًا أولًا، وتبتعد عمدًا عن خطوط النظام العامة والتدرّجات البنفسجية المتوقّعة."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس هو نفسه الذي تقوله Anthropic عن نماذجها: لا يملك Claude ذوقًا افتراضيًا — وإذا تُرك وحده يتقارب نحو المركز الإحصائي لتصميم الويب (Inter، تدرّجات بنفسجية، ظلال ناعمة). إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Claude Code لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Claude Code قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، تهيئة CLAUDE.md، إضافة الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة CLAUDE.md ← إضافة Frontend Design skill ← تفعيل التحقق في المتصفح."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في CLAUDE.md ووجّه Claude إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "أضف التحقق في المتصفح", "body": "اربط Playwright أو Chrome MCP كي يعرض Claude في متصفح حقيقي ويتحقق من مخرجاته عبر نقاط التوقف بدلًا من مجرد تأكيد نجاح البناء."}]}]}, {"id": "skills-workflow", "heading": "سير عمل CLAUDE.md والـ Skills", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Claude Code هي تغذيته بمراجع حقيقية إضافةً إلى سياق التصميم لديك، ثم التكرار حتى تطابق الواجهة — مع حمل CLAUDE.md والـ Skills للقيود كي لا تعيد شرحها في كل مطالبة."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة حتى مع وكيل قوي.", "احتفظ بنظام تصميمك وأعرافك في CLAUDE.md، وأخبر Claude بمكان الـ tokens والعناصر الأولية المرجعية.", "أضف Frontend Design skill كي يلتزم Claude باتجاه جمالي حقيقي قبل كتابة الشيفرة.", "اربط التحقق في المتصفح كي يعرض Claude، ويغيّر الحجم إلى نقاط التوقف، ويقارن بالمراجع — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "أسقِط صورة مرجعية في الجلسة وأرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "شغّل خادم تطوير بالتوازي، وأبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة / وأرجِع السيئة (مع إخبار Claude حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة. استخدم وضع التخطيط لإعادة الهيكلة الأكبر كي تراجع المنهج قبل أي تغيير على الملفات."}]}, {"id": "figma", "heading": "‏Claude Code + Figma: تكامل ثنائي الاتجاه بين التصميم والشيفرة", "blocks": [{"kind": "p", "text": "في فبراير 2026 أطلقت Anthropic وFigma تكاملًا متقدّمًا ثنائي الاتجاه عبر خادم Figma MCP. وهو يعمل في الاتجاهين."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "حدّد إطارًا في Figma أو الصق رابطًا في Claude Code، واسحب سياق التصميم، واطلب منه تنفيذ التصميم باستخدام مكتبة مكوّناتك الموجودة. ويبقي Code Connect المخرجات متوائمة مع مكوّناتك الحقيقية."}, {"label": "الشيفرة ← التصميم", "body": "ابنِ ميزة وعاينها في المتصفح، ثم قل «Send this to Figma» لالتقاط الواجهة قيد التشغيل بصفتها طبقات Figma قابلة للتحرير — الشاشة كاملةً أو عنصرًا محددًا."}]}, {"kind": "p", "text": "ثبّته مرة واحدة عبر claude plugin install figma@claude-plugins-official (يتطلب Dev Mode MCP خطة Figma مدفوعة). وخادم Figma MCP نفسه متاح لـ Claude Code وCodex وCursor وVS Code — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Claude Code مقابل Codex مقابل Cursor للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتفكير في تجربة المستخدم واعٍ بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"], ["Codex", "صقل بصري قوي وفهم للصور؛ عمليات بناء غير متزامنة في بيئة معزولة", "عمليات البناء غير المتزامنة المفوّضة وقواعد AGENTS.md المحمولة"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "حتى مع سمعة Claude Code في الذوق، فإن أكثر شكوى شيوعًا عن التصميم المولَّد بالذكاء الاصطناعي أنه يبدو عامًا — خطوط Inter، تدرّجات بنفسجية على أبيض، ظلال ناعمة، زوايا دائرية مفرطة الحجم، جماليّة «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتعزو Anthropic نفسها ذلك إلى التقارب التوزيعي: الخيارات الآمنة تهيمن على بيانات تدريب الويب. وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال وتسرّب التعليمات إلى نصوص الواجهة."}, {"kind": "steps", "items": [{"label": "ثبّت Frontend Design skill", "body": "يجبر Claude على الالتزام باتجاه حقيقي ويتجنّب صراحةً الخطوط والتدرّجات المفرَطة الاستخدام من الذكاء الاصطناعي."}, {"label": "فعّل التحقق في المتصفح", "body": "اجعل Claude يعرض ويتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في CLAUDE.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Claude Code داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Claude Code بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Claude Code جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Claude Code وكيلًا لك.", "صادِق بمفتاح Anthropic API (مبدأ BYOK) أو اشتراك Claude — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Claude Code نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل Claude Code جيد لعمل التصميم؟", "text": "نعم — فهو يُعدّ على نطاق واسع وكيل البرمجة صاحب الذوق الأفضل في الواجهة الأمامية، إذ يتخذ قرارات محددة وواعية بقاعدة الشيفرة بشأن قيم hex والمسافات وسلالم الخطوط. ومع Frontend Design skill ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل أحتاج إلى اشتراك Claude للتصميم بـ Claude Code؟", "text": "يمكنك استخدام مفتاح Anthropic API (مبدأ BYOK، عبر الـ Console) أو اشتراك Claude (Pro / Max). وفي كلتا الحالتين لا يمرّر Open Design بيانات اعتمادك أبدًا — فهي تُستخدَم مباشرةً بواسطة وكيلك على جهازك."}, {"name": "‏Claude Code أم Codex لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة وتفكير في الواجهة الأمامية؛ ويتمتع Codex بصقل بصري قوي ويتفوّق في عمليات البناء المفوّضة المعزولة. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Claude Code بـ Figma؟", "text": "ثبّت إضافة Figma الرسمية عبر claude plugin install figma@claude-plugins-official. عندها يمكنك تنفيذ إطارات Figma في شيفرة باستخدام سياق التصميم، ودفع واجهة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير عبر «Send this to Figma». ويتطلب Dev Mode MCP خطة Figma مدفوعة."}, {"name": "ما هي الـ Skills وملف CLAUDE.md؟", "text": "‏CLAUDE.md ملف markdown في جذر مشروعك يقرؤه Claude Code في بداية كل جلسة — وهو المكان لترميز أعراف التصميم لديك. وتجمع الـ Skills تعليمات وموارد قابلة للتكرار يحمّلها Claude عند الطلب، بما في ذلك Frontend Design skill الرسمي من Anthropic. ويقدّم Open Design مكتبة منسّقة من الاثنين كي تتخطّى الإعداد لكل مشروع."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "ثبّت Frontend Design skill، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في CLAUDE.md، وفعّل التحقق في المتصفح. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ Anthropic؟", "text": "لا. Claude Code منتج من Anthropic؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وClaude وClaude Code علامتان تجاريتان لـ Anthropic."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا وبرخصة Apache-2.0. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد Anthropic مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Claude Code، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح Anthropic أو اشتراك Claude الخاص بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Claude Code داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex للتصميم — Open Design",
        description: "كيف يستخدم الناس OpenAI Codex في تصميم الواجهات والويب — إضافة Product Design، تكامل Figma، skills الواجهة الأمامية — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "Codex",
        label: "وكيل · Codex",
        heading: "Codex للتصميم.",
        lead: "‏Codex هو وكيل البرمجة من OpenAI. وبإضافة Product Design وتكامل Figma صار أداة تصميم جادّة. يربط Open Design الأداة Codex بسير عمل تصميمي مفتوح المصدر — مفتاح OpenAI أو اشتراك ChatGPT الخاص بك، وملفاتك، محليًا أولًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Codex إلى وكيل تصميم محلي أولًا ومفتوح المصدر — مفتاح OpenAI الخاص بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Codex داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["بدأ OpenAI Codex مولّدًا للشيفرة، لكنه صار في 2026 أداة موثوقة لتصميم واجهات حقيقية — بمجرد أن تزوّده بالمراجع والـ skills وحلقة التحقق الصحيحة. هذا دليل عملي وشامل لاستخدام Codex في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو Codex اليوم، ولماذا صار فجأةً جيدًا في الواجهة الأمامية، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-إلى-الواجهة، والتكامل الرسمي ثنائي الاتجاه مع Figma، وكيف يقارَن بـ Cursor وClaude Code، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "حلقة تغذية راجعة لتصميم Codex: وكيل طرفي، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يبني Codex الواجهة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويكرّر مقابل مراجعك."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-codex", "label": "ما هو OpenAI Codex فعلًا"}, {"id": "why-design", "label": "لماذا صار Codex جيدًا في التصميم الآن"}, {"id": "setup", "label": "إعداد Codex للتصميم (من الصفر)"}, {"id": "screenshot-workflow", "label": "سير عمل من لقطة الشاشة إلى الواجهة"}, {"id": "figma", "label": "التكامل ثنائي الاتجاه بين Codex وFigma"}, {"id": "vs", "label": "‏Codex مقابل Cursor مقابل Claude Code"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Codex داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-codex", "heading": "ما هو OpenAI Codex فعلًا (وما ليس هو)", "blocks": [{"kind": "p", "text": "أولًا، توضيح يُربك كل من يبحث عن «Codex» تقريبًا. كان OpenAI Codex الأصلي نموذج إكمال شيفرة من 2021 شغّل النسخ المبكرة من GitHub Copilot وأُوقِف في 2023. ليس هذا موضوع الصفحة. أما Codex اليوم فهو أداة البرمجة الوكيلة من OpenAI — يخطّط ويكتب ويشغّل ويتحقق من الشيفرة انطلاقًا من مهام باللغة الطبيعية."}, {"kind": "p", "text": "يأتي Codex الحديث عبر أربع واجهات: واجهة سطر أوامر طرفية (أُعيدت كتابتها بـ Rust، برخصة Apache-2.0)، وإضافة لبيئات التطوير VS Code وCursor وWindsurf، وتجربة سحابية/ويب للمهام غير المتزامنة المفوّضة، وتطبيق سطح مكتب بمتصفح داخلي وميزة Computer Use."}, {"kind": "steps", "items": [{"label": "النموذج الافتراضي", "body": "اعتبارًا من منتصف 2026، النموذج المُوصى به هو gpt-5.5، مع كون gpt-5.4 النموذج الذي درّبته OpenAI صراحةً للواجهة الأمامية واستخدام الحاسوب."}, {"label": "ملف التعليمات", "body": "يقرأ Codex ملف AGENTS.md في مشروعك (معيار متعدد الأدوات) لقواعد المشروع — المكان الطبيعي لترميز أعراف التصميم لديك."}, {"label": "البيئة المعزولة", "body": "يعمل في بيئة معزولة على مستوى النواة (وضع الكتابة في مساحة العمل افتراضيًا)، فلا يستطيع وكيل يحرّر واجهتك أن يتجوّل خارج المشروع."}]}, {"kind": "ul", "items": ["المزوِّد: OpenAI", "بيانات الاعتماد: مفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "رخصة واجهة سطر الأوامر: Apache-2.0، مفتوحة المصدر"]}]}, {"id": "why-design", "heading": "لماذا صار Codex جيدًا في التصميم الآن", "blocks": [{"kind": "p", "text": "تقاطعت ثلاثة أمور في أوائل 2026 لتجعل Codex أداة تصميم حقيقية لا مجرد مولّد شيفرة عام."}, {"kind": "steps", "items": [{"label": "نموذج مدرَّب للواجهة الأمامية", "body": "أطلقت OpenAI النموذج GPT-5.4، أول نموذج رئيسي لها مدرَّب للواجهة الأمامية واستخدام الحاسوب، بفهم أفضل بكثير للصور عبر سير عمل التصميم وتحقّق ذاتي أقوى. بل يمكنه توليد لوحات مزاج وخيارات بصرية قبل الالتزام بالأصول النهائية."}, {"label": "skill رسمي للواجهة الأمامية", "body": "يقدّم كتالوج openai/skills مهارة frontend منسّقة تفرض ذوقًا حقيقيًا: تخطيطات بلا بطاقات، أبطال ممتدة الحواف، هرمية تقدّم العلامة، حركة مقيّدة، خطّان كحد أقصى ولون توكيد واحد — وتجعل Codex يكتب أطروحة بصرية قبل البناء."}, {"label": "التحقق في المتصفح", "body": "مع مهارة Playwright يفتح Codex متصفحًا حقيقيًا، ويغيّر الحجم إلى نقاط التوقف، ويقارن مخرجاته بالمرجع بدلًا من مجرد التحقق من نجاح البناء."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس وراء الثلاثة جميعًا: لا يملك Codex ذوقًا افتراضيًا. إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا — نظام تصميم، وskill جمالي، ومراجع ملموسة. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Codex لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Codex قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، التهيئة، تثبيت الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة AGENTS.md ← تثبيت frontend skill ← تفعيل التحقق في المتصفح."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في AGENTS.md أو في DESIGN.md ووجّه Codex إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "اختر مستوى الاستدلال الصحيح", "body": "تشير OpenAI إلى أن مستويات الاستدلال المنخفضة إلى المتوسطة كثيرًا ما تنتج نتائج واجهة أمامية أقوى من الإعداد الأعلى."}]}]}, {"id": "screenshot-workflow", "heading": "سير عمل من لقطة الشاشة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Codex هي تحويل صورة مرجعية إلى واجهة عاملة ومتجاوبة والتكرار حتى تطابق. وتتلخّص إرشادات OpenAI نفسها في خمس خطوات."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر Codex بمكان الـ tokens والعناصر الأولية المرجعية.", "فعّل مهارة Playwright التفاعلية كي يعرض Codex في متصفح حقيقي ويغيّر الحجم إلى نقاط التوقف.", "كرّر بجعل Codex يقارن تنفيذه بلقطات الشاشة — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "غذِّ الصور بسحب لقطة شاشة إلى الطرفية أو عبر علامة الصورة، ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "شغّل خادم تطوير في طرفية ثانية، وأبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة / وأرجِع السيئة (مع إخبار Codex حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة."}]}, {"id": "figma", "heading": "‏Codex + Figma: تكامل ثنائي الاتجاه بين التصميم والشيفرة", "blocks": [{"kind": "p", "text": "في فبراير 2026 أعلنت OpenAI وFigma شراكة رسمية، حوّلت نسخة Figma MCP التجريبية السابقة إلى تكامل متقدّم ثنائي الاتجاه. وهو يعمل في الاتجاهين."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "انسخ «link to selection» لإطار في Figma، والصقه في Codex مع get_design_context، واطلب منه تنفيذ التصميم باستخدام مكتبة مكوّناتك الموجودة."}, {"label": "الشيفرة ← التصميم", "body": "تحوّل أداة generate_figma_design («Code to Canvas») واجهةً حيّة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير — الشاشة كاملةً، أو عنصرًا محددًا، أو ملفًا كاملًا."}]}, {"kind": "p", "text": "يعمل Figma MCP بصفته خادمًا بعيدًا ومُعفى من حدود المعدل. أضِفه مرة واحدة فيصبح متاحًا لـ Codex وClaude Code وCursor وVS Code والمزيد — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Codex مقابل Cursor مقابل Claude Code للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Codex", "صقل بصري قوي بعد GPT-5.4 + frontend-skill؛ فهم للصور", "عمليات البناء غير المتزامنة المفوّضة، التشغيل المعزول، قواعد AGENTS.md المحمولة"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بـ Codex أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال، وتسرّب التعليمات إلى نصوص الواجهة، وبلوغ حدود الاستخدام بسرعة."}, {"kind": "steps", "items": [{"label": "ثبّت frontend skill", "body": "skill جمالي منسّق يجبر Codex على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "فعّل تحقق Playwright", "body": "اجعل Codex يعرض ويتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في AGENTS.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Codex داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Codex بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Codex جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Codex وكيلًا لك.", "صادِق بمفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Codex نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع OpenAI Codex فعلًا أداء عمل التصميم؟", "text": "نعم — مع frontend skill ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج Codex (وخاصةً على GPT-5.4) واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل هذه إضافة OpenAI Codex Product Design؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج Codex بصفته وكيلًا. وهو يكمّل أدوات OpenAI الخاصة بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك ChatGPT للتصميم بـ Codex؟", "text": "يمكنك استخدام مفتاح OpenAI API (مبدأ BYOK) أو اشتراك ChatGPT الخاص بك. وعادةً ما يمنح تسجيل الدخول عبر ChatGPT حدودًا أكثر سخاءً؛ ولا يمرّر Open Design بيانات اعتمادك في كلتا الحالتين."}, {"name": "‏Codex أم Claude Code لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة؛ ويتمتع Codex بصقل بصري قوي بعد GPT-5.4 ويتفوّق في عمليات البناء المفوّضة المعزولة. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Codex بـ Figma؟", "text": "أضِف خادم Figma MCP الرسمي (codex mcp add figma --url https://mcp.figma.com/mcp). عندها يمكنك تنفيذ إطارات Figma في شيفرة عبر get_design_context، ودفع واجهة قيد التشغيل عائدةً إلى إطارات Figma قابلة للتحرير عبر generate_figma_design."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "ثبّت frontend skill، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في AGENTS.md، وفعّل تحقق Playwright. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ OpenAI؟", "text": "لا. Codex منتج من OpenAI؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وOpenAI وCodex علامتان تجاريتان لـ OpenAI."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد OpenAI مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Codex، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح OpenAI الخاص بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Codex داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor للمصممين — Open Design",
        description: "كيف يستخدم المصممون Cursor في تصميم الواجهات والويب — وضع التصميم، Figma إلى شيفرة، Figma MCP — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "Cursor",
        label: "وكيل · Cursor",
        heading: "Cursor للمصممين.",
        lead: "‏Cursor هو محرّر الشيفرة بالذكاء الاصطناعي، ومعه الآن وضع تصميم بصري. يستخدمه المصممون لتحرير الواجهة بالإشارة والرسم، ولتحويل Figma إلى شيفرة. يربط Open Design وكيل Cursor بسير عمل تصميمي مفتوح المصدر يبقي ملفاتك محلية.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة Cursor إلى وكيل تصميم محلي أولًا ومفتوح المصدر — حساب Cursor أو مفاتيح النماذج الخاصة بك، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم Cursor داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["‏Cursor هو محرّر الشيفرة الذي يضع الذكاء الاصطناعي أولًا، والذي جعل «ابنِه وشاهده يُعرَض» الطريقة الافتراضية لشحن الواجهات. مع وضع الوكيل والتحريرات المضمّنة والمعاينة داخل المحرّر وFigma عبر MCP، صار أداة تصميم حقيقية — بمجرد أن تزوّده بالمراجع والقواعد الصحيحة وحلقة تحقق. هذا دليل عملي وشامل لاستخدام Cursor في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو Cursor فعلًا، ولماذا تُجيد حلقته المحكمة بالتكرار-والمراقبة التصميم، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-والمعاينة-إلى-الواجهة، والتكامل ثنائي الاتجاه مع Figma عبر MCP، وكيف يقارَن بـ Codex وClaude Code، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "تقارب تصميم Cursor: محرّر على اليسار، ومركز منسّق من الـ skills وأنظمة التصميم في الوسط مع شعار Cursor في المنتصف، وواجهة معروضة على اليمين", "caption": "الفكرة الأساسية: يحرّر Cursor الواجهة ويعرضها في المحرّر، بينما يغذّيه مركز تصميم منسّق بالنظام والـ skills والمراجع التي تجعل المخرجات تبدو مقصودة."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-cursor", "label": "ما هو Cursor فعلًا"}, {"id": "why-design", "label": "لماذا يجيد Cursor التصميم"}, {"id": "setup", "label": "إعداد Cursor للتصميم (من الصفر)"}, {"id": "preview-workflow", "label": "سير عمل من المعاينة إلى الواجهة"}, {"id": "figma", "label": "‏Cursor + Figma عبر MCP"}, {"id": "vs", "label": "‏Cursor مقابل Codex مقابل Claude Code"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ Cursor داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-cursor", "heading": "ما هو Cursor فعلًا", "blocks": [{"kind": "p", "text": "‏Cursor هو محرّر شيفرة يضع الذكاء الاصطناعي أولًا، بناه Anysphere. وهو نسخة معدّلة من VS Code، فيحتفظ بالمحرّر والإضافات واختصارات المفاتيح المألوفة، لكنه يعيد بناء سير العمل حول وكيل ذكاء اصطناعي يقرأ مشروعك كاملًا، ويحرّر ملفات متعددة، ويشغّل الأوامر، ويكرّر معك ضمن الحلقة."}, {"kind": "p", "text": "في عمل التصميم، الواجهات المهمة هي وضع الوكيل (تصف نتيجة فيخطّط Cursor ويحرّر عبر الملفات)، والتحريرات المضمّنة وإكمالات Tab للتعديلات السريعة، ومعاينة/متصفح داخل المحرّر يتيحان رؤية الواجهة قيد التشغيل دون مغادرة النافذة، ودعم MCP الذي يسمح له بجلب سياق خارجي كملف Figma حيّ."}, {"kind": "steps", "items": [{"label": "قواعد المشروع", "body": "يقرأ Cursor ملفات تعليمات المشروع — قواعد `.mdc` المُدارة بإصدارات تحت `.cursor/rules`، وملف `AGENTS.md` بسيط — كي ترمّز أعراف التصميم لديك حيث يقرؤها الوكيل في كل تشغيل."}, {"label": "النماذج", "body": "‏Cursor مرن في النماذج: يأتي بنماذج متقدّمة عبر اشتراكك ويدعم أيضًا إحضار مفاتيح نماذجك الخاصة، فتختار المحرّك خلف سير عمل المحرّر نفسه."}, {"label": "MCP", "body": "يتحدّث بروتوكول Model Context Protocol، فتصبح الخوادم الخارجية — وأبرزها خادم Figma MCP — سياقًا أصيلًا للوكيل."}]}, {"kind": "ul", "items": ["المزوِّد: Anysphere", "بيانات الاعتماد: حساب / اشتراك Cursor (Hobby / Pro / Business) أو مفاتيح نماذجك الخاصة (مبدأ BYOK)", "الصيغة: محرّر شيفرة يضع الذكاء الاصطناعي أولًا (نسخة معدّلة من VS Code) مع وكيل ومعاينة داخل المحرّر"]}]}, {"id": "why-design", "heading": "لماذا يجيد Cursor التصميم", "blocks": [{"kind": "p", "text": "ميزة Cursor في التصميم ليست ميزة واحدة — بل إحكام حلقة البناء-والمشاهدة. ثلاثة أمور تجعله يبدو أداة تصميم لا مجرد مولّد شيفرة عام."}, {"kind": "steps", "items": [{"label": "حلقة محكمة بالتكرار-والمراقبة", "body": "تطالب فيحرّر Cursor عبر الملفات، وتعرض المعاينة داخل المحرّر النتيجة فورًا — فتضبط المسافات والهرمية والحركة في ثوانٍ بدلًا من التنقّل عبر طرفية ومتصفح منفصلين."}, {"label": "تحرير بصري مباشر", "body": "إلى جانب المحادثة، يتيح لك Cursor تحديد عناصر في المعاينة وتعديل الأنماط، فتبدو التصحيحات البصرية الصغيرة كتحريرات تصميم لا كتنقيب في الشيفرة."}, {"label": "قواعد المشروع وسياق MCP", "body": "مع `.cursor/rules` (أو `AGENTS.md`) وخادم Figma MCP، يعمل الوكيل مقابل tokens ومكوّناتك ومواصفات التصميم الحقيقية بدلًا من التخمين."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية."}, {"kind": "p", "text": "الدرس نفسه الذي يعلّمه كل وكيل: لا يملك Cursor ذوقًا افتراضيًا. إنه ينتج تصميمًا جيدًا حين تمنحه قيودًا — نظام تصميم، وskill جمالي، ومراجع ملموسة. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد Cursor لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى Cursor قادر على بناء الواجهة ومعاينتها والتحقق منها مقابل نظام تصميمك."}, {"kind": "ol", "items": ["ثبّت Cursor من cursor.com وسجّل الدخول بحساب Cursor، أو هيّئ مفاتيح نماذجك الخاصة (مبدأ BYOK) في الإعدادات.", "افتح مشروعك واختر نموذجًا في لوحة المحادثة / الوكيل.", "أضف قواعد المشروع: أنشئ `.cursor/rules/*.mdc` لأعراف منظّمة محدّدة النطاق بالأنماط، أو ملف `AGENTS.md` بسيط لتعليمات بسيطة وقابلة للقراءة.", "اربط خادم Figma MCP (اختياري) كي يقرأ الوكيل سياق التصميم الحيّ.", "شغّل خادم التطوير واستخدم المعاينة داخل المحرّر لرؤية الواجهة والتحقق منها أثناء التكرار."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة، تهيئة القواعد، إضافة الـ skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة ← تهيئة قواعد المشروع ← إضافة skill ← تفعيل التحقق بالمعاينة."}, {"kind": "p", "text": "ملف قواعد مشروع بسيط يجعل الوكيل يصمّم لهوية علامة بدلًا من العودة إلى مظهر عام. ضعه حيث يقرؤه Cursor في كل تشغيل:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في `.cursor/rules` أو `AGENTS.md` ووجّه Cursor إليها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "أبقِ المطالبات صغيرة", "body": "حلقة Cursor المحكمة تكافئ الطلبات المركّزة — كرّر مكوّنًا أو حالة واحدة في كل مرة وراقب المعاينة بين التمريرات."}]}]}, {"id": "preview-workflow", "heading": "سير عمل من المعاينة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع Cursor هي تحويل مرجع إلى واجهة عاملة ومتجاوبة والتكرار في المحرّر حتى تطابق — مع مراقبة المعاينة الحيّة طوال الوقت بدلًا من التخمين."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر Cursor بمكان الـ tokens والعناصر الأولية المرجعية.", "أبقِ المعاينة داخل المحرّر مفتوحة وخادم التطوير يعمل كي تُعرَض كل تحريرة فورًا عند نقاط التوقف التي تهمّك.", "كرّر بمقارنة الواجهة المعروضة بالمراجع — واستخدم تحديد العناصر المباشر في المعاينة للتصحيحات البصرية الصغيرة."]}, {"kind": "p", "text": "غذِّ المراجع بإرفاق صورة بالمحادثة، ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "ثبّت التكرارات الجيدة وأرجِع السيئة (مع إخبار Cursor حين تُرجِع) كي تبني كل تمريرة على قاعدة نظيفة — الانضباط نفسه الذي يمنع أي حلقة وكيل من الانحراف."}]}, {"id": "figma", "heading": "‏Cursor + Figma: التصميم ↔ الشيفرة عبر MCP", "blocks": [{"kind": "p", "text": "يتصل Cursor بـ Figma عبر خادم Figma MCP الرسمي، الذي يمنح الوكيل وصولًا منظّمًا إلى ملف Figma حيّ بدلًا من لقطة شاشة مسطّحة. وهذا يزيل التخمين من التسليم."}, {"kind": "steps", "items": [{"label": "التصميم ← الشيفرة", "body": "انسخ رابط إطار في Figma، والصقه في Cursor، واطلب منه تنفيذ التصميم. يعرض خادم MCP سياق التصميم الحقيقي — مكوّنات، متغيرات، بيانات تخطيط، tokens — كي تطابق الشيفرة المولَّدة المصدر بدلًا من مقاربته."}, {"label": "ابقَ متوائمًا", "body": "مع استخدام tokens التصميم والأنماط والمكوّنات باتّساق في Figma (وCode Connect حيث يتوفّر)، تبقى مخرجات Cursor مرتبطة بنظام تصميمك الحقيقي بدلًا من إعادة ابتكار العناصر الأولية."}]}, {"kind": "p", "text": "أعدّ خادم Figma MCP البعيد مرة واحدة فيصبح متاحًا لـ Cursor بصفته سياقًا أصيلًا. ولأن MCP معيار مفتوح، فإن الخادم نفسه قابل لإعادة الاستخدام عبر Cursor وClaude Code وCodex وVS Code — وهو تمامًا نوع القدرة المحمولة متعددة الوكلاء التي بُني Open Design لتنسيقها."}]}, {"id": "vs", "heading": "‏Cursor مقابل Codex مقابل Claude Code للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة داخل المحرّر وتحرير مباشر للعناصر", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"], ["Codex", "صقل بصري قوي مع frontend skill؛ فهم للصور وتشغيل معزول", "عمليات البناء غير المتزامنة المفوّضة وقواعد AGENTS.md المحمولة"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بـ Cursor أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها تخطيطات تنكسر على الجوال وتسرّب التعليمات إلى نصوص الواجهة."}, {"kind": "steps", "items": [{"label": "أضف skill تصميم", "body": "skill جمالي منسّق يجبر Cursor على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "استخدم المعاينة للتحقق", "body": "اعرض وتحقق ذاتيًا عبر نقاط التوقف في المعاينة داخل المحرّر كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في `.cursor/rules`", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ Cursor داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل Cursor بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل Cursor جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة."}, {"kind": "ol", "items": ["ثبّت Open Design واختر Cursor وكيلًا لك.", "صادِق بحساب Cursor أو مفاتيح نماذجك الخاصة (مبدأ BYOK) — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل Cursor نفسه، المفتاح نفسه — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع Cursor فعلًا أداء عمل التصميم؟", "text": "نعم — مع skill تصميم ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج Cursor واجهة بجودة إنتاجية ومتجاوبة، وتتيح لك المعاينة داخل المحرّر التحقق منها وصقلها بصريًا. وبدون ذلك السياق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "هل هذا منتج Cursor رسمي؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج Cursor بصفته وكيلًا. وهو يكمّل Cursor بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك Cursor للتصميم بـ Cursor؟", "text": "يمكنك استخدام حساب / اشتراك Cursor أو إحضار مفاتيح نماذجك الخاصة (مبدأ BYOK). ولا يمرّر Open Design بيانات اعتمادك في كلتا الحالتين — فهي تُستخدَم مباشرةً بواسطة وكيلك."}, {"name": "‏Cursor أم Claude Code لتصميم الواجهة الأمامية؟", "text": "كلاهما قوي. يُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة؛ وميزة Cursor هي حلقته المحكمة بالبناء-والمشاهدة مع معاينة حيّة داخل المحرّر. وتستخدم فرق كثيرة كليهما — ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أصل Cursor بـ Figma؟", "text": "أضِف خادم Figma MCP الرسمي في Cursor، ثم الصق رابط إطار Figma في المحادثة واطلب من Cursor تنفيذه. يعرض الخادم مكوّنات ومتغيرات وبيانات تخطيط حقيقية كي تطابق الشيفرة المولَّدة تصميم المصدر."}, {"name": "كيف أتجنّب جماليّة «فوضى الذكاء الاصطناعي» العامة؟", "text": "أضف skill تصميم، وزوّده بـ tokens تصميم حقيقية ولقطات شاشة مرجعية، ورمّز قواعد العلامة في `.cursor/rules` أو `AGENTS.md`، وتحقق عبر نقاط التوقف في المعاينة. ويقدّم Open Design هذه بصفتها مكتبة منسّقة كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ Cursor أو Anysphere؟", "text": "لا. Cursor منتج من Anysphere؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا. وCursor وAnysphere علامتان تجاريتان لـ Anysphere, Inc."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد Cursor أو النموذج مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ Cursor، بالطريقة المفتوحة.", "ctaBody": "أحضر حساب Cursor أو مفاتيح النماذج الخاصة بك، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم Cursor داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode للتصميم — Open Design",
        description: "كيف يستخدم الناس OpenCode في تصميم الواجهات والويب — ملفات design.md، skills واجهة المستخدم/تجربة المستخدم، Figma MCP — وكيف يحوّله Open Design إلى وكيل تصميم محلي أولًا ومفتوح المصدر.",
        breadcrumb: "OpenCode",
        label: "وكيل · OpenCode",
        heading: "OpenCode للتصميم.",
        lead: "‏OpenCode هو وكيل البرمجة الطرفي بالذكاء الاصطناعي مفتوح المصدر. يركّب عليه المصممون skills تصميم وملفات DESIGN.md لتوليد واجهات حقيقية. يجعل Open Design ذلك سير عمل منظّمًا مفتوح المصدر — أحضر مفاتيح مزوّدك، واحتفظ بكل شيء محليًا.",
        rich: {"heroCtaLead": "يحوّل Open Design الأداة OpenCode إلى وكيل تصميم محلي أولًا ومفتوح المصدر — أي نموذج تختاره بمفتاح مزوّدك الخاص، وملفاتك، ومكتبة منسّقة من الـ skills وأنظمة التصميم تحيط بها.", "heroCtaActions": [{"label": "استخدم OpenCode داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["‏OpenCode هو وكيل برمجة بالذكاء الاصطناعي مفتوح المصدر يضع الطرفية أولًا ومحايد للنماذج عمدًا: تُحضر مفتاح مزوّدك الخاص وتشغّل أي نموذج تريده خلف سير العمل نفسه. هذا الانفتاح يجعله قاعدة طبيعية لعمل التصميم — لكنه، كأي وكيل، لا ينتج واجهة جيدة إلا حين تزوّده بالمراجع والـ skills وحلقة تحقق صحيحة. هذا دليل عملي وشامل لاستخدام OpenCode في عمل الواجهات والواجهة الأمامية وأنظمة التصميم، ولربطه بسير عمل تصميمي منظّم عبر Open Design.", "يغطّي ما هو OpenCode فعلًا، ولماذا يلائم وكيل مفتوح محايد للنماذج التصميم، وكيف تعدّه من الصفر، وحلقة من-لقطة-الشاشة-إلى-الواجهة، وكيف يوسّعه AGENTS.md وMCP، وكيف يقارَن بـ Codex وClaude Code وCursor، والمزالق التي تجعل مخرجات الذكاء الاصطناعي تبدو عامة، وكيف يسدّ Open Design الفجوة بصفته طبقة تصميم مفتوحة ومحلية أولًا — وهو اقتران طبيعي، إذ إن كلا المشروعين مفتوحا المصدر ويعملان على جهازك."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "حلقة تغذية راجعة لتصميم OpenCode: وكيل بواجهة طرفية نصية، ومتصفح يعرض الواجهة، ومساحة عمل، مع سهم تغذية راجعة يعود إلى البداية", "caption": "الحلقة الأساسية: يبني OpenCode الواجهة في الطرفية، ويعرضها ويتحقق منها في متصفح حقيقي، ويكرّر مقابل مراجعك — على أي نموذج تختاره."}, "tocLabel": "في هذه الصفحة", "toc": [{"id": "what-is-opencode", "label": "ما هو OpenCode فعلًا"}, {"id": "why-design", "label": "لماذا يلائم وكيل مفتوح متعدد النماذج التصميم"}, {"id": "setup", "label": "إعداد OpenCode للتصميم (من الصفر)"}, {"id": "screenshot-workflow", "label": "سير عمل من لقطة الشاشة إلى الواجهة"}, {"id": "extend", "label": "AGENTS.md وMCP والجلسات القابلة للمشاركة"}, {"id": "vs", "label": "‏OpenCode مقابل Codex مقابل Claude Code مقابل Cursor"}, {"id": "pitfalls", "label": "المزالق ومظهر «فوضى الذكاء الاصطناعي»"}, {"id": "open-design", "label": "التصميم بـ OpenCode داخل Open Design"}, {"id": "faq", "label": "الأسئلة الشائعة"}], "sections": [{"id": "what-is-opencode", "heading": "ما هو OpenCode فعلًا", "blocks": [{"kind": "p", "text": "‏OpenCode هو وكيل برمجة بالذكاء الاصطناعي مفتوح المصدر مبني للطرفية، يصونه الفريق وراء SST (Anomaly Innovations). يقرأ مستودعك، ويشغّل الأوامر، ويحرّر الملفات، ويتحدّث إلى نموذج لغوي كبير — لكنه، بخلاف الوكلاء المرتبطين بمزوّد، لا يأتي بنموذجه الخاص. توجّهه نحو أي مزوّد ونموذج تريده وتُحضر مفتاحك الخاص."}, {"kind": "p", "text": "يعمل بواجهة طرفية نصية (TUI)، مع تطبيق سطح مكتب وإضافات بيئات تطوير فوق المحرك نفسه. وتحت الغطاء يستخدم بنية عميل/خادم، فيكون الوكيل الذي ينجز العمل منفصلًا عن الواجهة التي تقوده منها. ويتبدّل وكيلان مدمجان — build وplan — بمفتاح Tab."}, {"kind": "steps", "items": [{"label": "محايد للنماذج", "body": "تأتي النماذج والمزوّدون من models.dev، وهو كتالوج مفتوح. تهيّئهم في opencode.json بسلسلة provider/model-id ويمكنك تعطيل المزوّدين الذين لا تريد تحميلهم — فيعمل سير عمل التصميم نفسه على Anthropic وOpenAI وGoogle وOpenRouter والنماذج المحلية والمزيد."}, {"label": "ملف التعليمات", "body": "يقرأ OpenCode ملف AGENTS.md في مشروعك (المعيار متعدد الأدوات، المتوافق أيضًا مع CLAUDE.md) لقواعد المشروع — المكان الطبيعي لترميز أعراف التصميم لديك. شغّل /init لتوليد واحد."}, {"label": "قابل للتوسيع", "body": "يدعم تكامل LSP وخوادم MCP والثيمات واختصارات المفاتيح والأوامر المخصّصة، إضافةً إلى روابط جلسات قابلة للمشاركة للتعاون."}]}, {"kind": "ul", "items": ["الصائن: SST / Anomaly Innovations (مشروع مفتوح المصدر)", "بيانات الاعتماد: مفاتيح API الخاصة بمزوّد نماذجك — مبدأ BYOK، بلا ارتباط بمزوّد", "الرخصة: MIT، مفتوحة المصدر"]}]}, {"id": "why-design", "heading": "لماذا يلائم وكيل مفتوح متعدد النماذج عمل التصميم", "blocks": [{"kind": "p", "text": "لا يملك OpenCode «نموذج تصميم» واحدًا كما يملك وكيل مرتبط بمزوّد — وهذا هو المغزى. ولأنه محايد للنماذج ومفتوح، يمكنك تشغيل سير عمل التصميم نفسه على أي نموذج أفضل حاليًا في الواجهة الأمامية، أو تبديله لاحقًا، أو الرجوع إلى نموذج محلي، كل ذلك دون تغيير إعدادك."}, {"kind": "p", "text": "لكن اختيار النموذج وحده لا يشتري ذوقًا. وكأي وكيل برمجة، ينتج OpenCode واجهة عامة ما لم تمنحه قيودًا. ومخرجات التصميم الجيدة تأتي من ثلاثة مدخلات تقدّمها أنت."}, {"kind": "steps", "items": [{"label": "نظام تصميم", "body": "tokens وعناصر أولية وأعراف حقيقية يعيد الوكيل استخدامها، كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام."}, {"label": "skill جمالي", "body": "skill منسّق يفرض ذوقًا حقيقيًا — حركة مقيّدة، هرمية تقدّم العلامة، خطّان كحد أقصى ولون توكيد واحد — ويجعل الوكيل يلتزم باتجاه قبل البناء."}, {"label": "مراجع ملموسة", "body": "صور مرجعية فعلية وحالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "رسم تخطيطي يوضّح تقارب نظام التصميم والـ skill والصورة المرجعية نحو مخرجات تصميم جيدة", "caption": "ينبع الذوق من ثلاثة مدخلات تقدّمها أنت: نظام تصميم، وskill، وصور مرجعية حقيقية — بمعزل عن النموذج الذي تشغّله."}, {"kind": "p", "text": "الدرس: يمنحك OpenCode حرية النماذج، لكن الذوق ما زال يأتي من سياق تصميم منسّق. ويجمع Open Design تلك المدخلات بالضبط، ولهذا يتلاءم الاثنان معًا — كلاهما مفتوح المصدر ومحلي أولًا (المزيد أدناه)."}]}, {"id": "setup", "heading": "إعداد OpenCode لعمل التصميم، من الصفر", "blocks": [{"kind": "p", "text": "هذا هو المسار الكامل من جهاز نظيف إلى OpenCode قادر على بناء الواجهة والتحقق منها."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "سير إعداد من خمس خطوات: التثبيت، المصادقة بمفتاح مزوّدك، تهيئة AGENTS.md، إضافة skill، التحقق", "caption": "تسلسل الإعداد: التثبيت ← المصادقة (مفتاح مزوّدك) ← تهيئة AGENTS.md ← إضافة skill ← التحقق في متصفح حقيقي."}, {"kind": "steps", "items": [{"label": "رمّز قواعد التصميم لديك", "body": "ضع tokens وعناصرك الأولية وأعرافك في AGENTS.md (أو في DESIGN.md مُشار إليه منه) كي تطابق المخرجات هوية علامة بدلًا من العودة إلى مظهر عام. ويمكن لخيار instructions في opencode.json أن يشير إلى ملفات قواعد إضافية عبر الأنماط."}, {"label": "اختر نموذجًا قادرًا", "body": "لأن OpenCode محايد للنماذج، اختر المزوّد/النموذج الأقوى حاليًا في الواجهة الأمامية لتمريرة التصميم — وأبقِ بقية سير عملك دون تغيير."}]}]}, {"id": "screenshot-workflow", "heading": "سير عمل من لقطة الشاشة إلى الواجهة", "blocks": [{"kind": "p", "text": "أعلى حلقات التصميم رافعةً مع أي وكيل هي تحويل صورة مرجعية إلى واجهة عاملة ومتجاوبة والتكرار حتى تطابق. وينطبق الشكل نفسه من خمس خطوات في OpenCode."}, {"kind": "ol", "items": ["ابدأ من أوضح المراجع البصرية لديك — وضمّن حالات متعددة (سطح المكتب والجوال، التحويم، الفارغ، التحميل)، لا لقطة بطل واحدة فقط.", "كن محددًا في المطالبة؛ فالمطالبات الغامضة تنتج واجهة عامة.", "جهّز نظام تصميم وأخبر OpenCode بمكان الـ tokens والعناصر الأولية المرجعية (في AGENTS.md).", "شغّل خادم تطوير واجعل الوكيل يعرض في متصفح حقيقي، مغيّرًا الحجم إلى نقاط التوقف لفحص النتيجة.", "كرّر بجعل OpenCode يقارن تنفيذه بلقطات الشاشة — لا أن يكتفي بتأكيد البناء."]}, {"kind": "p", "text": "أشِر إلى الملفات بـ @ في الواجهة الطرفية لبحث ضبابي في مجلد عملك، وشغّل أوامر الصدفة مضمّنةً ببادئة !، وقُد الإجراءات بأوامر /. ثم أرسِل مطالبة بقيود ملموسة:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "أبقِ المطالبات صغيرة ومركّزة، وثبّت التكرارات الجيدة وأرجِع السيئة (مع إخبار OpenCode حين تُرجِع)، كي تبني كل تمريرة على قاعدة نظيفة."}]}, {"id": "extend", "heading": "AGENTS.md وMCP والجلسات القابلة للمشاركة", "blocks": [{"kind": "p", "text": "ثلاث نقاط توسيع تجعل OpenCode عمليًا لعمل التصميم المستمر، وتنطبق الثلاث جميعًا بسلاسة على سير عمل تصميم مفتوح."}, {"kind": "steps", "items": [{"label": "قواعد AGENTS.md", "body": "تعيش قواعد المشروع في AGENTS.md في جذر المستودع (أو قواعد عامة في ~/.config/opencode/AGENTS.md). إنه المنزل الدائم لأعراف التصميم لديك، يُقرأ في كل تشغيل، وهو متوافق مع ملفات CLAUDE.md التي تستخدمها وكلاء أخرى."}, {"label": "خوادم MCP", "body": "يدعم OpenCode خوادم MCP المحلية (أمر) والبعيدة (URL)، المهيّأة تحت مفتاح mcp — الطريقة المحمولة لجلب سياق التصميم والأدوات الخارجية التي تعمل عبر الوكلاء، لا OpenCode فقط."}, {"label": "جلسات قابلة للمشاركة", "body": "ينشئ الأمر /share رابطًا عامًا لمحادثة للتعاون أو المراجعة، ويلغيه /unshare — مفيد للحصول على ملاحظات على تمريرة تصميم."}]}, {"kind": "p", "text": "هذه قدرات محمولة متعددة الوكلاء — تمامًا نوع الشيء الذي بُني Open Design لتنسيقه، بدلًا من إعادة بنائه لكل مشروع."}]}, {"id": "vs", "heading": "‏OpenCode مقابل Codex مقابل Claude Code مقابل Cursor للتصميم", "blocks": [{"kind": "p", "text": "لا يوجد فائز واحد في عمل التصميم — فلكل وكيل قوة مختلفة، والفرق المتمرّسة تجمع بينها. وإليك خلاصة منصفة:"}, {"kind": "table", "columns": ["الوكيل", "قوة التصميم", "الأنسب لـ"], "rows": [["OpenCode", "مفتوح المصدر ومحايد للنماذج؛ شغّل أي مزوّد خلف سير عمل طرفي واحد", "حرية BYOK، وتبديل النماذج، والإعدادات المفتوحة والمحلية أولًا بالكامل"], ["Codex", "صقل بصري قوي مع frontend skill؛ فهم للصور", "غير المتزامن المفوّض، عمليات البناء المعزولة، قواعد AGENTS.md المحمولة"], ["Claude Code", "قرارات تصميم محددة (hex، مسافات، خطوط) وتجربة مستخدم واعية بقاعدة الشيفرة", "تفكير الواجهة الأمامية وإعادة الهيكلة بسياق واسع"], ["Cursor", "حلقة بناء-ومشاهدة بصرية مع معاينة حيّة وتحريرات مضمّنة", "عمل واجهة محكم بالتكرار-والمراقبة داخل بيئة تطوير"]]}, {"kind": "p", "text": "الحكم المتكرر في المجتمع أن الذوق يأتي من البشر: فجميعها تتجه افتراضيًا إلى مظهر عام دون skills ومراجع وقيود. تلك هي المشكلة الحقيقية التي ينبغي حلّها — وهي بشكل أداة تصميم، لا بشكل نموذج، وهذا بالضبط سبب تلاؤم وكيل مفتوح مثل OpenCode تلاؤمًا جيدًا مع طبقة تصميم مفتوحة."}]}, {"id": "pitfalls", "heading": "المزالق، وكيف تتجنّب مظهر «فوضى الذكاء الاصطناعي»", "blocks": [{"kind": "p", "text": "أكثر شكوى شيوعًا عن التصميم المولَّد بالذكاء الاصطناعي أنه يبدو عامًا — تدرّجات ناعمة، لوحات عائمة، زوايا دائرية مفرطة الحجم، ظلال دراميّة، أجواء Inter-والبنفسجي «تصرخ بأن ذكاءً اصطناعيًا صنع هذا.» وتشمل المشكلات الأخرى المبلَّغ عنها انكسار تخطيطات الجوال وتسرّب التعليمات إلى نصوص الواجهة. وليست أيٌّ منها خاصةً بـ OpenCode؛ بل هي ما يحدث حين يعمل أي وكيل دون سياق تصميم منسّق."}, {"kind": "steps", "items": [{"label": "أضف skill جماليًا", "body": "skill تصميم منسّق يجبر الوكيل على الالتزام باتجاه حقيقي بدلًا من المظهر الافتراضي."}, {"label": "تحقق في متصفح حقيقي", "body": "اعرض وتحقق ذاتيًا عبر نقاط التوقف كي لا تنكسر التخطيطات بصمت على الجوال."}, {"label": "زوّده بالـ tokens والمراجع", "body": "tokens التصميم الحقيقية ولقطات الشاشة المرجعية هي أكبر رافعة منفردة على جودة المخرجات."}, {"label": "رمّز القواعد في AGENTS.md", "body": "ضع قواعد بأسلوب «لا بطاقات بطل، خطّان كحد أقصى، هرمية تقدّم العلامة» حيث يقرؤها الوكيل في كل تشغيل."}]}, {"kind": "p", "text": "لاحظ أن كل إجراء تخفيف يتمحور حول منح الوكيل سياق تصميم منسّقًا — بمعزل عن النموذج الذي تشغّله. والحفاظ على ذلك السياق يدويًا، لكل مشروع، هو الكدّ الذي يزيله Open Design."}]}, {"id": "open-design", "heading": "التصميم بـ OpenCode داخل Open Design", "blocks": [{"kind": "p", "text": "‏Open Design هو طبقة التصميم مفتوحة المصدر التي يطلبها سير العمل أعلاه باستمرار. يعامل OpenCode بصفته محوّلًا أصيلًا ويغلّفه بمكتبة منسّقة من الـ skills وأنظمة التصميم، وخط معالجة عرض منظّم، وواجهة سطح مكتب محلية — كي يكون سياق التصميم الذي يجعل أي وكيل جيدًا حاضرًا من أول تشغيل، لا مُجمَّعًا يدويًا في كل مرة. وكلا المشروعين مفتوحا المصدر ومحليان أولًا، ما يجعل الاقتران ملائمًا بطبيعته."}, {"kind": "ol", "items": ["ثبّت Open Design واختر OpenCode وكيلًا لك.", "صادِق بمفتاح API الخاص بمزوّد نماذجك (مبدأ BYOK) — تبقى بيانات الاعتماد على جهازك ولا تُمرَّر عبرنا أبدًا.", "اختر أي مزوّد ونموذج، إضافةً إلى نظام تصميم وskill، ثم ولّد العروض والنماذج الأولية وصفحات الهبوط بذوق متّسق.", "كل أثر وكل ملف DESIGN.md يعيش في مستودعك الخاص، لا في سحابة مستضافة."]}, {"kind": "p", "text": "وكيل OpenCode نفسه، حرية النماذج نفسها — إضافةً إلى سير عمل تصميمي حقيقي ومحمول ومفتوح المصدر يحيط به. إنه محلي أولًا وبرخصة Apache-2.0، فلا شيء عن عملك أو بيانات اعتمادك يغادر جهازك."}]}], "faqTitle": "الأسئلة الشائعة", "faq": [{"name": "هل يستطيع OpenCode فعلًا أداء عمل التصميم؟", "text": "نعم — مع skill جمالي ونظام تصميم وصور مرجعية حقيقية في السياق، ينتج OpenCode واجهة بجودة إنتاجية ومتجاوبة ويمكنه التحقق منها في متصفح. ولأنه محايد للنماذج، تشغّل النموذج الأفضل حاليًا في الواجهة الأمامية. وبدون ذلك السياق المنسّق يميل إلى مظهر عام، وهي الفجوة التي يسدّها Open Design."}, {"name": "أي نموذج ينبغي أن أستخدم مع OpenCode للتصميم؟", "text": "أيًّا أحببت — OpenCode محايد للمزوّدين عبر models.dev، فيمكنك تشغيل Anthropic أو OpenAI أو Google أو OpenRouter أو نماذج محلية خلف سير العمل نفسه والتبديل في أي وقت. وتعتمد جودة مخرجات التصميم على skill ونظام تصميمك ومراجعك أكثر بكثير من النموذج وحده."}, {"name": "هل صنع Open Design فريق OpenCode (SST)؟", "text": "لا. Open Design مشروع مستقل مفتوح المصدر يدمج OpenCode بصفته وكيلًا. وهو يكمّل OpenCode بمكتبة skills وأنظمة تصميم مفتوحة ومحلية أولًا."}, {"name": "هل أحتاج إلى اشتراك خاص للتصميم بـ OpenCode؟", "text": "لا — OpenCode يقوم على مبدأ BYOK. تُحضر مفتاح API الخاص بمزوّد نماذجك، ولا يمرّر Open Design بيانات اعتمادك أبدًا. ولا يوجد ارتباط بمزوّد."}, {"name": "‏OpenCode أم Codex أم Claude Code لتصميم الواجهة الأمامية؟", "text": "جميعها قوية، وفرق كثيرة تجمع بينها. ميزة OpenCode أنه مفتوح المصدر بالكامل ومحايد للنماذج؛ ويتفوّق Codex في عمليات البناء المفوّضة المعزولة؛ ويُعرَف Claude Code بقرارات تصميم محددة وواعية بقاعدة الشيفرة. ويتيح لك Open Design تبديل الوكلاء دون تغيير سير عمل التصميم."}, {"name": "كيف أوسّع OpenCode من أجل سياق التصميم؟", "text": "رمّز القواعد في AGENTS.md، وأضِف خوادم MCP تحت مفتاح mcp للأدوات المحمولة وسياق التصميم، واستخدم الجلسات القابلة للمشاركة للمراجعة. ويقدّم Open Design مكتبة منسّقة من الـ skills وأنظمة التصميم كي تتخطّى الإعداد لكل مشروع."}, {"name": "هل Open Design تابع لـ OpenCode أو SST؟", "text": "لا. OpenCode مشروع مفتوح المصدر يصونه SST (Anomaly Innovations)؛ وOpen Design مشروع مستقل مفتوح المصدر يدعمه بصفته محوّلًا أصيلًا."}, {"name": "هل ملفاتي وبيانات اعتمادي آمنة؟", "text": "نعم — Open Design محلي أولًا. تبقى ملفاتك وآثارك وملف DESIGN.md في مستودعك الخاص، وتُستخدَم بيانات اعتماد مزوّد نماذجك مباشرةً بواسطة وكيلك، ولا تُمرَّر عبر خوادم Open Design أبدًا."}], "ctaTitle": "صمّم بـ OpenCode، بالطريقة المفتوحة.", "ctaBody": "أحضر مفتاح مزوّد نماذجك الخاص، واحتفظ بكل ملف محليًا، واحصل على مكتبة تصميم منسّقة حول الوكيل المفتوح الذي تستخدمه أصلًا.", "ctaActions": [{"label": "استخدم OpenCode داخل Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "ضع نجمة على GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "نزّل تطبيق سطح المكتب", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "اعرض كل الوكلاء المدعومين"},
      },
    },
    'tr': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Tasarım için Claude Code — Open Design",
        description: "Tasarımcılar Claude Code'u UI ve web tasarımı için nasıl kullanır ve Open Design onu nasıl gerçek bir tasarım ajanına dönüştürür — yerel öncelikli, BYOK, özenle seçilmiş skill ve tasarım sistemi kütüphanesiyle.",
        breadcrumb: "Claude Code",
        label: "Ajan · Claude Code",
        heading: "Tasarım için Claude Code.",
        lead: "Claude Code, Anthropic'in terminal kodlama ajanıdır. İnsanlar onu zaten UI'lar, tasarım sistemleri ve açılış sayfaları oluşturmak için kullanıyor. Open Design onu gerçek bir tasarım iş akışına bağlar — Anthropic anahtarınızı veya Claude aboneliğinizi getirin, her dosyayı yerel tutun.",
        rich: {"heroCtaLead": "Open Design, Claude Code'u yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — Anthropic anahtarınız veya Claude aboneliğiniz, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Claude Code'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code, frontend konusunda en iyi zevke sahip kodlama ajanı olarak yaygın biçimde kabul edilir — arayüzler üzerinde alışılmadık bir kesinlikle akıl yürütür, tam hex değerlerini, boşlukları ve tipografi ölçeklerini adlandırır ve büyük bir kod tabanı boyunca UI'ı, bağlamı kaybetmeden yeniden düzenler. Ama kutudan çıktığı haliyle, ona bir tasarım sistemi, skill'ler ve gerçek referanslar vermediğiniz sürece yine de jenerik bir görünüme kayar. Bu, Claude Code'u UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Claude Code'un gerçekte ne olduğunu, frontend'de neden güçlü olduğunu, sıfırdan nasıl kurulacağını, CLAUDE.md ve Skills iş akışını, resmi Figma gidiş-dönüşünü, Codex ve Cursor ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code tasarım geri bildirim döngüsü: spesifik tasarım kararları veren terminal ajanı, UI'ı işleyen bir tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: Claude Code terminalde spesifik UI kararlarını akıl yürüterek belirler, bunları gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yakınsar."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-claude-code", "label": "Claude Code gerçekte nedir"}, {"id": "why-design", "label": "Claude Code tasarımda neden iyi"}, {"id": "setup", "label": "Claude Code'u tasarım için kurun (sıfırdan)"}, {"id": "skills-workflow", "label": "CLAUDE.md ve Skills iş akışı"}, {"id": "figma", "label": "Claude Code + Figma gidiş-dönüşü"}, {"id": "vs", "label": "Claude Code, Codex ve Cursor karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Claude Code ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code gerçekte nedir", "blocks": [{"kind": "p", "text": "Claude Code, Anthropic'in ajansal kodlama aracıdır. Kod tabanınızı okur, dosyaları düzenler, komutları çalıştırır ve geliştirme araçlarınızla entegre olur — yalnızca satırları otomatik tamamlamak yerine doğal dildeki görevlerden işi planlar, yazar ve doğrular."}, {"kind": "p", "text": "Hepsi aynı motoru paylaşan birkaç yüzey üzerinden sunulur: bir terminal CLI'si, VS Code, Cursor ve JetBrains için IDE eklentileri, görsel diff incelemesi olan bir masaüstü uygulaması ve uzun süren görevler için bir web deneyimi. CLAUDE.md dosyalarınız, ayarlarınız ve MCP sunucularınız hepsinde geçerlidir."}, {"kind": "steps", "items": [{"label": "Talimat dosyası", "body": "Claude Code, her oturumun başında proje kökünüzdeki bir CLAUDE.md dosyasını okur — tasarım kurallarınızı, token'larınızı ve inceleme kontrol listelerinizi kodlamak için doğal yer."}, {"label": "Skills", "body": "Agent Skills, Claude'un talep üzerine yüklediği yinelenebilir talimatları, betikleri ve kaynakları paketler; buna zevk için Anthropic'in resmi Frontend Design skill'i de dahildir."}, {"label": "Plan ve alt ajanlar", "body": "Eylemden önce plan yapabilir ve bir görevin farklı parçaları üzerinde paralel çalışan alt ajanlar başlatabilir; bu da büyük UI yeniden düzenlemelerini tutarlı tutar."}]}, {"kind": "ul", "items": ["Sağlayıcı: Anthropic", "Kimlik bilgisi: Anthropic API anahtarı (BYOK, Console üzerinden) veya bir Claude aboneliği (Pro / Max)", "Yüzeyler: terminal CLI, VS Code / Cursor / JetBrains eklentileri, masaüstü uygulaması, web"]}]}, {"id": "why-design", "heading": "Claude Code tasarımda neden iyi", "blocks": [{"kind": "p", "text": "Kodlama ajanları arasında Claude Code, frontend çalışmasında zevk konusunda bir üne sahiptir. Birkaç şey bunu açıklar."}, {"kind": "steps", "items": [{"label": "Belirsiz değil, spesifik kararlar", "body": "Claude Code, el sallayarak geçiştirmek yerine somut seçimlere bağlanma eğilimindedir — tam hex değerleri, boşluk ölçekleri, tipografi rampaları ve bileşen hiyerarşisi — gerçek bir arayüzü bir yer tutucudan ayıran şey de budur."}, {"label": "Kod tabanının farkında akıl yürütme", "body": "Geniş bir çalışma bağlamıyla, UI'ı bir kerede birçok dosya boyunca yeniden düzenler; tek seferlik stiller icat etmek yerine mevcut bileşenlerinizi ve token'larınızı yeniden kullanır."}, {"label": "Resmi bir frontend skill'i", "body": "Anthropic, Claude'un önce bir tasarım yönü yazmasını sağlayan ve jenerik sistem yazı tiplerinden ve tahmin edilebilir mor degradelerden bilinçli olarak uzaklaşan bir Frontend Design skill'i sunar."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Çıkarılan ders, Anthropic'in kendi modelleri hakkında söylediğiyle aynıdır: Claude varsayılan olarak zevke sahip değildir — kendi haline bırakılırsa web tasarımının istatistiksel merkezine yakınsar (Inter, mor degradeler, yumuşak gölgeler). Ona kısıtlar verdiğinizde iyi tasarım üretir. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Claude Code'u tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir Claude Code'a giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, CLAUDE.md yapılandır, skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → CLAUDE.md yapılandır → Frontend Design skill'ini ekle → tarayıcı doğrulamasını etkinleştir."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı CLAUDE.md içine koyun ve Claude'u bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Tarayıcı doğrulaması ekleyin", "body": "Bir Playwright veya Chrome MCP bağlayın, böylece Claude yalnızca derlemenin geçtiğini onaylamak yerine gerçek bir tarayıcıda işlesin ve çıktısını kırılma noktaları boyunca kontrol etsin."}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md ve Skills iş akışı", "blocks": [{"kind": "p", "text": "Claude Code ile en yüksek kaldıraçlı tasarım döngüsü, ona gerçek referansları artı tasarım bağlamınızı beslemek ve ardından UI eşleşene kadar yinelemektir — CLAUDE.md ve Skills kısıtları taşır, böylece bunları her komutta yeniden açıklamazsınız."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar, güçlü bir ajanla bile jenerik UI üretir.", "Tasarım sisteminizi ve kurallarınızı CLAUDE.md içinde tutun ve Claude'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Frontend Design skill'ini ekleyin, böylece Claude kod yazmadan önce gerçek bir estetik yöne bağlansın.", "Tarayıcı doğrulamasını bağlayın, böylece Claude işlesin, kırılma noktalarına yeniden boyutlandırsın ve referanslarla karşılaştırsın — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "Oturuma bir referans görseli bırakın ve somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Yanında bir dev sunucusu çalıştırın, komutları küçük ve odaklı tutun, iyi yinelemeleri commit edin / kötü olanları geri alın (geri aldığınızda Claude'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin. Büyük yeniden düzenlemeler için plan modunu kullanın, böylece herhangi bir dosya değişikliğinden önce yaklaşımı inceleyebilirsiniz."}]}, {"id": "figma", "heading": "Claude Code + Figma: tasarım ↔ kod gidiş-dönüşü", "blocks": [{"kind": "p", "text": "Şubat 2026'da Anthropic ve Figma, Figma MCP sunucusu aracılığıyla birinci sınıf, çift yönlü bir entegrasyon yayınladı. Her iki yönde de çalışır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame seçin veya Claude Code'a bir bağlantı yapıştırın, tasarım bağlamını çekin ve ondan mevcut bileşen kütüphanenizi kullanarak tasarımı uygulamasını isteyin. Code Connect, çıktıyı gerçek bileşenlerinizle hizalı tutar."}, {"label": "Kod → Tasarım", "body": "Bir özelliği tarayıcıda oluşturup önizleyin, ardından çalışan UI'ı düzenlenebilir Figma katmanları olarak yakalamak için “Send this to Figma” deyin — tüm ekran veya seçili bir öğe."}]}, {"kind": "p", "text": "Bir kez claude plugin install figma@claude-plugins-official ile kurun (Dev Mode MCP, ücretli bir Figma planı gerektirir). Aynı Figma MCP; Claude Code, Codex, Cursor ve VS Code için kullanılabilir — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Claude Code, Codex ve Cursor", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX akıl yürütmesi", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"], ["Codex", "Güçlü görsel cila ve görsel anlama; sandbox'lanmış asenkron derlemeler", "Devredilen asenkron derlemeler ve taşınabilir AGENTS.md kuralları"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Claude Code'un zevk konusundaki ününe rağmen, AI tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — Inter yazı tipleri, beyaz üzerine mor degradeler, yumuşak gölgeler, aşırı büyük yuvarlatılmış köşeler, “bunu bir AI yaptı diye bağıran” bir estetik. Anthropic bunu dağılımsal yakınsamaya bağlar: güvenli seçimler web eğitim verilerine hakimdir. Bildirilen diğer sorunlar arasında bozuk mobil düzenler ve UI metnine sızan talimatlar yer alır."}, {"kind": "steps", "items": [{"label": "Frontend Design skill'ini kurun", "body": "Claude'u gerçek bir yöne bağlanmaya zorlar ve AI tarafından aşırı kullanılan yazı tiplerinden ve degradelerden açıkça kaçınır."}, {"label": "Tarayıcı doğrulamasını etkinleştirin", "body": "Claude'un kırılma noktaları boyunca işlemesini ve kendi kendini kontrol etmesini sağlayın, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları CLAUDE.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Claude Code ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Claude Code'u birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Claude Code'u iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Claude Code'u seçin.", "Anthropic API anahtarınız (BYOK) veya Claude aboneliğinizle kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Claude Code ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "Claude Code tasarım çalışması için iyi mi?", "text": "Evet — frontend konusunda en iyi zevke sahip kodlama ajanı olarak yaygın biçimde kabul edilir; hex değerleri, boşluk ve tipografi ölçekleri hakkında spesifik, kod tabanının farkında kararlar verir. Frontend Design skill'i, bir tasarım sistemi ve bağlamdaki gerçek referans görsellerle, üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Claude Code ile tasarım yapmak için bir Claude aboneliğine ihtiyacım var mı?", "text": "Bir Anthropic API anahtarı (BYOK, Console üzerinden) veya bir Claude aboneliği (Pro / Max) kullanabilirsiniz. Her iki durumda da Open Design kimlik bilgilerinizi asla proxy'lemez — bunlar doğrudan makinenizdeki ajanınız tarafından kullanılır."}, {"name": "Frontend tasarımı için Claude Code mı yoksa Codex mı?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararları ve frontend akıl yürütmesiyle bilinir; Codex'in güçlü bir görsel cilası vardır ve devredilen, sandbox'lanmış derlemelerde öne çıkar. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Claude Code'u Figma'ya nasıl bağlarım?", "text": "Resmi Figma eklentisini claude plugin install figma@claude-plugins-official ile kurun. Ardından tasarım bağlamını kullanarak Figma frame'lerini kod olarak uygulayabilir ve çalışan bir UI'ı “Send this to Figma” ile düzenlenebilir Figma frame'lerine geri gönderebilirsiniz. Dev Mode MCP, ücretli bir Figma planı gerektirir."}, {"name": "Skills ve CLAUDE.md nedir?", "text": "CLAUDE.md, Claude Code'un her oturumun başında okuduğu, proje kökünüzdeki bir markdown dosyasıdır — tasarım kurallarınızı kodlama yeri. Skills, Claude'un talep üzerine yüklediği yinelenebilir talimatları ve kaynakları paketler; buna Anthropic'in resmi Frontend Design skill'i de dahildir. Open Design her ikisinden de özenle seçilmiş bir kütüphane sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Frontend Design skill'ini kurun, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını CLAUDE.md içinde kodlayın ve tarayıcı doğrulamasını etkinleştirin. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, Anthropic ile bağlantılı mı?", "text": "Hayır. Claude Code, Anthropic'in bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. Claude ve Claude Code, Anthropic'in ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel öncelikli ve Apache-2.0'dır. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve Anthropic kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Claude Code ile açık yolla tasarlayın.", "ctaBody": "Kendi Anthropic anahtarınızı veya Claude aboneliğinizi getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Claude Code'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'codex': {
        ...en['codex']!,
        title: "Tasarım için Codex — Open Design",
        description: "İnsanlar OpenAI Codex'i UI ve web tasarımı için nasıl kullanır — Product Design eklentisi, Figma entegrasyonu, frontend skill'leri — ve Open Design Codex'i nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "Codex",
        label: "Ajan · Codex",
        heading: "Tasarım için Codex.",
        lead: "Codex, OpenAI'nin kodlama ajanıdır. Product Design eklentisi ve Figma entegrasyonu ile ciddi bir tasarım aracı haline geldi. Open Design, Codex'i açık kaynaklı bir tasarım iş akışına bağlar — OpenAI anahtarınız veya ChatGPT aboneliğiniz, dosyalarınız, yerel öncelikli.",
        rich: {"heroCtaLead": "Open Design, Codex'i yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — OpenAI anahtarınız, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Codex'i Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex bir kod üreticisi olarak başladı, ancak 2026'da — ona doğru referansları, skill'leri ve doğrulama döngüsünü verdiğinizde — gerçek arayüzler tasarlamak için inandırıcı bir araç haline geldi. Bu, Codex'i UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Codex'in bugün ne olduğunu, frontend'de neden birden iyi olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden UI'a döngüyü, resmi Figma gidiş-dönüşünü, Cursor ve Claude Code ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex tasarım geri bildirim döngüsü: terminal ajanı, UI'ı işleyen tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: Codex terminalde UI oluşturur, bunu gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yineler."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-codex", "label": "OpenAI Codex gerçekte nedir"}, {"id": "why-design", "label": "Codex artık tasarımda neden iyi"}, {"id": "setup", "label": "Codex'i tasarım için kurun (sıfırdan)"}, {"id": "screenshot-workflow", "label": "Ekran görüntüsünden UI'a iş akışı"}, {"id": "figma", "label": "Codex + Figma gidiş-dönüşü"}, {"id": "vs", "label": "Codex, Cursor ve Claude Code karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Codex ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-codex", "heading": "OpenAI Codex gerçekte nedir (ve ne değildir)", "blocks": [{"kind": "p", "text": "Önce, “Codex” arayan hemen herkesi tökezleten bir kavram karmaşasını giderelim. Orijinal OpenAI Codex, erken GitHub Copilot'a güç veren ve 2023'te kullanımdan kaldırılan 2021 tarihli bir kod tamamlama modeliydi. Bu sayfanın konusu o değil. Bugünün Codex'i, OpenAI'nin ajansal kodlama aracıdır — doğal dildeki görevlerden kodu planlar, yazar, çalıştırır ve doğrular."}, {"kind": "p", "text": "Modern Codex dört yüzey üzerinden sunulur: bir terminal CLI'si (Rust ile yeniden yazılmış, Apache-2.0 lisanslı), VS Code, Cursor ve Windsurf için bir IDE eklentisi, devredilen asenkron görevler için bir bulut/web deneyimi ve uygulama içi bir tarayıcı ve Computer Use'a sahip bir masaüstü uygulaması."}, {"kind": "steps", "items": [{"label": "Varsayılan model", "body": "2026 ortası itibarıyla önerilen model gpt-5.5'tir; gpt-5.4 ise OpenAI'nin frontend ve bilgisayar kullanımı için açıkça eğittiği modeldir."}, {"label": "Talimat dosyası", "body": "Codex, proje kuralları için projenizdeki bir AGENTS.md dosyasını (araçlar arası bir standart) okur — tasarım kurallarınızı kodlamak için doğal yer."}, {"label": "Sandbox", "body": "Çekirdek düzeyinde bir sandbox'ta çalışır (varsayılan olarak workspace-write), böylece UI'ınızı düzenleyen bir ajan projenin dışına çıkamaz."}]}, {"kind": "ul", "items": ["Sağlayıcı: OpenAI", "Kimlik bilgisi: OpenAI API anahtarı (BYOK) veya ChatGPT aboneliği (Free / Go / Plus / Pro / Business / Enterprise)", "CLI'nin lisansı: Apache-2.0, açık kaynak"]}]}, {"id": "why-design", "heading": "Codex artık tasarımda neden iyi", "blocks": [{"kind": "p", "text": "2026'nın başlarında üç şey bir araya gelerek Codex'i jenerik bir kod üreticisi yerine gerçek bir tasarım aracı haline getirdi."}, {"kind": "steps", "items": [{"label": "Frontend için eğitilmiş bir model", "body": "OpenAI, frontend ve bilgisayar kullanımı için eğitilmiş ilk ana hat modeli olan GPT-5.4'ü, tasarım iş akışı boyunca çok daha iyi görsel anlama ve daha güçlü kendi kendini doğrulama ile yayınladı. Hatta son varlıklara bağlanmadan önce mood board'lar ve görsel seçenekler bile üretebilir."}, {"label": "Resmi bir frontend skill'i", "body": "openai/skills kataloğu, gerçek bir zevki dayatan özenle seçilmiş bir frontend-skill sunar: kartsız düzenler, tam genişlikte hero'lar, marka öncelikli hiyerarşi, ölçülü hareket, en fazla iki yazı tipi ve bir vurgu rengi — ve Codex'in oluşturmadan önce bir görsel tez yazmasını sağlar."}, {"label": "Tarayıcı doğrulaması", "body": "Playwright skill'i ile Codex, yalnızca derlemenin geçtiğini kontrol etmek yerine gerçek bir tarayıcı açar, kırılma noktalarına yeniden boyutlandırır ve çıktısını referansla karşılaştırır."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Üçünün de ardındaki ders: Codex varsayılan olarak zevke sahip değildir. Ona kısıtlar verdiğinizde iyi tasarım üretir — bir tasarım sistemi, estetik bir skill ve somut referanslar. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Codex'i tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir Codex'e giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, yapılandır, skill kur, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → AGENTS.md yapılandır → frontend skill'ini kur → tarayıcı doğrulamasını etkinleştir."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı AGENTS.md veya bir DESIGN.md içine koyun ve Codex'i bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Doğru akıl yürütme seviyesini seçin", "body": "OpenAI, düşük-orta akıl yürütme seviyelerinin sıklıkla en yüksek ayardan daha güçlü frontend sonuçları ürettiğini belirtiyor."}]}]}, {"id": "screenshot-workflow", "heading": "Ekran görüntüsünden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Codex ile en yüksek kaldıraçlı tasarım döngüsü, bir referans görseli çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar yinelemektir. OpenAI'nin kendi rehberliği beş adıma indirgenir."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve Codex'e token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Playwright etkileşimli skill'ini etkinleştirin, böylece Codex gerçek bir tarayıcıda işler ve kırılma noktalarına yeniden boyutlandırır.", "Codex'in uygulamasını ekran görüntüleriyle karşılaştırmasını sağlayarak yineleyin — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "Bir ekran görüntüsünü terminale sürükleyerek veya image bayrağı ile görselleri besleyin, ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "İkinci bir terminalde bir dev sunucusu çalıştırın, komutları küçük ve odaklı tutun ve iyi yinelemeleri commit edin / kötü olanları geri alın (geri aldığınızda Codex'e söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin."}]}, {"id": "figma", "heading": "Codex + Figma: tasarım ↔ kod gidiş-dönüşü", "blocks": [{"kind": "p", "text": "Şubat 2026'da OpenAI ve Figma resmi bir ortaklık duyurarak önceki Figma MCP beta'sını birinci sınıf, çift yönlü bir entegrasyona dönüştürdü. Her iki yönde de çalışır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame'in “link to selection” bağlantısını kopyalayın, onu get_design_context ile Codex'e yapıştırın ve ondan mevcut bileşen kütüphanenizi kullanarak tasarımı uygulamasını isteyin."}, {"label": "Kod → Tasarım", "body": "generate_figma_design aracı (“Code to Canvas”), canlı, çalışan bir UI'ı düzenlenebilir Figma frame'lerine geri dönüştürür — tüm ekran, seçili bir öğe veya bütün bir dosya."}]}, {"kind": "p", "text": "Figma MCP, uzak bir sunucu olarak çalışır ve hız sınırlarından muaftır. Bir kez ekleyin ve Codex, Claude Code, Cursor, VS Code ve daha fazlası için kullanılabilir olsun — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Codex, Cursor ve Claude Code", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Codex", "GPT-5.4 + frontend-skill sonrası güçlü görsel cila; görsel anlama", "Devredilen asenkron derlemeler, sandbox'lanmış çalıştırmalar, taşınabilir AGENTS.md kuralları"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Codex tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında bozuk mobil düzenler, UI metnine sızan talimatlar ve kullanım sınırlarına hızla ulaşmak yer alır."}, {"kind": "steps", "items": [{"label": "Bir frontend skill'i kurun", "body": "Özenle seçilmiş bir estetik skill, Codex'i varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Playwright doğrulamasını etkinleştirin", "body": "Codex'in kırılma noktaları boyunca işlemesini ve kendi kendini kontrol etmesini sağlayın, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları AGENTS.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Codex ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Codex'i birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Codex'i iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Codex'i seçin.", "OpenAI API anahtarınız (BYOK) veya ChatGPT aboneliğinizle kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Codex ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "OpenAI Codex gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda bir frontend skill'i, bir tasarım sistemi ve gerçek referans görsellerle Codex (özellikle GPT-5.4 üzerinde) üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Bu, OpenAI Codex Product Design eklentisi mi?", "text": "Hayır. Open Design, Codex'i bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. OpenAI'nin kendi araçlarını yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "Codex ile tasarım yapmak için bir ChatGPT aboneliğine ihtiyacım var mı?", "text": "Bir OpenAI API anahtarı (BYOK) veya ChatGPT aboneliğinizi kullanabilirsiniz. ChatGPT ile oturum açmak genellikle daha cömert sınırlar verir; Open Design her iki durumda da kimlik bilgilerinizi asla proxy'lemez."}, {"name": "Frontend tasarımı için Codex mi yoksa Claude Code mu?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararlarıyla bilinir; Codex'in GPT-5.4 sonrası güçlü bir görsel cilası vardır ve devredilen, sandbox'lanmış derlemelerde öne çıkar. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Codex'i Figma'ya nasıl bağlarım?", "text": "Resmi Figma MCP sunucusunu ekleyin (codex mcp add figma --url https://mcp.figma.com/mcp). Ardından get_design_context ile Figma frame'lerini kod olarak uygulayabilir ve çalışan bir UI'ı generate_figma_design ile düzenlenebilir Figma frame'lerine geri gönderebilirsiniz."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Bir frontend skill'i kurun, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını AGENTS.md içinde kodlayın ve Playwright doğrulamasını etkinleştirin. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, OpenAI ile bağlantılı mı?", "text": "Hayır. Codex, OpenAI'nin bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. OpenAI ve Codex, OpenAI'nin ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve OpenAI kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Codex ile açık yolla tasarlayın.", "ctaBody": "Kendi OpenAI anahtarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Codex'i Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Tasarımcılar için Cursor — Open Design",
        description: "Tasarımcılar Cursor'ı UI ve web tasarımı için nasıl kullanır — Design Mode, Figma'dan koda, Figma MCP — ve Open Design Cursor'ı nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "Cursor",
        label: "Ajan · Cursor",
        heading: "Tasarımcılar için Cursor.",
        lead: "Cursor, artık görsel bir Design Mode'a sahip AI kod editörüdür. Tasarımcılar onu işaret ve çizim yoluyla UI düzenlemek ve Figma'yı koda dönüştürmek için kullanır. Open Design, Cursor Agent'ı dosyalarınızı yerel tutan açık kaynaklı bir tasarım iş akışına bağlar.",
        rich: {"heroCtaLead": "Open Design, Cursor'ı yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — Cursor hesabınız veya model anahtarlarınız, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "Cursor'ı Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor, “oluştur ve işlenmesini izle” yaklaşımını UI'ı yayınlamanın varsayılan yolu haline getiren AI öncelikli kod editörüdür. Agent modu, satır içi düzenlemeler, editör içi bir önizleme ve MCP üzerinden Figma ile — ona doğru referansları, kuralları ve bir doğrulama döngüsü verdiğinizde — gerçek bir tasarım aracı haline geldi. Bu, Cursor'ı UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "Cursor'ın gerçekte ne olduğunu, sıkı yinele-ve-izle döngüsünün tasarım için neden iyi olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden ve önizlemeden UI'a döngüyü, MCP üzerinden Figma gidiş-dönüşünü, Codex ve Claude Code ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor tasarım yakınsaması: solda editör, ortada merkezinde Cursor işaretiyle özenle seçilmiş bir skill ve tasarım sistemi merkezi ve sağda işlenmiş bir UI", "caption": "Çekirdek fikir: Cursor, editörde UI'ı düzenler ve işler, bu sırada özenle seçilmiş bir tasarım merkezi ona çıktıyı bilinçli gösteren sistemi, skill'leri ve referansları besler."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-cursor", "label": "Cursor gerçekte nedir"}, {"id": "why-design", "label": "Cursor tasarımda neden iyi"}, {"id": "setup", "label": "Cursor'ı tasarım için kurun (sıfırdan)"}, {"id": "preview-workflow", "label": "Önizlemeden UI'a iş akışı"}, {"id": "figma", "label": "MCP üzerinden Cursor + Figma"}, {"id": "vs", "label": "Cursor, Codex ve Claude Code karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde Cursor ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor gerçekte nedir", "blocks": [{"kind": "p", "text": "Cursor, Anysphere tarafından geliştirilen AI öncelikli bir kod editörüdür. VS Code'un bir fork'udur, bu yüzden tanıdık editörü, eklentileri ve kısayol tuşlarını korur, ancak iş akışını; tüm projenizi okuyabilen, birden çok dosyayı düzenleyebilen, komutları çalıştırabilen ve sizinle döngü içinde yineleyebilen bir AI ajanı etrafında yeniden inşa eder."}, {"kind": "p", "text": "Tasarım çalışması için önemli yüzeyler şunlardır: Agent modu (bir sonuç tarif edersiniz ve Cursor dosyalar boyunca planlar ve düzenler), hızlı ince ayarlar için satır içi düzenlemeler ve Tab tamamlamaları, pencereyi terk etmeden çalışan UI'ı görebilmeniz için editör içi bir önizleme / tarayıcı ve canlı bir Figma dosyası gibi harici bağlamı çekmesine izin veren MCP desteği."}, {"kind": "steps", "items": [{"label": "Proje kuralları", "body": "Cursor, proje talimat dosyalarını okur — `.cursor/rules` altındaki sürümlenmiş `.mdc` kuralları ve sade bir `AGENTS.md` — böylece tasarım kurallarınızı ajanın her çalıştırmada okuduğu yere kodlayabilirsiniz."}, {"label": "Modeller", "body": "Cursor model açısından esnektir: aboneliğiniz üzerinden öncü modellerle gelir ve ayrıca kendi model anahtarlarınızı getirmeyi destekler, böylece aynı editör iş akışının arkasındaki motoru siz seçersiniz."}, {"label": "MCP", "body": "Model Context Protocol konuşur, böylece harici sunucular — en alakalısı Figma MCP sunucusu — ajan için birinci sınıf bağlam haline gelir."}]}, {"kind": "ul", "items": ["Sağlayıcı: Anysphere", "Kimlik bilgisi: Cursor hesabı / aboneliği (Hobby / Pro / Business) veya kendi model anahtarlarınız (BYOK)", "Biçim: Editör içi bir ajan ve önizlemeye sahip AI öncelikli kod editörü (VS Code fork'u)"]}]}, {"id": "why-design", "heading": "Cursor tasarımda neden iyi", "blocks": [{"kind": "p", "text": "Cursor'ın tasarım üstünlüğü tek bir özellik değildir — oluştur-ve-gör döngüsünün sıkılığıdır. Üç şey onu jenerik bir kod üreticisi yerine bir tasarım aracı gibi hissettirir."}, {"kind": "steps", "items": [{"label": "Sıkı bir yinele-ve-izle döngüsü", "body": "Komut verirsiniz, Cursor dosyalar boyunca düzenler ve editör içi önizleme sonucu hemen işler — böylece boşluğu, hiyerarşiyi ve hareketi ayrı bir terminal ve tarayıcı arasında gidip gelmek yerine saniyeler içinde ayarlarsınız."}, {"label": "Doğrudan görsel düzenleme", "body": "Sohbetin ötesinde, Cursor önizlemede öğeleri seçmenize ve stilleri ince ayar yapmanıza izin verir, böylece küçük görsel düzeltmeler kod arkeolojisi yerine tasarım düzenlemeleri gibi hissettirir."}, {"label": "Proje kuralları ve MCP bağlamı", "body": "`.cursor/rules` (veya `AGENTS.md`) ve Figma MCP sunucusu ile ajan, tahmin yürütmek yerine token'larınıza, bileşenlerinize ve gerçek tasarım spesifikasyonlarınıza karşı çalışır."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller."}, {"kind": "p", "text": "Çıkarılan ders, her ajanın öğrettiğiyle aynıdır: Cursor varsayılan olarak zevke sahip değildir. Ona kısıtlar verdiğinizde iyi tasarım üretir — bir tasarım sistemi, estetik bir skill ve somut referanslar. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "Cursor'ı tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden; tasarım sisteminize karşı UI oluşturabilen, önizleyebilen ve doğrulayabilen bir Cursor'a giden tam yol şudur."}, {"kind": "ol", "items": ["Cursor'ı cursor.com'dan kurun ve Cursor hesabınızla oturum açın veya Ayarlar'da kendi model anahtarlarınızı (BYOK) yapılandırın.", "Projenizi açın ve sohbet / Agent panelinde bir model seçin.", "Proje kuralları ekleyin: yapılandırılmış, glob kapsamlı kurallar için `.cursor/rules/*.mdc` oluşturun veya basit, okunabilir talimatlar için sade bir `AGENTS.md` oluşturun.", "Figma MCP sunucusunu bağlayın (isteğe bağlı), böylece ajan canlı tasarım bağlamını okuyabilir.", "Dev sunucunuzu çalıştırın ve yinelerken UI'ı görmek ve doğrulamak için editör içi önizlemeyi kullanın."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, kimlik doğrula, kuralları yapılandır, skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula → proje kurallarını yapılandır → bir skill ekle → önizleme doğrulamasını etkinleştir."}, {"kind": "p", "text": "Minimal bir proje kuralları dosyası, ajanın jenerik bir görünüme dönmek yerine bir markaya göre tasarlamasını sağlar. Onu Cursor'ın her çalıştırmada okuduğu yere koyun:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı `.cursor/rules` veya `AGENTS.md` içine koyun ve Cursor'ı bunlara yönlendirin; böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin."}, {"label": "Komutları küçük tutun", "body": "Cursor'ın sıkı döngüsü odaklı isteklere ödül verir — bir seferde bir bileşen veya durum üzerinde yineleyin ve geçişler arasında önizlemeyi izleyin."}]}]}, {"id": "preview-workflow", "heading": "Önizlemeden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Cursor ile en yüksek kaldıraçlı tasarım döngüsü, bir referansı çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar editörde yinelemektir — tahmin yürütmek yerine canlı önizlemeyi sürekli izleyerek."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve Cursor'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin.", "Editör içi önizlemeyi açık ve dev sunucunuzu çalışır tutun, böylece her düzenleme önemsediğiniz kırılma noktalarında hemen işlensin.", "İşlenmiş UI'ı referanslarla karşılaştırarak yineleyin — ve küçük görsel düzeltmeler için önizlemede doğrudan öğe seçimini kullanın."]}, {"kind": "p", "text": "Sohbete bir görsel ekleyerek referansları besleyin, ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "İyi yinelemeleri commit edin ve kötü olanları geri alın (geri aldığınızda Cursor'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin — herhangi bir ajan döngüsünün sapmasını önleyen aynı disiplin."}]}, {"id": "figma", "heading": "Cursor + Figma: MCP üzerinden tasarım ↔ kod", "blocks": [{"kind": "p", "text": "Cursor, resmi Figma MCP sunucusu aracılığıyla Figma'ya bağlanır; bu da ajana düz bir ekran görüntüsü yerine canlı bir Figma dosyasına yapılandırılmış erişim sağlar. Bu, devirden tahmin yürütmeyi ortadan kaldırır."}, {"kind": "steps", "items": [{"label": "Tasarım → Kod", "body": "Figma'da bir frame'in bağlantısını kopyalayın, onu Cursor'a yapıştırın ve ondan tasarımı uygulamasını isteyin. MCP sunucusu gerçek tasarım bağlamını — bileşenler, değişkenler, düzen verisi, token'lar — açığa çıkarır, böylece üretilen kod kaynağa yaklaşmak yerine onunla eşleşir."}, {"label": "Hizalı kalın", "body": "Figma'da tutarlı kullanılan tasarım token'ları, stiller ve bileşenlerle (ve mevcut olduğunda Code Connect ile), Cursor'ın çıktısı ilkelleri yeniden icat etmek yerine gerçek tasarım sisteminize eşlenmiş kalır."}]}, {"kind": "p", "text": "Uzak Figma MCP sunucusunu bir kez kurun, Cursor için birinci sınıf bağlam olarak kullanılabilir olsun. MCP açık bir standart olduğundan, aynı sunucu Cursor, Claude Code, Codex ve VS Code arasında yeniden kullanılabilir — tam olarak Open Design'ın düzenlemek için inşa edildiği türden taşınabilir, çok ajanlı bir yetenek."}]}, {"id": "vs", "heading": "Tasarım için Cursor, Codex ve Claude Code", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["Cursor", "Canlı editör içi önizleme ve doğrudan öğe düzenlemeyle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"], ["Codex", "Bir frontend skill'i ile güçlü görsel cila; görsel anlama ve sandbox'lanmış çalıştırmalar", "Devredilen asenkron derlemeler ve taşınabilir AGENTS.md kuralları"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: üçü de skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "Cursor tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında mobilde bozulan düzenler ve UI metnine sızan talimatlar yer alır."}, {"kind": "steps", "items": [{"label": "Bir tasarım skill'i ekleyin", "body": "Özenle seçilmiş bir estetik skill, Cursor'ı varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Doğrulamak için önizlemeyi kullanın", "body": "Editör içi önizlemede kırılma noktaları boyunca işleyin ve kendi kendini kontrol edin, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları `.cursor/rules` içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde Cursor ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. Cursor'ı birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece Cursor'ı iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak Cursor'ı seçin.", "Cursor hesabınız veya kendi model anahtarlarınızla (BYOK) kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Bir tasarım sistemi ve bir skill seçin, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı Cursor ajanı, aynı anahtar — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "Cursor gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda bir tasarım skill'i, bir tasarım sistemi ve gerçek referans görsellerle Cursor üretim kalitesinde, duyarlı UI üretir ve editör içi önizlemesi onu görsel olarak doğrulamanıza ve iyileştirmenize olanak tanır. Bu bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Bu resmi bir Cursor ürünü mü?", "text": "Hayır. Open Design, Cursor'ı bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. Cursor'ı yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "Cursor ile tasarım yapmak için bir Cursor aboneliğine ihtiyacım var mı?", "text": "Bir Cursor hesabı / aboneliği kullanabilir veya kendi model anahtarlarınızı (BYOK) getirebilirsiniz. Open Design her iki durumda da kimlik bilgilerinizi asla proxy'lemez — bunlar doğrudan ajanınız tarafından kullanılır."}, {"name": "Frontend tasarımı için Cursor mı yoksa Claude Code mu?", "text": "İkisi de güçlüdür. Claude Code, spesifik, kod tabanının farkında tasarım kararlarıyla bilinir; Cursor'ın üstünlüğü, editör içinde canlı bir önizlemeyle sıkı oluştur-ve-gör döngüsüdür. Birçok ekip ikisini de kullanır — Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "Cursor'ı Figma'ya nasıl bağlarım?", "text": "Cursor'a resmi Figma MCP sunucusunu ekleyin, ardından bir Figma frame bağlantısını sohbete yapıştırın ve Cursor'dan onu uygulamasını isteyin. Sunucu gerçek bileşenleri, değişkenleri ve düzen verisini açığa çıkarır, böylece üretilen kod kaynak tasarımla eşleşir."}, {"name": "Jenerik “AI çöplüğü” estetiğinden nasıl kaçınırım?", "text": "Bir tasarım skill'i ekleyin, gerçek tasarım token'ları ve referans ekran görüntüleri sağlayın, marka kurallarını `.cursor/rules` veya `AGENTS.md` içinde kodlayın ve önizlemede kırılma noktaları boyunca doğrulayın. Open Design bunları özenle seçilmiş bir kütüphane olarak sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, Cursor veya Anysphere ile bağlantılı mı?", "text": "Hayır. Cursor, Anysphere'in bir ürünüdür; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir. Cursor ve Anysphere, Anysphere, Inc.'in ticari markalarıdır."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve Cursor veya model kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "Cursor ile açık yolla tasarlayın.", "ctaBody": "Kendi Cursor hesabınızı veya model anahtarlarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "Cursor'ı Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "Tasarım için OpenCode — Open Design",
        description: "İnsanlar OpenCode'u UI ve web tasarımı için nasıl kullanır — design.md dosyaları, UI/UX skill'leri, Figma MCP — ve Open Design OpenCode'u nasıl yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür.",
        breadcrumb: "OpenCode",
        label: "Ajan · OpenCode",
        heading: "Tasarım için OpenCode.",
        lead: "OpenCode, açık kaynaklı terminal AI kodlama ajanıdır. Tasarımcılar gerçek UI üretmek için ona tasarım skill'leri ve DESIGN.md dosyaları ekler. Open Design bunu yapılandırılmış, açık kaynaklı bir iş akışı haline getirir — sağlayıcı anahtarlarınızı getirin, her şeyi yerel tutun.",
        rich: {"heroCtaLead": "Open Design, OpenCode'u yerel öncelikli, açık kaynaklı bir tasarım ajanına dönüştürür — kendi sağlayıcı anahtarınızla seçtiğiniz herhangi bir model, dosyalarınız ve etrafında özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi.", "heroCtaActions": [{"label": "OpenCode'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode, bilinçli olarak modelden bağımsız, açık kaynaklı, terminal öncelikli bir AI kodlama ajanıdır: kendi sağlayıcı anahtarınızı getirir ve aynı iş akışının arkasında istediğiniz herhangi bir modeli çalıştırırsınız. Bu açıklık onu tasarım çalışması için doğal bir temel haline getirir — ama her ajan gibi, yalnızca ona doğru referansları, skill'leri ve bir doğrulama döngüsü verdiğinizde iyi UI üretir. Bu, OpenCode'u UI, frontend ve tasarım sistemi çalışmaları için kullanmaya ve onu Open Design ile yapılandırılmış bir tasarım iş akışına bağlamaya dair pratik, uçtan uca bir rehberdir.", "OpenCode'un gerçekte ne olduğunu, modelden bağımsız, açık bir ajanın tasarım için neden iyi bir uyum olduğunu, sıfırdan nasıl kurulacağını, ekran görüntüsünden UI'a döngüyü, AGENTS.md ve MCP'nin onu nasıl genişlettiğini, Codex, Claude Code ve Cursor ile nasıl karşılaştırıldığını, AI çıktısını jenerik gösteren tuzakları ve Open Design'ın açık, yerel öncelikli bir tasarım katmanı olarak bu boşluğu nasıl kapattığını ele alır — doğal bir eşleşme, çünkü her iki proje de açık kaynaklı ve kendi makinenizde çalışır."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode tasarım geri bildirim döngüsü: bir terminal TUI ajanı, UI'ı işleyen bir tarayıcı ve bir çalışma alanı, geri döngü oluşturan bir geri bildirim okuyla", "caption": "Çekirdek döngü: OpenCode terminalde UI oluşturur, bunu gerçek bir tarayıcıda işler ve doğrular, referanslarınıza karşı yineler — seçtiğiniz hangi model olursa olsun."}, "tocLabel": "Bu sayfada", "toc": [{"id": "what-is-opencode", "label": "OpenCode gerçekte nedir"}, {"id": "why-design", "label": "Açık, her-model ajanı tasarıma neden uyar"}, {"id": "setup", "label": "OpenCode'u tasarım için kurun (sıfırdan)"}, {"id": "screenshot-workflow", "label": "Ekran görüntüsünden UI'a iş akışı"}, {"id": "extend", "label": "AGENTS.md, MCP ve paylaşılabilir oturumlar"}, {"id": "vs", "label": "OpenCode, Codex, Claude Code ve Cursor karşılaştırması"}, {"id": "pitfalls", "label": "Tuzaklar ve “AI çöplüğü” görünümü"}, {"id": "open-design", "label": "Open Design içinde OpenCode ile tasarım"}, {"id": "faq", "label": "SSS"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode gerçekte nedir", "blocks": [{"kind": "p", "text": "OpenCode, SST'nin (Anomaly Innovations) arkasındaki ekip tarafından sürdürülen, terminal için inşa edilmiş açık kaynaklı bir AI kodlama ajanıdır. Reponuzu okur, komutları çalıştırır, dosyaları düzenler ve büyük bir dil modeliyle konuşur — ama sağlayıcıya bağlı ajanların aksine, kendi modelini sunmaz. Onu istediğiniz herhangi bir sağlayıcıya ve modele yönlendirir ve kendi anahtarınızı getirirsiniz."}, {"kind": "p", "text": "Aynı motorun üzerinde bir masaüstü uygulaması ve IDE eklentileriyle birlikte bir terminal UI'sı (TUI) olarak çalışır. Kaputun altında bir istemci/sunucu mimarisi kullanır, böylece işi yapan ajan, onu sürdüğünüz yüzeyden ayrıştırılmıştır. İki yerleşik ajan — build ve plan — Tab tuşuyla geçiş yapar."}, {"kind": "steps", "items": [{"label": "Modelden bağımsız", "body": "Modeller ve sağlayıcılar, açık bir katalog olan models.dev'den gelir. Bunları opencode.json içinde bir provider/model-id dizesiyle yapılandırır ve yüklenmesini istemediğiniz sağlayıcıları devre dışı bırakabilirsiniz — böylece aynı tasarım iş akışı Anthropic, OpenAI, Google, OpenRouter, yerel modeller ve daha fazlasında çalışır."}, {"label": "Talimat dosyası", "body": "OpenCode, proje kuralları için projenizdeki bir AGENTS.md dosyasını (araçlar arası standart, CLAUDE.md ile de uyumlu) okur — tasarım kurallarınızı kodlamak için doğal yer. Bir tane oluşturmak için /init çalıştırın."}, {"label": "Genişletilebilir", "body": "LSP entegrasyonunu, MCP sunucularını, temaları, kısayol tuşlarını ve özel komutları destekler, ayrıca işbirliği için paylaşılabilir oturum bağlantıları sunar."}]}, {"kind": "ul", "items": ["Sürdüren: SST / Anomaly Innovations (açık kaynaklı proje)", "Kimlik bilgisi: kendi model sağlayıcı API anahtar(lar)ınız — BYOK, sağlayıcı kilidi yok", "Lisans: MIT, açık kaynak"]}]}, {"id": "why-design", "heading": "Açık, her-model ajanı tasarım çalışmasına neden uyar", "blocks": [{"kind": "p", "text": "OpenCode'un, bir sağlayıcı ajanı gibi tek bir “tasarım modeli” yoktur — ve asıl mesele de budur. Modelden bağımsız ve açık olduğundan, aynı tasarım iş akışını şu anda frontend'de en iyi olan modelde çalıştırabilir, sonra değiştirebilir veya yerel bir modele geri dönebilirsiniz, hepsi kurulumunuzu değiştirmeden."}, {"kind": "p", "text": "Ama model seçimi tek başına zevk satın almaz. Her kodlama ajanı gibi, OpenCode da ona kısıtlar vermediğiniz sürece jenerik UI üretir. İyi tasarım çıktısı, sağladığınız üç girdiden gelir."}, {"kind": "steps", "items": [{"label": "Bir tasarım sistemi", "body": "Ajanın yeniden kullandığı gerçek token'lar, ilkeller ve kurallar, böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşir."}, {"label": "Estetik bir skill", "body": "Gerçek bir zevki dayatan özenle seçilmiş bir skill — ölçülü hareket, marka öncelikli hiyerarşi, en fazla iki yazı tipi ve bir vurgu rengi — ve ajanın oluşturmadan önce bir yöne bağlanmasını sağlar."}, {"label": "Somut referanslar", "body": "Gerçek referans görseller ve birden çok durum (masaüstü ve mobil, hover, boş, yükleniyor), tek bir hero görseli değil."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Tasarım sistemi, skill ve referans görselin iyi tasarım çıktısına yakınsadığını gösteren diyagram", "caption": "Zevk, sağladığınız üç girdiden gelir: bir tasarım sistemi, bir skill ve gerçek referans görseller — hangi modeli çalıştırdığınızdan bağımsız olarak."}, {"kind": "p", "text": "Ders: OpenCode size model özgürlüğü verir, ama zevk yine de özenle seçilmiş bir tasarım bağlamından gelir. Open Design tam olarak bu girdileri paketler; ikisinin neden birbirine uyduğunun nedeni de budur — her ikisi de açık kaynaklı ve yerel önceliklidir (daha fazlası aşağıda)."}]}, {"id": "setup", "heading": "OpenCode'u tasarım çalışması için sıfırdan kurun", "blocks": [{"kind": "p", "text": "Temiz bir makineden, UI oluşturabilen ve doğrulayabilen bir OpenCode'a giden tam yol şudur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Beş adımlı kurulum akışı: kur, sağlayıcı anahtarınızla kimlik doğrula, AGENTS.md yapılandır, bir skill ekle, doğrula", "caption": "Kurulum sırası: kur → kimlik doğrula (sağlayıcı anahtarınız) → AGENTS.md yapılandır → bir skill ekle → gerçek bir tarayıcıda doğrula."}, {"kind": "steps", "items": [{"label": "Tasarım kurallarınızı kodlayın", "body": "Token'larınızı, ilkellerinizi ve kurallarınızı AGENTS.md (veya ondan referans verilen bir DESIGN.md) içine koyun, böylece çıktı jenerik bir görünüme dönmek yerine bir markayla eşleşsin. opencode.json içindeki instructions seçeneği, glob'lar aracılığıyla ek kural dosyalarına işaret edebilir."}, {"label": "Yetenekli bir model seçin", "body": "OpenCode modelden bağımsız olduğundan, tasarım geçişi için şu anda frontend'de en güçlü olan sağlayıcı/modeli seçin — ve iş akışınızın geri kalanını değişmeden bırakın."}]}]}, {"id": "screenshot-workflow", "heading": "Ekran görüntüsünden UI'a iş akışı", "blocks": [{"kind": "p", "text": "Herhangi bir ajanla en yüksek kaldıraçlı tasarım döngüsü, bir referans görseli çalışan, duyarlı bir UI'a dönüştürmek ve eşleşene kadar yinelemektir. Aynı beş adımlı biçim OpenCode'da da geçerlidir."}, {"kind": "ol", "items": ["Sahip olduğunuz en net görsel referanslardan başlayın — ve yalnızca tek bir hero görseli değil, birden çok durumu (masaüstü ve mobil, hover, boş, yükleniyor) dahil edin.", "Komutta spesifik olun; belirsiz komutlar jenerik UI üretir.", "Bir tasarım sistemi hazırlayın ve OpenCode'a token'ların ve kanonik ilkellerin nerede yaşadığını söyleyin (AGENTS.md içinde).", "Bir dev sunucusu çalıştırın ve ajanın gerçek bir tarayıcıda işlemesini sağlayın, sonucu kontrol etmek için kırılma noktalarına yeniden boyutlandırarak.", "OpenCode'un uygulamasını ekran görüntüleriyle karşılaştırmasını sağlayarak yineleyin — yalnızca derlendiğini onaylamasın."]}, {"kind": "p", "text": "TUI'da çalışma dizininizin bulanık bir aramasını yapmak için dosyalara @ ile referans verin, satır içi shell komutlarını başta bir ! ile çalıştırın ve eylemleri / komutlarıyla sürün. Ardından somut kısıtlarla komut verin:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Komutları küçük ve odaklı tutun, iyi yinelemeleri commit edin ve kötü olanları geri alın (geri aldığınızda OpenCode'a söyleyin), böylece her geçiş temiz bir temel üzerine inşa edilsin."}]}, {"id": "extend", "heading": "AGENTS.md, MCP ve paylaşılabilir oturumlar", "blocks": [{"kind": "p", "text": "Üç genişletme noktası, OpenCode'u sürekli tasarım çalışması için pratik kılar ve üçü de açık bir tasarım iş akışına temizce eşlenir."}, {"kind": "steps", "items": [{"label": "AGENTS.md kuralları", "body": "Proje kuralları, repo kökündeki bir AGENTS.md içinde yaşar (veya ~/.config/opencode/AGENTS.md içindeki global kurallar). Her çalıştırmada okunan, tasarım kurallarınız için kalıcı evdir ve diğer ajanların kullandığı CLAUDE.md dosyalarıyla uyumludur."}, {"label": "MCP sunucuları", "body": "OpenCode, mcp anahtarı altında yapılandırılan hem yerel (command) hem de uzak (URL) MCP sunucularını destekler — yalnızca OpenCode'da değil, ajanlar arasında çalışan tasarım bağlamı ve harici araçları getirmenin taşınabilir yolu."}, {"label": "Paylaşılabilir oturumlar", "body": "/share komutu, işbirliği veya inceleme için bir konuşmaya genel bir bağlantı oluşturur ve /unshare onu iptal eder — bir tasarım geçişi üzerine geri bildirim almak için kullanışlıdır."}]}, {"kind": "p", "text": "Bunlar taşınabilir, çok ajanlı yeteneklerdir — tam olarak Open Design'ın, her proje başına yeniden oluşturmak yerine düzenlemek için inşa edildiği türden şeyler."}]}, {"id": "vs", "heading": "Tasarım için OpenCode, Codex, Claude Code ve Cursor", "blocks": [{"kind": "p", "text": "Tasarım çalışması için tek bir kazanan yoktur — her ajanın farklı bir gücü vardır ve deneyimli ekipler bunları üst üste yığar. Adil bir özet:"}, {"kind": "table", "columns": ["Ajan", "Tasarım gücü", "En iyi olduğu alan"], "rows": [["OpenCode", "Açık kaynaklı ve modelden bağımsız; tek bir terminal iş akışının arkasında herhangi bir sağlayıcı çalıştırın", "BYOK özgürlüğü, model değiştirme, tamamen açık ve yerel öncelikli kurulumlar"], ["Codex", "Bir frontend skill'i ile güçlü görsel cila; görsel anlama", "Devredilen asenkron, sandbox'lanmış derlemeler, taşınabilir AGENTS.md kuralları"], ["Claude Code", "Spesifik tasarım kararları (hex, boşluk, tipografi) ve kod tabanının farkında UX", "Frontend akıl yürütmesi ve geniş bağlamlı yeniden düzenlemeler"], ["Cursor", "Canlı önizleme ve satır içi düzenlemelerle görsel oluştur-ve-gör döngüsü", "Bir IDE içinde sıkı yinele-ve-izle UI çalışması"]]}, {"kind": "p", "text": "Tekrarlanan topluluk kararı, zevkin insanlardan geldiğidir: hepsi skill'ler, referanslar ve kısıtlar olmadan jenerik bir estetiğe varsayılan olarak kayar. Çözülmesi gereken asıl sorun budur — ve bu sorun, model biçimli değil, tasarım aracı biçimlidir; OpenCode gibi açık bir ajanın açık bir tasarım katmanıyla bu kadar iyi eşleşmesinin nedeni de tam olarak budur."}]}, {"id": "pitfalls", "heading": "Tuzaklar ve “AI çöplüğü” görünümünden nasıl kaçınılır", "blocks": [{"kind": "p", "text": "AI tarafından üretilen tasarımla ilgili en yaygın şikayet, jenerik görünmesidir — yumuşak degradeler, yüzen paneller, aşırı büyük yuvarlatılmış köşeler, dramatik gölgeler, “bunu bir AI yaptı diye bağıran” bir Inter-ve-mor havası. Bildirilen diğer sorunlar arasında bozuk mobil düzenler ve UI metnine sızan talimatlar yer alır. Bunların hiçbiri OpenCode'a özgü değildir; herhangi bir ajan özenle seçilmiş bir tasarım bağlamı olmadan çalıştığında olan budur."}, {"kind": "steps", "items": [{"label": "Estetik bir skill ekleyin", "body": "Özenle seçilmiş bir tasarım skill'i, ajanı varsayılan görünüm yerine gerçek bir yöne bağlanmaya zorlar."}, {"label": "Gerçek bir tarayıcıda doğrulayın", "body": "Kırılma noktaları boyunca işleyin ve kendi kendini kontrol edin, böylece düzenler mobilde sessizce bozulmasın."}, {"label": "Token ve referans sağlayın", "body": "Gerçek tasarım token'ları ve referans ekran görüntüleri, çıktı kalitesi üzerindeki en büyük tek kaldıraçtır."}, {"label": "Kuralları AGENTS.md içinde kodlayın", "body": "“hero kartı yok, en fazla iki yazı tipi, marka öncelikli hiyerarşi” gibi kuralları, ajanın her çalıştırmada okuduğu yere koyun."}]}, {"kind": "p", "text": "Her hafifletmenin, hangi modeli çalıştırdığınızdan bağımsız olarak, ajana özenle seçilmiş bir tasarım bağlamı vermekle ilgili olduğuna dikkat edin. Bu bağlamı proje başına elle sürdürmek, Open Design'ın ortadan kaldırdığı zahmettir."}]}, {"id": "open-design", "heading": "Open Design içinde OpenCode ile tasarım", "blocks": [{"kind": "p", "text": "Open Design, yukarıdaki iş akışının sürekli istediği açık kaynaklı tasarım katmanıdır. OpenCode'u birinci taraf bir adaptör olarak ele alır ve onu özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi, yapılandırılmış bir render hattı ve yerel bir masaüstü UI'sı ile sarmalar — böylece herhangi bir ajanı iyi yapan tasarım bağlamı, her seferinde elle bir araya getirilmek yerine ilk çalıştırmadan itibaren oradadır. Her iki proje de açık kaynaklı ve yerel önceliklidir, bu da eşleşmeyi doğal bir uyum haline getirir."}, {"kind": "ol", "items": ["Open Design'ı kurun ve ajanınız olarak OpenCode'u seçin.", "Kendi model sağlayıcı API anahtarınızla (BYOK) kimlik doğrulayın — kimlik bilgileri makinenizde kalır ve asla bizim üzerimizden proxy'lenmez.", "Herhangi bir sağlayıcı ve model seçin, artı bir tasarım sistemi ve bir skill, ardından tutarlı bir zevkle sunumlar, prototipler ve açılış sayfaları üretin.", "Her artefakt ve DESIGN.md dosyası, barındırılan bir bulutta değil, kendi reponuzda yaşar."]}, {"kind": "p", "text": "Aynı OpenCode ajanı, aynı model özgürlüğü — artı etrafında gerçek, taşınabilir, açık kaynaklı bir tasarım iş akışı. Yerel öncelikli ve Apache-2.0'dır, bu yüzden çalışmanız veya kimlik bilgileriniz hakkında hiçbir şey makinenizden ayrılmaz."}]}], "faqTitle": "Sıkça sorulan sorular", "faq": [{"name": "OpenCode gerçekten tasarım çalışması yapabilir mi?", "text": "Evet — bağlamda estetik bir skill, bir tasarım sistemi ve gerçek referans görsellerle OpenCode üretim kalitesinde, duyarlı UI üretir ve bunu bir tarayıcıda doğrulayabilir. Modelden bağımsız olduğundan, şu anda frontend'de en iyi olan hangi modelse onu çalıştırırsınız. Bu özenle seçilmiş bağlam olmadan jenerik bir görünüme dönme eğilimindedir; Open Design'ın doldurduğu boşluk da budur."}, {"name": "Tasarım için OpenCode ile hangi modeli kullanmalıyım?", "text": "Hangisini isterseniz — OpenCode, models.dev aracılığıyla sağlayıcıdan bağımsızdır, böylece Anthropic, OpenAI, Google, OpenRouter veya yerel modelleri aynı iş akışının arkasında çalıştırabilir ve istediğiniz zaman değiştirebilirsiniz. Tasarım çıktısının kalitesi, modelden çok daha fazla skill'inize, tasarım sisteminize ve referanslarınıza bağlıdır."}, {"name": "Open Design, OpenCode (SST) ekibi tarafından mı yapıldı?", "text": "Hayır. Open Design, OpenCode'u bir ajan olarak entegre eden bağımsız bir açık kaynaklı projedir. OpenCode'u yerel öncelikli, açık bir skill ve tasarım sistemi kütüphanesiyle tamamlar."}, {"name": "OpenCode ile tasarım yapmak için özel bir aboneliğe ihtiyacım var mı?", "text": "Hayır — OpenCode BYOK'tur. Kendi model sağlayıcı API anahtarınızı getirirsiniz ve Open Design kimlik bilgilerinizi asla proxy'lemez. Sağlayıcı kilidi yoktur."}, {"name": "Frontend tasarımı için OpenCode mu, Codex mi yoksa Claude Code mu?", "text": "Hepsi güçlüdür ve birçok ekip bunları üst üste yığar. OpenCode'un üstünlüğü tamamen açık kaynaklı ve modelden bağımsız olmasıdır; Codex devredilen, sandbox'lanmış derlemelerde öne çıkar; Claude Code spesifik, kod tabanının farkında tasarım kararlarıyla bilinir. Open Design, tasarım iş akışınızı değiştirmeden ajanlar arasında geçiş yapmanızı sağlar."}, {"name": "OpenCode'u tasarım bağlamı için nasıl genişletirim?", "text": "Kuralları AGENTS.md içinde kodlayın, taşınabilir araçlar ve tasarım bağlamı için mcp anahtarı altına MCP sunucuları ekleyin ve inceleme için paylaşılabilir oturumları kullanın. Open Design, özenle seçilmiş bir skill ve tasarım sistemi kütüphanesi sunar, böylece proje başına kurulumu atlarsınız."}, {"name": "Open Design, OpenCode veya SST ile bağlantılı mı?", "text": "Hayır. OpenCode, SST (Anomaly Innovations) tarafından sürdürülen açık kaynaklı bir projedir; Open Design, onu birinci taraf bir adaptör olarak destekleyen bağımsız bir açık kaynaklı projedir."}, {"name": "Dosyalarım ve kimlik bilgilerim güvende mi?", "text": "Evet — Open Design yerel önceliklidir. Dosyalarınız, artefaktlarınız ve DESIGN.md'niz kendi reponuzda kalır ve model sağlayıcı kimlik bilgileriniz doğrudan ajanınız tarafından kullanılır, asla Open Design sunucuları üzerinden yönlendirilmez."}], "ctaTitle": "OpenCode ile açık yolla tasarlayın.", "ctaBody": "Kendi model sağlayıcı anahtarınızı getirin, her dosyayı yerel tutun ve zaten kullandığınız açık ajanın etrafında özenle seçilmiş bir tasarım kütüphanesi edinin.", "ctaActions": [{"label": "OpenCode'u Open Design içinde kullanın", "href": "/quickstart/", "variant": "primary"}, {"label": "GitHub'da yıldız verin", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Masaüstü uygulamasını indirin", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Desteklenen tüm ajanları görün"},
      },
    },
    'uk': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code для дизайну — Open Design",
        description: "Як дизайнери використовують Claude Code для UI та вебдизайну, і як Open Design перетворює його на справжнього дизайн-агента — local-first, BYOK, із кураторською бібліотекою skill-ів і дизайн-систем.",
        breadcrumb: "Claude Code",
        label: "Агент · Claude Code",
        heading: "Claude Code для дизайну.",
        lead: "Claude Code — це термінальний агент для кодування від Anthropic. Люди вже використовують його для створення UI, дизайн-систем і лендингів. Open Design вбудовує його в повноцінний дизайн-процес — підключіть свій ключ Anthropic або підписку Claude, тримайте кожен файл локально.",
        rich: {"heroCtaLead": "Open Design перетворює Claude Code на local-first дизайн-агента з відкритим кодом — ваш ключ Anthropic або підписка Claude, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code широко вважають агентом для кодування з найкращим смаком до фронтенду — він міркує про інтерфейси з незвичною точністю, називаючи конкретні значення hex, відступи й типографічні шкали, і рефакторить UI у великій кодовій базі, не втрачаючи нитки. Але «з коробки» він усе ще тяжіє до загального вигляду, доки ви не дасте йому дизайн-систему, skill-и та реальні референси. Це практичний наскрізний посібник з використання Claude Code для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований процес разом з Open Design.", "Тут розглядається, чим насправді є Claude Code, чому він сильний у фронтенді, як налаштувати його з нуля, робочий процес із CLAUDE.md і Skills, офіційний двосторонній обмін із Figma, як він порівнюється з Codex і Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну Claude Code: термінальний агент, що ухвалює конкретні дизайн-рішення, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Claude Code продумує конкретні UI-рішення в терміналі, рендерить і перевіряє їх у справжньому браузері та сходиться до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-claude-code", "label": "Чим насправді є Claude Code"}, {"id": "why-design", "label": "Чому Claude Code добрий у дизайні"}, {"id": "setup", "label": "Налаштування Claude Code для дизайну (з нуля)"}, {"id": "skills-workflow", "label": "Робочий процес із CLAUDE.md і Skills"}, {"id": "figma", "label": "Двосторонній обмін Claude Code + Figma"}, {"id": "vs", "label": "Claude Code проти Codex проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Claude Code в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-claude-code", "heading": "Чим насправді є Claude Code", "blocks": [{"kind": "p", "text": "Claude Code — це агентний інструмент кодування від Anthropic. Він читає вашу кодову базу, редагує файли, виконує команди й інтегрується з вашими інструментами розробки — планує, пише та перевіряє роботу за завданнями природною мовою, а не просто автодоповнює рядки."}, {"kind": "p", "text": "Він постачається на кількох поверхнях, що мають один і той самий рушій: термінальний CLI, розширення IDE для VS Code, Cursor і JetBrains, десктопний застосунок з візуальним переглядом diff та вебдосвід для тривалих завдань. Ваші файли CLAUDE.md, налаштування та сервери MCP переносяться між усіма ними."}, {"kind": "steps", "items": [{"label": "Файл інструкцій", "body": "Claude Code читає файл CLAUDE.md у корені проєкту на початку кожної сесії — природне місце, щоб закодувати ваші дизайн-конвенції, tokens і чеклісти рев'ю."}, {"label": "Skills", "body": "Agent Skills упаковують повторювані інструкції, скрипти та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic для смаку."}, {"label": "План і субагенти", "body": "Він може планувати перед дією та породжувати субагентів, що працюють над різними частинами завдання паралельно, завдяки чому великі рефактори UI лишаються узгодженими."}]}, {"kind": "ul", "items": ["Постачальник: Anthropic", "Облікові дані: API-ключ Anthropic (BYOK, через Console) або підписка Claude (Pro / Max)", "Поверхні: термінальний CLI, розширення VS Code / Cursor / JetBrains, десктопний застосунок, веб"]}]}, {"id": "why-design", "heading": "Чому Claude Code добрий у дизайні", "blocks": [{"kind": "p", "text": "Серед агентів для кодування Claude Code має репутацію смакового у фронтенд-роботі. Це пояснюється кількома речами."}, {"kind": "steps", "items": [{"label": "Конкретні, а не розпливчасті рішення", "body": "Claude Code схильний обирати конкретні варіанти — точні значення hex, шкали відступів, типографічні градації та ієрархію компонентів — замість відмахування, і саме це відрізняє справжній інтерфейс від заглушки."}, {"label": "Міркування з урахуванням кодової бази", "body": "Маючи великий робочий контекст, він рефакторить UI одразу в багатьох файлах, повторно використовуючи ваші наявні компоненти й tokens замість того, щоб винаходити одноразові стилі."}, {"label": "Офіційний frontend skill", "body": "Anthropic постачає Frontend Design skill, який змушує Claude спершу написати дизайн-напрямок і свідомо уникати загальних системних шрифтів та передбачуваних фіолетових градієнтів."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його Anthropic робить про власні моделі: Claude не має смаку за замовчуванням — наданий сам собі, він сходиться до статистичного центру вебдизайну (Inter, фіолетові градієнти, м'які тіні). Він створює добрий дизайн, коли ви даєте йому обмеження. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Claude Code для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Claude Code, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування CLAUDE.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування CLAUDE.md → додавання Frontend Design skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в CLAUDE.md і вкажіть на них Claude, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або Chrome MCP, щоб Claude рендерив у справжньому браузері та перевіряв свій вивід на різних брейкпойнтах, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "skills-workflow", "heading": "Робочий процес із CLAUDE.md і Skills", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Claude Code — це подавати йому реальні референси разом із вашим дизайн-контекстом, а потім ітерувати, доки UI не збіжиться — при цьому CLAUDE.md і Skills несуть обмеження, тож вам не доводиться пояснювати їх заново в кожному промпті."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI навіть із сильним агентом.", "Тримайте свою дизайн-систему й конвенції в CLAUDE.md і кажіть Claude, де живуть tokens і канонічні примітиви.", "Додайте Frontend Design skill, щоб Claude обрав реальний естетичний напрямок перед написанням коду.", "Підключіть перевірку в браузері, щоб Claude рендерив, змінював розмір під брейкпойнти й порівнював із референсами — а не лише підтверджував, що збірка проходить."]}, {"kind": "p", "text": "Перетягніть референсне зображення в сесію та задайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер поруч, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Claude, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі. Використовуйте режим планування для більших рефакторів, щоб переглянути підхід до будь-яких змін у файлах."}]}, {"id": "figma", "heading": "Claude Code + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року Anthropic і Figma випустили першокласну двонапрямлену інтеграцію через сервер Figma MCP. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Виберіть фрейм у Figma або вставте посилання в Claude Code, підтягніть дизайн-контекст і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів. Code Connect тримає вивід узгодженим із вашими реальними компонентами."}, {"label": "Код → Дизайн", "body": "Зберіть і перегляньте функцію в браузері, а потім скажіть «Send this to Figma», щоб зафіксувати робочий UI як редаговані шари Figma — увесь екран або вибраний елемент."}]}, {"kind": "p", "text": "Встановіть її одного разу за допомогою claude plugin install figma@claude-plugins-official (Dev Mode MCP вимагає платного плану Figma). Той самий Figma MCP доступний для Claude Code, Codex, Cursor і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Claude Code проти Codex проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX-міркування з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Codex", "Сильне візуальне опрацювання й розуміння зображень; асинхронні збірки в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Навіть із репутацією Claude Code за смак найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: шрифти Inter, фіолетові градієнти на білому, м'які тіні, завеликі заокруглені кути, естетика, яка «кричить, що це зробив ШІ». Сама Anthropic пояснює це збіжністю розподілу: безпечні рішення домінують у тренувальних даних вебу. Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Встановіть Frontend Design skill", "body": "Він змушує Claude обрати реальний напрямок і явно уникає шрифтів та градієнтів, надмірно вживаних ШІ."}, {"label": "Увімкніть перевірку в браузері", "body": "Змусьте Claude рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в CLAUDE.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Claude Code всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Claude Code як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Claude Code добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Claude Code як свого агента.", "Автентифікуйтеся своїм API-ключем Anthropic (BYOK) або підпискою Claude — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Claude Code, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи добрий Claude Code для дизайн-роботи?", "text": "Так — його широко вважають агентом для кодування з найкращим смаком до фронтенду, що ухвалює конкретні рішення з урахуванням кодової бази щодо значень hex, відступів і типографічних шкал. Зі skill-ом Frontend Design, дизайн-системою та реальними референсними зображеннями в контексті він створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Чи потрібна мені підписка Claude, щоб проєктувати з Claude Code?", "text": "Ви можете використовувати або API-ключ Anthropic (BYOK, через Console), або підписку Claude (Pro / Max). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент на вашій машині."}, {"name": "Claude Code чи Codex для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази та фронтенд-міркуваннями; Codex має сильне візуальне опрацювання й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Claude Code до Figma?", "text": "Встановіть офіційний плагін Figma командою claude plugin install figma@claude-plugins-official. Тоді ви зможете реалізовувати фрейми Figma в коді, використовуючи дизайн-контекст, і відправляти робочий UI назад у редаговані фрейми Figma за допомогою «Send this to Figma». Dev Mode MCP вимагає платного плану Figma."}, {"name": "Що таке Skills і CLAUDE.md?", "text": "CLAUDE.md — це markdown-файл у корені проєкту, який Claude Code читає на початку кожної сесії — місце, щоб закодувати ваші дизайн-конвенції. Skills упаковують повторювані інструкції та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic. Open Design постачає кураторську бібліотеку обох, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть Frontend Design skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в CLAUDE.md та увімкніть перевірку в браузері. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Anthropic?", "text": "Ні. Claude Code — продукт Anthropic; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Claude і Claude Code — торгові марки Anthropic."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first і Apache-2.0. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Anthropic використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Claude Code, відкрито.", "ctaBody": "Підключіть власний ключ Anthropic або підписку Claude, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex для дизайну — Open Design",
        description: "Як люди використовують OpenAI Codex для UI та вебдизайну — плагін Product Design, інтеграцію з Figma, фронтенд-skill-и — і як Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Codex",
        label: "Агент · Codex",
        heading: "Codex для дизайну.",
        lead: "Codex — це агент для кодування від OpenAI. Із плагіном Product Design та інтеграцією Figma він став серйозним дизайн-інструментом. Open Design вбудовує Codex у дизайн-процес з відкритим кодом — ваш ключ OpenAI або підписка ChatGPT, ваші файли, local-first.",
        rich: {"heroCtaLead": "Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом — ваш ключ OpenAI, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex починався як генератор коду, але у 2026 році став надійним інструментом для проєктування справжніх інтерфейсів — щойно ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання Codex для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим є Codex сьогодні, чому він раптом став добрим у фронтенді, як налаштувати його з нуля, цикл «скриншот → UI», офіційний двосторонній обмін із Figma, як він порівнюється з Cursor і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Цикл зворотного зв'язку дизайну Codex: термінальний агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Codex будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-codex", "label": "Чим насправді є OpenAI Codex"}, {"id": "why-design", "label": "Чому Codex тепер добрий у дизайні"}, {"id": "setup", "label": "Налаштування Codex для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "figma", "label": "Двосторонній обмін Codex + Figma"}, {"id": "vs", "label": "Codex проти Cursor проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Codex в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-codex", "heading": "Чим насправді є OpenAI Codex (і чим він не є)", "blocks": [{"kind": "p", "text": "Спершу — уточнення, яке збиває з пантелику майже всіх, хто шукає «Codex». Початковий OpenAI Codex був моделлю автодоповнення коду 2021 року, що живила ранній GitHub Copilot і була виведена з експлуатації у 2023 році. Ця сторінка не про неї. Сьогоднішній Codex — це агентний інструмент кодування від OpenAI: він планує, пише, виконує й перевіряє код за завданнями природною мовою."}, {"kind": "p", "text": "Сучасний Codex постачається на чотирьох поверхнях: термінальний CLI (переписаний на Rust, під ліцензією Apache-2.0), розширення IDE для VS Code, Cursor і Windsurf, хмарний/вебдосвід для делегованих асинхронних завдань і десктопний застосунок із вбудованим браузером та Computer Use."}, {"kind": "steps", "items": [{"label": "Модель за замовчуванням", "body": "Станом на середину 2026 року рекомендована модель — gpt-5.5, а gpt-5.4 — це модель, яку OpenAI явно тренувала для фронтенду й роботи з комп'ютером."}, {"label": "Файл інструкцій", "body": "Codex читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції."}, {"label": "Пісочниця", "body": "Він працює в пісочниці рівня ядра (workspace-write за замовчуванням), тож агент, що редагує ваш UI, не може вийти за межі проєкту."}]}, {"kind": "ul", "items": ["Постачальник: OpenAI", "Облікові дані: API-ключ OpenAI (BYOK) або підписка ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Ліцензія CLI: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому Codex тепер добрий у дизайні", "blocks": [{"kind": "p", "text": "На початку 2026 року зійшлися три речі, що зробили Codex справжнім дизайн-інструментом, а не загальним генератором коду."}, {"kind": "steps", "items": [{"label": "Модель, натренована для фронтенду", "body": "OpenAI випустила GPT-5.4 — свою першу основну модель, натреновану для фронтенду й роботи з комп'ютером, із набагато кращим розумінням зображень у дизайн-процесі та сильнішою самоперевіркою. Вона навіть може генерувати mood-борди та візуальні варіанти перед тим, як обрати фінальні ассети."}, {"label": "Офіційний frontend skill", "body": "Каталог openai/skills постачає кураторський frontend-skill, що нав'язує реальний смак: розкладки без карток, повноширинні hero-блоки, ієрархія за брендом, стриманий рух, щонайбільше два шрифти й один акцентний колір — і змушує Codex написати візуальну тезу перед побудовою."}, {"label": "Перевірка в браузері", "body": "Зі skill-ом Playwright Codex відкриває справжній браузер, змінює розмір під брейкпойнти й порівнює свій вивід із референсом, а не лише перевіряє, що збірка проходить."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок за всіма трьома: Codex не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Codex для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Codex, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування, встановлення skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування AGENTS.md → встановлення frontend skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md або DESIGN.md і вкажіть на них Codex, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Виберіть правильний рівень міркування", "body": "OpenAI зазначає, що низький-середній рівні міркування часто дають сильніші фронтенд-результати, ніж найвище налаштування."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Codex — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Власні рекомендації OpenAI зводяться до п'яти кроків."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Codex, де живуть tokens і канонічні примітиви.", "Увімкніть інтерактивний skill Playwright, щоб Codex рендерив у справжньому браузері й змінював розмір під брейкпойнти.", "Ітеруйте, змушуючи Codex порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Подавайте зображення, перетягуючи скриншот у термінал або через прапорець зображення, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер у другому терміналі, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Codex, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "figma", "heading": "Codex + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року OpenAI і Figma оголосили про офіційне партнерство, перетворивши попередню бета-версію Figma MCP на першокласну двонапрямлену інтеграцію. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте «link to selection» фрейму у Figma, вставте його в Codex із get_design_context і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів."}, {"label": "Код → Дизайн", "body": "Інструмент generate_figma_design («Code to Canvas») перетворює живий робочий UI назад на редаговані фрейми Figma — увесь екран, вибраний елемент або цілий файл."}]}, {"kind": "p", "text": "Figma MCP працює як віддалений сервер і звільнений від лімітів швидкості. Додайте його одного разу, і він стане доступним для Codex, Claude Code, Cursor, VS Code тощо — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Codex проти Cursor проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Codex", "Сильне візуальне опрацювання після GPT-5.4 + frontend-skill; розуміння зображень", "Делеговані асинхронні збірки, запуски в пісочниці, переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Codex, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки, інструкції, що протікають у текст UI, та швидке досягнення лімітів використання."}, {"kind": "steps", "items": [{"label": "Встановіть frontend skill", "body": "Кураторський естетичний skill змушує Codex обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Увімкніть перевірку Playwright", "body": "Змусьте Codex рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Codex всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Codex як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Codex добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Codex як свого агента.", "Автентифікуйтеся своїм API-ключем OpenAI (BYOK) або підпискою ChatGPT — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Codex, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenAI Codex може виконувати дизайн-роботу?", "text": "Так — із frontend skill, дизайн-системою та реальними референсними зображеннями в контексті Codex (особливо на GPT-5.4) створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це плагін OpenAI Codex Product Design?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Codex як агента. Він доповнює власний інструментарій OpenAI local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка ChatGPT, щоб проєктувати з Codex?", "text": "Ви можете використовувати або API-ключ OpenAI (BYOK), або свою підписку ChatGPT. Вхід через ChatGPT зазвичай дає щедріші ліміти; у будь-якому разі Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Codex чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; Codex має сильне візуальне опрацювання після GPT-5.4 й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Codex до Figma?", "text": "Додайте офіційний сервер Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Тоді ви зможете реалізовувати фрейми Figma в коді за допомогою get_design_context і відправляти робочий UI назад у редаговані фрейми Figma за допомогою generate_figma_design."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть frontend skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в AGENTS.md та увімкніть перевірку Playwright. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenAI?", "text": "Ні. Codex — продукт OpenAI; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. OpenAI і Codex — торгові марки OpenAI."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані OpenAI використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Codex, відкрито.", "ctaBody": "Підключіть власний ключ OpenAI, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor для дизайнерів — Open Design",
        description: "Як дизайнери використовують Cursor для UI та вебдизайну — Design Mode, Figma-у-код, Figma MCP — і як Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Cursor",
        label: "Агент · Cursor",
        heading: "Cursor для дизайнерів.",
        lead: "Cursor — це AI-редактор коду, тепер із візуальним Design Mode. Дизайнери використовують його, щоб редагувати UI вказуванням і малюванням, і перетворювати Figma на код. Open Design вбудовує Cursor Agent у дизайн-процес з відкритим кодом, що тримає ваші файли локально.",
        rich: {"heroCtaLead": "Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом — ваш акаунт Cursor або ключі моделей, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor — це AI-first редактор коду, який зробив «зроби й подивись, як воно рендериться» стандартним способом випускати UI. З режимом Agent, інлайн-правками, попереднім переглядом усередині редактора та Figma через MCP він став справжнім дизайн-інструментом — щойно ви даєте йому правильні референси, правила та цикл перевірки. Це практичний наскрізний посібник з використання Cursor для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є Cursor, чому його щільний цикл «ітеруй і спостерігай» добрий для дизайну, як налаштувати його з нуля, цикл «скриншот і попередній перегляд → UI», двосторонній обмін із Figma через MCP, як він порівнюється з Codex і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Збіжність дизайну Cursor: редактор ліворуч, кураторський хаб skill-ів і дизайн-систем посередині зі знаком Cursor у центрі та відрендерений UI праворуч", "caption": "Основна ідея: Cursor редагує й рендерить UI в редакторі, а кураторський дизайн-хаб подає йому систему, skill-и та референси, що роблять вивід умисним."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-cursor", "label": "Чим насправді є Cursor"}, {"id": "why-design", "label": "Чому Cursor добрий у дизайні"}, {"id": "setup", "label": "Налаштування Cursor для дизайну (з нуля)"}, {"id": "preview-workflow", "label": "Робочий процес «попередній перегляд → UI»"}, {"id": "figma", "label": "Cursor + Figma через MCP"}, {"id": "vs", "label": "Cursor проти Codex проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Cursor в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-cursor", "heading": "Чим насправді є Cursor", "blocks": [{"kind": "p", "text": "Cursor — це AI-first редактор коду, створений компанією Anysphere. Це форк VS Code, тож він зберігає звичний редактор, розширення та комбінації клавіш, але перебудовує робочий процес навколо AI-агента, який може читати весь ваш проєкт, редагувати кілька файлів, виконувати команди та ітерувати разом з вами в циклі."}, {"kind": "p", "text": "Для дизайн-роботи важливі поверхні — це режим Agent (ви описуєте результат, а Cursor планує й редагує між файлами), інлайн-правки та доповнення Tab для швидких налаштувань, попередній перегляд / браузер усередині редактора, щоб бачити робочий UI, не залишаючи вікно, і підтримка MCP, що дозволяє підтягувати зовнішній контекст, як-от живий файл Figma."}, {"kind": "steps", "items": [{"label": "Правила проєкту", "body": "Cursor читає файли інструкцій проєкту — версіоновані правила `.mdc` під `.cursor/rules` та звичайний `AGENTS.md` — тож ви можете закодувати свої дизайн-конвенції там, де агент читає їх щоразу."}, {"label": "Моделі", "body": "Cursor гнучкий до моделей: він постачається з передовими моделями через вашу підписку й також підтримує підключення власних ключів моделей, тож ви обираєте рушій за тим самим робочим процесом редактора."}, {"label": "MCP", "body": "Він розмовляє Model Context Protocol, тож зовнішні сервери — найрелевантніше, сервер Figma MCP — стають першокласним контекстом для агента."}]}, {"kind": "ul", "items": ["Постачальник: Anysphere", "Облікові дані: акаунт / підписка Cursor (Hobby / Pro / Business) або власні ключі моделей (BYOK)", "Форма: AI-first редактор коду (форк VS Code) з агентом і попереднім переглядом усередині редактора"]}]}, {"id": "why-design", "heading": "Чому Cursor добрий у дизайні", "blocks": [{"kind": "p", "text": "Дизайн-перевага Cursor — не окрема функція, а щільність циклу «зроби й подивись». Три речі роблять його схожим на дизайн-інструмент, а не на загальний генератор коду."}, {"kind": "steps", "items": [{"label": "Щільний цикл «ітеруй і спостерігай»", "body": "Ви задаєте промпт, Cursor редагує між файлами, а попередній перегляд усередині редактора рендерить результат миттєво — тож ви налаштовуєте відступи, ієрархію та рух за секунди замість того, щоб ходити кругом через окремий термінал і браузер."}, {"label": "Пряме візуальне редагування", "body": "Окрім чату, Cursor дозволяє вибирати елементи в попередньому перегляді й підправляти стилі, тож дрібні візуальні корекції відчуваються як дизайн-правки, а не археологія коду."}, {"label": "Правила проєкту та контекст MCP", "body": "З `.cursor/rules` (або `AGENTS.md`) і сервером Figma MCP агент працює з вашими tokens, компонентами та реальними дизайн-специфікаціями замість того, щоб вгадувати."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його вчить кожен агент: Cursor не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Cursor для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Cursor, який може будувати, переглядати й перевіряти UI відносно вашої дизайн-системи."}, {"kind": "ol", "items": ["Встановіть Cursor із cursor.com і увійдіть зі своїм акаунтом Cursor або налаштуйте власні ключі моделей (BYOK) у Settings.", "Відкрийте свій проєкт і виберіть модель у панелі чату / Agent.", "Додайте правила проєкту: створіть `.cursor/rules/*.mdc` для структурованих, обмежених glob-ами конвенцій, або звичайний `AGENTS.md` для простих, читабельних інструкцій.", "Підключіть сервер Figma MCP (опційно), щоб агент міг читати живий дизайн-контекст.", "Запустіть свій dev-сервер і використовуйте попередній перегляд усередині редактора, щоб бачити й перевіряти UI під час ітерацій."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування правил, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування правил проєкту → додавання skill-а → увімкнення перевірки через попередній перегляд."}, {"kind": "p", "text": "Мінімальний файл правил проєкту змушує агента проєктувати під бренд замість звертання до загального вигляду. Помістіть його туди, де Cursor читає його щоразу:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в `.cursor/rules` або `AGENTS.md` і вкажіть на них Cursor, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Тримайте промпти невеликими", "body": "Щільний цикл Cursor винагороджує сфокусовані запити — ітеруйте по одному компоненту чи стану за раз і спостерігайте попередній перегляд між проходами."}]}]}, {"id": "preview-workflow", "heading": "Робочий процес «попередній перегляд → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Cursor — перетворити референс на робочий, адаптивний UI та ітерувати в редакторі, доки він не збіжиться — спостерігаючи живий попередній перегляд увесь час замість того, щоб вгадувати."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Cursor, де живуть tokens і канонічні примітиви.", "Тримайте попередній перегляд усередині редактора відкритим, а dev-сервер запущеним, щоб кожна правка рендерилась миттєво на потрібних вам брейкпойнтах.", "Ітеруйте, порівнюючи відрендерений UI з референсами — і використовуйте прямий вибір елементів у попередньому перегляді для дрібних візуальних корекцій."]}, {"kind": "p", "text": "Подавайте референси, прикріплюючи зображення до чату, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Комітьте вдалі ітерації й відкочуйте невдалі (кажучи Cursor, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі — та сама дисципліна, що не дає будь-якому циклу агента зноситися."}]}, {"id": "figma", "heading": "Cursor + Figma: дизайн ↔ код через MCP", "blocks": [{"kind": "p", "text": "Cursor підключається до Figma через офіційний сервер Figma MCP, що дає агенту структурований доступ до живого файлу Figma замість плаского скриншота. Це усуває здогадки з передачі."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте посилання на фрейм у Figma, вставте його в Cursor і попросіть реалізувати дизайн. Сервер MCP надає реальний дизайн-контекст — компоненти, змінні, дані розкладки, tokens — тож згенерований код відповідає джерелу, а не наближає його."}, {"label": "Лишайтеся узгодженими", "body": "З дизайн-tokens, стилями та компонентами, що послідовно використовуються у Figma (і Code Connect, де доступно), вивід Cursor лишається прив'язаним до вашої реальної дизайн-системи, а не винаходить примітиви заново."}]}, {"kind": "p", "text": "Налаштуйте віддалений сервер Figma MCP одного разу, і він стане доступним для Cursor як першокласний контекст. Оскільки MCP — це відкритий стандарт, той самий сервер можна повторно використовувати в Cursor, Claude Code, Codex і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Cursor проти Codex проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом усередині редактора та прямим редагуванням елементів", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень і запуски в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Cursor, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — розкладки, що ламаються на мобільному, та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Додайте дизайн-skill", "body": "Кураторський естетичний skill змушує Cursor обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Використовуйте попередній перегляд для перевірки", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах у попередньому перегляді всередині редактора, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в `.cursor/rules`", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Cursor всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Cursor як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Cursor добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Cursor як свого агента.", "Автентифікуйтеся своїм акаунтом Cursor або власними ключами моделей (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Cursor, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді Cursor може виконувати дизайн-роботу?", "text": "Так — із дизайн-skill, дизайн-системою та реальними референсними зображеннями в контексті Cursor створює UI продакшн-якості, адаптивний, а його попередній перегляд усередині редактора дозволяє перевіряти й уточнювати його візуально. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це офіційний продукт Cursor?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Cursor як агента. Він доповнює Cursor local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка Cursor, щоб проєктувати з Cursor?", "text": "Ви можете використовувати акаунт / підписку Cursor або підключити власні ключі моделей (BYOK). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент."}, {"name": "Cursor чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Cursor — його щільний цикл «зроби й подивись» із живим попереднім переглядом усередині редактора. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Cursor до Figma?", "text": "Додайте офіційний сервер Figma MCP у Cursor, потім вставте посилання на фрейм Figma в чат і попросіть Cursor реалізувати його. Сервер надає реальні компоненти, змінні та дані розкладки, тож згенерований код відповідає вихідному дизайну."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Додайте дизайн-skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в `.cursor/rules` або `AGENTS.md` і перевіряйте на різних брейкпойнтах у попередньому перегляді. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Cursor або Anysphere?", "text": "Ні. Cursor — продукт Anysphere; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Cursor і Anysphere — торгові марки Anysphere, Inc."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Cursor чи моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Cursor, відкрито.", "ctaBody": "Підключіть власний акаунт Cursor або ключі моделей, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode для дизайну — Open Design",
        description: "Як люди використовують OpenCode для UI та вебдизайну — файли design.md, UI/UX skill-и, Figma MCP — і як Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "OpenCode",
        label: "Агент · OpenCode",
        heading: "OpenCode для дизайну.",
        lead: "OpenCode — це термінальний AI-агент для кодування з відкритим кодом. Дизайнери прикручують до нього дизайн-skill-и та файли DESIGN.md, щоб генерувати справжній UI. Open Design робить це структурованим процесом з відкритим кодом — підключіть ключі своїх постачальників, тримайте все локально.",
        rich: {"heroCtaLead": "Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом — будь-яка модель, яку ви обираєте, з вашим власним ключем постачальника, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode — це термінальний AI-агент для кодування з відкритим кодом, навмисно незалежний від моделей: ви підключаєте власний ключ постачальника й запускаєте будь-яку модель за тим самим робочим процесом. Така відкритість робить його природною базою для дизайн-роботи — але, як і кожен агент, він створює добрий UI лише тоді, коли ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання OpenCode для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є OpenCode, чому відкритий агент, незалежний від моделей, добре пасує дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як AGENTS.md і MCP розширюють його, як він порівнюється з Codex, Claude Code та Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар — природне поєднання, адже обидва проєкти з відкритим кодом і працюють на вашій власній машині."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну OpenCode: термінальний TUI-агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: OpenCode будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів — на будь-якій моделі, яку ви оберете."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-opencode", "label": "Чим насправді є OpenCode"}, {"id": "why-design", "label": "Чому відкритий агент із будь-якою моделлю пасує дизайну"}, {"id": "setup", "label": "Налаштування OpenCode для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "AGENTS.md, MCP та сесії, якими можна ділитися"}, {"id": "vs", "label": "OpenCode проти Codex проти Claude Code проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із OpenCode в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-opencode", "heading": "Чим насправді є OpenCode", "blocks": [{"kind": "p", "text": "OpenCode — це AI-агент для кодування з відкритим кодом, створений для терміналу й підтримуваний командою, що стоїть за SST (Anomaly Innovations). Він читає ваш репозиторій, виконує команди, редагує файли й спілкується з великою мовною моделлю — але, на відміну від прив'язаних до вендора агентів, він не постачає власну модель. Ви спрямовуєте його на будь-який постачальник і модель, які захочете, і підключаєте власний ключ."}, {"kind": "p", "text": "Він працює як термінальний UI (TUI), з десктопним застосунком та розширеннями IDE поверх того самого рушія. Під капотом він використовує клієнт-серверну архітектуру, тож агент, що виконує роботу, відокремлений від поверхні, з якої ви ним керуєте. Два вбудовані агенти — build і plan — перемикаються клавішею Tab."}, {"kind": "steps", "items": [{"label": "Незалежний від моделей", "body": "Моделі та постачальники беруться з models.dev, відкритого каталогу. Ви налаштовуєте їх в opencode.json рядком provider/model-id і можете вимкнути постачальників, яких не хочете завантажувати — тож той самий дизайн-процес працює на Anthropic, OpenAI, Google, OpenRouter, локальних моделях тощо."}, {"label": "Файл інструкцій", "body": "OpenCode читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт, також сумісний із CLAUDE.md) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції. Запустіть /init, щоб згенерувати його."}, {"label": "Розширюваний", "body": "Він підтримує інтеграцію LSP, сервери MCP, теми, комбінації клавіш і кастомні команди, а також посилання на сесії, якими можна ділитися, для співпраці."}]}, {"kind": "ul", "items": ["Супровід: SST / Anomaly Innovations (проєкт з відкритим кодом)", "Облікові дані: ваш(і) власний(і) API-ключ(і) постачальника моделей — BYOK, без прив'язки до вендора", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому відкритий агент із будь-якою моделлю пасує дизайн-роботі", "blocks": [{"kind": "p", "text": "OpenCode не має єдиної «дизайн-моделі», як її має вендорний агент — і в цьому суть. Оскільки він незалежний від моделей і відкритий, ви можете запускати той самий дизайн-процес на тій моделі, яка зараз найкраща у фронтенді, замінити її пізніше або відкотитися до локальної моделі — і все без зміни вашого налаштування."}, {"kind": "p", "text": "Але самого вибору моделі мало для смаку. Як і кожен агент для кодування, OpenCode створює загальний UI, доки ви не дасте йому обмежень. Добрий дизайн-вивід походить із трьох вхідних даних, які надаєте ви."}, {"kind": "steps", "items": [{"label": "Дизайн-система", "body": "Реальні tokens, примітиви та конвенції, які агент повторно використовує, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Естетичний skill", "body": "Кураторський skill, що нав'язує реальний смак — стриманий рух, ієрархія за брендом, щонайбільше два шрифти й один акцентний колір — і змушує агента обрати напрямок перед побудовою."}, {"label": "Конкретні референси", "body": "Справжні референсні зображення та кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не один hero-кадр."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень — незалежно від того, яку модель ви запускаєте."}, {"kind": "p", "text": "Урок: OpenCode дає вам свободу моделі, але смак усе одно походить із кураторського дизайн-контексту. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному — обидва з відкритим кодом і local-first (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте OpenCode для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до OpenCode, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація ключем постачальника, налаштування AGENTS.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація (ваш ключ постачальника) → налаштування AGENTS.md → додавання skill-а → перевірка у справжньому браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md (або DESIGN.md, на який є посилання звідти), щоб вивід відповідав бренду, а не звертався до загального вигляду. Опція instructions в opencode.json може вказувати на додаткові файли правил через glob-и."}, {"label": "Виберіть здатну модель", "body": "Оскільки OpenCode незалежний від моделей, виберіть той постачальник/модель, що зараз найсильніший у фронтенді, для дизайн-проходу — і лишіть решту свого процесу незмінною."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із будь-яким агентом — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Та сама форма з п'яти кроків застосовна в OpenCode."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть OpenCode, де живуть tokens і канонічні примітиви (в AGENTS.md).", "Запустіть dev-сервер і змусьте агента рендерити у справжньому браузері, змінюючи розмір під брейкпойнти, щоб перевірити результат.", "Ітеруйте, змушуючи OpenCode порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Посилайтеся на файли через @ у TUI для нечіткого пошуку у вашій робочій директорії, виконуйте shell-команди інлайн із початковим !, і керуйте діями через команди /. Потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте промпти невеликими й сфокусованими, комітьте вдалі ітерації й відкочуйте невдалі (кажучи OpenCode, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "AGENTS.md, MCP та сесії, якими можна ділитися", "blocks": [{"kind": "p", "text": "Три точки розширення роблять OpenCode практичним для сталої дизайн-роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Правила AGENTS.md", "body": "Правила проєкту живуть в AGENTS.md у корені репозиторію (або глобальні правила в ~/.config/opencode/AGENTS.md). Це довговічна домівка для ваших дизайн-конвенцій, що читається щоразу, і вона сумісна з файлами CLAUDE.md, які використовують інші агенти."}, {"label": "Сервери MCP", "body": "OpenCode підтримує як локальні (command), так і віддалені (URL) сервери MCP, налаштовані під ключем mcp — переносний спосіб привнести дизайн-контекст і зовнішні інструменти, що працюють між агентами, а не лише в OpenCode."}, {"label": "Сесії, якими можна ділитися", "body": "Команда /share створює публічне посилання на розмову для співпраці чи рев'ю, а /unshare відкликає його — корисно для отримання відгуку про дизайн-прохід."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме той тип речей, який Open Design створено оркеструвати, а не відтворювати для кожного проєкту."}]}, {"id": "vs", "heading": "OpenCode проти Codex проти Claude Code проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["OpenCode", "Відкритий код і незалежність від моделей; запускайте будь-який постачальник за одним термінальним процесом", "Свобода BYOK, перемикання моделей, повністю відкриті та local-first налаштування"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень", "Делеговані асинхронні, збірки в пісочниці, переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі вони за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі, і саме тому відкритий агент на кшталт OpenCode так добре поєднується з відкритим дизайн-шаром."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI. Жодна з них не унікальна для OpenCode; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту — незалежно від того, яку модель ви запускаєте. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із OpenCode всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує OpenCode як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить будь-якого агента добрим, був на місці з першого запуску, а не збирався вручну щоразу. Обидва проєкти з відкритим кодом і local-first, що робить поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть OpenCode як свого агента.", "Автентифікуйтеся своїм власним API-ключем постачальника моделі (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть будь-який постачальник і модель, а також дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент OpenCode, та сама свобода моделі — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenCode може виконувати дизайн-роботу?", "text": "Так — із естетичним skill, дизайн-системою та реальними референсними зображеннями в контексті OpenCode створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Оскільки він незалежний від моделей, ви запускаєте ту модель, яка зараз найкраща у фронтенді. Без цього кураторського контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Яку модель слід використовувати з OpenCode для дизайну?", "text": "Будь-яку, що вам до вподоби — OpenCode незалежний від постачальників через models.dev, тож ви можете запускати Anthropic, OpenAI, Google, OpenRouter або локальні моделі за тим самим процесом і перемикатися будь-коли. Якість дизайн-виводу залежить набагато більше від вашого skill-а, дизайн-системи та референсів, ніж від самої моделі."}, {"name": "Чи зроблено Open Design командою OpenCode (SST)?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує OpenCode як агента. Він доповнює OpenCode local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені особлива підписка, щоб проєктувати з OpenCode?", "text": "Ні — OpenCode працює за BYOK. Ви підключаєте власний API-ключ постачальника моделі, і Open Design ніколи не проксіює ваші облікові дані. Немає прив'язки до вендора."}, {"name": "OpenCode, Codex чи Claude Code для фронтенд-дизайну?", "text": "Усі сильні, і багато команд поєднують їх. Перевага OpenCode — бути повністю з відкритим кодом і незалежним від моделей; Codex чудовий у делегованих збірках у пісочниці; Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази. Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як розширити OpenCode для дизайн-контексту?", "text": "Закодуйте правила в AGENTS.md, додайте сервери MCP під ключем mcp для переносних інструментів і дизайн-контексту та використовуйте сесії, якими можна ділитися, для рев'ю. Open Design постачає кураторську бібліотеку skill-ів і дизайн-систем, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenCode або SST?", "text": "Ні. OpenCode — проєкт з відкритим кодом, який підтримує SST (Anomaly Innovations); Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані постачальника моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з OpenCode, відкрито.", "ctaBody": "Підключіть власний ключ постачальника моделі, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо відкритого агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
    },
  };
}
